import { useEffect } from "react";
import { Toaster } from "@/components/ui/toaster";
import { Toaster as Sonner } from "@/components/ui/sonner";
import { TooltipProvider } from "@/components/ui/tooltip";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { BrowserRouter, Routes, Route, Navigate, useLocation } from "react-router-dom";
import { AuthProvider, useAuth } from "@/contexts/AuthContext";
import { ProtectedRoute } from "@/components/auth/ProtectedRoute";
import { PWAInstallPrompt } from "@/components/pwa/PWAInstallPrompt";
import { usePWAUpdate } from "@/hooks/use-pwa-update";

// Pages
import Login from "./pages/Login";
import SignUp from "./pages/SignUp";
import ForgotPassword from "./pages/ForgotPassword";
import ResetPassword from "./pages/ResetPassword";
import PlanSelection from "./pages/PlanSelection";
import Subscription from "./pages/Subscription";
import Upgrade from "./pages/Upgrade";
import WaitingApproval from "./pages/WaitingApproval";
import CompanySetup from "./pages/CompanySetup";
import CompanyJoin from "./pages/CompanyJoin";
import Dashboard from "./pages/Painel/Painel";
import Vendas from "./pages/Vendas/Vendas";
import Clientes from "./pages/Clientes";
import Espaco from "./pages/Espaco/Espaco";
import Financeiro from "./pages/Financeiro/Financeiro";
import Compras from "./pages/Compras";
import Contas from "./pages/Contas/Contas";
import Relatorios from "./pages/Relatorios";
import Comissoes from "./pages/Comissoes";

import Garantias from "./pages/Garantias";
import Estoque from "./pages/Estoque";
import Servicos from "./pages/Servicos";

import Perfil from "./pages/Perfil";
import Empresa from "./pages/Empresa";
import Funcionarios from "./pages/Funcionarios";
import MaterialLosses from "./pages/MaterialLosses";
import Master from "./pages/Master";
import NotFound from "./pages/NotFound";

import { MainLayout } from "./components/layout/MainLayout";
import { ErrorBoundary } from "@/components/ui/ErrorBoundary";

const queryClient = new QueryClient();

function AppRoutes() {
  const { isAuthenticated, isLoading, user } = useAuth();
  const location = useLocation();
  const searchParams = new URLSearchParams(location.search);
  const isUpgradeMode = searchParams.get('mode') === 'upgrade';

  // Check if the upgrade is actually needed (user doesn't already have target plan or better)
  const isUpgradeNeeded = (() => {
    if (!isUpgradeMode || !user) return false;
    const planHierarchy: Record<string, number> = { basic: 1, ultra: 2, premium: 3 };
    const targetPlan = searchParams.get('target') || 'ultra';
    const currentPlanLevel = planHierarchy[user.planCode || 'basic'] || 0;
    const targetPlanLevel = planHierarchy[targetPlan] || 0;
    return user.subscriptionStatus === 'active' && currentPlanLevel >= targetPlanLevel ? false : true;
  })();

  useEffect(() => {
    if (!isLoading) {
      const loader = document.getElementById('loader-screen');
      if (loader) {
        const startTime = (window as any).__loaderStartTime || Date.now();
        const elapsed = Date.now() - startTime;
        const MIN_DISPLAY_TIME = 1500;
        const remaining = Math.max(0, MIN_DISPLAY_TIME - elapsed);

        setTimeout(() => {
          loader.classList.add('hide-loader');
          setTimeout(() => {
            loader.remove();
          }, 800);
        }, remaining);
      }
    }
  }, [isLoading]);

  if (isLoading) {
    return null;
  }

  return (
    <Routes>
      {/* Public Routes */}
      <Route
        path="/login"
        element={isAuthenticated ? <Navigate to="/" replace /> : <Login />}
      />
      <Route
        path="/cadastro"
        element={isAuthenticated ? <Navigate to="/" replace /> : <SignUp />}
      />
      <Route
        path="/esqueci-senha"
        element={isAuthenticated ? <Navigate to="/" replace /> : <ForgotPassword />}
      />
      <Route
        path="/redefinir-senha"
        element={<ResetPassword />}
      />

      {/* Subscription Flow Routes (authenticated but no company yet) */}
      <Route
        path="/planos"
        element={
          !isAuthenticated ? (
            <Navigate to="/login" replace />
          ) : ((user?.subscriptionStatus === 'active' || user?.subscriptionStatus === 'pending_payment') && user?.companyId && (!isUpgradeMode || !isUpgradeNeeded)) ? (
            <Navigate to="/" replace />
          ) : (
            <PlanSelection />
          )
        }
      />
      <Route
        path="/assinatura"
        element={
          !isAuthenticated ? (
            <Navigate to="/login" replace />
          ) : ((user?.subscriptionStatus === 'active' || user?.subscriptionStatus === 'pending_payment') && user?.companyId && (!isUpgradeMode || !isUpgradeNeeded)) ? (
            <Navigate to="/" replace />
          ) : (
            <Subscription />
          )
        }
      />
      <Route
        path="/upgrade"
        element={<Navigate to="/planos?mode=upgrade" replace />}
      />
      <Route
        path="/aguardando-liberacao"
        element={
          !isAuthenticated ? (
            <Navigate to="/login" replace />
          ) : (user?.subscriptionStatus === 'active' || user?.subscriptionStatus === 'pending_payment') ? (
            user?.companyId ? <Navigate to="/" replace /> : <Navigate to="/empresa/cadastro" replace />
          ) : user?.subscriptionStatus !== 'payment_submitted' ? (
            user?.planCode ? <Navigate to="/assinatura" replace /> : <Navigate to="/planos" replace />
          ) : (
            <WaitingApproval />
          )
        }
      />
      <Route
        path="/empresa/cadastro"
        element={
          !isAuthenticated ? (
            <Navigate to="/login" replace />
          ) : (user?.subscriptionStatus !== 'active' && user?.subscriptionStatus !== 'pending_payment') ? (
            user?.planCode ? <Navigate to="/assinatura" replace /> : <Navigate to="/planos" replace />
          ) : user?.companyId ? (
            <Navigate to="/" replace />
          ) : (
            <CompanySetup />
          )
        }
      />
      <Route
        path="/empresa/entrar"
        element={
          !isAuthenticated ? (
            <Navigate to="/login" replace />
          ) : user?.companyId ? (
            <Navigate to="/" replace />
          ) : (
            <CompanyJoin />
          )
        }
      />

      {/* Protected Routes - ADMIN and FUNCIONARIO */}
      <Route path="/" element={
        <ProtectedRoute allowedRoles={['ADMIN', 'FUNCIONARIO']}>
          <MainLayout><Dashboard /></MainLayout>
        </ProtectedRoute>
      } />

      <Route path="/vendas" element={
        <ProtectedRoute allowedRoles={['ADMIN', 'FUNCIONARIO']}>
          <MainLayout><Vendas /></MainLayout>
        </ProtectedRoute>
      } />

      <Route path="/clientes" element={
        <ProtectedRoute allowedRoles={['ADMIN', 'FUNCIONARIO']}>
          <MainLayout><Clientes /></MainLayout>
        </ProtectedRoute>
      } />

      <Route path="/espaco" element={
        <ProtectedRoute allowedRoles={['ADMIN', 'FUNCIONARIO']}>
          <MainLayout><Espaco /></MainLayout>
        </ProtectedRoute>
      } />

      <Route path="/financeiro" element={
        <ProtectedRoute allowedRoles={['ADMIN']}>
          <MainLayout><Financeiro /></MainLayout>
        </ProtectedRoute>
      } />

      <Route path="/compras" element={
        <ProtectedRoute allowedRoles={['ADMIN']}>
          <MainLayout><Compras /></MainLayout>
        </ProtectedRoute>
      } />

      <Route path="/contas" element={
        <ProtectedRoute allowedRoles={['ADMIN']}>
          <MainLayout><Contas /></MainLayout>
        </ProtectedRoute>
      } />

      <Route path="/relatorios" element={
        <ProtectedRoute allowedRoles={['ADMIN']}>
          <MainLayout><Relatorios /></MainLayout>
        </ProtectedRoute>
      } />

      <Route path="/comissoes" element={
        <ProtectedRoute allowedRoles={['ADMIN']}>
          <MainLayout><Comissoes /></MainLayout>
        </ProtectedRoute>
      } />

      <Route path="/garantias" element={
        <ProtectedRoute allowedRoles={['ADMIN', 'FUNCIONARIO']}>
          <MainLayout><Garantias /></MainLayout>
        </ProtectedRoute>
      } />


      <Route path="/perfil" element={
        <ProtectedRoute allowedRoles={['ADMIN', 'FUNCIONARIO', 'PRODUCAO']}>
          <MainLayout><Perfil /></MainLayout>
        </ProtectedRoute>
      } />

      <Route path="/empresa" element={
        <ProtectedRoute allowedRoles={['ADMIN']}>
          <MainLayout><Empresa /></MainLayout>
        </ProtectedRoute>
      } />

      <Route path="/funcionarios" element={
        <ProtectedRoute allowedRoles={['ADMIN']}>
          <MainLayout><Funcionarios /></MainLayout>
        </ProtectedRoute>
      } />

      {/* Protected Routes - ADMIN and PRODUCAO (Estoque) */}
      <Route path="/estoque" element={
        <ProtectedRoute allowedRoles={['ADMIN', 'PRODUCAO']}>
          <MainLayout><Estoque /></MainLayout>
        </ProtectedRoute>
      } />
      <Route path="/perdas" element={
        <ProtectedRoute allowedRoles={['ADMIN', 'PRODUCAO', 'FUNCIONARIO']}>
          <MainLayout><ErrorBoundary><MaterialLosses /></ErrorBoundary></MainLayout>
        </ProtectedRoute>
      } />

      {/* Protected Routes - Serviços */}
      <Route path="/servicos" element={
        <ProtectedRoute allowedRoles={['ADMIN', 'FUNCIONARIO', 'PRODUCAO']}>
          <MainLayout><Servicos /></MainLayout>
        </ProtectedRoute>
      } />

      {/* Protected Routes - Master only */}
      <Route path="/master" element={
        <ProtectedRoute requireMaster>
          <MainLayout><Master /></MainLayout>
        </ProtectedRoute>
      } />

      {/* Catch-all */}
      <Route path="*" element={<NotFound />} />
    </Routes>
  );
}

function App() {
  usePWAUpdate();
  return (
    <QueryClientProvider client={queryClient}>
      <TooltipProvider>
        <Toaster />
        <Sonner />
        <BrowserRouter>
          <AuthProvider>
            <PWAInstallPrompt />
            <AppRoutes />
          </AuthProvider>
        </BrowserRouter>
      </TooltipProvider>
    </QueryClientProvider>
  );
}

export default App;

// @ts-nocheck
import { Client } from "@/pages/Clientes";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import {
  MoreVertical,
  Phone,
  Car,
  DollarSign,
  Calendar,
  Eye,
  Pencil,
  Trash2,
  MessageCircle,
  MapPin,
} from "lucide-react";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Button } from "@/components/ui/button";

interface ClientCardProps {
  client: Client;
  onViewProfile: (client: Client) => void;
  onEdit: (client: Client) => void;
  onDelete: (client: Client) => void;
  onWhatsApp: (phone: string) => void;
}

export function ClientCard({
  client,
  onViewProfile,
  onEdit,
  onDelete,
  onWhatsApp,
}: ClientCardProps) {
  const getInitials = (name: string) => {
    return name
      .split(" ")
      .map((n) => n[0])
      .join("")
      .slice(0, 2)
      .toUpperCase();
  };

  const getTierBadgeProps = (tier: string) => {
    switch (tier) {
      case "VIP":
        return "bg-amber-500/10 text-amber-500 border-amber-500/20";
      case "Comum":
        return "bg-primary/10 text-primary border-primary/20";
      case "Sem Compras":
        return "bg-zinc-500/10 text-zinc-500 border-zinc-500/20";
      default:
        return "bg-zinc-500/10 text-zinc-500 border-zinc-500/20";
    }
  };

  const getStatusBadgeProps = (status: string) => {
    if (status === "Ativo") {
      return "bg-green-500/10 text-green-500 border-green-500/20";
    }
    return "bg-red-500/10 text-red-500 border-red-500/20";
  };

  const handleCardClick = (e: React.MouseEvent) => {
    // Only trigger if not clicking a button/dropdown
    const target = e.target as HTMLElement;
    if (!target.closest("button") && !target.closest('[role="menuitem"]')) {
      onViewProfile(client);
    }
  };

  return (
    <Card 
      className="bg-card/50 border-border/50 hover:bg-card/80 hover:border-primary/30 transition-all duration-200 cursor-pointer overflow-hidden group"
      onClick={handleCardClick}
    >
      <CardContent className="p-0">
        <div className="p-4 space-y-4">
          {/* Header Row */}
          <div className="flex justify-between items-start">
            <div className="flex gap-3">
              <div 
                className={`w-12 h-12 rounded-full flex items-center justify-center flex-shrink-0 font-semibold text-lg
                  ${client.tier === "VIP" 
                    ? "bg-gradient-to-br from-amber-400 to-yellow-600 text-white shadow-sm" 
                    : client.status === "Inativo"
                      ? "bg-zinc-500/20 text-zinc-400"
                      : "bg-primary/20 text-primary"
                  }
                `}
              >
                {getInitials(client.name)}
              </div>
              <div>
                <h3 className="font-medium text-base text-foreground leading-tight line-clamp-1">
                  {client.name}
                </h3>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    onWhatsApp(client.phone);
                  }}
                  className="flex items-center gap-1.5 text-sm text-muted-foreground hover:text-green-500 mt-1 transition-colors"
                >
                  <Phone className="h-3.5 w-3.5" />
                  {client.phone}
                </button>
              </div>
            </div>

            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button 
                  variant="ghost" 
                  size="icon" 
                  className="h-8 w-8 text-muted-foreground hover:text-foreground opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity -mr-2 -mt-2"
                  onClick={(e) => e.stopPropagation()}
                >
                  <MoreVertical className="h-4 w-4" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end" className="w-48">
                <DropdownMenuItem onClick={() => onViewProfile(client)}>
                  <Eye className="h-4 w-4 mr-2" />
                  Ver Perfil
                </DropdownMenuItem>
                <DropdownMenuItem onClick={() => onWhatsApp(client.phone)}>
                  <MessageCircle className="h-4 w-4 mr-2 text-green-500" />
                  WhatsApp
                </DropdownMenuItem>
                <DropdownMenuItem onClick={() => onEdit(client)}>
                  <Pencil className="h-4 w-4 mr-2" />
                  Editar
                </DropdownMenuItem>
                <DropdownMenuItem 
                  onClick={() => onDelete(client)}
                  className="text-destructive focus:bg-destructive/10 focus:text-destructive"
                >
                  <Trash2 className="h-4 w-4 mr-2" />
                  Excluir
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>

          {/* Badges Row */}
          <div className="flex flex-wrap gap-2">
            <Badge variant="outline" className={`text-[10px] uppercase font-semibold tracking-wider ${getStatusBadgeProps(client.status)}`}>
              {client.status}
            </Badge>
            <Badge variant="outline" className={`text-[10px] uppercase font-semibold tracking-wider ${getTierBadgeProps(client.tier)}`}>
              {client.tier}
            </Badge>
            {client.origem && (
              <Badge variant="outline" className="text-[10px] uppercase font-semibold tracking-wider bg-card text-muted-foreground border-border/50 flex items-center gap-1">
                <MapPin className="h-3 w-3 -ml-0.5" />
                {client.origem}
              </Badge>
            )}
          </div>
        </div>

        {/* Footer Info */}
        <div className="bg-muted/20 p-4 border-t border-border/50 space-y-2">
          <div className="flex justify-between items-center text-sm">
            <div className="flex items-center gap-2 text-muted-foreground">
              <Car className="h-4 w-4 text-primary" />
              <span>{client.vehicles.length} veículo{client.vehicles.length !== 1 && 's'}</span>
            </div>
            <div className="flex items-center gap-2 font-medium">
              <DollarSign className="h-4 w-4 text-green-500" />
              <span className={client.total_spent > 0 ? "text-foreground" : "text-muted-foreground"}>
                R$ {client.total_spent.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}
              </span>
            </div>
          </div>
          <div className="flex items-center gap-2 text-xs text-muted-foreground pt-1">
            <Calendar className="h-3.5 w-3.5" />
            <span>
              Último serviço: {client.last_sale_date 
                ? format(new Date(client.last_sale_date), "dd/MM/yyyy")
                : "Nunca"
              }
            </span>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

import { useState, useMemo } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { ChevronLeft, ChevronRight } from "lucide-react";
import {
    BarChart,
    Bar,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Legend,
    ResponsiveContainer,
    LineChart,
    Line,
    Cell
} from "recharts";

interface ClientChartsTabProps {
    clients: any[];
    sales: any[];
}

export function ClientChartsTab({ clients, sales }: ClientChartsTabProps) {
    const [selectedDate, setSelectedDate] = useState(new Date());

    const handlePrevMonth = () => {
        setSelectedDate(prev => {
            const d = new Date(prev);
            d.setMonth(d.getMonth() - 1);
            return d;
        });
    };

    const handleNextMonth = () => {
        setSelectedDate(prev => {
            const d = new Date(prev);
            d.setMonth(d.getMonth() + 1);
            return d;
        });
    };

    const monthName = selectedDate.toLocaleString('pt-BR', { month: 'long', year: 'numeric' });
    const selectedYear = selectedDate.getFullYear();

    // Mapear primeira compra de cada cliente para determinar "Novo" vs "Retorno"
    const clientFirstSaleMap = useMemo(() => {
        const map = new Map<number, Date>();
        sales.forEach(sale => {
            const saleDate = new Date(sale.created_at);
            const existing = map.get(sale.client_id);
            if (!existing || saleDate < existing) {
                map.set(sale.client_id, saleDate);
            }
        });
        return map;
    }, [sales]);

    // Gráfico 1: Mensal (Novos vs Retorno)
    const monthlyStatusData = useMemo(() => {
        const month = selectedDate.getMonth();
        const year = selectedDate.getFullYear();

        const clientsInMonth = new Set<number>();
        sales.forEach(s => {
            const d = new Date(s.created_at);
            if (d.getMonth() === month && d.getFullYear() === year) {
                clientsInMonth.add(s.client_id);
            }
        });

        let novos = 0;
        let retorno = 0;

        clientsInMonth.forEach(clientId => {
            const firstSale = clientFirstSaleMap.get(clientId);
            if (firstSale && firstSale.getMonth() === month && firstSale.getFullYear() === year) {
                novos++;
            } else {
                retorno++;
            }
        });

        return [
            { name: "Novos", value: novos, fill: "#3b82f6" }, // blue-500
            { name: "Retornos", value: retorno, fill: "#10b981" } // emerald-500
        ];
    }, [sales, selectedDate, clientFirstSaleMap]);

    // Gráfico 2: Mensal (Origens)
    const monthlyOriginsData = useMemo(() => {
        const month = selectedDate.getMonth();
        const year = selectedDate.getFullYear();

        const clientsInMonth = new Set<number>();
        sales.forEach(s => {
            const d = new Date(s.created_at);
            if (d.getMonth() === month && d.getFullYear() === year) {
                clientsInMonth.add(s.client_id);
            }
        });

        const originCounts: Record<string, number> = {};
        clientsInMonth.forEach(clientId => {
            const client = clients.find(c => c.id === clientId);
            // Fallback default or mapped from standard fields
            const origin = (client?.origem && client.origem.trim() !== "") ? client.origem : "Outros";
            originCounts[origin] = (originCounts[origin] || 0) + 1;
        });

        const colors = ["#8b5cf6", "#ec4899", "#f59e0b", "#06b6d4", "#6366f1", "#f43f5e", "#14b8a6"];

        return Object.entries(originCounts)
            .map(([name, value], index) => ({
                name,
                value,
                fill: colors[index % colors.length]
            }))
            .sort((a, b) => b.value - a.value);
    }, [sales, clients, selectedDate]);

    // Gráfico 3: Anual (3 linhas)
    const annualData = useMemo(() => {
        const year = selectedDate.getFullYear();
        const months = ["Jan", "Fev", "Mar", "Abr", "Mai", "Jun", "Jul", "Ago", "Set", "Out", "Nov", "Dez"];

        return months.map((monthLabel, index) => {
            const clientsInThisMonth = new Set<number>();
            sales.forEach(s => {
                const d = new Date(s.created_at);
                if (d.getMonth() === index && d.getFullYear() === year) {
                    clientsInThisMonth.add(s.client_id);
                }
            });

            let novos = 0;
            let retornos = 0;

            clientsInThisMonth.forEach(clientId => {
                const firstSale = clientFirstSaleMap.get(clientId);
                if (firstSale && firstSale.getMonth() === index && firstSale.getFullYear() === year) {
                    novos++;
                } else {
                    retornos++;
                }
            });

            return {
                name: monthLabel,
                Novos: novos,
                Retornos: retornos,
                Total: novos + retornos
            };
        });
    }, [sales, selectedDate, clientFirstSaleMap]);

    // Formatação em maiúscula para exibição
    const capitalizedMonthName = monthName.charAt(0).toUpperCase() + monthName.slice(1);

    return (
        <div className="space-y-6">
            {/* Seletor de Mês */}
            <div className="flex justify-center items-center gap-4 mb-6">
                <Button variant="outline" size="icon" onClick={handlePrevMonth}>
                    <ChevronLeft className="h-4 w-4" />
                </Button>
                <div className="text-xl font-medium w-[200px] text-center">
                    {capitalizedMonthName}
                </div>
                <Button variant="outline" size="icon" onClick={handleNextMonth}>
                    <ChevronRight className="h-4 w-4" />
                </Button>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {/* Gráfico 1 */}
                <Card className="bg-card/50 border-border/50">
                    <CardHeader>
                        <CardTitle className="text-lg font-medium text-muted-foreground">
                            Novos vs Retornos ({capitalizedMonthName})
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="h-[300px]">
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart
                                    data={monthlyStatusData}
                                    layout="vertical"
                                    margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
                                >
                                    <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#333" />
                                    <XAxis type="number" stroke="#888888" fontSize={12} tickLine={false} axisLine={false} />
                                    <YAxis dataKey="name" type="category" stroke="#888888" fontSize={12} tickLine={false} axisLine={false} />
                                    <Tooltip
                                        cursor={{ fill: 'rgba(255,255,255,0.05)' }}
                                        contentStyle={{ backgroundColor: '#1f2937', border: 'none', borderRadius: '8px', color: '#fff' }}
                                    />
                                    <Bar dataKey="value" radius={[0, 4, 4, 0]} maxBarSize={50}>
                                        {
                                            monthlyStatusData.map((entry, index) => (
                                                <Cell key={`cell-${index}`} fill={entry.fill} />
                                            ))
                                        }
                                    </Bar>
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    </CardContent>
                </Card>

                {/* Gráfico 2 */}
                <Card className="bg-card/50 border-border/50">
                    <CardHeader>
                        <CardTitle className="text-lg font-medium text-muted-foreground">
                            Origens dos Clientes ({capitalizedMonthName})
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="h-[300px]">
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart
                                    data={monthlyOriginsData}
                                    layout="vertical"
                                    margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
                                >
                                    <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#333" />
                                    <XAxis type="number" stroke="#888888" fontSize={12} tickLine={false} axisLine={false} />
                                    <YAxis dataKey="name" type="category" width={100} stroke="#888888" fontSize={12} tickLine={false} axisLine={false} />
                                    <Tooltip
                                        cursor={{ fill: 'rgba(255,255,255,0.05)' }}
                                        contentStyle={{ backgroundColor: '#1f2937', border: 'none', borderRadius: '8px', color: '#fff' }}
                                    />
                                    <Bar dataKey="value" radius={[0, 4, 4, 0]} maxBarSize={40}>
                                        {
                                            monthlyOriginsData.map((entry, index) => (
                                                <Cell key={`cell-${index}`} fill={entry.fill} />
                                            ))
                                        }
                                    </Bar>
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    </CardContent>
                </Card>
            </div>

            {/* Gráfico Anual (Linhas) */}
            <Card className="bg-card/50 border-border/50 mt-6">
                <CardHeader>
                    <CardTitle className="text-lg font-medium text-muted-foreground">
                        Acompanhamento Mensal ({selectedYear})
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    <div className="h-[400px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <LineChart
                                data={annualData}
                                margin={{ top: 20, right: 30, left: 20, bottom: 5 }}
                            >
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#333" />
                                <XAxis dataKey="name" stroke="#888888" fontSize={12} tickLine={false} axisLine={false} dy={10} />
                                <YAxis stroke="#888888" fontSize={12} tickLine={false} axisLine={false} dx={-10} />
                                <Tooltip
                                    contentStyle={{ backgroundColor: '#1f2937', border: 'none', borderRadius: '8px', color: '#fff' }}
                                />
                                <Legend wrapperStyle={{ paddingTop: '20px' }} />
                                <Line
                                    type="monotone"
                                    dataKey="Novos"
                                    stroke="#3b82f6"
                                    strokeWidth={3}
                                    dot={{ r: 4, strokeWidth: 2 }}
                                    activeDot={{ r: 6 }}
                                />
                                <Line
                                    type="monotone"
                                    dataKey="Retornos"
                                    stroke="#10b981"
                                    strokeWidth={3}
                                    dot={{ r: 4, strokeWidth: 2 }}
                                    activeDot={{ r: 6 }}
                                />
                                <Line
                                    type="monotone"
                                    dataKey="Total"
                                    stroke="#f59e0b"
                                    strokeWidth={3}
                                    dot={{ r: 4, strokeWidth: 2 }}
                                    activeDot={{ r: 6 }}
                                />
                            </LineChart>
                        </ResponsiveContainer>
                    </div>
                </CardContent>
            </Card>
        </div>
    );
}

﻿// @ts-nocheck
import { useState, useEffect, useMemo } from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import {
  MessageCircle,
  Plus,
  ShoppingBag,
  Car,
  Phone,
  MapPin,
  Calendar,
  DollarSign,
  Search,
  Pencil,
  Trash2,
  X,
  Loader2,
} from "lucide-react";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { SaleWithDetails } from "@/types/sales";
import SaleDetailsModal from "@/pages/Vendas/components/SaleDetailsModal";

interface Vehicle {
  id: number;
  brand: string;
  model: string;
  year: number | null;
  plate: string | null;
  size: string | null;
}

interface ClientData {
  id: number;
  name: string;
  phone: string;
  email?: string | null;
  cpf_cnpj?: string | null;
  origem?: string | null;
  created_at: string | null;
  vehicles: Vehicle[];
  total_spent: number;
  sales_count: number;
  last_sale_date?: string | null;
  status?: string;
  tier?: string;
}

interface ProfileSale {
  id: number;
  sale_date: string;
  total: number;
  is_open: boolean | null;
  vehicle_id: number | null;
  payment_method: string | null;
  sale_items: {
    id: number;
    service: { name: string } | null;
  }[];
}

interface ClientProfileModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  client: ClientData;
  onEdit: () => void;
  onCreateSale?: () => void;
  onAddToSpace?: () => void;
  onDelete?: (client: ClientData) => void;
}

export function ClientProfileModal({
  open,
  onOpenChange,
  client,
  onEdit,
  onCreateSale,
  onAddToSpace,
  onDelete,
}: ClientProfileModalProps) {
  const { user } = useAuth();
  const [vehicleSearch, setVehicleSearch] = useState("");
  const [selectedVehicle, setSelectedVehicle] = useState<Vehicle | null>(null);
  const [clientSales, setClientSales] = useState<ProfileSale[]>([]);
  const [selectedSaleDetails, setSelectedSaleDetails] = useState<SaleWithDetails | null>(null);
  const [loadingSaleId, setLoadingSaleId] = useState<number | null>(null);
  const [loadingSales, setLoadingSales] = useState(false);

  // Fetch real sales from Supabase when modal opens
  useEffect(() => {
    if (open && client?.id) {
      fetchClientSales();
    }
    if (!open) {
      // Reset state when modal closes
      setClientSales([]);
      setSelectedVehicle(null);
      setVehicleSearch("");
      setLoadingSaleId(null);
    }
  }, [open, client?.id]);

  const fetchClientSales = async () => {
    if (!user?.id) return;

    setLoadingSales(true);
    try {
      const { data, error } = await supabase
        .from("sales")
        .select(`
          id,
          sale_date,
          total,
          is_open,
          vehicle_id,
          payment_method,
          sale_items(
            id,
            service:services(name)
          )
        `)
        .eq("client_id", client.id)
        .is("deleted_at", null)
        .order("sale_date", { ascending: false });

      if (error) {
        console.error("Error fetching client sales:", error);
      } else {
        setClientSales(data || []);
      }
    } catch (err) {
      console.error("Error fetching client sales:", err);
    } finally {
      setLoadingSales(false);
    }
  };

  // Filter sales by vehicle if selected
  const filteredSales = useMemo(() => {
    if (!selectedVehicle) return clientSales;
    return clientSales.filter(sale => sale.vehicle_id === selectedVehicle.id);
  }, [clientSales, selectedVehicle]);

  // Filter vehicles
  const filteredVehicles = useMemo(() => {
    if (!vehicleSearch) return client.vehicles;
    const term = vehicleSearch.toLowerCase();
    return client.vehicles.filter(v =>
      (v.brand?.toLowerCase() || "").includes(term) ||
      (v.model?.toLowerCase() || "").includes(term) ||
      (v.plate?.toLowerCase() || "").includes(term)
    );
  }, [client.vehicles, vehicleSearch]);

  const openWhatsApp = () => {
    const cleanPhone = client.phone.replace(/\D/g, '');
    const url = `https://wa.me/${cleanPhone}`;
    window.location.href = url;
  };

  const getServiceNames = (saleItems: ProfileSale["sale_items"]) => {
    if (!saleItems || saleItems.length === 0) return "Serviço";
    return saleItems
      .map(item => item.service?.name || "Serviço")
      .join(", ");
  };

  const handleOpenSaleDetails = async (saleId: number) => {
    setLoadingSaleId(saleId);
    try {
      const { data, error } = await supabase
        .from("sales")
        .select(`
          *,
          client:clients(id, name, phone),
          vehicle:vehicles(id, brand, model, year, plate, size),
          sale_items(
            id, service_id, quantity, unit_price, total_price,
            service:services(id, name, base_price)
          )
        `)
        .eq("id", saleId)
        .single();

      if (error) {
        console.error("Error fetching sale details:", error);
        return;
      }

      if (data) {
        const saleDetails: SaleWithDetails = {
          id: data.id,
          client_id: data.client_id,
          vehicle_id: data.vehicle_id,
          sale_date: data.sale_date,
          subtotal: data.subtotal,
          discount: data.discount,
          total: data.total,
          payment_method: data.payment_method,
          status: data.status,
          is_open: data.is_open,
          observations: data.observations,
          created_at: data.created_at,
          client: data.client,
          vehicle: data.vehicle,
          sale_items: data.sale_items || [],
        };
        setSelectedSaleDetails(saleDetails);
      }
    } catch (err) {
      console.error("Error fetching sale details:", err);
    } finally {
      setLoadingSaleId(null);
    }
  };

  return (
    <>
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="bg-card border-border max-w-2xl max-h-[90vh] overflow-hidden flex flex-col">
        <DialogHeader className="flex-shrink-0">
          <div className="flex items-center gap-4">
            <div className="w-16 h-16 rounded-full bg-primary/20 flex items-center justify-center">
              <span className="text-2xl font-semibold text-primary">
                {client.name.split(' ').map(n => n[0]).join('').slice(0, 2)}
              </span>
            </div>
            <div>
              <DialogTitle className="text-xl">{client.name}</DialogTitle>
              <p className="text-sm text-muted-foreground">
                Cliente desde {client.created_at ? format(new Date(client.created_at), "MMM yyyy", { locale: ptBR }) : "—"}
              </p>
            </div>
          </div>
        </DialogHeader>

        <div className="flex-1 overflow-y-auto pr-4">
          <div className="space-y-6">
            {/* Quick Actions */}
            <div className="flex flex-wrap gap-2">
              <Button 
                onClick={openWhatsApp}
                className="bg-green-600 hover:bg-green-700 text-white"
              >
                <MessageCircle className="h-4 w-4 mr-2" />
                Chamar no Whatsapp
              </Button>
              <Button 
                variant="outline" 
                className="border-blue-500 text-blue-500 hover:bg-blue-500/10"
                onClick={onCreateSale}
              >
                <Plus className="h-4 w-4 mr-2" />
                Criar venda com cliente
              </Button>
              <Button 
                variant="outline" 
                className="border-blue-500 text-blue-500 hover:bg-blue-500/10"
                onClick={onAddToSpace}
              >
                <ShoppingBag className="h-4 w-4 mr-2" />
                Adicionar na vaga do espaço
              </Button>
            </div>

            {/* Client Info */}
            <div className="space-y-2">
              <div className="flex items-center gap-2 text-sm">
                <Phone className="h-4 w-4 text-blue-500" />
                <span className="text-foreground">{client.phone}</span>
              </div>
              {client.origem && (
                <div className="flex items-center gap-2 text-sm">
                  <MapPin className="h-4 w-4 text-blue-500" />
                  <span className="text-foreground">{client.origem}</span>
                </div>
              )}
            </div>

            {/* Vehicles Section */}
            <div className="space-y-3">
              <h3 className="text-sm font-medium text-muted-foreground uppercase tracking-wide">
                Gestão de Veículos
              </h3>
              
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Buscar veículo por marca, modelo, placa..."
                  value={vehicleSearch}
                  onChange={(e) => setVehicleSearch(e.target.value)}
                  className="pl-10 bg-background border-border"
                />
              </div>

              {selectedVehicle && (
                <div className="flex items-center gap-2 p-2 bg-primary/10 rounded-lg">
                  <span className="text-sm text-foreground">
                    Filtrando por: {selectedVehicle.brand} {selectedVehicle.model}
                  </span>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => setSelectedVehicle(null)}
                    className="h-6 w-6 p-0"
                  >
                    <X className="h-4 w-4" />
                  </Button>
                </div>
              )}

              <div className="grid gap-2">
                {filteredVehicles.map((vehicle) => (
                  <button
                    key={vehicle.id}
                    onClick={() => setSelectedVehicle(vehicle.id === selectedVehicle?.id ? null : vehicle)}
                    className={`flex items-center gap-3 p-3 rounded-lg border transition-colors text-left w-full ${
                      selectedVehicle?.id === vehicle.id
                        ? 'border-primary bg-primary/5'
                        : 'border-border bg-background hover:border-primary/50'
                    }`}
                  >
                    <Car className="h-5 w-5 text-muted-foreground" />
                    <div className="flex-1">
                      <p className="font-medium text-foreground">
                        {vehicle.brand} {vehicle.model}
                      </p>
                      <p className="text-sm text-muted-foreground">
                        {vehicle.year} • {vehicle.plate || "S/ Placa"} • Porte {vehicle.size || "—"}
                      </p>
                    </div>
                  </button>
                ))}

                {filteredVehicles.length === 0 && (
                  <p className="text-sm text-muted-foreground text-center py-4">
                    Nenhum veículo encontrado
                  </p>
                )}
              </div>
            </div>

            {/* Sales History */}
            <div className="space-y-3">
              <div className="flex items-center justify-between">
                <h3 className="text-sm font-medium text-muted-foreground uppercase tracking-wide">
                  Histórico de Vendas
                </h3>
                {selectedVehicle && (
                  <span className="text-xs text-primary">
                    Filtrando por {selectedVehicle.model}
                  </span>
                )}
              </div>

              {!selectedVehicle && (
                <p className="text-xs text-muted-foreground">
                  Nenhum filtro aplicado. Clique em um veículo para filtrar.
                </p>
              )}

              {loadingSales ? (
                <div className="space-y-2">
                  <Skeleton className="h-16 w-full" />
                  <Skeleton className="h-16 w-full" />
                </div>
              ) : (
                <div className="space-y-2">
                  {filteredSales.map((sale) => (
                    <div
                      key={sale.id}
                      className="flex items-center gap-3 p-3 rounded-lg border border-border bg-background hover:border-primary/50 transition-colors cursor-pointer"
                      onClick={() => handleOpenSaleDetails(sale.id)}
                    >
                      <div className="w-10 h-10 rounded-full bg-green-500/20 flex items-center justify-center flex-shrink-0">
                        {loadingSaleId === sale.id ? (
                          <Loader2 className="h-5 w-5 text-green-500 animate-spin" />
                        ) : (
                          <DollarSign className="h-5 w-5 text-green-500" />
                        )}
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className="font-medium text-foreground">
                          Venda Nº {sale.id}
                        </p>
                        <p className="text-sm text-muted-foreground truncate">
                          {format(new Date(sale.sale_date + 'T12:00:00'), "dd/MM/yyyy")} • {getServiceNames(sale.sale_items).slice(0, 40)}{getServiceNames(sale.sale_items).length > 40 ? '...' : ''}
                        </p>
                      </div>
                      <div className="text-right flex-shrink-0">
                        <p className="font-semibold text-foreground">
                          R$ {sale.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                        </p>
                        <Badge 
                          variant={!sale.is_open ? 'default' : 'secondary'}
                          className={!sale.is_open ? 'bg-green-500/20 text-green-500' : 'bg-orange-500/20 text-orange-500'}
                        >
                          {sale.is_open ? 'Aberta' : 'Fechada'}
                        </Badge>
                      </div>
                    </div>
                  ))}

                  {filteredSales.length === 0 && (
                    <p className="text-sm text-muted-foreground text-center py-4">
                      Nenhuma venda encontrada
                    </p>
                  )}
                </div>
              )}
            </div>

            {/* Statistics */}
            <div className="space-y-3 p-4 rounded-lg bg-background border border-border">
              <h3 className="text-sm font-medium text-muted-foreground uppercase tracking-wide">
                Estatísticas
              </h3>
              <div className="grid gap-2 text-sm">
                <div className="flex items-center gap-2">
                  <Calendar className="h-4 w-4 text-blue-500" />
                  <span className="text-muted-foreground">Criado em:</span>
                  <span className="text-foreground">
                    {client.created_at ? format(new Date(client.created_at), "dd/MM/yyyy") : "—"}
                  </span>
                </div>
                <div className="flex items-center gap-2">
                  <Car className="h-4 w-4 text-blue-500" />
                  <span className="text-muted-foreground">Cliente com</span>
                  <span className="text-foreground">{client.vehicles.length} veículos</span>
                </div>
                <div className="flex items-center gap-2">
                  <ShoppingBag className="h-4 w-4 text-blue-500" />
                  <span className="text-muted-foreground">Foram</span>
                  <span className="text-foreground">{client.sales_count} vendas realizadas</span>
                </div>
                <div className="flex items-center gap-2">
                  <DollarSign className="h-4 w-4 text-blue-500" />
                  <span className="text-muted-foreground">Total gasto:</span>
                  <span className="text-foreground font-semibold">
                    R$ {client.total_spent.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                  </span>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Footer Actions */}
        <div className="flex gap-2 pt-4 border-t border-border flex-shrink-0">
          <Button 
            onClick={onEdit}
            className="flex-1 bg-[#c6e60b] hover:bg-[#b0cc0a] text-black font-semibold"
          >
            <Pencil className="h-4 w-4 mr-2" />
            Editar
          </Button>
          <Button 
            variant="destructive"
            className="flex-1"
            onClick={() => onDelete?.(client)}
          >
            <Trash2 className="h-4 w-4 mr-2" />
            Excluir
          </Button>
        </div>
      </DialogContent>
    </Dialog>

    {/* Sale Details Modal */}
    <SaleDetailsModal
      open={!!selectedSaleDetails}
      onOpenChange={(open) => {
        if (!open) {
          setSelectedSaleDetails(null);
          // Refresh sales list in case something was edited
          fetchClientSales();
        }
      }}
      sale={selectedSaleDetails}
    />
    </>
  );
}

﻿import { useState } from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { 
  User, 
  Plus, 
  Minus,
  Car,
  Pencil,
  Trash2
} from "lucide-react";
import { Client, Vehicle } from "@/lib/mockData";
import NewVehicleModal from "@/pages/Vendas/components/NewVehicleModal";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface EditClientModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  client: Client;
  onSave: () => void;
}

import { ORIGIN_OPTIONS, ClientOrigin } from "@/constants/origins";

export function EditClientModal({
  open,
  onOpenChange,
  client,
  onSave,
}: EditClientModalProps) {
  const [name, setName] = useState(client.name);
  const [phone, setPhone] = useState(client.phone);
  const [email, setEmail] = useState(client.email);
  const [cpf, setCpf] = useState(client.cpf || '');
  const [origem, setOrigem] = useState<ClientOrigin>(client.origem as ClientOrigin);
  const [vehicles, setVehicles] = useState<Vehicle[]>(client.vehicles);
  
  // Field visibility
  const [showCpf, setShowCpf] = useState(!!client.cpf);
  const [showEmail, setShowEmail] = useState(!!client.email);
  const [showOrigem, setShowOrigem] = useState(true);

  const [showVehicleModal, setShowVehicleModal] = useState(false);
  const [editingVehicle, setEditingVehicle] = useState<Vehicle | null>(null);

  const formatPhone = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 2) return `+${numbers}`;
    if (numbers.length <= 4) return `+${numbers.slice(0, 2)} (${numbers.slice(2)}`;
    if (numbers.length <= 9) return `+${numbers.slice(0, 2)} (${numbers.slice(2, 4)}) ${numbers.slice(4)}`;
    return `+${numbers.slice(0, 2)} (${numbers.slice(2, 4)}) ${numbers.slice(4, 9)}-${numbers.slice(9, 13)}`;
  };

  const formatCpf = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 3) return numbers;
    if (numbers.length <= 6) return `${numbers.slice(0, 3)}.${numbers.slice(3)}`;
    if (numbers.length <= 9) return `${numbers.slice(0, 3)}.${numbers.slice(3, 6)}.${numbers.slice(6)}`;
    return `${numbers.slice(0, 3)}.${numbers.slice(3, 6)}.${numbers.slice(6, 9)}-${numbers.slice(9, 11)}`;
  };

  const handleAddVehicle = (vehicle: Vehicle) => {
    if (editingVehicle) {
      setVehicles(vehicles.map(v => v.id === editingVehicle.id ? vehicle : v));
      setEditingVehicle(null);
    } else {
      setVehicles([...vehicles, { ...vehicle, id: Date.now() }]);
    }
    setShowVehicleModal(false);
  };

  const handleRemoveVehicle = (vehicleId: number) => {
    setVehicles(vehicles.filter(v => v.id !== vehicleId));
  };

  const handleSave = async () => {
    try {
      const updateData = {
        name,
        phone,
        email: email || null,
        cpf_cnpj: cpf || null,
        origem,
      };

      const { error: clientError } = await supabase
        .from('clients')
        .update(updateData)
        .eq('id', client.id);

      if (clientError) throw clientError;

      const existingVehicleIds = client.vehicles.map(v => v.id);
      const currentVehicleIds = vehicles.map(v => v.id);
      
      const removedIds = existingVehicleIds.filter(id => !currentVehicleIds.includes(id));
      
      if (removedIds.length > 0) {
        const { error: deleteError } = await supabase
          .from('vehicles')
          .delete()
          .in('id', removedIds);
        if (deleteError) throw deleteError;
      }

      for (const vehicle of vehicles) {
        if (existingVehicleIds.includes(vehicle.id)) {
          const { error: updateError } = await supabase
            .from('vehicles')
            .update({
              plate: vehicle.plate,
              brand: vehicle.brand,
              model: vehicle.model,
              year: vehicle.year,
              size: vehicle.size,
            })
            .eq('id', vehicle.id);
          if (updateError) throw updateError;
        } else {
          const { error: insertError } = await supabase
            .from('vehicles')
            .insert({
              client_id: client.id,
              company_id: (client as any).company_id,
              plate: vehicle.plate,
              brand: vehicle.brand,
              model: vehicle.model,
              year: vehicle.year,
              size: vehicle.size,
            });
          if (insertError) throw insertError;
        }
      }

      onSave();
    } catch (error) {
      console.error("Error saving client:", error);
      toast.error("Erro ao salvar alterações");
    }
  };

  return (
    <>
      <Dialog open={open} onOpenChange={onOpenChange}>
        <DialogContent className="bg-card border-border max-w-lg max-h-[90vh] overflow-hidden flex flex-col">
          <DialogHeader className="flex-shrink-0">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-full bg-destructive/20 flex items-center justify-center">
                <User className="h-5 w-5 text-destructive" />
              </div>
              <div>
                <DialogTitle>Editar cliente</DialogTitle>
                <p className="text-sm text-muted-foreground">
                  Atualize os dados do cliente
                </p>
              </div>
            </div>
          </DialogHeader>

          <div className="flex-1 overflow-y-auto pr-4">
            <div className="space-y-4">
              {/* Name */}
              <div className="space-y-2">
                <Label className="text-foreground">
                  Nome completo <span className="text-destructive">*</span>
                </Label>
                <Input
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="Nome do cliente"
                  className="bg-background border-border focus:border-primary"
                />
              </div>

              {/* Phone */}
              <div className="space-y-2">
                <Label className="text-foreground">
                  WhatsApp <span className="text-destructive">*</span>
                </Label>
                <Input
                  value={phone}
                  onChange={(e) => setPhone(formatPhone(e.target.value))}
                  placeholder="+55 (00) 00000-0000"
                  className="bg-background border-border focus:border-primary"
                />
              </div>

              {/* Vehicles */}
              <div className="space-y-2">
                <Label className="text-foreground">Veículos</Label>
                <div className="space-y-2">
                  {vehicles.map((vehicle) => (
                    <div
                      key={vehicle.id}
                      className="flex items-center gap-3 p-3 rounded-lg border border-border bg-background"
                    >
                      <Car className="h-5 w-5 text-muted-foreground" />
                      <div className="flex-1">
                        <p className="font-medium text-foreground text-sm">
                          {vehicle.brand} {vehicle.model}
                        </p>
                        <p className="text-xs text-muted-foreground">
                          {vehicle.year} • {vehicle.plate}
                        </p>
                      </div>
                      <Button
                        type="button"
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8"
                        onClick={() => {
                          setEditingVehicle(vehicle);
                          setShowVehicleModal(true);
                        }}
                      >
                        <Pencil className="h-4 w-4" />
                      </Button>
                      <Button
                        type="button"
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8 text-destructive"
                        onClick={() => handleRemoveVehicle(vehicle.id)}
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </div>
                  ))}

                  <Button
                    type="button"
                    variant="outline"
                    className="w-full border-primary text-primary hover:bg-primary/10"
                    onClick={() => {
                      setEditingVehicle(null);
                      setShowVehicleModal(true);
                    }}
                  >
                    <Plus className="h-4 w-4 mr-2" />
                    Novo veículo
                  </Button>
                </div>
              </div>

              {/* Field Toggles */}
              <div className="flex flex-wrap gap-2 py-2">
                <Badge
                  variant="secondary"
                  className={`cursor-pointer ${showCpf ? 'bg-foreground text-background' : 'bg-muted text-muted-foreground'}`}
                  onClick={() => setShowCpf(!showCpf)}
                >
                  {showCpf ? <Minus className="h-3 w-3 mr-1" /> : <Plus className="h-3 w-3 mr-1" />}
                  CPF
                </Badge>
                <Badge
                  variant="secondary"
                  className={`cursor-pointer ${showEmail ? 'bg-foreground text-background' : 'bg-muted text-muted-foreground'}`}
                  onClick={() => setShowEmail(!showEmail)}
                >
                  {showEmail ? <Minus className="h-3 w-3 mr-1" /> : <Plus className="h-3 w-3 mr-1" />}
                  E-mail
                </Badge>
                <Badge
                  variant="secondary"
                  className={`cursor-pointer ${showOrigem ? 'bg-foreground text-background' : 'bg-muted text-muted-foreground'}`}
                  onClick={() => setShowOrigem(!showOrigem)}
                >
                  {showOrigem ? <Minus className="h-3 w-3 mr-1" /> : <Plus className="h-3 w-3 mr-1" />}
                  Origem
                </Badge>
              </div>

              {/* Conditional Fields */}
              {showCpf && (
                <div className="space-y-2">
                  <Label className="text-foreground">CPF</Label>
                  <Input
                    value={cpf}
                    onChange={(e) => setCpf(formatCpf(e.target.value))}
                    placeholder="000.000.000-00"
                    maxLength={14}
                    className="bg-background border-border focus:border-primary"
                  />
                </div>
              )}

              {showEmail && (
                <div className="space-y-2">
                  <Label className="text-foreground">E-mail</Label>
                  <Input
                    type="email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    placeholder="email@exemplo.com"
                    className="bg-background border-border focus:border-primary"
                  />
                </div>
              )}

              {showOrigem && (
                <div className="space-y-2">
                  <Label className="text-foreground">Origem</Label>
                  <Select value={origem} onValueChange={(v) => setOrigem(v as ClientOrigin)}>
                    <SelectTrigger className="bg-background border-border">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent className="bg-card border-border">
                      {ORIGIN_OPTIONS.map((option) => (
                        <SelectItem key={option} value={option}>
                          {option}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              )}
            </div>
          </div>

          {/* Footer */}
          <div className="pt-4 border-t border-border flex-shrink-0">
            <Button
              onClick={handleSave}
              className="w-full bg-primary text-primary-foreground hover:bg-primary/90"
              disabled={!name || !phone}
            >
              Salvar alterações
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      <NewVehicleModal
        open={showVehicleModal}
        onOpenChange={setShowVehicleModal}
        onVehicleCreated={handleAddVehicle}
        editVehicle={editingVehicle}
      />
    </>
  );
}

