﻿import React, { useState, useEffect } from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { DollarSign, Plus, Check, Loader2 } from "lucide-react";
import { PaymentBlock, SalePayment } from "@/pages/Vendas/components/PaymentBlock";
import { toast } from "sonner";
import { cn } from "@/lib/utils";
import { supabase } from "@/integrations/supabase/client";

interface ConfirmPurchasePaymentModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  installmentAmount: number;
  companyId: number;
  defaultAccountId: number | null;
  purchasePaymentMethod: string;
  onConfirm: (payments: SalePayment[]) => Promise<void>;
}

export function ConfirmPurchasePaymentModal({
  open,
  onOpenChange,
  installmentAmount,
  companyId,
  defaultAccountId,
  purchasePaymentMethod,
  onConfirm
}: ConfirmPurchasePaymentModalProps) {
  const [payments, setPayments] = useState<SalePayment[]>([]);
  const [isPaying, setIsPaying] = useState(false);

  // Inicializar o pagamento com o valor da parcela e conta padrão da compra
  useEffect(() => {
    if (open) {
      setPayments([
        {
          tempId: Math.random().toString(36).substring(2, 9),
          payment_method: "Boleto",
          amount: installmentAmount,
          account_id: defaultAccountId,
          machine_id: null,
          installments: 1,
          due_date: new Date().toISOString(),
          status: 'received'
        }
      ]);
    }
  }, [open, installmentAmount, defaultAccountId, purchasePaymentMethod]);

  const handleAddPayment = () => {
    const paidTotal = payments.reduce((acc, curr) => acc + curr.amount, 0);
    const remaining = Math.max(0, installmentAmount - paidTotal);

    setPayments([
      ...payments,
      {
        tempId: Math.random().toString(36).substring(2, 9),
        payment_method: "Boleto",
        amount: remaining,
        account_id: payments[0]?.account_id || defaultAccountId,
        machine_id: null,
        installments: 1,
        due_date: new Date().toISOString(),
        status: 'received'
      }
    ]);
  };

  const handleUpdatePayment = (updated: SalePayment) => {
    setPayments(payments.map(item => item.tempId === updated.tempId ? updated : item));
  };

  const handleRemovePayment = (tempId: string) => {
    setPayments(payments.filter(item => item.tempId !== tempId));
  };

  const handleConfirm = async () => {
    if (payments.length === 0) {
      toast.error("Adicione pelo menos uma forma de pagamento");
      return;
    }

    if (payments.some(p => !p.account_id)) {
      toast.error("Selecione a conta para todos os pagamentos");
      return;
    }

    const paidTotal = payments.reduce((acc, p) => acc + p.amount, 0);
    if (paidTotal <= 0) {
      toast.error("O valor total pago deve ser maior que zero.");
      return;
    }

    const uniqueAccountIds = Array.from(new Set(payments.map(p => p.account_id).filter(Boolean)));
    if (uniqueAccountIds.length > 0) {
      const { data } = await supabase
        .from("accounts")
        .select("id, name, accepted_payment_methods")
        .in("id", uniqueAccountIds);

      const accountsToCheck = data as any[] | null;
      if (accountsToCheck) {
        for (const p of payments) {
          if (p.account_id && p.payment_method !== "Crédito" && p.payment_method !== "Débito") {
            const account = accountsToCheck.find(a => a.id === p.account_id);
            if (account && account.accepted_payment_methods && !account.accepted_payment_methods.includes(p.payment_method)) {
              toast.error(`A forma de pagamento "${p.payment_method}" não é aceita pela conta "${account.name}".`);
              return;
            }
          }
        }
      }
    }

    setIsPaying(true);
    try {
      await onConfirm(payments);
      onOpenChange(false);
    } catch (error) {
      console.error("Erro ao confirmar pagamento:", error);
    } finally {
      setIsPaying(false);
    }
  };

  const paidTotal = payments.reduce((acc, p) => acc + p.amount, 0);
  const diff = paidTotal - installmentAmount;
  const isBalanced = Math.abs(diff) < 0.01;
  const isExcess = diff > 0.01;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="w-[95vw] max-w-xl rounded-lg max-h-[90vh] overflow-y-auto bg-background text-foreground border border-border">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2 text-xl font-bold">
            <DollarSign className="h-5 w-5 text-green-500" />
            Confirmar Pagamento
          </DialogTitle>
          <DialogDescription className="text-muted-foreground">
            Confirme as formas de pagamento antes de registrar o recebimento.
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-5 py-2">
          {/* Seção de Pagamentos */}
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <Label className="text-sm font-semibold">Pagamentos</Label>
            </div>

            <div className="space-y-3">
              {payments.map((p, index) => (
                <PaymentBlock
                  key={p.tempId}
                  payment={p}
                  isFirst={index === 0}
                  companyId={companyId}
                  totalRemaining={installmentAmount - payments.reduce((acc, curr, i) => i < index ? acc + curr.amount : acc, 0)}
                  onUpdate={handleUpdatePayment}
                  onRemove={() => handleRemovePayment(p.tempId)}
                  removePaymentMethod={true}
                  hideInstallments={true}
                />
              ))}
            </div>

            {/* Resumo do total pago vs total da parcela */}
            <div className={cn(
              "p-3 rounded-lg text-sm font-medium space-y-1 border",
              isBalanced
                ? "bg-green-500/10 text-green-500 border-green-500/20"
                : isExcess
                  ? "bg-amber-500/10 text-amber-500 border-amber-500/20"
                  : "bg-red-500/10 text-red-500 border-red-500/20"
            )}>
              <div className="flex justify-between items-center">
                <span>Total Pago: R$ {paidTotal.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                <span>Total Parcela: R$ {installmentAmount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
              </div>
              {!isBalanced && (
                <div className={cn(
                  "text-xs pt-1 border-t flex items-center gap-1.5",
                  isExcess ? "border-amber-500/20" : "border-red-500/20"
                )}>
                  {isExcess ? (
                    <span>⚠ Juros / Acréscimo de <strong>R$ {Math.abs(diff).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</strong></span>
                  ) : (
                    <span>⚠ Restam <strong>R$ {Math.abs(diff).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</strong> para concluir</span>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>

        <DialogFooter className="flex-row gap-2 justify-end sm:justify-end">
          <Button variant="outline" className="border-border" onClick={() => onOpenChange(false)}>
            Cancelar
          </Button>
          <Button
            className="bg-green-600 hover:bg-green-600/90 text-white gap-2"
            onClick={handleConfirm}
            disabled={isPaying}
          >
            {isPaying ? (
              <Loader2 className="h-4 w-4 animate-spin" />
            ) : (
              <Check className="h-4 w-4" />
            )}
            Confirmar Pagamento
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useEffect, useState } from "react";
import { format, addMonths, parseISO } from "date-fns";
import { ptBR } from "date-fns/locale";
import { Calendar, AlertCircle, RefreshCw } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Alert, AlertDescription } from "@/components/ui/alert";

export interface InstallmentDraft {
  installmentNumber: number;
  amount: number;
  dueDate: string;
}

interface InstallmentGeneratorProps {
  totalAmount: number;
  installmentsCount: number;
  firstDueDate: string;
  installments: InstallmentDraft[];
  onChange: (installments: InstallmentDraft[]) => void;
}

export function InstallmentGenerator({
  totalAmount,
  installmentsCount,
  firstDueDate,
  installments,
  onChange,
}: InstallmentGeneratorProps) {
  const [localErrors, setLocalErrors] = useState<string | null>(null);

  // Efeito para gerar as parcelas iniciais quando as dependências básicas mudam
  useEffect(() => {
    if (totalAmount <= 0 || installmentsCount <= 0 || !firstDueDate) {
      onChange([]);
      return;
    }

    const baseAmount = Math.floor((totalAmount / installmentsCount) * 100) / 100;
    const generated: InstallmentDraft[] = [];
    const baseDate = parseISO(firstDueDate);

    let sum = 0;
    for (let i = 0; i < installmentsCount; i++) {
      const isLast = i === installmentsCount - 1;
      const installmentDate = addMonths(baseDate, i);
      const installmentDateStr = format(installmentDate, "yyyy-MM-dd");

      let amount = baseAmount;
      if (isLast) {
        // A última parcela recebe o residual
        amount = Math.round((totalAmount - sum) * 100) / 100;
      } else {
        sum += baseAmount;
      }

      generated.push({
        installmentNumber: i + 1,
        amount: amount,
        dueDate: installmentDateStr,
      });
    }

    onChange(generated);
  }, [totalAmount, installmentsCount, firstDueDate]);

  // Efeito para validar a soma das parcelas
  useEffect(() => {
    if (installments.length === 0) {
      setLocalErrors(null);
      return;
    }

    const sum = installments.reduce((acc, inst) => acc + Number(inst.amount), 0);
    const difference = Math.round((totalAmount - sum) * 100) / 100;

    if (Math.abs(difference) > 0.01) {
      setLocalErrors(
        `A soma das parcelas (R$ ${sum.toLocaleString("pt-BR", {
          minimumFractionDigits: 2,
        })}) difere do valor total (R$ ${totalAmount.toLocaleString("pt-BR", {
          minimumFractionDigits: 2,
        })}). Diferença: R$ ${difference.toLocaleString("pt-BR", {
          minimumFractionDigits: 2,
        })}`
      );
    } else {
      setLocalErrors(null);
    }
  }, [installments, totalAmount]);

  const handleAmountChange = (index: number, newAmountStr: string) => {
    const updated = [...installments];
    const cleanStr = newAmountStr.replace(",", ".");
    const newAmount = Number(cleanStr);
    
    if (!isNaN(newAmount)) {
      updated[index] = {
        ...updated[index],
        amount: newAmount,
      };
      onChange(updated);
    }
  };

  const handleDateChange = (index: number, newDateStr: string) => {
    const updated = [...installments];
    updated[index] = {
      ...updated[index],
      dueDate: newDateStr,
    };
    onChange(updated);
  };

  // Restaura e divide de forma igual com residual no final
  const handleRecalculateEqually = () => {
    const baseAmount = Math.floor((totalAmount / installments.length) * 100) / 100;
    const updated = installments.map((inst, i) => {
      const isLast = i === installments.length - 1;
      let amount = baseAmount;
      if (isLast) {
        const sum = baseAmount * (installments.length - 1);
        amount = Math.round((totalAmount - sum) * 100) / 100;
      }
      return {
        ...inst,
        amount: amount,
      };
    });
    onChange(updated);
  };

  if (installments.length === 0) return null;

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between border-b border-border pb-2">
        <h4 className="text-sm font-semibold text-foreground">Distribuição das Parcelas</h4>
        <Button
          type="button"
          variant="outline"
          size="sm"
          className="text-xs h-8 gap-1.5"
          onClick={handleRecalculateEqually}
        >
          <RefreshCw className="w-3.5 h-3.5" />
          Dividir Igualmente
        </Button>
      </div>

      {localErrors && (
        <Alert variant="destructive" className="py-2.5">
          <AlertCircle className="h-4 w-4" />
          <AlertDescription className="text-xs">{localErrors}</AlertDescription>
        </Alert>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3 max-h-[250px] overflow-y-auto pr-1 py-1 scrollbar-thin">
        {installments.map((inst, index) => (
          <div
            key={inst.installmentNumber}
            className="flex flex-col p-3 rounded-lg border border-border bg-card/40 hover:bg-card/75 transition-colors gap-2"
          >
            <div className="flex items-center justify-between">
              <span className="text-xs font-semibold text-primary uppercase">
                Parcela {inst.installmentNumber}
              </span>
              <span className="text-[10px] text-muted-foreground font-mono">
                {inst.dueDate ? format(parseISO(inst.dueDate), "MMM/yyyy", { locale: ptBR }) : ""}
              </span>
            </div>

            <div className="space-y-3 mt-1">
              <div className="space-y-1">
                <span className="text-[10px] font-medium text-muted-foreground">Vencimento</span>
                <div className="relative">
                  <Input
                    type="date"
                    value={inst.dueDate}
                    onChange={(e) => handleDateChange(index, e.target.value)}
                    className="h-8 text-xs px-2 [color-scheme:dark] w-full"
                  />
                </div>
              </div>

              <div className="space-y-1">
                <span className="text-[10px] font-medium text-muted-foreground">Valor (R$)</span>
                <Input
                  type="text"
                  value={inst.amount}
                  onChange={(e) => handleAmountChange(index, e.target.value)}
                  placeholder="0,00"
                  className="h-8 text-xs font-mono font-medium px-2 w-full"
                />
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { Plus, Trash2, Tag, ShoppingBag, Info, Calculator } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Label } from "@/components/ui/label";
import { supabase } from "@/integrations/supabase/client";

export interface PurchaseItemDraft {
  materialId?: number | null;
  description?: string | null;
  quantity: number;
  unit: string;
  unitPrice: number;
  totalPrice: number;
}

interface MaterialOption {
  id: number;
  name: string;
  unit: string;
  average_cost: number | null;
  product_types?: { cost_per_meter: number | null } | null;
}

interface ItemsInputProps {
  companyId: number;
  items: PurchaseItemDraft[];
  onChange: (items: PurchaseItemDraft[]) => void;
  onUpdateTotalAmount?: (amount: number) => void;
}

export function ItemsInput({
  companyId,
  items,
  onChange,
  onUpdateTotalAmount,
}: ItemsInputProps) {
  const [materials, setMaterials] = useState<MaterialOption[]>([]);
  const [loading, setLoading] = useState(false);

  // Busca os materiais do estoque
  useEffect(() => {
    const fetchMaterials = async () => {
      if (!companyId) return;
      setLoading(true);
      try {
        const { data, error } = await supabase
          .from("materials")
          .select("id, name, unit, average_cost, product_types(cost_per_meter)")
          .eq("company_id", companyId)
          .eq("is_active", true)
          .order("name", { ascending: true });

        if (error) throw error;
        setMaterials(data || []);
      } catch (error) {
        console.error("[ItemsInput] Error fetching materials:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchMaterials();
  }, [companyId]);

  const handleAddItem = () => {
    const newItem: PurchaseItemDraft = {
      materialId: null,
      description: "",
      quantity: 1,
      unit: "un",
      unitPrice: 0,
      totalPrice: 0,
    };
    onChange([...items, newItem]);
  };

  const handleRemoveItem = (index: number) => {
    const updated = items.filter((_, i) => i !== index);
    onChange(updated);
  };

  const handleItemChange = (index: number, field: keyof PurchaseItemDraft, value: any) => {
    const updated = [...items];
    const currentItem = { ...updated[index] };

    if (field === "materialId") {
      const matId = value === "free_text" ? null : Number(value);
      currentItem.materialId = matId;

      if (matId) {
        const selectedMaterial = materials.find((m) => m.id === matId);
        if (selectedMaterial) {
          currentItem.unit = selectedMaterial.unit || "un";
          currentItem.unitPrice = selectedMaterial.product_types?.cost_per_meter || selectedMaterial.average_cost || 0;
          currentItem.description = null;
        }
      } else {
        currentItem.unit = "un";
        currentItem.description = "";
      }
    } else {
      (currentItem as any)[field] = value;
    }

    // Recalcular preço total do item
    if (field === "quantity" || field === "unitPrice" || field === "materialId") {
      const q = Number(currentItem.quantity) || 0;
      const p = Number(currentItem.unitPrice) || 0;
      currentItem.totalPrice = Math.round(q * p * 100) / 100;
    }

    updated[index] = currentItem;
    onChange(updated);
  };

  const sumTotalItems = items.reduce((sum, item) => sum + item.totalPrice, 0);

  const handleApplyTotalToPurchase = () => {
    if (onUpdateTotalAmount) {
      onUpdateTotalAmount(sumTotalItems);
    }
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between border-b border-border pb-2">
        <div className="flex items-center gap-2">
          <ShoppingBag className="w-4 h-4 text-primary" />
          <h4 className="text-sm font-semibold text-foreground">Itens da Compra (Opcional)</h4>
        </div>
        <Button
          type="button"
          variant="outline"
          size="sm"
          className="text-xs h-8 gap-1.5"
          onClick={handleAddItem}
        >
          <Plus className="w-3.5 h-3.5" /> Adicionar Item
        </Button>
      </div>

      {items.length === 0 ? (
        <div className="flex flex-col items-center justify-center p-6 border border-dashed border-border rounded-lg bg-muted/20 text-center">
          <Info className="w-6 h-6 text-muted-foreground opacity-55 mb-1.5" />
          <p className="text-xs text-muted-foreground max-w-[280px]">
            Nenhum item adicionado. A compra será cadastrada com valor global.
          </p>
        </div>
      ) : (
        <div className="space-y-3">
          <div className="max-h-[300px] overflow-y-auto pr-1 py-1 space-y-3 scrollbar-thin">
            {items.map((item, index) => (
              <div
                key={index}
                className="flex flex-col sm:flex-row items-stretch sm:items-center gap-3 p-3 rounded-lg border border-border bg-card/30 hover:bg-card/65 transition-colors relative"
              >
                {/* Seleção do tipo de item (Estoque ou Descrição Livre) */}
                <div className="flex-1 space-y-1 min-w-[140px]">
                  <span className="text-[10px] font-medium text-muted-foreground">Produto / Item</span>
                  <Select
                    value={item.materialId ? item.materialId.toString() : "free_text"}
                    onValueChange={(val) => handleItemChange(index, "materialId", val)}
                  >
                    <SelectTrigger className="h-9 text-xs">
                      <SelectValue placeholder="Selecione um produto..." />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="free_text" className="font-semibold text-primary">
                        + Item Textual Livre
                      </SelectItem>
                      {materials.map((mat) => (
                        <SelectItem key={mat.id} value={mat.id.toString()}>
                          {mat.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                {/* Se for item livre, exibe input de texto */}
                {item.materialId === null && (
                  <div className="flex-1 space-y-1 min-w-[140px]">
                    <span className="text-[10px] font-medium text-muted-foreground">Descrição do Item</span>
                    <Input
                      type="text"
                      placeholder="Ex: Parafusos, Fita crepe"
                      value={item.description || ""}
                      onChange={(e) => handleItemChange(index, "description", e.target.value)}
                      className="h-9 text-xs"
                    />
                  </div>
                )}

                {/* Unidade */}
                <div className="w-20 space-y-1">
                  <span className="text-[10px] font-medium text-muted-foreground">Unidade</span>
                  <Input
                    type="text"
                    value={item.unit}
                    onChange={(e) => handleItemChange(index, "unit", e.target.value)}
                    placeholder="un"
                    className="h-9 text-xs"
                    disabled={item.materialId !== null} // Trava se for material do estoque
                  />
                </div>

                {/* Quantidade */}
                <div className="w-24 space-y-1">
                  <span className="text-[10px] font-medium text-muted-foreground">Qtd.</span>
                  <Input
                    type="number"
                    step="any"
                    value={item.quantity}
                    onChange={(e) => handleItemChange(index, "quantity", Number(e.target.value))}
                    className="h-9 text-xs"
                  />
                </div>

                {/* Preço Unitário */}
                <div className="w-28 space-y-1">
                  <span className="text-[10px] font-medium text-muted-foreground">Preço Unit. (R$)</span>
                  <Input
                    type="text"
                    value={item.unitPrice}
                    onChange={(e) =>
                      handleItemChange(index, "unitPrice", e.target.value.replace(",", "."))
                    }
                    className="h-9 text-xs font-mono"
                  />
                </div>

                {/* Preço Total (Calculado) */}
                <div className="w-28 space-y-1">
                  <span className="text-[10px] font-medium text-muted-foreground">Total (R$)</span>
                  <Input
                    type="text"
                    value={item.totalPrice.toLocaleString("pt-BR", {
                      minimumFractionDigits: 2,
                      maximumFractionDigits: 2,
                    })}
                    className="h-9 text-xs font-mono bg-muted/40 font-semibold"
                    disabled
                  />
                </div>

                {/* Botão de Excluir */}
                <div className="flex items-end justify-end sm:pb-0.5">
                  <Button
                    type="button"
                    variant="ghost"
                    size="icon"
                    className="h-9 w-9 text-muted-foreground hover:text-destructive hover:bg-destructive/10"
                    onClick={() => handleRemoveItem(index)}
                  >
                    <Trash2 className="w-4 h-4" />
                  </Button>
                </div>
              </div>
            ))}
          </div>

          {/* Resumo e Ação de Vincular */}
          <div className="flex flex-col sm:flex-row items-center justify-between p-3 rounded-lg border border-primary/20 bg-primary/5 gap-3">
            <div className="flex items-center gap-2">
              <Calculator className="w-4 h-4 text-primary" />
              <span className="text-xs font-medium text-muted-foreground">
                Total dos Itens:{" "}
                <strong className="text-foreground text-sm font-semibold ml-1">
                  R$ {sumTotalItems.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}
                </strong>
              </span>
            </div>
            {onUpdateTotalAmount && (
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="text-xs h-8 border-primary/30 text-primary hover:bg-primary/10 gap-1.5"
                onClick={handleApplyTotalToPurchase}
              >
                Vincular ao Valor Total da Compra
              </Button>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from "react";
import { format, startOfMonth, endOfMonth, parseISO } from "date-fns";
import { ptBR } from "date-fns/locale";
import { cn } from "@/lib/utils";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Loader2, Calendar, CheckCircle2, XCircle, AlertCircle, RefreshCw } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { payInstallment, reverseInstallment } from "@/lib/purchaseService";
import { toast } from "sonner";

interface MonthBillsModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  companyId: number;
  onSuccess?: () => void;
}

interface InstallmentWithPurchase {
  id: number;
  purchase_id: number;
  installment_number: number;
  amount: number;
  due_date: string;
  status: "pendente" | "paga";
  paid_at: string | null;
  purchases: {
    supplier_name_snapshot: string;
    installments_count: number;
  };
}

export function MonthBillsModal({
  open,
  onOpenChange,
  companyId,
  onSuccess,
}: MonthBillsModalProps) {
  const [installments, setInstallments] = useState<InstallmentWithPurchase[]>([]);
  const [loading, setLoading] = useState(false);
  const [processingId, setProcessingId] = useState<number | null>(null);

  const fetchMonthBills = async () => {
    if (!companyId) return;
    setLoading(true);
    try {
      const now = new Date();
      const start = format(startOfMonth(now), "yyyy-MM-dd");
      const end = format(endOfMonth(now), "yyyy-MM-dd");

      const { data, error } = await supabase
        .from("purchase_installments")
        .select(`
          id, purchase_id, installment_number, amount, due_date, status, paid_at,
          purchases!inner (
            supplier_name_snapshot,
            installments_count,
            company_id
          )
        `)
        .eq("purchases.company_id", companyId)
        .gte("due_date", start)
        .lte("due_date", end)
        .order("due_date", { ascending: true });

      if (error) throw error;
      setInstallments((data as any) || []);
    } catch (error) {
      console.error("[MonthBillsModal] Error fetching monthly bills:", error);
      toast.error("Erro ao carregar contas do mês");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (open) {
      fetchMonthBills();
    }
  }, [open, companyId]);

  const handlePay = async (id: number) => {
    setProcessingId(id);
    try {
      const ok = await payInstallment(id);
      if (ok) {
        toast.success("Parcela marcada como paga!");
        await fetchMonthBills();
        onSuccess?.();
      } else {
        toast.error("Erro ao pagar parcela");
      }
    } catch (err) {
      console.error(err);
      toast.error("Erro ao processar pagamento");
    } finally {
      setProcessingId(null);
    }
  };

  const handleReverse = async (id: number) => {
    setProcessingId(id);
    try {
      const ok = await reverseInstallment(id);
      if (ok) {
        toast.success("Pagamento estornado com sucesso!");
        await fetchMonthBills();
        onSuccess?.();
      } else {
        toast.error("Erro ao estornar parcela");
      }
    } catch (err) {
      console.error(err);
      toast.error("Erro ao processar estorno");
    } finally {
      setProcessingId(null);
    }
  };

  const currentMonthName = format(new Date(), "MMMM 'de' yyyy", { locale: ptBR });

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-2xl max-h-[85vh] flex flex-col p-0">
        <div className="p-6 pb-4 border-b border-border flex items-center justify-between">
          <div className="space-y-1">
            <DialogTitle className="text-lg font-bold flex items-center gap-2">
              <Calendar className="w-5 h-5 text-primary" /> Compromissos de {currentMonthName}
            </DialogTitle>
            <DialogDescription className="text-xs">
              Listagem de todas as parcelas com vencimento no mês corrente.
            </DialogDescription>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-4 scrollbar-thin">
          {loading ? (
            <div className="flex items-center justify-center py-12 text-sm text-muted-foreground gap-2">
              <Loader2 className="w-5 h-5 animate-spin text-primary" />
              Carregando compromissos...
            </div>
          ) : installments.length === 0 ? (
            <div className="text-center py-12 border border-dashed border-border rounded-lg bg-muted/10">
              <CheckCircle2 className="w-8 h-8 mx-auto mb-2 text-green-500/60" />
              <p className="text-sm font-semibold text-foreground">Tudo limpo!</p>
              <p className="text-xs text-muted-foreground mt-1">
                Nenhuma conta a pagar encontrada para este mês.
              </p>
            </div>
          ) : (
            <div className="space-y-3">
              {installments.map((inst) => {
                const isPaid = inst.status === "paga";
                const isOverdue = !isPaid && inst.due_date < format(new Date(), "yyyy-MM-dd");
                const isProcessing = processingId === inst.id;

                return (
                  <div
                    key={inst.id}
                    className={cn(
                      "flex flex-col sm:flex-row items-stretch sm:items-center justify-between p-4 rounded-lg border transition-all gap-4",
                      isPaid
                        ? "bg-green-500/5 border-green-500/20"
                        : isOverdue
                        ? "bg-red-500/5 border-red-500/20 animate-pulse-subtle"
                        : "bg-card border-border hover:border-muted-foreground/30"
                    )}
                  >
                    {/* Informações da Conta */}
                    <div className="flex-1 min-w-0 space-y-1.5">
                      <div className="flex items-center gap-2 flex-wrap">
                        <span className="font-semibold text-sm truncate text-foreground">
                          {inst.purchases?.supplier_name_snapshot}
                        </span>
                        <Badge variant="outline" className="text-[10px] py-0 px-1.5 font-medium">
                          Parcela {inst.installment_number}/{inst.purchases?.installments_count}
                        </Badge>
                        {isPaid ? (
                          <Badge className="bg-green-500/10 text-green-500 hover:bg-green-500/20 border-green-500/10 text-[9px] py-0 px-1.5">
                            Paga
                          </Badge>
                        ) : isOverdue ? (
                          <Badge variant="destructive" className="text-[9px] py-0 px-1.5 animate-pulse">
                            Atrasada
                          </Badge>
                        ) : (
                          <Badge variant="secondary" className="text-[9px] py-0 px-1.5">
                            Pendente
                          </Badge>
                        )}
                      </div>

                      <div className="flex items-center gap-3 text-[11px] text-muted-foreground flex-wrap">
                        <span className="flex items-center gap-1">
                          <Calendar className="w-3.5 h-3.5" />
                          Vence em: {format(parseISO(inst.due_date), "dd/MM/yyyy")}
                        </span>
                        {isPaid && inst.paid_at && (
                          <span className="text-green-500 flex items-center gap-1">
                            <CheckCircle2 className="w-3.5 h-3.5" />
                            Pago em: {format(parseISO(inst.paid_at), "dd/MM/yyyy")}
                          </span>
                        )}
                      </div>
                    </div>

                    {/* Preço e Botão de Ação */}
                    <div className="flex items-center justify-between sm:justify-end gap-4 border-t sm:border-t-0 pt-3 sm:pt-0 border-border/60">
                      <div className="text-left sm:text-right">
                        <span className="text-[10px] text-muted-foreground block uppercase font-semibold">
                          Valor
                        </span>
                        <span className="font-mono font-bold text-sm text-foreground">
                          R$ {inst.amount.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}
                        </span>
                      </div>

                      <div className="w-24 flex justify-end">
                        {isPaid ? (
                          <Button
                            type="button"
                            variant="outline"
                            size="sm"
                            className="text-xs h-8 border-red-500/30 text-red-500 hover:bg-red-500/10 w-full"
                            onClick={() => handleReverse(inst.id)}
                            disabled={isProcessing}
                          >
                            {isProcessing ? (
                              <Loader2 className="w-3.5 h-3.5 animate-spin" />
                            ) : (
                              "Estornar"
                            )}
                          </Button>
                        ) : (
                          <Button
                            type="button"
                            variant="default"
                            size="sm"
                            className="text-xs h-8 bg-green-600 hover:bg-green-700 text-white w-full"
                            onClick={() => handlePay(inst.id)}
                            disabled={isProcessing}
                          >
                            {isProcessing ? (
                              <Loader2 className="w-3.5 h-3.5 animate-spin" />
                            ) : (
                              "Pagar"
                            )}
                          </Button>
                        )}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

// @ts-nocheck
import React, { useState } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useAuth } from "@/contexts/AuthContext";
import { createPurchase, uploadAttachment } from "@/lib/purchaseService";
import { toast } from "sonner";
import { SupplierAutocomplete } from "./SupplierAutocomplete";
import { InstallmentGenerator } from "./InstallmentGenerator";
import { ItemsInput } from "./ItemsInput";
import { AttachmentsBlock } from "./AttachmentsBlock";

interface NewPurchaseModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSuccess: () => void;
  accounts: any[];
  categories: any[];
}

export function NewPurchaseModal({ open, onOpenChange, onSuccess, accounts, categories }: NewPurchaseModalProps) {
  const { user } = useAuth();
  const [loading, setLoading] = useState(false);

  // States
  const [supplier, setSupplier] = useState<any | null>(null);
  const [purchaseDate, setPurchaseDate] = useState(new Date().toISOString().split("T")[0]);
  const [totalAmount, setTotalAmount] = useState<number>(0);
  const [paymentMethod, setPaymentMethod] = useState("Boleto");
  const [accountId, setAccountId] = useState<number | null>(null);
  const [categoryId, setCategoryId] = useState<number | null>(null);

  // Installments
  const [installmentsCount, setInstallmentsCount] = useState(1);
  const [firstDueDate, setFirstDueDate] = useState(new Date().toISOString().split("T")[0]);
  const [installments, setInstallments] = useState<any[]>([]);

  // Items & Attachments
  const [items, setItems] = useState<any[]>([]);
  const [images, setImages] = useState<File[]>([]);
  const [pdfs, setPdfs] = useState<File[]>([]);

  const isImmediate = ["Pix", "Débito", "Dinheiro"].includes(paymentMethod);

  // Auto-selecionar conta principal se não houver
  React.useEffect(() => {
    if (open && accounts.length > 0 && !accountId) {
      const mainAcc = accounts.find(a => a.is_main);
      if (mainAcc) setAccountId(mainAcc.id);
    }
  }, [open, accounts, accountId]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!supplier) {
      toast.error("Selecione ou crie um fornecedor.");
      return;
    }
    if (totalAmount <= 0) {
      toast.error("O valor total deve ser maior que zero.");
      return;
    }
    if (!accountId || !categoryId) {
      toast.error("Conta e Categoria são obrigatórias.");
      return;
    }

    setLoading(true);
    try {
      const companyId = supplier.company_id;

      const purchaseResult = await createPurchase({
        companyId,
        supplierId: supplier.id,
        supplierNameSnapshot: supplier.name,
        supplierPhoneSnapshot: supplier.phone,
        purchaseDate,
        totalAmount,
        paymentMethod,
        installmentsCount: isImmediate ? 1 : installmentsCount,
        accountId,
        categoryId,
        createdBy: user?.id || "",
        installments: isImmediate
          ? [{ installmentNumber: 1, amount: totalAmount, dueDate: purchaseDate }]
          : installments,
        items: items.length > 0 ? items.map(i => ({
          description: i.description,
          quantity: i.quantity,
          unitPrice: i.unit_price,
          totalPrice: i.total_price
        })) : []
      });

      if (!purchaseResult) {
        toast.error("Erro ao registrar compra.");
        setLoading(false);
        return;
      }

      // Handle uploads
      const allFiles = [...images, ...pdfs];
      for (const file of allFiles) {
        await uploadAttachment(file, purchaseResult.id, companyId);
      }

      toast.success("Compra registrada com sucesso!");
      resetForm();
      onSuccess();
      onOpenChange(false);
    } catch (error) {
      toast.error("Erro inesperado ao salvar a compra.");
    } finally {
      setLoading(false);
    }
  };

  const resetForm = () => {
    setSupplier(null);
    setPurchaseDate(new Date().toISOString().split("T")[0]);
    setTotalAmount(0);
    setPaymentMethod("Boleto");
    setInstallmentsCount(1);
    setItems([]);
    setImages([]);
    setPdfs([]);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl w-[calc(100%-2rem)] sm:w-full p-4 sm:p-6 max-h-[85dvh] sm:max-h-[90vh] overflow-y-auto overflow-x-hidden">
        <DialogHeader>
          <DialogTitle>Nova Compra</DialogTitle>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-6 pt-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Fornecedor *</Label>
              <SupplierAutocomplete
                companyId={user?.companyId || accounts[0]?.company_id || 0}
                value={supplier}
                onChange={setSupplier}
                onCreateNew={() => { }} // Internamente ele mesmo já cria e seta
              />
            </div>
            <div className="space-y-2">
              <Label>Data da Compra *</Label>
              <Input type="date" required value={purchaseDate} onChange={e => setPurchaseDate(e.target.value)} className="[color-scheme:dark]" />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Valor Total *</Label>
              <Input
                type="number"
                step="0.01"
                min="0.01"
                required
                value={totalAmount || ""}
                onChange={e => setTotalAmount(parseFloat(e.target.value) || 0)}
                placeholder="R$ 0,00"
              />
            </div>
            <div className="space-y-2">
              <Label>Categoria *</Label>
              <Select value={categoryId?.toString() || ""} onValueChange={v => setCategoryId(parseInt(v))}>
                <SelectTrigger><SelectValue placeholder="Selecione a categoria" /></SelectTrigger>
                <SelectContent>
                  {categories.map(cat => (
                    <SelectItem key={cat.id} value={cat.id.toString()}>{cat.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>

          {!isImmediate && (
            <div className="border p-4 rounded-md space-y-4 bg-muted/10">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Quantidade de Parcelas</Label>
                  <Input type="number" min="1" max="24" value={installmentsCount} onChange={e => setInstallmentsCount(parseInt(e.target.value) || 1)} />
                </div>
                <div className="space-y-2">
                  <Label>1º Vencimento</Label>
                  <Input type="date" value={firstDueDate} onChange={e => setFirstDueDate(e.target.value)} className="[color-scheme:dark]" />
                </div>
              </div>
              <InstallmentGenerator
                totalAmount={totalAmount}
                installmentsCount={installmentsCount}
                firstDueDate={firstDueDate}
                paymentMethod={paymentMethod}
                installments={installments}
                onChange={setInstallments}
              />
            </div>
          )}

          {/* <ItemsInput companyId={accounts[0]?.company_id || 0} items={items} onChange={setItems} /> */}
          <div className="text-sm text-muted-foreground italic border-t pt-2 mt-4">
            Nota: Inserção de Itens implementada separadamente para evitar complexidade inicial. (Será vinculada pelo ItemsInput real do repositório)
          </div>

          <AttachmentsBlock
            images={images}
            pdfs={pdfs}
            onImagesChange={setImages}
            onPdfsChange={setPdfs}
          />

          <div className="flex flex-col sm:flex-row justify-end gap-2 pt-4">
            <Button type="button" variant="outline" className="w-full sm:w-auto" onClick={() => onOpenChange(false)}>Cancelar</Button>
            <Button type="submit" className="w-full sm:w-auto" disabled={loading || totalAmount <= 0}>
              {loading ? "Salvando..." : "Registrar Compra"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

// @ts-nocheck
import React, { useEffect, useState } from "react";
import { format } from "date-fns";
import {
  Sheet, SheetContent, SheetHeader, SheetTitle
} from "@/components/ui/sheet";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { Check, Download, Paperclip, Undo2 } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { payInstallment, payInstallmentWithDetails, reverseInstallment } from "@/lib/purchaseService";
import { toast } from "sonner";
import { Purchase, PurchaseInstallment, PurchaseItem, PurchaseAttachment } from "@/lib/database.types";
import { ConfirmPurchasePaymentModal } from "./ConfirmPurchasePaymentModal";

interface PurchaseDetailDrawerProps {
  purchaseId: number | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onUpdate: () => void;
}

export function PurchaseDetailDrawer({ purchaseId, open, onOpenChange, onUpdate }: PurchaseDetailDrawerProps) {
  const [purchase, setPurchase] = useState<Purchase | null>(null);
  const [installments, setInstallments] = useState<PurchaseInstallment[]>([]);
  const [items, setItems] = useState<PurchaseItem[]>([]);
  const [attachments, setAttachments] = useState<PurchaseAttachment[]>([]);
  const [loading, setLoading] = useState(false);

  const [paymentModalOpen, setPaymentModalOpen] = useState(false);
  const [selectedInstallment, setSelectedInstallment] = useState<{ id: number; amount: number } | null>(null);

  useEffect(() => {
    if (open && purchaseId) {
      fetchPurchaseDetails();
    }
  }, [open, purchaseId]);

  const fetchPurchaseDetails = async () => {
    setLoading(true);
    try {
      const { data: pData } = await supabase.from("purchases").select("*").eq("id", purchaseId).single();
      if (pData) setPurchase(pData);

      const { data: instData } = await supabase.from("purchase_installments").select("*").eq("purchase_id", purchaseId).order("installment_number");
      if (instData) setInstallments(instData);

      const { data: itemsData } = await supabase.from("purchase_items").select("*").eq("purchase_id", purchaseId);
      if (itemsData) setItems(itemsData);

      const { data: attData } = await supabase.from("purchase_attachments").select("*").eq("purchase_id", purchaseId);
      if (attData) setAttachments(attData);

    } catch (error) {
      console.error("Erro ao carregar detalhes:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleOpenPaymentModal = (instId: number, amount: number) => {
    setSelectedInstallment({ id: instId, amount });
    setPaymentModalOpen(true);
  };

  const handleConfirmPayment = async (paymentsList: any[]) => {
    if (!selectedInstallment) return;

    const paymentDetails = paymentsList.map(p => ({
      payment_method: p.payment_method,
      amount: p.amount,
      account_id: p.account_id,
      payment_date: p.due_date
    }));

    const success = await payInstallmentWithDetails(selectedInstallment.id, paymentDetails);
    if (success) {
      toast.success("Pagamento registrado com sucesso!");
      fetchPurchaseDetails();
      onUpdate();
    } else {
      toast.error("Erro ao registrar pagamento.");
    }
  };

  const handleReverse = async (instId: number) => {
    const success = await reverseInstallment(instId);
    if (success) {
      toast.success("Pagamento revertido com sucesso!");
      fetchPurchaseDetails();
      onUpdate();
    } else {
      toast.error("Erro ao reverter parcela.");
    }
  };

  const downloadAttachment = async (path: string, name: string) => {
    try {
      const { data, error } = await supabase.storage.from("purchase-attachments").createSignedUrl(path, 60);
      if (error || !data) throw error;
      window.open(data.signedUrl, '_blank');
    } catch (e) {
      toast.error("Erro ao gerar link de download.");
    }
  };

  if (!purchase) return null;

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent className="w-full sm:max-w-md overflow-y-auto">
        <SheetHeader className="mb-4">
          <SheetTitle className="flex items-center gap-2">
            Compra #{purchase.id}
            {purchase.status === 'paga' && <Badge className="bg-green-500">Paga</Badge>}
            {purchase.status === 'em_aberto' && <Badge variant="outline" className="text-amber-600 border-amber-600">Em Aberto</Badge>}
            {purchase.status === 'atrasada' && <Badge variant="destructive">Atrasada</Badge>}
          </SheetTitle>
        </SheetHeader>

        {loading ? (
          <p className="text-sm text-muted-foreground">Carregando...</p>
        ) : (
          <div className="space-y-6">
            <div className="space-y-2">
              <h3 className="font-semibold">Resumo</h3>
              <div className="grid grid-cols-2 gap-2 text-sm">
                <span className="text-muted-foreground">Fornecedor:</span>
                <span className="font-medium text-right">{purchase.supplier_name_snapshot}</span>
                <span className="text-muted-foreground">Data:</span>
                <span className="font-medium text-right">{format(new Date(purchase.purchase_date + 'T12:00:00'), "dd/MM/yyyy")}</span>
                <span className="text-muted-foreground">Valor Total:</span>
                <span className="font-medium text-right">R$ {Number(purchase.total_amount).toFixed(2)}</span>
                <span className="text-muted-foreground">Forma de Pgto:</span>
                <span className="font-medium text-right">{purchase.payment_method}</span>
              </div>
            </div>

            <Separator />

            {items.length > 0 && (
              <div className="space-y-2">
                <h3 className="font-semibold text-sm">Itens Comprados</h3>
                <div className="space-y-2">
                  {items.map(item => (
                    <div key={item.id} className="flex justify-between text-sm bg-muted/20 p-2 rounded-md">
                      <span>{item.quantity}x {item.description || "Material Genérico"}</span>
                      <span className="font-medium">R$ {Number(item.total_price).toFixed(2)}</span>
                    </div>
                  ))}
                </div>
                <Separator className="mt-4" />
              </div>
            )}

            <div className="space-y-2">
              <h3 className="font-semibold text-sm">Parcelas ({purchase.installments_count})</h3>
              <div className="space-y-3">
                {installments.map(inst => (
                  <div key={inst.id} className="p-3 border rounded-md shadow-sm">
                    <div className="flex justify-between items-start mb-2">
                      <span className="text-xs font-bold text-muted-foreground uppercase">Parcela {inst.installment_number}</span>
                      {inst.status === 'paga' ? (
                        <Badge className="bg-green-500 hover:bg-green-600">Paga</Badge>
                      ) : (
                        <Badge variant="outline" className="text-amber-600 border-amber-600">Pendente</Badge>
                      )}
                    </div>
                    <div className="flex justify-between items-end">
                      <div>
                        <div className="text-lg font-bold">R$ {Number(inst.amount).toFixed(2)}</div>
                        <div className="text-xs text-muted-foreground">Venc: {format(new Date(inst.due_date + 'T12:00:00'), "dd/MM/yyyy")}</div>
                      </div>
                      <div>
                        {inst.status !== 'paga' ? (
                          <Button size="sm" variant="outline" className="border-green-500/50 text-green-600 hover:bg-green-50" onClick={() => handleOpenPaymentModal(inst.id, Number(inst.amount))}>
                            <Check className="h-4 w-4 mr-1" /> Pagar
                          </Button>
                        ) : (
                          <Button size="sm" variant="ghost" className="text-muted-foreground" onClick={() => handleReverse(inst.id)}>
                            <Undo2 className="h-4 w-4 mr-1" /> Reverter
                          </Button>
                        )}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {attachments.length > 0 && (
              <>
                <Separator />
                <div className="space-y-2">
                  <h3 className="font-semibold text-sm">Anexos</h3>
                  <div className="space-y-2">
                    {attachments.map(att => (
                      <div key={att.id} className="flex justify-between items-center text-sm border p-2 rounded-md">
                        <div className="flex items-center gap-2 truncate pr-2">
                          <Paperclip className="h-4 w-4 text-muted-foreground flex-shrink-0" />
                          <span className="truncate">{att.file_name}</span>
                        </div>
                        <Button size="sm" variant="secondary" className="flex-shrink-0" onClick={() => downloadAttachment(att.file_path, att.file_name)}>
                          <Download className="h-3 w-3 mr-1" /> Abrir
                        </Button>
                      </div>
                    ))}
                  </div>
                </div>
              </>
            )}
          </div>
        )}
      </SheetContent>
      {selectedInstallment && (
        <ConfirmPurchasePaymentModal
          open={paymentModalOpen}
          onOpenChange={setPaymentModalOpen}
          installmentAmount={selectedInstallment.amount}
          companyId={purchase.company_id}
          defaultAccountId={purchase.account_id}
          purchasePaymentMethod={purchase.payment_method}
          onConfirm={handleConfirmPayment}
        />
      )}
    </Sheet>
  );
}

// @ts-nocheck
import { useState, useEffect } from "react";
import { Check, ChevronsUpDown, Plus, ArrowLeft, Loader2, Phone } from "lucide-react";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "@/components/ui/command";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { supabase } from "@/integrations/supabase/client";
import { Supplier } from "@/lib/purchaseService";
import { toast } from "sonner";

interface SupplierAutocompleteProps {
  companyId: number;
  value: Supplier | null;
  onChange: (supplier: Supplier | null) => void;
  className?: string;
  placeholder?: string;
}

export function SupplierAutocomplete({
  companyId,
  value,
  onChange,
  className,
  placeholder = "Selecione um fornecedor..."
}: SupplierAutocompleteProps) {
  const [open, setOpen] = useState(false);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  
  // Estado para fluxo de criação inline
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [newSupplierName, setNewSupplierName] = useState("");
  const [newSupplierPhone, setNewSupplierPhone] = useState("");
  const [creating, setCreating] = useState(false);

  // Busca fornecedores ativos no banco
  const fetchSuppliers = async () => {
    if (!companyId) return;
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from("suppliers")
        .select("*")
        .eq("company_id", companyId)
        .eq("is_active", true)
        .order("name", { ascending: true });

      if (error) throw error;
      setSuppliers(data || []);
    } catch (error) {
      console.error("[SupplierAutocomplete] Error fetching suppliers:", error);
      toast.error("Erro ao carregar fornecedores");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (open) {
      fetchSuppliers();
      setShowCreateForm(false);
      setNewSupplierName("");
      setNewSupplierPhone("");
    }
  }, [open, companyId]);

  // Criação rápida de fornecedor
  const handleCreateSupplier = async () => {
    if (newSupplierName.trim().length < 2) {
      toast.error("O nome do fornecedor deve ter pelo menos 2 caracteres");
      return;
    }

    setCreating(true);
    try {
      const { data, error } = await supabase
        .from("suppliers")
        .insert({
          company_id: companyId,
          name: newSupplierName.trim(),
          phone: newSupplierPhone.trim() || null,
          is_active: true
        })
        .select("*")
        .single();

      if (error) throw error;

      toast.success("Fornecedor cadastrado com sucesso!");
      
      const createdSupplier = data as Supplier;
      // Atualiza lista local
      setSuppliers(prev => [...prev, createdSupplier].sort((a, b) => a.name.localeCompare(b.name)));
      // Seleciona o recém-criado
      onChange(createdSupplier);
      // Fecha o popover
      setOpen(false);
    } catch (error: any) {
      console.error("[SupplierAutocomplete] Error creating supplier:", error);
      toast.error(error?.message || "Erro ao cadastrar fornecedor");
    } finally {
      setCreating(false);
    }
  };

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          variant="outline"
          role="combobox"
          aria-expanded={open}
          className={cn(
            "w-full justify-between font-normal",
            !value && "text-muted-foreground",
            className
          )}
        >
          {value ? (
            <div className="flex items-center gap-2">
              <span className="font-medium text-foreground">{value.name}</span>
              {value.phone && (
                <span className="text-xs text-muted-foreground">({value.phone})</span>
              )}
            </div>
          ) : (
            <span>{placeholder}</span>
          )}
          <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-[var(--radix-popover-trigger-width)] min-w-[320px] p-0" align="start">
        {!showCreateForm ? (
          <Command className="w-full">
            <CommandInput 
              placeholder="Buscar fornecedor..." 
              value={searchQuery}
              onValueChange={setSearchQuery}
            />
            <CommandList className="max-h-[300px] overflow-y-auto scrollbar-thin">
              {loading ? (
                <div className="flex items-center justify-center py-6 text-sm text-muted-foreground gap-2">
                  <Loader2 className="w-4 h-4 animate-spin text-primary" />
                  <span>Carregando fornecedores...</span>
                </div>
              ) : (
                <>
                  <CommandEmpty className="py-4 px-2 text-center text-sm">
                    <p className="text-muted-foreground">Nenhum fornecedor encontrado.</p>
                  </CommandEmpty>

                  <CommandGroup>
                    {suppliers.map((supplier) => (
                      <CommandItem
                        key={supplier.id}
                        value={supplier.name}
                        onSelect={() => {
                          onChange(supplier);
                          setOpen(false);
                        }}
                      >
                        <Check
                          className={cn(
                            "mr-2 h-4 w-4 text-primary",
                            value?.id === supplier.id ? "opacity-100" : "opacity-0"
                          )}
                        />
                        <div className="flex flex-col">
                          <span className="font-medium">{supplier.name}</span>
                          {supplier.phone && (
                            <span className="text-xs text-muted-foreground flex items-center gap-1 mt-0.5">
                              <Phone className="w-3 h-3" /> {supplier.phone}
                            </span>
                          )}
                        </div>
                      </CommandItem>
                    ))}
                  </CommandGroup>
                </>
              )}
            </CommandList>
            
            {/* Rodapé fixo para cadastrar novo fornecedor */}
            <div className="p-2 border-t border-border bg-muted/40 flex justify-center">
              <Button 
                variant="outline" 
                size="sm" 
                className="w-full text-xs flex items-center justify-center gap-1.5"
                onClick={() => {
                  setNewSupplierName("");
                  setShowCreateForm(true);
                }}
              >
                <Plus className="w-3.5 h-3.5" /> Novo Fornecedor
              </Button>
            </div>
          </Command>
        ) : (
          /* Formulário de criação inline */
          <div className="p-4 space-y-4">
            <div className="flex items-center gap-2 pb-2 border-b border-border">
              <Button 
                variant="ghost" 
                size="icon" 
                className="h-8 w-8 text-muted-foreground hover:text-foreground"
                onClick={() => setShowCreateForm(false)}
              >
                <ArrowLeft className="w-4 h-4" />
              </Button>
              <h4 className="text-sm font-semibold">Novo Fornecedor</h4>
            </div>

            <div className="space-y-3">
              <div className="space-y-1">
                <Label htmlFor="sup-name" className="text-xs font-semibold text-muted-foreground">Nome Comercial *</Label>
                <Input
                  id="sup-name"
                  value={newSupplierName}
                  onChange={(e) => setNewSupplierName(e.target.value)}
                  placeholder="Ex: Distribuidora WFE"
                  className="h-9 text-sm"
                  autoFocus
                />
              </div>

              <div className="space-y-1">
                <Label htmlFor="sup-phone" className="text-xs font-semibold text-muted-foreground">Telefone de Contato</Label>
                <Input
                  id="sup-phone"
                  value={newSupplierPhone}
                  onChange={(e) => {
                    const digits = e.target.value.replace(/\D/g, "");
                    let formatted = digits;
                    if (digits.length > 0) {
                      if (digits.length <= 2) formatted = `(${digits}`;
                      else if (digits.length <= 6) formatted = `(${digits.slice(0, 2)}) ${digits.slice(2)}`;
                      else if (digits.length <= 10) formatted = `(${digits.slice(0, 2)}) ${digits.slice(2, 6)}-${digits.slice(6)}`;
                      else formatted = `(${digits.slice(0, 2)}) ${digits.slice(2, 7)}-${digits.slice(7, 11)}`;
                    }
                    setNewSupplierPhone(formatted);
                  }}
                  placeholder="Ex: (11) 99999-9999"
                  maxLength={15}
                  className="h-9 text-sm"
                />
              </div>
            </div>

            <div className="flex gap-2 pt-2">
              <Button
                variant="outline"
                size="sm"
                className="flex-1 text-xs"
                onClick={() => setShowCreateForm(false)}
                disabled={creating}
              >
                Voltar
              </Button>
              <Button
                size="sm"
                className="flex-1 text-xs"
                onClick={handleCreateSupplier}
                disabled={creating || !newSupplierName.trim()}
              >
                {creating ? (
                  <>
                    <Loader2 className="w-3 h-3 animate-spin mr-1" />
                    Criando...
                  </>
                ) : (
                  "Cadastrar"
                )}
              </Button>
            </div>
          </div>
        )}
      </PopoverContent>
    </Popover>
  );
}

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import PhoneInputWithDDI from "@/components/ui/PhoneInputWithDDI";
import { Loader2 } from "lucide-react";

interface EditCompanyModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSaved?: () => void;
}

export function EditCompanyModal({ open, onOpenChange, onSaved }: EditCompanyModalProps) {
  const { user } = useAuth();
  const [name, setName] = useState("");
  const [cnpj, setCnpj] = useState("");
  const [phone, setPhone] = useState("");
  const [email, setEmail] = useState("");
  const [street, setStreet] = useState("");
  const [number, setNumber] = useState("");
  const [neighborhood, setNeighborhood] = useState("");
  const [city, setCity] = useState("");
  const [state, setState] = useState("");
  const [cep, setCep] = useState("");
  const [isSaving, setIsSaving] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (open && user?.companyId) {
      loadCompanyData();
    }
  }, [open, user?.companyId]);

  const loadCompanyData = async () => {
    if (!user?.companyId) return;
    setIsLoading(true);
    const { data, error } = await supabase
      .from("companies")
      .select("company_name, cnpj, phone, email, street, number, neighborhood, city, state, cep")
      .eq("id", user.companyId)
      .single();

    if (!error && data) {
      setName(data.company_name || "");
      setCnpj(data.cnpj || "");
      setPhone(data.phone || "");
      setEmail(data.email || "");
      setStreet(data.street || "");
      setNumber(data.number || "");
      setNeighborhood(data.neighborhood || "");
      setCity(data.city || "");
      setState(data.state || "");
      setCep(data.cep || "");
    }
    setIsLoading(false);
  };

  const handleSubmit = async () => {
    if (!name || !phone || !email) {
      toast.error("Preencha os campos obrigatórios");
      return;
    }
    if (!user?.companyId) return;

    setIsSaving(true);
    try {
      const { error } = await supabase
        .from("companies")
        .update({
          company_name: name,
          cnpj: cnpj || null,
          phone,
          email,
          street: street || null,
          number: number || null,
          neighborhood: neighborhood || null,
          city: city || null,
          state: state || null,
          cep: cep || null,
        })
        .eq("id", user.companyId);

      if (error) throw error;

      toast.success("Dados da empresa atualizados!");
      onSaved?.();
      onOpenChange(false);
    } catch (error) {
      console.error("Error updating company:", error);
      toast.error("Erro ao atualizar dados da empresa");
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-lg max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Editar Dados da Empresa</DialogTitle>
        </DialogHeader>

        {isLoading ? (
          <div className="flex justify-center py-8">
            <Loader2 className="h-6 w-6 animate-spin text-primary" />
          </div>
        ) : (
          <div className="space-y-4">
            <div className="space-y-2">
              <Label>Nome da Empresa *</Label>
              <Input value={name} onChange={e => setName(e.target.value)} />
            </div>

            <div className="space-y-2">
              <Label>CNPJ</Label>
              <Input value={cnpj} onChange={e => setCnpj(e.target.value)} placeholder="00.000.000/0000-00" />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>WhatsApp *</Label>
                <PhoneInputWithDDI value={phone} onChange={setPhone} />
              </div>
              <div className="space-y-2">
                <Label>Email *</Label>
                <Input type="email" value={email} onChange={e => setEmail(e.target.value)} />
              </div>
            </div>

            <div className="grid grid-cols-3 gap-4">
              <div className="space-y-2 col-span-2">
                <Label>Rua</Label>
                <Input value={street} onChange={e => setStreet(e.target.value)} placeholder="Rua / Avenida" />
              </div>
              <div className="space-y-2">
                <Label>Número</Label>
                <Input value={number} onChange={e => setNumber(e.target.value)} placeholder="Nº" />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Bairro</Label>
                <Input value={neighborhood} onChange={e => setNeighborhood(e.target.value)} />
              </div>
              <div className="space-y-2">
                <Label>CEP</Label>
                <Input value={cep} onChange={e => setCep(e.target.value)} placeholder="00000-000" />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Cidade</Label>
                <Input value={city} onChange={e => setCity(e.target.value)} />
              </div>
              <div className="space-y-2">
                <Label>Estado</Label>
                <Input value={state} onChange={e => setState(e.target.value)} placeholder="UF" />
              </div>
            </div>

            <div className="flex gap-2 pt-4">
              <Button variant="outline" className="flex-1" onClick={() => onOpenChange(false)}>
                Cancelar
              </Button>
              <Button className="flex-1" onClick={handleSubmit} disabled={isSaving}>
                {isSaving ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : null}
                Salvar
              </Button>
            </div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

// @ts-nocheck
import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Skeleton } from "@/components/ui/skeleton";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { Save, AlertCircle } from "lucide-react";

interface Material {
  id: number;
  name: string;
  type: string | null;
  unit: string;
}

interface ConsumptionRule {
  id?: number;
  material_type: string;
  size_p: number | null;
  size_m: number | null;
  size_g: number | null;
  company_id: number | null;
}

interface ConsumptionRulesModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function ConsumptionRulesModal({ open, onOpenChange }: ConsumptionRulesModalProps) {
  const { user } = useAuth();
  const [materials, setMaterials] = useState<Material[]>([]);
  const [rules, setRules] = useState<Record<string, ConsumptionRule>>({});
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [companyId, setCompanyId] = useState<number | null>(null);

  useEffect(() => {
    if (open) {
      fetchData();
    }
  }, [open, user?.id]);

  const fetchData = async () => {
    if (!user?.id) return;

    setLoading(true);
    try {
      const { data: profile } = await supabase
        .from("profiles")
        .select("company_id")
        .eq("user_id", user.id)
        .single();

      if (!profile?.company_id) {
        setLoading(false);
        return;
      }

      setCompanyId(profile.company_id);

      // Fetch materials
      const { data: materialsData } = await supabase
        .from("materials")
        .select("id, name, type, unit")
        .eq("company_id", profile.company_id)
        .eq("is_active", true)
        .order("name");

      // Fetch existing rules
      const { data: rulesData } = await supabase
        .from("consumption_rules")
        .select("*")
        .eq("company_id", profile.company_id);

      setMaterials(materialsData || []);

      // Create rules map indexed by material_type
      const rulesMap: Record<string, ConsumptionRule> = {};
      (rulesData || []).forEach((rule) => {
        rulesMap[rule.material_type] = rule;
      });

      setRules(rulesMap);
    } catch (error) {
      console.error("Error fetching data:", error);
      toast.error("Erro ao carregar dados");
    } finally {
      setLoading(false);
    }
  };

  const handleRuleChange = (
    materialType: string,
    size: "p" | "m" | "g",
    value: string
  ) => {
    const numValue = parseFloat(value) || 0;

    setRules((prev) => {
      const existingRule = prev[materialType] || {
        material_type: materialType,
        size_p: 0,
        size_m: 0,
        size_g: 0,
        company_id: companyId,
      };

      return {
        ...prev,
        [materialType]: {
          ...existingRule,
          [`size_${size}`]: numValue,
        } as ConsumptionRule,
      };
    });
  };

  const saveRules = async () => {
    if (!companyId) return;

    setSaving(true);

    try {
      // Save each rule with upsert
      for (const [materialType, rule] of Object.entries(rules)) {
        // Check if rule already exists
        const { data: existingRule } = await supabase
          .from("consumption_rules")
          .select("id")
          .eq("company_id", companyId)
          .eq("material_type", materialType)
          .single();

        if (existingRule) {
          // Update existing
          await supabase
            .from("consumption_rules")
            .update({
              size_p: rule.size_p || 0,
              size_m: rule.size_m || 0,
              size_g: rule.size_g || 0,
            })
            .eq("id", existingRule.id);
        } else {
          // Insert new
          await supabase.from("consumption_rules").insert({
            material_type: materialType,
            size_p: rule.size_p || 0,
            size_m: rule.size_m || 0,
            size_g: rule.size_g || 0,
            company_id: companyId,
          });
        }
      }

      toast.success("Regras de consumo salvas com sucesso!");
    } catch (error) {
      console.error("Error saving rules:", error);
      toast.error("Erro ao salvar regras de consumo");
    } finally {
      setSaving(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-2xl max-h-[80vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Regras de Consumo (P/M/G)</DialogTitle>
        </DialogHeader>

        <div className="space-y-6">
          <p className="text-sm text-muted-foreground">
            Define a quantidade de material consumido automaticamente por tamanho do veículo 
            (P = Pequeno, M = Médio, G = Grande).
          </p>

          {loading ? (
            <div className="space-y-2">
              {[1, 2, 3].map((i) => (
                <Skeleton key={i} className="h-12" />
              ))}
            </div>
          ) : materials.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              <AlertCircle className="h-8 w-8 mx-auto mb-2" />
              <p>Nenhum material cadastrado</p>
              <p className="text-sm">Cadastre materiais no Estoque para configurar regras de consumo</p>
            </div>
          ) : (
            <>
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Material</TableHead>
                    <TableHead>Tipo</TableHead>
                    <TableHead>Unidade</TableHead>
                    <TableHead className="text-center w-24">P</TableHead>
                    <TableHead className="text-center w-24">M</TableHead>
                    <TableHead className="text-center w-24">G</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {materials.map((material) => {
                    const materialType = material.type || material.name;
                    const rule: ConsumptionRule = rules[materialType] || {
                      material_type: materialType,
                      size_p: 0,
                      size_m: 0,
                      size_g: 0,
                      company_id: companyId,
                    };

                    return (
                      <TableRow key={material.id}>
                        <TableCell className="font-medium">{material.name}</TableCell>
                        <TableCell>
                          <Badge variant="outline">{material.type || "-"}</Badge>
                        </TableCell>
                        <TableCell className="text-muted-foreground">{material.unit}</TableCell>
                        <TableCell>
                          <Input
                            type="number"
                            step="0.01"
                            min="0"
                            placeholder="0"
                            value={rule.size_p || ""}
                            onChange={(e) => handleRuleChange(materialType, "p", e.target.value)}
                            className="w-20 text-center"
                          />
                        </TableCell>
                        <TableCell>
                          <Input
                            type="number"
                            step="0.01"
                            min="0"
                            placeholder="0"
                            value={rule.size_m || ""}
                            onChange={(e) => handleRuleChange(materialType, "m", e.target.value)}
                            className="w-20 text-center"
                          />
                        </TableCell>
                        <TableCell>
                          <Input
                            type="number"
                            step="0.01"
                            min="0"
                            placeholder="0"
                            value={rule.size_g || ""}
                            onChange={(e) => handleRuleChange(materialType, "g", e.target.value)}
                            className="w-20 text-center"
                          />
                        </TableCell>
                      </TableRow>
                    );
                  })}
                </TableBody>
              </Table>

              <div className="flex justify-end">
                <Button onClick={saveRules} disabled={saving}>
                  <Save className="h-4 w-4 mr-2" />
                  {saving ? "Salvando..." : "Salvar Regras"}
                </Button>
              </div>
            </>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { Save, Loader2, Calculator } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Input } from "@/components/ui/input";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { ProductCategory, VehicleRegion, RegionConsumptionRule, VehicleSize } from "@/lib/database.types";
import { Skeleton } from "@/components/ui/skeleton";

interface ConsumptionRulesTabProps {
  companyId: number | null;
}

interface ConsumptionInputProps {
  value: number;
  onChange: (value: number) => void;
  disabled: boolean;
}

function ConsumptionInput({ value, onChange, disabled }: ConsumptionInputProps) {
  return (
    <div className="flex items-center gap-2">
      <Input
        type="number"
        step="0.1"
        min="0"
        value={value === 0 ? '' : value}
        onChange={(e) => onChange(parseFloat(e.target.value) || 0)}
        disabled={disabled}
        className="w-20 sm:w-24 text-center h-8 sm:h-10 text-sm"
        placeholder="0.0"
      />
      <span className="text-xs sm:text-sm text-muted-foreground">metros</span>
    </div>
  );
}

export function ConsumptionRulesTab({ companyId }: ConsumptionRulesTabProps) {
  const [activeCategory, setActiveCategory] = useState<ProductCategory>("INSULFILM");
  const [formValues, setFormValues] = useState<Record<number, Record<VehicleSize, number>>>({});
  const [isDirty, setIsDirty] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  // Query para carregar regiões
  const { data: regions, isLoading: isLoadingRegions } = useQuery({
    queryKey: ["vehicle-regions-for-rules", activeCategory, companyId],
    queryFn: async () => {
      if (!companyId) return [];
      const { data, error } = await supabase
        .from("vehicle_regions")
        .select("id, name, description")
        .eq("company_id", companyId)
        .eq("category", activeCategory)
        .eq("is_active", true)
        .order("sort_order");

      if (error) throw error;
      return data as Pick<VehicleRegion, "id" | "name" | "description">[];
    },
    enabled: !!companyId,
  });

  // Query para carregar regras existentes
  const { data: existingRules, refetch: refetchRules, isLoading: isLoadingRules } = useQuery({
    queryKey: ["consumption-rules", activeCategory, companyId],
    queryFn: async () => {
      if (!companyId) return [];
      const { data, error } = await supabase
        .from("region_consumption_rules")
        .select("*")
        .eq("company_id", companyId)
        .eq("category", activeCategory);

      if (error) throw error;
      return data as RegionConsumptionRule[];
    },
    enabled: !!companyId,
  });

  // Criar mapa de regras existentes
  const rulesMap = useMemo(() => {
    const map: Record<number, Record<VehicleSize, number>> = {};
    existingRules?.forEach((rule) => {
      if (!map[rule.region_id]) map[rule.region_id] = { P: 0, M: 0, G: 0 };
      map[rule.region_id][rule.vehicle_size] = rule.meters_consumed;
    });
    return map;
  }, [existingRules]);

  // Inicializar valores do formulário quando dados carregarem
  useEffect(() => {
    if (regions && rulesMap) {
      const initialValues: Record<number, Record<VehicleSize, number>> = {};
      regions.forEach((region) => {
        initialValues[region.id] = {
          P: rulesMap[region.id]?.P || 0,
          M: rulesMap[region.id]?.M || 0,
          G: rulesMap[region.id]?.G || 0,
        };
      });
      setFormValues(initialValues);
      setIsDirty(false);
    }
  }, [regions, rulesMap]);

  // Handler de mudança de input
  const handleInputChange = (regionId: number, size: VehicleSize, value: number) => {
    setFormValues((prev) => ({
      ...prev,
      [regionId]: {
        ...prev[regionId],
        [size]: Math.max(0, value),
      },
    }));
    setIsDirty(true);
  };

  // Handler de salvar todas as regras
  const handleSaveAllRules = async () => {
    setIsSaving(true);

    try {
      // Converter formValues em array de regras
      const rulesArray: Array<{
        region_id: number;
        vehicle_size: VehicleSize;
        meters_consumed: number;
        category: ProductCategory;
        company_id: number;
      }> = [];

      Object.entries(formValues).forEach(([regionId, sizes]) => {
        (["P", "M", "G"] as VehicleSize[]).forEach((size) => {
          rulesArray.push({
            region_id: parseInt(regionId),
            vehicle_size: size,
            meters_consumed: sizes[size] || 0,
            category: activeCategory,
            company_id: companyId!,
          });
        });
      });

      // UPSERT todas as regras
      const { error } = await supabase
        .from("region_consumption_rules")
        .upsert(rulesArray, {
          onConflict: "region_id,vehicle_size,company_id",
        });

      if (error) throw error;

      toast.success("Regras de consumo salvas com sucesso!");
      setIsDirty(false);
      refetchRules();
    } catch (error: any) {
      toast.error("Erro ao salvar regras: " + error.message);
    } finally {
      setIsSaving(false);
    }
  };

  const isLoading = isLoadingRegions || isLoadingRules;

  if (isLoading) {
    return (
      <div className="space-y-4">
        <Skeleton className="h-10 w-full" />
        <Skeleton className="h-64 w-full" />
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Header com sub-tabs e botão salvar */}
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3">
        <Tabs value={activeCategory} onValueChange={(v) => setActiveCategory(v as ProductCategory)}>
          <TabsList>
            <TabsTrigger value="INSULFILM">INSULFILM</TabsTrigger>
            <TabsTrigger value="PPF">PPF</TabsTrigger>
          </TabsList>
        </Tabs>

        <Button onClick={handleSaveAllRules} disabled={!isDirty || isSaving} className="w-full sm:w-auto">
          {isSaving ? (
            <>
              <Loader2 className="h-4 w-4 mr-2 animate-spin" />
              Salvando...
            </>
          ) : (
            <>
              <Save className="h-4 w-4 mr-2" />
              Salvar Todas as Regras
            </>
          )}
        </Button>
      </div>

      {/* Tabela de regras */}
      {!regions || regions.length === 0 ? (
        <Card className="bg-card/50 border-border/50">
          <CardContent className="p-12 text-center">
            <Calculator className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
            <h3 className="text-lg font-medium mb-2">
              Nenhuma região cadastrada para {activeCategory}
            </h3>
            <p className="text-muted-foreground">
              Cadastre regiões na aba "Regiões do Veículo" primeiro.
            </p>
          </CardContent>
        </Card>
      ) : (
        <>
          {/* Desktop View */}
          <div className="hidden md:block">
            <Card className="bg-card/50 border-border/50">
              <CardContent className="p-0">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Região</TableHead>
                      <TableHead className="text-center">P (Pequeno)</TableHead>
                      <TableHead className="text-center">M (Médio)</TableHead>
                      <TableHead className="text-center">G (Grande)</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {regions.map((region) => (
                      <TableRow key={region.id}>
                        <TableCell>
                          <div>
                            <p className="font-medium">{region.name}</p>
                            {region.description && (
                              <p className="text-sm text-muted-foreground">{region.description}</p>
                            )}
                          </div>
                        </TableCell>
                        <TableCell>
                          <div className="flex justify-center">
                            <ConsumptionInput
                              value={formValues[region.id]?.P || 0}
                              onChange={(val) => handleInputChange(region.id, "P", val)}
                              disabled={isSaving}
                            />
                          </div>
                        </TableCell>
                        <TableCell>
                          <div className="flex justify-center">
                            <ConsumptionInput
                              value={formValues[region.id]?.M || 0}
                              onChange={(val) => handleInputChange(region.id, "M", val)}
                              disabled={isSaving}
                            />
                          </div>
                        </TableCell>
                        <TableCell>
                          <div className="flex justify-center">
                            <ConsumptionInput
                              value={formValues[region.id]?.G || 0}
                              onChange={(val) => handleInputChange(region.id, "G", val)}
                              disabled={isSaving}
                            />
                          </div>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          </div>

          {/* Mobile View */}
          <div className="grid grid-cols-1 gap-3 md:hidden">
            {regions.map((region) => (
              <Card key={region.id} className="bg-card/30 border-border/50 overflow-hidden">
                <div className="p-3 bg-muted/20 border-b border-border/50">
                  <p className="font-semibold text-sm">{region.name}</p>
                  {region.description && (
                    <p className="text-[10px] text-muted-foreground mt-0.5">{region.description}</p>
                  )}
                </div>
                <CardContent className="p-3 grid grid-cols-1 gap-2">
                  <div className="flex items-center justify-between border-border/20 pb-2 border-b">
                    <span className="text-xs font-semibold text-muted-foreground">P (Pequeno)</span>
                    <ConsumptionInput
                      value={formValues[region.id]?.P || 0}
                      onChange={(val) => handleInputChange(region.id, "P", val)}
                      disabled={isSaving}
                    />
                  </div>
                  <div className="flex items-center justify-between border-border/20 pb-2 border-b">
                    <span className="text-xs font-semibold text-muted-foreground">M (Médio)</span>
                    <ConsumptionInput
                      value={formValues[region.id]?.M || 0}
                      onChange={(val) => handleInputChange(region.id, "M", val)}
                      disabled={isSaving}
                    />
                  </div>
                  <div className="flex items-center justify-between">
                    <span className="text-xs font-semibold text-muted-foreground">G (Grande)</span>
                    <ConsumptionInput
                      value={formValues[region.id]?.G || 0}
                      onChange={(val) => handleInputChange(region.id, "G", val)}
                      disabled={isSaving}
                    />
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        </>
      )}

      {isDirty && (
        <p className="text-sm text-muted-foreground text-center">
          * Você tem alterações não salvas
        </p>
      )}
    </div>
  );
}

import { useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { BarChart3, PieChart as PieIcon } from "lucide-react";
import {
  Bar,
  BarChart,
  Cell,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
  PieChart,
  Pie,
} from "recharts";
import { Card, CardContent } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";
import { ProductCategory } from "@/lib/database.types";
import { supabase } from "@/integrations/supabase/client";
import { getOperationalStatus } from "@/lib/stockHistory";

interface HistoryAnalyticsSectionProps {
  companyId: number | null;
  activeCategory: ProductCategory;
  filteredMaterials: {
    id: number;
    name: string;
    brand: string | null;
    unit: string;
    current_stock: number | null;
    is_active: boolean | null;
    is_open_roll: boolean | null;
    open_roll_accumulated: number | null;
    product_types: {
      ppf_material_type: string | null;
      light_transmission: string | null;
    } | null;
  }[];
  rangeStart: Date;
}

const PPF_TYPE_COLORS: Record<string, string> = {
  TPU: "#3b82f6",
  TPH: "#f59e0b",
  PVC: "#10b981",
};

export function HistoryAnalyticsSection({
  companyId,
  activeCategory,
  filteredMaterials,
  rangeStart,
}: HistoryAnalyticsSectionProps) {
  const eligibleMaterialIds = useMemo(
    () => filteredMaterials.map((material) => material.id),
    [filteredMaterials]
  );

  const materialNameMap = useMemo(() => {
    const map = new Map<number, string>();
    filteredMaterials.forEach((material) => {
      const transmission = material.product_types?.light_transmission;
      const displayName = transmission ? `${material.name} (${transmission})` : material.name;
      map.set(material.id, displayName);
    });
    return map;
  }, [filteredMaterials]);

  const { data: consumptionData, isLoading } = useQuery({
    queryKey: [
      "history-analytics-consumption",
      companyId,
      activeCategory,
      rangeStart.toISOString(),
      eligibleMaterialIds.join(","),
    ],
    queryFn: async () => {
      if (!companyId || !eligibleMaterialIds.length) return [];

      const { data, error } = await supabase
        .from("stock_movements")
        .select("quantity, material_id, created_at, is_open_roll_closure")
        .eq("company_id", companyId)
        .in("movement_type", ["Saida", "open_roll_use"])
        .eq("is_open_roll_closure", false)
        .in("material_id", eligibleMaterialIds)
        .gte("created_at", rangeStart.toISOString());

      if (error) throw error;
      if (!data) return [];

      const materialMap = new Map<number, { name: string; total: number }>();

      data.forEach((movement) => {
        if (!movement.material_id) return;

        const existing = materialMap.get(movement.material_id);
        if (existing) {
          existing.total += movement.quantity;
          return;
        }

        materialMap.set(movement.material_id, {
          name:
            materialNameMap.get(movement.material_id) ||
            `Material ${movement.material_id}`,
          total: movement.quantity,
        });
      });

      return Array.from(materialMap.values())
        .sort((left, right) => right.total - left.total)
        .slice(0, 10);
    },
    enabled: !!companyId,
  });

  const ppfDistribution = useMemo(() => {
    if (activeCategory !== "PPF") return [];

    const counts: Record<string, number> = {};
    filteredMaterials.forEach((material) => {
      const type = material.product_types?.ppf_material_type;
      if (!type) return;
      counts[type] = (counts[type] || 0) + 1;
    });

    return Object.entries(counts).map(([name, value]) => ({ name, value }));
  }, [activeCategory, filteredMaterials]);

  const statusData = useMemo(() => {
    const counts: Record<string, number> = {
      "Aberta em Uso": 0,
      "Aberta Encerrada": 0,
      "Fechada em Estoque": 0,
      "Inativo": 0,
    };

    filteredMaterials.forEach((material) => {
      const status = getOperationalStatus(material as any);
      if (status === "open_in_use") counts["Aberta em Uso"] += 1;
      else if (status === "open_closed") counts["Aberta Encerrada"] += 1;
      else if (status === "closed_in_stock") counts["Fechada em Estoque"] += 1;
      else if (status === "inactive") counts["Inativo"] += 1;
    });

    return Object.entries(counts)
      .map(([name, value]) => ({ name, value }))
      .filter((item) => item.value > 0);
  }, [filteredMaterials]);

  const brandStockData = useMemo(() => {
    const brandMap = new Map<string, number>();
    filteredMaterials.forEach((material) => {
      const stock = material.is_open_roll ? 0 : (material.current_stock || 0);
      if (stock <= 0) return;
      const brand = material.brand || "Sem Marca";
      brandMap.set(brand, (brandMap.get(brand) || 0) + stock);
    });

    return Array.from(brandMap.entries())
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 5);
  }, [filteredMaterials]);

  const STATUS_COLORS = ["#3b82f6", "#f59e0b", "#10b981", "#6b7280"];
  const BRAND_COLORS = ["#8b5cf6", "#3b82f6", "#10b981", "#ef4444", "#f59e0b"];

  const hasConsumptionData = !!consumptionData?.length;
  const hasPpfDistribution =
    activeCategory === "PPF" && ppfDistribution.length > 0;

  if (isLoading) {
    return (
      <Card className="bg-card/50 border-border/50">
        <CardContent className="p-6">
          <Skeleton className="mb-4 h-6 w-48" />
          <Skeleton className="h-64 w-full" />
        </CardContent>
      </Card>
    );
  }

  const hasAnyData = hasConsumptionData || hasPpfDistribution || statusData.length > 0 || brandStockData.length > 0;

  if (!hasAnyData) {
    return (
      <Card className="bg-card/50 border-border/50">
        <CardContent className="p-8 text-center">
          <BarChart3 className="mx-auto mb-4 h-12 w-12 text-muted-foreground" />
          <h3 className="mb-2 text-lg font-medium">Analises do Historico</h3>
          <p className="text-muted-foreground">
            Dados insuficientes para gerar analise no periodo selecionado.
          </p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-6">
      <h3 className="text-lg font-semibold tracking-tight text-foreground flex items-center gap-2 border-b border-border/40 pb-2">
        <PieIcon className="h-5 w-5 text-primary" /> Análises Visuais de Estoque ({activeCategory})
      </h3>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Gráfico 1: Top 10 - Materiais Mais Usados */}
        {hasConsumptionData && (
          <Card className="bg-card/50 border-border/50">
            <CardContent className="p-6">
              <h4 className="mb-4 flex items-center gap-2 text-sm font-semibold">
                <BarChart3 className="h-4 w-4 text-primary" />
                Top 10 - Materiais Mais Usados
              </h4>
              <div className="h-72">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart
                    data={consumptionData}
                    layout="vertical"
                    margin={{ top: 5, right: 30, left: 0, bottom: 5 }}
                  >
                    <XAxis type="number" />
                    <YAxis
                      dataKey="name"
                      type="category"
                      width={120}
                      tick={{ fontSize: 11 }}
                    />
                    <Tooltip
                      formatter={(value: number) => [
                        `${value.toFixed(1)}m`,
                        "Consumo",
                      ]}
                    />
                    <Bar
                      dataKey="total"
                      fill="hsl(var(--primary))"
                      radius={[0, 4, 4, 0]}
                    />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </CardContent>
          </Card>
        )}

        {/* Gráfico 2: Distribuição por Situação (Pizza) */}
        {statusData.length > 0 && (
          <Card className="bg-card/50 border-border/50">
            <CardContent className="p-6">
              <h4 className="mb-4 flex items-center gap-2 text-sm font-semibold">
                <PieIcon className="h-4 w-4 text-blue-500" />
                Situação das Bobinas / Materiais
              </h4>
              <div className="h-72 flex flex-col justify-between">
                <div className="h-[80%] w-full flex items-center justify-center">
                  <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie
                        data={statusData}
                        cx="50%"
                        cy="50%"
                        innerRadius={50}
                        outerRadius={70}
                        paddingAngle={3}
                        dataKey="value"
                      >
                        {statusData.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={STATUS_COLORS[index % STATUS_COLORS.length]} />
                        ))}
                      </Pie>
                      <Tooltip formatter={(value: number) => [value, "Materiais"]} />
                    </PieChart>
                  </ResponsiveContainer>
                </div>
                <div className="flex flex-wrap justify-center gap-x-3 gap-y-1 text-[11px]">
                  {statusData.map((entry, index) => (
                    <div key={entry.name} className="flex items-center gap-1">
                      <div className="w-2 h-2 rounded-full" style={{ backgroundColor: STATUS_COLORS[index % STATUS_COLORS.length] }} />
                      <span className="text-muted-foreground">{entry.name}: <span className="font-semibold text-foreground">{entry.value}</span></span>
                    </div>
                  ))}
                </div>
              </div>
            </CardContent>
          </Card>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Gráfico 3: Distribuição de Estoque por Marca (Pizza) */}
        {brandStockData.length > 0 && (
          <Card className="bg-card/50 border-border/50">
            <CardContent className="p-6">
              <h4 className="mb-4 flex items-center gap-2 text-sm font-semibold">
                <PieIcon className="h-4 w-4 text-purple-500" />
                Volume de Estoque por Marca
              </h4>
              <div className="h-72 flex flex-col justify-between">
                <div className="h-[80%] w-full flex items-center justify-center">
                  <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                      <Pie
                        data={brandStockData}
                        cx="50%"
                        cy="50%"
                        outerRadius={70}
                        paddingAngle={2}
                        dataKey="value"
                      >
                        {brandStockData.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={BRAND_COLORS[index % BRAND_COLORS.length]} />
                        ))}
                      </Pie>
                      <Tooltip formatter={(value: number) => [`${value.toFixed(1)} un/m`, "Estoque"]} />
                    </PieChart>
                  </ResponsiveContainer>
                </div>
                <div className="flex flex-wrap justify-center gap-x-3 gap-y-1 text-[11px]">
                  {brandStockData.map((entry, index) => (
                    <div key={entry.name} className="flex items-center gap-1">
                      <div className="w-2 h-2 rounded-full" style={{ backgroundColor: BRAND_COLORS[index % BRAND_COLORS.length] }} />
                      <span className="text-muted-foreground">{entry.name}: <span className="font-semibold text-foreground">{entry.value.toFixed(1)}</span></span>
                    </div>
                  ))}
                </div>
              </div>
            </CardContent>
          </Card>
        )}

        {/* Gráfico 4: Distribuição PPF */}
        {hasPpfDistribution && (
          <Card className="bg-card/50 border-border/50">
            <CardContent className="p-6">
              <h4 className="mb-4 flex items-center gap-2 text-sm font-semibold">
                <BarChart3 className="h-4 w-4 text-amber-500" />
                Distribuição PPF por Tipo de Material
              </h4>
              <div className="h-72">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart
                    data={ppfDistribution}
                    margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
                  >
                    <XAxis dataKey="name" tick={{ fontSize: 11 }} />
                    <YAxis allowDecimals={false} />
                    <Tooltip
                      formatter={(value: number) => [value, "Tipos cadastrados"]}
                    />
                    <Bar dataKey="value" radius={[4, 4, 0, 0]}>
                      {ppfDistribution.map((entry) => (
                        <Cell
                          key={entry.name}
                          fill={PPF_TYPE_COLORS[entry.name] || "#6b7280"}
                        />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </CardContent>
          </Card>
        )}
      </div>
    </div>
  );
}

// @ts-nocheck
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Package, ArrowDown, ArrowUp, Activity } from "lucide-react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { cn } from "@/lib/utils";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { Skeleton } from "@/components/ui/skeleton";

interface Material {
  id: number;
  name: string;
  type: string | null;
  brand: string | null;
  unit: string;
  current_stock: number | null;
  minimum_stock: number | null;
  average_cost: number | null;
  is_active: boolean | null;
  is_open_roll: boolean | null;
  open_roll_accumulated: number | null;
  company_id: number | null;
  product_type_id: number | null;
  product_types?: { light_transmission: string | null; cost_per_meter: number | null } | null;
}

interface MaterialDetailsModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  material: Material | null;
}

export function MaterialDetailsModal({ open, onOpenChange, material }: MaterialDetailsModalProps) {
  const { data: movements, isLoading } = useQuery({
    queryKey: ["stock-movements", material?.id],
    queryFn: async () => {
      if (!material?.id) return [];
      const { data, error } = await supabase
        .from("stock_movements")
        .select("*")
        .eq("material_id", material.id)
        .order("created_at", { ascending: false });

      if (error) throw error;
      return data;
    },
    enabled: !!material?.id && open,
  });

  if (!material) return null;

  const getStockStatus = (material: Material) => {
    if (material.is_open_roll) {
      return { status: "em_uso", label: "Em Uso", color: "text-blue-500", bg: "bg-blue-500/10" };
    }
    const currentStock = material.current_stock || 0;
    const minStock = material.minimum_stock || 1;
    const ratio = currentStock / minStock;

    if (ratio <= 0.5) return { status: "critico", label: "Crítico", color: "text-red-500", bg: "bg-red-500/10" };
    if (ratio <= 1) return { status: "baixo", label: "Baixo", color: "text-yellow-500", bg: "bg-yellow-500/10" };
    return { status: "ok", label: "OK", color: "text-green-500", bg: "bg-green-500/10" };
  };

  const status = getStockStatus(material);
  const currentCost = material.product_types?.cost_per_meter || material.average_cost || 0;
  const totalVal = (material.is_open_roll
    ? (material.open_roll_accumulated || 0)
    : (material.current_stock || 0)) * currentCost;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto w-[90vw]">
        <DialogHeader className="mb-4">
          <div className="flex items-start justify-between">
            <div className="flex flex-col gap-1">
              <DialogTitle className="text-2xl font-bold flex items-center gap-2">
                <Package className="h-6 w-6 text-primary" />
                {material.name}
              </DialogTitle>
              <DialogDescription className="text-base">
                Detalhes completos e histórico de movimentações
              </DialogDescription>
            </div>
            <Badge className={cn(status.bg, status.color, "border-0 shadow-none text-sm px-3 py-1 font-semibold tracking-wide uppercase")}>
              {status.label}
            </Badge>
          </div>
        </DialogHeader>

        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
          <div className="bg-muted/40 border p-4 rounded-xl flex flex-col justify-center">
            <span className="text-xs text-muted-foreground mb-1 uppercase tracking-wider font-semibold">
              {material.is_open_roll ? "Consumo Acumulado" : "Estoque Atual"}
            </span>
            <span className={cn("text-3xl font-bold mt-1", material.is_open_roll ? "text-blue-500" : "text-primary")}>
              {material.is_open_roll ? `${material.open_roll_accumulated || 0} ` : `${material.current_stock || 0} `}
              <span className="text-lg text-muted-foreground font-normal">{material.unit}</span>
            </span>
          </div>

          <div className="bg-muted/40 border p-4 rounded-xl flex flex-col justify-center">
            <span className="text-xs text-muted-foreground mb-1 uppercase tracking-wider font-semibold">
              {material.is_open_roll ? "Tipo de Rolagem" : "Estoque Mínimo"}
            </span>
            <span className="text-xl font-medium mt-1">
              {material.is_open_roll ? "Bobina Aberta" : `${material.minimum_stock || 0} ${material.unit}`}
            </span>
            {material.is_open_roll && (
              <span className="text-xs text-muted-foreground mt-1">Consumo acumulado até encerramento.</span>
            )}
          </div>

          <div className="bg-muted/40 border p-4 rounded-xl flex flex-col justify-center">
            <span className="text-xs text-muted-foreground mb-1 uppercase tracking-wider font-semibold">Marca / Tipo</span>
            <span className="text-xl font-medium mt-1 truncate" title={`${material.brand || '-'} / ${material.type || '-'}`}>
              {material.brand || "-"}
            </span>
            <span className="text-sm text-muted-foreground truncate">{material.type || "-"}</span>
          </div>

          <div className="bg-muted/40 border p-4 rounded-xl flex flex-col justify-center">
            <span className="text-xs text-muted-foreground mb-1 uppercase tracking-wider font-semibold">
              {material.is_open_roll ? "Valor Consumido" : "Valor em Estoque"}
            </span>
            <span className="text-xl font-medium mt-1">
              {totalVal.toLocaleString("pt-BR", { style: "currency", currency: "BRL" })}
            </span>
            <span className="text-xs text-muted-foreground mt-1">
              {currentCost.toLocaleString("pt-BR", { style: "currency", currency: "BRL" })} / {material.unit}
            </span>
          </div>
        </div>

        <div className="mt-2 border rounded-xl overflow-hidden bg-card shadow-sm">
          <div className="bg-muted/50 p-4 border-b flex items-center justify-between">
            <h3 className="font-semibold flex items-center gap-2">
              <Activity className="h-4 w-4 text-primary" />
              Histórico de Movimentações ({movements?.length || 0})
            </h3>
          </div>

          <div className="max-h-[400px] overflow-y-auto">
            <Table>
              <TableHeader className="bg-background sticky top-0 z-10 shadow-sm">
                <TableRow>
                  <TableHead className="w-[180px]">Data e Hora</TableHead>
                  <TableHead className="w-[180px]">Tipo</TableHead>
                  <TableHead className="w-[150px]">Quantidade</TableHead>
                  <TableHead>Referência / Motivo</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {isLoading ? (
                  Array(3).fill(0).map((_, i) => (
                    <TableRow key={i}>
                      <TableCell><Skeleton className="h-5 w-24" /></TableCell>
                      <TableCell><Skeleton className="h-5 w-24" /></TableCell>
                      <TableCell><Skeleton className="h-5 w-16" /></TableCell>
                      <TableCell><Skeleton className="h-5 w-[200px]" /></TableCell>
                    </TableRow>
                  ))
                ) : movements && movements.length > 0 ? (
                  movements.map((mov) => {
                    const isEntry = mov.movement_type === "Entrada" || mov.movement_type === "Saldo Inicial";
                    const isExit = mov.movement_type === "Saida" || mov.movement_type === "Saída";
                    const isAdjustmentOpen = mov.movement_type === "Ajuste Bobina Aberta";
                    const isOpenRollUse = mov.movement_type === "open_roll_use";
                    const isOpenRollClosure = mov.movement_type === "open_roll_closure";

                    // Bobinas abertas acumulam uso (somam), estoque fechado subtrai
                    const isAccumulation = isOpenRollUse;
                    const showPositive = isEntry || isAccumulation;

                    return (
                      <TableRow key={mov.id} className="hover:bg-muted/30 transition-colors">
                        <TableCell>
                          <div className="font-medium text-sm">
                            {format(new Date(mov.created_at), "dd/MM/yyyy", { locale: ptBR })}
                          </div>
                          <div className="text-xs text-muted-foreground mt-0.5">
                            {format(new Date(mov.created_at), "HH:mm")}
                          </div>
                        </TableCell>
                        <TableCell>
                          {isEntry ? (
                            <Badge variant="outline" className="border-green-500 text-green-700 bg-green-500/10 font-medium whitespace-nowrap">
                              <ArrowDown className="h-3 w-3 mr-1" /> {mov.movement_type}
                            </Badge>
                          ) : isExit ? (
                            <Badge variant="outline" className="border-red-500 text-red-700 bg-red-500/10 font-medium whitespace-nowrap">
                              <ArrowUp className="h-3 w-3 mr-1" /> Consumo Geral
                            </Badge>
                          ) : isAdjustmentOpen ? (
                            <Badge variant="outline" className="border-blue-500 text-blue-700 bg-blue-500/10 font-medium whitespace-nowrap">
                              <Activity className="h-3 w-3 mr-1" /> Bobina Aberta
                            </Badge>
                          ) : isOpenRollUse ? (
                            <Badge variant="outline" className="border-blue-500 text-blue-700 bg-blue-500/10 font-medium whitespace-nowrap">
                              <ArrowUp className="h-3 w-3 mr-1" /> Uso de Bobina Aberta
                            </Badge>
                          ) : isOpenRollClosure ? (
                            <Badge variant="outline" className="border-orange-500 text-orange-700 bg-orange-500/10 font-medium whitespace-nowrap">
                              <Activity className="h-3 w-3 mr-1" /> Encerramento de Bobina
                            </Badge>
                          ) : (
                            <Badge variant="outline" className="text-muted-foreground whitespace-nowrap">
                              {mov.movement_type}
                            </Badge>
                          )}
                        </TableCell>
                        <TableCell>
                          <div className={cn(
                            "font-semibold font-mono tabular-nums",
                            isEntry ? "text-green-600" : isOpenRollUse ? "text-blue-600" : isOpenRollClosure ? "text-orange-600" : (isExit || isAdjustmentOpen) ? "text-foreground" : ""
                          )}>
                            {showPositive ? "+" : "-"}{mov.quantity} {material.unit}
                          </div>
                        </TableCell>
                        <TableCell>
                          <div className="text-sm truncate max-w-[300px]" title={mov.reason || ""}>
                            {mov.reason || "-"}
                          </div>
                        </TableCell>
                      </TableRow>
                    );
                  })
                ) : (
                  <TableRow>
                    <TableCell colSpan={4} className="h-32 text-center text-muted-foreground">
                      <div className="flex flex-col flex-center items-center justify-center gap-2">
                        <Activity className="h-8 w-8 text-muted-foreground/30" />
                        <p>Nenhuma movimentação registrada.</p>
                      </div>
                    </TableCell>
                  </TableRow>
                )}
              </TableBody>
            </Table>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

// @ts-nocheck
import { useState, useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectGroup, SelectItem, SelectLabel, SelectSeparator, SelectTrigger, SelectValue } from "@/components/ui/select";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";

interface NewMaterialModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSuccess?: () => void;
}

interface ProductType {
  id: number;
  category: string;
  brand: string;
  name: string;
  model: string | null;
  light_transmission: string | null;
  cost_per_meter: number | null;
}

export function NewMaterialModal({ open, onOpenChange, onSuccess }: NewMaterialModalProps) {
  const { user } = useAuth();
  const [selectedProductTypeId, setSelectedProductTypeId] = useState("");
  const [unit, setUnit] = useState("Metros");
  const [minStock, setMinStock] = useState("");
  const [currentStock, setCurrentStock] = useState("");
  const [isOpenRoll, setIsOpenRoll] = useState(false);
  const [width, setWidth] = useState("");
  const [loading, setLoading] = useState(false);
  const [companyId, setCompanyId] = useState<number | null>(null);

  // Fetch existing material to check width
  const { data: existingMaterial } = useQuery({
    queryKey: ['existing-material-width', selectedProductTypeId, isOpenRoll, companyId],
    queryFn: async () => {
      if (!selectedProductTypeId || !companyId) return null;
      const { data, error } = await supabase
        .from("materials")
        .select("id, width, current_stock")
        .eq("product_type_id", parseInt(selectedProductTypeId))
        .eq("company_id", companyId)
        .eq("is_open_roll", isOpenRoll)
        .maybeSingle();
      if (error) {
        console.error("Error fetching existing material:", error);
        return null;
      }
      return data;
    },
    enabled: !!selectedProductTypeId && !!companyId && open,
  });

  // Update width when existing material is loaded
  useEffect(() => {
    if (existingMaterial) {
      if (existingMaterial.width) {
        setWidth(existingMaterial.width.toString());
      } else {
        setWidth("1.52");
      }
    } else {
      setWidth("");
    }
  }, [existingMaterial]);

  // Fetch company ID
  const { data: profile } = useQuery({
    queryKey: ['profile-for-material', user?.id],
    queryFn: async () => {
      if (!user?.id) return null;
      const { data } = await supabase
        .from("profiles")
        .select("company_id")
        .eq("user_id", user.id)
        .single();
      if (data?.company_id) {
        setCompanyId(data.company_id);
      }
      return data;
    },
    enabled: !!user?.id && open,
  });

  // Fetch product types for the select
  const { data: productTypes } = useQuery({
    queryKey: ['product-types-for-select', companyId],
    queryFn: async () => {
      if (!companyId) return [];
      const { data, error } = await supabase
        .from('product_types')
        .select('id, category, brand, name, model, light_transmission, cost_per_meter')
        .eq('company_id', companyId)
        .eq('is_active', true)
        .order('category')
        .order('brand')
        .order('name');
      if (error) throw error;
      return data as ProductType[];
    },
    enabled: !!companyId && open,
  });

  const insulfilmProducts = productTypes?.filter(p => p.category === 'INSULFILM') || [];
  const ppfProducts = productTypes?.filter(p => p.category === 'PPF') || [];

  const handleSubmit = async () => {
    if (!selectedProductTypeId) {
      toast.error("Selecione um tipo de produto");
      return;
    }

    if (!user?.id || !companyId) {
      toast.error("Usuário não autenticado");
      return;
    }

    setLoading(true);

    try {
      const selectedProduct = productTypes?.find(p => p.id === parseInt(selectedProductTypeId));
      if (!selectedProduct) {
        toast.error("Produto não encontrado");
        return;
      }

      // Check if material already exists for this product type and roll state (active or inactive)
      const { data: existingMaterial } = await supabase
        .from("materials")
        .select("id, is_active, width")
        .eq("product_type_id", selectedProduct.id)
        .eq("company_id", companyId)
        .eq("is_open_roll", isOpenRoll)
        .maybeSingle();

      // Validação inteligente de largura: obrigatória apenas no primeiro cadastro de rolo do tipo "Metros"
      if (unit === "Metros" && !existingMaterial) {
        if (!width || parseFloat(width) <= 0) {
          toast.error("A largura da bobina é obrigatória para o primeiro cadastro deste material");
          setLoading(false);
          return;
        }
      }

      const materialNameBase = `${selectedProduct.brand ? selectedProduct.brand + ' ' : ''}${selectedProduct.name}${selectedProduct.model ? ` - ${selectedProduct.model}` : ''}`;
      const materialName = isOpenRoll ? `${materialNameBase} (Aberta)` : materialNameBase;

      let error;

      if (existingMaterial) {
        // Update the existing material with new stock values (keeping or adjusting the width)
        const { error: updateError } = await supabase
          .from("materials")
          .update({
            name: materialName,
            type: selectedProduct.category,
            brand: selectedProduct.brand,
            unit,
            minimum_stock: minStock ? parseFloat(minStock) : 0,
            current_stock: isOpenRoll ? 0 : (currentStock ? parseFloat(currentStock) : 0),
            average_cost: selectedProduct.cost_per_meter || 0,
            product_type_id: selectedProduct.id,
            is_active: true,
            is_open_roll: isOpenRoll,
            width: unit === "Metros" ? (width ? parseFloat(width) : (existingMaterial.width || 1.52)) : null,
          })
          .eq("id", existingMaterial.id);
        error = updateError;
      } else {
        // Create new material
        const initialQty = currentStock && parseFloat(currentStock) > 0 ? parseFloat(currentStock) : 0;

        // Se for metros e tiver estoque inicial, inserimos com 0 e criamos a bobina via RPC depois para sincronizar com material_rolls
        const stockToInsert = (unit === "Metros" && initialQty > 0) ? 0 : initialQty;

        const { data: newMaterial, error: insertError } = await supabase
          .from("materials")
          .insert({
            name: materialName,
            type: selectedProduct.category,
            brand: selectedProduct.brand,
            unit,
            minimum_stock: minStock ? parseFloat(minStock) : 0,
            current_stock: stockToInsert,
            average_cost: selectedProduct.cost_per_meter || 0,
            company_id: companyId,
            product_type_id: selectedProduct.id,
            is_active: true,
            is_open_roll: isOpenRoll,
            width: unit === "Metros" ? (width ? parseFloat(width) : 1.52) : null,
          })
          .select()
          .single();

        if (insertError) {
          error = insertError;
        } else if (unit === "Metros" && initialQty > 0 && newMaterial) {
          // Criar a bobina física correspondente ao estoque inicial
          const { error: rpcError } = await supabase.rpc("add_material_roll", {
            p_material_id: newMaterial.id,
            p_length: initialQty,
            p_status: "fechada",
            p_notes: "Estoque inicial (cadastro de material)",
            p_user_id: user.id,
            p_company_id: companyId,
          });
          error = rpcError;
        }
      }

      if (error) throw error;

      onOpenChange(false);
      resetForm();
      onSuccess?.();
    } catch (error: any) {
      console.error("Error creating material:", error);
      toast.error(`Erro ao cadastrar material: ${error.message || error.details || JSON.stringify(error)}`);
    } finally {
      setLoading(false);
    }
  };

  const resetForm = () => {
    setSelectedProductTypeId("");
    setUnit("Metros");
    setMinStock("");
    setCurrentStock("");
    setIsOpenRoll(false);
    setWidth("");
  };

  const formatProductLabel = (product: ProductType) => {
    let label = product.brand ? `${product.brand} ${product.name}` : product.name;
    if (product.light_transmission) label += ` (${product.light_transmission})`;
    if (product.model) label += ` - ${product.model}`;
    return label;
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>Novo Material</DialogTitle>
        </DialogHeader>

        <div className="space-y-4">
          <div className="space-y-2">
            <Label>Tipo de Produto *</Label>
            <Select value={selectedProductTypeId} onValueChange={setSelectedProductTypeId}>
              <SelectTrigger>
                <SelectValue placeholder="Selecione um produto..." />
              </SelectTrigger>
              <SelectContent>
                {insulfilmProducts.length > 0 && (
                  <SelectGroup>
                    <SelectLabel>INSULFILM</SelectLabel>
                    {insulfilmProducts.map(p => (
                      <SelectItem key={p.id} value={p.id.toString()}>
                        {formatProductLabel(p)}
                      </SelectItem>
                    ))}
                  </SelectGroup>
                )}
                {insulfilmProducts.length > 0 && ppfProducts.length > 0 && <SelectSeparator />}
                {ppfProducts.length > 0 && (
                  <SelectGroup>
                    <SelectLabel>PPF</SelectLabel>
                    {ppfProducts.map(p => (
                      <SelectItem key={p.id} value={p.id.toString()}>
                        {formatProductLabel(p)}
                      </SelectItem>
                    ))}
                  </SelectGroup>
                )}
                {!insulfilmProducts.length && !ppfProducts.length && (
                  <div className="px-2 py-4 text-center text-sm text-muted-foreground">
                    Nenhum tipo de produto cadastrado.
                    <br />
                    Cadastre primeiro na aba "Tipos de Materiais".
                  </div>
                )}
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-2">
            <Label>Unidade *</Label>
            <Select value={unit} onValueChange={setUnit}>
              <SelectTrigger>
                <SelectValue placeholder="Selecione..." />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="Metros">Metros</SelectItem>
                <SelectItem value="Unidades">Unidades</SelectItem>
                <SelectItem value="Litros">Litros</SelectItem>
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-2">
            <Label>Estado da Bobina</Label>
            <Select value={isOpenRoll ? "Aberta" : "Nova"} onValueChange={(v) => {
              const open = v === "Aberta";
              setIsOpenRoll(open);
              if (open) {
                setCurrentStock("");
                setMinStock("");
              }
            }}>
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="Nova">Nova</SelectItem>
                <SelectItem value="Aberta">Aberta</SelectItem>
              </SelectContent>
            </Select>
            {isOpenRoll && (
              <p className="text-[11px] text-muted-foreground">
                Bobina aberta não possui estoque inicial nem mínimo. O consumo será acumulado até o encerramento.
              </p>
            )}
          </div>

          {!isOpenRoll && (
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Estoque Inicial</Label>
                <Input
                  type="number"
                  placeholder="0"
                  value={currentStock}
                  onChange={(e) => setCurrentStock(e.target.value)}
                />
              </div>

              <div className="space-y-2">
                <Label>Estoque Mínimo</Label>
                <Input
                  type="number"
                  placeholder="0"
                  value={minStock}
                  onChange={(e) => setMinStock(e.target.value)}
                />
              </div>
            </div>
          )}

          {unit === "Metros" && (
            <div className="space-y-2">
              <Label className="flex items-center gap-1">
                Largura da Bobina (m)
                {existingMaterial ? (
                  <span className="text-[10px] text-muted-foreground font-normal">(Opcional - Já cadastrado)</span>
                ) : (
                  <span className="text-[10px] text-red-500 font-semibold">* Obrigatório</span>
                )}
              </Label>
              <Input
                type="number"
                step="0.01"
                placeholder="Ex: 1.52, 0.60, 1.00"
                value={width}
                onChange={(e) => setWidth(e.target.value)}
              />
              <p className="text-[11px] text-muted-foreground">
                {existingMaterial
                  ? "Bobina já existente. Deixe como está ou altere se for necessário."
                  : "Por ser o primeiro rolo deste tipo, informe a largura física real."}
              </p>
            </div>
          )}

          <div className="flex gap-2 pt-4">
            <Button variant="outline" className="flex-1" onClick={() => onOpenChange(false)} disabled={loading}>
              Cancelar
            </Button>
            <Button className="flex-1" onClick={handleSubmit} disabled={loading}>
              {loading ? "Salvando..." : "Cadastrar"}
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

// @ts-nocheck
import { useState } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { Pencil, Plus, Tag, Trash2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Switch } from "@/components/ui/switch";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Textarea } from "@/components/ui/textarea";
import { ProductCategory, ProductType } from "@/lib/database.types";
import { supabase } from "@/integrations/supabase/client";
import { cn } from "@/lib/utils";
import { toast } from "sonner";

interface ProductTypesTabProps {
  companyId: number | null;
}

export function ProductTypesTab({ companyId }: ProductTypesTabProps) {
  const queryClient = useQueryClient();
  const [activeCategory, setActiveCategory] =
    useState<ProductCategory>("INSULFILM");
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState<ProductType | null>(null);

  const [formData, setFormData] = useState({
    category: "INSULFILM" as ProductCategory,
    brand: "",
    name: "",
    batch: "",
    light_transmission: "",
    description: "",
    cost_per_meter: "",
    ppf_material_type: "",
  });

  const { data: productTypes, isLoading } = useQuery({
    queryKey: ["product-types", activeCategory, companyId],
    queryFn: async () => {
      if (!companyId) return [];

      const { data, error } = await supabase
        .from("product_types")
        .select("*")
        .eq("company_id", companyId)
        .eq("category", activeCategory)
        .order("brand")
        .order("name");

      if (error) throw error;
      return data as ProductType[];
    },
    enabled: !!companyId,
  });

  const invalidateStockQueries = () => {
    queryClient.invalidateQueries({ queryKey: ["product-types"] });
    queryClient.invalidateQueries({ queryKey: ["materials"] });
    queryClient.invalidateQueries({ queryKey: ["history-materials"] });
    queryClient.invalidateQueries({ queryKey: ["history-movements"] });
    queryClient.invalidateQueries({ queryKey: ["history-analytics-consumption"] });
  };

  const createMutation = useMutation({
    mutationFn: async (data: typeof formData) => {
      const { data: result, error } = await supabase
        .from("product_types")
        .insert({
          category: data.category,
          brand: data.brand,
          name: data.name,
          model: data.batch,
          light_transmission: data.light_transmission,
          description: data.description,
          cost_per_meter: parseFloat(data.cost_per_meter as string) || 0,
          ppf_material_type:
            data.category === "PPF" && data.ppf_material_type
              ? data.ppf_material_type
              : null,
          unit_price: 0,
          company_id: companyId,
          is_active: true,
        })
        .select()
        .single();

      if (error) throw error;
      return result;
    },
    onSuccess: () => {
      toast.success("Tipo de produto criado com sucesso!");
      invalidateStockQueries();
      handleCloseModal();
    },
    onError: (error: Error) => {
      toast.error("Erro ao criar produto: " + error.message);
    },
  });

  const updateMutation = useMutation({
    mutationFn: async ({ id, data }: { id: number; data: typeof formData }) => {
      const { data: result, error } = await supabase
        .from("product_types")
        .update({
          category: data.category,
          brand: data.brand,
          name: data.name,
          model: data.batch,
          light_transmission: data.light_transmission,
          description: data.description,
          cost_per_meter: parseFloat(data.cost_per_meter as string) || 0,
          ppf_material_type:
            data.category === "PPF" && data.ppf_material_type
              ? data.ppf_material_type
              : null,
        })
        .eq("id", id)
        .eq("company_id", companyId)
        .select()
        .single();

      if (error) throw error;
      return result;
    },
    onSuccess: () => {
      toast.success("Tipo de produto atualizado!");
      invalidateStockQueries();
      handleCloseModal();
    },
    onError: (error: Error) => {
      toast.error("Erro ao atualizar produto: " + error.message);
    },
  });

  const toggleMutation = useMutation({
    mutationFn: async ({
      id,
      currentStatus,
    }: {
      id: number;
      currentStatus: boolean;
    }) => {
      const { error } = await supabase
        .from("product_types")
        .update({ is_active: !currentStatus })
        .eq("id", id)
        .eq("company_id", companyId);

      if (error) throw error;
      return { id, newStatus: !currentStatus };
    },
    onSuccess: (data) => {
      toast.success(data.newStatus ? "Produto ativado!" : "Produto desativado!");
      invalidateStockQueries();
    },
    onError: (error: Error) => {
      toast.error("Erro ao alterar status: " + error.message);
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: number) => {
      const { count } = await supabase
        .from("service_items_detailed")
        .select("*", { count: "exact", head: true })
        .eq("product_type_id", id);

      if (count && count > 0) {
        const { error } = await supabase
          .from("product_types")
          .update({ is_active: false })
          .eq("id", id)
          .eq("company_id", companyId);

        if (error) throw error;

        await supabase
          .from("materials")
          .update({ is_active: false })
          .eq("product_type_id", id);

        return "soft";
      }

      await supabase.from("materials").delete().eq("product_type_id", id);

      const { error } = await supabase
        .from("product_types")
        .delete()
        .eq("id", id)
        .eq("company_id", companyId);

      if (error) throw error;
      return "hard";
    },
    onSuccess: (type) => {
      if (type === "soft") {
        toast.success("Produto desativado (possui servicos vinculados)");
      } else {
        toast.success("Tipo de produto excluido com sucesso!");
      }
      invalidateStockQueries();
    },
    onError: (error: Error) => {
      toast.error("Erro ao excluir produto: " + error.message);
    },
  });

  const handleDelete = (product: ProductType) => {
    if (
      !confirm(
        `Tem certeza que deseja excluir "${product.brand} ${product.name}"?`
      )
    ) {
      return;
    }

    deleteMutation.mutate(product.id);
  };

  const handleOpenModal = (product?: ProductType) => {
    if (product) {
      setEditingProduct(product);
      setFormData({
        category: product.category,
        brand: product.brand,
        name: product.name,
        batch: product.model || "",
        light_transmission: product.light_transmission || "",
        description: product.description || "",
        cost_per_meter: product.cost_per_meter ? product.cost_per_meter.toString() : "",
        ppf_material_type: product.ppf_material_type || "",
      });
    } else {
      setEditingProduct(null);
      setFormData({
        category: activeCategory,
        brand: "",
        name: "",
        batch: "",
        light_transmission: "",
        description: "",
        cost_per_meter: "",
        ppf_material_type: "",
      });
    }

    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingProduct(null);
    setFormData({
      category: activeCategory,
      brand: "",
      name: "",
      batch: "",
      light_transmission: "",
      description: "",
      cost_per_meter: 0,
      ppf_material_type: "",
    });
  };

  const handleSubmit = () => {
    if (!formData.name.trim()) {
      toast.error("Nome e obrigatorio");
      return;
    }

    if (editingProduct) {
      updateMutation.mutate({ id: editingProduct.id, data: formData });
      return;
    }

    createMutation.mutate(formData);
  };

  const formatCurrency = (value: number) =>
    new Intl.NumberFormat("pt-BR", {
      style: "currency",
      currency: "BRL",
    }).format(value);

  if (isLoading) {
    return (
      <div className="space-y-4">
        <Skeleton className="h-10 w-full" />
        <Skeleton className="h-64 w-full" />
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <Tabs
          value={activeCategory}
          onValueChange={(value) => setActiveCategory(value as ProductCategory)}
        >
          <TabsList>
            <TabsTrigger value="INSULFILM">INSULFILM</TabsTrigger>
            <TabsTrigger value="PPF">PPF</TabsTrigger>
          </TabsList>
        </Tabs>

        <Button onClick={() => handleOpenModal()}>
          <Plus className="mr-2 h-4 w-4" /> Novo Tipo de Material
        </Button>
      </div>

      <Card className="bg-card/50 border-border/50">
        <CardContent className="p-0">
          {productTypes?.length === 0 ? (
            <div className="p-12 text-center">
              <Tag className="mx-auto mb-4 h-12 w-12 text-muted-foreground" />
              <h3 className="mb-2 text-lg font-medium">
                Nenhum tipo de material cadastrado
              </h3>
              <p className="mb-4 text-muted-foreground">
                Cadastre tipos de materiais para {activeCategory}
              </p>
              <Button onClick={() => handleOpenModal()}>
                <Plus className="mr-2 h-4 w-4" /> Cadastrar Primeiro Material
              </Button>
            </div>
          ) : (
            <>
              {/* 🖥️ Visualização Desktop: Tabela Completa */}
              <div className="hidden md:block w-full overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Marca</TableHead>
                      <TableHead>Nome/Lote</TableHead>
                      {activeCategory === "INSULFILM" && (
                        <TableHead>Transmissao</TableHead>
                      )}
                      {activeCategory === "PPF" && (
                        <TableHead>Tipo Material</TableHead>
                      )}
                      <TableHead className="text-right">Custo/Metro</TableHead>
                      <TableHead className="text-center">Status</TableHead>
                      <TableHead className="w-[100px]">Acoes</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {productTypes.map((product) => (
                      <TableRow
                        key={product.id}
                        className={!product.is_active ? "opacity-50" : ""}
                      >
                        <TableCell className="font-medium">{product.brand}</TableCell>
                        <TableCell>
                          <div>
                            <span>{product.name}</span>
                            {product.model && (
                              <span className="ml-1 text-muted-foreground">
                                - Lote {product.model}
                              </span>
                            )}
                          </div>
                        </TableCell>
                        {activeCategory === "INSULFILM" && (
                          <TableCell>{product.light_transmission || "-"}</TableCell>
                        )}
                        {activeCategory === "PPF" && (
                          <TableCell>
                            {product.ppf_material_type ? (
                              <Badge variant="outline">
                                {product.ppf_material_type}
                              </Badge>
                            ) : (
                              "-"
                            )}
                          </TableCell>
                        )}
                        <TableCell className="text-right">
                          {formatCurrency(product.cost_per_meter)}
                        </TableCell>
                        <TableCell className="text-center">
                          <Badge
                            variant={product.is_active ? "default" : "destructive"}
                            className={product.is_active ? "bg-green-500" : ""}
                          >
                            {product.is_active ? "Ativo" : "Inativo"}
                          </Badge>
                        </TableCell>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            <Button
                              variant="ghost"
                              size="icon"
                              onClick={() => handleOpenModal(product)}
                            >
                              <Pencil className="h-4 w-4" />
                            </Button>
                            <Button
                              variant="ghost"
                              size="icon"
                              onClick={() => handleDelete(product)}
                              className="text-muted-foreground hover:text-destructive"
                              title="Excluir"
                            >
                              <Trash2 className="h-4 w-4" />
                            </Button>
                            <Switch
                              checked={product.is_active}
                              onCheckedChange={() =>
                                toggleMutation.mutate({
                                  id: product.id,
                                  currentStatus: product.is_active,
                                })
                              }
                            />
                          </div>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>

              {/* 📱 Visualização Mobile: Cards Empilhados */}
              <div className="flex md:hidden flex-col gap-4">
                {productTypes.map((product) => (
                  <div key={product.id} className={cn("p-4 text-sm space-y-3", !product.is_active && "opacity-50")}>
                    {/* 1. Título e Status */}
                    <div className="flex flex-wrap items-start justify-between gap-2">
                      <div>
                        <span className="font-bold text-base leading-none block">{product.name}</span>
                        {(product.brand || product.model) && (
                          <span className="text-xs text-muted-foreground mt-1 block">
                            {product.brand} {product.model ? `- Lote ${product.model}` : ''}
                          </span>
                        )}
                      </div>
                      <Badge
                        variant={product.is_active ? "default" : "destructive"}
                        className={cn("text-[10px] py-0 px-1.5 h-5", product.is_active ? "bg-green-500" : "")}
                      >
                        {product.is_active ? "Ativo" : "Inativo"}
                      </Badge>
                    </div>

                    {/* 2. Informações Específicas */}
                    {(activeCategory === "INSULFILM" && product.light_transmission) ||
                      (activeCategory === "PPF" && product.ppf_material_type) ? (
                      <div className="flex gap-2">
                        {activeCategory === "INSULFILM" && product.light_transmission && (
                          <Badge variant="outline" className="text-[10px] font-normal border-amber-500/20 text-amber-600 bg-amber-500/5">
                            Transmissão: {product.light_transmission}
                          </Badge>
                        )}
                        {activeCategory === "PPF" && product.ppf_material_type && (
                          <Badge variant="outline" className="text-[10px] font-normal">
                            Tipo: {product.ppf_material_type}
                          </Badge>
                        )}
                      </div>
                    ) : null}

                    {/* 3. Rodapé: Custo e Ações */}
                    <div className="flex items-center justify-between pt-2 border-t mt-3">
                      <div>
                        <span className="text-[10px] text-muted-foreground block">Custo/Metro</span>
                        <span className="font-semibold text-emerald-600 dark:text-emerald-400">{formatCurrency(product.cost_per_meter)}</span>
                      </div>
                      <div className="flex items-center gap-1.5">
                        <Button
                          variant="ghost"
                          size="icon"
                          className="h-8 w-8"
                          onClick={() => handleOpenModal(product)}
                        >
                          <Pencil className="h-4 w-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="icon"
                          className="h-8 w-8 text-muted-foreground hover:text-destructive"
                          onClick={() => handleDelete(product)}
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                        <Switch
                          className="ml-2 data-[state=checked]:bg-green-500"
                          checked={product.is_active}
                          onCheckedChange={() =>
                            toggleMutation.mutate({
                              id: product.id,
                              currentStatus: product.is_active,
                            })
                          }
                        />
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </>
          )}
        </CardContent>
      </Card>

      <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
        <DialogContent className="max-w-lg w-[calc(100%-2rem)] sm:w-full p-4 sm:p-6 max-h-[85dvh] sm:max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>
              {editingProduct
                ? "Editar Tipo de Material"
                : "Novo Tipo de Material"}
            </DialogTitle>
          </DialogHeader>

          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label>Categoria</Label>
              <Select
                value={formData.category}
                onValueChange={(value) =>
                  setFormData({
                    ...formData,
                    category: value as ProductCategory,
                  })
                }
                disabled={!!editingProduct}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="INSULFILM">INSULFILM</SelectItem>
                  <SelectItem value="PPF">PPF</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Marca</Label>
                <Input
                  placeholder="Ex: 3M, XPEL"
                  value={formData.brand}
                  onChange={(event) =>
                    setFormData({ ...formData, brand: event.target.value })
                  }
                />
              </div>
              <div className="space-y-2">
                <Label>Nome *</Label>
                <Input
                  placeholder="Ex: G70, Ultimate"
                  value={formData.name}
                  onChange={(event) =>
                    setFormData({ ...formData, name: event.target.value })
                  }
                />
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Lote</Label>
                <Input
                  placeholder="Ex: A001, B002, C003"
                  value={formData.batch}
                  onChange={(event) =>
                    setFormData({ ...formData, batch: event.target.value })
                  }
                />
              </div>
              {formData.category === "INSULFILM" && (
                <div className="space-y-2">
                  <Label>Transmissao de Luz</Label>
                  <Input
                    placeholder="Ex: 5%, 20%, 70%"
                    value={formData.light_transmission}
                    onChange={(event) =>
                      setFormData({
                        ...formData,
                        light_transmission: event.target.value,
                      })
                    }
                  />
                </div>
              )}
            </div>

            {formData.category === "PPF" && (
              <div className="space-y-2">
                <Label>Tipo de Material PPF</Label>
                <div className="grid grid-cols-3 gap-2">
                  {(["TPU", "TPH", "PVC"] as const).map((type) => (
                    <button
                      key={type}
                      type="button"
                      onClick={() =>
                        setFormData({ ...formData, ppf_material_type: type })
                      }
                      className={cn(
                        "rounded-lg border px-4 py-2 text-sm font-medium transition-colors",
                        formData.ppf_material_type === type
                          ? "border-primary bg-primary/10 text-primary"
                          : "border-border hover:bg-muted"
                      )}
                    >
                      {type}
                    </button>
                  ))}
                </div>
              </div>
            )}

            <div className="space-y-2">
              <Label>Custo por Metro (R$)</Label>
              <Input
                type="number"
                step="0.01"
                min="0"
                value={formData.cost_per_meter}
                onChange={(event) =>
                  setFormData({
                    ...formData,
                    cost_per_meter: event.target.value,
                  })
                }
              />
            </div>

            <div className="space-y-2">
              <Label>Descricao</Label>
              <Textarea
                placeholder="Descricao adicional do produto..."
                value={formData.description}
                onChange={(event) =>
                  setFormData({ ...formData, description: event.target.value })
                }
              />
            </div>
          </div>

          <DialogFooter className="flex flex-col sm:flex-row gap-2 mt-4">
            <Button variant="outline" className="w-full sm:w-auto" onClick={handleCloseModal}>
              Cancelar
            </Button>
            <Button
              className="w-full sm:w-auto"
              onClick={handleSubmit}
              disabled={createMutation.isPending || updateMutation.isPending}
            >
              {editingProduct ? "Salvar Alteracoes" : "Criar Produto"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

// @ts-nocheck
import { useState, useEffect } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Plus, Pencil, Trash2, GripVertical, Wrench, Lightbulb } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "@/components/ui/alert-dialog";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { ProductCategory } from "@/lib/database.types";
import { Skeleton } from "@/components/ui/skeleton";
import { Badge } from "@/components/ui/badge";
import { SIMPLE_REGION_CODES } from "@/constants/insulfilm-regions";
import {
  DndContext,
  closestCenter,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  DragEndEvent,
} from "@dnd-kit/core";
import {
  SortableContext,
  sortableKeyboardCoordinates,
  verticalListSortingStrategy,
  useSortable,
  arrayMove,
} from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";

interface VehicleRegionsTabProps {
  companyId: number | null;
}

interface VehicleRegion {
  id: number;
  category: ProductCategory;
  name: string;
  description: string | null;
  sort_order: number;
  is_active: boolean;
  created_at: string;
  company_id: number;
  fixed_price: number | null;
  product_type_id: number | null;
  region_code: string | null;
}

interface SortableRegionCardProps {
  region: VehicleRegion;
  onEdit: (region: VehicleRegion) => void;
  onDelete: (region: VehicleRegion) => void;
}

function SortableRegionCard({ region, onEdit, onDelete }: SortableRegionCardProps) {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: region.id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.5 : 1,
  };

  return (
    <div
      ref={setNodeRef}
      style={style}
      className="flex flex-col sm:flex-row sm:items-center gap-3 p-3 sm:p-4 bg-card border border-border rounded-lg hover:border-primary/50 transition-colors"
    >
      {/* Linha superior no Mobile / Lado esquerdo no Desktop */}
      <div className="flex items-center gap-3 flex-1 min-w-0">
        <button
          {...attributes}
          {...listeners}
          className="cursor-grab hover:text-primary touch-none shrink-0"
        >
          <GripVertical className="h-5 w-5 text-muted-foreground" />
        </button>

        <div className="flex-1 min-w-0">
          <div className="flex flex-wrap items-center gap-1.5">
            <p className="font-medium text-foreground truncate">{region.name}</p>
            {region.region_code && (
              <Badge variant="outline" className="text-[10px] px-1.5 py-0">
                {SIMPLE_REGION_CODES.find(r => r.code === region.region_code)?.label || region.region_code}
              </Badge>
            )}
          </div>
          {region.description && (
            <p className="text-xs text-muted-foreground truncate mt-0.5">{region.description}</p>
          )}
        </div>
      </div>

      {/* Linha inferior no Mobile / Lado direito no Desktop */}
      <div className="flex items-center justify-between sm:justify-end gap-4 pt-2 sm:pt-0 border-t border-border/40 sm:border-0">
        {/* Preço */}
        <div className="text-left sm:text-right sm:min-w-[100px]">
          <p className="text-[10px] sm:text-xs text-muted-foreground">Preço</p>
          <p className="font-semibold sm:font-medium text-success text-sm sm:text-base">
            {region.fixed_price && region.fixed_price > 0
              ? `R$ ${region.fixed_price.toFixed(2)}`
              : "-"}
          </p>
        </div>

        {/* Ações */}
        <div className="flex gap-1">
          <Button
            variant="ghost"
            size="icon"
            onClick={() => onEdit(region)}
            className="h-8 w-8 sm:h-9 sm:w-9"
          >
            <Pencil className="h-4 w-4" />
          </Button>
          <Button
            variant="ghost"
            size="icon"
            className="text-destructive hover:text-destructive h-8 w-8 sm:h-9 sm:w-9"
            onClick={() => onDelete(region)}
          >
            <Trash2 className="h-4 w-4" />
          </Button>
        </div>
      </div>
    </div>
  );
}

export function VehicleRegionsTab({ companyId }: VehicleRegionsTabProps) {
  const queryClient = useQueryClient();
  const [activeCategory, setActiveCategory] = useState<ProductCategory>("INSULFILM");
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isDeleteAlertOpen, setIsDeleteAlertOpen] = useState(false);
  const [editingRegion, setEditingRegion] = useState<VehicleRegion | null>(null);
  const [deletingRegion, setDeletingRegion] = useState<VehicleRegion | null>(null);
  const [localRegions, setLocalRegions] = useState<VehicleRegion[]>([]);

  const [formData, setFormData] = useState({
    category: "INSULFILM" as ProductCategory,
    name: "",
    description: "",
    fixed_price: "",
    region_code: "" as string,
  });

  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  );

  const { data: regions, isLoading } = useQuery({
    queryKey: ["vehicle-regions", activeCategory, companyId],
    queryFn: async () => {
      if (!companyId) return [];
      const { data, error } = await supabase
        .from("vehicle_regions")
        .select("*")
        .eq("company_id", companyId)
        .eq("category", activeCategory)
        .eq("is_active", true)
        .order("sort_order");

      if (error) throw error;
      return data as VehicleRegion[];
    },
    enabled: !!companyId,
  });

  useEffect(() => {
    if (regions) {
      setLocalRegions(regions);
    }
  }, [regions]);

  const createMutation = useMutation({
    mutationFn: async (data: typeof formData) => {
      // Buscar próximo sort_order
      const { data: maxOrderData } = await supabase
        .from("vehicle_regions")
        .select("sort_order")
        .eq("company_id", companyId)
        .eq("category", data.category)
        .order("sort_order", { ascending: false })
        .limit(1)
        .maybeSingle();

      const nextOrder = (maxOrderData?.sort_order || 0) + 1;

      const { data: result, error } = await supabase
        .from("vehicle_regions")
        .insert({
          name: data.name,
          description: data.description || null,
          category: data.category,
          fixed_price: parseFloat(data.fixed_price as string) || null,
          region_code: data.region_code || null,
          company_id: companyId,
          sort_order: nextOrder,
          is_active: true,
        })
        .select()
        .single();

      if (error) throw error;
      return result;
    },
    onSuccess: () => {
      toast.success("Serviço criado com sucesso!");
      queryClient.invalidateQueries({ queryKey: ["vehicle-regions"] });
      handleCloseModal();
    },
    onError: (error: Error) => {
      toast.error("Erro ao criar serviço: " + error.message);
    },
  });

  const updateMutation = useMutation({
    mutationFn: async ({ id, data }: { id: number; data: Partial<typeof formData> }) => {
      const { data: result, error } = await supabase
        .from("vehicle_regions")
        .update({
          name: data.name,
          description: data.description || null,
          fixed_price: parseFloat(data.fixed_price as string) || null,
          region_code: data.region_code || null,
        })
        .eq("id", id)
        .eq("company_id", companyId)
        .select()
        .single();

      if (error) throw error;
      return result;
    },
    onSuccess: () => {
      toast.success("Serviço atualizado!");
      queryClient.invalidateQueries({ queryKey: ["vehicle-regions"] });
      handleCloseModal();
    },
    onError: (error: Error) => {
      toast.error("Erro ao atualizar serviço: " + error.message);
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: number) => {
      // Verifica se existem itens de serviço vinculados
      const { count } = await supabase
        .from("service_items_detailed")
        .select("*", { count: "exact", head: true })
        .eq("region_id", id);

      if (count && count > 0) {
        // Soft delete - desativa o serviço
        const { error } = await supabase
          .from("vehicle_regions")
          .update({ is_active: false })
          .eq("id", id)
          .eq("company_id", companyId);

        if (error) throw error;
        return "soft";
      } else {
        // Hard delete
        const { error } = await supabase
          .from("vehicle_regions")
          .delete()
          .eq("id", id)
          .eq("company_id", companyId);

        if (error) throw error;
        return "hard";
      }
    },
    onSuccess: (type) => {
      if (type === "soft") {
        toast.success("Serviço desativado (possui vendas vinculadas)");
      } else {
        toast.success("Serviço excluído!");
      }
      queryClient.invalidateQueries({ queryKey: ["vehicle-regions"] });
      setIsDeleteAlertOpen(false);
      setDeletingRegion(null);
    },
    onError: (error: Error) => {
      toast.error("Erro ao excluir serviço: " + error.message);
    },
  });

  const updateOrderMutation = useMutation({
    mutationFn: async (reorderedRegions: VehicleRegion[]) => {
      const updates = reorderedRegions.map((region, index) => ({
        id: region.id,
        sort_order: index,
        company_id: region.company_id,
        category: region.category,
        name: region.name,
        description: region.description,
        is_active: region.is_active,
        fixed_price: region.fixed_price,
      }));

      const { error } = await supabase.from("vehicle_regions").upsert(updates);

      if (error) throw error;
    },
    onSuccess: () => {
      toast.success("Ordem atualizada!");
      queryClient.invalidateQueries({ queryKey: ["vehicle-regions"] });
    },
    onError: (error: Error) => {
      toast.error("Erro ao atualizar ordem: " + error.message);
    },
  });

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;

    if (over && active.id !== over.id) {
      setLocalRegions((items) => {
        const oldIndex = items.findIndex((item) => item.id === active.id);
        const newIndex = items.findIndex((item) => item.id === over.id);

        const reordered = arrayMove(items, oldIndex, newIndex);
        updateOrderMutation.mutate(reordered);
        return reordered;
      });
    }
  };

  const handleOpenModal = (region?: VehicleRegion) => {
    if (region) {
      setEditingRegion(region);
      setFormData({
        category: region.category,
        name: region.name,
        description: region.description || "",
        fixed_price: region.fixed_price ? region.fixed_price.toString() : "",
        region_code: region.region_code || "",
      });
    } else {
      setEditingRegion(null);
      setFormData({
        category: activeCategory,
        name: "",
        description: "",
        fixed_price: "",
        region_code: "",
      });
    }
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingRegion(null);
    setFormData({
      category: activeCategory,
      name: "",
      description: "",
      fixed_price: "",
      region_code: "",
    });
  };

  const handleSubmit = () => {
    if (!formData.name.trim()) {
      toast.error("Nome do serviço é obrigatório");
      return;
    }

    if (editingRegion) {
      updateMutation.mutate({
        id: editingRegion.id,
        data: { name: formData.name, description: formData.description, fixed_price: parseFloat(formData.fixed_price as string) || 0, region_code: formData.region_code },
      });
    } else {
      createMutation.mutate(formData);
    }
  };

  const handleDeleteClick = (region: VehicleRegion) => {
    setDeletingRegion(region);
    setIsDeleteAlertOpen(true);
  };

  if (isLoading) {
    return (
      <div className="space-y-4">
        <Skeleton className="h-10 w-full" />
        <div className="space-y-2">
          {[1, 2, 3].map((i) => (
            <Skeleton key={i} className="h-16 w-full" />
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Sub-tabs e botão */}
      <div className="flex items-center justify-between">
        <Tabs value={activeCategory} onValueChange={(v) => setActiveCategory(v as ProductCategory)}>
          <TabsList>
            <TabsTrigger value="INSULFILM">INSULFILM</TabsTrigger>
            <TabsTrigger value="PPF">PPF</TabsTrigger>
          </TabsList>
        </Tabs>

        <Button onClick={() => handleOpenModal()}>
          <Plus className="h-4 w-4 mr-2" /> Novo Serviço
        </Button>
      </div>

      {/* Lista de serviços */}
      {localRegions.length === 0 ? (
        <Card className="bg-card/50 border-border/50">
          <CardContent className="p-12 text-center">
            <Wrench className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
            <h3 className="text-lg font-medium mb-2">Nenhum serviço cadastrado</h3>
            <p className="text-muted-foreground mb-4">
              Cadastre os serviços para {activeCategory}
            </p>
            <Button onClick={() => handleOpenModal()}>
              <Plus className="h-4 w-4 mr-2" /> Cadastrar Primeiro Serviço
            </Button>
          </CardContent>
        </Card>
      ) : (
        <DndContext
          sensors={sensors}
          collisionDetection={closestCenter}
          onDragEnd={handleDragEnd}
        >
          <SortableContext
            items={localRegions.map((r) => r.id)}
            strategy={verticalListSortingStrategy}
          >
            <div className="space-y-2">
              {localRegions.map((region) => (
                <SortableRegionCard
                  key={region.id}
                  region={region}
                  onEdit={handleOpenModal}
                  onDelete={handleDeleteClick}
                />
              ))}
            </div>
          </SortableContext>
        </DndContext>
      )}

      {/* Modal de criar/editar */}
      <Dialog open={isModalOpen} onOpenChange={setIsModalOpen}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>
              {editingRegion ? "Editar Serviço" : "Novo Serviço"}
            </DialogTitle>
          </DialogHeader>

          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label>Categoria</Label>
              <Select
                value={formData.category}
                onValueChange={(v) => setFormData({ ...formData, category: v as ProductCategory })}
                disabled={!!editingRegion}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="INSULFILM">INSULFILM</SelectItem>
                  <SelectItem value="PPF">PPF</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label>Nome do Serviço *</Label>
              <Input
                placeholder="Ex: Para-brisa, Capô, Vidros Laterais"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
              />
              <div className="flex items-start gap-2 mt-2 p-2.5 bg-amber-500/10 border border-amber-500/20 rounded-md text-amber-600 dark:text-amber-500 text-xs shadow-sm animate-pulse">
                <Lightbulb className="h-4 w-4 shrink-0 mt-0.5" />
                <p className="leading-relaxed">
                  <strong className="font-semibold">Dica:</strong> Nomear serviço com o nome do material e o local do veículo.
                  <br />
                  Exemplo: <strong>Ultra-black Parabrisa</strong> ou <strong>Ultra-Black LAT(lateral)/TRAS(traseiro)</strong>.
                </p>
              </div>
            </div>

            <div className="space-y-2">
              <Label>Descrição</Label>
              <Textarea
                placeholder="Descrição do serviço..."
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
              />
            </div>

            <div className="space-y-2">
              <Label>Preço Pré-determinado (R$)</Label>
              <Input
                type="number"
                step="0.01"
                placeholder="0.00"
                value={formData.fixed_price}
                onChange={(e) => setFormData({ ...formData, fixed_price: e.target.value })}
              />
              <p className="text-xs text-muted-foreground">
                Este preço aparecerá automaticamente ao preencher vagas
              </p>
            </div>

            {formData.category === "INSULFILM" && (
              <div className="space-y-2">
                <Label>Região Física (Regra de Consumo)</Label>
                <Select
                  value={formData.region_code}
                  onValueChange={(v) => setFormData({ ...formData, region_code: v === "none" ? "" : v })}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Selecione a região" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">Nenhuma</SelectItem>
                    {SIMPLE_REGION_CODES.map((rc) => (
                      <SelectItem key={rc.code} value={rc.code}>
                        {rc.label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <p className="text-xs text-muted-foreground">
                  Associa este serviço a uma região para regras de consumo automáticas
                </p>
              </div>
            )}
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={handleCloseModal}>
              Cancelar
            </Button>
            <Button
              onClick={handleSubmit}
              disabled={createMutation.isPending || updateMutation.isPending}
            >
              {editingRegion ? "Salvar Alterações" : "Criar Serviço"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Alert de confirmação de exclusão */}
      <AlertDialog open={isDeleteAlertOpen} onOpenChange={setIsDeleteAlertOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Tem certeza?</AlertDialogTitle>
            <AlertDialogDescription>
              Esta ação não pode ser desfeita. Isso excluirá permanentemente o serviço
              "{deletingRegion?.name}".
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              onClick={() => deletingRegion && deleteMutation.mutate(deletingRegion.id)}
              disabled={deleteMutation.isPending}
            >
              Excluir
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

