       if (error) throw error;
       setServices(data || []);
     } catch (error) {
       console.error('Error fetching warranty services:', error);
       toast.error('Erro ao carregar serviços');
     } finally {
       setLoading(false);
     }
   };
 
   const handleDelete = async (id: number) => {
