import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { Edit, Trash2, ChevronDown, ChevronUp } from "lucide-react";
import { NewWarrantyTemplateModal } from "./NewWarrantyTemplateModal";

interface WarrantyTemplate {
  id: number;
  name: string;
  validity_months: number;
  terms: string | null;
  coverage: string | null;
  restrictions?: string | null;
  care_instructions?: string | null;
}

interface WarrantyTemplatesListModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onTemplatesChange?: () => void;
}

export function WarrantyTemplatesListModal({ open, onOpenChange, onTemplatesChange }: WarrantyTemplatesListModalProps) {
  const { user } = useAuth();
  const [templates, setTemplates] = useState<WarrantyTemplate[]>([]);
  const [loading, setLoading] = useState(true);
  const [expandedId, setExpandedId] = useState<number | null>(null);
  
  // For editing
  const [showEditModal, setShowEditModal] = useState(false);
  const [templateToEdit, setTemplateToEdit] = useState<WarrantyTemplate | null>(null);

  useEffect(() => {
    if (open && user?.id) {
      fetchTemplates();
    }
  }, [open, user?.id]);

  const fetchTemplates = async () => {
    setLoading(true);
    try {
      const { data: profile } = await supabase
        .from('profiles')
        .select('company_id')
        .eq('user_id', user?.id)
        .single();

      if (!profile?.company_id) return;

      const { data } = await supabase
        .from('warranty_templates')
        .select('*')
        .eq('company_id', profile.company_id)
        .order('name');

      setTemplates(data || []);
    } catch (error) {
      console.error('Error fetching warranty templates:', error);
      toast.error("Erro ao buscar modelos de garantia");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: number) => {
    if (!window.confirm("Tem certeza que deseja excluir este modelo? (Garantias já emitidas com ele não serão afetadas)")) return;

    try {
      const { error } = await supabase
        .from('warranty_templates')
        .delete()
        .eq('id', id);

      if (error) throw error;
      
      toast.success("Modelo de garantia excluído com sucesso");
      fetchTemplates();
      onTemplatesChange?.();
    } catch (error) {
      console.error('Error deleting warranty template:', error);
      toast.error("Erro ao excluir modelo de garantia");
    }
  };

  const handleEdit = (template: WarrantyTemplate) => {
    setTemplateToEdit(template);
    setShowEditModal(true);
  };

  const toggleExpand = (id: number) => {
    setExpandedId(expandedId === id ? null : id);
  };

  return (
    <>
      <Dialog open={open} onOpenChange={onOpenChange}>
        <DialogContent className="sm:max-w-2xl max-h-[85vh] p-0 flex flex-col">
          <DialogHeader className="px-6 pt-6 pb-2">
            <DialogTitle>Gerenciar Modelos de Garantia</DialogTitle>
          </DialogHeader>

          <ScrollArea className="flex-1 px-6 pb-6">
            <div className="space-y-4 pt-2">
              {loading ? (
                <div className="text-center py-8 text-muted-foreground">
                  Carregando modelos...
                </div>
              ) : templates.length === 0 ? (
                <div className="text-center py-12 text-muted-foreground">
                  Nenhum modelo de garantia criado
                </div>
              ) : (
                templates.map(template => (
                  <div key={template.id} className="border rounded-lg bg-card overflow-hidden">
                    <div 
                      className="p-4 flex items-center justify-between cursor-pointer hover:bg-muted/50 transition-colors"
                      onClick={() => toggleExpand(template.id)}
                    >
                      <div>
                        <h3 className="font-semibold">{template.name}</h3>
                        <p className="text-sm text-muted-foreground">Validade: {template.validity_months} meses</p>
                      </div>
                      <div className="flex items-center gap-2">
                        <Button 
                          variant="ghost" 
                          size="icon" 
                          className="h-8 w-8 text-blue-500 hover:text-blue-600 hover:bg-blue-100"
                          onClick={(e) => {
                            e.stopPropagation();
                            handleEdit(template);
                          }}
                        >
                          <Edit className="h-4 w-4" />
                        </Button>
                        <Button 
                          variant="ghost" 
                          size="icon" 
                          className="h-8 w-8 text-red-500 hover:text-red-600 hover:bg-red-100"
                          onClick={(e) => {
                            e.stopPropagation();
                            handleDelete(template.id);
                          }}
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                        <div className="w-8 flex justify-center text-muted-foreground">
                          {expandedId === template.id ? <ChevronUp className="h-5 w-5" /> : <ChevronDown className="h-5 w-5" />}
                        </div>
                      </div>
                    </div>
                    
                    {expandedId === template.id && (
                      <div className="p-4 bg-muted/20 border-t space-y-4 text-sm">
                        {template.coverage && (
                          <div>
                            <p className="font-semibold mb-1 text-primary">Cobertura:</p>
                            <p className="text-muted-foreground whitespace-pre-wrap">{template.coverage}</p>
                          </div>
                        )}
                        {template.terms && (
                          <div>
                            <p className="font-semibold mb-1 text-primary">Termos:</p>
                            <p className="text-muted-foreground whitespace-pre-wrap">{template.terms}</p>
                          </div>
                        )}
                        {template.restrictions && (
                          <div>
                            <p className="font-semibold mb-1 text-primary">Restrições:</p>
                            <p className="text-muted-foreground whitespace-pre-wrap">{template.restrictions}</p>
                          </div>
                        )}
                        {template.care_instructions && (
                          <div>
                            <p className="font-semibold mb-1 text-primary">Instruções de Cuidado:</p>
                            <p className="text-muted-foreground whitespace-pre-wrap">{template.care_instructions}</p>
                          </div>
                        )}
                        {!template.coverage && !template.terms && !template.restrictions && !template.care_instructions && (
                          <p className="text-muted-foreground italic">Nenhum detalhe adicional informado.</p>
                        )}
                      </div>
                    )}
                  </div>
                ))
              )}
            </div>
          </ScrollArea>
        </DialogContent>
      </Dialog>
      
      {/* Edit Modal overlays on top of the list modal */}
      <NewWarrantyTemplateModal
        open={showEditModal}
        templateToEdit={templateToEdit}
        onOpenChange={(open) => {
          setShowEditModal(open);
          if (!open) setTemplateToEdit(null);
        }}
        onTemplateCreated={() => {
          fetchTemplates();
          onTemplatesChange?.();
        }}
      />
    </>
  );
}

import { useState, useEffect } from "react";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import {
    Search,
    Users,
    Building,
    Mail,
    Calendar,
    Loader2,
    Crown
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";

interface EmployeeRow {
    user_id: string;
    name: string;
    email: string;
    phone: string | null;
    created_at: string | null;
    company_id: number;
    role: string | null;
    company_name: string;
    owner_id: string | null;
    plan_code: string | null;
    status: string | null;
}

export default function EmployeesManager() {
    const { toast } = useToast();
    const [employees, setEmployees] = useState<EmployeeRow[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState("");

    useEffect(() => {
        fetchEmployees();
    }, []);

    const fetchEmployees = async () => {
        setIsLoading(true);
        try {
            // 1. Fetch profiles with company_id not null
            const { data: profiles, error: pError } = await supabase
                .from("profiles")
                .select("user_id, name, email, phone, created_at, company_id")
                .not("company_id", "is", null)
                .order("created_at", { ascending: false });

            if (pError) throw pError;
            if (!profiles || profiles.length === 0) {
                setEmployees([]);
                return;
            }

            const userIds = profiles.map((p) => p.user_id);
            const companyIds = [...new Set(profiles.map((p) => p.company_id))];

            // 2. Fetch user_roles
            const { data: roles, error: rError } = await supabase
                .from("user_roles")
                .select("user_id, role")
                .in("user_id", userIds);

            if (rError) console.error("Error fetching roles:", rError);

            // 3. Fetch companies
            const { data: companies, error: cError } = await supabase
                .from("companies")
                .select("id, company_name, owner_id")
                .in("id", companyIds);

            if (cError) console.error("Error fetching companies:", cError);

            const ownerIds = companies ? [...new Set(companies.map((c) => c.owner_id))] : [];

            // 4. Fetch subscriptions for those owners
            const { data: subs, error: sError } = await supabase
                .from("subscriptions")
                .select("user_id, plan_code, status")
                .in("user_id", ownerIds);

            if (sError) console.error("Error fetching subscriptions:", sError);

            const enriched: EmployeeRow[] = profiles.map((p) => {
                const role = roles?.find((r) => r.user_id === p.user_id)?.role || "NENHUM";
                const company = companies?.find((c) => c.id === p.company_id);
                const sub = subs?.find((s) => s.user_id === company?.owner_id);

                return {
                    user_id: p.user_id,
                    name: p.name,
                    email: p.email,
                    phone: p.phone,
                    created_at: p.created_at,
                    company_id: p.company_id as number,
                    role,
                    company_name: company?.company_name || "Desconhecida",
                    owner_id: company?.owner_id || null,
                    plan_code: sub?.plan_code || "basic",
                    status: sub?.status || "active",
                };
            });

            // Optionally filter out owners so we only see true "employees"
            // Or keep them but mark them if they show up here. Let's filter out owners.
            const employeesOnly = enriched.filter((e) => e.user_id !== e.owner_id);

            setEmployees(employeesOnly);
        } catch (error) {
            console.error("Error fetching employees:", error);
            toast({
                title: "Erro ao buscar funcionários",
                description: "Não foi possível carregar a lista.",
                variant: "destructive",
            });
        } finally {
            setIsLoading(false);
        }
    };

    const getRoleBadge = (role: string | null) => {
        switch (role) {
            case "ADMIN":
                return <Badge className="bg-purple-500/20 text-purple-400">Admin</Badge>;
            case "FUNCIONARIO":
            case "VENDEDOR":
                return <Badge className="bg-blue-500/20 text-blue-400">Funcionário</Badge>;
            case "PRODUCAO":
                return <Badge className="bg-orange-500/20 text-orange-400">Produção</Badge>;
            default:
                return <Badge variant="secondary">Pendente</Badge>;
        }
    };

    const filteredEmployees = employees.filter((emp) => {
        const term = searchTerm.toLowerCase();
        return (
            (emp.name || "").toLowerCase().includes(term) ||
            (emp.email || "").toLowerCase().includes(term) ||
            (emp.company_name || "").toLowerCase().includes(term)
        );
    });

    if (isLoading) {
        return (
            <div className="flex items-center justify-center py-12">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        );
    }

    return (
        <div className="space-y-4">
            <Card>
                <CardHeader>
                    <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                        <div>
                            <CardTitle className="flex items-center gap-2">
                                <Users className="h-5 w-5" />
                                Controle de Funcionários
                            </CardTitle>
                            <CardDescription>
                                Visão geral de todos os funcionários e respectivas empresas parceiras
                            </CardDescription>
                        </div>
                        <div className="relative w-full sm:w-64">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                            <Input
                                placeholder="Buscar por nome, email ou empresa..."
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="pl-9"
                            />
                        </div>
                    </div>
                </CardHeader>
                <CardContent>
                    <Table>
                        <TableHeader>
                            <TableRow>
                                <TableHead>Funcionário</TableHead>
                                <TableHead>Função</TableHead>
                                <TableHead>Empresa Vinculada</TableHead>
                                <TableHead>Plano da Empresa</TableHead>
                                <TableHead>Data de Entrada</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {filteredEmployees.map((emp) => (
                                <TableRow key={emp.user_id}>
                                    <TableCell>
                                        <div className="flex items-center gap-2">
                                            <Mail className="h-4 w-4 text-muted-foreground" />
                                            <div>
                                                <p className="font-medium">{emp.name || "—"}</p>
                                                <p className="text-xs text-muted-foreground">{emp.email}</p>
                                            </div>
                                        </div>
                                    </TableCell>
                                    <TableCell>{getRoleBadge(emp.role)}</TableCell>
                                    <TableCell>
                                        <div className="flex items-center gap-2">
                                            <Building className="h-4 w-4 text-muted-foreground" />
                                            {emp.company_name}
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <span className="capitalize font-medium flex items-center gap-1.5">
                                            <Crown className="h-4 w-4 text-primary" />
                                            {emp.plan_code}
                                        </span>
                                    </TableCell>
                                    <TableCell>
                                        <div className="flex items-center gap-2 text-sm">
                                            <Calendar className="h-4 w-4 text-muted-foreground" />
                                            {emp.created_at ? format(new Date(emp.created_at), "dd/MM/yyyy", { locale: ptBR }) : "—"}
                                        </div>
                                    </TableCell>
                                </TableRow>
                            ))}
                            {filteredEmployees.length === 0 && (
                                <TableRow>
                                    <TableCell colSpan={5} className="text-center text-muted-foreground py-8">
                                        Nenhum funcionário encontrado.
                                    </TableCell>
                                </TableRow>
                            )}
                        </TableBody>
                    </Table>
                </CardContent>
            </Card>
        </div>
    );
}

// @ts-nocheck
import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from "@/components/ui/card";
import { Loader2, Save } from "lucide-react";
import { useToast } from "@/hooks/use-toast";

interface PlanPrice {
  id: number;
  plan_code: string;
  billing_period: string;
  price: number;
}

export default function PlanPricesTab() {
  const { toast } = useToast();
  const [prices, setPrices] = useState<PlanPrice[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Form states
  const [formData, setFormData] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState<Record<string, boolean>>({});

  useEffect(() => {
    fetchPrices();
  }, []);

  const fetchPrices = async () => {
    try {
      setIsLoading(true);
      const { data, error } = await supabase
        .from('plan_prices')
        .select('*')
        .order('plan_code');

      if (error) throw error;
      
      setPrices(data as PlanPrice[]);
      
      // Initialize form data
      const initialData: Record<string, string> = {};
      data.forEach((p) => {
        initialData[`${p.plan_code}_${p.billing_period}`] = p.price.toString();
      });
      setFormData(initialData);

    } catch (error) {
      console.error('Error fetching plan prices:', error);
      toast({ title: "Erro ao carregar preços", variant: "destructive" });
    } finally {
      setIsLoading(false);
    }
  };

  const handlePriceChange = (plan_code: string, billing_period: string, value: string) => {
    setFormData(prev => ({
      ...prev,
      [`${plan_code}_${billing_period}`]: value
    }));
  };

  const handleSave = async (plan_code: string, billing_period: string) => {
    const key = `${plan_code}_${billing_period}`;
    const newPrice = parseFloat(formData[key]);
    
    if (isNaN(newPrice) || newPrice < 0) {
      toast({ title: "Valor inválido", variant: "destructive" });
      return;
    }

    const reason = window.prompt(`Informe o motivo da alteração para o plano ${plan_code} (${billing_period}):`);
    if (!reason) return; // cancelled or empty

    setIsSubmitting(prev => ({ ...prev, [key]: true }));

    try {
      const { error } = await supabase.rpc('master_update_plan_price', {
        p_plan_code: plan_code,
        p_billing_period: billing_period,
        p_new_price: newPrice,
        p_notes: reason
      });

      if (error) throw error;

      toast({ title: "Preço atualizado com sucesso!" });
      fetchPrices();
    } catch (error: any) {
      console.error('Error updating plan price:', error);
      toast({ title: "Erro ao atualizar preço", description: error.message, variant: "destructive" });
    } finally {
      setIsSubmitting(prev => ({ ...prev, [key]: false }));
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  // Group prices by plan_code for rendering
  const plans = ['basic', 'ultra', 'premium'];
  const periods = ['monthly', 'annual'];

  return (
    <div className="space-y-6">
      <div className="mb-4">
        <p className="text-muted-foreground">
          Gerencie os preços base de cada plano. As alterações afetarão apenas as <strong>novas assinaturas</strong> e solicitações de upgrade futuras.
        </p>
      </div>

      <div className="grid md:grid-cols-3 gap-6">
        {plans.map((plan_code) => {
          const isPremium = plan_code === 'premium';
          return (
            <Card key={plan_code} className={isPremium ? 'opacity-70' : ''}>
              <CardHeader>
                <CardTitle className="capitalize">Plano {plan_code}</CardTitle>
                <CardDescription>
                  {isPremium ? 'Plano personalizado (não editável aqui)' : `Configuração de preços do plano ${plan_code}`}
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-6">
                {periods.map(period => {
                  const key = `${plan_code}_${period}`;
                  // If we don't have it in the DB, skip or show empty. We should have it.
                  if (formData[key] === undefined && !isPremium) return null;

                  return (
                    <div key={period} className="space-y-2">
                      <Label className="capitalize">{period === 'annual' ? 'Anual' : 'Mensal'}</Label>
                      <div className="flex gap-2">
                        <div className="relative flex-1">
                          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground text-sm">R$</span>
                          <Input
                            type="number"
                            step="0.01"
                            min="0"
                            className="pl-9"
                            value={formData[key] || ''}
                            onChange={(e) => handlePriceChange(plan_code, period, e.target.value)}
                            disabled={isPremium || isSubmitting[key]}
                          />
                        </div>
                        <Button 
                          size="icon" 
                          disabled={isPremium || isSubmitting[key] || formData[key] === prices.find(p => p.plan_code === plan_code && p.billing_period === period)?.price.toString()}
                          onClick={() => handleSave(plan_code, period)}
                          title="Salvar preço"
                        >
                          {isSubmitting[key] ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
                        </Button>
                      </div>
                    </div>
                  );
                })}
              </CardContent>
            </Card>
          );
        })}
      </div>
    </div>
  );
}

