            </div>

            <FormField
              control={form.control}
              name="material_id"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Material Perdido *</FormLabel>
                  <Select onValueChange={field.onChange} value={field.value} disabled={isEditing}>
                    <FormControl>
                      <SelectTrigger>
                        <SelectValue placeholder="Selecione (bobina fechada)" />
                      </SelectTrigger>
                    </FormControl>
                    <SelectContent>
                      {materials?.map((mat) => (
                        <SelectItem key={mat.id} value={mat.id.toString()}>
                          {mat.name} (Disp: {mat.current_stock} {mat.unit})
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  <FormMessage />
                </FormItem>
              )}
            />

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <FormField
                control={form.control}
                name="lost_meters"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>
                      Metros Perdidos *
                    </FormLabel>
                    <FormControl>
                      <Input
                        type="number"
                        step="0.01"
                        placeholder="0"
                        {...field}
                        value={field.value || ""}
                        onChange={e => field.onChange(parseFloat(e.target.value) || 0)}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="lost_width"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>
                      Largura da Peça (m) <span className="text-[10px] text-muted-foreground">(Opcional)</span>
                    </FormLabel>
                    <FormControl>
                      <Input
                        type="number"
                        step="0.01"
                        placeholder={selectedMaterial ? `${widthVal.toFixed(2)}m (largura bobina)` : "Ex: 0.90"}
                        value={field.value ?? ""}
                        onChange={e => {
                          const val = e.target.value;
                          field.onChange(val === "" ? null : parseFloat(val));
                        }}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            <FormField
              control={form.control}
              name="reason"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Motivo *</FormLabel>
                  <Select onValueChange={field.onChange} value={field.value}>
                    <FormControl>
                      <SelectTrigger>
                        <SelectValue placeholder="Selecione" />
                      </SelectTrigger>
                    </FormControl>
                    <SelectContent>
                      <SelectItem value="RETRABALHO">Retrabalho</SelectItem>
                      <SelectItem value="DEFEITO_FABRICA">Defeito de Fábrica</SelectItem>
                      <SelectItem value="DANO_INSTALACAO">Dano na Instalação</SelectItem>
                      <SelectItem value="SOBRA_INUTILIZAVEL">Sobra Inutilizável</SelectItem>
                      <SelectItem value="OUTRO">Outro</SelectItem>
                    </SelectContent>
                  </Select>
                  <FormMessage />
                </FormItem>
              )}
            />

            <FormField
              control={form.control}
              name="reason_details"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>
                    Motivo Detalhado {form.watch('reason') === 'OUTRO' ? '*' : '(Opcional)'}
                  </FormLabel>
                  <FormControl>
                    <Textarea
                      placeholder="Descreva o que ocorreu..."
                      className="resize-none"
                      {...field}
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            {selectedMaterial && (
              <div className="p-3 rounded-lg bg-blue-500/5 border border-blue-500/10 text-xs space-y-1.5 animate-in fade-in duration-300">
                <p className="font-semibold text-blue-600 flex items-center gap-1.5">
                  <span>⚡ Resumo Proporcional da Perda:</span>
                </p>
                <div className="grid grid-cols-3 gap-2 pt-1">
                  <div>
                    <p className="text-[10px] uppercase tracking-wider font-semibold text-muted-foreground">Largura da Peça</p>
                    <p className="font-medium text-foreground">
                      {activeWidth.toFixed(2)}m
                      {lostWidthVal !== null && lostWidthVal !== undefined && (
                        <span className="text-[9px] text-blue-600 ml-1 font-bold">(personalizada)</span>
                      )}
                    </p>
                  </div>
                  <div>
                    <p className="text-[10px] uppercase tracking-wider font-semibold text-muted-foreground">Área Total</p>
                    <p className="font-semibold text-blue-600">
                      {previewM2.toLocaleString('pt-BR', { maximumFractionDigits: 2 })} m²
                    </p>
                  </div>
                  <div>
                    <p className="text-[10px] uppercase tracking-wider font-semibold text-muted-foreground">Custo Proporcional</p>
                    <p className="font-semibold text-destructive">
                      R$ {previewCost.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                    </p>
                  </div>
                </div>
              </div>
            )}

            <div className="flex justify-end gap-2 pt-4">
              <Button type="button" variant="outline" onClick={() => onOpenChange(false)} disabled={isPending}>
                Cancelar
              </Button>
              <Button type="submit" disabled={isPending}>
                {isPending ? "Salvando..." : isEditing ? "Salvar Alterações" : "Registrar Perda"}
              </Button>
            </div>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

// @ts-nocheck
import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { z } from "zod";
import { zodResolver } from "@hookform/resolvers/zod";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useMaterialLossLimits, useUpdateMaterialLossLimit } from "@/hooks/useMaterialLossLimits";
import { Database } from "@/integrations/supabase/types";

type MaterialLossLimit = Database["public"]["Tables"]["material_loss_limits"]["Row"];

const limitFormSchema = z.object({
  limit_type: z.enum(['cost', 'meters', 'count'], {
    required_error: "Selecione o critério",
  }),
  limit_value: z.number().positive("O valor deve ser maior que zero"),
});

type LimitFormValues = z.infer<typeof limitFormSchema>;

interface MaterialLossLimitsModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function MaterialLossLimitsModal({ open, onOpenChange }: MaterialLossLimitsModalProps) {
  const [activeTab, setActiveTab] = useState<'PPF' | 'INSULFILM'>('PPF');
  const { data: limits, isLoading } = useMaterialLossLimits();
  const updateMutation = useUpdateMaterialLossLimit();

  const activeLimit = limits?.find((l: MaterialLossLimit) => l.category === activeTab);

  const form = useForm<LimitFormValues>({
    resolver: zodResolver(limitFormSchema),
    defaultValues: {
      limit_type: "cost",
      limit_value: 0,
    },
  });

  useEffect(() => {
    if (activeLimit) {
      form.reset({
        limit_type: activeLimit.limit_type as 'cost' | 'meters' | 'count',
        limit_value: Number(activeLimit.limit_value),
      });
    } else {
      form.reset({
        limit_type: "cost",
        limit_value: 0,
      });
    }
  }, [activeLimit, form, activeTab]);

  const onSubmit = async (values: LimitFormValues) => {
    try {
      await updateMutation.mutateAsync({
        id: activeLimit?.id,
        category: activeTab,
        limit_type: values.limit_type,
        limit_value: values.limit_value,
      });
      onOpenChange(false);
    } catch (error) {
      console.error(error);
    }
  };

  const isPending = updateMutation.isPending;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[425px]">
        <DialogHeader>
          <DialogTitle>Limites de Perda</DialogTitle>
          <DialogDescription>
            Configure os alertas de limite mensal de desperdício.
          </DialogDescription>
        </DialogHeader>

        <Tabs value={activeTab} onValueChange={(val) => setActiveTab(val as 'PPF' | 'INSULFILM')}>
          <TabsList className="grid w-full grid-cols-2">
            <TabsTrigger value="PPF">PPF</TabsTrigger>
            <TabsTrigger value="INSULFILM">Insulfilm</TabsTrigger>
          </TabsList>
          
          <div className="mt-4">
            <Form {...form}>
              <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
                <FormField
                  control={form.control}
                  name="limit_type"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Critério de Medida</FormLabel>
                      <Select onValueChange={field.onChange} value={field.value}>
                        <FormControl>
                          <SelectTrigger>
                            <SelectValue placeholder="Selecione o critério" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="cost">Custo Financeiro (R$)</SelectItem>
                          <SelectItem value="meters">Metros (m)</SelectItem>
                          <SelectItem value="count">Quantidade de Registros</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="limit_value"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>
                        Valor Teto 
                        {form.watch('limit_type') === 'cost' ? ' (R$)' : ''}
                        {form.watch('limit_type') === 'meters' ? ' (m)' : ''}
                      </FormLabel>
                      <FormControl>
                        <Input 
                          type="number" 
                          step={form.watch('limit_type') === 'count' ? '1' : '0.01'}
                          placeholder="0"
                          {...field} 
                          value={field.value || ""}
                          onChange={e => field.onChange(parseFloat(e.target.value) || 0)} 
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <div className="flex justify-end gap-2 pt-4">
                  <Button type="button" variant="outline" onClick={() => onOpenChange(false)} disabled={isPending}>
                    Cancelar
                  </Button>
                  <Button type="submit" disabled={isPending || isLoading}>
                    {isPending ? "Salvando..." : "Salvar Limite"}
                  </Button>
                </div>
              </form>
            </Form>
          </div>
        </Tabs>
      </DialogContent>
    </Dialog>
  );
}

// @ts-nocheck
import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Download, FileText, Loader2, FileSpreadsheet } from "lucide-react";
import { type ReportType } from "@/lib/mockData";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { generateReportPDF, type ReportPDFData } from "@/lib/pdfGenerator";
import { format, subDays } from "date-fns";
import { ptBR } from "date-fns/locale";
import { Switch } from "@/components/ui/switch";
import { getMockReportData } from "@/lib/mockReportData";

/**
 * Converte string de data "yyyy-MM-dd" para Date local.
 * new Date("2026-01-01") é interpretado como UTC, causando
 * deslocamento de -1 dia em fusos negativos (ex.: Brasil UTC-3).
 * Adicionando T00:00:00, o JS interpreta como horário local.
 */
function parseLocalDate(dateStr: string): Date {
  if (dateStr && !dateStr.includes('T')) {
    return new Date(dateStr + 'T00:00:00');
  }
  return new Date(dateStr);
}
import { uploadExcelToStorage, saveExcelRecord } from "@/lib/excelStorage";

interface Account {
  id: number;
  name: string;
}

interface ReportConfigModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  report: ReportType | null;
}

export function ReportConfigModal({ open, onOpenChange, report }: ReportConfigModalProps) {
  const { user } = useAuth();
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");
  const [accountId, setAccountId] = useState("");
  const [accounts, setAccounts] = useState<Account[]>([]);
  const [generating, setGenerating] = useState(false);
  const [companyId, setCompanyId] = useState<number | null>(null);
  const [exportFormat, setExportFormat] = useState<'pdf' | 'xlsx'>('pdf');
  const [useMockData, setUseMockData] = useState(false);

  useEffect(() => {
    if (open) {
      fetchCompanyData();
      // Set default dates (last 30 days)
      setEndDate(format(new Date(), 'yyyy-MM-dd'));
      setStartDate(format(subDays(new Date(), 30), 'yyyy-MM-dd'));
    }
  }, [open, user?.id]);

  const fetchCompanyData = async () => {
    if (!user?.id) return;

    const { data: profile } = await supabase
      .from('profiles')
      .select('company_id')
      .eq('user_id', user.id)
      .single();

    if (!profile?.company_id) return;

    setCompanyId(profile.company_id);

    if (report?.id === 'extrato_conta') {
      const { data } = await supabase
        .from('accounts')
        .select('id, name')
        .eq('company_id', profile.company_id)
        .eq('is_active', true);

      setAccounts(data || []);
    }
  };

  const generateDFCReport = async (): Promise<ReportPDFData> => {
    const { data } = await supabase
      .from('transactions')
      .select('*, accounts(name, bank_name), categories(name), subcategories(name)')
      .eq('company_id', companyId)
      .gte('transaction_date', startDate)
      .lte('transaction_date', endDate)
      .order('transaction_date', { ascending: true });

    const entradas = data?.filter(t => t.type === 'Entrada').reduce((s, t) => s + t.amount, 0) || 0;
    const saidas = data?.filter(t => t.type === 'Saida').reduce((s, t) => s + t.amount, 0) || 0;

    const rows = data?.map((t, i) => [
      (i + 1).toString(),
      format(parseLocalDate(t.transaction_date), 'dd/MM/yyyy'),
      t.name,
      t.description || '-',
      t.type,
      t.payment_method || '-',
      t.is_paid ? 'Pago' : 'Pendente',
      `R$ ${t.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`,
      (t.accounts as any)?.bank_name || (t.accounts as any)?.name || '-',
      (t.categories as any)?.name || '-',
      (t.subcategories as any)?.name || '-'
    ]) || [];

    return {
      title: 'DFC - Demonstração de Fluxo de Caixa',
      period: { start: startDate, end: endDate },
      columns: ['#', 'Data', 'Nome', 'Descrição', 'Tipo', 'Método Pgto', 'Status', 'Valor', 'Conta Bancária', 'Categoria', 'Subcategoria'],
      rows,
      summary: [
        { label: 'Total Entradas', value: `R$ ${entradas.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` },
        { label: 'Total Saídas', value: `R$ ${saidas.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` },
        { label: 'Saldo do Período', value: `R$ ${(entradas - saidas).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` },
      ],
    };
  };

  const generateSaidasFinanceiroReport = async (): Promise<ReportPDFData> => {
    const { data } = await supabase
      .from('transactions')
      .select('*, accounts(name, bank_name), categories(name), subcategories(name)')
      .eq('company_id', companyId)
      .eq('type', 'Saida')
      .gte('transaction_date', startDate)
      .lte('transaction_date', endDate)
      .order('transaction_date', { ascending: true });

    const totalPago = data?.filter(t => t.is_paid).reduce((s, t) => s + t.amount, 0) || 0;
    const totalPendente = data?.filter(t => !t.is_paid).reduce((s, t) => s + t.amount, 0) || 0;
    const totalGeral = (data?.reduce((s, t) => s + t.amount, 0)) || 0;

    const rows = data?.map((t, i) => [
      (i + 1).toString(),
      t.name,
      t.description || '-',
      `R$ ${t.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`,
      t.payment_method || '-',
      format(parseLocalDate(t.transaction_date), 'dd/MM/yyyy'),
      t.is_paid ? 'Pago' : 'Pendente',
      (t.accounts as any)?.bank_name || (t.accounts as any)?.name || '-',
      (t.categories as any)?.name || '-',
      (t.subcategories as any)?.name || '-'
    ]) || [];

    return {
      title: 'Relatório de Saídas Financeiro (Pagos e Pendentes)',
      period: { start: startDate, end: endDate },
      columns: ['#', 'Nome', 'Descrição', 'Valor', 'Método Pgto', 'Data Pgto', 'Status', 'Conta Bancária', 'Categoria', 'Subcategoria'],
      rows,
      summary: [
        { label: 'Total Pago', value: `R$ ${totalPago.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` },
        { label: 'Total Pendente', value: `R$ ${totalPendente.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` },
        { label: 'Total Geral', value: `R$ ${totalGeral.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` },
      ],
    };
  };

  const generateDREReport = async (): Promise<ReportPDFData> => {
    const fmt = (v: number) => `R$ ${v.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;
    const pct = (v: number, base: number) => base !== 0 ? `${((v / base) * 100).toFixed(1)}%` : '-';

    // ─── 1. RECEITA BRUTA DE VENDAS (tabela sales, status Fechada) ───
    const { data: salesData } = await supabase
      .from('sales')
      .select('id, total, subtotal, discount, sale_date')
      .eq('company_id', companyId)
      .eq('status', 'Fechada')
      .gte('sale_date', startDate)
      .lte('sale_date', endDate);

    const receitaBrutaVendas = salesData?.reduce((s, sale) => s + (sale.subtotal || sale.total + (sale.discount || 0)), 0) || 0;
    const totalDescontos = salesData?.reduce((s, sale) => s + (sale.discount || 0), 0) || 0;
    const totalVendas = salesData?.length || 0;

    // ─── 2. RECEITAS FINANCEIRAS (transações tipo Entrada) ───
    const { data: transactionsData } = await supabase
      .from('transactions')
      .select('*, categories(name), subcategories(name)')
      .eq('company_id', companyId)
      .gte('transaction_date', startDate)
      .lte('transaction_date', endDate);

    const entradasFinanceiras = transactionsData?.filter(t => t.type === 'Entrada') || [];
    const saidasFinanceiras = transactionsData?.filter(t => t.type === 'Saida') || [];

    const totalEntradasFinanceiras = entradasFinanceiras.reduce((s, t) => s + t.amount, 0);

    // ─── 3. COMISSÕES (sale_commissions) ───
    const saleIds = salesData?.map(s => s.id) || [];
    let totalComissoes = 0;
    if (saleIds.length > 0) {
      const { data: commissions } = await supabase
        .from('sale_commissions')
        .select('commission_amount')
        .in('sale_id', saleIds);
      totalComissoes = commissions?.reduce((s, c) => s + c.commission_amount, 0) || 0;
    }

    // ─── 4. CUSTO DE MATERIAIS (stock_movements de saída no período) ───
    const { data: stockData } = await supabase
      .from('stock_movements')
      .select('quantity, materials(name, average_cost)')
      .eq('company_id', companyId)
      .in('movement_type', ['Saida', 'open_roll_use'])
      .gte('created_at', startDate + 'T00:00:00')
      .lte('created_at', endDate + 'T23:59:59');

    const custoMateriais = stockData?.reduce((s, mov) => {
      const avgCost = (mov.materials as any)?.average_cost || 0;
      return s + (mov.quantity * avgCost);
    }, 0) || 0;

    // ─── 5. DESPESAS POR CATEGORIA ───
    const despesasPorCategoria: Record<string, number> = {};
    saidasFinanceiras.forEach(t => {
      const catName = (t.categories as any)?.name || 'Sem categoria';
      if (!despesasPorCategoria[catName]) despesasPorCategoria[catName] = 0;
      despesasPorCategoria[catName] += t.amount;
    });
    const totalDespesasOperacionais = saidasFinanceiras.reduce((s, t) => s + t.amount, 0);

    // ═══════════════════════════════════════════════
    // CÁLCULOS DO DRE
    // ═══════════════════════════════════════════════
    const receitaBruta = receitaBrutaVendas;
    const deducoes = totalDescontos;
    const receitaLiquida = receitaBruta - deducoes;
    const custoServicos = custoMateriais + totalComissoes; // CSP
    const lucroBruto = receitaLiquida - custoServicos;
    const resultadoOperacional = lucroBruto - totalDespesasOperacionais;
    const resultadoFinanceiro = totalEntradasFinanceiras; // receitas financeiras extras
    const resultadoLiquido = resultadoOperacional + resultadoFinanceiro;

    // ═══════════════════════════════════════════════
    // MONTAGEM DA TABELA HIERÁRQUICA
    // ═══════════════════════════════════════════════
    const rows: string[][] = [];

    // --- RECEITA BRUTA ---
    rows.push(['', '(+) RECEITA BRUTA DE SERVIÇOS', fmt(receitaBruta), pct(receitaBruta, receitaBruta)]);
    rows.push(['', `    Vendas fechadas (${totalVendas})`, fmt(receitaBrutaVendas), '']);

    // --- DEDUÇÕES ---
    rows.push(['', '(-) DEDUÇÕES SOBRE RECEITA', fmt(deducoes), pct(deducoes, receitaBruta)]);
    if (totalDescontos > 0) {
      rows.push(['', '    Descontos concedidos', fmt(totalDescontos), '']);
    }

    // --- RECEITA LÍQUIDA ---
    rows.push(['', '(=) RECEITA LÍQUIDA', fmt(receitaLiquida), pct(receitaLiquida, receitaBruta)]);

    // --- CUSTO DOS SERVIÇOS PRESTADOS (CSP) ---
    rows.push(['', '(-) CUSTO DOS SERVIÇOS PRESTADOS', fmt(custoServicos), pct(custoServicos, receitaBruta)]);
    if (custoMateriais > 0) {
      rows.push(['', '    Materiais consumidos', fmt(custoMateriais), '']);
    }
    if (totalComissoes > 0) {
      rows.push(['', '    Comissões sobre vendas', fmt(totalComissoes), '']);
    }

    // --- LUCRO BRUTO ---
    rows.push(['', '(=) LUCRO BRUTO', fmt(lucroBruto), pct(lucroBruto, receitaBruta)]);

    // --- DESPESAS OPERACIONAIS ---
    rows.push(['', '(-) DESPESAS OPERACIONAIS', fmt(totalDespesasOperacionais), pct(totalDespesasOperacionais, receitaBruta)]);
    Object.entries(despesasPorCategoria)
      .sort((a, b) => b[1] - a[1])
      .forEach(([cat, val]) => {
        rows.push(['', `    ${cat}`, fmt(val), pct(val, receitaBruta)]);
      });

    // --- RESULTADO OPERACIONAL ---
    rows.push(['', '(=) RESULTADO OPERACIONAL', fmt(resultadoOperacional), pct(resultadoOperacional, receitaBruta)]);

    // --- RESULTADO FINANCEIRO ---
    if (totalEntradasFinanceiras > 0) {
      rows.push(['', '(+) RECEITAS FINANCEIRAS', fmt(resultadoFinanceiro), pct(resultadoFinanceiro, receitaBruta)]);
      const recFinPorCategoria: Record<string, number> = {};
      entradasFinanceiras.forEach(t => {
        const catName = (t.categories as any)?.name || 'Sem categoria';
        if (!recFinPorCategoria[catName]) recFinPorCategoria[catName] = 0;
        recFinPorCategoria[catName] += t.amount;
      });
      Object.entries(recFinPorCategoria)
        .sort((a, b) => b[1] - a[1])
        .forEach(([cat, val]) => {
          rows.push(['', `    ${cat}`, fmt(val), '']);
        });
    }

    // --- RESULTADO LÍQUIDO ---
    rows.push(['', '(=) RESULTADO LÍQUIDO DO PERÍODO', fmt(resultadoLiquido), pct(resultadoLiquido, receitaBruta)]);

    return {
      title: 'DRE - Demonstração de Resultado do Exercício',
      period: { start: startDate, end: endDate },
      columns: ['', 'Descrição', 'Valor (R$)', 'AV%'],
      rows,
      summary: [
        { label: 'Receita Bruta', value: fmt(receitaBruta) },
        { label: 'Receita Líquida', value: fmt(receitaLiquida) },
        { label: 'Lucro Bruto', value: fmt(lucroBruto) },
        { label: `Margem Bruta`, value: pct(lucroBruto, receitaBruta) },
        { label: 'Despesas Operacionais', value: fmt(totalDespesasOperacionais) },
        { label: 'Resultado Operacional', value: fmt(resultadoOperacional) },
        { label: 'Resultado Líquido', value: fmt(resultadoLiquido) },
        { label: 'Margem Líquida', value: pct(resultadoLiquido, receitaBruta) },
      ],
    };
  };

  const generateVendasPeriodoReport = async (): Promise<ReportPDFData> => {
    const { data } = await supabase
      .from('sales')
      .select('*, clients(name), vehicles(brand, model, plate)')
      .eq('company_id', companyId)
      .eq('status', 'Fechada')
      .gte('sale_date', startDate)
      .lte('sale_date', endDate)
      .order('sale_date', { ascending: false });

    // Fetch service items for all sales
    const saleIds = data?.map(s => s.id) || [];
    let serviceItemsMap: Record<number, string[]> = {};
    let productItemsMap: Record<number, string[]> = {};

    if (saleIds.length > 0) {
      const { data: serviceItems } = await supabase
        .from('service_items_detailed')
        .select('sale_id, display_name, service_name, region_code, product_types(name)')
        .in('sale_id', saleIds);

      serviceItems?.forEach(item => {
        if (!serviceItemsMap[item.sale_id]) serviceItemsMap[item.sale_id] = [];
        if (!productItemsMap[item.sale_id]) productItemsMap[item.sale_id] = [];

        // Build description from region_code + service_name
        const desc = item.display_name || [item.region_code, item.service_name].filter(Boolean).join(' - ') || '-';
        serviceItemsMap[item.sale_id].push(desc);

        // Build product/item name
        const productName = (item.product_types as any)?.name;
        if (productName && !productItemsMap[item.sale_id].includes(productName)) {
          productItemsMap[item.sale_id].push(productName);
        }
      });
    }

    const total = data?.reduce((s, sale) => s + sale.total, 0) || 0;
    const totalDesconto = data?.reduce((s, sale) => s + (sale.discount || 0), 0) || 0;

    const rows = data?.map((sale, i) => [
      format(parseLocalDate(sale.sale_date), 'dd/MM/yyyy'),
      sale.id.toString(),
      (sale.clients as any)?.name || '-',
      (serviceItemsMap[sale.id] || []).join(', ') || '-',
      (productItemsMap[sale.id] || []).join(', ') || '-',
      `R$ ${(sale.subtotal || sale.total).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`,
      `R$ ${(sale.discount || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`,
      `R$ ${sale.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`,
      (sale.vehicles as any) ? `${(sale.vehicles as any).brand} ${(sale.vehicles as any).model}` : '-'
    ]) || [];

    return {
      title: 'Relatório de Vendas (Somente Fechadas)',
      period: { start: startDate, end: endDate },
      columns: ['Data Venda', 'Venda', 'Cliente', 'Descrição', 'Item/Produto', 'Subtotal', 'Desconto', 'Total', 'Veículo'],
      rows,
      summary: [
        { label: 'Total de Vendas', value: (data?.length || 0).toString() },
        { label: 'Total Descontos', value: `R$ ${totalDesconto.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` },
        { label: 'Valor Total', value: `R$ ${total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` },
      ],
    };
  };

