  const generatePerdasMaterialReport = async (): Promise<ReportPDFData> => {
    const { data } = await supabase
      .from('material_losses')
      .select('*, material:materials(*)')
      .eq('company_id', companyId)
      .eq('status', 'active')
      .gte('created_at', startDate)
      .lte('created_at', endDate);

    const formatReason = (reason: string) => {
      switch (reason) {
        case 'RETRABALHO': return 'Retrabalho';
        case 'DEFEITO_FABRICA': return 'Defeito de Fábrica';
        case 'DANO_INSTALACAO': return 'Dano na Instalação';
        case 'SOBRA_INUTILIZAVEL': return 'Sobra Inutilizável';
        case 'OUTRO': return 'Outro';
        default: return reason || '-';
      }
    };

    const losses = (data || []) as any[];
    const lossStats: Record<number, {
      name: string;
      brand: string;
      category: string;
      requestCount: number;
      totalMeters: number;
      totalM2: number;
      totalCost: number;
      reasonsMap: Record<string, number>;
    }> = {};

    let globalReasonsMap: Record<string, number> = {};

    losses.forEach(loss => {
      const mat = loss.material;
      if (!mat) return;

      const matId = mat.id;
      if (!lossStats[matId]) {
        lossStats[matId] = {
          name: mat.name || '',
          brand: mat.brand || '',
          category: loss.category || '',
          requestCount: 0,
          totalMeters: 0,
          totalM2: 0,
          totalCost: 0,
          reasonsMap: {}
        };
      }

      const stat = lossStats[matId];
      stat.requestCount += 1;
      stat.totalMeters += Number(loss.lost_meters) || 0;
      stat.totalM2 += Number(loss.lost_m2) || 0;
      stat.totalCost += Number(loss.cost) || 0;

      const reason = loss.reason || 'OUTRO';
      stat.reasonsMap[reason] = (stat.reasonsMap[reason] || 0) + 1;
      globalReasonsMap[reason] = (globalReasonsMap[reason] || 0) + 1;
    });

    let grandTotalRequests = 0;
    let grandTotalMeters = 0;
    let grandTotalM2 = 0;
    let grandTotalCost = 0;

    const rows = Object.values(lossStats)
      .map(stat => {
        const reqCount = stat.requestCount;
        const meters = stat.totalMeters;
        const m2 = stat.totalM2;
        const cost = stat.totalCost;

        grandTotalRequests += reqCount;
        grandTotalMeters += meters;
        grandTotalM2 += m2;
        grandTotalCost += cost;

        const avgMeters = reqCount > 0 ? (meters / reqCount) : 0;
        const avgM2 = reqCount > 0 ? (m2 / reqCount) : 0;
        const avgCost = reqCount > 0 ? (cost / reqCount) : 0;

        let mostFrequentReason = '-';
        let maxCount = 0;
        Object.entries(stat.reasonsMap).forEach(([reason, count]) => {
          if (count > maxCount) {
            maxCount = count;
            mostFrequentReason = formatReason(reason);
          }
        });

        const fmtBRL = (v: number) => `R$ ${v.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
        const fmtMeters = (v: number) => `${v.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} m`;
        const fmtM2 = (v: number) => `${v.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} m²`;

        const materialName = [stat.brand, stat.name].filter(Boolean).join(' - ');

        return {
          materialName,
          category: stat.category,
          requestCountFormatted: reqCount.toString(),
          metersFormatted: fmtMeters(meters),
          m2Formatted: fmtM2(m2),
          costFormatted: fmtBRL(cost),
          avgMetersFormatted: fmtMeters(avgMeters),
          avgM2Formatted: fmtM2(avgM2),
          avgCostFormatted: fmtBRL(avgCost),
          mostFrequentReason,
          costValue: cost
        };
      })
      .sort((a, b) => b.costValue - a.costValue)
      .map((item, i) => [
        (i + 1).toString(),
        item.materialName,
        item.category,
        item.requestCountFormatted,
        item.metersFormatted,
        item.m2Formatted,
        item.costFormatted,
        item.avgMetersFormatted,
        item.avgM2Formatted,
        item.avgCostFormatted,
        item.mostFrequentReason
      ]);

    let globalMostFrequentReason = '-';
    let globalMaxCount = 0;
    Object.entries(globalReasonsMap).forEach(([reason, count]) => {
      if (count > globalMaxCount) {
        globalMaxCount = count;
        globalMostFrequentReason = formatReason(reason);
      }
    });

    const grandAverageCost = grandTotalRequests > 0 ? (grandTotalCost / grandTotalRequests) : 0;

    const fmtBRL = (v: number) => `R$ ${v.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
    const fmtMeters = (v: number) => `${v.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} m`;
    const fmtM2 = (v: number) => `${v.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} m²`;

    return {
      title: 'Relatório de Perdas de Material',
      period: { start: startDate, end: endDate },
      columns: [
        '#',
        'Material',
        'Categoria',
        'Solicit.',
        'Metros Perdidos',
        'M² Perdidos',
        'Custo Total',
        'Média m/Solicit.',
        'Média m²/Solicit.',
        'Média $/Solicit.',
        'Motivo Principal'
      ],
      rows,
      summary: [
        { label: 'Total de Solicitações', value: grandTotalRequests.toString() },
        { label: 'Metragem Perdida Total', value: fmtMeters(grandTotalMeters) },
        { label: 'Área Perdida Total', value: fmtM2(grandTotalM2) },
        { label: 'Custo de Perda Consolidado', value: fmtBRL(grandTotalCost) },
        { label: 'Custo Médio por Perda', value: fmtBRL(grandAverageCost) },
        { label: 'Motivo Mais Comum Geral', value: globalMostFrequentReason }
      ]
    };
  };

  const generateClientesMarketingReport = async (): Promise<ReportPDFData> => {
    const { data } = await supabase
      .from('clients')
      .select('name, phone, email')
      .eq('company_id', companyId)
      .order('name');

    const rows = data?.map((c, i) => [
      (i + 1).toString(),
      c.name,
      c.phone || '-',
      c.email || '-'
    ]) || [];

    return {
      title: 'Lista de Marketing',
      columns: ['#', 'Nome', 'Telefone', 'Email'],
      rows,
      summary: [
        { label: 'Total de Clientes', value: rows.length.toString() },
      ],
    };
  };

  const generateClientesCompletoReport = async (): Promise<ReportPDFData> => {
    const { data: clients } = await supabase
      .from('clients')
      .select('id, name, phone, email, cpf_cnpj')
      .eq('company_id', companyId)
      .order('name');

    const { data: vehicles } = await supabase
      .from('vehicles')
      .select('client_id, brand, model, plate')
      .eq('company_id', companyId);

    const { data: sales } = await supabase
      .from('sales')
      .select('client_id, sale_date, total, sale_items(services(name))')
      .eq('company_id', companyId);

    const vehiclesByClient: Record<number, string[]> = {};
    vehicles?.forEach(v => {
      if (!v.client_id) return;
      if (!vehiclesByClient[v.client_id]) vehiclesByClient[v.client_id] = [];
      vehiclesByClient[v.client_id].push(`${v.brand} ${v.model}${v.plate ? ` (${v.plate})` : ''}`);
    });

    const salesByClient: Record<number, { total: number; lastDate: string }> = {};
    sales?.forEach(s => {
      if (!s.client_id) return;
      if (!salesByClient[s.client_id]) salesByClient[s.client_id] = { total: 0, lastDate: '' };
      salesByClient[s.client_id].total += s.total;
      if (s.sale_date > salesByClient[s.client_id].lastDate) salesByClient[s.client_id].lastDate = s.sale_date;
    });

    let totalGeral = 0;
    let totalVeiculos = 0;

    const rows = clients?.map((c, i) => {
      const veics = vehiclesByClient[c.id] || [];
      const saleData = salesByClient[c.id];
      totalGeral += saleData?.total || 0;
      totalVeiculos += veics.length;
      return [
        (i + 1).toString(),
        c.name,
        c.phone || '-',
        c.email || '-',
        c.cpf_cnpj || '-',
        veics.length > 0 ? veics.join(', ') : '-',
        saleData ? `R$ ${saleData.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` : 'R$ 0,00',
        saleData?.lastDate ? format(parseLocalDate(saleData.lastDate), 'dd/MM/yyyy') : '-'
      ];
    }) || [];

    return {
      title: 'Lista Completa de Clientes (Backup)',
      columns: ['#', 'Nome', 'Telefone', 'Email', 'CPF/CNPJ', 'Veículos', 'Total Gasto', 'Última Compra'],
      rows,
      summary: [
        { label: 'Total de Clientes', value: rows.length.toString() },
        { label: 'Total de Veículos', value: totalVeiculos.toString() },
        { label: 'Valor Total', value: `R$ ${totalGeral.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` },
      ],
    };
  };

  const generateExtratoContaReport = async (): Promise<ReportPDFData> => {
    const account = accounts.find(a => a.id === parseInt(accountId));

    const { data } = await supabase
      .from('transactions')
      .select('*')
      .eq('company_id', companyId)
      .eq('account_id', parseInt(accountId))
      .gte('transaction_date', startDate)
      .lte('transaction_date', endDate)
      .order('transaction_date', { ascending: true });

    const entradas = data?.filter(t => t.type === 'Entrada').reduce((s, t) => s + t.amount, 0) || 0;
    const saidas = data?.filter(t => t.type === 'Saida').reduce((s, t) => s + t.amount, 0) || 0;

    const rows = data?.map((t, i) => [
      (i + 1).toString(),
      format(parseLocalDate(t.transaction_date), 'dd/MM/yyyy'),
      t.name,
      t.type,
      `R$ ${t.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`
    ]) || [];

    return {
      title: `Extrato - ${account?.name || 'Conta'}`,
      period: { start: startDate, end: endDate },
      columns: ['#', 'Data', 'Descrição', 'Tipo', 'Valor'],
      rows,
      summary: [
        { label: 'Entradas', value: `R$ ${entradas.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` },
        { label: 'Saídas', value: `R$ ${saidas.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` },
        { label: 'Saldo', value: `R$ ${(entradas - saidas).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` },
      ],
    };
  };

  const generateExcel = async (data: ReportPDFData, companyId?: number) => {
    let html = '<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">';
    html += '<head><meta charset="utf-8"><style>td,th{border:1px solid #ccc;padding:6px 10px;font-family:Arial;font-size:12px}th{background:#f0f0f0;font-weight:bold}h2{font-family:Arial}</style></head><body>';
    html += `<h2>${data.title}</h2>`;
    if (data.period) {
      html += `<p>Período: ${format(parseLocalDate(data.period.start), 'dd/MM/yyyy')} a ${format(parseLocalDate(data.period.end), 'dd/MM/yyyy')}</p>`;
    }
    html += '<table border="1" cellspacing="0">';
    html += '<tr>' + data.columns.map(c => `<th>${c}</th>`).join('') + '</tr>';
    data.rows.forEach(row => {
      html += '<tr>' + row.map(cell => `<td>${cell}</td>`).join('') + '</tr>';
    });
    html += '</table>';
    if (data.summary && data.summary.length > 0) {
      html += '<br/><table border="1" cellspacing="0">';
      html += '<tr><th colspan="2">Resumo</th></tr>';
      data.summary.forEach(s => {
        html += `<tr><td><b>${s.label}</b></td><td>${s.value}</td></tr>`;
      });
      html += '</table>';
    }
    html += '</body></html>';

    const blob = new Blob(['\ufeff' + html], { type: 'application/vnd.ms-excel;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    const filename = `${data.title.toLowerCase().replace(/\s+/g, '-')}.xls`;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    // Upload to Supabase Storage
    let storagePath: string | undefined;
    if (companyId) {
      const path = `${companyId}/relatorios/excel/${filename}`;
      const uploaded = await uploadExcelToStorage(blob, path);
      if (uploaded) {
        storagePath = uploaded;
      }
    }

    // Save metadata record
    saveExcelRecord({
      filename,
      type: 'Relatório Excel',
      module: 'relatorios',
      details: data.title + (data.period ? ` (${format(parseLocalDate(data.period.start), 'dd/MM/yyyy')} - ${format(parseLocalDate(data.period.end), 'dd/MM/yyyy')})` : ''),
      storagePath,
    });
  };

  const handleGenerate = async () => {
    if (!report || !companyId) return;

    setGenerating(true);
    try {
      let reportData: ReportPDFData;

      if (useMockData && user?.email?.toLowerCase() === 'hg.lavila@gmail.com') {
        const mock = getMockReportData(report.id, startDate, endDate);
        if (!mock) {
          toast.error("Mock data não implementado para este relatório.");
          setGenerating(false);
          return;
        }
        reportData = mock;
      } else {
        switch (report.id) {
          case 'dfc':
            reportData = await generateDFCReport();
            break;
          case 'dre':
            reportData = await generateDREReport();
            break;
          case 'vendas_periodo':
            reportData = await generateVendasPeriodoReport();
            break;
          case 'vendas_servico':
            reportData = await generateVendasServicoReport();
            break;
          case 'vendas_vendedor':
            reportData = await generateVendasVendedorReport();
            break;
          case 'vendas_pelicula':
            reportData = await generateVendasPeliculaReport();
            break;
          case 'clientes_ativos':
            reportData = await generateClientesAtivosReport();
            break;
          case 'clientes_inativos':
            reportData = await generateClientesInativosReport();
            break;
          case 'clientes_marketing':
            reportData = await generateClientesMarketingReport();
            break;
          case 'clientes_completo':
            reportData = await generateClientesCompletoReport();
            break;
          case 'ocupacao_vagas':
            reportData = await generateOcupacaoVagasReport();
            break;
          case 'estoque_movimento':
            reportData = await generateEstoqueMovimentoReport();
            break;
          case 'perdas_material':
            reportData = await generatePerdasMaterialReport();
            break;
          case 'extrato_conta':
            if (!accountId) {
              toast.error("Selecione uma conta");
              return;
            }
            reportData = await generateExtratoContaReport();
            break;
          case 'saidas_financeiro':
            reportData = await generateSaidasFinanceiroReport();
            break;
          default:
            toast.error("Relatório não implementado");
            return;
        }
      }

      if (exportFormat === 'xlsx') {
        await generateExcel(reportData, companyId || undefined);
        toast.success(`Relatório ${report.name} gerado em Excel!`);
      } else {
        await generateReportPDF(reportData, companyId || undefined);
        toast.success(`Relatório ${report.name} gerado em PDF!`);
      }
      onOpenChange(false);
    } catch (error) {
      console.error('Error generating report:', error);
      toast.error('Erro ao gerar relatório');
    } finally {
      setGenerating(false);
    }
  };

  if (!report) return null;

  const needsAccount = report.id === 'extrato_conta';
  const needsDateRange = !['clientes_ativos', 'clientes_inativos', 'clientes_marketing', 'clientes_completo'].includes(report.id);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <FileText className="h-5 w-5" />
            {report.name}
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-4">
          <p className="text-sm text-muted-foreground">{report.description}</p>

          {needsDateRange && (
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>Data Inicial</Label>
                <Input
                  type="date"
                  value={startDate}
                  onChange={e => setStartDate(e.target.value)}
                />
              </div>
              <div className="space-y-2">
                <Label>Data Final</Label>
                <Input
                  type="date"
                  value={endDate}
                  onChange={e => setEndDate(e.target.value)}
                />
              </div>
            </div>
          )}

          {needsAccount && (
            <div className="space-y-2">
              <Label>Conta</Label>
              <Select value={accountId} onValueChange={setAccountId}>
                <SelectTrigger>
                  <SelectValue placeholder="Selecione a conta..." />
                </SelectTrigger>
                <SelectContent>
                  {accounts.map(acc => (
                    <SelectItem key={acc.id} value={acc.id.toString()}>
                      {acc.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          )}

          {/* Format selector */}
          <div className="space-y-2">
            <Label>Formato de exportação</Label>
            <div className="flex gap-2">
              <Button
                type="button"
                variant={exportFormat === 'pdf' ? 'default' : 'outline'}
                className="flex-1"
                onClick={() => setExportFormat('pdf')}
              >
                <FileText className="h-4 w-4 mr-2" />
                PDF
              </Button>
              <Button
                type="button"
                variant={exportFormat === 'xlsx' ? 'default' : 'outline'}
                className="flex-1"
                onClick={() => setExportFormat('xlsx')}
              >
                <FileSpreadsheet className="h-4 w-4 mr-2" />
                Excel
              </Button>
            </div>
          </div>

          {user?.email?.toLowerCase() === 'hg.lavila@gmail.com' && (
            <div className="flex items-center space-x-2 py-2">
              <Switch
                id="mock-data"
                checked={useMockData}
                onCheckedChange={setUseMockData}
              />
              <Label htmlFor="mock-data" className="text-sm cursor-pointer whitespace-nowrap">
                Usar dados fictícios para teste
              </Label>
            </div>
          )}

          <div className="flex gap-2 pt-4">
            <Button variant="outline" className="flex-1" onClick={() => onOpenChange(false)}>
              Cancelar
            </Button>
            <Button className="flex-1" onClick={handleGenerate} disabled={generating}>
              {generating ? (
                <>
                  <Loader2 className="h-4 w-4 mr-2 animate-spin" /> Gerando...
                </>
              ) : (
                <>
                  <Download className="h-4 w-4 mr-2" /> {exportFormat === 'pdf' ? 'Gerar PDF' : 'Gerar Excel'}
                </>
              )}
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

