// @ts-nocheck
// AuthContext - Manages authentication state and user data
import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User, Session } from '@supabase/supabase-js';
import { supabase, setSupabaseReadOnly } from '@/integrations/supabase/client';
import type { Profile, AppRole } from '@/lib/database.types';
import { checkPwnedPassword } from '@/lib/passwordSecurity';

export type SubscriptionStatus = 'pending_payment' | 'payment_submitted' | 'active' | 'expired' | 'blocked';

interface AuthUser {
  id: string;
  email: string;
  profile: Profile | null;
  role: AppRole;
  subscriptionStatus: SubscriptionStatus;
  companyId: number | null;
  isMaster: boolean;
  hasPendingJoinRequest: boolean;
  isCompanyOwner: boolean;
  planCode: string | null;
  billingPeriod: string | null;
}

interface AuthContextType {
  user: AuthUser | null;
  session: Session | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  signIn: (email: string, password: string, captchaToken?: string | null) => Promise<{ error: Error | null }>;
  signUp: (email: string, password: string, name: string, phone?: string, captchaToken?: string | null) => Promise<{ error: Error | null; isPwnedPassword?: boolean }>;
  signOut: () => Promise<void>;
  refreshUser: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<AuthUser | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (user) {
      const isReadOnly = user.subscriptionStatus === 'pending_payment' && !user.isMaster;
      setSupabaseReadOnly(isReadOnly);
    } else {
      setSupabaseReadOnly(false);
    }
  }, [user]);

  const fetchUserData = async (userId: string): Promise<AuthUser | null> => {
    try {
      // Fetch profile
      const { data: profile, error: profileError } = await supabase
        .from('profiles')
        .select('*')
        .eq('user_id', userId)
        .maybeSingle();

      if (profileError) {
        console.error('Error fetching profile:', profileError);
      }

      // Fetch role
      const { data: roleData, error: roleError } = await supabase
        .from('user_roles')
        .select('role')
        .eq('user_id', userId)
        .maybeSingle();

      if (roleError) {
        console.error('Error fetching role:', roleError);
      }

      // Check if user is company owner mapping and get company owner id if exists
      let isCompanyOwner = false;
      let companyOwnerId = userId; // Default to self

      if (profile?.company_id) {
        const { data: companyData } = await supabase
          .from('companies')
          .select('owner_id')
          .eq('id', profile.company_id)
          .single();

        if (companyData) {
          isCompanyOwner = companyData.owner_id === userId;
          companyOwnerId = companyData.owner_id;
        }
      }

      // Fetch subscription (check owner's subscription if user is in a company)
      const { data: subscriptionData, error: subscriptionError } = await supabase
        .from('subscriptions')
        .select('status, company_id, expires_at, plan_code, billing_period')
        .eq('user_id', companyOwnerId)
        .maybeSingle();

      if (subscriptionError) {
        console.error('Error fetching subscription:', subscriptionError);
      }

      // Check for pending join request (only if user has no company)
      let hasPendingJoinRequest = false;
      if (!profile?.company_id) {
        const { data: pendingRequest } = await supabase
          .from('company_join_requests')
          .select('id')
          .eq('requester_user_id', userId)
          .eq('status', 'pending')
          .maybeSingle();

        hasPendingJoinRequest = !!pendingRequest;
      }

      // Check if user is master account via database function (secure, no email exposed in frontend)
      const { data: isMasterResult } = await supabase.rpc('check_is_master');
      const isMaster = isMasterResult === true;

      // Determine subscription status
      let calculatedStatus: SubscriptionStatus = 'pending_payment';
      if (subscriptionData) {
        const rawStatus = (subscriptionData.status as SubscriptionStatus) || 'pending_payment';

        if (rawStatus === 'blocked') {
          calculatedStatus = 'blocked';
        } else if (rawStatus === 'expired') {
          calculatedStatus = 'expired';
        } else if (rawStatus === 'payment_submitted') {
          calculatedStatus = 'payment_submitted';
        } else if (rawStatus === 'pending_payment') {
          calculatedStatus = 'pending_payment';
        } else {
          // If status is active, check if it has expired
          calculatedStatus = 'active';

          if (subscriptionData.expires_at) {
            const expiresAtDate = new Date(subscriptionData.expires_at);
            const now = new Date();

            if (expiresAtDate <= now) {
              // If the expiration date has passed, force expired status
              calculatedStatus = 'expired';
            }
          }
        }
      } else if (profile?.company_id) {
        // Legacy company grandfathering: owner has no subscription record but company exists
        calculatedStatus = 'active';
      }

      let computedRole = roleData?.role as AppRole;
      if (!computedRole || computedRole === 'NENHUM') {
        if (profile?.company_id && !isCompanyOwner) {
          computedRole = 'FUNCIONARIO';
        } else {
          computedRole = 'NENHUM';
        }
      }

      return {
        id: userId,
        email: profile?.email || '',
        profile: profile as Profile | null,
        role: computedRole,
        subscriptionStatus: isMaster ? 'active' : calculatedStatus,
        companyId: profile?.company_id || subscriptionData?.company_id || null,
        isMaster,
        hasPendingJoinRequest,
        isCompanyOwner,
        planCode: subscriptionData?.plan_code || null,
        billingPeriod: subscriptionData?.billing_period || null
      };
    } catch (error) {
      console.error('Error fetching user data:', error);
      return null;
    }
  };

  useEffect(() => {
    // Set up auth state listener FIRST
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      (event, currentSession) => {
        setSession(currentSession);

        if (currentSession?.user) {
          // Defer Supabase calls with setTimeout to avoid deadlock
          setTimeout(async () => {
            const userData = await fetchUserData(currentSession.user.id);
            setUser(userData);
            setIsLoading(false);
          }, 0);
        } else {
          setUser(null);
          setIsLoading(false);
        }
      }
    );

    // THEN check for existing session
    supabase.auth.getSession().then(({ data: { session: existingSession } }) => {
      setSession(existingSession);

      if (existingSession?.user) {
        fetchUserData(existingSession.user.id).then((userData) => {
          setUser(userData);
          setIsLoading(false);
        });
      } else {
        setIsLoading(false);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const signIn = async (email: string, password: string, captchaToken?: string | null): Promise<{ error: Error | null }> => {
    try {
      const { error } = await supabase.auth.signInWithPassword({
        email,
        password,
        options: {
          captchaToken: captchaToken || undefined,
        }
      });

      if (error) {
        return { error };
      }

      return { error: null };
    } catch (error) {
      return { error: error as Error };
    }
  };

  const signUp = async (email: string, password: string, name: string, phone?: string, captchaToken?: string | null): Promise<{ error: Error | null; isPwnedPassword?: boolean }> => {
    try {
      // Validate name before sending to server
      const trimmedName = name.trim();
      if (!trimmedName || trimmedName.length < 2) {
        return { error: new Error('Nome deve ter pelo menos 2 caracteres') };
      }
      if (trimmedName.length > 100) {
        return { error: new Error('Nome deve ter no máximo 100 caracteres') };
      }
      if (!/^[a-zA-ZÀ-ÿ\s'-]+$/.test(trimmedName)) {
        return { error: new Error('Nome contém caracteres inválidos') };
      }

      // Validate email
      const trimmedEmail = email.trim().toLowerCase();
      if (!trimmedEmail || trimmedEmail.length > 255) {
        return { error: new Error('Email inválido') };
      }
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!emailRegex.test(trimmedEmail)) {
        return { error: new Error('Email inválido') };
      }

      // Validate password
      if (!password || password.length < 6) {
        return { error: new Error('Senha deve ter pelo menos 6 caracteres') };
      }

      // Check if password has been exposed in data breaches
      const pwnedResult = await checkPwnedPassword(password);
      if (pwnedResult.isPwned) {
        return {
          error: new Error(`Esta senha foi encontrada em ${pwnedResult.count.toLocaleString('pt-BR')} vazamentos de dados. Por favor, escolha uma senha diferente e mais segura.`),
          isPwnedPassword: true
        };
      }

      // Validate phone if provided
      const trimmedPhone = phone?.trim() || null;
      if (trimmedPhone && !/^[\d\s()+\-]+$/.test(trimmedPhone)) {
        return { error: new Error('Telefone inválido') };
      }

      const redirectUrl = `${window.location.origin}/login`;

      const { error } = await supabase.auth.signUp({
        email: trimmedEmail,
        password,
        options: {
          emailRedirectTo: redirectUrl,
          captchaToken: captchaToken || undefined,
          data: {
            name: trimmedName,
            phone: trimmedPhone
          }
        }
      });

      if (error) {
        return { error };
      }

      return { error: null };
    } catch (error) {
      return { error: error as Error };
    }
  };

  const signOut = async () => {
    await supabase.auth.signOut();
    setUser(null);
    setSession(null);
  };

  const refreshUser = async () => {
    if (session?.user) {
      const userData = await fetchUserData(session.user.id);
      setUser(userData);
    }
  };

  return (
    <AuthContext.Provider value={{
      user,
      session,
      isAuthenticated: !!user,
      isLoading,
      signIn,
      signUp,
      signOut,
      refreshUser
    }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

import { useState, useEffect } from "react";

interface BeforeInstallPromptEvent extends Event {
  prompt: () => Promise<void>;
  userChoice: Promise<{ outcome: "accepted" | "dismissed" }>;
}

export function usePWAInstall() {
  const [deferredPrompt, setDeferredPrompt] =
    useState<BeforeInstallPromptEvent | null>(null);
  const [isInstallable, setIsInstallable] = useState(false);
  const [isInstalled, setIsInstalled] = useState(false);
  const [isIOS, setIsIOS] = useState(false);

  useEffect(() => {
    // Check if already installed (standalone mode)
    const isStandalone =
      window.matchMedia("(display-mode: standalone)").matches ||
      (window.navigator as any).standalone === true;
    setIsInstalled(isStandalone);

    // Check if iOS
    const isIOSDevice =
      /iPad|iPhone|iPod/.test(navigator.userAgent) &&
      !(window as any).MSStream;
    setIsIOS(isIOSDevice);

    // Listen for beforeinstallprompt
    const handleBeforeInstall = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e as BeforeInstallPromptEvent);
      setIsInstallable(true);
    };

    window.addEventListener("beforeinstallprompt", handleBeforeInstall);

    // Listen for app installed
    const handleAppInstalled = () => {
      setIsInstalled(true);
      setIsInstallable(false);
      setDeferredPrompt(null);
    };

    window.addEventListener("appinstalled", handleAppInstalled);

    return () => {
      window.removeEventListener("beforeinstallprompt", handleBeforeInstall);
      window.removeEventListener("appinstalled", handleAppInstalled);
    };
  }, []);

  const promptInstall = async () => {
    if (!deferredPrompt) return false;

    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;

    if (outcome === "accepted") {
      setIsInstallable(false);
      setDeferredPrompt(null);
    }

    return outcome === "accepted";
  };

  return {
    isInstallable,
    isInstalled,
    isIOS,
    promptInstall,
  };
}

