import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "@/hooks/use-toast";
import { Database } from "@/integrations/supabase/types";

type MaterialLoss = Database["public"]["Tables"]["material_losses"]["Row"];
type MaterialLossInsert = Database["public"]["Tables"]["material_losses"]["Insert"];
type MaterialLossUpdate = Database["public"]["Tables"]["material_losses"]["Update"];

export function useMaterialLosses(filters?: { 
  startDate?: string; 
  endDate?: string; 
  category?: 'PPF' | 'INSULFILM'; 
  materialId?: number;
  saleId?: number;
  installerId?: string;
}) {
  const { user } = useAuth();
  const companyId = user?.companyId;

  return useQuery({
    queryKey: ['material-losses', companyId, filters],
    queryFn: async () => {
      if (!companyId) return [];

      let query = supabase
        .from('material_losses')
        .select(`
          *,
          material:materials(id, name, unit)
        `)
        .eq('company_id', companyId)
        .order('created_at', { ascending: false });

      if (filters?.startDate) {
        query = query.gte('created_at', filters.startDate);
      }
      if (filters?.endDate) {
        query = query.lte('created_at', filters.endDate);
      }
      if (filters?.category) {
        query = query.eq('category', filters.category);
      }
      if (filters?.materialId) {
        query = query.eq('material_id', filters.materialId);
      }
      if (filters?.saleId) {
        query = query.eq('sale_id', filters.saleId);
      }
      if (filters?.installerId) {
        query = query.eq('installer_id', filters.installerId);
      }

      const { data: lossesData, error } = await query;

      if (error) {
        console.error('Error fetching material losses:', error);
        throw error;
      }

      // Fetch profiles to map installer names manually
      const { data: profilesData, error: profilesError } = await supabase
        .from('profiles')
        .select('id, name, user_id')
        .eq('company_id', companyId);

      if (profilesError) {
        console.error('Error fetching profiles for material losses:', profilesError);
      }

      const profilesMap = new Map((profilesData || []).map(p => [p.user_id, p]));

      return (lossesData || []).map(loss => {
        const profile = profilesMap.get(loss.installer_id);
        return {
          ...loss,
          installer: profile ? {
            id: profile.id,
            name: profile.name
          } : null
        };
      });
    },
    enabled: !!companyId,
  });
}

export function useCreateMaterialLoss() {
  const queryClient = useQueryClient();
  const { user } = useAuth();

  return useMutation({
    mutationFn: async (lossData: Omit<MaterialLossInsert, 'company_id'>) => {
      if (!user?.companyId) throw new Error("Usuário sem empresa vinculada");

      const { data, error } = await supabase
        .from('material_losses')
        .insert([{ ...lossData, company_id: user.companyId }])
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['material-losses'] });
      // Invalidate materials and stock movements as well because triggers update stock
      queryClient.invalidateQueries({ queryKey: ['materials'] });
      queryClient.invalidateQueries({ queryKey: ['stock-movements'] });
      toast({ title: "Perda de material registrada com sucesso" });
    },
    onError: (error: any) => {
      console.error('Error creating material loss:', error);
      toast({ 
        title: "Erro ao registrar perda", 
        description: error.message || "Não foi possível registrar a perda de material.", 
        variant: "destructive" 
      });
    }
  });
}

export function useUpdateMaterialLoss() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ id, updates }: { id: number; updates: MaterialLossUpdate }) => {
      const { data, error } = await supabase
        .from('material_losses')
        .update(updates)
        .eq('id', id)
        .select()
        .single();

      if (error) throw error;
      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['material-losses'] });
      queryClient.invalidateQueries({ queryKey: ['materials'] });
      queryClient.invalidateQueries({ queryKey: ['stock-movements'] });
      toast({ title: "Registro atualizado com sucesso" });
    },
    onError: (error: any) => {
      console.error('Error updating material loss:', error);
      toast({ 
        title: "Erro ao atualizar registro", 
        description: error.message || "Não foi possível atualizar o registro.", 
        variant: "destructive" 
      });
    }
  });
}

export function useDeleteMaterialLoss() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (id: number) => {
      // Deletion is a soft delete according to design: update status to 'cancelled'
      const { error } = await supabase
        .from('material_losses')
        .update({ status: 'cancelled' })
        .eq('id', id);

      if (error) throw error;
      return true;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['material-losses'] });
      queryClient.invalidateQueries({ queryKey: ['materials'] });
      queryClient.invalidateQueries({ queryKey: ['stock-movements'] });
      toast({ title: "Registro cancelado com sucesso" });
    },
    onError: (error: any) => {
      console.error('Error deleting material loss:', error);
      toast({ 
        title: "Erro ao cancelar registro", 
        description: error.message || "Não foi possível cancelar o registro.", 
        variant: "destructive" 
      });
    }
  });
}

import { createClient } from '@supabase/supabase-js';
import type { Database } from './types';
import { toast as sonnerToast } from "sonner";

type AugmentedDatabase = Omit<Database, 'public'> & {
  public: Omit<Database['public'], 'Tables' | 'Functions'> & {
    Tables: Database['public']['Tables'] & Record<string, any>;
    Functions: Database['public']['Functions'] & Record<string, any>;
  }
};

const SUPABASE_URL = import.meta.env.VITE_SUPABASE_URL;
const SUPABASE_PUBLISHABLE_KEY = import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY;

if (!SUPABASE_URL || !SUPABASE_PUBLISHABLE_KEY) {
  throw new Error(
    'Missing Supabase environment variables. Please set VITE_SUPABASE_URL and VITE_SUPABASE_PUBLISHABLE_KEY in your .env file.'
  );
}

// Import the supabase client like this:
// import { supabase } from "@/integrations/supabase/client";

const rawSupabase = createClient<AugmentedDatabase>(SUPABASE_URL, SUPABASE_PUBLISHABLE_KEY, {
  auth: {
    storage: localStorage,
    persistSession: true,
    autoRefreshToken: true,
  }
});

let isReadOnlyMode = false;

// Global monkey patch for Sonner Toast to intercept and override error messages in read-only mode
try {
  const rawToast = sonnerToast as any;
  if (rawToast && typeof rawToast === 'function') {
    const originalError = rawToast.error;
    if (typeof originalError === 'function') {
      rawToast.error = function (message: any, options?: any) {
        if (isReadOnlyMode) {
          return originalError.call(
            rawToast,
            "Modo de leitura ativo: Regularize sua assinatura pelo WhatsApp no topo da tela para realizar alterações.",
            options
          );
        }
        return originalError.call(rawToast, message, options);
      };
    }
  }
} catch (e) {
  console.error("Erro ao aplicar patch no sonner toast:", e);
}

export const setSupabaseReadOnly = (readOnly: boolean) => {
  isReadOnlyMode = readOnly;
};

export const getSupabaseReadOnly = () => {
  return isReadOnlyMode;
};

// Create a Proxy handler to block write operations when in read-only mode
const createWriteBlocker = () => {
  return () => {
    const errorResult = {
      data: null,
      error: {
        message: "Assinatura pendente: Regularize o pagamento pelo WhatsApp no topo da página para liberar a alteração de dados.",
        details: "Assinatura pendente de pagamento",
        hint: "read-only-mode",
        code: "READ_ONLY_BLOCK"
      }
    };

    const blockerPromise = Promise.resolve(errorResult);

    const builderProxy = new Proxy(blockerPromise, {
      get(target, prop, receiver) {
        if (['then', 'catch', 'finally'].includes(prop as string)) {
          const val = Reflect.get(target, prop, receiver);
          if (typeof val === 'function') {
            return val.bind(target);
          }
          return val;
        }
        return builderProxy;
      }
    });

    return builderProxy;
  };
};

const queryBuilderHandler: ProxyHandler<any> = {
  get(target, prop, receiver) {
    if (isReadOnlyMode && ['insert', 'update', 'delete', 'upsert'].includes(prop as string)) {
      return createWriteBlocker();
    }
    const val = Reflect.get(target, prop, receiver);
    if (typeof val === 'function') {
      return val.bind(target);
    }
    return val;
  }
};

export const supabase = new Proxy(rawSupabase, {
  get(target, prop, receiver) {
    // Intercept client.from(...)
    if (prop === 'from') {
      return (relation: string) => {
        const queryBuilder = target.from(relation);
        return new Proxy(queryBuilder, queryBuilderHandler);
      };
    }
    // Intercept client.rpc(...)
    if (prop === 'rpc') {
      return (fn: string, args?: any, options?: any) => {
        const allowedRpcs = ['check_is_master'];
        if (isReadOnlyMode && !allowedRpcs.includes(fn)) {
          return createWriteBlocker()();
        }
        return target.rpc(fn, args, options);
      };
    }
    const val = Reflect.get(target, prop, receiver);
    if (typeof val === 'function') {
      return val.bind(target);
    }
    return val;
  }
}) as typeof rawSupabase;

// @ts-nocheck
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

// ===================================================
// Serviço centralizado de transações financeiras
// TODA operação que cria/modifica/reverte transações
// DEVE usar este módulo.
// ===================================================

// ------- Tipos -------

export type TransactionOriginType =
  | "sale"
  | "sale_payment"
  | "boleto_installment"
  | "space_payment"
  | "roas"
  | "manual"
  | "purchase_installment";

export interface CreateTransactionParams {
  name: string;
  amount: number;
  type: "Entrada" | "Saida";
  transactionDate: string;
  accountId: number;
  companyId: number;
  isPaid: boolean;
  paymentMethod?: string | null;
  saleId?: number | null;
  categoryId?: number | null;
  subcategoryId?: number | null;
  description?: string | null;
  originType?: TransactionOriginType;
  originId?: number | null;
  salePaymentId?: number | null;
}

export interface CreateSaleTransactionParams {
  saleId: number;
  saleTotal: number;
  clientName: string;
  paymentMethod: string | null;
  saleDate: string;
  companyId: number;
  accountId?: number | null;
  isPaid: boolean;
  salePaymentId?: number | null;
  installments?: number;
  netAmount?: number;
  /** Sufixo descritivo, ex: "Parcela 1/3" */
  nameSuffix?: string;
  dueDate?: string;
}

export interface SettleTransactionParams {
  transactionId: number;
  paymentDate?: string;
  paidAmount?: number;
}

export interface ReverseTransactionResult {
  success: boolean;
  error?: string;
}

// ------- Helpers -------

/**
 * Busca a conta principal da empresa.
 * Retorna o ID ou a primeira conta ativa encontrada como fallback.
 */
async function getMainAccountId(companyId: number): Promise<number | null> {
  // 1. Tenta buscar a conta marcada como principal
  const { data: mainAccount, error: mainError } = await supabase
    .from("accounts")
    .select("id")
    .eq("company_id", companyId)
    .eq("is_main", true)
    .eq("is_active", true)
    .maybeSingle();

  if (mainAccount) {
    return mainAccount.id;
  }

  // 2. Fallback: se não achar a principal, pega a primeira conta ativa disponível
  const { data: fallbackAccount, error: fallbackError } = await supabase
    .from("accounts")
    .select("id")
    .eq("company_id", companyId)
    .eq("is_active", true)
    .order("id", { ascending: true })
    .limit(1)
    .maybeSingle();

  if (fallbackAccount) {
    return fallbackAccount.id;
  }

  console.error("[FinTx] Nenhuma conta ativa encontrada para a empresa", companyId);
  return null;
}

// ------- API Pública -------

/**
 * Cria uma transação financeira genérica.
 * O trigger do banco garante a atualização do saldo.
 */
export async function createTransaction(
  params: CreateTransactionParams
): Promise<{ id: number } | null> {
  const { data, error } = await supabase
    .from("transactions")
    .insert({
      name: params.name,
      amount: params.amount,
      type: params.type,
      transaction_date: params.transactionDate,
      account_id: params.accountId,
      company_id: params.companyId,
      is_paid: params.isPaid,
      payment_method: params.paymentMethod ?? null,
      sale_id: params.saleId ?? null,
      category_id: params.categoryId ?? null,
      subcategory_id: params.subcategoryId ?? null,
      description: params.description ?? null,
      origin_type: params.originType ?? null,
      origin_id: params.originId ?? null,
      sale_payment_id: params.salePaymentId ?? null,
    })
    .select("id")
    .single();

  if (error) {
    console.error("[FinTx] Error creating transaction:", error);
    toast.error("Ocorreu um erro ao criar o lançamento financeiro. Tente novamente.");
    return null;
  }

  return data;
}

/**
 * Cria a transação de uma venda.
 * - Pagamento imediato: is_paid = true → trigger credita saldo
 * - Boleto: is_paid = false → saldo inalterado, parcelas geram liquidação
 */
export async function createSaleTransaction(
  params: CreateSaleTransactionParams
): Promise<{ id: number } | null> {
  let targetAccountId = params.accountId;

  if (!targetAccountId) {
    targetAccountId = await getMainAccountId(params.companyId);
    if (!targetAccountId) return null;
  }

  const suffix = params.nameSuffix ? ` - ${params.nameSuffix}` : "";
  const description =
    params.installments && params.installments > 1
      ? `Venda em ${params.installments}x${suffix}`
      : suffix || null;

  return createTransaction({
    name: `Venda #${params.saleId} - ${params.clientName}`,
    amount: params.netAmount ?? params.saleTotal,
    type: "Entrada",
    transactionDate: params.dueDate ?? params.saleDate,
    accountId: targetAccountId,
    companyId: params.companyId,
    isPaid: params.isPaid,
    paymentMethod: params.paymentMethod,
    saleId: params.saleId,
    description,
    originType: params.salePaymentId ? "sale_payment" : "sale",
    originId: params.salePaymentId ?? params.saleId,
    salePaymentId: params.salePaymentId,
  });
}

/**
 * Cria N transações pendentes para parcelas de boleto.
 * Cada transação fica com is_paid=false e vinculada ao boleto_installment.
 */
export async function createBoletoInstallmentTransactions(params: {
  saleId: number;
  clientName: string;
  saleDate: string;
  companyId: number;
  accountId: number;
  installments: Array<{
    installmentNumber: number;
    amount: number;
    dueDate: string;
    installmentId: number; // boleto_installments.id
  }>;
}): Promise<boolean> {
  for (const inst of params.installments) {
    const txResult = await createTransaction({
      name: `Boleto #${params.saleId} - ${params.clientName} - Parcela ${inst.installmentNumber}/${params.installments.length}`,
      amount: inst.amount,
      type: "Entrada",
      transactionDate: inst.dueDate,
      accountId: params.accountId,
      companyId: params.companyId,
      isPaid: false,
      paymentMethod: "Boleto",
      saleId: params.saleId,
      description: `Parcela ${inst.installmentNumber} de ${params.installments.length}`,
      originType: "boleto_installment",
      originId: inst.installmentId,
    });

    if (!txResult) {
      console.error(
        `[FinTx] Failed to create tx for installment ${inst.installmentNumber}`
      );
      return false;
    }

    // Vincular transaction_id na parcela
    await supabase
      .from("boleto_installments")
      .update({ transaction_id: txResult.id })
      .eq("id", inst.installmentId);
  }

  return true;
}

/**
 * Liquida uma transação pendente (marca como paga).
 * O trigger do banco atualiza o saldo automaticamente.
 */
export async function settleTransaction(
  params: SettleTransactionParams
): Promise<boolean> {
  const { error } = await supabase
    .from("transactions")
    .update({
      is_paid: true,
      transaction_date: params.paymentDate ?? new Date().toISOString().split("T")[0],
      ...(params.paidAmount !== undefined ? { amount: params.paidAmount } : {}),
    })
    .eq("id", params.transactionId);

  if (error) {
    console.error("[FinTx] Error settling transaction:", error);
    return false;
  }

  return true;
}

/**
 * Reverte uma transação existente:
 * - Se é paga, marca como não-paga (trigger subtrai do saldo)
 * - Alternativa: deleta a transação (trigger de DELETE subtrai do saldo)
 * 
 * Usa update para manter histórico. Delete é mais agressivo.
 */
export async function reverseTransaction(
  transactionId: number,
  mode: "unpay" | "delete" = "unpay"
): Promise<ReverseTransactionResult> {
  if (mode === "delete") {
    const { error } = await supabase
      .from("transactions")
      .delete()
      .eq("id", transactionId);

    if (error) {
      console.error("[FinTx] Error deleting transaction:", error);
      return { success: false, error: error.message };
    }
    return { success: true };
  }

  // mode === "unpay"
  const { error } = await supabase
    .from("transactions")
    .update({ is_paid: false })
    .eq("id", transactionId);

  if (error) {
    console.error("[FinTx] Error reversing transaction:", error);
    return { success: false, error: error.message };
  }
  return { success: true };
}

/**
 * Reverte TODAS transações vinculadas a uma venda.
 * Usado ao cancelar/editar uma venda.
 * Retorna quantas transações foram revertidas.
 */
export async function reverseAllSaleTransactions(
  saleId: number,
  mode: "unpay" | "delete" = "delete"
): Promise<{ success: boolean; count: number }> {
  // Primeiro busca todas as transações da venda
  const { data: transactions, error: fetchError } = await supabase
    .from("transactions")
    .select("id, is_paid")
    .eq("sale_id", saleId);

  if (fetchError) {
    console.error("[FinTx] Error fetching sale transactions:", fetchError);
    return { success: false, count: 0 };
  }

  if (!transactions || transactions.length === 0) {
    return { success: true, count: 0 };
  }

  let reversed = 0;
  for (const tx of transactions) {
    const result = await reverseTransaction(tx.id, mode);
    if (result.success) reversed++;
  }

  return { success: reversed === transactions.length, count: reversed };
}

/**
 * Busca transação por origem (idempotência).
 * Evita duplicatas ao re-executar um fluxo.
 */
export async function findTransactionByOrigin(
  originType: TransactionOriginType,
  originId: number
): Promise<{ id: number; is_paid: boolean } | null> {
  const { data, error } = await supabase
    .from("transactions")
    .select("id, is_paid")
    .eq("origin_type", originType)
    .eq("origin_id", originId)
    .maybeSingle();

  if (error) {
    console.error("[FinTx] Error finding transaction by origin:", error);
    return null;
  }

  return data;
}

/**
 * Cria uma transação de despesa (ROAS, fornecedores, etc).
