async function saveAndUploadPDF(
  doc: jsPDF,
  filename: string,
  type: any,
  module: any,
  details: string,
  companyId?: number
): Promise<void> {
  // Download locally
  doc.save(filename);

  // Upload to Supabase Storage
  let storagePath: string | undefined;
  if (companyId) {
    const blob = doc.output('blob');
    const path = `${companyId}/${module}/${filename}`;
    const uploaded = await uploadPDFToStorage(blob, path);
    if (uploaded) {
      storagePath = uploaded;
    }
  }

  // Save metadata record
  savePDFRecord({
    filename,
    type,
    module,
    details,
    storagePath,
  });
}

export async function generateSalePDFA4(sale: SalePDFData, options: Record<string, boolean> = {}, companyId?: number): Promise<void> {
  const doc = new jsPDF('portrait', 'mm', 'a4');
  const pageWidth = doc.internal.pageSize.getWidth();
  let y = 15;

  // Header logo
  if (options.companyName !== false && sale.company_logo_url) {
    try {
      const response = await fetch(sale.company_logo_url);
      const blob = await response.blob();
      const reader = new FileReader();
      const dataUrl: string = await new Promise((resolve, reject) => {
        reader.onloadend = () => resolve(reader.result as string);
        reader.onerror = reject;
        reader.readAsDataURL(blob);
      });

      const imgFormat = blob.type.includes('jpeg') || blob.type.includes('jpg') ? 'JPEG' : 'PNG';

      const img = new Image();
      await new Promise<void>((resolve, reject) => {
        img.onload = () => resolve();
        img.onerror = reject;
        img.src = dataUrl;
      });

      const maxW = 35; // largura máxima
      const ratio = img.naturalWidth / img.naturalHeight;
      let drawW = maxW;
      let drawH = maxW / ratio;
      if (drawH > 18) { // altura máxima
        drawH = 18;
        drawW = 18 * ratio;
      }

      const logoX = (pageWidth - drawW) / 2;
      doc.addImage(dataUrl, imgFormat, logoX, y, drawW, drawH);
      y += drawH + 4;
    } catch (e) {
      console.warn('Não foi possível carregar a logo para o PDF A4:', e);
    }
  }

  // Header
  if (options.companyName !== false) {
    doc.setFontSize(18);
    doc.setFont('helvetica', 'bold');
    doc.text(sale.company_name || 'WFE EVOLUTION', pageWidth / 2, y, { align: 'center' });
    y += 8;
  }

  if (options.companyCnpj !== false && sale.company_cnpj) {
    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`CNPJ: ${sale.company_cnpj}`, pageWidth / 2, y, { align: 'center' });
    y += 6;
  }

  if (options.receiptText !== false) {
    doc.setFontSize(12);
    doc.setFont('helvetica', 'normal');
    doc.text('Comprovante de Serviço', pageWidth / 2, y, { align: 'center' });
    y += 6;
  }

  if (options.saleNumber !== false) {
    doc.setFontSize(10);
    doc.text(`Venda Nº ${sale.id} - ${formatDate(sale.date)}`, pageWidth / 2, y, { align: 'center' });
    y += 10;
  }

  doc.setLineWidth(0.5);
  doc.line(15, y, pageWidth - 15, y);
  y += 8;

  const clientLines = [];
  if (options.clientName !== false && sale.client_name) {
    clientLines.push(`Nome: ${sale.client_name}`);
  }
  if (options.clientWhatsApp !== false && sale.client_phone) {
    clientLines.push(`WhatsApp: ${sale.client_phone}`);
  }
  if (options.clientCpf !== false && sale.client_cpf) {
    clientLines.push(`CPF/CNPJ: ${sale.client_cpf}`);
  }
  if (options.clientEmail !== false && sale.client_email) {
    clientLines.push(`Email: ${sale.client_email}`);
  }

  if (clientLines.length > 0) {
    const boxHeight = 8 + (clientLines.length * 5) + 3; // header (8) + lines * 5 + padding
    doc.setFillColor(245, 245, 245);
    doc.rect(15, y - 2, pageWidth - 30, boxHeight, 'F');

    doc.setFontSize(11);
    doc.setFont('helvetica', 'bold');
    doc.text('Informações do Cliente', 20, y + 4);
    y += 9;

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10);
    clientLines.forEach(line => {
      doc.text(line, 20, y);
      y += 5;
    });
    y += 5; // spacing after the box
  }

  if (options.vehicle !== false) {
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(11);
    doc.text(`Veículo: ${sale.vehicle_brand} ${sale.vehicle_model} (${sale.vehicle_plate})`, 20, y);
    y += 10;
  }

  if (options.serviceName !== false) {
    const tableData = sale.services.map(s => {
      const row = [s.name];
      if (options.serviceDescription !== false) {
        row.push(s.description || '');
      }
      if (options.servicePrice !== false) {
        row.push(`R$ ${s.price.toFixed(2)}`);
      }
      return row;
    });

    const columns = ['Serviço'];
    if (options.serviceDescription !== false) columns.push('Descrição');
    if (options.servicePrice !== false) columns.push('Valor');

    autoTable(doc, {
      startY: y,
      head: [columns],
      body: tableData,
      theme: 'striped',
      headStyles: { fillColor: [50, 50, 50] },
      margin: { left: 15, right: 15 },
    });

    y = (doc as any).lastAutoTable.finalY + 10;
  }

  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  if (options.subtotal !== false) {
    doc.text(`Subtotal: R$ ${sale.subtotal.toFixed(2)}`, pageWidth - 60, y);
    y += 6;
  }
  if (options.discount !== false && sale.discount > 0) {
    doc.setTextColor(0, 128, 0);
    doc.text(`Desconto: - R$ ${sale.discount.toFixed(2)}`, pageWidth - 60, y);
    doc.setTextColor(0, 0, 0);
    y += 6;
  }
  if (options.total !== false) {
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(14);
    doc.text(`TOTAL: R$ ${sale.total.toFixed(2)}`, pageWidth - 60, y);
    y += 8;
  }
  if (options.paymentMethod !== false) {
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10);
    doc.text(`Forma de Pagamento: ${sale.payment_method}`, pageWidth - 60, y);
  }

  const filename = `venda-${sale.id}-A4.pdf`;
  await saveAndUploadPDF(doc, filename, 'Recibo A4', 'vendas', `Venda #${sale.id} - ${sale.client_name}`, companyId);
}

