export interface SpacePDFData {
  id: number;
  client_name: string;
  client_phone: string;
  client_email?: string;
  vehicle_brand: string;
  vehicle_model: string;
  vehicle_plate: string;
  vehicle_year?: number;
  entry_date: string;
  entry_time: string;
  exit_date: string;
  exit_time: string;
  services: Array<{ name: string; price: number; description?: string }>;
