export async function generateSpacePDFA4(space: SpacePDFData, companyId?: number): Promise<void> {
  const doc = new jsPDF('portrait', 'mm', 'a4');
  const pageWidth = doc.internal.pageSize.getWidth();
  let y = 15;

  // Header logo
  if (space.company_logo_url) {
    try {
      const response = await fetch(space.company_logo_url);
      const blob = await response.blob();
      const reader = new FileReader();
      const dataUrl: string = await new Promise((resolve, reject) => {
        reader.onloadend = () => resolve(reader.result as string);
        reader.onerror = reject;
        reader.readAsDataURL(blob);
      });

      const imgFormat = blob.type.includes('jpeg') || blob.type.includes('jpg') ? 'JPEG' : 'PNG';

      const img = new Image();
      await new Promise<void>((resolve, reject) => {
        img.onload = () => resolve();
        img.onerror = reject;
        img.src = dataUrl;
      });

      const maxW = 35; // largura máxima
      const ratio = img.naturalWidth / img.naturalHeight;
      let drawW = maxW;
      let drawH = maxW / ratio;
      if (drawH > 18) { // altura máxima
        drawH = 18;
        drawW = 18 * ratio;
      }

      const logoX = (pageWidth - drawW) / 2;
      doc.addImage(dataUrl, imgFormat, logoX, y, drawW, drawH);
      y += drawH + 4;
    } catch (e) {
      console.warn('Não foi possível carregar a logo para o PDF A4:', e);
    }
  }

  doc.setFontSize(18);
  doc.setFont('helvetica', 'bold');
  doc.text(space.company_name || 'Comprovante', pageWidth / 2, y, { align: 'center' });
  y += 8;

  if (space.company_cnpj) {
    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`CNPJ: ${space.company_cnpj}`, pageWidth / 2, y, { align: 'center' });
    y += 6;
  }

  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.text(`Data: ${space.entry_date ? formatDate(space.entry_date) : '-'}`, pageWidth / 2, y, { align: 'center' });
  y += 6;

  doc.setFontSize(12);
  doc.setFont('helvetica', 'bold');
  doc.text(`Vaga Nº ${space.id}`, pageWidth / 2, y, { align: 'center' });
  y += 10;

  doc.setLineWidth(0.5);
  doc.line(15, y, pageWidth - 15, y);
  y += 8;

  // Informações do cliente
  const clientLines = [];
  clientLines.push(`Nome: ${space.client_name}`);
  if (space.client_email) clientLines.push(`Email: ${space.client_email}`);
  clientLines.push(`WhatsApp: ${space.client_phone}`);

  const clientBoxHeight = 8 + (clientLines.length * 5) + 3;
  doc.setFillColor(245, 245, 245);
  doc.rect(15, y - 2, pageWidth - 30, clientBoxHeight, 'F');

  doc.setFontSize(11);
  doc.setFont('helvetica', 'bold');
  doc.text('Informações do Cliente', 20, y + 4);
  y += 9;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(10);
  clientLines.forEach(line => {
    doc.text(line, 20, y);
    y += 5;
  });
  y += 10;

  // Veículo
  doc.setFontSize(11);
  doc.setFont('helvetica', 'bold');
  doc.text('Dados do Veículo', 15, y);
  y += 6;
  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.text(`Marca: ${space.vehicle_brand}`, 15, y);
  y += 5;
  doc.text(`Modelo: ${space.vehicle_model}`, 15, y);
  y += 5;
  doc.text(`Placa: ${space.vehicle_plate}`, 15, y);
  y += 5;
  if (space.vehicle_year) {
    doc.text(`Ano: ${space.vehicle_year}`, 15, y);
    y += 5;
  }
  y += 8;

  // Serviços
  doc.setFontSize(11);
  doc.setFont('helvetica', 'bold');
  doc.text('Serviços Realizados', 15, y);
  y += 4;

  if (space.services.length > 0) {
    const tableData = space.services.map(s => [s.name, `R$ ${s.price.toFixed(2)}`]);
    autoTable(doc, {
      startY: y,
      head: [['Serviço', 'Valor']],
      body: tableData,
      theme: 'striped',
      headStyles: { fillColor: [50, 50, 50] },
      margin: { left: 15, right: 15 },
    });
    const finalY = (doc as any).lastAutoTable.finalY + 10;
    y = finalY;
  } else {
    y += 6;
  }

  // Valores finais
  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.text(`Subtotal: R$ ${space.subtotal.toFixed(2)}`, pageWidth - 60, y);
  y += 6;

  if (space.discount > 0) {
    doc.setTextColor(0, 128, 0);
    doc.text(`Desconto: - R$ ${space.discount.toFixed(2)}`, pageWidth - 60, y);
    doc.setTextColor(0, 0, 0);
    y += 6;
  }

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(14);
  doc.text(`TOTAL: R$ ${space.total.toFixed(2)}`, pageWidth - 60, y);
  y += 20;

  if (space.observations) {
    doc.setFontSize(11);
    doc.setFont('helvetica', 'bold');
    doc.text('Observações', 15, y);
    y += 6;

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10);
    const obsLines = doc.splitTextToSize(space.observations, pageWidth - 30);
    obsLines.forEach((line: string) => {
      doc.text(line, 15, y);
      y += 5;
    });
    y += 10;
  }

  doc.setLineWidth(0.5);
  doc.line(15, y, pageWidth - 15, y);
  y += 8;
  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.text('Obrigado pela preferência!', pageWidth / 2, y, { align: 'center' });

  const filename = `vaga-${space.id}-A4.pdf`;
  await saveAndUploadPDF(doc, filename, 'Comprovante Vaga A4', 'espaco', `Vaga #${space.id} - ${space.client_name}`, companyId);
}

export async function generateSpacePDFReceipt(space: SpacePDFData, size: '80mm' | '58mm', companyId?: number): Promise<void> {
  const width = size === '80mm' ? 80 : 58;
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: [width, 200] });
  let y = 6;
  const margin = 3;

  // Render company logo if available
  if (space.company_logo_url) {
    try {
      const response = await fetch(space.company_logo_url);
      const blob = await response.blob();
      const reader = new FileReader();
      const dataUrl: string = await new Promise((resolve, reject) => {
        reader.onloadend = () => resolve(reader.result as string);
        reader.onerror = reject;
        reader.readAsDataURL(blob);
      });

      const imgFormat = blob.type.includes('jpeg') || blob.type.includes('jpg') ? 'JPEG' : 'PNG';
      const img = new Image();
      await new Promise<void>((resolve, reject) => {
        img.onload = () => resolve();
        img.onerror = reject;
        img.src = dataUrl;
      });

      const maxW = size === '80mm' ? 20 : 15;
      const ratio = img.naturalWidth / img.naturalHeight;
      let drawW = maxW;
      let drawH = maxW / ratio;
      if (drawH > maxW) {
        drawH = maxW;
        drawW = maxW * ratio;
      }

      const logoX = (width - drawW) / 2;
      doc.addImage(dataUrl, imgFormat, logoX, y, drawW, drawH);
      y += drawH + 3;
    } catch (e) {
      console.warn('Não foi possível carregar a logo para a notinha:', e);
    }
  }

  doc.setFontSize(size === '80mm' ? 12 : 10);
  doc.setFont('helvetica', 'bold');
  doc.text(space.company_name || 'Comprovante', width / 2, y, { align: 'center' });
  y += 6;

  if (space.company_cnpj) {
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(7.5);
    doc.text(`CNPJ: ${space.company_cnpj}`, width / 2, y, { align: 'center' });
    y += 4;
  }

  doc.setFontSize(8);
  doc.setFont('helvetica', 'normal');
  doc.text(`Data: ${space.entry_date ? formatDate(space.entry_date) : '-'}`, width / 2, y, { align: 'center' });
  y += 5;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(10);
  doc.text(`Vaga Nº ${space.id}`, width / 2, y, { align: 'center' });
  y += 6;

  doc.setLineDashPattern([1, 1], 0);
  doc.line(margin, y, width - margin, y);
  y += 4;

  // Informações do cliente
  doc.setFontSize(7.5);
  doc.setFont('helvetica', 'bold');
  doc.text('Informações do cliente', width / 2, y, { align: 'center' });
  y += 4;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(8);
  doc.text(`Nome: ${space.client_name}`, margin, y);
  y += 3.5;
  if (space.client_email) {
    doc.text(`Email: ${space.client_email}`, margin, y);
    y += 3.5;
  }
  doc.text(`Tel: ${space.client_phone}`, margin, y);
  y += 4;

  // Dados do veículo
  doc.setFontSize(7.5);
  doc.setFont('helvetica', 'bold');
  doc.text('Dados do veículo', width / 2, y, { align: 'center' });
  y += 4;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(8);
  doc.text(`Marca: ${space.vehicle_brand}`, margin, y);
  y += 3.5;
  doc.text(`Modelo: ${space.vehicle_model}`, margin, y);
  y += 3.5;
  doc.text(`Placa: ${space.vehicle_plate}`, margin, y);
  y += 3.5;
  if (space.vehicle_year) {
    doc.text(`Ano: ${space.vehicle_year}`, margin, y);
    y += 3.5;
  }
  y += 1;

  // Serviços realizados
  doc.setFontSize(7.5);
  doc.setFont('helvetica', 'bold');
  doc.text('Serviços realizados', width / 2, y, { align: 'center' });
  y += 4;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(8);
  space.services.forEach((s, i) => {
    const numStr = (i + 1).toString().padStart(2, '0');
    // Multiline handling for service name
    const lines = doc.splitTextToSize(`${numStr} - ${s.name}`, width - margin * 2 - 15);
    lines.forEach((line: string, idx: number) => {
      doc.text(line, margin, y);
      if (idx === 0) {
        doc.text(`R$ ${s.price.toFixed(2)}`, width - margin, y, { align: 'right' });
      }
      y += 3.5;
    });
  });

  y += 1;
  doc.text(`Total de serviços: R$ ${space.subtotal.toFixed(2)}`, width - margin, y, { align: 'right' });
  y += 5;

  // Valores finais
  doc.setFontSize(7.5);
  doc.setFont('helvetica', 'bold');
  doc.text('Valores finais', width / 2, y, { align: 'center' });
  y += 4;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(8);
  doc.text('Subtotal', margin, y);
  doc.text(`R$ ${space.subtotal.toFixed(2)}`, width - margin, y, { align: 'right' });
  y += 3.5;

  if (space.discount > 0) {
    doc.text('Desconto', margin, y);
    doc.text(`- R$ ${space.discount.toFixed(2)}`, width - margin, y, { align: 'right' });
    y += 3.5;
  }

  doc.setFont('helvetica', 'bold');
  doc.text('Total', margin, y);
  doc.text(`R$ ${space.total.toFixed(2)}`, width - margin, y, { align: 'right' });
  y += 6;

  if (space.observations) {
    doc.setFontSize(7.5);
    doc.setFont('helvetica', 'bold');
    doc.text('Observações', width / 2, y, { align: 'center' });
    y += 4;

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    const obsLines = doc.splitTextToSize(space.observations, width - margin * 2);
    obsLines.forEach((line: string) => {
      doc.text(line, margin, y);
      y += 3.5;
    });
    y += 2;
  }

  doc.setLineDashPattern([1, 1], 0);
  doc.line(margin, y, width - margin, y);
  y += 4;
  doc.setFontSize(7.5);
  doc.setFont('helvetica', 'normal');
  doc.text('Obrigado pela preferência!', width / 2, y, { align: 'center' });

  const filename = `vaga-${space.id}-${size}.pdf`;
  await saveAndUploadPDF(doc, filename, size === '80mm' ? 'Comprovante Vaga 80mm' : 'Comprovante Vaga 58mm', 'espaco', `Vaga #${space.id} - ${space.client_name}`, companyId);
}

