import { openWhatsApp } from "@/lib/utils";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { toast } from "sonner";

interface Vehicle {
  id: number;
  brand: string;
  model: string;
  year: number | null;
  plate: string | null;
  size: string | null;
}

interface Client {
  id: number;
  name: string;
  phone: string;
  email: string | null;
  cpf_cnpj: string | null;
  origem: string | null;
  created_at: string | null;
  vehicles: Vehicle[];
  total_spent: number;
  sales_count: number;
  last_sale_date: string | null;
  status: 'Ativo' | 'Inativo';
  tier: 'VIP' | 'Comum' | 'Sem Compras';
}

type SortOption = 'name-asc' | 'name-desc' | 'recent' | 'spent';

export default function Clientes() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [clients, setClients] = useState<Client[]>([]);
  const [sales, setSales] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchParams] = useSearchParams();
  const searchParamValue = searchParams.get("search") || "";
  const [searchTerm, setSearchTerm] = useState(searchParamValue);

  useEffect(() => {
    if (searchParamValue) {
      setSearchTerm(searchParamValue);
    }
  }, [searchParamValue]);
  const [filterOrigem, setFilterOrigem] = useState<string>("todas");
  const [filterStatus, setFilterStatus] = useState<string>("todos");
  const [filterTier, setFilterTier] = useState<string>("todos");
  const [sortBy, setSortBy] = useState<SortOption>('name-asc');
  const [showNewClientModal, setShowNewClientModal] = useState(false);
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [clientToDelete, setClientToDelete] = useState<Client | null>(null);
  const [showNewSaleModal, setShowNewSaleModal] = useState(false);
  const [showNewSlotModal, setShowNewSlotModal] = useState(false);

  const fetchClients = async () => {
    if (!user?.id) return;

    try {
      const { data: profile } = await supabase
        .from("profiles")
        .select("company_id")
        .eq("user_id", user.id)
        .single();

      if (!profile?.company_id) {
        setLoading(false);
        return;
      }

      // Fetch clients
      const { data: clientsData, error: clientsError } = await supabase
        .from("clients")
        .select("*")
        .eq("company_id", profile.company_id)
        .order("name");

      if (clientsError) throw clientsError;

      // Fetch vehicles for all clients
      const { data: vehiclesData } = await supabase
        .from("vehicles")
        .select("*")
        .eq("company_id", profile.company_id);

      // Fetch sales to calculate stats
      const { data: salesData } = await supabase
        .from("sales")
        .select("client_id, total, created_at")
        .eq("company_id", profile.company_id)
        .order("created_at", { ascending: false });

      setSales(salesData || []);

      // Map clients with vehicles and stats
      const clientsWithData = (clientsData || []).map((client) => {
        const clientVehicles = (vehiclesData || []).filter(v => v.client_id === client.id);
        const clientSales = (salesData || []).filter(s => s.client_id === client.id);
        const totalSpent = clientSales.reduce((sum, s) => sum + (s.total || 0), 0);
        const lastSaleDate = clientSales.length > 0 ? clientSales[0].created_at : null;

        // Calculate Status
        let status: 'Ativo' | 'Inativo' = 'Inativo';
        if (lastSaleDate) {
          const sixMonthsAgo = new Date();
          sixMonthsAgo.setMonth(sixMonthsAgo.getMonth() - 6);
          if (new Date(lastSaleDate) > sixMonthsAgo) {
            status = 'Ativo';
          }
        } else if (client.created_at) {
          const threeMonthsAgo = new Date();
          threeMonthsAgo.setMonth(threeMonthsAgo.getMonth() - 3);
          if (new Date(client.created_at) > threeMonthsAgo) {
            status = 'Ativo'; // New clients are active for a while
          }
        }

        // Calculate Tier
        let tier: 'VIP' | 'Comum' | 'Sem Compras' = 'Sem Compras';

        if (totalSpent >= 3000 || clientSales.length >= 3) {
          tier = 'VIP';
        } else if (clientSales.length > 0) {
          tier = 'Comum';
        }

        return {
          ...client,
          vehicles: clientVehicles,
          total_spent: totalSpent,
          sales_count: clientSales.length,
          last_sale_date: lastSaleDate,
          status,
          tier
        };
      });

      setClients(clientsWithData);
    } catch (error) {
      console.error("Error fetching clients:", error);
      toast.error("Erro ao carregar clientes");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchClients();
  }, [user?.id]);

  const filteredAndSortedClients = useMemo(() => {
    let result = [...clients];

    // Filter
    if (searchTerm) {
      const term = searchTerm.toLowerCase();
      result = result.filter(client =>
        client.name.toLowerCase().includes(term) ||
        client.phone.includes(term) ||
        client.vehicles.some(v =>
          v.model.toLowerCase().includes(term) ||
          (v.plate?.toLowerCase() || "").includes(term)
        )
      );
    }

    if (filterOrigem && filterOrigem !== "todas") {
      result = result.filter(client => client.origem === filterOrigem);
    }
    if (filterStatus && filterStatus !== "todos") {
      result = result.filter(client => client.status.toLowerCase() === filterStatus.toLowerCase());
    }
    if (filterTier && filterTier !== "todos") {
      result = result.filter(client => client.tier.toLowerCase() === filterTier.toLowerCase());
    }

    // Sort
    switch (sortBy) {
      case 'name-asc':
        result.sort((a, b) => a.name.localeCompare(b.name));
        break;
      case 'name-desc':
        result.sort((a, b) => b.name.localeCompare(a.name));
        break;
      case 'recent':
        result.sort((a, b) => new Date(b.created_at || 0).getTime() - new Date(a.created_at || 0).getTime());
        break;
      case 'spent':
        result.sort((a, b) => b.total_spent - a.total_spent);
        break;
    }

    return result;
  }, [clients, searchTerm, sortBy]);

  const handleViewProfile = (client: Client) => {
    setSelectedClient(client);
    setShowProfileModal(true);
  };

  const handleEditClient = (client: Client) => {
    setSelectedClient(client);
    setShowEditModal(true);
  };

  const handleDeleteClient = (client: Client) => {
    setClientToDelete(client);
  };

  const confirmDelete = async () => {
    if (!clientToDelete) return;

    // Check if client has sales
    if (clientToDelete.sales_count > 0) {
      toast.error("Cliente possui vendas vinculadas. Não pode ser excluído.");
      setClientToDelete(null);
      return;
    }

    try {
      const vehicleIds = (clientToDelete.vehicles || []).map(v => v.id);

      // 1. Delete pipeline items and events associated with the client's vehicles
      if (vehicleIds.length > 0) {
        const { data: pipelineItems } = await supabase
          .from("pipeline_items")
          .select("id")
          .in("vehicle_id", vehicleIds);

        const pipelineItemIds = pipelineItems?.map(item => item.id) || [];
        if (pipelineItemIds.length > 0) {
          await supabase.from("whatsapp_messages").delete().in("related_pipeline_item", pipelineItemIds);
          await supabase.from("pipeline_events").delete().in("item_id", pipelineItemIds);
          await supabase.from("pipeline_items").delete().in("id", pipelineItemIds);
        }

        // Delete other operational data associated with the vehicles
        await supabase.from("pipeline_stages").delete().in("vehicle_id", vehicleIds);
        await supabase.from("spaces").delete().in("vehicle_id", vehicleIds);
        await supabase.from("warranties").delete().in("vehicle_id", vehicleIds);
      }

      // 2. Delete pipeline items and events associated directly with the client
      const { data: clientPipelineItems } = await supabase
        .from("pipeline_items")
        .select("id")
        .eq("client_id", clientToDelete.id);

      const clientPipelineItemIds = clientPipelineItems?.map(item => item.id) || [];
      if (clientPipelineItemIds.length > 0) {
        await supabase.from("whatsapp_messages").delete().in("related_pipeline_item", clientPipelineItemIds);
        await supabase.from("pipeline_events").delete().in("item_id", clientPipelineItemIds);
        await supabase.from("pipeline_items").delete().in("id", clientPipelineItemIds);
      }

      // 3. Delete other operational data associated directly with the client_id
      await supabase.from("pipeline_stages").delete().eq("client_id", clientToDelete.id);
      await supabase.from("spaces").delete().eq("client_id", clientToDelete.id);
      await supabase.from("warranties").delete().eq("client_id", clientToDelete.id);

      // 4. Delete associated vehicles
      const { error: vehiclesError } = await supabase
        .from("vehicles")
        .delete()
        .eq("client_id", clientToDelete.id);

      if (vehiclesError) throw vehiclesError;

      // 5. Delete the client
      const { error } = await supabase
        .from("clients")
        .delete()
        .eq("id", clientToDelete.id);

      if (error) throw error;

      toast.success(`Cliente "${clientToDelete.name}" excluído com sucesso`);
      fetchClients();
    } catch (error: any) {
      console.error("Error deleting client:", error);
      toast.error(`Erro ao excluir cliente: ${error?.message || "Erro desconhecido"}`);
    } finally {
      setClientToDelete(null);
    }
  };


  const getSortLabel = () => {
    switch (sortBy) {
      case 'name-asc': return 'A-Z';
      case 'name-desc': return 'Z-A';
      case 'recent': return 'Mais Recentes';
      case 'spent': return 'Maior Gasto';
    }
  };

  const totalClients = filteredAndSortedClients.length;
  const activeClients = filteredAndSortedClients.filter(c => c.status === 'Ativo').length;
  const vipClients = filteredAndSortedClients.filter(c => c.tier === 'VIP').length;
  const totalRevenue = filteredAndSortedClients.reduce((sum, c) => sum + c.total_spent, 0);

  if (loading) {
    return (
      <div className="space-y-6">
        <Skeleton className="h-10 w-48" />
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <Skeleton className="h-24 w-full" />
          <Skeleton className="h-24 w-full" />
          <Skeleton className="h-24 w-full" />
          <Skeleton className="h-24 w-full" />
        </div>
        <Skeleton className="h-96 w-full" />
      </div>
    );
  }

  return (
    <div className="space-y-6 max-w-[100vw]">
      <HelpOverlay
        tabId="clientes"
        title="Guia de Clientes"
        sections={[
          {
            title: "Vídeo Aula — Clientes",
            description: "Assista ao vídeo tutorial completo para aprender a usar todas as funcionalidades da gestão de clientes.",
            videoUrl: "/help/video-aula-clientes.mp4"
          },
          {
            title: "Cadastrar Novo Cliente",
            description: "Clique em 'Novo cliente' para abrir o formulário. Preencha nome, WhatsApp, e-mail e CPF/CNPJ. O cliente ficará disponível para associar a vendas e veículos.",
            screenshotUrl: "/help/help-clientes-novo.png"
          },
          {
            title: "Buscar e Filtrar",
            description: "Use a barra de pesquisa para buscar clientes por nome, número de WhatsApp, modelo do veículo ou placa. Use o botão de ordenação para classificar por nome (A-Z / Z-A), mais recentes ou maior gasto.",
            screenshotUrl: "/help/help-clientes-busca.png"
          },
          {
            title: "Ações do Cliente",
            description: "Clique no menu '⋮' de cada cliente para: Ver Perfil (histórico completo), Editar (alterar dados), Excluir (remover cliente sem vendas), ou enviar mensagem via WhatsApp.",
            screenshotUrl: "/help/help-clientes-acoes.png"
          },
          {
            title: "Perfil Completo",
            description: "No perfil do cliente você encontra todos os veículos cadastrados, histórico de vendas, total gasto e dados de contato. Use essa visão para entender o relacionamento com cada cliente.",
            screenshotUrl: "/help/help-clientes-perfil.png"
          },
        ]}
      />

      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-light text-foreground">Clientes</h1>
          <p className="text-sm text-muted-foreground">
            {clients.length} clientes cadastrados
          </p>
        </div>
        <div className="flex items-center gap-2">
          <Button
            onClick={() => setShowNewClientModal(true)}
            className="bg-primary text-primary-foreground hover:bg-primary/90"
          >
            <Plus className="h-4 w-4 mr-2" />
            Novo cliente
          </Button>
        </div>
      </div>

      <Tabs defaultValue="lista" className="space-y-6">
        <TabsList>
          <TabsTrigger value="lista">Lista de Clientes</TabsTrigger>
          <TabsTrigger value="graficos">Visão Geral (Gráficos)</TabsTrigger>
        </TabsList>

        <TabsContent value="lista" className="space-y-6">
          {/* KPI Cards */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <Card className="bg-card/50 border-border/50">
              <CardContent className="p-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 rounded-lg bg-primary/10">
                    <Users className="h-5 w-5 text-primary" />
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Total</p>
                    <p className="text-2xl font-bold">{totalClients}</p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card className="bg-card/50 border-border/50">
              <CardContent className="p-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 rounded-lg bg-green-500/10">
                    <CheckCircle className="h-5 w-5 text-green-500" />
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Ativos</p>
                    <p className="text-2xl font-bold text-green-500">{activeClients}</p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card className="bg-card/50 border-border/50">
              <CardContent className="p-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 rounded-lg bg-amber-500/10">
                    <Crown className="h-5 w-5 text-amber-500" />
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">VIP</p>
                    <p className="text-2xl font-bold text-amber-500">{vipClients}</p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card className="bg-card/50 border-border/50">
              <CardContent className="p-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 rounded-lg bg-emerald-500/10">
                    <DollarSign className="h-5 w-5 text-emerald-500" />
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Receita Total</p>
                    <p className="text-xl font-bold text-emerald-500">
                      R$ {totalRevenue.toLocaleString("pt-BR", { minimumFractionDigits: 0, maximumFractionDigits: 0 })}
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Toolbar */}
          <div className="flex flex-col sm:flex-row gap-3">
            <div className="relative flex-1 min-w-[200px]">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder="Buscar por nome, whatsapp ou placa..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10 bg-card border-border h-10"
              />
            </div>

            <div className="flex overflow-x-auto gap-2 pb-2 sm:pb-0 hide-scrollbar">
              {/* Origin Filter */}
              <div className="w-[140px] flex-shrink-0">
                <Select value={filterOrigem} onValueChange={setFilterOrigem}>
                  <SelectTrigger className="bg-card border-border">
                    <SelectValue placeholder="Origem" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="todas">Origens (Todas)</SelectItem>
                    {Array.from(new Set(clients.map(c => c.origem).filter(Boolean))).sort().map(origem => (
                      <SelectItem key={origem} value={origem as string}>{origem}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              {/* Status Filter */}
              <div className="w-[130px] flex-shrink-0">
                <Select value={filterStatus} onValueChange={setFilterStatus}>
                  <SelectTrigger className="bg-card border-border">
                    <SelectValue placeholder="Status" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="todos">Status (Todos)</SelectItem>
                    <SelectItem value="ativo">Ativos</SelectItem>
                    <SelectItem value="inativo">Inativos</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="outline" className="border-border h-10 flex-shrink-0">
                    <ArrowUpDown className="h-4 w-4 sm:mr-2" />
                    <span className="hidden sm:inline">{getSortLabel()}</span>
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="bg-card border-border">
                  <DropdownMenuItem onClick={() => setSortBy('name-asc')}>
                    Nome A-Z
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setSortBy('name-desc')}>
                    Nome Z-A
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setSortBy('recent')}>
                    Mais Recentes
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => setSortBy('spent')}>
                    Maior Gasto
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          </div>

          {/* Empty State or Table */}
          {clients.length === 0 ? (
            <div className="rounded-xl border border-border bg-card p-12 text-center">
              <Users className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
              <h3 className="text-lg font-medium mb-2">Nenhum cliente cadastrado</h3>
              <p className="text-muted-foreground mb-4">
                Comece cadastrando seu primeiro cliente
              </p>
              <Button onClick={() => setShowNewClientModal(true)}>
                <Plus className="h-4 w-4 mr-2" /> Cadastrar Primeiro Cliente
              </Button>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {filteredAndSortedClients.map((client) => (
                <ClientCard
                  key={client.id}
                  client={client}
                  onViewProfile={handleViewProfile}
                  onEdit={handleEditClient}
                  onDelete={handleDeleteClient}
                  onWhatsApp={(phone) => window.open(openWhatsApp(phone), "_blank")}
                />
              ))}
              {filteredAndSortedClients.length === 0 && clients.length > 0 && (
                <div className="col-span-full p-8 text-center text-muted-foreground rounded-xl border border-border bg-card">
                  Nenhum cliente encontrado com os filtros atuais.
                </div>
              )}
            </div>
          )}

          {/* Pagination info */}
          {clients.length > 0 && (
            <div className="flex justify-between items-center text-sm text-muted-foreground">
              <span>Exibindo resultados de 1 a {filteredAndSortedClients.length}</span>
            </div>
          )}
        </TabsContent>

        <TabsContent value="graficos" className="space-y-6">
          <ClientChartsTab clients={clients} sales={sales} />
        </TabsContent>
      </Tabs>

      {/* Modals */}
      <NewClientModal
        open={showNewClientModal}
        onOpenChange={setShowNewClientModal}
        onClientCreated={() => {
          setShowNewClientModal(false);
          fetchClients();
          toast.success("Cliente criado com sucesso!");
        }}
      />

      {selectedClient && (
        <>
          <ClientProfileModal
            open={showProfileModal}
            onOpenChange={setShowProfileModal}
            client={selectedClient as any}
            onEdit={() => {
              setShowProfileModal(false);
              setShowEditModal(true);
            }}
            onCreateSale={() => {
              setShowProfileModal(false);
              setShowNewSaleModal(true);
            }}
            onAddToSpace={() => {
              setShowProfileModal(false);
              setShowNewSlotModal(true);
            }}
            onDelete={(client) => {
              setShowProfileModal(false);
              handleDeleteClient(client as any);
            }}
          />

          <EditClientModal
            open={showEditModal}
            onOpenChange={setShowEditModal}
            client={selectedClient as any}
            onSave={() => {
              setShowEditModal(false);
              fetchClients();
              toast.success("Cliente atualizado com sucesso!");
            }}
          />
        </>
      )}

      {/* New Sale Modal */}
      <NewSaleModal
        open={showNewSaleModal}
        onOpenChange={(open) => {
          setShowNewSaleModal(open);
          if (!open) fetchClients();
        }}
        defaultClientId={selectedClient?.id}
      />

      {/* New Slot Modal */}
      <FillSlotModal
        open={showNewSlotModal}
        onOpenChange={setShowNewSlotModal}
        defaultClientId={selectedClient?.id}
      />

      {/* Delete Confirmation */}
      <AlertDialog open={!!clientToDelete} onOpenChange={() => setClientToDelete(null)}>
        <AlertDialogContent className="bg-card border-border">
          <AlertDialogHeader>
            <AlertDialogTitle>Confirmar exclusão</AlertDialogTitle>
            <AlertDialogDescription>
              Tem certeza que deseja excluir o cliente "{clientToDelete?.name}"?
              Esta ação não pode ser desfeita.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel className="border-border">Cancelar</AlertDialogCancel>
            <AlertDialogAction
              onClick={confirmDelete}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              Excluir
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

// @ts-nocheck
import { useState, useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import { Plus, Percent } from "lucide-react";
import { Button } from "@/components/ui/button";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { usePlanGate } from "@/hooks/usePlanGate";
import { useNavigate } from "react-router-dom";
import CommissionPeopleSection from "@/components/comissoes/CommissionPeopleSection";
import CommissionPersonModal from "@/components/comissoes/CommissionPersonModal";
import { CommissionPersonWithMetrics } from "@/components/comissoes/CommissionPersonCard";
import CommissionDetailDrawer from "@/components/comissoes/CommissionDetailDrawer";
import { HelpOverlay } from "@/components/help/HelpOverlay";
import { toast } from "sonner";

export default function Comissoes() {
  const { user } = useAuth();
  const gate = usePlanGate('comissoes');
  const navigate = useNavigate();

  useEffect(() => {
    if (!gate.hasAccess) {
      if (gate.message) toast.error(gate.message);
      if (gate.redirectTo) navigate(gate.redirectTo, { replace: true });
    }
  }, [gate.hasAccess, gate.redirectTo, gate.message, navigate]);
  const [showPersonModal, setShowPersonModal] = useState(false);
  const [showDetailDrawer, setShowDetailDrawer] = useState(false);
  const [selectedPerson, setSelectedPerson] = useState<CommissionPersonWithMetrics | null>(null);
  const [detailPerson, setDetailPerson] = useState<CommissionPersonWithMetrics | null>(null);

  const { data: companyId } = useQuery({
    queryKey: ['companyId'],
    queryFn: async () => {
      const { data } = await supabase
        .from('profiles')
        .select('company_id')
        .eq('user_id', user?.id || '')
        .single();
      return data?.company_id;
    },
    enabled: !!user?.id
  });

  const { data: people = [], refetch } = useQuery({
    queryKey: ['commission_people_with_metrics', companyId],
    queryFn: async () => {
      // 1. Fetch people
      const { data: peopleData, error: peopleError } = await supabase
        .from('commission_people')
        .select('*')
        .eq('company_id', companyId)
        .order('name');

      if (peopleError) throw peopleError;

      // 2. Fetch metrics
      const { data: commissionsData, error: commError } = await supabase
        .from('sale_commissions')
        .select('commission_person_id, commission_amount')
        .eq('company_id', companyId);

      if (commError) throw commError;

      // 3. Aggregate
      const metricsMap = new Map<number, { total_sales: number, total_commission: number }>();

      commissionsData?.forEach(comm => {
        const current = metricsMap.get(comm.commission_person_id) || { total_sales: 0, total_commission: 0 };
        current.total_sales += 1;
        current.total_commission += Number(comm.commission_amount);
        metricsMap.set(comm.commission_person_id, current);
      });

      return (peopleData || []).map(p => ({
        ...p,
        total_sales: metricsMap.get(p.id)?.total_sales || 0,
        total_commission: metricsMap.get(p.id)?.total_commission || 0,
      })) as CommissionPersonWithMetrics[];
    },
    enabled: !!companyId
  });

  const sellers = people.filter(p => p.type === 'VENDEDOR');
  const instInsulfilm = people.filter(p => p.type === 'INSTALADOR_INSULFILM');
  const instPpf = people.filter(p => p.type === 'INSTALADOR_PPF');

  const handleAdd = () => {
    setSelectedPerson(null);
    setShowPersonModal(true);
  };

  const handleEdit = (person: CommissionPersonWithMetrics) => {
    setSelectedPerson(person);
    setShowPersonModal(true);
  };

  const handleViewDetail = (person: CommissionPersonWithMetrics) => {
    setDetailPerson(person);
    setShowDetailDrawer(true);
  };

  const handleToggleStatus = async (person: CommissionPersonWithMetrics, checked: boolean) => {
    try {
      const { error } = await supabase
        .from('commission_people')
        .update({ is_active: checked, updated_at: new Date().toISOString() })
        .eq('id', person.id);

      if (error) throw error;

      toast.success(`${person.name} foi ${checked ? 'ativado' : 'inativado'} com sucesso!`);
      refetch();
    } catch (err) {
      console.error('Erro ao atualizar status:', err);
      toast.error('Erro ao atualizar status do comissionado.');
    }
  };

  if (!gate.hasAccess) return null;

  return (
    <div className="space-y-6 p-6 pb-20 max-w-[100vw] overflow-x-hidden">
      <HelpOverlay
        tabId="comissoes"
        title="Guia de Comissões"
        sections={[
          {
            title: "Vídeo Aula — Comissões",
            description: "Assista ao vídeo tutorial para entender como gerenciar vendedores, instaladores e pagamentos.",
            videoUrl: "/help/video-aula-comissoes.mp4"
          },
          {
            title: "Gestão de Comissionados",
            description: "Adicione pessoas para receber comissões, configure suas taxas e visualize métricas e relatórios diretamente no card de cada um.",
            screenshotUrl: "/help/help-comissoes.png"
          }
        ]}
      />
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <Percent className="h-6 w-6 text-primary" />
            Comissões
          </h1>
          <p className="text-muted-foreground">
            Gestão de comissionados e acompanhamento de ganhos
          </p>
        </div>
        <Button onClick={handleAdd} className="gap-2">
          <Plus className="h-4 w-4" />
          Novo Comissionado
        </Button>
      </div>

      <div className="space-y-8">
        <CommissionPeopleSection
          type="VENDEDOR"
          people={sellers}
          onAdd={handleAdd}
          onEdit={handleEdit}
          onViewDetail={handleViewDetail}
          onToggleStatus={handleToggleStatus}
        />
        <CommissionPeopleSection
          type="INSTALADOR_INSULFILM"
          people={instInsulfilm}
          onAdd={handleAdd}
          onEdit={handleEdit}
          onViewDetail={handleViewDetail}
          onToggleStatus={handleToggleStatus}
        />
        <CommissionPeopleSection
          type="INSTALADOR_PPF"
          people={instPpf}
          onAdd={handleAdd}
          onEdit={handleEdit}
          onViewDetail={handleViewDetail}
          onToggleStatus={handleToggleStatus}
        />
      </div>

      <CommissionPersonModal
        open={showPersonModal}
        onOpenChange={setShowPersonModal}
        person={selectedPerson}
        onSuccess={refetch}
      />

      <CommissionDetailDrawer
        open={showDetailDrawer}
        onOpenChange={setShowDetailDrawer}
        person={detailPerson}
      />
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/integrations/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { useToast } from '@/hooks/use-toast';
import { Loader2, Users, Send, Clock, Building2, ArrowLeft, LogOut, RefreshCw } from 'lucide-react';

export default function CompanyJoin() {
  const { user, refreshUser, signOut } = useAuth();
  const navigate = useNavigate();
  const { toast } = useToast();

  const [companyCode, setCompanyCode] = useState('');
  const [selectedRole, setSelectedRole] = useState<'FUNCIONARIO' | 'PRODUCAO'>('FUNCIONARIO');
  const [isLoading, setIsLoading] = useState(false);
  const [isCheckingRequest, setIsCheckingRequest] = useState(true);
  const [requestSent, setRequestSent] = useState(false);
  const [foundCompany, setFoundCompany] = useState<{ id: number; company_name: string } | null>(null);
  const [pendingRequest, setPendingRequest] = useState<any>(null);
  const [isSearchingCode, setIsSearchingCode] = useState(false);
  const [searchError, setSearchError] = useState<string | null>(null);

  useEffect(() => {
    // Redirect if user already has company
    if (user?.companyId) {
      navigate('/');
      return;
    }
    // Check for existing pending request
    checkExistingRequest();
  }, [user, navigate]);

  // Supabase Realtime subscription for approval updates
  useEffect(() => {
    if (!user?.id) return;

    const channel = supabase
      .channel('join-request-updates')
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'company_join_requests',
          filter: `requester_user_id=eq.${user.id}`,
        },
        async (payload) => {
          const newStatus = (payload.new as any).status;
          if (newStatus === 'approved') {
            toast({
              title: 'Solicitação aprovada!',
              description: 'Você foi aceito na empresa. Redirecionando...',
            });
            // Wait a moment then refresh
            setTimeout(async () => {
              await refreshUser();
              navigate('/');
            }, 1500);
          } else if (newStatus === 'rejected') {
            toast({
              title: 'Solicitação rejeitada',
              description: (payload.new as any).rejected_reason || 'Sua solicitação foi rejeitada.',
              variant: 'destructive',
            });
            setPendingRequest(null);
            setRequestSent(false);
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user?.id, refreshUser, navigate, toast]);

  const checkExistingRequest = async () => {
    if (!user) return;

    setIsCheckingRequest(true);
    try {
      const { data, error } = await supabase
        .from('company_join_requests')
        .select(`
          *,
          companies:company_id (company_name)
        `)
        .eq('requester_user_id', user.id)
        .eq('status', 'pending')
        .maybeSingle();

      if (!error && data) {
        setPendingRequest(data);
      }
    } catch (error) {
      console.error('Error checking existing request:', error);
    } finally {
      setIsCheckingRequest(false);
    }
  };

  const handleCodeChange = async (value: string) => {
    const code = value.toUpperCase().replace(/[^A-Z0-9]/g, '').slice(0, 6);
    setCompanyCode(code);
    setFoundCompany(null);
    setSearchError(null);

    if (code.length === 6) {
      setIsSearchingCode(true);
      try {
        // Search for company by code
        const { data, error } = await supabase
          .rpc('get_company_by_code', { code_input: code });

        if (error) {
          setSearchError(error.message);
          return;
        }

        if (data && data.length > 0) {
          setFoundCompany({ id: data[0].id, company_name: data[0].company_name });
        } else {
          setSearchError("Código de empresa não localizado.");
        }
      } catch (err: any) {
        setSearchError(err.message || 'Erro de comunicação');
      } finally {
        setIsSearchingCode(false);
      }
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user || !foundCompany) return;

    setIsLoading(true);

    try {
      // Check if request already exists
      const { data: existingRequests, error: existingError } = await supabase
        .from('company_join_requests')
        .select('id, status')
        .eq('requester_user_id', user.id)
        .eq('company_id', foundCompany.id)
        .order('created_at', { ascending: false })
        .limit(1);

      if (existingError) throw existingError;

      const existingRequest = existingRequests?.[0];

      if (existingRequest) {
        if (existingRequest.status === 'pending') {
          toast({
            title: 'Solicitação já existe',
            description: 'Você já possui uma solicitação pendente para esta empresa.',
            variant: 'destructive',
          });
          setIsLoading(false);
          return;
        }

        // If it was rejected or approved (but they were unlinked), they can try again.
        // We will just update the existing request back to pending.
        const { error: updateError } = await supabase
          .from('company_join_requests')
          .update({
            status: 'pending',
            requested_role: selectedRole,
            rejected_reason: null,
            updated_at: new Date().toISOString()
          })
          .eq('id', existingRequest.id);

        if (updateError) throw updateError;
      } else {
        // Create join request
        const { error } = await supabase
          .from('company_join_requests')
          .insert({
            company_id: foundCompany.id,
            requester_user_id: user.id,
            requester_name: user.profile?.name || user.email,
            requester_email: user.email,
            requested_role: selectedRole,
            status: 'pending',
          });

        if (error) throw error;
      }

      setRequestSent(true);
      toast({
        title: 'Solicitação enviada!',
        description: 'O administrador da empresa será notificado.',
      });

    } catch (error: any) {
      console.error('Error creating join request:', error);
      const friendlyError = error?.message?.includes('new row violates row-level security policy')
        ? 'Você já possui uma solicitação ou não tem permissão para esta empresa.'
        : error.message || 'Tente novamente';
      toast({
        title: 'Erro ao enviar solicitação',
        description: friendlyError,
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleCancelRequest = async () => {
    if (!pendingRequest) return;

    try {
      await supabase
        .from('company_join_requests')
        .delete()
        .eq('id', pendingRequest.id);

      setPendingRequest(null);
      setRequestSent(false);
      toast({
        title: 'Solicitação cancelada',
      });
    } catch (error) {
      console.error('Error canceling request:', error);
    }
  };

  const handleBackToLogin = async () => {
    await signOut();
    navigate('/login');
  };

  if (isCheckingRequest) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  // Show pending request screen
  if (pendingRequest || requestSent) {
    const companyName = pendingRequest?.companies?.company_name || foundCompany?.company_name;

    return (
      <div className="min-h-screen bg-gradient-to-br from-background via-background to-muted/30 py-8 px-4">
        <div className="max-w-md mx-auto">
          <Card>
            <CardHeader className="text-center">
              <div className="mx-auto mb-4 w-16 h-16 rounded-full bg-primary/10 flex items-center justify-center">
                <Clock className="h-8 w-8 text-primary" />
              </div>
              <CardTitle className="text-xl">Aguardando Aprovação</CardTitle>
              <CardDescription>
                Sua solicitação para entrar em <strong>{companyName}</strong> foi enviada.
              </CardDescription>
            </CardHeader>
            <CardContent className="text-center space-y-4">
              <div className="flex items-center justify-center gap-2 text-sm text-muted-foreground">
                <RefreshCw className="h-4 w-4 animate-spin" />
                <span>Aguardando resposta em tempo real...</span>
              </div>
              <p className="text-sm text-muted-foreground">
                O administrador da empresa receberá sua solicitação e poderá aprová-la ou rejeitá-la.
                Você será redirecionado automaticamente quando aprovado.
              </p>
              <div className="space-y-2 pt-4">
                <Button
                  variant="outline"
                  onClick={handleCancelRequest}
                  className="w-full"
                >
                  Cancelar Solicitação
                </Button>
                <Button
                  variant="ghost"
                  onClick={handleBackToLogin}
                  className="w-full text-muted-foreground"
                >
                  <LogOut className="h-4 w-4 mr-2" />
                  Sair e Voltar ao Login
                </Button>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-background via-background to-muted/30 py-8 px-4">
      <div className="max-w-md mx-auto">
        <Card>
          <CardHeader className="text-center relative">
            <div className="mx-auto mb-4 w-16 h-16 rounded-xl bg-primary flex items-center justify-center mt-2">
              <Users className="h-8 w-8 text-primary-foreground" />
            </div>
            <CardTitle className="text-2xl">Entrar em uma Empresa</CardTitle>
            <CardDescription>
              Digite o código fornecido pelo administrador da empresa
            </CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-6">
              {/* Company Code */}
              <div className="space-y-2">
                <Label htmlFor="companyCode">Código da Empresa *</Label>
                <div className="relative">
                  <Input
                    id="companyCode"
                    value={companyCode}
                    onChange={(e) => handleCodeChange(e.target.value)}
                    placeholder="ABC123"
                    className="text-center font-mono text-2xl tracking-widest uppercase"
                    maxLength={6}
                    required
                  />
                  {isSearchingCode && (
                    <div className="absolute right-3 top-1/2 -translate-y-1/2">
                      <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
                    </div>
                  )}
                </div>
                {searchError && !isSearchingCode && companyCode.length === 6 && (
                  <p className="text-sm text-destructive">{searchError}</p>
                )}
                {foundCompany && !isSearchingCode && (
                  <div className="flex items-center gap-2 p-3 bg-green-500/10 border border-green-500/30 rounded-lg">
                    <Building2 className="h-4 w-4 text-green-500" />
                    <span className="text-sm text-green-600 dark:text-green-400">
                      {foundCompany.company_name}
                    </span>
                  </div>
                )}
              </div>

              {/* Role Selection */}
              <div className="space-y-3">
                <Label>Solicitar acesso como *</Label>
                <RadioGroup
                  value={selectedRole}
                  onValueChange={(value) => setSelectedRole(value as 'FUNCIONARIO' | 'PRODUCAO')}
                  className="space-y-3"
                >
                  <div className="flex items-start space-x-3 p-3 border rounded-lg hover:bg-muted/50 transition-colors">
                    <RadioGroupItem value="FUNCIONARIO" id="funcionario" className="mt-1" />
                    <div className="flex-1">
                      <Label htmlFor="funcionario" className="font-medium cursor-pointer">
                        Funcionário
                      </Label>
                      <p className="text-sm text-muted-foreground">
                        Acesso a vendas, espaço, clientes e garantias
                      </p>
                    </div>
                  </div>
                  <div className="flex items-start space-x-3 p-3 border rounded-lg hover:bg-muted/50 transition-colors">
                    <RadioGroupItem value="PRODUCAO" id="producao" className="mt-1" />
                    <div className="flex-1">
                      <Label htmlFor="producao" className="font-medium cursor-pointer">
                        Produção
                      </Label>
                      <p className="text-sm text-muted-foreground">
                        Acesso ao estoque e movimentação de materiais
                      </p>
                    </div>
                  </div>
                </RadioGroup>
              </div>

              <Button
                type="submit"
                className="w-full"
                size="lg"
                disabled={isLoading || !foundCompany}
              >
                {isLoading ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Enviando...
                  </>
                ) : (
                  <>
                    <Send className="mr-2 h-4 w-4" />
                    Enviar Solicitação
                  </>
                )}
              </Button>
            </form>

            {/* Navigation buttons */}
            <div className="mt-6 space-y-2">
              <Button
                variant="outline"
                onClick={() => navigate('/empresa/cadastro')}
                className="w-full"
              >
                <ArrowLeft className="h-4 w-4 mr-2" />
                Criar Minha Própria Empresa
              </Button>
              <Button
                variant="ghost"
                onClick={handleBackToLogin}
                className="w-full text-muted-foreground"
              >
                <LogOut className="h-4 w-4 mr-2" />
                Sair e Voltar ao Login
              </Button>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/integrations/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { useToast } from '@/hooks/use-toast';
import { Loader2, Building2, CheckCircle, ArrowRight, LogOut } from 'lucide-react';
import { CompanyCodeDisplay } from '@/components/team/CompanyCodeDisplay';

export default function CompanySetup() {
  const { user, refreshUser, signOut } = useAuth();
  const navigate = useNavigate();
  const { toast } = useToast();

  const [isLoading, setIsLoading] = useState(false);
  const [isFetchingCep, setIsFetchingCep] = useState(false);
  const [companyCode, setCompanyCode] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    company_name: '',
    cnpj: '',
    phone: '',
    email: '',
    cep: '',
    state: '',
    city: '',
    neighborhood: '',
    street: '',
    number: '',
    complement: '',
  });

  useEffect(() => {
    // Redirect if user already has company
    if (user?.companyId) {
      navigate('/');
    }
    // Redirect if subscription not active
    if (user?.subscriptionStatus !== 'active') {
      if (user?.subscriptionStatus === 'pending_payment') {
        if (!user?.planCode) {
          navigate('/planos');
        } else {
          navigate('/assinatura');
        }
      } else if (user?.subscriptionStatus === 'payment_submitted') {
        navigate('/aguardando-liberacao');
      }
    }
  }, [user, navigate]);

  const formatCNPJ = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 2) return numbers;
    if (numbers.length <= 5) return `${numbers.slice(0, 2)}.${numbers.slice(2)}`;
    if (numbers.length <= 8) return `${numbers.slice(0, 2)}.${numbers.slice(2, 5)}.${numbers.slice(5)}`;
    if (numbers.length <= 12) return `${numbers.slice(0, 2)}.${numbers.slice(2, 5)}.${numbers.slice(5, 8)}/${numbers.slice(8)}`;
    return `${numbers.slice(0, 2)}.${numbers.slice(2, 5)}.${numbers.slice(5, 8)}/${numbers.slice(8, 12)}-${numbers.slice(12, 14)}`;
  };

  const formatPhone = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 2) return numbers;
    if (numbers.length <= 7) return `(${numbers.slice(0, 2)}) ${numbers.slice(2)}`;
    if (numbers.length <= 11) return `(${numbers.slice(0, 2)}) ${numbers.slice(2, 7)}-${numbers.slice(7)}`;
    return `(${numbers.slice(0, 2)}) ${numbers.slice(2, 7)}-${numbers.slice(7, 11)}`;
  };

  const formatCEP = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 5) return numbers;
    return `${numbers.slice(0, 5)}-${numbers.slice(5, 8)}`;
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;

    let formattedValue = value;
    if (name === 'cnpj') formattedValue = formatCNPJ(value);
    if (name === 'phone') formattedValue = formatPhone(value);
    if (name === 'cep') formattedValue = formatCEP(value);

    setFormData(prev => ({ ...prev, [name]: formattedValue }));

    // Auto-fetch address when CEP is complete
    if (name === 'cep' && value.replace(/\D/g, '').length === 8) {
      fetchAddress(value.replace(/\D/g, ''));
    }
  };

  const fetchAddress = async (cep: string) => {
    setIsFetchingCep(true);
    try {
      const response = await fetch(`https://viacep.com.br/ws/${cep}/json/`);
      const data = await response.json();

      if (!data.erro) {
        setFormData(prev => ({
          ...prev,
          state: data.uf || '',
          city: data.localidade || '',
          neighborhood: data.bairro || '',
          street: data.logradouro || '',
        }));
      }
    } catch (error) {
      console.error('Error fetching address:', error);
    } finally {
      setIsFetchingCep(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;

    setIsLoading(true);

    try {
      // 1. Create company (code will be auto-generated by trigger)
      const { data: company, error: companyError } = await supabase
        .from('companies')
        .insert({
          ...formData,
          owner_id: user.id
        })
        .select('id, company_code')
        .single();

      if (companyError) throw companyError;

      // 2. Update profile with company_id
      const { error: profileError } = await supabase
        .from('profiles')
        .update({ company_id: company.id })
        .eq('user_id', user.id);

      if (profileError) throw profileError;

      // 3. Update subscription with company_id
      const { error: subscriptionError } = await supabase
        .from('subscriptions')
        .update({ company_id: company.id })
        .eq('user_id', user.id);

      if (subscriptionError) throw subscriptionError;

      // 4. Update user role to ADMIN using UPSERT for reliability
      // Note: The trigger ensure_owner_is_admin should also handle this,
      // but we do it explicitly as a safety measure
      const { error: roleError } = await supabase
        .from('user_roles')
        .upsert(
          { user_id: user.id, role: 'ADMIN' },
          { onConflict: 'user_id' }
        );

      if (roleError) {
        console.error('Error setting ADMIN role:', roleError);
        // Don't throw - the trigger should have handled this
        // Just log the error for debugging
      }

      // 5. Create default bank account
      const { error: accountError } = await supabase
        .from('accounts')
        .insert({
          name: 'Conta Principal',
          company_id: company.id,
          is_main: true,
          is_active: true,
          initial_balance: 0,
          current_balance: 0
        });

      if (accountError) throw accountError;

      // Show success screen with company code
      setCompanyCode(company.company_code);

      toast({
        title: 'Empresa cadastrada!',
        description: 'Bem-vindo ao WFE Evolution CRM',
      });

    } catch (error: any) {
      console.error('Error creating company:', error);
      const friendlyError = error?.message?.includes('new row violates row-level security policy')
        ? 'Erro de permissão ao criar empresa. Verifique sua conta.'
        : error.message || 'Tente novamente';
      toast({
        title: 'Erro ao cadastrar empresa',
        description: friendlyError,
        variant: 'destructive'
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleGoToDashboard = async () => {
    await refreshUser();
    navigate('/');
  };

  const handleSignOut = async () => {
    try {
      await signOut();
      navigate('/login');
    } catch (error) {
      console.error('Error signing out:', error);
    }
  };

  // Success screen with company code
  if (companyCode) {
    return (
      <div className="min-h-screen relative bg-gradient-to-br from-background via-background to-muted/30 py-8 px-4">
        <div className="absolute top-4 right-4">
          <Button variant="ghost" className="text-muted-foreground hover:text-foreground" onClick={handleSignOut}>
            <LogOut className="mr-2 h-4 w-4" />
            Voltar para o Login
          </Button>
        </div>
        <div className="max-w-md mx-auto">
          <Card>
            <CardHeader className="text-center">
              <div className="mx-auto mb-4 w-16 h-16 rounded-full bg-green-500/10 flex items-center justify-center">
                <CheckCircle className="h-8 w-8 text-green-500" />
              </div>
              <CardTitle className="text-2xl">Empresa Cadastrada!</CardTitle>
              <CardDescription>
                Você é o administrador desta empresa
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
              <CompanyCodeDisplay
                code={companyCode}
                showCard={false}
              />

              <div className="bg-yellow-500/10 border border-yellow-500/30 rounded-lg p-4">
                <p className="text-sm text-yellow-600 dark:text-yellow-400">
                  <strong>⚠️ Importante!</strong> Compartilhe este código com membros da sua equipe para que eles possam solicitar acesso. Você precisará aprovar cada solicitação.
                </p>
              </div>

              <Button onClick={handleGoToDashboard} className="w-full" size="lg">
                Ir para o Dashboard
                <ArrowRight className="ml-2 h-4 w-4" />
              </Button>
            </CardContent>
          </Card>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen relative bg-gradient-to-br from-background via-background to-muted/30 py-8 px-4">
      <div className="absolute top-4 right-4">
        <Button variant="ghost" className="text-muted-foreground hover:text-foreground" onClick={handleSignOut}>
          <LogOut className="mr-2 h-4 w-4" />
          Voltar para o Login
        </Button>
      </div>
      <div className="max-w-2xl mx-auto">
        <Card>
          <CardHeader className="text-center">
            <div className="mx-auto mb-4 w-16 h-16 rounded-xl bg-primary flex items-center justify-center">
              <Building2 className="h-8 w-8 text-primary-foreground" />
            </div>
            <CardTitle className="text-2xl">Cadastre sua empresa</CardTitle>
            <CardDescription>
              Preencha os dados da sua empresa para começar a usar o sistema
            </CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-6">
              {/* Company Info */}
              <div className="grid gap-4 md:grid-cols-2">
                <div className="space-y-2 md:col-span-2">
                  <Label htmlFor="company_name">Nome da Empresa *</Label>
                  <Input
                    id="company_name"
                    name="company_name"
                    value={formData.company_name}
                    onChange={handleChange}
                    placeholder="Razão social ou nome fantasia"
                    required
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="cnpj">CNPJ</Label>
                  <Input
                    id="cnpj"
                    name="cnpj"
                    value={formData.cnpj}
                    onChange={handleChange}
                    placeholder="00.000.000/0000-00"
                    maxLength={18}
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="phone">WhatsApp da Empresa *</Label>
                  <Input
                    id="phone"
                    name="phone"
                    value={formData.phone}
                    onChange={handleChange}
                    placeholder="(00) 00000-0000"
                    maxLength={15}
                    required
                  />
                </div>

                <div className="space-y-2 md:col-span-2">
                  <Label htmlFor="email">Email da Empresa</Label>
                  <Input
                    id="email"
                    name="email"
                    type="email"
                    value={formData.email}
                    onChange={handleChange}
                    placeholder="contato@empresa.com.br"
                  />
                </div>
              </div>

              {/* Divider */}
              <div className="relative">
                <div className="absolute inset-0 flex items-center">
                  <span className="w-full border-t" />
                </div>
                <div className="relative flex justify-center text-xs uppercase">
                  <span className="bg-card px-2 text-muted-foreground">Endereço</span>
                </div>
              </div>

              {/* Address */}
              <div className="grid gap-4 md:grid-cols-3">
                <div className="space-y-2">
                  <Label htmlFor="cep">CEP</Label>
                  <div className="relative">
                    <Input
                      id="cep"
                      name="cep"
                      value={formData.cep}
                      onChange={handleChange}
                      placeholder="00000-000"
                      maxLength={9}
                    />
                    {isFetchingCep && (
                      <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 animate-spin text-muted-foreground" />
                    )}
                  </div>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="state">Estado</Label>
                  <Input
                    id="state"
                    name="state"
                    value={formData.state}
                    onChange={handleChange}
                    placeholder="UF"
                    maxLength={2}
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="city">Cidade</Label>
                  <Input
                    id="city"
                    name="city"
                    value={formData.city}
                    onChange={handleChange}
                    placeholder="Cidade"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="neighborhood">Bairro</Label>
                  <Input
                    id="neighborhood"
                    name="neighborhood"
                    value={formData.neighborhood}
                    onChange={handleChange}
                    placeholder="Bairro"
                  />
                </div>

                <div className="space-y-2 md:col-span-2">
                  <Label htmlFor="street">Rua</Label>
                  <Input
                    id="street"
                    name="street"
                    value={formData.street}
                    onChange={handleChange}
                    placeholder="Nome da rua"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="number">Número</Label>
                  <Input
                    id="number"
                    name="number"
                    value={formData.number}
                    onChange={handleChange}
                    placeholder="Nº"
                  />
                </div>

                <div className="space-y-2 md:col-span-2">
                  <Label htmlFor="complement">Complemento</Label>
                  <Input
                    id="complement"
                    name="complement"
                    value={formData.complement}
                    onChange={handleChange}
                    placeholder="Sala, andar, etc."
                  />
                </div>
              </div>

              <Button type="submit" className="w-full" size="lg" disabled={isLoading}>
                {isLoading ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Cadastrando...
                  </>
                ) : (
                  'Cadastrar e começar'
                )}
              </Button>
            </form>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

// @ts-nocheck
import React, { useState, useEffect } from "react";
import { Plus } from "lucide-react";
import { Button } from "@/components/ui/button";
import { useAuth } from "@/contexts/AuthContext";
import { useNavigate } from "react-router-dom";
import { usePlanGate } from "@/hooks/usePlanGate";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";
import { PurchaseKPIs } from "@/components/compras/PurchaseKPIs";
import { PurchasesTable, PurchaseRow, PurchaseFilters } from "@/components/compras/PurchasesTable";
import { NewPurchaseModal } from "@/components/compras/NewPurchaseModal";
import { PurchaseDetailDrawer } from "@/components/compras/PurchaseDetailDrawer";
import { MonthBillsModal } from "@/components/compras/MonthBillsModal";
import { fetchPurchaseMetrics } from "@/lib/purchaseService";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, ResponsiveContainer } from "recharts";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { format, subMonths, addMonths } from "date-fns";
import { ptBR } from "date-fns/locale";

export default function Compras() {
  const { user } = useAuth();
  const gate = usePlanGate('compras');
  const navigate = useNavigate();

  useEffect(() => {
    if (!gate.hasAccess) {
      if (gate.message) toast.error(gate.message);
      if (gate.redirectTo) navigate(gate.redirectTo, { replace: true });
    }
  }, [gate.hasAccess, gate.redirectTo, gate.message, navigate]);


  const [metrics, setMetrics] = useState({ totalMonthDue: 0, monthBillsCount: 0, totalOpenPurchases: 0, totalOverduePurchases: 0, chartData: [] as { name: string, valor: number }[] });
  const [purchases, setPurchases] = useState<PurchaseRow[]>([]);
  const [accounts, setAccounts] = useState<any[]>([]);
  const [categories, setCategories] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // Modals state
  const [isNewPurchaseOpen, setIsNewPurchaseOpen] = useState(false);
  const [isBillsModalOpen, setIsBillsModalOpen] = useState(false);
  const [detailPurchaseId, setDetailPurchaseId] = useState<number | null>(null);

  const [filters, setFilters] = useState<PurchaseFilters>({ search: "", status: "all", paymentMethod: "all", filterMonth: format(new Date(), "yyyy-MM") });

  useEffect(() => {
    if (user?.companyId) {
      loadData();
    }
  }, [user?.companyId]);

  const loadData = async () => {
    setLoading(true);
    await Promise.all([
      fetchMetrics(),
      fetchPurchases(),
      fetchAccountsAndCategories()
    ]);
    setLoading(false);
  };

  const fetchMetrics = async () => {
    if (!user?.companyId) return;
    const data = await fetchPurchaseMetrics(user.companyId);
    setMetrics(data);
  };

  const fetchPurchases = async () => {
    if (!user?.companyId) return;
    const { data } = await supabase
      .from("purchases")
      .select("*, purchase_installments(id, status)")
      .eq("company_id", user.companyId)
      .order("created_at", { ascending: false });

    if (data) {
      const formatted = data.map(p => ({
        ...p,
        supplier_name: p.supplier_name_snapshot
      })) as unknown as PurchaseRow[];
      setPurchases(formatted);
    }
  };

  const fetchAccountsAndCategories = async () => {
    if (!user?.companyId) return;
    const [accRes, catRes] = await Promise.all([
      supabase.from("accounts").select("*").eq("company_id", user.companyId).eq("is_active", true),
      supabase.from("categories").select("*").eq("type", "Saida").order("name")
    ]);

    if (accRes.data) setAccounts(accRes.data);

    if (catRes.data) {
      let existingCats = catRes.data;
      // Auto create 'Compras de material' if it doesn't exist
      const hasCompraCat = existingCats.some(c => c.name === "Compras de material");
      if (!hasCompraCat) {
        const { data: newCat } = await supabase.from("categories").insert({
          name: "Compras de material",
          type: "Saida",
          color: "#f59e0b"
        }).select().single();
        if (newCat) existingCats = [...existingCats, newCat];
      }
      setCategories(existingCats);
    }
  };

  const handleDelete = async (id: number) => {
    if (window.confirm("Tem certeza que deseja excluir esta compra? Isso reverterá pagamentos.")) {
      const { deletePurchase } = await import("@/lib/purchaseService");
      const success = await deletePurchase(id, user!.companyId!);
      if (success) {
        loadData();
      }
    }
  };

  // Dados do gráfico agora vêm de metrics.chartData

  if (!gate.hasAccess) return null;

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold tracking-tight">Compras e Despesas</h2>
          <p className="text-muted-foreground">Gerencie suas compras de material, fornecedores e contas a pagar.</p>
        </div>
        <div className="flex gap-2">
          <Button onClick={() => setIsNewPurchaseOpen(true)}>
            <Plus className="h-4 w-4 mr-2" />
            Nova Compra
          </Button>
        </div>
      </div>

      <PurchaseKPIs
        metrics={metrics}
        loading={loading}
        monthlyAverage={metrics.totalMonthDue || 0}
        onBillsClick={() => setIsBillsModalOpen(true)}
      />

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2">
          <PurchasesTable
            purchases={purchases}
            loading={loading}
            onViewDetails={setDetailPurchaseId}
            onDelete={handleDelete}
            filters={filters}
            onFiltersChange={setFilters}
          />
        </div>

        <div className="lg:col-span-1">
          <Card>
            <CardHeader>
              <CardTitle className="text-sm font-medium">Previsão de Compromissos</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="h-[300px] w-full">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={metrics.chartData || []}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="hsl(var(--muted))" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: "hsl(var(--muted-foreground))" }} />
                    <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: "hsl(var(--muted-foreground))" }} tickFormatter={(value) => `R$${value / 1000}k`} />
                    <RechartsTooltip cursor={{ fill: "hsl(var(--muted))" }} contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} formatter={(value: number) => [`R$ ${value.toFixed(2)}`, 'Valor']} />
                    <Bar dataKey="valor" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>

      <NewPurchaseModal
        open={isNewPurchaseOpen}
        onOpenChange={setIsNewPurchaseOpen}
        onSuccess={loadData}
        accounts={accounts}
        categories={categories}
      />

      <PurchaseDetailDrawer
        purchaseId={detailPurchaseId}
        open={!!detailPurchaseId}
        onOpenChange={(v) => !v && setDetailPurchaseId(null)}
        onUpdate={loadData}
      />

      <MonthBillsModal
        open={isBillsModalOpen}
        onOpenChange={setIsBillsModalOpen}
        companyId={user?.companyId || 0}
        onSuccess={loadData}
      />
    </div>
  );
}

﻿// @ts-nocheck
import { useState, useEffect, useCallback } from "react";
import { Eye, EyeOff, Settings, Plus, Landmark, FolderPlus, FolderTree, ArrowRightLeft, ArrowDownRight, ArrowUpRight } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { cn } from "@/lib/utils";
import { HelpOverlay } from "@/components/help/HelpOverlay";

// Modals
import { AddAccountModal } from "@/shared/components/financeiro/AddAccountModal";
import { EditAccountModal } from "./components/EditAccountModal";
import { AddTransactionModal } from "@/shared/components/financeiro/AddTransactionModal";
import { AddTransferModal } from "@/shared/components/financeiro/AddTransferModal";
import { NewCategoryModal } from "@/shared/components/financeiro/NewCategoryModal";
import { ManageCategoriesModal } from "@/shared/components/financeiro/ManageCategoriesModal";
import { ConfirmPurchasePaymentModal } from "@/components/compras/ConfirmPurchasePaymentModal";
import { Dialog, DialogContent, DialogTrigger, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { SalePayment } from "@/pages/Vendas/components/PaymentBlock";

// Sub-abas
import { Extrato } from "./sub-abas/Extrato/Extrato";
import { CardMachinesList } from "@/shared/components/financeiro/CardMachinesList";
import { BoletoManagement } from "@/shared/components/financeiro/BoletoManagement";

// Services and context
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";
import { payInstallment, reverseInstallment, payInstallmentWithDetails } from "@/lib/purchaseService";

interface Account {
  id: number;
  name: string;
  account_type: string | null;
  current_balance: number | null;
  is_main: boolean | null;
  is_active: boolean | null;
  bank_code?: string | null;
  bank_name?: string | null;
  accepted_payment_methods?: string[] | null;
}

interface Transaction {
  id: number | string;
  type: string;
  amount: number;
  name: string;
  description: string | null;
  transaction_date: string;
  payment_method: string | null;
  is_paid: boolean | null;
  category_id: number | null;
  account_id: number | null;
  origin_type?: string | null;
  origin_id?: number | null;
}

interface Category {
  id: number;
  name: string;
  type: string;
  color: string | null;
}

export default function Contas() {
  const { user } = useAuth();
  const [accounts, setAccounts] = useState<Account[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedAccountId, setSelectedAccountId] = useState<number | null>(null);
  const [showValues, setShowValues] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingAccount, setEditingAccount] = useState<Account | null>(null);
  const [activeTab, setActiveTab] = useState<'extrato' | 'maquininhas' | 'boletos'>('extrato');
  const [selectedAccountsForTotal, setSelectedAccountsForTotal] = useState<number[]>([]);

  const toggleAccountSelection = (id: number, e: React.MouseEvent) => {
    e.stopPropagation();
    setSelectedAccountsForTotal(prev =>
      prev.includes(id) ? prev.filter(a => a !== id) : [...prev, id]
    );
  };

  const [fabOpen, setFabOpen] = useState(false);
  const [transactionModalOpen, setTransactionModalOpen] = useState(false);
  const [transactionType, setTransactionType] = useState<'entrada' | 'saida'>('entrada');
  const [transferModalOpen, setTransferModalOpen] = useState(false);
  const [categoryModalOpen, setCategoryModalOpen] = useState(false);
  const [manageCategoriesOpen, setManageCategoriesOpen] = useState(false);

  const [companyId, setCompanyId] = useState<number | null>(null);
  const [paymentModalOpen, setPaymentModalOpen] = useState(false);
  const [transactionToPay, setTransactionToPay] = useState<Transaction | null>(null);

  const formatCurrency = (value: number) => {
    if (!showValues) return "••••••";
    return `R$ ${value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;
  };

  const fetchData = useCallback(async () => {
    if (!user?.id) return;
    try {
      const { data: profile } = await supabase
        .from("profiles")
        .select("company_id")
        .eq("user_id", user.id)
        .single();

      if (!profile?.company_id) {
        setLoading(false);
        return;
      }
      setCompanyId(profile.company_id);

      const { data: accountsData } = await supabase
        .from("accounts")
        .select("*")
        .eq("company_id", profile.company_id)
        .eq("is_active", true)
        .order("is_main", { ascending: false });

      const { data: transactionsData } = await supabase
        .from("transactions")
        .select("*")
        .eq("company_id", profile.company_id)
        .order("transaction_date", { ascending: false });

      const { data: transfersData } = await supabase
        .from("transfers")
        .select("*")
        .eq("company_id", profile.company_id)
        .order("transfer_date", { ascending: false });

      const { data: categoriesData } = await supabase
        .from("categories")
        .select("*")
        .eq("company_id", profile.company_id);

      setAccounts(accountsData || []);

      const mappedTransfersOut = (transfersData || []).map(tr => {
        const fromAccountName = accountsData?.find(a => String(a.id) === String(tr.from_account_id))?.name || 'Outra conta';
        const toAccountName = accountsData?.find(a => String(a.id) === String(tr.to_account_id))?.name || 'Outra conta';
        const transferName = `Transf. de ${fromAccountName} para ${toAccountName}`;

        return {
          id: `transfer-out-${tr.id}`,
          type: 'Saida',
          amount: tr.amount,
          name: tr.description ? `${transferName} - ${tr.description}` : transferName,
          description: tr.description,
          transaction_date: tr.transfer_date,
          payment_method: 'Transferência',
          is_paid: true,
          category_id: null,
          account_id: tr.from_account_id
        };
      });

      const mappedTransfersIn = (transfersData || []).map(tr => {
        const fromAccountName = accountsData?.find(a => String(a.id) === String(tr.from_account_id))?.name || 'Outra conta';
        const toAccountName = accountsData?.find(a => String(a.id) === String(tr.to_account_id))?.name || 'Outra conta';
        const transferName = `Transf. de ${fromAccountName} para ${toAccountName}`;

        return {
          id: `transfer-in-${tr.id}`,
          type: 'Entrada',
          amount: tr.amount,
          name: tr.description ? `${transferName} - ${tr.description}` : transferName,
          description: tr.description,
          transaction_date: tr.transfer_date,
          payment_method: 'Transferência',
          is_paid: true,
          category_id: null,
          account_id: tr.to_account_id
        };
      });

      const allTransactions = [...(transactionsData || []), ...mappedTransfersOut, ...mappedTransfersIn];
      allTransactions.sort((a, b) => new Date(b.transaction_date).getTime() - new Date(a.transaction_date).getTime());

      setTransactions(allTransactions);
      setCategories(categoriesData || []);

      if (accountsData && accountsData.length > 0 && !selectedAccountId) {
        setSelectedAccountId(accountsData[0].id);
      }
    } catch (error) {
      toast.error("Erro ao carregar dados");
    } finally {
      setLoading(false);
    }
  }, [user?.id, selectedAccountId]);

  useEffect(() => {
    fetchData();
    const handleFinancialUpdate = () => fetchData();
    window.addEventListener("financial-data-changed", handleFinancialUpdate);
    return () => window.removeEventListener("financial-data-changed", handleFinancialUpdate);
  }, [user?.id, fetchData]);

  const selectedAccount = accounts.find(a => String(a.id) === String(selectedAccountId));
  const accountTransactions = transactions.filter(t => String(t.account_id) === String(selectedAccountId));

  const handleTogglePayment = async (tx: Transaction, newStatus: boolean) => {
    if (typeof tx.id === 'string' && tx.id.startsWith('transfer-')) {
      if (window.confirm("Deseja reverter esta transferência? Isso irá desfazer a transferência e remover eventuais taxas associadas.")) {
        const transferId = parseInt(tx.id.replace('transfer-in-', '').replace('transfer-out-', ''));
        await supabase.from("transactions").delete().eq("origin_type", "transfer_fee").eq("origin_id", transferId);
        const { error } = await supabase.from("transfers").delete().eq("id", transferId);
        if (!error) {
          toast.success("Transferência revertida e saldo devolvido!");
          fetchData();
        } else {
          toast.error("Erro ao reverter transferência.");
        }
      }
      return;
    }

    if (window.confirm(newStatus ? "Confirmar o recebimento/pagamento deste lançamento?" : "Reverter o pagamento deste lançamento?")) {
      if (!newStatus && tx.name.includes("Taxa de TED/DOC") && tx.origin_type === 'transfer_fee' && tx.origin_id) {
        await supabase.from("transfers").delete().eq("id", tx.origin_id);
        const { error } = await supabase.from("transactions").delete().eq("id", tx.id);
        if (!error) {
          toast.success("Taxa e Transferência revertidas com sucesso! Os valores voltaram para as contas.");
          fetchData();
        }
        return;
      }
      if (!newStatus && tx.name.includes("Taxa de TED/DOC") && !tx.origin_type) {
        toast.info("Atenção: A taxa foi revertida, mas a transferência ainda consta. Exclua a transferência manualmente se desejar.");
        const { error } = await supabase.from('transactions').delete().eq('id', tx.id);
        if (!error) fetchData();
        return;
      }
      if (tx.origin_type === 'purchase_installment' && tx.origin_id) {
        let success = false;
        if (newStatus) {
          success = await payInstallment(tx.origin_id);
        } else {
          success = await reverseInstallment(tx.origin_id);
        }
        if (success) {
          toast.success(newStatus ? "Lançamento de compra pago e sincronizado!" : "Pagamento de compra revertido!");
          fetchData();
        }
        return;
      }

      const { error } = await supabase.from('transactions').update({ is_paid: newStatus }).eq('id', tx.id);
      if (!error) {
        toast.success(newStatus ? "Lançamento confirmado!" : "Lançamento revertido!");
        fetchData();
      }
    }
  };

  const handleOpenPaymentModal = (tx: Transaction) => {
    if (typeof tx.id === 'string') {
      toast.error("Não é possível alterar o status de uma transferência.");
      return;
    }
    setTransactionToPay(tx);
    setPaymentModalOpen(true);
  };

  const handleConfirmPaymentTransactions = async (payments: SalePayment[]) => {
    if (!transactionToPay || !companyId) return;

    try {
      if (transactionToPay.origin_type === 'purchase_installment' && transactionToPay.origin_id) {
        const purchasePayments = payments.map(p => ({ payment_method: p.payment_method, amount: p.amount, account_id: p.account_id }));
        const success = await payInstallmentWithDetails(transactionToPay.origin_id, purchasePayments);
        if (success) {
          fetchData();
          toast.success('Pagamento da compra confirmado e sincronizado!');
          setPaymentModalOpen(false);
          setTransactionToPay(null);
        }
        return;
      }

      const p = payments[0];
      let finalNetAmount = p.amount;
      if ((p.payment_method === "Crédito" || p.payment_method === "Débito") && p.machine_id) {
        const { data: rateData } = await supabase
          .from("card_machine_rates")
          .select("rate")
          .eq("machine_id", p.machine_id)
          .eq("installments", p.installments)
          .single();
        if (rateData) finalNetAmount = p.amount * (1 - rateData.rate / 100);
      }

      const { error: txError } = await supabase
        .from('transactions')
        .update({
          is_paid: true,
          amount: finalNetAmount,
          account_id: p.account_id,
          payment_method: p.payment_method
        })
        .eq('id', transactionToPay.id);
      if (txError) throw txError;

      for (let i = 1; i < payments.length; i++) {
        const splitPayment = payments[i];
        let splitNetAmount = splitPayment.amount;
        if ((splitPayment.payment_method === "Crédito" || splitPayment.payment_method === "Débito") && splitPayment.machine_id) {
          const { data: rateData } = await supabase
            .from("card_machine_rates")
            .select("rate")
            .eq("machine_id", splitPayment.machine_id)
            .eq("installments", splitPayment.installments)
            .single();
          if (rateData) splitNetAmount = splitPayment.amount * (1 - rateData.rate / 100);
        }
        const { error: splitError } = await supabase
          .from('transactions')
          .insert({
            name: `${transactionToPay.name} (Split)`,
            amount: splitNetAmount,
            type: transactionToPay.type,
            transaction_date: transactionToPay.transaction_date,
            account_id: splitPayment.account_id,
            company_id: companyId,
            is_paid: true,
            payment_method: splitPayment.payment_method,
            description: transactionToPay.description
          });
        if (splitError) throw splitError;
      }

      fetchData();
      toast.success('Pagamento confirmado e registrado!');
      setPaymentModalOpen(false);
      setTransactionToPay(null);
    } catch (err: any) {
      toast.error('Erro ao atualizar status do lançamento.');
    }
  };

  const handleAccountCreated = () => fetchData();
  const handleAccountUpdated = () => fetchData();
  const handleAccountDeleted = (accountId: number) => {
    const remaining = accounts.filter(a => a.id !== accountId);
    if (selectedAccountId === accountId && remaining.length > 0) setSelectedAccountId(remaining[0].id);
    fetchData();
  };

  if (loading) {
    return (
      <div className="flex flex-col md:flex-row h-[calc(100vh-4rem)]">
        <div className="w-full md:w-72 border-b md:border-b-0 md:border-r border-border/50 p-4 space-y-4">
          <Skeleton className="h-8 w-32" />
          {[1, 2, 3].map(i => <Skeleton key={i} className="h-24" />)}
        </div>
        <div className="flex-1 p-6 space-y-6">
          <Skeleton className="h-32" />
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <Skeleton className="h-64" />
            <Skeleton className="h-64" />
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col md:flex-row h-[calc(100vh-4rem)] overflow-x-hidden">
      <HelpOverlay
        tabId="contas"
        title="Guia de Contas"
        sections={[
          { title: "Vídeo Aula — Contas", description: "Assista ao tutorial...", videoUrl: "/help/video-aula-conta.mp4" },
          { title: "Selecionar Conta", description: "Veja detalhes da conta...", screenshotUrl: "/help/help-contas-selecionar.png" },
          { title: "Gráficos de Análise", description: "Veja distribuições...", screenshotUrl: "/help/help-contas-graficos.png" },
          { title: "Extrato Detalhado", description: "Transações em azul...", screenshotUrl: "/help/help-contas-extrato.png" },
        ]}
      />

      <div className="w-full md:w-72 border-b md:border-b-0 md:border-r border-border/50 p-4 space-y-4 overflow-x-hidden overflow-y-auto">
        <div className="flex items-center justify-between">
          <h2 className="font-semibold">Contas</h2>
          <div className="flex gap-1">
            <Button variant="ghost" size="icon" onClick={() => setShowAddModal(true)}><Plus className="h-4 w-4" /></Button>
            <Button variant="ghost" size="icon" onClick={() => setShowValues(!showValues)}>
              {showValues ? <Eye className="h-4 w-4" /> : <EyeOff className="h-4 w-4" />}
            </Button>
          </div>
        </div>

        {accounts.length === 0 ? (
          <div className="text-center py-8 text-muted-foreground">
            <p className="text-sm">Nenhuma conta cadastrada</p>
            <Button onClick={() => setShowAddModal(true)} className="mt-4" size="sm">
              <Plus className="h-4 w-4 mr-2" /> Criar Conta
            </Button>
          </div>
        ) : (
          <div className="flex md:flex-col gap-3 md:gap-2 md:space-y-0 overflow-x-auto pb-2 -mx-4 px-4 md:mx-0 md:px-0 md:pb-0 scrollbar-hide">
            {accounts.map(account => (
              <button
                key={account.id}
                onClick={() => setSelectedAccountId(account.id)}
                className={cn(
                  "min-w-[200px] md:min-w-0 w-full p-3 rounded-lg text-left transition-colors relative group flex-shrink-0",
                  selectedAccountId === account.id ? "bg-primary/10 border border-primary/30" : "bg-card/50 border border-border/50 hover:bg-accent"
                )}
              >
                <div onClick={(e) => toggleAccountSelection(account.id, e)} className={cn("absolute top-2 right-8 p-1 rounded transition-all flex items-center justify-center", selectedAccountsForTotal.includes(account.id) ? "opacity-100" : "opacity-0 group-hover:opacity-100")}>
                  <input type="checkbox" checked={selectedAccountsForTotal.includes(account.id)} readOnly className="w-3.5 h-3.5 cursor-pointer accent-primary" />
                </div>
                <button onClick={(e) => { e.stopPropagation(); setEditingAccount(account); }} className="absolute top-2 right-2 p-1 rounded opacity-0 group-hover:opacity-100 hover:bg-muted transition-all">
                  <Settings className="h-3 w-3 text-muted-foreground" />
                </button>
                <div className="flex items-center justify-between mb-1">
                  <span className="font-medium text-sm truncate pr-2">{account.name}</span>
                  {account.is_main && <Badge variant="outline" className="text-[10px] shrink-0">Principal</Badge>}
                </div>
                <div className="flex items-center gap-2 mt-1 mb-2">
                  {account.bank_code ? (
                    <div className="flex items-center gap-1.5 text-xs text-muted-foreground" title={account.bank_name || undefined}>
                      <img src={`/banks/${account.bank_code}.svg`} alt={account.bank_name || "Banco"} className="w-4 h-4 object-contain rounded-sm" onError={(e) => { (e.target as HTMLImageElement).style.display = 'none'; }} />
                      <span className="truncate max-w-[130px]">{account.bank_name}</span>
                    </div>
                  ) : (
                    <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                      <Landmark className="w-3.5 h-3.5" />
                      <span className="truncate max-w-[130px]">{account.account_type}</span>
                    </div>
                  )}
                </div>
                <p className="text-lg font-bold">{formatCurrency(account.current_balance || 0)}</p>
              </button>
            ))}
          </div>
        )}
      </div>

      <div className="flex-1 p-6 overflow-y-auto space-y-6">
        {selectedAccount ? (
          <>
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6">
              <div className="flex items-center gap-3">
                {selectedAccount.bank_code ? (
                  <div className="w-12 h-12 rounded-xl bg-white border border-border/50 flex items-center justify-center shadow-sm overflow-hidden shrink-0">
                    <img src={`/banks/${selectedAccount.bank_code}.svg`} alt={selectedAccount.bank_name || "Banco"} className="w-8 h-8 object-contain" onError={(e) => { (e.target as HTMLImageElement).style.display = 'none'; }} />
                  </div>
                ) : (
                  <div className="w-12 h-12 rounded-xl bg-muted border border-border/50 flex items-center justify-center shrink-0">
                    <Landmark className="w-6 h-6 text-muted-foreground" />
                  </div>
                )}
                <div>
                  <h1 className="text-2xl font-bold">{selectedAccount.name}</h1>
                  <p className="text-muted-foreground text-sm flex items-center gap-1.5 mt-0.5">
                    <span>{selectedAccount.account_type}</span>
                    {selectedAccount.bank_name && <><span className="text-muted-foreground/50">•</span><span>{selectedAccount.bank_name}</span></>}
                  </p>
                </div>
              </div>

              <div className="flex flex-wrap items-center gap-3 sm:ml-auto justify-end mt-4 sm:mt-0">
                {selectedAccountsForTotal.length > 0 && (
                  <div className="bg-card border border-border/50 rounded-lg px-4 py-1.5 flex flex-col items-end shadow-sm animate-in fade-in slide-in-from-right-4">
                    <span className="text-[10px] text-muted-foreground uppercase tracking-wider font-semibold">Saldo Selecionado</span>
                    <span className="text-sm font-bold text-foreground">
                      {formatCurrency(accounts.filter(a => selectedAccountsForTotal.includes(a.id)).reduce((sum, a) => sum + (a.current_balance || 0), 0))}
                    </span>
                  </div>
                )}
                <Dialog open={fabOpen} onOpenChange={setFabOpen}>
                  <DialogTrigger asChild>
                    <Button className="bg-primary hover:bg-primary/90 text-primary-foreground font-medium rounded-full px-6">
                      Adicionar <Plus className="h-4 w-4 ml-2" />
                    </Button>
                  </DialogTrigger>
                  <DialogContent className="sm:max-w-3xl bg-background border-border/50">
                    <DialogHeader>
                      <DialogTitle className="text-xl font-semibold mb-4">Escolha o que deseja fazer</DialogTitle>
                    </DialogHeader>
                    <div className="grid grid-cols-2 lg:grid-cols-3 gap-4">
                      <button onClick={() => { setFabOpen(false); setTransactionType('entrada'); setTransactionModalOpen(true); }} className="flex flex-col items-center justify-center p-6 gap-3 rounded-xl border border-border bg-card/50 hover:bg-accent hover:border-accent transition-all">
                        <ArrowUpRight className="h-8 w-8 text-green-500" />
                        <span className="font-medium text-sm text-center">Nova entrada na conta</span>
                      </button>
                      <button onClick={() => { setFabOpen(false); setTransactionType('saida'); setTransactionModalOpen(true); }} className="flex flex-col items-center justify-center p-6 gap-3 rounded-xl border border-border bg-card/50 hover:bg-accent hover:border-accent transition-all">
                        <ArrowDownRight className="h-8 w-8 text-red-500" />
                        <span className="font-medium text-sm text-center">Nova saída na conta</span>
                      </button>
                      <button onClick={() => { setFabOpen(false); setTransferModalOpen(true); }} className="flex flex-col items-center justify-center p-6 gap-3 rounded-xl border border-border bg-card/50 hover:bg-accent hover:border-accent transition-all">
                        <ArrowRightLeft className="h-8 w-8 text-blue-500" />
                        <span className="font-medium text-sm text-center">Nova transferência</span>
                      </button>
                      <button onClick={() => { setFabOpen(false); setCategoryModalOpen(true); }} className="flex flex-col items-center justify-center p-6 gap-3 rounded-xl border border-border bg-card/50 hover:bg-accent hover:border-accent transition-all">
                        <FolderPlus className="h-8 w-8 text-primary" />
                        <span className="font-medium text-sm text-center">Nova categoria</span>
                      </button>
                      <button onClick={() => { setFabOpen(false); setManageCategoriesOpen(true); }} className="flex flex-col items-center justify-center p-6 gap-3 rounded-xl border border-border bg-card/50 hover:bg-accent hover:border-accent transition-all">
                        <FolderTree className="h-8 w-8 text-primary" />
                        <span className="font-medium text-sm text-center">Gerenciar categorias</span>
                      </button>
                      <button onClick={() => { setFabOpen(false); setShowAddModal(true); }} className="flex flex-col items-center justify-center p-6 gap-3 rounded-xl border border-border bg-card/50 hover:bg-accent hover:border-accent transition-all">
                        <Landmark className="h-8 w-8 text-primary" />
                        <span className="font-medium text-sm text-center">Nova conta</span>
                      </button>
                    </div>
                  </DialogContent>
                </Dialog>

                <Button variant="outline" size="icon" className="rounded-full shrink-0" onClick={() => setEditingAccount(selectedAccount)}>
                  <Settings className="h-4 w-4" />
                </Button>
              </div>
            </div>

            <div className="flex space-x-1 border-b border-border/50 mb-6">
              <button
                className={cn("px-4 py-2 text-sm font-medium transition-colors border-b-2 relative top-[1px]", activeTab === 'extrato' ? "border-primary text-foreground" : "border-transparent text-muted-foreground hover:text-foreground hover:border-border")}
                onClick={() => setActiveTab('extrato')}
              >Extrato</button>
              <button
                className={cn("px-4 py-2 text-sm font-medium transition-colors border-b-2 relative top-[1px]", activeTab === 'maquininhas' ? "border-primary text-foreground" : "border-transparent text-muted-foreground hover:text-foreground hover:border-border")}
                onClick={() => setActiveTab('maquininhas')}
              >Maquininhas</button>
              <button
                className={cn("px-4 py-2 text-sm font-medium transition-colors border-b-2 relative top-[1px]", activeTab === 'boletos' ? "border-primary text-foreground" : "border-transparent text-muted-foreground hover:text-foreground hover:border-border")}
                onClick={() => setActiveTab('boletos')}
              >Boletos</button>
            </div>

            {activeTab === 'extrato' ? (
              <Extrato
                selectedAccount={selectedAccount}
                accounts={accounts}
                accountTransactions={accountTransactions}
                categories={categories}
                handleTogglePayment={handleTogglePayment}
                handleOpenPaymentModal={handleOpenPaymentModal}
                formatCurrency={formatCurrency}
              />
            ) : activeTab === 'maquininhas' ? (
              <CardMachinesList />
            ) : (
              <BoletoManagement accountId={selectedAccountId!} onRefreshRequired={fetchData} />
            )}
          </>
        ) : (
          <div className="flex items-center justify-center h-full text-muted-foreground">
            <div className="text-center">
              <p>Selecione ou crie uma conta para visualizar</p>
              <Button onClick={() => setShowAddModal(true)} className="mt-4"><Plus className="h-4 w-4 mr-2" /> Criar Conta</Button>
            </div>
          </div>
        )}

        <AddAccountModal open={showAddModal} onOpenChange={setShowAddModal} onSuccess={handleAccountCreated} />
        <EditAccountModal open={!!editingAccount} onOpenChange={(open) => !open && setEditingAccount(null)} account={editingAccount} onAccountUpdated={handleAccountUpdated} onAccountDeleted={handleAccountDeleted} canDelete={accounts.length > 1} />
        <AddTransactionModal open={transactionModalOpen} onOpenChange={setTransactionModalOpen} type={transactionType} onSuccess={fetchData} defaultAccountId={selectedAccountId?.toString()} />
        <AddTransferModal open={transferModalOpen} onOpenChange={setTransferModalOpen} onSuccess={fetchData} />
        <NewCategoryModal open={categoryModalOpen} onOpenChange={setCategoryModalOpen} onSuccess={fetchData} />
        <ManageCategoriesModal open={manageCategoriesOpen} onOpenChange={setManageCategoriesOpen} onCategoriesChange={fetchData} />
      </div>

      {transactionToPay && companyId && (
        <ConfirmPurchasePaymentModal
          open={paymentModalOpen}
          onOpenChange={setPaymentModalOpen}
          installmentAmount={transactionToPay.amount}
          companyId={companyId}
          defaultAccountId={transactionToPay.account_id}
          purchasePaymentMethod={transactionToPay.payment_method || "Pix"}
          onConfirm={handleConfirmPaymentTransactions}
        />
      )}
    </div>
  );
}

// @ts-nocheck
import React, { useState, Fragment } from "react";
import { format, subDays, parse, addMonths, subMonths } from "date-fns";
import { ptBR } from "date-fns/locale";
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip } from "recharts";
import { Search, Calendar as CalendarIcon, Filter, ArrowUpRight, ArrowDownRight, RefreshCw, CheckCircle2, ChevronRight, ChevronLeft, ChevronsUpDown, ChevronUp, ChevronDown, Landmark, Receipt } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Label } from "@/components/ui/label";
import { cn } from "@/lib/utils";

interface ExtratoProps {
    selectedAccount?: any;
    accounts: any[];
    accountTransactions: any[];
    categories: any[];
    formatCurrency: (value: number) => string;
    handleTogglePayment: (tx: any, newStatus: boolean) => void;
    handleOpenPaymentModal: (tx: any) => void;
}

export function Extrato({
    selectedAccount,
    accounts,
    accountTransactions,
    categories,
    formatCurrency,
    handleTogglePayment,
    handleOpenPaymentModal
}: ExtratoProps) {
    const [searchTerm, setSearchTerm] = useState("");
    const [filterMonth, setFilterMonth] = useState(format(new Date(), "yyyy-MM"));

    const handlePrevMonth = () => {
        const current = parse(filterMonth, "yyyy-MM", new Date());
        setFilterMonth(format(subMonths(current, 1), "yyyy-MM"));
    };

    const handleNextMonth = () => {
        const current = parse(filterMonth, "yyyy-MM", new Date());
        setFilterMonth(format(addMonths(current, 1), "yyyy-MM"));
    };

    const [filterType, setFilterType] = useState<string>("todos");
    const [filterStatus, setFilterStatus] = useState<string>("todos");

    type SortField = 'date' | 'name' | 'amount' | 'status';
    const [sortField, setSortField] = useState<SortField>('date');
    const [sortDirection, setSortDirection] = useState<'asc' | 'desc'>('desc');

    const toggleSort = (field: SortField) => {
        if (sortField === field) {
            setSortDirection(prev => prev === 'asc' ? 'desc' : 'asc');
        } else {
            setSortField(field);
            setSortDirection(field === 'date' ? 'desc' : 'asc');
        }
    };

    const SortIcon = ({ field }: { field: SortField }) => {
        if (sortField !== field) return <ChevronsUpDown className="ml-1 h-3 w-3 inline text-muted-foreground/40" />;
        return sortDirection === 'asc'
            ? <ChevronUp className="ml-1 h-3 w-3 inline text-primary" />
            : <ChevronDown className="ml-1 h-3 w-3 inline text-primary" />;
    };

    const [expandedFutureGroups, setExpandedFutureGroups] = useState<Record<string, boolean>>({});
    const [expandedExtratoGroups, setExpandedExtratoGroups] = useState<Record<string, boolean>>({});

    const toggleExtratoGroup = (id: string, e?: React.MouseEvent) => {
        if (e) e.stopPropagation();
        setExpandedExtratoGroups(prev => ({ ...prev, [id]: !prev[id] }));
    };

    const getCategoryById = (id: number) => categories.find(c => c.id === id);

    // Payment methods breakdown from real transactions
    const paymentMethodsMap: Record<string, number> = {};
    accountTransactions
        .filter(t => t.type === 'Entrada' && t.is_paid)
        .forEach(t => {
            const method = t.payment_method || 'Outros';
            paymentMethodsMap[method] = (paymentMethodsMap[method] || 0) + t.amount;
        });

    const paymentColors: Record<string, string> = {
        'Pix': '#22c55e',
        'Dinheiro': '#3b82f6',
        'Crédito': '#8b5cf6',
        'Débito': '#06b6d4',
        'Boleto': '#f97316',
        'Transferência': '#ec4899',
        'Outros': '#6b7280'
    };

    const paymentData = Object.entries(paymentMethodsMap).map(([name, value]) => ({
        name,
        value,
        color: paymentColors[name] || '#6b7280'
    }));

    // Categories breakdown from real transactions
    const categoryTotals: Record<number, number> = {};
    accountTransactions
        .filter(t => t.type === 'Saida' && t.category_id)
        .forEach(t => {
            categoryTotals[t.category_id!] = (categoryTotals[t.category_id!] || 0) + t.amount;
        });

    const categoryData = Object.entries(categoryTotals)
        .map(([catId, value]) => {
            const category = categories.find(c => c.id === parseInt(catId));
            return {
                name: category?.name || 'Outros',
                value,
                color: category?.color || '#6b7280'
            };
        })
        .filter(c => c.value > 0)
        .sort((a, b) => b.value - a.value)
        .slice(0, 5);

    const futureTransactions = accountTransactions.filter(t => !t.is_paid);
    const currentTransactions = accountTransactions.filter(t => t.is_paid);

    const groupedFuture = futureTransactions.reduce((groups, t) => {
        let baseName = t.name;
        const regex = /(\s*-\s*Parcela\s*\d+(?:\s*\/\s*\d+)?|\s*\(\d+\/\d+\)).*/i;
        if (regex.test(baseName)) {
            baseName = baseName.replace(regex, '').trim();
        }
        if (!groups[baseName]) groups[baseName] = [];
        groups[baseName].push(t);
        return groups;
    }, {} as Record<string, any[]>);

    const futureGroupsArray = Object.entries(groupedFuture).map(([name, txs]) => {
        txs.sort((a, b) => new Date(a.transaction_date).getTime() - new Date(b.transaction_date).getTime());
        return {
            name,
            transactions: txs,
            totalAmount: txs.reduce((sum, t) => sum + t.amount, 0),
            installmentsCount: txs.length,
            nextDate: txs[0]?.transaction_date
        };
    }).sort((a, b) => new Date(a.nextDate).getTime() - new Date(b.nextDate).getTime());

    const toggleFutureGroup = (name: string) => {
        setExpandedFutureGroups(prev => ({ ...prev, [name]: !prev[name] }));
    };

    let filteredTransactions = currentTransactions;

    if (filterMonth) {
        filteredTransactions = filteredTransactions.filter(t => t.transaction_date.startsWith(filterMonth));
    }
    if (searchTerm) {
        const term = searchTerm.toLowerCase();
        filteredTransactions = filteredTransactions.filter(t =>
            t.name.toLowerCase().includes(term) ||
            (t.description?.toLowerCase() || "").includes(term) ||
            (getCategoryById(t.category_id || 0)?.name.toLowerCase() || "").includes(term)
        );
    }
    if (filterType !== "todos") {
        filteredTransactions = filteredTransactions.filter(t => t.type.toLowerCase() === filterType.toLowerCase());
    }
    if (filterStatus !== "todos") {
        if (filterStatus === "pago") {
            filteredTransactions = filteredTransactions.filter(t => t.is_paid === true);
        } else if (filterStatus === "pendente") {
            filteredTransactions = filteredTransactions.filter(t => t.is_paid === false);
        }
    }

    filteredTransactions = [...filteredTransactions].sort((a, b) => {
        let comparison = 0;
        if (sortField === 'date') {
            comparison = new Date(a.transaction_date).getTime() - new Date(b.transaction_date).getTime();
        } else if (sortField === 'name') {
            comparison = a.name.localeCompare(b.name);
        } else if (sortField === 'amount') {
            comparison = a.amount - b.amount;
        } else if (sortField === 'status') {
            comparison = (a.is_paid === b.is_paid) ? 0 : a.is_paid ? -1 : 1;
        }
        return sortDirection === 'asc' ? comparison : -comparison;
    });

    const extratoGroups: any[] = [];
    const extratoTempGroups: Record<string, any[]> = {};
    filteredTransactions.forEach(t => {
        let baseName = t.name;
        const regex = /(\s*-\s*Parcela\s*\d+(?:\s*\/\s*\d+)?|\s*\(\d+\/\d+\)).*/i;
        if (regex.test(baseName)) {
            baseName = baseName.replace(regex, '').trim();
        }

        if (!extratoTempGroups[baseName]) extratoTempGroups[baseName] = [];
        extratoTempGroups[baseName].push(t);
    });

    Object.entries(extratoTempGroups).forEach(([name, txs]) => {
        if (txs.length > 1) {
            extratoGroups.push({
                isGroup: true,
                id: `extrato-group-${name}`,
                name: `${name}`,
                transactions: txs,
                totalAmount: txs.reduce((sum, t) => sum + t.amount, 0),
                type: txs[0].type,
                category_id: txs[0].category_id,
                is_paid: txs.every(t => t.is_paid),
                transaction_date: txs[0].transaction_date,
                payment_method: txs[0].payment_method
            });
        } else {
            extratoGroups.push({
                isGroup: false,
                id: txs[0].id.toString(),
                name: txs[0].name,
                transactions: [txs[0]],
                totalAmount: txs[0].amount,
                type: txs[0].type,
                category_id: txs[0].category_id,
                is_paid: txs[0].is_paid,
                transaction_date: txs[0].transaction_date,
                originalTx: txs[0],
                payment_method: txs[0].payment_method
            });
        }
    });

    extratoGroups.sort((a, b) => {
        let comparison = 0;
        if (sortField === 'date') {
            comparison = new Date(a.transaction_date || '').getTime() - new Date(b.transaction_date || '').getTime();
        } else if (sortField === 'name') {
            comparison = a.name.localeCompare(b.name);
        } else if (sortField === 'amount') {
            comparison = (a.totalAmount || 0) - (b.totalAmount || 0);
        } else if (sortField === 'status') {
            comparison = (a.is_paid === b.is_paid) ? 0 : a.is_paid ? -1 : 1;
        }
        return sortDirection === 'asc' ? comparison : -comparison;
    });

    const summaryEntries = filteredTransactions.filter(t => t.type === 'Entrada' && t.is_paid).reduce((sum, t) => sum + t.amount, 0);
    const summaryExits = filteredTransactions.filter(t => t.type === 'Saida' && t.is_paid).reduce((sum, t) => sum + t.amount, 0);
    const geracaoCaixa = summaryEntries - summaryExits;
    const saldoFinal = selectedAccount?.current_balance || 0;
    const saldoInicial = saldoFinal - geracaoCaixa;

    const pendingEntries = accountTransactions.filter(t => t.type === 'Entrada' && !t.is_paid).reduce((sum, t) => sum + t.amount, 0);
    const pendingExits = accountTransactions.filter(t => t.type === 'Saida' && !t.is_paid).reduce((sum, t) => sum + t.amount, 0);
    const saldoPrevisto = saldoFinal + pendingEntries - pendingExits;

    const last7Days = Array.from({ length: 7 }).map((_, i) => {
        const date = subDays(new Date(), 6 - i);
        const dateStr = format(date, 'yyyy-MM-dd');
        const dayTxs = accountTransactions.filter(t => t.transaction_date === dateStr && t.is_paid);
        const entradas = dayTxs.filter(t => t.type === 'Entrada').reduce((acc, t) => acc + t.amount, 0);
        const saidas = dayTxs.filter(t => t.type === 'Saida').reduce((acc, t) => acc + t.amount, 0);
        return {
            date: format(date, 'dd/MM'),
            entradas,
            saidas
        };
    });

    return (
        <>
            <Card className="bg-gradient-to-br from-primary/20 to-primary/5 border-primary/30 relative overflow-hidden">
                <div className="absolute right-4 top-4 opacity-10">
                    <Landmark size={80} />
                </div>
                <CardContent className="p-6 relative z-10">
                    <p className="text-sm font-medium text-muted-foreground">Saldo Atual</p>
                    <p className="text-4xl font-bold mt-1">{formatCurrency(selectedAccount?.current_balance || 0)}</p>
                    <p className="text-xs text-muted-foreground mt-2">
                        Previsto: <span className="font-semibold">{formatCurrency(saldoPrevisto)}</span>
                    </p>
                </CardContent>
            </Card>

            <div className="grid grid-cols-2 sm:grid-cols-2 md:grid-cols-5 gap-4">
                <Card className="bg-card/50 border-border/50">
                    <CardContent className="p-4">
                        <p className="text-xs text-muted-foreground mb-1">Entradas recebidas</p>
                        <p className="text-lg font-bold text-green-500">+{formatCurrency(summaryEntries)}</p>
                    </CardContent>
                </Card>
                <Card className="bg-card/50 border-border/50">
                    <CardContent className="p-4">
                        <p className="text-xs text-muted-foreground mb-1">Saídas pagas</p>
                        <p className="text-lg font-bold text-red-500">-{formatCurrency(summaryExits)}</p>
                    </CardContent>
                </Card>
                <Card className="bg-card/50 border-border/50">
                    <CardContent className="p-4">
                        <p className="text-xs text-muted-foreground mb-1">Geração de caixa</p>
                        <p className={`text-lg font-bold ${geracaoCaixa >= 0 ? 'text-green-500' : 'text-red-500'}`}>
                            {geracaoCaixa >= 0 ? '+' : ''}{formatCurrency(geracaoCaixa)}
                        </p>
                    </CardContent>
                </Card>
                <Card className="bg-card/50 border-border/50">
                    <CardContent className="p-4">
                        <p className="text-xs text-muted-foreground mb-1">Saldo inicial</p>
                        <p className="text-lg font-bold">{formatCurrency(saldoInicial)}</p>
                    </CardContent>
                </Card>
                <Card className="bg-card/50 border-border/50">
                    <CardContent className="p-4">
                        <p className="text-xs text-muted-foreground mb-1">Saldo final</p>
                        <p className="text-lg font-bold">{formatCurrency(saldoFinal)}</p>
                    </CardContent>
                </Card>
            </div>

            <Card className="bg-card/50 border-border/50">
                <CardHeader>
                    <CardTitle className="text-sm">Entradas e saídas (Últimos 7 dias)</CardTitle>
                </CardHeader>
                <CardContent>
                    <div className="h-[250px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={last7Days}>
                                <XAxis dataKey="date" fontSize={12} tickMargin={10} axisLine={false} tickLine={false} />
                                <YAxis hide />
                                <Tooltip formatter={(value: number) => formatCurrency(value)} cursor={{ fill: 'transparent' }} />
                                <Bar dataKey="entradas" name="Entradas" fill="#22c55e" radius={[4, 4, 0, 0]} barSize={30} />
                                <Bar dataKey="saidas" name="Saídas" fill="#ef4444" radius={[4, 4, 0, 0]} barSize={30} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </CardContent>
            </Card>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <Card className="bg-card/50 border-border/50">
                    <CardHeader>
                        <CardTitle className="text-sm">Formas de Pagamento</CardTitle>
                    </CardHeader>
                    <CardContent>
                        {paymentData.length === 0 ? (
                            <div className="h-[200px] flex items-center justify-center text-muted-foreground">
                                <p className="text-sm">Sem dados de entradas</p>
                            </div>
                        ) : (
                            <>
                                <div className="h-[200px]">
                                    <ResponsiveContainer width="100%" height="100%">
                                        <PieChart>
                                            <Pie
                                                data={paymentData}
                                                cx="50%"
                                                cy="50%"
                                                innerRadius={50}
                                                outerRadius={80}
                                                dataKey="value"
                                            >
                                                {paymentData.map((entry, index) => (
                                                    <Cell key={`cell-${index}`} fill={entry.color} />
                                                ))}
                                            </Pie>
                                            <Tooltip formatter={(value: number) => formatCurrency(value)} />
                                        </PieChart>
                                    </ResponsiveContainer>
                                </div>
                                <div className="flex flex-wrap gap-2 mt-2 justify-center">
                                    {paymentData.map(item => (
                                        <div key={item.name} className="flex items-center gap-1 text-xs">
                                            <div className="w-2 h-2 rounded-full" style={{ backgroundColor: item.color }} />
                                            <span>{item.name}</span>
                                        </div>
                                    ))}
                                </div>
                            </>
                        )}
                    </CardContent>
                </Card>

                <Card className="bg-card/50 border-border/50">
                    <CardHeader>
                        <CardTitle className="text-sm">Saídas por Categoria</CardTitle>
                    </CardHeader>
                    <CardContent>
                        {categoryData.length === 0 ? (
                            <div className="h-[200px] flex items-center justify-center text-muted-foreground">
                                <p className="text-sm">Sem dados de saídas</p>
                            </div>
                        ) : (
                            <div className="h-[200px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={categoryData} layout="vertical">
                                        <XAxis type="number" hide />
                                        <YAxis type="category" dataKey="name" width={100} fontSize={11} />
                                        <Tooltip formatter={(value: number) => formatCurrency(value)} />
                                        <Bar dataKey="value" radius={[0, 4, 4, 0]}>
                                            {categoryData.map((entry, index) => (
                                                <Cell key={`cell-${index}`} fill={entry.color} />
                                            ))}
                                        </Bar>
                                    </BarChart>
                                </ResponsiveContainer>
                            </div>
                        )}
                    </CardContent>
                </Card>
            </div>

            <Card className="bg-card/50 border-border/50">
                <CardHeader className="flex flex-col xl:flex-row items-start xl:items-center justify-between gap-4">
                    <CardTitle className="text-sm">Extrato</CardTitle>
                    <div className="flex flex-col sm:flex-row gap-2 w-full xl:w-auto">
                        <div className="relative w-full sm:w-[250px]">
                            <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                            <Input
                                placeholder="Buscar por transação..."
                                className="pl-8 bg-background"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </div>
                        <div className="flex flex-wrap gap-2 w-full xl:w-auto items-center">
                            <Popover>
                                <PopoverTrigger asChild>
                                    <Button variant="outline" size="sm" className="gap-2 h-9">
                                        <Filter className="h-4 w-4" /> Filtros
                                        {(filterType !== 'todos' || filterStatus !== 'todos') && (
                                            <Badge variant="secondary" className="ml-1 h-5 px-1.5 text-[10px]">Ativo</Badge>
                                        )}
                                    </Button>
                                </PopoverTrigger>
                                <PopoverContent align="end" className="w-80 border-border/50">
                                    <div className="space-y-4">
                                        <div className="space-y-2">
                                            <h4 className="font-medium leading-none">Filtros do Extrato</h4>
                                            <p className="text-sm text-muted-foreground">
                                                Refine as transações exibidas.
                                            </p>
                                        </div>
                                        <div className="flex flex-col gap-4">
                                            <div className="space-y-2">
                                                <Label>Tipo</Label>
                                                <Select value={filterType} onValueChange={setFilterType}>
                                                    <SelectTrigger className="w-full bg-background">
                                                        <SelectValue placeholder="Tipo" />
                                                    </SelectTrigger>
                                                    <SelectContent>
                                                        <SelectItem value="todos">Todos</SelectItem>
                                                        <SelectItem value="entrada">Entradas</SelectItem>
                                                        <SelectItem value="saida">Saídas</SelectItem>
                                                    </SelectContent>
                                                </Select>
                                            </div>
                                            <div className="space-y-2">
                                                <Label>Status</Label>
                                                <Select value={filterStatus} onValueChange={setFilterStatus}>
                                                    <SelectTrigger className="w-full bg-background">
                                                        <SelectValue placeholder="Status" />
                                                    </SelectTrigger>
                                                    <SelectContent>
                                                        <SelectItem value="todos">Todos</SelectItem>
                                                        <SelectItem value="pago">Conciliado</SelectItem>
                                                        <SelectItem value="pendente">Pendente</SelectItem>
                                                    </SelectContent>
                                                </Select>
                                            </div>
                                            <div className="space-y-2 pt-2 border-t border-border/50 mt-2">
                                                <Label>Ordenar por</Label>
                                                <div className="grid grid-cols-2 gap-2">
                                                    <Select value={sortField} onValueChange={(val: any) => setSortField(val)}>
                                                        <SelectTrigger className="w-full bg-background">
                                                            <SelectValue placeholder="Campo" />
                                                        </SelectTrigger>
                                                        <SelectContent>
                                                            <SelectItem value="date">Data</SelectItem>
                                                            <SelectItem value="name">Transação</SelectItem>
                                                            <SelectItem value="amount">Valor</SelectItem>
                                                            <SelectItem value="status">Status</SelectItem>
                                                        </SelectContent>
                                                    </Select>
                                                    <Select value={sortDirection} onValueChange={(val: any) => setSortDirection(val)}>
                                                        <SelectTrigger className="w-full bg-background">
                                                            <SelectValue placeholder="Direção" />
                                                        </SelectTrigger>
                                                        <SelectContent>
                                                            <SelectItem value="asc">Crescente</SelectItem>
                                                            <SelectItem value="desc">Decrescente</SelectItem>
                                                        </SelectContent>
                                                    </Select>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </PopoverContent>
                            </Popover>

                            <div className="flex items-center bg-background border border-input rounded-md h-9">
                                <Button variant="ghost" size="icon" className="h-full w-9 rounded-none rounded-l-md hover:bg-muted" onClick={handlePrevMonth}>
                                    <ChevronLeft className="h-4 w-4" />
                                </Button>
                                <div className="flex-1 text-center text-sm font-medium px-4 capitalize min-w-[140px] text-foreground">
                                    {format(parse(filterMonth, "yyyy-MM", new Date()), 'MMMM yyyy', { locale: ptBR })}
                                </div>
                                <Button variant="ghost" size="icon" className="h-full w-9 rounded-none rounded-r-md hover:bg-muted" onClick={handleNextMonth}>
                                    <ChevronRight className="h-4 w-4" />
                                </Button>
                            </div>
                        </div>
                    </div>
                </CardHeader>
                <CardContent>
                    {filteredTransactions.length === 0 ? (
                        <div className="text-center py-8 text-muted-foreground">
                            <p className="text-sm">Nenhuma transação encontrada</p>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            <div className="hidden md:block rounded-md border border-border/50 overflow-x-auto overscroll-x-contain">
                                <Table>
                                    <TableHeader>
                                        <TableRow>
                                            <TableHead
                                                className="min-w-[200px] cursor-pointer hover:bg-muted/50 transition-colors select-none"
                                                onClick={() => toggleSort('name')}
                                            >
                                                Transação <SortIcon field="name" />
                                            </TableHead>
                                            <TableHead>Conta</TableHead>
                                            <TableHead className="text-center">Categoria</TableHead>
                                            <TableHead
                                                className="text-right whitespace-nowrap cursor-pointer hover:bg-muted/50 transition-colors select-none"
                                                onClick={() => toggleSort('amount')}
                                            >
                                                Valor <SortIcon field="amount" />
                                            </TableHead>
                                            <TableHead
                                                className="text-center cursor-pointer hover:bg-muted/50 transition-colors select-none"
                                                onClick={() => toggleSort('status')}
                                            >
                                                <div className="flex items-center justify-center">Status <SortIcon field="status" /></div>
                                            </TableHead>
                                        </TableRow>
                                    </TableHeader>
                                    <TableBody>
                                        {extratoGroups.map((group, index) => {
                                            const renderTx = (tx: any, isChild: boolean = false) => {
                                                const category = tx.category_id ? getCategoryById(tx.category_id) : null;
                                                const isEntry = tx.type === 'Entrada';
                                                const isTransfer = tx.payment_method === 'Transferência';
                                                const isTedFee = tx.name.includes("Taxa de TED/DOC");
                                                return (
                                                    <TableRow key={tx.id} className={cn(isChild && "bg-muted/10 border-l-[3px] border-l-primary/30", isTedFee && "bg-yellow-500/5")}>
                                                        <TableCell className={cn(isChild && "pl-8")}>
                                                            <div className="flex items-center gap-3">
                                                                <div className={cn("p-1.5 rounded-full flex-shrink-0", isTedFee ? "bg-yellow-500/20 text-yellow-600" : isTransfer ? "bg-blue-500/10 text-blue-500" : (isEntry ? "bg-green-500/10 text-green-500" : "bg-red-500/10 text-red-500"))}>
                                                                    {isTedFee ? <Receipt className="h-3 w-3" /> : isTransfer ? <RefreshCw className="h-3 w-3" /> : (isEntry ? <ArrowUpRight className="h-3 w-3" /> : <ArrowDownRight className="h-3 w-3" />)}
                                                                </div>
                                                                <div>
                                                                    <p className={cn("text-sm leading-none mb-1", isTedFee ? "font-bold text-yellow-600 dark:text-yellow-500" : "font-medium")}>{tx.name}</p>
                                                                    <span className="text-[10px] text-muted-foreground">{format(new Date(tx.transaction_date), "dd/MM/yyyy")}</span>
                                                                </div>
                                                            </div>
                                                        </TableCell>
                                                        <TableCell className="text-muted-foreground text-sm">{selectedAccount?.name}</TableCell>
                                                        <TableCell className="text-center">
                                                            {category ? <Badge variant="outline" className="text-[10px] whitespace-nowrap" style={{ borderColor: category.color || undefined, color: category.color || undefined }}>{category.name}</Badge> : <span className="text-muted-foreground">-</span>}
                                                        </TableCell>
                                                        <TableCell className="text-right">
                                                            <span className={cn("font-medium whitespace-nowrap", isEntry ? "text-green-500" : "text-red-500")}>
                                                                {isEntry ? '+' : '-'}{formatCurrency(tx.amount)}
                                                            </span>
                                                        </TableCell>
                                                        <TableCell className="text-center">
                                                            <div className="flex items-center justify-center gap-2">
                                                                <Badge variant={tx.is_paid ? 'default' : 'secondary'} className={cn("text-[10px]", tx.is_paid ? "bg-green-500/10 text-green-500 hover:bg-green-500/20" : "")}>{tx.is_paid ? 'Pago' : 'Pendente'}</Badge>
                                                                {tx.is_paid && (
                                                                    <Button variant="ghost" size="icon" className="h-6 w-6 rounded-full hover:bg-red-500/10 hover:text-red-500" onClick={(e) => { e.stopPropagation(); handleTogglePayment(tx, false); }} title="Reverter Pagamento">
                                                                        <RefreshCw className="h-3 w-3" />
                                                                    </Button>
                                                                )}
                                                            </div>
                                                        </TableCell>
                                                    </TableRow>
                                                );
                                            };

                                            if (!group.isGroup) {
                                                return renderTx(group.originalTx);
                                            }

                                            const isExpanded = expandedExtratoGroups[group.id];
                                            const type = group.type === 'Entrada';
                                            const isTransfer = group.payment_method === 'Transferência';
                                            return (
                                                <Fragment key={group.id}>
                                                    <TableRow className="cursor-pointer hover:bg-muted/50 bg-muted/5 transition-colors group" onClick={(e) => toggleExtratoGroup(group.id, e as any)}>
                                                        <TableCell>
                                                            <div className="flex items-center gap-3">
                                                                <div className="p-1.5 rounded-full flex-shrink-0 bg-primary/10 text-primary w-7 h-7 flex items-center justify-center font-bold text-[10px]">
                                                                    {group.transactions.length}x
                                                                </div>
                                                                <div>
                                                                    <div className="flex items-center gap-2 mb-1">
                                                                        <p className="text-sm font-semibold leading-none">{group.name}</p>
                                                                        {isExpanded ? <ChevronDown className="h-3.5 w-3.5 text-muted-foreground" /> : <ChevronRight className="h-3.5 w-3.5 text-muted-foreground transition-transform group-hover:translate-x-0.5" />}
                                                                    </div>
                                                                    <span className="text-[10px] text-muted-foreground">Múltiplas datas agrupadas</span>
                                                                </div>
                                                            </div>
                                                        </TableCell>
                                                        <TableCell className="text-muted-foreground text-sm">{selectedAccount?.name}</TableCell>
                                                        <TableCell className="text-center">
                                                            {group.category_id && getCategoryById(group.category_id) ? (
                                                                <Badge variant="outline" className="text-[10px] whitespace-nowrap" style={{ borderColor: getCategoryById(group.category_id)?.color, color: getCategoryById(group.category_id)?.color }}>
                                                                    {getCategoryById(group.category_id)?.name}
                                                                </Badge>
                                                            ) : <span className="text-muted-foreground">-</span>}
                                                        </TableCell>
                                                        <TableCell className="text-right">
                                                            <span className={cn("font-bold whitespace-nowrap", type ? "text-green-500" : "text-red-500")}>
                                                                {type ? '+' : '-'}{formatCurrency(group.totalAmount || 0)}
                                                            </span>
                                                        </TableCell>
                                                        <TableCell className="text-center">
                                                            <Badge variant={group.is_paid ? 'default' : 'outline'} className={cn("text-[10px]", group.is_paid ? "bg-green-500/10 text-green-500 hover:bg-green-500/20" : "")}>{group.is_paid ? 'Total Pago' : 'Misto'}</Badge>
                                                        </TableCell>
                                                    </TableRow>
                                                    {isExpanded && group.transactions.map((tx: any) => renderTx(tx, true))}
                                                </Fragment>
                                            );
                                        })}
                                    </TableBody>
                                </Table>
                            </div>

                            <div className="grid grid-cols-1 gap-3 md:hidden">
                                {extratoGroups.map((group, index) => {
                                    const renderCard = (tx: any, isChild: boolean = false) => {
                                        const category = tx.category_id ? getCategoryById(tx.category_id) : null;
                                        const isEntry = tx.type === 'Entrada';
                                        const isTransfer = tx.payment_method === 'Transferência';
                                        const isTedFee = tx.name.includes("Taxa de TED/DOC");

                                        return (
                                            <div key={tx.id} className={cn("p-4 space-y-3", isChild ? "bg-muted/10 border-t border-border/40 pl-6" : isTedFee ? "bg-yellow-500/5 border border-yellow-500/30 rounded-xl" : "bg-card/50 border border-border/50 rounded-xl")}>
                                                <div className="flex items-start justify-between gap-2">
                                                    <div className="flex items-center gap-2">
                                                        <div className={cn("p-1.5 rounded-full flex-shrink-0", isTedFee ? "bg-yellow-500/20 text-yellow-600" : isTransfer ? "bg-blue-500/10 text-blue-500" : (isEntry ? "bg-green-500/10 text-green-500" : "bg-red-500/10 text-red-500"))}>
                                                            {isTedFee ? <Receipt className="h-3.5 w-3.5" /> : isTransfer ? <RefreshCw className="h-3.5 w-3.5" /> : (isEntry ? <ArrowUpRight className="h-3.5 w-3.5" /> : <ArrowDownRight className="h-3.5 w-3.5" />)}
                                                        </div>
                                                        <div>
                                                            <p className={cn("text-sm leading-snug", isTedFee ? "font-bold text-yellow-600 dark:text-yellow-500" : "font-semibold text-foreground")}>{tx.name}</p>
                                                            <span className="text-[10px] text-muted-foreground">{format(new Date(tx.transaction_date), "dd/MM/yyyy")}</span>
                                                        </div>
                                                    </div>
                                                    <span className={cn("font-bold text-sm whitespace-nowrap", isEntry ? "text-green-500" : "text-red-500")}>
                                                        {isEntry ? '+' : '-'}{formatCurrency(tx.amount)}
                                                    </span>
                                                </div>

                                                <div className="flex items-center justify-between pt-2 border-t border-border/40 text-xs">
                                                    <div className="flex items-center gap-1 text-muted-foreground">
                                                        <Landmark className="h-3 w-3" />
                                                        <span>{selectedAccount?.name}</span>
                                                    </div>
                                                    <div className="flex items-center gap-1.5">
                                                        {category && (
                                                            <Badge variant="outline" className="text-[10px] py-0 px-2 font-normal" style={{ borderColor: category.color || undefined, color: category.color || undefined }}>
                                                                {category.name}
                                                            </Badge>
                                                        )}
                                                        <div className="flex items-center gap-1">
                                                            <Badge variant={tx.is_paid ? 'default' : 'secondary'} className={cn("text-[10px] py-0 px-2 font-normal", tx.is_paid ? "bg-green-500/10 text-green-500 hover:bg-green-500/20" : "")}>
                                                                {tx.is_paid ? 'Pago' : 'Pendente'}
                                                            </Badge>
                                                            {tx.is_paid && (
                                                                <Button variant="ghost" size="icon" className="h-6 w-6 rounded-full hover:bg-red-500/10 hover:text-red-500" onClick={(e) => { e.stopPropagation(); handleTogglePayment(tx, false); }} title="Reverter Pagamento">
                                                                    <RefreshCw className="h-3 w-3" />
                                                                </Button>
                                                            )}
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        );
                                    };

                                    if (!group.isGroup) {
                                        return renderCard(group.originalTx);
                                    }

                                    const isExpanded = expandedExtratoGroups[group.id];
                                    const type = group.type === 'Entrada';
                                    const isTransfer = group.payment_method === 'Transferência';

                                    return (
                                        <div key={group.id} className="bg-card/50 border border-border/50 rounded-xl overflow-hidden shadow-sm">
                                            <div
                                                className="p-4 space-y-3 cursor-pointer hover:bg-muted/30 transition-colors"
                                                onClick={(e) => toggleExtratoGroup(group.id, e as any)}
                                            >
                                                <div className="flex items-start justify-between gap-2">
                                                    <div className="flex items-center gap-2">
                                                        <div className="p-1.5 rounded-full flex-shrink-0 bg-primary/10 text-primary w-8 h-8 flex items-center justify-center font-bold text-[10px]">
                                                            {group.transactions.length}x
                                                        </div>
                                                        <div>
                                                            <div className="flex items-center gap-1">
                                                                <p className="text-sm font-semibold text-foreground leading-snug">{group.name}</p>
                                                                {isExpanded ? <ChevronDown className="h-3.5 w-3.5 text-muted-foreground" /> : <ChevronRight className="h-3.5 w-3.5 text-muted-foreground" />}
                                                            </div>
                                                            <span className="text-[10px] text-muted-foreground">Múltiplas parcelas</span>
                                                        </div>
                                                    </div>
                                                    <span className={cn("font-bold text-sm whitespace-nowrap", type ? "text-green-500" : "text-red-500")}>
                                                        {type ? '+' : '-'}{formatCurrency(group.totalAmount || 0)}
                                                    </span>
                                                </div>

                                                <div className="flex items-center justify-between pt-2 border-t border-border/40 text-xs">
                                                    <div className="flex items-center gap-1 text-muted-foreground">
                                                        <Landmark className="h-3 w-3" />
                                                        <span>{selectedAccount?.name}</span>
                                                    </div>
                                                    <div className="flex items-center gap-1.5">
                                                        {group.category_id && getCategoryById(group.category_id) && (
                                                            <Badge variant="outline" className="text-[10px] py-0 px-2 font-normal" style={{ borderColor: getCategoryById(group.category_id)?.color, color: getCategoryById(group.category_id)?.color }}>
                                                                {getCategoryById(group.category_id)?.name}
                                                            </Badge>
                                                        )}
                                                        <Badge variant={group.is_paid ? 'default' : 'outline'} className={cn("text-[10px] py-0 px-2 font-normal", group.is_paid ? "bg-green-500/10 text-green-500" : "")}>
                                                            {group.is_paid ? 'Total Pago' : 'Misto'}
                                                        </Badge>
                                                    </div>
                                                </div>
                                            </div>

                                            {isExpanded && (
                                                <div className="divide-y divide-border/30 bg-muted/5">
                                                    {group.transactions.map((tx: any) => renderCard(tx, true))}
                                                </div>
                                            )}
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    )}
                </CardContent>
            </Card>

            {futureGroupsArray.length > 0 && (
                <Card className="bg-card/50 border-border/50 mt-6">
                    <CardHeader>
                        <CardTitle className="text-sm flex items-center gap-2">
                            <CalendarIcon className="h-4 w-4 text-orange-500" />
                            Lançamentos Futuros e Parcelamentos
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="space-y-3">
                            {futureGroupsArray.map(group => {
                                const isExpanded = expandedFutureGroups[group.name];

                                return (
                                    <div key={group.name} className="border border-border/50 rounded-lg overflow-hidden">
                                        <div
                                            className="bg-muted/30 p-4 flex flex-col sm:flex-row sm:items-center justify-between gap-3 cursor-pointer hover:bg-accent/50 transition-colors"
                                            onClick={() => toggleFutureGroup(group.name)}
                                        >
                                            <div>
                                                <h4 className="font-semibold text-sm leading-snug">{group.name}</h4>
                                                <p className="text-xs text-muted-foreground mt-0.5">
                                                    Próximo venc.: {format(new Date(group.nextDate), "dd/MM/yyyy")} • {group.installmentsCount} {group.installmentsCount === 1 ? 'parcela' : 'parcelas'}
                                                </p>
                                            </div>
                                            <div className="flex items-center justify-between sm:justify-end gap-4 w-full sm:w-auto border-t sm:border-0 pt-2 sm:pt-0 mt-1 sm:mt-0">
                                                <span className="font-bold text-sm text-foreground">
                                                    {formatCurrency(group.totalAmount)}
                                                </span>
                                                <div className="p-1.5 rounded-md bg-background border shrink-0">
                                                    {isExpanded ? <ArrowDownRight className="h-4 w-4" /> : <ChevronRight className="h-4 w-4" />}
                                                </div>
                                            </div>
                                        </div>

                                        {isExpanded && (
                                            <div className="bg-background divide-y divide-border/40">
                                                {group.transactions.map((tx: any) => {
                                                    const isTransfer = tx.payment_method === 'Transferência';
                                                    const isEntry = tx.type === 'Entrada';

                                                    return (
                                                        <div key={tx.id} className="p-3 pl-4 sm:pl-6 flex flex-col sm:flex-row sm:items-center justify-between gap-3 hover:bg-muted/10 transition-colors">
                                                            <div className="flex items-start sm:items-center gap-3">
                                                                <div className={cn(
                                                                    "p-1.5 rounded-full flex-shrink-0 mt-0.5 sm:mt-0",
                                                                    isTransfer ? "bg-blue-500/10 text-blue-500" : (isEntry ? "bg-green-500/10 text-green-500" : "bg-red-500/10 text-red-500")
                                                                )}>
                                                                    {isTransfer ? <RefreshCw className="h-3 w-3" /> : (isEntry ? <ArrowUpRight className="h-3 w-3" /> : <ArrowDownRight className="h-3 w-3" />)}
                                                                </div>
                                                                <div>
                                                                    <p className="text-sm font-medium leading-snug">{tx.name}</p>
                                                                    <span className="text-[10px] text-muted-foreground block mt-0.5">Vencimento: {format(new Date(tx.transaction_date), "dd/MM/yyyy")}</span>
                                                                </div>
                                                            </div>
                                                            <div className="flex items-center justify-between sm:justify-end gap-4 w-full sm:w-auto pl-8 sm:pl-0 pt-2 sm:pt-0 border-t sm:border-0 border-border/40">
                                                                <span className="font-semibold text-sm whitespace-nowrap">
                                                                    {formatCurrency(tx.amount)}
                                                                </span>
                                                                <Button
                                                                    size="sm"
                                                                    variant="outline"
                                                                    className="h-7 text-xs bg-green-500/10 text-green-500 hover:bg-green-500 hover:text-white border-green-500/20 shrink-0"
                                                                    onClick={(e) => { e.stopPropagation(); handleOpenPaymentModal(tx); }}
                                                                >
                                                                    <CheckCircle2 className="h-3.5 w-3.5 mr-1" />
                                                                    Pagar
                                                                </Button>
                                                            </div>
                                                        </div>
                                                    )
                                                })}
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    </CardContent>
                </Card>
            )}
        </>
    );
}

import { useState, useRef, useEffect } from "react";
import { Phone, Mail, MapPin, Upload, Edit, Loader2, Users } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { HelpOverlay } from "@/components/help/HelpOverlay";
import { EditCompanyModal } from "@/components/empresa/EditCompanyModal";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { validateUpload, sanitizeFilename } from "@/lib/uploadValidator";

interface CompanyData {
  company_name: string;
  cnpj: string | null;
  phone: string;
  email: string | null;
  logo_url: string | null;
  company_code: string | null;
  max_members: number;
  street: string | null;
  number: string | null;
  neighborhood: string | null;
  city: string | null;
  state: string | null;
  cep: string | null;
}

export default function Empresa() {
  const { user } = useAuth();
  const [showEditModal, setShowEditModal] = useState(false);

  const [company, setCompany] = useState<CompanyData | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const fetchCompanyData = async () => {
    if (!user?.companyId) return;

    setIsLoading(true);

    // Fetch company data
    const { data: companyData, error: companyError } = await supabase
      .from("companies")
      .select("company_name, cnpj, phone, email, logo_url, company_code, max_members, street, number, neighborhood, city, state, cep")
      .eq("id", user.companyId)
      .single();

    if (!companyError && companyData) {
      setCompany(companyData);
    }

    setIsLoading(false);
  };

  useEffect(() => {
    fetchCompanyData();
  }, [user?.companyId]);



  const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !user?.companyId) return;

    const validation = validateUpload(file, { type: 'logo' });
    if (!validation.valid) {
      toast.error(validation.error);
      return;
    }

    setIsUploading(true);

    try {
      const fileExt = file.name.split('.').pop() || 'png';
      const sanitizedName = sanitizeFilename(file.name.replace(`.${fileExt}`, ''));
      const fileName = `logo-${Date.now()}-${sanitizedName}.${fileExt}`;
      const filePath = `${user.companyId}/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('company-logos')
        .upload(filePath, file, { upsert: true });

      if (uploadError) throw uploadError;

      const { data: { publicUrl } } = supabase.storage
        .from('company-logos')
        .getPublicUrl(filePath);

      const { error: updateError } = await supabase
        .from('companies')
        .update({ logo_url: publicUrl })
        .eq('id', user.companyId);

      if (updateError) throw updateError;

      setCompany(prev => prev ? { ...prev, logo_url: publicUrl } : null);
      toast.success('Logo atualizada com sucesso!');
    } catch (error) {
      console.error('Erro ao fazer upload:', error);
      toast.error('Erro ao fazer upload da logo');
    } finally {
      setIsUploading(false);
    }
  };

  const formatAddress = () => {
    if (!company) return 'Endereço não cadastrado';
    const parts = [
      company.street,
      company.number,
      company.neighborhood,
      company.city,
      company.state,
      company.cep
    ].filter(Boolean);
    return parts.length > 0 ? parts.join(', ') : 'Endereço não cadastrado';
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-6 p-6 max-w-4xl mx-auto overflow-x-hidden">
      <HelpOverlay
        tabId="empresa"
        title="Guia da Empresa"
        sections={[
          {
            title: "Vídeo Aula — Empresa",
            description: "Assista ao vídeo tutorial completo para aprender a configurar e gerenciar os dados da sua empresa e equipe.",
            videoUrl: "/help/video-aula-empresa.mp4"
          },
          {
            title: "Atualizar Logo e Dados",
            description: "Clique na área da logo para fazer upload de uma imagem (PNG ou JPG). Use o botão 'Editar Dados' para alterar nome, CNPJ, telefone, e-mail e endereço. Essas informações aparecem em documentos e garantias.",
            screenshotUrl: "/help/help-empresa-dados.png"
          },
          {
            title: "Código da Equipe",
            description: "O código de equipe é usado por colaboradores para solicitar acesso ao sistema. Compartilhe esse código com novos membros — eles usam na tela de cadastro para associar-se à sua empresa.",
            screenshotUrl: "/help/help-empresa-codigo.png"
          },
          {
            title: "Gerenciar Membros",
            description: "A barra de progresso mostra quantos membros estão cadastrados em relação ao limite do plano. Para aprovar novos membros, vá até 'Solicitações de Acesso' no menu lateral.",
            screenshotUrl: "/help/help-empresa-membros.png"
          },
        ]}
      />

      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">Sua Empresa</h1>
          <p className="text-muted-foreground">Configure os dados da empresa</p>
        </div>
        <Button onClick={() => setShowEditModal(true)}>
          <Edit className="h-4 w-4 mr-2" /> Editar Dados
        </Button>
      </div>

      {/* Company Logo & Name */}
      <Card className="bg-gradient-to-br from-primary/20 to-primary/5 border-primary/30">
        <CardContent className="p-6">
          <div className="flex items-center gap-6">
            <input
              type="file"
              ref={fileInputRef}
              onChange={handleLogoUpload}
              accept="image/png, image/jpeg, image/webp"
              className="hidden"
            />
            <div
              onClick={() => !isUploading && fileInputRef.current?.click()}
              className="w-24 h-24 rounded-xl border-2 border-dashed border-primary/30 flex items-center justify-center bg-primary/5 cursor-pointer hover:bg-primary/10 transition-colors overflow-hidden"
            >
              {isUploading ? (
                <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
              ) : company?.logo_url ? (
                <img src={company.logo_url} alt="Logo" className="w-full h-full object-contain" />
              ) : (
                <div className="text-center">
                  <Upload className="h-6 w-6 mx-auto text-muted-foreground" />
                  <span className="text-xs text-muted-foreground">Upload</span>
                </div>
              )}
            </div>
            <div>
              <h2 className="text-2xl font-bold">{company?.company_name || 'Empresa'}</h2>
              <p className="text-muted-foreground">{company?.cnpj || 'CNPJ não cadastrado'}</p>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Contact Info */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <Card className="bg-card/50 border-border/50">
          <CardContent className="p-4">
            <div className="flex items-center gap-3">
              <div className="p-2 rounded-lg bg-primary/10">
                <Phone className="h-5 w-5 text-primary" />
              </div>
              <div>
                <p className="text-sm text-muted-foreground">WhatsApp</p>
                <p className="font-medium">{company?.phone || 'Não cadastrado'}</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card className="bg-card/50 border-border/50">
          <CardContent className="p-4">
            <div className="flex items-center gap-3">
              <div className="p-2 rounded-lg bg-primary/10">
                <Mail className="h-5 w-5 text-primary" />
              </div>
              <div>
                <p className="text-sm text-muted-foreground">Email</p>
                <p className="font-medium">{company?.email || 'Não cadastrado'}</p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <Card className="bg-card/50 border-border/50">
        <CardContent className="p-4">
          <div className="flex items-center gap-3">
            <div className="p-2 rounded-lg bg-primary/10">
              <MapPin className="h-5 w-5 text-primary" />
            </div>
            <div>
              <p className="text-sm text-muted-foreground">Endereço</p>
              <p className="font-medium">{formatAddress()}</p>
            </div>
          </div>
        </CardContent>
      </Card>



      {/* Modals */}
      <EditCompanyModal open={showEditModal} onOpenChange={setShowEditModal} onSaved={fetchCompanyData} />
    </div>
  );
}

import { useState } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { Car, CheckCircle, AlertTriangle, Download, Trash2, Plus } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { HelpOverlay } from "@/components/help/HelpOverlay";
import { FillSlotModal } from "@/shared/components/espaco/FillSlotModal";
import { SlotDetailsDrawer } from "./components/SlotDetailsDrawer";
import { SlotsDayDrawer } from "./components/SlotsDayDrawer";
import { ConfigureSlotsModal } from "./components/ConfigureSlotsModal";
import { DownloadedPDFsTab } from "@/components/shared/DownloadedPDFsTab";
import { VagasAtivas } from "./sub-abas/VagasAtivas/VagasAtivas";
import { Lixeira } from "./sub-abas/Lixeira/Lixeira";
import VeiculosPagos from "./sub-abas/VeiculosPagos/VeiculosPagos";
import VeiculosNaoPagos from "./sub-abas/VeiculosNaoPagos/VeiculosNaoPagos";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

export default function Espaco() {
  const { user } = useAuth();
  const queryClient = useQueryClient();
  const companyId = user?.companyId;

  const [showFillSlotModal, setShowFillSlotModal] = useState(false);
  const [selectedSpaceId, setSelectedSpaceId] = useState<number | null>(null);
  const [showDetailsDrawer, setShowDetailsDrawer] = useState(false);
  const [showConfigureSlotsModal, setShowConfigureSlotsModal] = useState(false);
  const [selectedDay, setSelectedDay] = useState<Date | null>(null);
  const [activeTab, setActiveTab] = useState("vagas");
  const [refreshTrigger, setRefreshTrigger] = useState(0);
  const [fallbackSpace, setFallbackSpace] = useState<any | null>(null);

  // Global counts and settings
  const { data: unpaidCount } = useQuery({
    queryKey: ['unpaid-exited-count', companyId],
    queryFn: async () => {
      const { count, error } = await supabase
        .from('spaces')
        .select('*', { count: 'exact', head: true })
        .eq('company_id', companyId)
        .is('deleted_at', null)
        .or('payment_status.neq.paid,payment_status.is.null');
      if (error) throw error;
      return count || 0;
    },
    enabled: !!companyId,
  });

  const { data: companySettings, refetch: refetchSettings } = useQuery({
    queryKey: ['company-settings', companyId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('company_settings')
        .select('total_slots')
        .eq('company_id', companyId)
        .maybeSingle();
      if (error) throw error;
      return data;
    },
    enabled: !!companyId,
  });

  const totalSlots = companySettings?.total_slots || 10;

  // Real-time Space selected logic
  const { data: spaces } = useQuery({ queryKey: ['spaces', companyId] });
  const { data: deletedSpaces } = useQuery({ queryKey: ['spaces-deleted', companyId] });
  const selectedSpace = (spaces as any[])?.find(s => s.id === selectedSpaceId)
    || (deletedSpaces as any[])?.find(s => s.id === selectedSpaceId)
    || fallbackSpace || null;

  const handleSlotFilled = () => {
    queryClient.invalidateQueries({ queryKey: ['spaces'] });
    queryClient.invalidateQueries({ queryKey: ['spaces-deleted'] });
    queryClient.invalidateQueries({ queryKey: ['unpaid-exited-count'] });
    setRefreshTrigger(prev => prev + 1);
  };

  const handleSlotClick = (space: any) => {
    setFallbackSpace(null);
    setSelectedSpaceId(space.id);
    setShowDetailsDrawer(true);
  };

  const handleUnpaidSpaceClick = (space: any) => {
    setFallbackSpace(space);
    setSelectedSpaceId(space.id);
    setShowDetailsDrawer(true);
  };

  return (
    <div className="space-y-6 p-4 sm:p-6 max-w-[100vw] overflow-x-hidden">
      <HelpOverlay
        tabId="espaco"
        title="Guia de Vagas"
        sections={[
          {
            title: "Vídeo Aula — Espaço",
            description: "Assista ao vídeo tutorial completo para aprender a usar todas as funcionalidades da gestão de vagas.",
            videoUrl: "/help/video-aula-espaco.mp4"
          },
          {
            title: "Preencher Vaga",
            description: "Clique em 'Preencher Vaga' para registrar a entrada de um veículo. Selecione o cliente, veículo, serviços a serem realizados e a data/hora de entrada. O veículo aparecerá como vaga ocupada.",
            screenshotUrl: "/help/help-espaco-preencher.png"
          },
          {
            title: "Vagas Ativas",
            description: "Na aba 'Vagas Ativas' você vê os cards de resumo (Total, Disponíveis, Ocupadas) e os cards de cada veículo em serviço. Clique em um card para ver detalhes, registrar saída ou alterar informações.",
            screenshotUrl: "/help/help-espaco-ativas.png"
          },
          {
            title: "Veículos Pagos e Não Pagos",
            description: "Use as abas 'Veículos Pagos' e 'Não Pagos' para acompanhar o status de pagamento dos veículos. O badge vermelho na aba indica quantos veículos não foram pagos.",
            screenshotUrl: "/help/help-espaco-pagos.png"
          },
          {
            title: "Calendário de Ocupação",
            description: "O calendário mostra a ocupação diária. Dias com badges amarelos indicam veículos em andamento, verdes indicam finalizados. Clique em um dia para ver detalhes.",
            screenshotUrl: "/help/help-espaco-calendario.png"
          }
        ]}
      />

      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold">Espaço (Vagas)</h1>
          <p className="text-muted-foreground">Gerencie a ocupação das vagas do seu estabelecimento</p>
        </div>
        <Button onClick={() => setShowFillSlotModal(true)} className="w-full sm:w-auto">
          <Plus className="h-4 w-4 mr-2" />
          Preencher Vaga
        </Button>
      </div>

      {/* Tabs */}
      <Tabs value={activeTab} onValueChange={setActiveTab}>
        <TabsList className="h-auto flex-wrap justify-start gap-2 pb-1">
          <TabsTrigger value="vagas" className="gap-2">
            <Car className="h-4 w-4" />
            Vagas Ativas
          </TabsTrigger>
          <TabsTrigger value="pagos-saida" className="gap-2">
            <CheckCircle className="h-4 w-4" />
            Veículos Pagos
          </TabsTrigger>
          <TabsTrigger value="nao-pagos-saida" className="gap-2">
            <AlertTriangle className="h-4 w-4" />
            Não Pagos
            {unpaidCount !== undefined && unpaidCount > 0 && (
              <Badge variant="destructive" className="ml-1 px-1.5 py-0.5 text-xs bg-destructive text-destructive-foreground animate-pulse flex items-center gap-0.5">
                <AlertTriangle className="h-3 w-3" />
                {unpaidCount}
              </Badge>
            )}
          </TabsTrigger>
          <TabsTrigger value="pdfs" className="gap-2">
            <Download className="h-4 w-4" />
            PDFs Baixados
          </TabsTrigger>
          <TabsTrigger value="lixeira" className="gap-2">
            <Trash2 className="h-4 w-4" />
            Lixeira
          </TabsTrigger>
        </TabsList>

        <TabsContent value="vagas">
          <VagasAtivas
            setShowConfigureSlotsModal={setShowConfigureSlotsModal}
            setShowFillSlotModal={setShowFillSlotModal}
            handleSlotClick={handleSlotClick}
            setSelectedDay={setSelectedDay}
            totalSlots={totalSlots}
          />
        </TabsContent>

        <TabsContent value="pagos-saida" className="mt-6">
          <VeiculosPagos refreshTrigger={refreshTrigger} />
        </TabsContent>

        <TabsContent value="nao-pagos-saida" className="mt-6">
          <VeiculosNaoPagos refreshTrigger={refreshTrigger} onSpaceClick={handleUnpaidSpaceClick} />
        </TabsContent>

        <TabsContent value="pdfs" className="mt-6">
          <DownloadedPDFsTab module="espaco" />
        </TabsContent>

        <TabsContent value="lixeira">
          <Lixeira handleSlotClick={handleSlotClick} />
        </TabsContent>
      </Tabs>

      {/* Modals & Drawers */}
      <FillSlotModal
        open={showFillSlotModal}
        onOpenChange={setShowFillSlotModal}
        onSlotFilled={handleSlotFilled}
        preselectedDate={selectedDay || undefined}
        totalSlots={totalSlots}
        occupiedCount={(spaces as any[])?.filter(s => !s.has_exited).length || 0}
      />
      <SlotDetailsDrawer
        open={showDetailsDrawer}
        onOpenChange={(open) => {
          setShowDetailsDrawer(open);
          if (!open) setFallbackSpace(null);
        }}
        space={selectedSpace}
        onUpdate={handleSlotFilled}
      />
      <SlotsDayDrawer
        open={!!selectedDay}
        onOpenChange={(open) => !open && setSelectedDay(null)}
        date={selectedDay}
        onAddSlot={() => setShowFillSlotModal(true)}
      />
      <ConfigureSlotsModal
        open={showConfigureSlotsModal}
        onOpenChange={setShowConfigureSlotsModal}
        currentTotal={totalSlots}
        onSuccess={() => refetchSettings()}
      />
    </div>
  );
}

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Loader2 } from "lucide-react";

interface ConfigureSlotsModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  currentTotal: number;
  onSuccess: () => void;
}

export function ConfigureSlotsModal({
  open,
  onOpenChange,
  currentTotal,
  onSuccess,
}: ConfigureSlotsModalProps) {
  const { user } = useAuth();
  const { toast } = useToast();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [totalSlots, setTotalSlots] = useState<string>(currentTotal.toString());

  useEffect(() => {
    if (open) {
      setTotalSlots(currentTotal.toString());
    }
  }, [open, currentTotal]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user?.companyId) return;

    setIsSubmitting(true);
    try {
      const newTotal = parseInt(totalSlots, 10);

      // Try to update existing record first
      const { data: updateData, error: updateError } = await supabase
        .from("company_settings")
        .update({ total_slots: newTotal })
        .eq("company_id", user.companyId)
        .select("id");

      if (updateError) {
        console.error("Update error:", updateError);
        throw updateError;
      }

      // If no row was updated, insert a new one
      if (!updateData || updateData.length === 0) {
        const { error: insertError } = await supabase
          .from("company_settings")
          .insert({ company_id: user.companyId, total_slots: newTotal });

        if (insertError) {
          console.error("Insert error:", insertError);
          throw insertError;
        }
      }

      toast({
        title: "Sucesso",
        description: "Quantidade de vagas atualizada com sucesso.",
      });
      onSuccess();
      onOpenChange(false);
    } catch (error: any) {
      console.error("Error updating slots:", error);
      toast({
        title: "Erro",
        description: error?.message || "Não foi possível atualizar a quantidade de vagas.",
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[425px]">
        <DialogHeader>
          <DialogTitle>Configurar Quantidade de Vagas</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4 mt-4">
          <div className="space-y-2">
            <Label htmlFor="slots">Total de Vagas Disponíveis</Label>
            <Select value={totalSlots} onValueChange={setTotalSlots}>
              <SelectTrigger>
                <SelectValue placeholder="Selecione..." />
              </SelectTrigger>
              <SelectContent>
                {Array.from({ length: 15 }).map((_, i) => (
                  <SelectItem key={i + 1} value={(i + 1).toString()}>
                    {i + 1}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            <p className="text-sm text-muted-foreground mt-2">
              Defina o máximo de vagas que seu estabelecimento possui.
            </p>
          </div>
          <div className="flex justify-end gap-2 pt-4">
            <Button
              type="button"
              variant="outline"
              onClick={() => onOpenChange(false)}
              disabled={isSubmitting}
            >
              Cancelar
            </Button>
            <Button type="submit" disabled={isSubmitting}>
              {isSubmitting ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  Salvando...
                </>
              ) : (
                "Salvar"
              )}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

