import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Calendar as CalendarPicker } from "@/components/ui/calendar";
import { cn } from "@/lib/utils";

import { Calendar, Clock, Car, User, Camera, Tag, FileText, DollarSign, Package, Plus, RefreshCw, Loader2, Check, Percent, X, Sliders, CalendarIcon } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import ServiceItemRow, { DetailedServiceItem, ProductCategory } from "@/pages/Vendas/components/ServiceItemRow";
import CustomizedServiceBlock, { CustomizedRegionItem, createInitialCustomItems } from "@/pages/Vendas/components/CustomizedServiceBlock";
import NewVehicleModal from "@/pages/Vendas/components/NewVehicleModal";
import NewClientModal from "@/pages/Vendas/components/NewClientModal";
import { validateUpload, sanitizeFilename } from "@/lib/uploadValidator";

interface EditSlotModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSlotUpdated?: () => void;
  space: any;
}

interface ClientVehicle {
  id: number;
  brand: string;
  model: string;
  plate: string | null;
  year: number | null;
  size: string | null;
}

interface VehicleRegion {
  id: number;
  category: string;
  name: string;
  description: string | null;
  fixed_price: number | null;
  region_code?: string | null;
}

export function EditSlotModal({ open, onOpenChange, onSlotUpdated, space }: EditSlotModalProps) {
  const { user } = useAuth();
  const queryClient = useQueryClient();
  const companyId = user?.companyId;

  // Form state
  const [slotName, setSlotName] = useState(space?.name || "");
  const [selectedClientId, setSelectedClientId] = useState<string>(space?.client_id ? space.client_id.toString() : "");
  const [selectedVehicleId, setSelectedVehicleId] = useState<string>(space?.vehicle_id ? space.vehicle_id.toString() : "");
  const [entryDate, setEntryDate] = useState<Date>(space?.entry_date ? parseISO(space.entry_date) : new Date());
  const [entryTime, setEntryTime] = useState(space?.entry_time || format(new Date(), 'HH:mm'));
  const [isEntryCalendarOpen, setIsEntryCalendarOpen] = useState(false);
  const [exitDate, setExitDate] = useState<Date | undefined>(space?.exit_date ? parseISO(space.exit_date) : undefined);
  const [exitTime, setExitTime] = useState(space?.exit_time || "");
  const [isExitCalendarOpen, setIsExitCalendarOpen] = useState(false);
  const [discount, setDiscount] = useState<number>(space?.discount || 0);
  const [discountPercent, setDiscountPercent] = useState<number>(0);
  const [discountType, setDiscountType] = useState<'fixed' | 'percent'>('fixed');
  const [observations, setObservations] = useState(space?.observations || "");
  const [tag, setTag] = useState(space?.tag || "");
  const [photos, setPhotos] = useState<File[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Detailed services state
  const [detailedItems, setDetailedItems] = useState<DetailedServiceItem[]>([]);
  const [customizedGroups, setCustomizedGroups] = useState<Map<string, CustomizedRegionItem[]>>(new Map());

  // New vehicle modal
  const [showNewVehicleModal, setShowNewVehicleModal] = useState(false);
  const [showNewClientModal, setShowNewClientModal] = useState(false);

  // Toggle states for optional fields
  const [showDiscount, setShowDiscount] = useState(false);
  const [showObservations, setShowObservations] = useState(false);
  const [showTag, setShowTag] = useState(false);

  // Fetch clients
  const { data: clients, isLoading: loadingClients, refetch: refetchClients } = useQuery({
    queryKey: ['clients-for-slot', companyId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('clients')
        .select('id, name, phone, birth_date')
        .eq('company_id', companyId)
        .order('name');
      if (error) throw error;
      return data;
    },
    enabled: !!companyId && open,
  });

  // Fetch client's vehicles
  const { data: clientVehicles, isLoading: loadingVehicles, refetch: refetchVehicles } = useQuery({
    queryKey: ['client-vehicles', selectedClientId, companyId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('vehicles')
        .select('id, brand, model, plate, year, size')
        .eq('client_id', parseInt(selectedClientId))
        .eq('company_id', companyId);
      if (error) throw error;
      return data as ClientVehicle[];
    },
    enabled: !!selectedClientId && !!companyId,
  });

  // Fetch product types for services
  const { data: productTypes } = useQuery({
    queryKey: ['product-types', companyId],
    queryFn: async () => {
      // 1. Fetch materials (bobinas) from stock
      const { data: materialsData, error: materialsError } = await supabase
        .from('materials')
        .select('product_type_id, is_open_roll')
        .eq('company_id', companyId)
        .eq('is_active', true);

      if (materialsError) throw materialsError;

      // 2. Fetch product types
      const { data: productsData, error: productsError } = await supabase
        .from('product_types')
        .select('id, category, brand, name, model, light_transmission, unit_price')
        .eq('company_id', companyId)
        .eq('is_active', true);

      if (productsError) throw productsError;

      // 3. Map stock to products
      const materialsList = materialsData || [];
      const enrichedProducts = (productsData || []).map(pt => {
        const ptMaterials = materialsList.filter(m => m.product_type_id === pt.id);
        const openRolls = ptMaterials.filter(m => m.is_open_roll);
        const closedRolls = ptMaterials.filter(m => !m.is_open_roll);
        return {
          ...pt,
          openRollsCount: openRolls.length,
          hasClosedRoll: closedRolls.length > 0
        };
      });

      return enrichedProducts;
    },
    enabled: !!companyId && open,
  });

  // Fetch vehicle regions (services) with fixed_price
  const { data: vehicleRegions } = useQuery({
    queryKey: ['vehicle-regions-with-price', companyId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('vehicle_regions')
        .select('id, category, name, description, fixed_price, region_code')
        .eq('company_id', companyId)
        .eq('is_active', true)
        .order('sort_order');
      if (error) throw error;
      return data as unknown as VehicleRegion[];
    },
    enabled: !!companyId && open,
  });

  // Fetch consumption rules
  const { data: consumptionRules } = useQuery({
    queryKey: ['consumption-rules', companyId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('region_consumption_rules')
        .select('id, category, region_id, vehicle_size, meters_consumed')
        .eq('company_id', companyId);
      if (error) throw error;
      return data as any[];
    },
    enabled: !!companyId && open,
  });

  // Get selected data
  const selectedClient = clients?.find(c => c.id === parseInt(selectedClientId));
  const selectedVehicle = clientVehicles?.find(v => v.id === parseInt(selectedVehicleId));

  const rulesWithRegionCode = (consumptionRules || []).map(rule => {
    const region = vehicleRegions?.find(r => r.id === rule.region_id);
    return { ...rule, region_code: (region as any)?.region_code || null };
  });

  // Calculate totals
  const subtotal = detailedItems.reduce((sum, item) => sum + (item.totalPrice || 0), 0);
  const calculatedDiscount = discountType === 'percent'
    ? (subtotal * (discountPercent / 100))
    : (discount || 0);
  const finalTotal = subtotal - calculatedDiscount;
  const serviceCount = detailedItems.length;

  useEffect(() => {
    if (open && space) {
      setSlotName(space.name || "");
      if (space.client_id) setSelectedClientId(space.client_id.toString());
      if (space.vehicle_id) setSelectedVehicleId(space.vehicle_id.toString());

      if (space.entry_date) setEntryDate(parseISO(space.entry_date));
      if (space.entry_time) setEntryTime(space.entry_time);
      if (space.exit_date) setExitDate(parseISO(space.exit_date));
      if (space.exit_time) setExitTime(space.exit_time);

      if (space.discount) {
        setDiscount(space.discount);
        // calculate percentage based on services total later if needed, but for now fixed
        setDiscountType('fixed');
      }
      if (space.observations) {
        setObservations(space.observations);
        setShowObservations(true);
      }
      if (space.tag) {
        setTag(space.tag);
        setShowTag(true);
      }

      if (space.discount > 0) setShowDiscount(true);

      // Detailed items
      if (space.services_data && Array.isArray(space.services_data)) {
        const loadedItems: DetailedServiceItem[] = [];
        const loadedGroups = new Map<string, CustomizedRegionItem[]>();

        for (const item of space.services_data as any[]) {
          if (item.isCustomized && item.customizationGroup && item.items) {
            const groupId = item.customizationGroup;
            loadedItems.push({
              id: Math.random().toString(36).substr(2, 9),
              category: item.category || 'INSULFILM' as ProductCategory,
              regionId: null,
              regionName: '',
              productTypeId: null,
              productTypeName: '',
              metersUsed: 0,
              totalPrice: item.totalPrice || 0,
              serviceName: '',
              regionCode: null,
              displayName: '',
              isCustomized: true,
              customizationGroup: groupId,
            });
            loadedGroups.set(groupId, item.items.map((gi: any) => ({
              regionCode: gi.regionCode,
              regionLabel: gi.regionLabel,
              productTypeId: gi.productTypeId,
              productTypeName: gi.productTypeName || '',
              metersUsed: gi.metersUsed || 0,
              totalPrice: gi.totalPrice || 0,
            })));
          } else {
            loadedItems.push({
              id: Math.random().toString(36).substr(2, 9),
              category: item.category || 'INSULFILM' as ProductCategory,
              regionId: item.regionId || null,
              regionName: item.regionName || '',
              productTypeId: item.productTypeId || null,
              productTypeName: item.productTypeName || '',
              metersUsed: item.metersUsed || 0,
              totalPrice: item.totalPrice || 0,
              serviceName: item.serviceName || '',
              regionCode: item.regionCode || null,
              displayName: item.displayName || '',
              isCustomized: false,
              customizationGroup: null,
            });
          }
        }
        setDetailedItems(loadedItems);
        setCustomizedGroups(loadedGroups);
      }
    }
  }, [open, space]);

  // Reset vehicle and services when client changes
  useEffect(() => {
    setDetailedItems([]);
    setSelectedVehicleId("");
  }, [selectedClientId]);

  // Auto-select vehicle if there is exactly 1
  useEffect(() => {
    if (clientVehicles && clientVehicles.length === 1 && !selectedVehicleId) {
      setSelectedVehicleId(clientVehicles[0].id.toString());
    }
  }, [clientVehicles]);

  // Handle adding a new detailed service item
  const handleAddDetailedItem = () => {
    const newItem: DetailedServiceItem = {
      id: Math.random().toString(36).substr(2, 9),
      category: "INSULFILM" as ProductCategory,
      regionId: null,
      regionName: "",
      productTypeId: null,
      productTypeName: "",
      metersUsed: 0,
      totalPrice: 0,
      serviceName: "",
      regionCode: null,
      displayName: "",
      isCustomized: false,
      customizationGroup: null,
    };
    setDetailedItems([...detailedItems, newItem]);
  };

  // Toggle customized mode
  const handleToggleCustomize = (itemId: string) => {
    const item = detailedItems.find(i => i.id === itemId);
    if (!item || (item.isCustomized && item.customizationGroup)) return;

    const groupId = Math.random().toString(36).substr(2, 9);
    const initialItems = createInitialCustomItems(
      selectedVehicle?.size || null,
      consumptionRules || [],
      item.productTypeId,
      item.productTypeName,
      item.regionId
    );

    setDetailedItems(prev =>
      prev.map(i =>
        i.id === itemId
          ? { ...i, isCustomized: true, customizationGroup: groupId }
          : i
      )
    );
    setCustomizedGroups(prev => new Map(prev).set(groupId, initialItems));
  };

  const handleRevertToSimple = (itemId: string, groupId: string) => {
    setDetailedItems(prev =>
      prev.map(i =>
        i.id === itemId
          ? { ...i, isCustomized: false, customizationGroup: null, productTypeId: null, productTypeName: "" }
          : i
      )
    );
    setCustomizedGroups(prev => {
      const next = new Map(prev);
      next.delete(groupId);
      return next;
    });
  };

  const handleUpdateCustomizedItems = (groupId: string, items: CustomizedRegionItem[]) => {
    setCustomizedGroups(prev => new Map(prev).set(groupId, items));
  };

  // Handle updating a detailed service item with fixed_price support
  const handleUpdateDetailedItem = (updatedItem: DetailedServiceItem) => {
    // If region changed, apply fixed_price if available
    const region = vehicleRegions?.find(r => r.id === updatedItem.regionId);
    if (region?.fixed_price && region.fixed_price > 0 && updatedItem.totalPrice === 0) {
      updatedItem = { ...updatedItem, totalPrice: region.fixed_price };
    }

    setDetailedItems(prev =>
      prev.map(item => item.id === updatedItem.id ? updatedItem : item)
    );
  };

  // Update customized group price
  const handleUpdateCustomizedPrice = (itemId: string, newPrice: number) => {
    setDetailedItems(prev =>
      prev.map(i => i.id === itemId ? { ...i, totalPrice: newPrice } : i)
    );
  };

  // Handle removing a detailed service item
  const handleRemoveDetailedItem = (itemId: string) => {
    setDetailedItems(items => items.filter(item => item.id !== itemId));
  };

  const handlePhotoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles = Array.from(e.target.files);

      const validFiles: File[] = [];
      for (const file of newFiles) {
        const validation = validateUpload(file, {
          type: 'checklist-photo',
          maxFiles: 20,
          currentFiles: photos.length + validFiles.length
        });

        if (!validation.valid) {
          toast.error(`Falha em ${file.name}: ${validation.error}`);
          continue;
        }
        validFiles.push(file);
      }

      setPhotos([...photos, ...validFiles]);
    }
  };

  // Handle new vehicle created
  const handleVehicleCreated = async (vehicleData: any) => {
    try {
      const { data, error } = await supabase
        .from('vehicles')
        .insert({
          client_id: parseInt(selectedClientId),
          brand: vehicleData.brand,
          model: vehicleData.model,
          plate: vehicleData.plate,
          year: vehicleData.year,
          size: vehicleData.size,
          company_id: companyId,
        })
        .select()
        .single();

      if (error) throw error;

      toast.success("Veículo cadastrado com sucesso!");
      refetchVehicles();
      setSelectedVehicleId(data.id.toString());
      setShowNewVehicleModal(false);
    } catch (error) {
      console.error("Erro ao cadastrar veículo:", error);
      toast.error("Erro ao cadastrar veículo");
    }
  };

  // Mutation to update space
  const updateMutation = useMutation({
    mutationFn: async () => {
      if (!companyId || !selectedClientId || !selectedVehicleId) {
        throw new Error("Dados inválidos");
      }

      // Update space
      const { data: spaceData, error: spaceError } = await supabase
        .from('spaces')
        .update({
          name: slotName || `Vaga de ${selectedClient?.name}`,
          client_id: parseInt(selectedClientId),
          vehicle_id: parseInt(selectedVehicleId),
          entry_date: format(entryDate, 'yyyy-MM-dd'),
          entry_time: entryTime,
          exit_date: exitDate ? format(exitDate, 'yyyy-MM-dd') : null,
          exit_time: exitTime || null,
          discount: calculatedDiscount || null,
          observations: observations || null,
          tag: tag || null,
        })
        .eq('id', space.id)
        .select()
        .single();

      if (spaceError) throw spaceError;

      // Save services data as JSONB
      if (detailedItems.length > 0) {
        const servicesData: any[] = [];
        for (const item of detailedItems) {
          if (item.isCustomized && item.customizationGroup) {
            const groupItems = customizedGroups.get(item.customizationGroup) || [];
            servicesData.push({
              category: item.category,
              isCustomized: true,
              customizationGroup: item.customizationGroup,
              totalPrice: item.totalPrice || 0,
              items: groupItems.map(gi => ({
                regionCode: gi.regionCode,
                regionLabel: gi.regionLabel,
                productTypeId: gi.productTypeId,
                productTypeName: gi.productTypeName,
                metersUsed: gi.metersUsed,
                totalPrice: gi.totalPrice,
              })),
            });
          } else {
            const region = (vehicleRegions || []).find(r => r.id === item.regionId);
            servicesData.push({
              category: item.category,
              regionId: item.regionId,
              regionName: item.regionName || 'Serviço',
              productTypeId: item.productTypeId,
              productTypeName: item.productTypeName || '',
              totalPrice: item.totalPrice || 0,
              metersUsed: item.metersUsed || 0,
              serviceName: item.serviceName || item.regionName,
              regionCode: region?.region_code || null,
              displayName: item.displayName || `${item.regionName} • ${item.productTypeName}`,
              isCustomized: false,
            });
          }
        }

        await supabase
          .from('spaces')
          .update({ services_data: servicesData } as any)
          .eq('id', spaceData.id);
      }

      // Upload photos (validated locally, but Storage RLS ensures bounds too)
      if (photos.length > 0) {
        for (let i = 0; i < photos.length; i++) {
          const photo = photos[i];
          const fileExt = photo.name.split('.').pop() || 'jpg';
          const sanitizedName = sanitizeFilename(photo.name.replace(`.${fileExt}`, ''));
          const fileName = `${Date.now()}_${i}_${sanitizedName}.${fileExt}`;
          const filePath = `${companyId}/${spaceData.id}/${fileName}`;

          const { error: uploadError } = await supabase.storage
            .from('checklists')
            .upload(filePath, photo, { upsert: true });

          if (uploadError) {
            console.error("Erro no upload da foto", photo.name, uploadError);
          }
        }
      }

      return spaceData;
    },
    onSuccess: () => {
      toast.success("Vaga atualizada com sucesso!");
      queryClient.invalidateQueries({ queryKey: ['spaces'] });
      onSlotUpdated?.();
      onOpenChange(false);
    },
    onError: (error) => {
      console.error("Erro ao criar vaga:", error);
      toast.error("Erro ao preencher vaga");
    },
  });

  const handleSubmit = () => {
    if (!selectedClientId) {
      toast.error("Selecione um cliente");
      return;
    }
    if (!selectedVehicleId) {
      toast.error("Selecione um veículo");
      return;
    }
    if (!entryDate || !entryTime) {
      toast.error("Informe a data e hora de entrada");
      return;
    }
    updateMutation.mutate();
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Editar vaga</DialogTitle>
          <DialogDescription>Edite os dados desta vaga</DialogDescription>
        </DialogHeader>

        <div className="space-y-6">
          {/* Nome da vaga */}
          <div className="space-y-2">
            <Label>Nome da vaga (opcional)</Label>
            <Input
              value={slotName}
              onChange={(e) => setSlotName(e.target.value)}
              placeholder="Ex: Vaga 1, Box A, etc."
            />
          </div>

          {/* Cliente */}
          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <Label>Cliente *</Label>
              <Button
                variant="default"
                size="sm"
                onClick={() => setShowNewClientModal(true)}
                className="h-8 text-xs bg-green-600 hover:bg-green-700 text-white border-0"
              >
                <Plus className="h-3 w-3 mr-1" />
                Novo
              </Button>
            </div>
            <Select value={selectedClientId} onValueChange={setSelectedClientId}>
              <SelectTrigger>
                <SelectValue placeholder={loadingClients ? "Carregando..." : "Selecione um cliente"} />
              </SelectTrigger>
              <SelectContent>
                {clients?.map(client => (
                  <SelectItem key={client.id} value={client.id.toString()}>
                    <div className="flex items-center gap-2">
                      <User className="h-4 w-4 text-muted-foreground" />
                      <span>{client.name}</span>
                      {client.phone && (
                        <span className="text-muted-foreground text-xs">({client.phone})</span>
                      )}
                    </div>
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Veículo */}
          {selectedClientId && (
            <div className="space-y-2">
              <Label>Veículo *</Label>
              {loadingVehicles ? (
                <div className="flex items-center justify-center py-4">
                  <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
                </div>
              ) : (
                <div className="flex gap-2">
                  <Select value={selectedVehicleId} onValueChange={setSelectedVehicleId}>
                    <SelectTrigger className="flex-1">
                      <SelectValue placeholder="Selecione um veículo" />
                    </SelectTrigger>
                    <SelectContent>
                      {clientVehicles && clientVehicles.length > 0 ? (
                        clientVehicles.map(vehicle => (
                          <SelectItem key={vehicle.id} value={vehicle.id.toString()}>
                            <div className="flex items-center gap-2">
                              <Car className="h-4 w-4 text-muted-foreground" />
                              <span>{vehicle.brand} {vehicle.model}</span>
                              {vehicle.plate && (
                                <Badge variant="outline" className="text-xs">{vehicle.plate}</Badge>
                              )}
                            </div>
                          </SelectItem>
                        ))
                      ) : (
                        <SelectItem value="none" disabled>
                          Nenhum veículo cadastrado
                        </SelectItem>
                      )}
                    </SelectContent>
                  </Select>
                  <Button
                    variant="default"
                    onClick={() => setShowNewVehicleModal(true)}
                    className="h-8 text-xs bg-green-600 hover:bg-green-700 text-white border-0"
                  >
                    <Plus className="h-4 w-4 mr-1" /> Novo
                  </Button>
                </div>
              )}
            </div>
          )}

          {/* Serviços Detalhados */}
          {selectedVehicleId && (
            <div className="space-y-3">
              <div className="flex items-center justify-between">
                <Label>Serviços</Label>
                <Button
                  variant="default"
                  size="sm"
                  onClick={handleAddDetailedItem}
                  className="gap-2 bg-blue-600 hover:bg-blue-700 text-white border-0"
                >
                  <Plus className="h-4 w-4 mr-1" /> Adicionar Serviço
                </Button>
              </div>

              {detailedItems.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-4">
                  Clique em "Adicionar Serviço" para incluir serviços na vaga
                </p>
              ) : (
                <div className="space-y-2">
                  {detailedItems.map(item => (
                    <div key={item.id} className="space-y-2">
                      {item.isCustomized && item.customizationGroup ? (
                        <CustomizedServiceBlock
                          groupId={item.customizationGroup}
                          items={customizedGroups.get(item.customizationGroup) || []}
                          productTypes={productTypes || []}
                          vehicleSize={selectedVehicle?.size || null}
                          consumptionRules={rulesWithRegionCode}
                          servicePrice={item.totalPrice}
                          onUpdate={(items) => handleUpdateCustomizedItems(item.customizationGroup!, items)}
                          onRevertToSimple={() => handleRevertToSimple(item.id, item.customizationGroup!)}
                          onPriceChange={(price) => handleUpdateCustomizedPrice(item.id, price)}
                        />
                      ) : (
                        <div className="flex items-center gap-2">
                          <div className="flex-1">
                            <ServiceItemRow
                              item={item}
                              vehicleSize={selectedVehicle?.size || null}
                              productTypes={productTypes || []}
                              vehicleRegions={vehicleRegions || []}
                              consumptionRules={rulesWithRegionCode}
                              onUpdate={handleUpdateDetailedItem}
                              onRemove={handleRemoveDetailedItem}
                            />
                          </div>
                          {item.category === 'INSULFILM' && item.regionCode === 'SIDE_REAR' && (
                            <Button
                              type="button"
                              variant="outline"
                              size="icon"
                              className="h-8 w-8 shrink-0"
                              onClick={() => handleToggleCustomize(item.id)}
                              title="Personalizar"
                            >
                              <Sliders className="h-4 w-4" />
                            </Button>
                          )}
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              )}

              {detailedItems.length > 0 && (
                <div className="flex justify-end">
                  <Badge variant="secondary">
                    {serviceCount} serviço(s) - R$ {subtotal.toFixed(2)}
                  </Badge>
                </div>
              )}
            </div>
          )}

          {/* Datas de entrada e saída */}
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label className="flex items-center gap-2">
                <CalendarIcon className="h-4 w-4" />
                Dia da entrada *
              </Label>
              <Popover open={isEntryCalendarOpen} onOpenChange={setIsEntryCalendarOpen}>
                <PopoverTrigger asChild>
                  <Button
                    variant="outline"
                    className="w-full justify-start text-left font-normal"
                  >
                    <CalendarIcon className="mr-2 h-4 w-4" />
                    {format(entryDate, "dd 'de' MMMM 'de' yyyy", { locale: ptBR })}
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0" align="start">
                  <CalendarPicker
                    mode="single"
                    selected={entryDate}
                    onSelect={(date) => {
                      if (date) {
                        setEntryDate(date);
                        setIsEntryCalendarOpen(false);
                      }
                    }}
                    initialFocus
                    className="p-3 pointer-events-auto"
                  />
                </PopoverContent>
              </Popover>
            </div>
            <div className="space-y-2">
              <Label className="flex items-center gap-2">
                <Clock className="h-4 w-4" />
                Hora da entrada *
              </Label>
              <Input
                type="time"
                value={entryTime}
                onChange={(e) => setEntryTime(e.target.value)}
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label className="flex items-center gap-2">
                <CalendarIcon className="h-4 w-4" />
                Dia da saída (previsão)
              </Label>
              <Popover open={isExitCalendarOpen} onOpenChange={setIsExitCalendarOpen}>
                <PopoverTrigger asChild>
                  <Button
                    variant="outline"
                    className={cn(
                      "w-full justify-start text-left font-normal",
                      !exitDate && "text-muted-foreground"
                    )}
                  >
                    <CalendarIcon className="mr-2 h-4 w-4" />
                    {exitDate
                      ? format(exitDate, "dd 'de' MMMM 'de' yyyy", { locale: ptBR })
                      : "Selecione uma data"}
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0" align="start">
                  <CalendarPicker
                    mode="single"
                    selected={exitDate}
                    onSelect={(date) => {
                      setExitDate(date);
                      setIsExitCalendarOpen(false);
                    }}
                    initialFocus
                    className="p-3 pointer-events-auto"
                  />
                </PopoverContent>
              </Popover>
            </div>
            <div className="space-y-2">
              <Label className="flex items-center gap-2">
                <Clock className="h-4 w-4" />
                Hora da saída
              </Label>
              <Input
                type="time"
                value={exitTime}
                onChange={(e) => setExitTime(e.target.value)}
              />
            </div>
          </div>

          {/* Fotos de checklist */}
          <div className="space-y-2">
            <div className="flex justify-between items-center">
              <Label className="flex items-center gap-2">
                <Camera className="h-4 w-4" />
                Fotos de checklist
              </Label>
              <span className="text-xs text-muted-foreground">{photos.length}/20</span>
            </div>
            <p className="text-sm text-muted-foreground">Opcional: Adicione fotos para referenciar a avaria ou condição de recebimento do veículo.</p>

            {photos.length > 0 && (
              <div className="flex gap-2 overflow-x-auto overscroll-x-contain pb-2">
                {photos.map((photo, index) => (
                  <div key={index} className="relative min-w-[80px] h-[80px] rounded border overflow-hidden shrink-0">
                    <img src={URL.createObjectURL(photo)} alt={`Foto ${index + 1}`} className="w-full h-full object-cover" />
                    <button
                      type="button"
                      onClick={() => setPhotos(photos.filter((_, i) => i !== index))}
                      className="absolute top-1 right-1 bg-black/50 hover:bg-black p-1 rounded-full text-white transition-colors"
                    >
                      <X className="h-3 w-3" />
                    </button>
                  </div>
                ))}
              </div>
            )}

            <input
              type="file"
              multiple
              accept="image/png, image/jpeg, image/webp, image/heic"
              className="hidden"
              ref={fileInputRef}
              onChange={handlePhotoSelect}
            />
            <Button
              variant="outline"
              className="w-full"
              onClick={() => fileInputRef.current?.click()}
              disabled={photos.length >= 20}
              type="button"
            >
              <Plus className="h-4 w-4 mr-2" />
              Carregar nova foto
            </Button>
          </div>

          {/* Campos opcionais */}
          <div className="space-y-2">
            <Label>Campos opcionais</Label>
            <div className="flex gap-2 flex-wrap">
              <Button
                variant={showDiscount ? "default" : "outline"}
                size="sm"
                onClick={() => setShowDiscount(!showDiscount)}
              >
                <DollarSign className="h-4 w-4 mr-1" />
                Desconto
              </Button>
              <Button
                variant={showObservations ? "default" : "outline"}
                size="sm"
                onClick={() => setShowObservations(!showObservations)}
              >
                <FileText className="h-4 w-4 mr-1" />
                Observações
              </Button>
              <Button
                variant={showTag ? "default" : "outline"}
                size="sm"
                onClick={() => setShowTag(!showTag)}
              >
                <Tag className="h-4 w-4 mr-1" />
                Tag
              </Button>
            </div>
          </div>

          {/* Campos opcionais expandidos */}
          {showDiscount && (
            <div className="space-y-3">
              {/* Seleção do tipo de desconto */}
              <div className="flex gap-2">
                <Card
                  className={`flex-1 cursor-pointer transition-all ${discountType === 'fixed'
                    ? "border-primary bg-primary/10"
                    : "border-border/50 hover:border-muted-foreground"
                    }`}
                  onClick={() => setDiscountType('fixed')}
                >
                  <CardContent className="p-3 text-center">
                    <DollarSign className="h-5 w-5 mx-auto mb-1" />
                    <span className="text-sm font-medium">Valor (R$)</span>
                  </CardContent>
                </Card>

                <Card
                  className={`flex-1 cursor-pointer transition-all ${discountType === 'percent'
                    ? "border-primary bg-primary/10"
                    : "border-border/50 hover:border-muted-foreground"
                    }`}
                  onClick={() => setDiscountType('percent')}
                >
                  <CardContent className="p-3 text-center">
                    <Percent className="h-5 w-5 mx-auto mb-1" />
                    <span className="text-sm font-medium">Percentual (%)</span>
                  </CardContent>
                </Card>
              </div>

              {/* Input baseado no tipo selecionado */}
              {discountType === 'fixed' ? (
                <div className="space-y-2">
                  <Label>Desconto (R$)</Label>
                  <Input
                    type="number"
                    value={discount || ""}
                    onChange={(e) => setDiscount(parseFloat(e.target.value) || 0)}
                    placeholder="0.00"
                  />
                </div>
              ) : (
                <div className="space-y-2">
                  <Label>Desconto (%)</Label>
                  <Input
                    type="number"
                    value={discountPercent || ""}
                    onChange={(e) => setDiscountPercent(parseFloat(e.target.value) || 0)}
                    placeholder="0"
                    max={100}
                  />
                  {discountPercent > 0 && subtotal > 0 && (
                    <p className="text-xs text-muted-foreground">
                      = R$ {(subtotal * (discountPercent / 100)).toFixed(2)} de desconto
                    </p>
                  )}
                </div>
              )}
            </div>
          )}

          {showObservations && (
            <div className="space-y-2">
              <Label>Observações</Label>
              <Textarea
                value={observations}
                onChange={(e) => setObservations(e.target.value)}
                placeholder="Observações sobre a vaga..."
              />
            </div>
          )}

          {showTag && (
            <div className="space-y-2">
              <Label>Tag</Label>
              <Select value={tag} onValueChange={setTag}>
                <SelectTrigger>
                  <SelectValue placeholder="Selecione uma tag" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="Em andamento">Em andamento</SelectItem>
                  <SelectItem value="Pausado">Pausado</SelectItem>
                  <SelectItem value="Em espera">Em espera</SelectItem>
                  <SelectItem value="Finalizado">Finalizado</SelectItem>
                </SelectContent>
              </Select>
            </div>
          )}

          {/* Resumo da vaga */}
          {selectedVehicleId && (
            <Card className="bg-muted/30 border-border/50">
              <CardContent className="p-4 space-y-2">
                <h4 className="font-medium">Resumo da vaga</h4>
                <div className="space-y-1 text-sm">
                  <p className="flex items-center gap-2">
                    <User className="h-4 w-4 text-muted-foreground" />
                    <span>{selectedClient?.name}</span>
                  </p>
                  <p className="flex items-center gap-2">
                    <Car className="h-4 w-4 text-muted-foreground" />
                    <span>{selectedVehicle?.brand} {selectedVehicle?.model} {selectedVehicle?.plate && `- ${selectedVehicle.plate}`}</span>
                  </p>
                  <p className="flex items-center gap-2">
                    <Package className="h-4 w-4 text-muted-foreground" />
                    <span>{serviceCount} serviço(s) adicionado(s)</span>
                  </p>
                  <p className="flex items-center gap-2">
                    <DollarSign className="h-4 w-4 text-muted-foreground" />
                    <span>Sub-total: R$ {subtotal.toFixed(2)}</span>
                  </p>
                  {calculatedDiscount > 0 && (
                    <p className="flex items-center gap-2">
                      <Tag className="h-4 w-4 text-muted-foreground" />
                      <span>
                        Desconto: R$ {calculatedDiscount.toFixed(2)}
                        {discountType === 'percent' && ` (${discountPercent}%)`}
                      </span>
                    </p>
                  )}
                  <p className="flex items-center gap-2 font-medium">
                    <DollarSign className="h-4 w-4 text-primary" />
                    <span className="text-primary">Total: R$ {finalTotal.toFixed(2)}</span>
                  </p>
                  <p className="flex items-center gap-2">
                    <Calendar className="h-4 w-4 text-muted-foreground" />
                    <span>Entrada em {format(new Date(entryDate), "dd/MM/yyyy", { locale: ptBR })}</span>
                  </p>
                </div>
              </CardContent>
            </Card>
          )}

          {/* Botão de ação */}
          <Button
            className="w-full"
            size="lg"
            onClick={handleSubmit}
            disabled={updateMutation.isPending || !selectedClientId || !selectedVehicleId}
          >
            {updateMutation.isPending ? (
              <Loader2 className="h-5 w-5 animate-spin mr-2" />
            ) : (
              <Check className="h-5 w-5 mr-2" />
            )}
            Salvar vaga
          </Button>
        </div>
      </DialogContent>

      {/* New Vehicle Modal */}
      <NewVehicleModal
        open={showNewVehicleModal}
        onOpenChange={setShowNewVehicleModal}
        onVehicleCreated={handleVehicleCreated}
      />

      {/* New Client Modal */}
      <NewClientModal
        open={showNewClientModal}
        onOpenChange={setShowNewClientModal}
        onClientCreated={() => {
          refetchClients();
          setShowNewClientModal(false);
        }}
      />
    </Dialog>
  );
}

// @ts-nocheck
import { useState, useEffect } from "react";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { useNavigate } from "react-router-dom";
import { Sheet, SheetContent, SheetHeader, SheetTitle } from "@/components/ui/sheet";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import { Switch } from "@/components/ui/switch";
import { Separator } from "@/components/ui/separator";
import { Textarea } from "@/components/ui/textarea";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import {
  Car, Phone, User, Calendar, Clock, DollarSign, Link2,
  FileText, MessageSquare, Trash2, Edit,
  CheckCircle, Package, AlertCircle, Loader2, Camera, Undo2
} from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { UnpaidExitAlertDialog } from "./UnpaidExitAlertDialog";
import { SpaceWhatsAppModal } from "./SpaceWhatsAppModal";
import { generateSpacePDFA4, generateSpacePDFReceipt } from "@/lib/pdfGenerator";
import { useAuth } from "@/contexts/AuthContext";
import { EditSlotModal } from "./EditSlotModal";
import NewSaleModal from "@/pages/Vendas/components/NewSaleModal";
import { FillSlotModal } from "@/shared/components/espaco/FillSlotModal";
import { createSaleTransaction, reverseAllSaleTransactions } from "@/lib/financialTransactions";
import { ClientProfileModal } from "@/components/clientes/ClientProfileModal";
import { EditClientModal } from "@/components/clientes/EditClientModal";

interface SpaceDetails {
  id: number;
  name: string;
  client_id: number | null;
  vehicle_id: number | null;
  sale_id: number | null;
  entry_date: string | null;
  entry_time: string | null;
  exit_date: string | null;
  exit_time: string | null;
  has_exited: boolean | null;
  payment_status: string | null;
  observations: string | null;
  tag: string | null;
  discount: number | null;
  services_data?: any[];
  deleted_at?: string | null;
  deleted_by?: string | null;
  deleted_reason?: string | null;
  client?: {
    id: number;
    name: string;
    phone: string;
    email?: string | null;
    birth_date: string | null;
  } | null;
  vehicle?: {
    id: number;
    brand: string;
    model: string;
    plate: string | null;
    year: number | null;
  } | null;
  sale?: {
    id: number;
    total: number;
    subtotal: number;
    discount: number | null;
    sale_items?: {
      id: number;
      total_price: number;
      service?: {
        id: number;
        name: string;
      } | null;
    }[];
  } | null;
}

interface SlotDetailsDrawerProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  space: SpaceDetails | null;
  onUpdate?: () => void;
}

export function SlotDetailsDrawer({ open, onOpenChange, space, onUpdate }: SlotDetailsDrawerProps) {
  const { user } = useAuth();
  const companyId = user?.companyId;

  const queryClient = useQueryClient();
  const navigate = useNavigate();
  const [isCompleting, setIsCompleting] = useState(false);
  const [showUnpaidAlert, setShowUnpaidAlert] = useState(false);
  const [isReleasing, setIsReleasing] = useState(false);
  const [whatsAppType, setWhatsAppType] = useState<'entrada' | 'saida'>('entrada');
  const [showWhatsApp, setShowWhatsApp] = useState(false);
  const [checklistPhotos, setChecklistPhotos] = useState<{ name: string, url: string }[]>([]);
  const [isLoadingPhotos, setIsLoadingPhotos] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showExportSaleModal, setShowExportSaleModal] = useState(false);

  // Fetch photos
  useEffect(() => {
    async function fetchPhotos() {
      if (!open || !space || !companyId) return;
      setIsLoadingPhotos(true);
      try {
        const { data, error } = await supabase.storage
          .from('checklists')
          .list(`${companyId}/${space.id}`);

        if (data && !error) {
          const files = data.filter(f => f.name !== '.emptyFolderPlaceholder');
          const urls = await Promise.all(
            files.map(async file => {
              const { data } = await supabase.storage
                .from('checklists')
                .createSignedUrl(`${companyId}/${space.id}/${file.name}`, 3600);
              return { name: file.name, url: data?.signedUrl || '' };
            })
          );
          setChecklistPhotos(urls.filter(u => u.url !== ''));
        } else {
          setChecklistPhotos([]);
        }
      } catch (err) {
        console.error("Erro ao carregar fotos", err);
      } finally {
        setIsLoadingPhotos(false);
      }
    }

    if (open) {
      fetchPhotos();
    } else {
      setChecklistPhotos([]);
    }
  }, [open, space?.id, companyId]);

  // Complete slot mutation (for paid vehicles or reopening)
  const completeMutation = useMutation({
    mutationFn: async (completed: boolean) => {
      if (!space) return;
      const updateData: any = {
        has_exited: completed,
      };

      if (completed) {
        updateData.exit_date = format(new Date(), 'yyyy-MM-dd');
        updateData.exit_time = format(new Date(), 'HH:mm');
      }

      const { error } = await supabase
        .from('spaces')
        .update(updateData)
        .eq('id', space.id);

      if (error) throw error;

      if (completed && space.payment_status === 'paid' && space.sale_id) {
        const { error: saleError } = await supabase
          .from('sales')
          .update({ is_open: false, status: 'Fechada' })
          .eq('id', space.sale_id);

        if (saleError) throw saleError;
      }
    },
    onMutate: async (completed: boolean) => {
      await queryClient.cancelQueries({ queryKey: ['spaces'] });

      queryClient.setQueriesData({ queryKey: ['spaces'] }, (old: any) => {
        if (!old) return old;
        return old.map((s: any) => s.id === space?.id ? {
          ...s,
          has_exited: completed,
          exit_date: completed ? format(new Date(), 'yyyy-MM-dd') : s.exit_date,
          exit_time: completed ? format(new Date(), 'HH:mm') : s.exit_time,
        } : s);
      });
      return {};
    },
    onSuccess: () => {
      toast.success(isCompleting ? "Vaga liberada!" : "Vaga reaberta!");
      queryClient.invalidateQueries({ queryKey: ['spaces'] });
      onUpdate?.();
    },
    onError: (error) => {
      console.error("Erro ao atualizar vaga:", error);
      toast.error("Erro ao atualizar vaga");
    },
  });



  const [profileLoading, setProfileLoading] = useState(false);
  const [profileClient, setProfileClient] = useState<any>(null);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [showEditClientModal, setShowEditClientModal] = useState(false);
  const [showNewSaleModal, setShowNewSaleModal] = useState(false);
  const [showNewSlotModal, setShowNewSlotModal] = useState(false);
  const [clientToDelete, setClientToDelete] = useState<any>(null);

  const handleOpenClientProfile = async () => {
    if (!space?.client_id) return;
    setProfileLoading(true);

    try {
      const { data: clientData, error: clientError } = await supabase
        .from("clients")
        .select("id, name, phone, email, cpf_cnpj, birth_date, cep, street, number, complement, neighborhood, city, state, origem, created_at, company_id")
        .eq("id", space.client_id)
        .single();

      if (clientError) throw clientError;

      const { data: vehiclesData } = await supabase
        .from("vehicles")
        .select("id, brand, model, plate, year, size, client_id, created_at")
        .eq("client_id", space.client_id);

      const { data: salesData } = await supabase
        .from("sales")
        .select("total")
        .eq("client_id", space.client_id);

      const totalSpent = (salesData || []).reduce((sum, s) => sum + (s.total || 0), 0);

      const fullClient = {
        ...clientData,
        vehicles: vehiclesData || [],
        total_spent: totalSpent,
        sales_count: (salesData || []).length,
        created_at: clientData?.created_at || new Date().toISOString()
      };

      setProfileClient(fullClient);
      setShowProfileModal(true);
    } catch (error) {
      console.error(error);
      toast.error("Falha ao carregar perfil do cliente");
    } finally {
      setProfileLoading(false);
    }
  };

  const confirmDeleteClient = async () => {
    if (!clientToDelete) return;
    try {
      const { error } = await supabase
        .from('clients')
        .update({ deleted_at: new Date().toISOString() } as any)
        .eq('id', clientToDelete.id);

      if (error) throw error;

      toast.success("Cliente excluído com sucesso!");
      setClientToDelete(null);
      setProfileClient(null);
      queryClient.invalidateQueries({ queryKey: ['spaces'] });
    } catch (error) {
      console.error(error);
      toast.error("Falha ao excluir cliente.");
    }
  };

  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
  const [deleteReason, setDeleteReason] = useState("");
  const [isPermanentDeleteDialogOpen, setIsPermanentDeleteDialogOpen] = useState(false);

  // Fetch deleter user profile if space is deleted
  const { data: deleterProfile } = useQuery({
    queryKey: ['profile-deleter-space', space?.deleted_by],
    queryFn: async () => {
      if (!space?.deleted_by) return null;
      const { data, error } = await supabase
        .from('profiles')
        .select('name')
        .eq('user_id', space.deleted_by)
        .maybeSingle();
      if (error) {
        console.error('Error fetching deleter profile:', error);
        return null;
      }
      return data;
    },
    enabled: !!space?.deleted_by && open,
  });

  // Soft Delete space mutation
  const softDeleteMutation = useMutation({
    mutationFn: async (reason: string) => {
      if (!space) return;
      const { error } = await supabase.rpc('soft_delete_space' as any, {
        p_space_id: space.id,
        p_reason: reason.trim() || "Nenhum motivo informado."
      });
      if (error) throw error;
    },
    onSuccess: () => {
      toast.success("Vaga movida para a lixeira!");
      queryClient.invalidateQueries({ queryKey: ['spaces'] });
      queryClient.invalidateQueries({ queryKey: ['spaces-deleted'] });
      queryClient.invalidateQueries({ queryKey: ['unpaid-exited-count'] });
      onOpenChange(false);
      onUpdate?.();
    },
    onError: (error) => {
      console.error("Erro ao excluir vaga:", error);
      toast.error("Erro ao enviar vaga para a lixeira");
    },
  });

  // Restore space mutation
  const restoreMutation = useMutation({
    mutationFn: async () => {
      if (!space) return;
      const { error } = await supabase.rpc('restore_space' as any, {
        p_space_id: space.id
      });
      if (error) throw error;
    },
    onSuccess: () => {
      toast.success("Vaga restaurada com sucesso!");
      queryClient.invalidateQueries({ queryKey: ['spaces'] });
      queryClient.invalidateQueries({ queryKey: ['spaces-deleted'] });
      queryClient.invalidateQueries({ queryKey: ['unpaid-exited-count'] });
      onOpenChange(false);
      onUpdate?.();
    },
    onError: (error) => {
      console.error("Erro ao restaurar vaga:", error);
      toast.error("Erro ao restaurar vaga");
    },
  });

  // Permanent delete space mutation
  const permanentDeleteMutation = useMutation({
    mutationFn: async () => {
      if (!space) return;
      const { error } = await supabase.rpc('permanently_delete_space' as any, {
        p_space_id: space.id
      });
      if (error) throw error;
    },
    onSuccess: () => {
      toast.success("Vaga excluída permanentemente!");
      queryClient.invalidateQueries({ queryKey: ['spaces'] });
      queryClient.invalidateQueries({ queryKey: ['spaces-deleted'] });
      queryClient.invalidateQueries({ queryKey: ['unpaid-exited-count'] });
      onOpenChange(false);
      onUpdate?.();
    },
    onError: (error) => {
      console.error("Erro ao excluir permanentemente:", error);
      toast.error("Erro ao excluir vaga permanentemente");
    },
  });

  // Early return AFTER all hooks
  if (!space) return null;

  const formatDate = (dateStr: string | null) => {
    if (!dateStr) return "-";
    return format(new Date(dateStr + 'T12:00:00'), "dd/MM/yyyy", { locale: ptBR });
  };

  const formatBirthDate = (dateStr: string | null) => {
    if (!dateStr) return null;
    return format(new Date(dateStr + 'T12:00:00'), "dd/MM/yyyy", { locale: ptBR });
  };

  // Get services from sale_items or services_data
  const saleServices = space.sale?.sale_items?.map(item => ({
    name: item.service?.name || 'Serviço',
    price: item.total_price,
  })) || [];

  const jsonServices: { name: string; price: number }[] = [];
  for (const s of ((space as any).services_data || []) as any[]) {
    if (s.isCustomized && s.items && Array.isArray(s.items)) {
      for (const gi of s.items) {
        jsonServices.push({
          name: `${gi.regionLabel || 'Região'}${gi.productTypeName ? ` • ${gi.productTypeName}` : ''}`,
          price: gi.totalPrice || 0,
        });
      }
    } else {
      jsonServices.push({
        name: s.displayName || s.regionName || 'Serviço',
        price: s.totalPrice || 0,
      });
    }
  }

  const services = saleServices.length > 0 ? saleServices : jsonServices;

  // Calculate totals
  const subtotal = space.sale?.subtotal || services.reduce((sum: number, s: any) => sum + s.price, 0);
  const discount = space.discount || space.sale?.discount || 0;
  const total = subtotal - discount;
  const serviceCount = services.length;

  const handleCompleteToggle = (checked: boolean) => {
    if (checked && space.payment_status !== 'paid') {
      setShowUnpaidAlert(true);
    } else {
      setIsCompleting(checked);
      completeMutation.mutate(checked);
    }
  };

  const handleReleaseWithPayment = async () => {
    if (!space) return;

    if (!space.sale_id) {
      toast.error("Vaga sem venda. Clique em 'Exportar Venda' primeiro para garantir o registro financeiro.");
      setShowUnpaidAlert(false);
      setIsCompleting(false);
      return;
    }

    setIsReleasing(true);

    try {
      const { error: spaceError } = await supabase
        .from('spaces')
        .update({
          has_exited: true,
          payment_status: 'paid',
          exit_date: format(new Date(), 'yyyy-MM-dd'),
          exit_time: format(new Date(), 'HH:mm'),
        })
        .eq('id', space.id);

      if (spaceError) throw spaceError;

      const { error: saleError } = await supabase
        .from('sales')
        .update({ is_open: false, status: 'Fechada' })
        .eq('id', space.sale_id);

      if (saleError) throw saleError;

      // Fetch required data for transaction
      const { data: saleData } = await supabase.from('sales').select('id, total, payment_method, sale_date, client_id, company_id').eq('id', space.sale_id).single();
      let clientName = 'Cliente';
      if (saleData?.client_id) {
        const { data: clientData } = await supabase.from('clients').select('name').eq('id', saleData.client_id).single();
        if (clientData) clientName = clientData.name;
      }

      if (saleData) {
        const { data: payments } = await supabase
          .from('sale_payments')
          .select(`
            *,
            card_machines (
              id,
              name,
              debit_rate
            )
          `)
          .eq('sale_id', saleData.id);

        if (payments && payments.length > 0) {
          await reverseAllSaleTransactions(saleData.id, "delete");
          let allSuccess = true;

          for (const p of payments) {
            let finalNetAmount = p.amount;
            if ((p.method === "Crédito" || p.method === "Débito") && p.machine_id) {
              if (p.method === "Débito") {
                const machine = p.card_machines;
                if (machine?.debit_rate) {
                  finalNetAmount = p.amount * (1 - machine.debit_rate / 100);
                }
              } else {
                const { data: rateData } = await supabase
                  .from("card_machine_rates")
                  .select("rate")
                  .eq("machine_id", p.machine_id)
                  .eq("installments", p.installments)
                  .single();
                if (rateData) {
                  finalNetAmount = p.amount * (1 - rateData.rate / 100);
                }
              }
            }

            const tx = await createSaleTransaction({
              saleId: saleData.id,
              saleTotal: p.amount,
              clientName: clientName,
              paymentMethod: p.method,
              saleDate: saleData.sale_date,
              companyId: saleData.company_id,
              accountId: p.account_id,
              isPaid: true,
              salePaymentId: p.id,
              installments: p.installments,
              netAmount: finalNetAmount
            });
            if (!tx) allSuccess = false;
          }

          if (!allSuccess) {
            console.warn("[SlotDetailsDrawer] Falha ao registrar uma ou mais transações financeiras automáticas no fechamento.");
            toast.error("Vaga liberada, mas não foi possível gerar todos os lançamentos financeiros automáticos. Verifique suas contas.");
          }
        } else {
          const tx = await createSaleTransaction({
            saleId: saleData.id,
            saleTotal: saleData.total,
            clientName: clientName,
            paymentMethod: saleData.payment_method || 'Pix',
            saleDate: saleData.sale_date,
            companyId: saleData.company_id,
            isPaid: true
          });
          if (!tx) {
            console.warn("[SlotDetailsDrawer] Falha ao registrar transação financeira automática no fechamento.");
            toast.error("Vaga liberada, mas não foi possível gerar o lançamento financeiro automático. Verifique suas contas.");
          }
        }
      }


      // Optimistic upate
      queryClient.setQueriesData({ queryKey: ['spaces'] }, (old: any) => {
        if (!old) return old;
        return old.map((s: any) => s.id === space?.id ? {
          ...s,
          has_exited: true,
          payment_status: 'paid',
          exit_date: format(new Date(), 'yyyy-MM-dd'),
          exit_time: format(new Date(), 'HH:mm'),
        } : s);
      });

      toast.success("Pagamento confirmado e vaga liberada!");
      queryClient.invalidateQueries({ queryKey: ['spaces'] });
      setShowUnpaidAlert(false);
      onOpenChange(false);
      onUpdate?.();
    } catch (error) {
      console.error("Erro ao liberar com pagamento:", error);
      toast.error("Erro ao processar liberação");
    } finally {
      setIsReleasing(false);
    }
  };

  const handleReleaseWithoutPayment = async () => {
    if (!space) return;
    setIsReleasing(true);

    try {
      const { error: spaceError } = await supabase
        .from('spaces')
        .update({
          has_exited: true,
          payment_status: 'pending',
          exit_date: format(new Date(), 'yyyy-MM-dd'),
          exit_time: format(new Date(), 'HH:mm'),
        })
        .eq('id', space.id);

      if (spaceError) throw spaceError;

      // Optimistic update
      queryClient.setQueriesData({ queryKey: ['spaces'] }, (old: any) => {
        if (!old) return old;
        return old.map((s: any) => s.id === space?.id ? {
          ...s,
          has_exited: true,
          payment_status: 'pending',
          exit_date: format(new Date(), 'yyyy-MM-dd'),
          exit_time: format(new Date(), 'HH:mm'),
        } : s);
      });

      toast.warning("Vaga liberada sem pagamento. Veículo movido para aba 'Não Pagos'.");
      queryClient.invalidateQueries({ queryKey: ['spaces'] });
      setShowUnpaidAlert(false);
      onOpenChange(false);
      onUpdate?.();
    } catch (error) {
      console.error("Erro ao liberar sem pagamento:", error);
      toast.error("Erro ao processar liberação");
    } finally {
      setIsReleasing(false);
    }
  };

  const handlePDF = async (format: 'a4' | '80mm' | '58mm') => {
    let companyName = undefined;
    let companyCnpj = undefined;
    let companyLogoUrl = undefined;

    if (companyId) {
      const { data } = await supabase
        .from('companies')
        .select('company_name, cnpj, logo_url')
        .eq('id', companyId)
        .maybeSingle();

      if (data) {
        companyName = data.company_name;
        companyCnpj = data.cnpj;
        companyLogoUrl = data.logo_url;
      }
    }

    const pdfData = {
      id: space.id,
      client_name: space.client?.name || 'N/A',
      client_phone: space.client?.phone || 'N/A',
      client_email: space.client?.email || undefined,
      vehicle_brand: space.vehicle?.brand || '',
      vehicle_model: space.vehicle?.model || '',
      vehicle_plate: space.vehicle?.plate || 'N/A',
      vehicle_year: space.vehicle?.year || undefined,
      entry_date: space.entry_date || '',
      entry_time: space.entry_time || '',
      exit_date: space.exit_date || '',
      exit_time: space.exit_time || '',
      services,
      subtotal,
      discount,
      total,
      observations: space.observations || undefined,
      company_name: companyName,
      company_cnpj: companyCnpj,
      company_logo_url: companyLogoUrl,
    };

    if (format === 'a4') {
      await generateSpacePDFA4(pdfData, companyId);
    } else {
      await generateSpacePDFReceipt(pdfData, format, companyId);
    }
    toast.success("PDF gerado com sucesso!");
  };

  const handleOpenWhatsApp = (type: 'entrada' | 'saida') => {
    setWhatsAppType(type);
    setShowWhatsApp(true);
  };

  const whatsAppSpaceData = {
    id: space.id,
    name: space.name,
    entry_date: space.entry_date,
    entry_time: space.entry_time,
    exit_date: space.exit_date,
    exit_time: space.exit_time,
    observations: space.observations,
    discount,
    client: space.client ? { name: space.client.name, phone: space.client.phone } : null,
    vehicle: space.vehicle ? { brand: space.vehicle.brand, model: space.vehicle.model, plate: space.vehicle.plate } : null,
    services,
    subtotal,
    total,
  };

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent className="w-full sm:max-w-lg overflow-y-auto">
        <SheetHeader>
          <SheetTitle className="flex items-center gap-2">
            <Car className="h-5 w-5 text-primary" />
            {space.name}
          </SheetTitle>
        </SheetHeader>

        <div className="mt-6 space-y-6">
          {/* Banner de Excluído */}
          {space.deleted_at && (
            <div className="p-4 rounded-lg bg-destructive/10 border border-destructive/20 text-destructive text-sm flex flex-col gap-2 shadow-sm">
              <div className="font-bold flex items-center gap-2 text-base">
                <Trash2 className="h-5 w-5 text-destructive" />
                Vaga Excluída (Lixeira Operacional)
              </div>
              <div className="text-muted-foreground">
                Esta vaga foi movida para a lixeira operacional em{" "}
                <span className="font-semibold text-destructive">
                  {format(new Date(space.deleted_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}
                </span>{" "}
                por <span className="font-semibold text-destructive">{deleterProfile?.name || "Carregando..."}</span>.
              </div>
              {space.deleted_reason && (
                <div className="mt-1 bg-destructive/5 p-3 rounded border border-destructive/10 text-xs text-muted-foreground">
                  <span className="font-semibold block text-destructive mb-1">Motivo da Exclusão:</span>
                  <span className="italic">"{space.deleted_reason}"</span>
                </div>
              )}
            </div>
          )}

          {/* Toggle para concluir */}
          {!space.deleted_at && (
            <div className="flex items-center justify-between p-4 rounded-lg bg-muted/50 border">
              <div className="flex items-center gap-3">
                <CheckCircle className={space.has_exited ? "h-5 w-5 text-success" : "h-5 w-5 text-muted-foreground"} />
                <span className="text-sm font-medium">Concluir vaga e liberar espaço</span>
              </div>
              <Switch
                checked={space.has_exited || false}
                onCheckedChange={handleCompleteToggle}
                disabled={completeMutation.isPending}
              />
            </div>
          )}

          {/* Info do cliente */}
          {space.client && (
            <div className="space-y-2">
              <div className="flex items-center gap-2 text-sm">
                <Phone className="h-4 w-4 text-info" />
                <span>{space.client.phone}</span>
              </div>
              {space.client.birth_date && (
                <div className="flex items-center gap-2 text-sm text-muted-foreground">
                  <User className="h-4 w-4" />
                  <span>Cliente nasceu em {formatBirthDate(space.client.birth_date)}</span>
                </div>
              )}
            </div>
          )}

          {/* Card do veículo com serviços */}
          <div className="space-y-2">
            <h4 className="text-sm font-medium">Serviços dessa vaga</h4>
            <Card className="bg-muted/50 border-border/50">
              <CardContent className="p-4 space-y-4">
                {space.vehicle && (
                  <div className="flex items-center gap-3">
                    <Car className="h-5 w-5 text-primary" />
                    <div>
                      <p className="font-medium">{space.vehicle.brand} {space.vehicle.model}</p>
                      <p className="text-sm text-muted-foreground">
                        {space.vehicle.plate && `Placa: ${space.vehicle.plate}`}
                        {space.vehicle.year && ` | Ano: ${space.vehicle.year}`}
                      </p>
                    </div>
                  </div>
                )}

                <Separator />

                {/* Serviços */}
                {services.length > 0 ? (
                  <div className="space-y-2">
                    {services.map((item: any, index: number) => (
                      <div key={index} className="flex justify-between text-sm">
                        <span className="text-muted-foreground">{item.name}</span>
                        <span className="font-medium">R$ {item.price.toFixed(2)}</span>
                      </div>
                    ))}
                  </div>
                ) : (
                  <p className="text-sm text-muted-foreground text-center py-2">
                    Nenhum serviço vinculado
                  </p>
                )}

                <Separator />

                <div className="flex justify-between text-sm font-medium">
                  <span>Total em serviços</span>
                  <span className="text-primary">R$ {subtotal.toFixed(2)}</span>
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Resumo da vaga */}
          <Card className="bg-muted/30 border-border/50">
            <CardContent className="p-4 space-y-2">
              <h4 className="font-medium">Resumo da vaga</h4>
              <div className="space-y-1 text-sm">
                <p className="flex items-center gap-2">
                  <Calendar className="h-4 w-4 text-muted-foreground" />
                  <span>Entrada em {formatDate(space.entry_date)} {space.entry_time && `às ${space.entry_time}h`}</span>
                </p>
                {space.exit_date && (
                  <p className="flex items-center gap-2">
                    <Clock className="h-4 w-4 text-muted-foreground" />
                    <span>
                      {space.has_exited ? 'Saída' : 'Saída prevista'} para {formatDate(space.exit_date)} {space.exit_time && `às ${space.exit_time}h`}
                    </span>
                  </p>
                )}
                <p className="flex items-center gap-2">
                  <Package className="h-4 w-4 text-muted-foreground" />
                  <span>Vaga com {serviceCount} serviço(s)</span>
                </p>
                <p className="flex items-center gap-2">
                  <DollarSign className="h-4 w-4 text-muted-foreground" />
                  <span>Sub-total ficou em R$ {subtotal.toFixed(2)}</span>
                </p>
                {discount > 0 && (
                  <p className="flex items-center gap-2">
                    <span className="text-muted-foreground">Desconto de R$ {discount.toFixed(2)}</span>
                  </p>
                )}
                <p className="flex items-center gap-2 font-medium text-primary">
                  <DollarSign className="h-4 w-4" />
                  <span>Total ficou em R$ {total.toFixed(2)}</span>
                </p>
                {space.sale_id && (
                  <p className="flex items-center gap-2">
                    <Link2 className="h-4 w-4 text-muted-foreground" />
                    <span>Vinculado à venda Nº {space.sale_id}</span>
                  </p>
                )}
              </div>
            </CardContent>
          </Card>

          {/* Status de pagamento */}
          <div className="flex items-center justify-between p-4 rounded-lg border">
            <div className="flex items-center gap-2">
              <span className="text-sm font-medium">Status do pagamento:</span>
              <Badge
                variant="outline"
                className={
                  space.payment_status === 'paid'
                    ? "bg-success/20 text-success border-success/30"
                    : "bg-destructive/20 text-destructive border-destructive/30"
                }
              >
                {space.payment_status === 'paid' ? (
                  <><CheckCircle className="h-3 w-3 mr-1" />Pago</>
                ) : (
                  <><AlertCircle className="h-3 w-3 mr-1" />Não pago</>
                )}
              </Badge>
            </div>

          </div>

          {/* Comprovantes em PDF */}
          {!space.deleted_at && (
            <div className="space-y-2">
              <h4 className="text-sm font-medium">Comprovantes em PDF</h4>
              <div className="space-y-2">
                <Button variant="outline" className="w-full justify-start text-destructive" onClick={() => handlePDF('a4')}>
                  <FileText className="h-4 w-4 mr-2" />
                  Baixar PDF em formato A4
                </Button>
                <Button variant="outline" className="w-full justify-start text-destructive" onClick={() => handlePDF('80mm')}>
                  <FileText className="h-4 w-4 mr-2" />
                  Baixar PDF em formato Notinha
                </Button>
                <Button variant="outline" className="w-full justify-start text-destructive" onClick={() => handlePDF('58mm')}>
                  <FileText className="h-4 w-4 mr-2" />
                  Baixar PDF em formato Notinha Mini
                </Button>
              </div>
            </div>
          )}

          {/* Mais opções */}
          {!space.deleted_at && (
            <div className="space-y-2">
              <h4 className="text-sm font-medium">Mais opções</h4>
              <div className="space-y-2">
                <Button variant="outline" className="w-full justify-start text-primary border-primary/20 hover:bg-primary/10" onClick={() => setShowExportSaleModal(true)}>
                  <DollarSign className="h-4 w-4 mr-2" />
                  Exportar para Venda
                </Button>
                <Button variant="outline" className="w-full justify-start text-success" onClick={() => handleOpenWhatsApp('entrada')}>
                  <MessageSquare className="h-4 w-4 mr-2" />
                  Enviar mensagem de entrada
                </Button>
                <Button variant="outline" className="w-full justify-start text-warning" onClick={() => handleOpenWhatsApp('saida')}>
                  <MessageSquare className="h-4 w-4 mr-2" />
                  Enviar mensagem de saída
                </Button>
                <Button
                  variant="outline"
                  className="w-full justify-start"
                  onClick={handleOpenClientProfile}
                  disabled={profileLoading}
                >
                  {profileLoading ? (
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  ) : (
                    <User className="h-4 w-4 mr-2" />
                  )}
                  Ver cliente da vaga
                </Button>
              </div>
            </div>
          )}

          {/* Fotos do Checklist */}
          {(checklistPhotos.length > 0 || isLoadingPhotos) && (
            <div className="space-y-2">
              <h4 className="flex items-center gap-2 text-sm font-medium">
                <Camera className="h-4 w-4" />
                Fotos da Vaga (Checklist)
              </h4>
              {isLoadingPhotos ? (
                <div className="flex items-center justify-center p-4 border rounded-lg bg-muted/30">
                  <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
                </div>
              ) : (
                <div className="flex gap-2 overflow-x-auto overscroll-x-contain pb-2">
                  {checklistPhotos.map((photo, index) => (
                    <a
                      key={index}
                      href={photo.url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="relative min-w-[100px] h-[100px] rounded border overflow-hidden shrink-0 block hover:opacity-80 transition-opacity"
                    >
                      <img src={photo.url} alt={`Foto ${index + 1}`} className="w-full h-full object-cover" />
                    </a>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* Observações */}
          {space.observations && (
            <div className="space-y-2">
              <h4 className="text-sm font-medium">Observações</h4>
              <p className="text-sm text-muted-foreground p-3 rounded-lg bg-muted/50">
                {space.observations}
              </p>
            </div>
          )}

          {/* Botões de ação */}
          <div className="flex gap-2 pt-4 border-t mt-4">
            {space.deleted_at ? (
              <>
                <Button
                  variant="default"
                  className="flex-1 gap-2 bg-success hover:bg-success/90 text-white font-medium"
                  onClick={() => restoreMutation.mutate()}
                  disabled={restoreMutation.isPending}
                >
                  {restoreMutation.isPending ? (
                    <Loader2 className="h-4 w-4 animate-spin" />
                  ) : (
                    <Undo2 className="h-4 w-4" />
                  )}
                  Restaurar Vaga
                </Button>
                {user?.role === "ADMIN" && (
                  <Button
                    variant="destructive"
                    className="flex-1 gap-2 font-medium"
                    onClick={() => setIsPermanentDeleteDialogOpen(true)}
                    disabled={permanentDeleteMutation.isPending}
                  >
                    {permanentDeleteMutation.isPending ? (
                      <Loader2 className="h-4 w-4 animate-spin" />
                    ) : (
                      <Trash2 className="h-4 w-4" />
                    )}
                    Excluir Permanente
                  </Button>
                )}
              </>
            ) : (
              <>
                <Button variant="outline" className="flex-1" onClick={() => setShowEditModal(true)}>
                  <Edit className="h-4 w-4 mr-2" />
                  Editar
                </Button>
                <Button
                  variant="destructive"
                  size="icon"
                  onClick={() => setIsDeleteDialogOpen(true)}
                >
                  <Trash2 className="h-4 w-4" />
                </Button>
              </>
            )}
          </div>
        </div>

        {/* Soft Delete Dialog */}
        <AlertDialog open={isDeleteDialogOpen} onOpenChange={setIsDeleteDialogOpen}>
          <AlertDialogContent className="w-11/12 max-w-md rounded-lg">
            <AlertDialogHeader>
              <AlertDialogTitle>Excluir Vaga (Lixeira)</AlertDialogTitle>
              <AlertDialogDescription>
                Tem certeza que deseja mover esta vaga para a lixeira operacional?
                Insira o motivo abaixo:
              </AlertDialogDescription>
            </AlertDialogHeader>
            <div className="py-2">
              <Textarea
                placeholder="Ex: Cliente desistiu do serviço, duplicado, etc..."
                value={deleteReason}
                onChange={(e) => setDeleteReason(e.target.value)}
                className="w-full min-h-[80px]"
              />
            </div>
            <AlertDialogFooter className="flex-row gap-2 justify-end">
              <AlertDialogCancel onClick={() => {
                setDeleteReason("");
                setIsDeleteDialogOpen(false);
              }}>
                Cancelar
              </AlertDialogCancel>
              <AlertDialogAction
                className="bg-destructive hover:bg-destructive/90 text-white"
                onClick={() => {
                  softDeleteMutation.mutate(deleteReason);
                  setDeleteReason("");
                  setIsDeleteDialogOpen(false);
                }}
                disabled={softDeleteMutation.isPending}
              >
                {softDeleteMutation.isPending ? "Excluindo..." : "Mover para Lixeira"}
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>

        {/* Permanent Delete Dialog */}
        <AlertDialog open={isPermanentDeleteDialogOpen} onOpenChange={setIsPermanentDeleteDialogOpen}>
          <AlertDialogContent className="w-11/12 max-w-md rounded-lg border-l-4 border-l-destructive">
            <AlertDialogHeader>
              <AlertDialogTitle className="text-destructive font-bold flex items-center gap-2">
                <AlertCircle className="h-5 w-5 text-destructive" />
                Exclusão Definitiva
              </AlertDialogTitle>
              <AlertDialogDescription>
                ATENÇÃO: Esta ação é irreversível. A vaga será excluída permanentemente do banco de dados, incluindo quaisquer registros de checklists associados.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter className="flex-row gap-2 justify-end">
              <AlertDialogCancel onClick={() => setIsPermanentDeleteDialogOpen(false)}>
                Cancelar
              </AlertDialogCancel>
              <AlertDialogAction
                className="bg-destructive hover:bg-destructive/90 text-white"
                onClick={() => {
                  permanentDeleteMutation.mutate();
                  setIsPermanentDeleteDialogOpen(false);
                }}
                disabled={permanentDeleteMutation.isPending}
              >
                {permanentDeleteMutation.isPending ? "Excluindo..." : "Excluir Definitivamente"}
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>

        {/* Alert Dialog for Unpaid Exit */}
        <UnpaidExitAlertDialog
          open={showUnpaidAlert}
          onOpenChange={setShowUnpaidAlert}
          space={space}
          onReleaseWithPayment={handleReleaseWithPayment}
          onReleaseWithoutPayment={handleReleaseWithoutPayment}
          isLoading={isReleasing}
        />

        {/* WhatsApp Modal */}
        <SpaceWhatsAppModal
          open={showWhatsApp}
          onOpenChange={setShowWhatsApp}
          space={whatsAppSpaceData}
          type={whatsAppType}
        />

        {/* Edit Modal */}
        {space && (
          <EditSlotModal
            open={showEditModal}
            onOpenChange={setShowEditModal}
            space={space}
            onSlotUpdated={() => {
              queryClient.invalidateQueries({ queryKey: ['spaces'] });
              onUpdate?.();
            }}
          />
        )}

        {/* New Sale Modal */}
        {space && space.client_id && space.vehicle_id && (
          <NewSaleModal
            open={showExportSaleModal}
            onOpenChange={setShowExportSaleModal}
            initialDate={space.entry_date ? new Date(space.entry_date + 'T12:00:00') : undefined}
            onSuccess={() => {
              queryClient.invalidateQueries({ queryKey: ['spaces'] });
              queryClient.invalidateQueries({ queryKey: ['spaces-day'] });
              queryClient.invalidateQueries({ queryKey: ['sales'] });
              onUpdate?.();
            }}
            prefillData={{
              clientId: space.client_id,
              vehicleId: space.vehicle_id,
              discount: space.discount || 0,
              services: space.services_data || [],
              spaceId: space.id,
              observations: space.observations || undefined
            }}
          />
        )}

        {profileClient && (
          <>
            <ClientProfileModal
              open={showProfileModal}
              onOpenChange={(open) => {
                setShowProfileModal(open);
                if (!open) {
                  setTimeout(() => setProfileClient(null), 300);
                }
              }}
              client={profileClient}
              onEdit={() => {
                setShowProfileModal(false);
                setShowEditClientModal(true);
              }}
              onCreateSale={() => {
                setShowProfileModal(false);
                setShowNewSaleModal(true);
              }}
              onAddToSpace={() => {
                setShowProfileModal(false);
                setShowNewSlotModal(true);
              }}
              onDelete={(client) => {
                setShowProfileModal(false);
                setClientToDelete(client);
              }}
            />

            <EditClientModal
              open={showEditClientModal}
              onOpenChange={(open) => {
                setShowEditClientModal(open);
                if (!open) {
                  setProfileClient(null);
                }
              }}
              client={profileClient}
              onSave={() => {
                setShowEditClientModal(false);
                setProfileClient(null);
                toast.success("Cliente atualizado com sucesso!");
                queryClient.invalidateQueries({ queryKey: ['spaces'] });
              }}
            />
          </>
        )}

        {/* New Sale Modal (general) */}
        <NewSaleModal
          open={showNewSaleModal}
          onOpenChange={(open) => {
            setShowNewSaleModal(open);
            if (!open) setProfileClient(null);
          }}
          defaultClientId={profileClient?.id}
        />

        {/* New Slot Modal */}
        <FillSlotModal
          open={showNewSlotModal}
          onOpenChange={(open) => {
            setShowNewSlotModal(open);
            if (!open) setProfileClient(null);
          }}
          defaultClientId={profileClient?.id}
        />

        {/* Client Delete Confirmation */}
        <AlertDialog open={!!clientToDelete} onOpenChange={(open) => {
          if (!open) setClientToDelete(null);
        }}>
          <AlertDialogContent className="bg-card border-border">
            <AlertDialogHeader>
              <AlertDialogTitle>Confirmar exclusão</AlertDialogTitle>
              <AlertDialogDescription>
                Tem certeza que deseja excluir o cliente "{clientToDelete?.name}"?
                Esta ação não pode ser desfeita.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel className="border-border">Cancelar</AlertDialogCancel>
              <AlertDialogAction
                onClick={confirmDeleteClient}
                className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              >
                Excluir
              </AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>
      </SheetContent>
    </Sheet>
  );
}

import { useState } from "react";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { Sheet, SheetContent, SheetHeader, SheetTitle } from "@/components/ui/sheet";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Car, User, Clock, CheckCircle, AlertCircle, Loader2, Plus } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { SlotDetailsDrawer } from "./SlotDetailsDrawer";

interface SlotsDayDrawerProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  date: Date | null;
  onAddSlot?: () => void;
}

interface DaySpace {
  id: number;
  name: string;
  entry_time: string | null;
  exit_time: string | null;
  has_exited: boolean | null;
  payment_status: string | null;
  client?: {
    id: number;
    name: string;
    phone: string;
  } | null;
  vehicle?: {
    id: number;
    brand: string;
    model: string;
    plate: string | null;
    year: number | null;
  } | null;
  sale?: {
    id: number;
    total: number;
  } | null;
}

export function SlotsDayDrawer({ open, onOpenChange, date, onAddSlot }: SlotsDayDrawerProps) {
  const { user } = useAuth();
  const companyId = user?.companyId;
  const queryClient = useQueryClient();
  const [selectedSpace, setSelectedSpace] = useState<any>(null);

  const dayStr = date ? format(date, 'yyyy-MM-dd') : null;

  const { data: spaces, isLoading } = useQuery({
    queryKey: ['spaces-day', dayStr, companyId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('spaces')
        .select(`
          *,
          client:clients(id, name, phone, birth_date),
          vehicle:vehicles(id, brand, model, plate, year),
          sale:sales(
            id, total, subtotal, discount,
            sale_items(
              id,
              total_price,
              service:services(id, name)
            )
          )
        `)
        .eq('company_id', companyId)
        .is('deleted_at', null)
        .eq('entry_date', dayStr)
        .order('entry_time', { ascending: true });

      if (error) throw error;
      return data as unknown as DaySpace[];
    },
    enabled: !!companyId && !!dayStr && open,
  });

  if (!date) return null;

  return (
    <>
      <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent side="right" className="w-full sm:max-w-md overflow-y-auto max-w-[100vw]">
        <SheetHeader className="space-y-4">
          <div className="flex items-center justify-between sm:pr-8">
            <SheetTitle className="text-left">
              {format(date, "dd 'de' MMMM 'de' yyyy", { locale: ptBR })}
            </SheetTitle>
          </div>
          {onAddSlot && (
            <Button size="sm" onClick={onAddSlot} className="w-full sm:w-auto">
              <Plus className="h-4 w-4 mr-2" />
              Cadastrar Vaga
            </Button>
          )}
        </SheetHeader>

        <div className="mt-6 space-y-4 pb-6">
          {isLoading ? (
            <div className="flex items-center justify-center py-12">
              <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
          ) : spaces && spaces.length > 0 ? (
            spaces.map(space => {
              const isPaid = space.payment_status === 'paid';
              const isCompleted = space.has_exited;

              return (
                <Card 
                  key={space.id} 
                  className="bg-card/50 cursor-pointer hover:border-primary/50 transition-colors"
                  onClick={() => setSelectedSpace(space)}
                >
                  <CardContent className="p-4 space-y-3">
                    <div className="flex items-center justify-between">
                      <span className="font-medium">{space.name}</span>
                      <Badge 
                        variant="outline"
                        className={
                          isCompleted 
                            ? "bg-green-500/20 text-green-400 border-green-500/30"
                            : "bg-yellow-500/20 text-yellow-400 border-yellow-500/30"
                        }
                      >
                        {isCompleted ? 'Finalizado' : 'Em andamento'}
                      </Badge>
                    </div>

                    {/* Client */}
                    {space.client && (
                      <div className="flex items-center gap-2 text-sm">
                        <User className="h-4 w-4 text-muted-foreground" />
                        <span>{space.client.name}</span>
                      </div>
                    )}

                    {/* Vehicle */}
                    {space.vehicle && (
                      <div className="flex items-center gap-2 text-sm">
                        <Car className="h-4 w-4 text-muted-foreground" />
                        <span>{space.vehicle.brand} {space.vehicle.model}</span>
                        {space.vehicle.plate && (
                          <span className="text-muted-foreground">- {space.vehicle.plate}</span>
                        )}
                      </div>
                    )}

                    {/* Times */}
                    <div className="flex items-center gap-4 text-sm text-muted-foreground">
                      {space.entry_time && (
                        <span className="flex items-center gap-1">
                          <Clock className="h-3 w-3" />
                          Entrada: {space.entry_time}
                        </span>
                      )}
                      {space.exit_time && (
                        <span className="flex items-center gap-1">
                          <Clock className="h-3 w-3" />
                          Saída: {space.exit_time}
                        </span>
                      )}
                    </div>

                    {/* Payment Status */}
                    <Badge 
                      variant="outline" 
                      className={
                        isPaid 
                          ? "bg-green-500/20 text-green-400 border-green-500/30" 
                          : "bg-red-500/20 text-red-400 border-red-500/30"
                      }
                    >
                      {isPaid ? (
                        <><CheckCircle className="h-3 w-3 mr-1" />Pago</>
                      ) : (
                        <><AlertCircle className="h-3 w-3 mr-1" />Não pago</>
                      )}
                    </Badge>

                    {/* Total */}
                    {space.sale && (
                      <div className="flex justify-between items-center pt-2 border-t">
                        <span className="text-muted-foreground text-sm">Total:</span>
                        <span className="font-bold text-primary">
                          R$ {space.sale.total.toFixed(2)}
                        </span>
                      </div>
                    )}
                  </CardContent>
                </Card>
              );
            })
          ) : (
            <div className="flex flex-col items-center justify-center py-12 text-muted-foreground">
              <Car className="h-12 w-12 mb-4 opacity-50" />
              <p className="mb-4">Nenhuma vaga registrada neste dia.</p>
              {onAddSlot && (
                <Button onClick={onAddSlot} variant="outline">
                  <Plus className="h-4 w-4 mr-2" />
                  Cadastrar Vaga
                </Button>
              )}
            </div>
          )}
        </div>
      </SheetContent>
    </Sheet>

    <SlotDetailsDrawer
        open={!!selectedSpace}
        onOpenChange={(op) => !op && setSelectedSpace(null)}
        space={selectedSpace}
        onUpdate={() => {
          queryClient.invalidateQueries({ queryKey: ['spaces-day'] });
        }}
    />
    </>
  );
}

import { useState, useRef, useEffect } from "react";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Card } from "@/components/ui/card";
import { ScrollArea } from "@/components/ui/scroll-area";
import { MessageCircle, Edit, X, Send, Save, Bold, Italic } from "lucide-react";
import { toast } from "sonner";

interface SpaceData {
  id: number;
  name: string;
  entry_date: string | null;
  entry_time: string | null;
  exit_date: string | null;
  exit_time: string | null;
  observations: string | null;
  discount: number | null;
  client?: {
    name: string;
    phone: string;
  } | null;
  vehicle?: {
    brand: string;
    model: string;
    plate: string | null;
  } | null;
  services: Array<{ name: string; price: number }>;
  subtotal: number;
  total: number;
}

interface SpaceWhatsAppModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  space: SpaceData | null;
  type: 'entrada' | 'saida';
  companyName?: string;
}

export function SpaceWhatsAppModal({ open, onOpenChange, space, type, companyName = "WFE EVOLUTION" }: SpaceWhatsAppModalProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [template, setTemplate] = useState("");
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const vehicleStr = space ? `${space.vehicle?.brand || ''} ${space.vehicle?.model || ''} ${space.vehicle?.plate ? `(${space.vehicle.plate})` : ''}`.trim() : '';
  const entryDateStr = space?.entry_date ? format(new Date(space.entry_date + 'T12:00:00'), "dd/MM/yyyy", { locale: ptBR }) : '-';
  const entryTimeStr = space?.entry_time || '';
  const exitDateStr = space?.exit_date ? format(new Date(space.exit_date + 'T12:00:00'), "dd/MM/yyyy", { locale: ptBR }) : '-';
  const exitTimeStr = space?.exit_time || '';
  const servicesStr = space && space.services && space.services.length > 0
    ? space.services.map((s, i) => `${i + 1}. ${s.name} - R$ ${s.price.toFixed(2)}`).join("\n")
    : 'Nenhum serviço';

  const defaultEntrance = space ? `Olá ${space.client?.name || ''}!\nO seu veículo ${vehicleStr} já está sob os cuidados da nossa equipe. Agradecemos pela confiança em nosso trabalho.\n\n*Entrada:*\n${entryDateStr} ${entryTimeStr && `às ${entryTimeStr}h`}\n\n*Saída prevista:*\n${exitDateStr} ${exitTimeStr && `às ${exitTimeStr}h`}\n\n_Obs.: Uma mensagem será enviada assim que o serviço estiver pronto!_` : '';

  const defaultExit = space ? `Olá ${space.client?.name || ''}!\n\n*Temos uma excelente notícia para você!*\n\nO seu veículo ${vehicleStr} já está pronto. Fique à vontade para vir buscar!\n\nObrigado por confiar em nosso trabalho, até logo!` : '';

  const defaultMessage = type === 'entrada' ? defaultEntrance : defaultExit;

  useEffect(() => {
    if (open && space) {
      setTemplate(type === 'entrada' ? defaultEntrance : defaultExit);
      setIsEditing(false);
    }
  }, [open, space?.id, type, defaultEntrance, defaultExit]);

  if (!space) return null;

  const resolveVariables = (text: string) => {
    return text
      .replace(/\{cliente\}/g, space.client?.name || '')
      .replace(/\{veiculo\}/g, vehicleStr)
      .replace(/\{nomeEmpresa\}/g, companyName)
      .replace(/\{servicos\}/g, servicesStr)
      .replace(/\{dataEntrada\}/g, `${entryDateStr} ${entryTimeStr && `às ${entryTimeStr}h`}`)
      .replace(/\{dataSaida\}/g, `${exitDateStr} ${exitTimeStr && `às ${exitTimeStr}h`}`)
      .replace(/\{descricao\}/g, space.observations || '')
      .replace(/\{subtotal\}/g, space.subtotal.toFixed(2))
      .replace(/\{desconto\}/g, (space.discount || 0).toFixed(2))
      .replace(/\{total\}/g, space.total.toFixed(2));
  };

  const messageToSend = template ? resolveVariables(template) : defaultMessage;

  const getWhatsAppUrl = () => {
    if (!space.client?.phone) return "#";
    const phone = space.client.phone.replace(/\D/g, "");
    const phoneWithCountryCode = phone.startsWith("55") ? phone : `55${phone}`;
    const encodedMessage = encodeURIComponent(messageToSend);
    return `https://wa.me/${phoneWithCountryCode}?text=${encodedMessage}`;
  };

  const handleSend = (e: React.MouseEvent) => {
    if (!space.client?.phone) {
      e.preventDefault();
      toast.error("Cliente sem telefone cadastrado");
      return;
    }
    toast.success("Abrindo WhatsApp Web em nova aba!");
    onOpenChange(false);
  };

  const handleEdit = () => {
    setIsEditing(true);
  };

  const handleSave = () => {
    setIsEditing(false);
    toast.success("Mensagem salva!");
  };

  const insertVariable = (variable: string) => {
    if (!textareaRef.current) return;
    const ta = textareaRef.current;
    const start = ta.selectionStart;
    const end = ta.selectionEnd;
    const newText = template.substring(0, start) + variable + template.substring(end);
    setTemplate(newText);
    setTimeout(() => {
      ta.focus();
      ta.selectionStart = ta.selectionEnd = start + variable.length;
    }, 0);
  };

  const insertFormatting = (wrapper: string) => {
    if (!textareaRef.current) return;
    const ta = textareaRef.current;
    const start = ta.selectionStart;
    const end = ta.selectionEnd;
    const selected = template.substring(start, end);
    const newText = template.substring(0, start) + `${wrapper}${selected || 'texto'}${wrapper}` + template.substring(end);
    setTemplate(newText);
  };

  const escapeHtml = (text: string) => {
    return text
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  };

  const formatWhatsAppPreview = (text: string) => {
    return escapeHtml(text)
      .replace(/\*(.*?)\*/g, '<strong>$1</strong>')
      .replace(/_(.*?)_/g, '<em>$1</em>')
      .replace(/\n/g, '<br/>');
  };

  const variables = [
    { label: "+ Nome Empresa", value: "{nomeEmpresa}" },
    { label: "+ Veículo", value: "{veiculo}" },
    { label: "+ Cliente", value: "{cliente}" },
    { label: "+ Serviços", value: "{servicos}" },
    { label: "+ Data entrada", value: "{dataEntrada}" },
    { label: "+ Data saída", value: "{dataSaida}" },
    { label: "+ Descrição", value: "{descricao}" },
    { label: "+ Subtotal", value: "{subtotal}" },
    { label: "+ Desconto", value: "{desconto}" },
    { label: "+ Total", value: "{total}" },
  ];

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent hideCloseButton className="max-w-2xl max-h-[90vh] overflow-hidden flex flex-col">
        <DialogHeader>
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
            <div className="hidden sm:flex items-center gap-3">
              <div className="p-2 rounded-lg bg-success/20">
                <MessageCircle className="h-5 w-5 text-success" />
              </div>
              <DialogTitle>
                {type === 'entrada' ? 'Mensagem de Entrada' : 'Mensagem de Saída'}
              </DialogTitle>
            </div>
            <div className="flex w-full sm:w-auto gap-2">
              {!isEditing ? (
                <>
                  <a
                    href={getWhatsAppUrl()}
                    target="_blank"
                    rel="noopener noreferrer"
                    onClick={handleSend}
                    className="flex-1 sm:flex-none inline-flex items-center justify-center gap-2 rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 bg-success text-white hover:bg-success/90 h-10 sm:h-9 px-3"
                  >
                    <Send className="h-4 w-4 hidden sm:inline" />
                    <span className="sm:hidden">Enviar whatsapp</span>
                    <span className="hidden sm:inline">Enviar WhatsApp</span>
                  </a>
                  <Button 
                    variant="outline" 
                    onClick={handleEdit} 
                    size="sm" 
                    className="flex-1 sm:flex-none gap-2 bg-[#3b82f6] hover:bg-[#2563eb] text-white border-none sm:bg-background sm:text-foreground sm:border sm:border-input sm:hover:bg-accent sm:hover:text-accent-foreground h-10 sm:h-9"
                  >
                    <Edit className="h-4 w-4 hidden sm:inline" />
                    <span>Editar mensagem</span>
                  </Button>
                </>
              ) : (
                <Button onClick={handleSave} className="flex-1 sm:flex-none gap-2 bg-success hover:bg-success/90 h-10 sm:h-9" size="sm">
                  <Save className="h-4 w-4" />
                  Salvar
                </Button>
              )}
              <Button 
                variant="destructive" 
                size="sm" 
                className="flex-1 sm:flex-none gap-2 h-10 sm:h-9" 
                onClick={() => { setIsEditing(false); onOpenChange(false); }}
              >
                <X className="h-4 w-4 hidden sm:inline" />
                <span className="sm:hidden">Fechar</span>
              </Button>
            </div>
          </div>
        </DialogHeader>

        <div className="flex-1 overflow-y-auto py-4 space-y-4">
          {isEditing ? (
            <>
              <div
                className="relative rounded-lg p-4 min-h-[300px]"
                style={{
                  backgroundImage: `url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23128C7E' fill-opacity='0.1'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E")`,
                  backgroundColor: "#E5DDD5",
                }}
              >
                <Card className="bg-[#DCF8C6] p-4 rounded-lg shadow-md">
                  <Textarea
                    ref={textareaRef}
                    value={template}
                    onChange={(e) => setTemplate(e.target.value)}
                    className="min-h-[250px] bg-transparent border-none focus-visible:ring-0 text-sm text-gray-800 font-sans resize-none [word-break:normal] break-words"
                  />
                </Card>
              </div>

              {/* Formatting bar */}
              <div className="border rounded-lg p-3 space-y-2">
                <div className="flex flex-wrap gap-2">
                  <Button variant="outline" size="sm" onClick={() => insertFormatting('*')}>
                    <Bold className="h-4 w-4" />
                  </Button>
                  <Button variant="outline" size="sm" onClick={() => insertFormatting('_')}>
                    <Italic className="h-4 w-4" />
                  </Button>
                  <div className="w-px h-6 bg-border self-center" />
                  {variables.map((v) => (
                    <Button
                      key={v.value}
                      variant="outline"
                      size="sm"
                      className="text-xs"
                      onClick={() => insertVariable(v.value)}
                    >
                      {v.label}
                    </Button>
                  ))}
                </div>
              </div>
            </>
          ) : (
            <div
              className="relative rounded-lg p-4 min-h-[400px]"
              style={{
                backgroundImage: `url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23128C7E' fill-opacity='0.1'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E")`,
                backgroundColor: "#E5DDD5",
              }}
            >
              <Card className="bg-[#DCF8C6] p-4 rounded-lg shadow-md max-w-md ml-auto [word-break:normal] break-words whitespace-pre-wrap text-sm text-gray-800 font-sans">
                <div
                  dangerouslySetInnerHTML={{ __html: formatWhatsAppPreview(messageToSend) }}
                />
                <div className="text-right mt-2">
                  <span className="text-[10px] text-gray-500">
                    {format(new Date(), "HH:mm")}
                  </span>
                </div>
              </Card>
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import React, { useState } from "react";
import { format } from "date-fns";
import { useQuery } from "@tanstack/react-query";
import { useSearchParams } from "react-router-dom";
import { Search, Loader2, Trash2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

interface LixeiraProps {
    handleSlotClick: (space: any) => void;
}

export function Lixeira({ handleSlotClick }: LixeiraProps) {
    const { user } = useAuth();
    const companyId = user?.companyId;

    const [searchParams] = useSearchParams();
    const searchParamValue = searchParams.get("search") || "";
    const [searchTerm, setSearchTerm] = useState(searchParamValue);

    // Fetch deleted spaces (Lixeira)
    const { data: deletedSpaces, isLoading: isDeletedLoading } = useQuery({
        queryKey: ['spaces-deleted', companyId],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('spaces')
                .select(`
          *,
          client:clients(id, name, phone, birth_date, email),
          vehicle:vehicles(id, brand, model, plate, year),
          sale:sales(
            id, total, subtotal, discount,
            sale_items(
              id,
              total_price,
              service:services(id, name)
            )
          )
        `)
                .eq('company_id', companyId)
                .not('deleted_at', 'is', null)
                .order('deleted_at', { ascending: false });

            if (error) throw error;
            return data;
        },
        enabled: !!companyId,
    });

    return (
        <div className="mt-6 space-y-4">
            <div className="flex flex-col sm:flex-row items-stretch sm:items-center justify-between gap-4 bg-card/30 p-4 rounded-lg border">
                <div>
                    <h2 className="text-lg font-bold flex items-center gap-2">
                        <Trash2 className="h-5 w-5 text-destructive" />
                        Lixeira Operacional (Vagas)
                    </h2>
                    <p className="text-sm text-muted-foreground">
                        Vagas que foram excluídas logicamente. Você pode visualizar detalhes, restaurá-las ou excluí-las permanentemente (apenas Administradores).
                    </p>
                </div>
                <div className="relative w-full sm:w-64">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <Input
                        placeholder="Buscar excluídos..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="pl-10 h-9"
                    />
                </div>
            </div>

            {isDeletedLoading ? (
                <div className="flex items-center justify-center py-12">
                    <Loader2 className="h-8 w-8 animate-spin text-primary" />
                </div>
            ) : (() => {
                const filteredDeleted = deletedSpaces?.filter((space: any) => {
                    if (!searchTerm) return true;
                    const term = searchTerm.toLowerCase();
                    return (
                        space.client?.name?.toLowerCase().includes(term) ||
                        space.name?.toLowerCase().includes(term) ||
                        space.vehicle?.plate?.toLowerCase().includes(term) ||
                        space.vehicle?.model?.toLowerCase().includes(term)
                    );
                }) || [];

                if (filteredDeleted.length === 0) {
                    return (
                        <Card className="flex flex-col items-center justify-center p-8 text-center min-h-[300px] border-dashed bg-card/30">
                            <div className="p-4 rounded-full bg-muted mb-4">
                                <Trash2 className="h-8 w-8 text-muted-foreground" />
                            </div>
                            <h3 className="text-lg font-semibold">Lixeira vazia</h3>
                            <p className="text-sm text-muted-foreground max-w-sm mt-1">
                                Nenhuma vaga excluída logicamente foi encontrada.
                            </p>
                        </Card>
                    );
                }

                return (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                        {filteredDeleted.map((space: any) => (
                            <Card
                                key={space.id}
                                className="flex flex-col justify-between border border-destructive/10 hover:border-destructive/20 hover:shadow-md transition-all bg-card/50 cursor-pointer"
                                onClick={() => handleSlotClick(space)}
                            >
                                <CardContent className="p-5 space-y-3">
                                    <div className="flex justify-between items-start">
                                        <div className="space-y-1">
                                            <h4 className="font-bold text-base flex items-center gap-1.5 text-foreground">
                                                {space.name}
                                            </h4>
                                            <span className="text-xs text-muted-foreground block">
                                                Entrada em: {space.entry_date ? format(new Date(space.entry_date + 'T12:00:00'), "dd/MM/yyyy") : "-"}
                                            </span>
                                        </div>
                                        <Badge variant="destructive" className="gap-1 bg-destructive/10 text-destructive border-destructive/20 hover:bg-destructive/10">
                                            <Trash2 className="h-3 w-3" />
                                            Excluída
                                        </Badge>
                                    </div>

                                    <div className="text-sm space-y-1.5 text-muted-foreground border-t pt-2 mt-2">
                                        <p><strong className="text-foreground font-medium">Cliente:</strong> {space.client?.name || "Sem Nome"}</p>
                                        {space.vehicle && (
                                            <p><strong className="text-foreground font-medium">Veículo:</strong> {space.vehicle.brand} {space.vehicle.model} ({space.vehicle.plate || "S/ Placa"})</p>
                                        )}
                                        <p className="text-xs text-destructive bg-destructive/5 p-2 rounded border border-destructive/15 mt-2 max-h-[60px] overflow-hidden text-ellipsis">
                                            <strong className="font-semibold block mb-0.5">Motivo:</strong>
                                            <span className="italic">"{space.deleted_reason || "Nenhum motivo informado."}"</span>
                                        </p>
                                    </div>

                                    <Button
                                        variant="outline"
                                        className="w-full mt-3 gap-2 border-destructive/20 text-destructive hover:bg-destructive/5 hover:text-destructive text-xs"
                                    >
                                        Visualizar & Gerenciar
                                    </Button>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                );
            })()}
        </div>
    );
}

import React, { useState, useEffect } from "react";
import { format, startOfMonth, endOfMonth, eachDayOfInterval, isSameMonth, isToday } from "date-fns";
import { ptBR } from "date-fns/locale";
import { useQuery } from "@tanstack/react-query";
import { useSearchParams } from "react-router-dom";
import { ChevronLeft, ChevronRight, Car, Clock, CheckCircle, AlertTriangle, Search, Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertTitle, AlertDescription } from "@/components/ui/alert";
import { cn } from "@/lib/utils";
import { BrazilCalendarLegend } from "@/components/calendar/BrazilCalendarLegend";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import {
    BRAZIL_CALENDAR_EVENT_STYLES,
    getBrazilCalendarTitle,
    getPrimaryBrazilCalendarEvent,
} from "@/lib/brazilCalendar";
import { SlotCard } from "../../components/SlotCard";

export interface SpaceData {
    id: number;
    name: string;
    client_id: number | null;
    vehicle_id: number | null;
    sale_id: number | null;
    entry_date: string | null;
    entry_time: string | null;
    exit_date: string | null;
    exit_time: string | null;
    has_exited: boolean | null;
    payment_status: string | null;
    observations: string | null;
    tag: string | null;
    discount: number | null;
    status: string | null;
    deleted_at?: string | null;
    deleted_by?: string | null;
    deleted_reason?: string | null;
    client?: {
        id: number;
        name: string;
        phone: string;
        birth_date: string | null;
        email?: string | null;
    } | null;
    vehicle?: {
        id: number;
        brand: string;
        model: string;
        plate: string | null;
        year: number | null;
    } | null;
    sale?: {
        id: number;
        total: number;
        subtotal: number;
        discount: number | null;
        sale_items?: {
            id: number;
            total_price: number;
            service?: {
                id: number;
                name: string;
            } | null;
        }[];
    } | null;
}

interface VagasAtivasProps {
    setShowConfigureSlotsModal: (v: boolean) => void;
    setShowFillSlotModal: (v: boolean) => void;
    handleSlotClick: (space: any) => void;
    setSelectedDay: (d: Date | null) => void;
    totalSlots: number;
}

export function VagasAtivas({
    setShowConfigureSlotsModal,
    setShowFillSlotModal,
    handleSlotClick,
    setSelectedDay,
    totalSlots,
}: VagasAtivasProps) {
    const { user } = useAuth();
    const companyId = user?.companyId;

    const [currentDate, setCurrentDate] = useState(new Date());
    const [searchParams] = useSearchParams();
    const searchParamValue = searchParams.get("search") || "";
    const [searchTerm, setSearchTerm] = useState(searchParamValue);

    useEffect(() => {
        if (searchParamValue) {
            setSearchTerm(searchParamValue);
        }
    }, [searchParamValue]);

    const monthStart = startOfMonth(currentDate);
    const monthEnd = endOfMonth(currentDate);
    const days = eachDayOfInterval({ start: monthStart, end: monthEnd });

    const prevMonth = () => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1));
    const nextMonth = () => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1));

    // Fetch active spaces from Supabase over month block
    const { data: spaces, isLoading } = useQuery({
        queryKey: ['spaces', companyId, format(currentDate, 'yyyy-MM')],
        queryFn: async () => {
            const { data, error } = await supabase
                .from('spaces')
                .select(`
          *,
          client:clients(id, name, phone, birth_date, email),
          vehicle:vehicles(id, brand, model, plate, year),
          sale:sales(
            id, total, subtotal, discount,
            sale_items(
              id,
              total_price,
              service:services(id, name)
            )
          )
        `)
                .eq('company_id', companyId)
                .is('deleted_at', null)
                .or(`has_exited.eq.false,and(entry_date.gte.${format(monthStart, 'yyyy-MM-dd')},entry_date.lte.${format(monthEnd, 'yyyy-MM-dd')})`)
                .order('entry_date', { ascending: false });

            if (error) throw error;
            return data as unknown as SpaceData[];
        },
        enabled: !!companyId,
    });

    const occupiedCount = spaces?.filter(s => !s.has_exited).length || 0;
    const availableCount = totalSlots - occupiedCount;

    const filteredSpaces = spaces?.filter(s => !s.has_exited).filter(s => {
        if (!searchTerm) return true;
        const term = searchTerm.toLowerCase();
        return (
            s.client?.name.toLowerCase().includes(term) ||
            (s.vehicle?.plate && s.vehicle.plate.toLowerCase().includes(term))
        );
    }) || [];

    const getSpacesForDay = (date: Date) => {
        const dayStr = format(date, 'yyyy-MM-dd');
        return spaces?.filter(s => s.entry_date === dayStr) || [];
    };

    return (
        <div className="space-y-6 mt-6">
            {/* Summary Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <Card
                    className="bg-card/50 border-border/50 cursor-pointer hover:bg-card/80 transition-colors"
                    onClick={() => setShowConfigureSlotsModal(true)}
                >
                    <CardContent className="p-4">
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-primary/10">
                                <Car className="h-5 w-5 text-primary" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground flex items-center gap-2">
                                    Total de Vagas
                                    <Badge variant="outline" className="text-[10px] px-1 py-0 h-4 hover:bg-transparent">Configurar</Badge>
                                </p>
                                <p className="text-2xl font-bold">{totalSlots}</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>

                <Card className="bg-card/50 border-border/50">
                    <CardContent className="p-4">
                        <div className="flex items-center gap-3">
                            <div className={cn(
                                "p-2 rounded-lg",
                                availableCount < 0
                                    ? "bg-red-500/10"
                                    : availableCount === 0
                                        ? "bg-amber-500/10"
                                        : "bg-green-500/10"
                            )}>
                                {availableCount <= 0 ? (
                                    <AlertTriangle className={cn(
                                        "h-5 w-5",
                                        availableCount < 0 ? "text-red-500" : "text-amber-500"
                                    )} />
                                ) : (
                                    <CheckCircle className="h-5 w-5 text-green-500" />
                                )}
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Disponíveis</p>
                                <p className={cn(
                                    "text-2xl font-bold",
                                    availableCount < 0
                                        ? "text-red-500"
                                        : availableCount === 0
                                            ? "text-amber-500"
                                            : "text-green-500"
                                )}>{availableCount}</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>

                <Card className="bg-card/50 border-border/50">
                    <CardContent className="p-4">
                        <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-yellow-500/10">
                                <Clock className="h-5 w-5 text-yellow-500" />
                            </div>
                            <div>
                                <p className="text-sm text-muted-foreground">Ocupadas</p>
                                <p className="text-2xl font-bold text-yellow-500">{occupiedCount}</p>
                            </div>
                        </div>
                    </CardContent>
                </Card>
            </div>

            {occupiedCount >= totalSlots && (
                <Alert
                    variant={occupiedCount > totalSlots ? "destructive" : "default"}
                    className={cn(
                        "transition-all duration-300 shadow-md border-2",
                        occupiedCount > totalSlots
                            ? "bg-red-500/10 border-red-500/30 text-red-200"
                            : "bg-amber-500/10 border-amber-500/30 text-amber-200"
                    )}
                >
                    <AlertTriangle className={cn(
                        "h-5 w-5 animate-pulse shrink-0",
                        occupiedCount > totalSlots ? "text-red-500" : "text-amber-500"
                    )} />
                    <AlertTitle className="font-bold text-base ml-2">
                        {occupiedCount > totalSlots ? "Limite de Vagas Excedido!" : "Limite de Vagas Atingido!"}
                    </AlertTitle>
                    <AlertDescription className="text-sm opacity-90 mt-1 ml-2">
                        O limite de vagas ({totalSlots}) do seu estabelecimento foi {occupiedCount > totalSlots ? "excedido" : "atingido"}. Para que uma nova vaga fique disponível, outra vaga deve encerrar o serviço.
                    </AlertDescription>
                </Alert>
            )}

            {/* Slots Grid */}
            <Card className="bg-card/50 border-border/50">
                <CardHeader className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                    <CardTitle className="text-lg">Vagas Ocupadas</CardTitle>
                    <div className="relative w-full sm:w-64">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                        <Input
                            placeholder="Buscar por cliente ou placa..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="pl-10 h-9"
                        />
                    </div>
                </CardHeader>
                <CardContent>
                    {isLoading ? (
                        <div className="flex items-center justify-center py-12">
                            <Loader2 className="h-8 w-8 animate-spin text-primary" />
                        </div>
                    ) : filteredSpaces.length > 0 ? (
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                            {filteredSpaces.map(space => (
                                <SlotCard
                                    key={space.id}
                                    space={space}
                                    onClick={() => handleSlotClick(space)}
                                />
                            ))}
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center py-12 text-muted-foreground">
                            <Car className="h-12 w-12 mb-4 opacity-50" />
                            <p>{searchTerm ? "Nenhuma vaga encontrada para sua busca" : "Nenhuma vaga ocupada no momento"}</p>
                            {!searchTerm && (
                                <Button
                                    variant="link"
                                    className="mt-2"
                                    onClick={() => setShowFillSlotModal(true)}
                                >
                                    Preencher primeira vaga
                                </Button>
                            )}
                        </div>
                    )}
                </CardContent>
            </Card>

            {/* Calendar */}
            <Card className="bg-card/50 border-border/50">
                <CardHeader>
                    <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                        <CardTitle className="text-lg">Calendário de Ocupação</CardTitle>
                        <div className="flex items-center justify-between sm:justify-end gap-2 w-full sm:w-auto">
                            <Button variant="ghost" size="icon" onClick={prevMonth}>
                                <ChevronLeft className="h-4 w-4" />
                            </Button>
                            <span className="font-medium min-w-[120px] sm:min-w-[140px] text-center capitalize">
                                {format(currentDate, "MMMM yyyy", { locale: ptBR })}
                            </span>
                            <Button variant="ghost" size="icon" onClick={nextMonth}>
                                <ChevronRight className="h-4 w-4" />
                            </Button>
                        </div>
                    </div>
                </CardHeader>
                <CardContent>
                    <div className="mb-4">
                        <BrazilCalendarLegend />
                    </div>
                    <div className="grid grid-cols-7 gap-1 sm:gap-2 mb-1">
                        {['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'].map(day => (
                            <div key={day} className="text-center text-[11px] sm:text-sm font-semibold text-muted-foreground py-1 sm:py-2 truncate">{day}</div>
                        ))}
                    </div>
                    <div className="grid grid-cols-7 gap-1 sm:gap-2">
                        {Array.from({ length: monthStart.getDay() }).map((_, i) => (
                            <div key={`empty-${i}`} className="h-[72px] sm:h-auto sm:aspect-square" />
                        ))}
                        {days.map(day => {
                            const daySpaces = getSpacesForDay(day);
                            const inProgress = daySpaces.filter(s => !s.has_exited && s.payment_status !== 'paid').length;
                            const completed = daySpaces.filter(s => s.has_exited || s.payment_status === 'paid').length;
                            const calendarEvent = getPrimaryBrazilCalendarEvent(day);
                            const eventTitle = getBrazilCalendarTitle(day);

                            return (
                                <button
                                    key={format(day, 'yyyy-MM-dd')}
                                    onClick={() => setSelectedDay(day)}
                                    title={eventTitle}
                                    className={cn(
                                        "h-[72px] sm:h-auto sm:aspect-square sm:min-h-[100px] p-1.5 sm:p-2 rounded-lg sm:rounded-xl border transition-all flex flex-col items-center cursor-pointer hover:bg-accent/80 hover:scale-[1.02] overflow-hidden relative shadow-sm",
                                        calendarEvent &&
                                        BRAZIL_CALENDAR_EVENT_STYLES[calendarEvent.kind].dayClass,
                                        isToday(day) && "border-primary ring-1 ring-primary/20",
                                        !isSameMonth(day, currentDate) && "opacity-40"
                                    )}
                                >
                                    <div className="flex w-full justify-between items-start mb-0.5 sm:mb-0 sm:absolute sm:top-1.5 sm:left-1.5 sm:right-1.5 pointer-events-none">
                                        {isToday(day) ? (
                                            <span className="rounded bg-red-600 text-white text-[8px] sm:text-[10px] font-black px-1 py-px sm:px-1.5 sm:py-0.5 shadow-[0_0_8px_rgba(239,68,68,0.7)] border border-red-500 uppercase tracking-wide leading-none z-10 shrink-0">
                                                Hoje
                                            </span>
                                        ) : <div className="shrink-0" />}

                                        {calendarEvent ? (
                                            <span
                                                className={cn(
                                                    "max-w-[60%] truncate rounded px-1 py-px sm:px-1.5 sm:py-0.5 text-[7px] sm:text-[7px] font-bold leading-none origin-right",
                                                    BRAZIL_CALENDAR_EVENT_STYLES[calendarEvent.kind].chipClass
                                                )}
                                            >
                                                {calendarEvent.shortName}
                                            </span>
                                        ) : null}
                                    </div>

                                    <div className="flex flex-col items-center justify-center my-auto">
                                        <span className={cn(
                                            "text-xl sm:text-4xl font-extrabold tracking-tight leading-none",
                                            isToday(day) ? "text-primary" : "text-foreground"
                                        )}>
                                            {format(day, 'd')}
                                        </span>
                                        <span className="text-[9px] sm:text-[11px] font-bold text-muted-foreground/60 mt-0.5 sm:mt-1.5 leading-none">
                                            {daySpaces.length}/{totalSlots}
                                        </span>
                                    </div>

                                    {(inProgress > 0 || completed > 0) ? (
                                        <>
                                            <div className="hidden sm:flex flex-col gap-1 items-center w-full mt-auto">
                                                {inProgress > 0 && (
                                                    <Badge variant="default" className="text-xs px-1.5 py-0 bg-yellow-500 text-yellow-950 hover:bg-yellow-600 truncate flex justify-center w-full font-bold shadow-sm">
                                                        {inProgress} {inProgress === 1 ? 'vaga' : 'vagas'}
                                                    </Badge>
                                                )}
                                                {completed > 0 && (
                                                    <Badge variant="default" className="text-xs px-1.5 py-0 bg-green-500 text-white hover:bg-green-600 truncate flex justify-center w-full font-bold shadow-sm">
                                                        {completed} {completed === 1 ? 'vaga' : 'vagas'}
                                                    </Badge>
                                                )}
                                            </div>
                                            <div className="flex sm:hidden flex-row items-center justify-center gap-1 mt-auto w-full pb-0.5">
                                                {inProgress > 0 && (
                                                    <div className="w-4 h-4 rounded-full bg-yellow-500 text-yellow-950 flex items-center justify-center text-[8px] font-extrabold shadow-sm">
                                                        {inProgress}
                                                    </div>
                                                )}
                                                {completed > 0 && (
                                                    <div className="w-4 h-4 rounded-full bg-green-500 text-white flex items-center justify-center text-[8px] font-extrabold shadow-sm">
                                                        {completed}
                                                    </div>
                                                )}
                                            </div>
                                        </>
                                    ) : (
                                        <div className="h-4 sm:h-8 w-full pointer-events-none opacity-0 mt-auto" />
                                    )}
                                </button>
                            );
                        })}
                    </div>
                    <div className="flex gap-4 mt-4 text-sm text-muted-foreground font-medium">
                        <div className="flex items-center gap-2">
                            <div className="w-3 h-3 rounded bg-yellow-500 shadow-sm" />
                            <span>Em andamento</span>
                        </div>
                        <div className="flex items-center gap-2">
                            <div className="w-3 h-3 rounded bg-green-500 shadow-sm" />
                            <span>Finalizados</span>
                        </div>
                    </div>
                </CardContent>
            </Card>
        </div>
    );
}

