import { useState, useEffect } from "react";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog";
import {
  Car,
  Calendar,
  Clock,
  Search,
  DollarSign,
  User,
  FileText,
  Loader2,
  AlertTriangle,
  CheckCircle,
  QrCode,
  Banknote,
  CreditCard,
  Receipt,
  Landmark,
  Plus,
} from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { cn } from "@/lib/utils";
import { PaymentBlock, SalePayment } from "@/pages/Vendas/components/PaymentBlock";
import { createTransactionFromSale } from "@/lib/stockConsumption";
import {
  reverseAllSaleTransactions,
  createBoletoInstallmentTransactions,
} from "@/lib/financialTransactions";

interface UnpaidExitedVehicle {
  id: number;
  name: string;
  client_id: number | null;
  vehicle_id: number | null;
  sale_id: number | null;
  entry_date: string | null;
  entry_time: string | null;
  exit_date: string | null;
  exit_time: string | null;
  has_exited: boolean | null;
  payment_status: string | null;
  observations: string | null;
  tag: string | null;
  discount: number | null;
  services_data?: any[];
  deleted_at?: string | null;
  deleted_by?: string | null;
  deleted_reason?: string | null;
  client?: {
    id: number;
    name: string;
    phone: string;
    birth_date: string | null;
  } | null;
  vehicle?: {
    id: number;
    brand: string;
    model: string;
    plate: string | null;
    year: number | null;
  } | null;
  sale?: {
    id: number;
    total: number;
    subtotal: number;
    discount: number | null;
    is_open: boolean;
    sale_items?: {
      id: number;
      total_price: number;
      service?: {
        id: number;
        name: string;
      } | null;
    }[];
  } | null;
}

interface UnpaidExitedVehiclesProps {
  refreshTrigger?: number;
  onSpaceClick?: (space: UnpaidExitedVehicle) => void;
}

const UnpaidExitedVehicles = ({ refreshTrigger, onSpaceClick }: UnpaidExitedVehiclesProps) => {
  const { user } = useAuth();
  const [vehicles, setVehicles] = useState<UnpaidExitedVehicle[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [markingPaidId, setMarkingPaidId] = useState<number | null>(null);
  const [confirmSpace, setConfirmSpace] = useState<UnpaidExitedVehicle | null>(null);
  const [payments, setPayments] = useState<SalePayment[]>([]);

  const companyId = user?.companyId;

  useEffect(() => {
    if (companyId) {
      fetchUnpaidExitedVehicles();
    }
  }, [companyId, refreshTrigger]);

  const fetchUnpaidExitedVehicles = async () => {
    try {
      const { data, error } = await supabase
        .from("spaces")
        .select(`
          *,
          client:clients(id, name, phone, birth_date, email),
          vehicle:vehicles(id, brand, model, plate, year),
          sale:sales(
            id, total, subtotal, discount, is_open,
            sale_items(
              id,
              total_price,
              service:services(id, name)
            )
          )
        `)
        .eq("company_id", companyId)
        .or("payment_status.neq.paid,payment_status.is.null")
        .is("deleted_at", null)
        .order("updated_at", { ascending: false });

      if (error) throw error;

      setVehicles((data || []) as unknown as UnpaidExitedVehicle[]);
    } catch (error) {
      console.error("Erro ao buscar veículos não pagos:", error);
      toast.error("Erro ao carregar veículos não pagos");
    } finally {
      setIsLoading(false);
    }
  };

  const handleMarkAsPaid = async (spaceId: number, saleId: number | null, paymentsList: SalePayment[]) => {
    if (!saleId) {
      toast.error("Vaga sem venda vinculada. Abra os detalhes e exporte-a para uma venda antes de receber.");
      return;
    }

    if (paymentsList.length === 0) {
      toast.error("Por favor, adicione pelo menos uma forma de pagamento.");
      return;
    }

    // Validate accounts
    if (paymentsList.some(p => !p.account_id)) {
      toast.error("Por favor, selecione a conta de destino para todos os pagamentos.");
      return;
    }

    const totalToReceive = confirmSpace?.sale?.total || 0;
    const paymentsTotal = paymentsList.reduce((acc, p) => acc + p.amount, 0);
    if (Math.abs(paymentsTotal - totalToReceive) > 0.01) {
      toast.error(`A soma dos pagamentos (R$ ${paymentsTotal.toFixed(2)}) deve ser igual ao total a receber (R$ ${totalToReceive.toFixed(2)})`);
      return;
    }

    setMarkingPaidId(spaceId);
    try {
      const hasBoleto = paymentsList.some(p => p.payment_method === "Boleto");
      const newPaymentStatus = hasBoleto ? "pending" : "paid";

      // Update space payment status
      const { error: spaceError } = await supabase
        .from("spaces")
        .update({ payment_status: newPaymentStatus })
        .eq("id", spaceId);

      if (spaceError) throw spaceError;

      // Close linked sale and update payment method info
      const finalPaymentMethod = paymentsList.length === 1
        ? paymentsList[0].payment_method
        : paymentsList.map(p => p.payment_method).filter((v, i, a) => a.indexOf(v) === i).join(" + ");

      const { error: saleError } = await supabase
        .from("sales")
        .update({ is_open: false, status: "Fechada", payment_method: finalPaymentMethod })
        .eq("id", saleId);

      if (saleError) throw saleError;

      // Clean existing payments and transactions to prevent duplicates
      await supabase.from("sale_payments").delete().eq("sale_id", saleId);
      await reverseAllSaleTransactions(saleId, "delete");

      // Fetch client details
      const { data: saleData } = await supabase
        .from('sales')
        .select('id, total, sale_date, client_id, company_id')
        .eq('id', saleId)
        .single();

      let clientName = 'Cliente';
      if (saleData?.client_id) {
        const { data: clientData } = await supabase
          .from('clients')
          .select('name')
          .eq('id', saleData.client_id)
          .single();
        if (clientData) clientName = clientData.name;
      }

      if (saleData && companyId) {
        const saleDateStr = saleData.sale_date;

        for (const p of paymentsList) {
          // Calculate net amount if card
          let finalNetAmount = p.amount;
          if ((p.payment_method === "Crédito" || p.payment_method === "Débito") && p.machine_id) {
            if (p.payment_method === "Débito") {
              const { data: machineData } = await supabase
                .from("card_machines")
                .select("debit_rate")
                .eq("id", p.machine_id)
                .single();
              if (machineData?.debit_rate) {
                finalNetAmount = p.amount * (1 - machineData.debit_rate / 100);
              }
            } else {
              const { data: rateData } = await supabase
                .from("card_machine_rates")
                .select("rate")
                .eq("machine_id", p.machine_id)
                .eq("installments", p.installments)
                .single();

              if (rateData) {
                finalNetAmount = p.amount * (1 - rateData.rate / 100);
              }
            }
          }


          // Insert sale payment
          await supabase.from("sale_payments").insert({
            sale_id: saleId,
            method: p.payment_method,
            amount: p.amount,
            account_id: p.account_id,
            machine_id: p.machine_id,
            installments: p.installments,
            status: p.status || 'received',
            company_id: companyId
          });

          const isBoleto = p.payment_method === "Boleto";
          if (!isBoleto) {
            await createTransactionFromSale(
              saleId,
              p.amount,
              clientName,
              p.payment_method,
              saleDateStr,
              companyId,
              p.account_id,
              p.machine_id,
              p.installments,
              finalNetAmount,
              true // isPaid
            );
          }

          // If Boleto, register installments
          if (isBoleto) {
            // Delete existing boletos if any to avoid duplication
            const { data: existingBoletos } = await supabase.from("boletos").select("id").eq("sale_id", saleId);
            if (existingBoletos && existingBoletos.length > 0) {
              const boletoIds = existingBoletos.map(eb => eb.id);
              await supabase.from("boleto_installments").delete().in("boleto_id", boletoIds);
              await supabase.from("boletos").delete().eq("sale_id", saleId);
            }

            const { data: boletoData, error: boletoError } = await supabase
              .from("boletos")
              .insert({
                sale_id: saleId,
                total_amount: p.amount,
                status: 'pending',
                company_id: companyId,
                account_id: p.account_id as number,
                client_id: saleData.client_id
              })
              .select()
              .single();

            if (boletoError) throw boletoError;

            if (boletoData) {
              const installmentsToInsert = [];
              const installmentAmount = p.amount / (p.installments || 1);

              for (let i = 1; i <= (p.installments || 1); i++) {
                const dueDate = new Date(saleDateStr + 'T12:00:00');
                dueDate.setMonth(dueDate.getMonth() + i);

                installmentsToInsert.push({
                  boleto_id: boletoData.id,
                  installment_number: i,
                  amount: installmentAmount,
                  due_date: format(dueDate, 'yyyy-MM-dd'),
                  status: 'pending'
                });
              }

              await supabase.from("boleto_installments").insert(installmentsToInsert);

              const { data: createdInstallments } = await supabase
                .from("boleto_installments")
                .select("id, installment_number, amount, due_date")
                .eq("boleto_id", boletoData.id)
                .order("installment_number");

              if (createdInstallments && createdInstallments.length > 0) {
                await createBoletoInstallmentTransactions({
                  saleId: saleId,
                  clientName: clientName,
                  saleDate: saleDateStr,
                  companyId,
                  accountId: p.account_id as number,
                  installments: createdInstallments.map(ci => ({
                    installmentNumber: ci.installment_number,
                    amount: ci.amount,
                    dueDate: ci.due_date,
                    installmentId: ci.id,
                  })),
                });
              }
            }
          }
        }
      }

      toast.success("Pagamento confirmado e transação criada! Veículo movido para aba de pagos.");
      fetchUnpaidExitedVehicles();
      setConfirmSpace(null);
    } catch (error) {
      console.error("Erro ao marcar como pago:", error);
      toast.error("Erro ao confirmar pagamento");
    } finally {
      setMarkingPaidId(null);
    }
  };

  const openPaymentConfirmation = (space: UnpaidExitedVehicle) => {
    setConfirmSpace(space);
    setPayments([
      {
        tempId: Math.random().toString(36).substr(2, 9),
        payment_method: "Pix",
        amount: space.sale ? space.sale.total : 0,
        account_id: null,
        machine_id: null,
        installments: 1,
        due_date: new Date().toISOString(),
        status: 'received'
      }
    ]);
  };

  const handleConfirmPayment = () => {
    if (!confirmSpace) return;
    handleMarkAsPaid(confirmSpace.id, confirmSpace.sale_id, payments);
  };

  const formatDate = (dateStr: string | null) => {
    if (!dateStr) return "-";
    return format(new Date(dateStr), "dd/MM/yyyy", { locale: ptBR });
  };

  const filteredVehicles = vehicles.filter((v) => {
    const term = searchTerm.toLowerCase();
    return (
      v.client?.name?.toLowerCase().includes(term) ||
      v.vehicle?.brand?.toLowerCase().includes(term) ||
      v.vehicle?.model?.toLowerCase().includes(term) ||
      v.vehicle?.plate?.toLowerCase().includes(term)
    );
  });

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Header com busca */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h3 className="text-lg font-semibold flex items-center gap-2">
            <AlertTriangle className="h-5 w-5 text-warning" />
            Veículos Não Pagos
          </h3>
          <p className="text-sm text-muted-foreground">
            {filteredVehicles.length} registro(s)
          </p>
        </div>
        <div className="relative w-full sm:w-64">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Buscar por cliente, veículo..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-9"
          />
        </div>
      </div>

      {/* Lista de veículos */}
      {filteredVehicles.length === 0 ? (
        <Card className="bg-card/50 border-border/50">
          <CardContent className="flex flex-col items-center justify-center py-12">
            <Car className="h-12 w-12 text-muted-foreground/50 mb-4" />
            <p className="text-muted-foreground">
              {searchTerm
                ? "Nenhum veículo encontrado com esse termo"
                : "Nenhum veículo não pago"}
            </p>
          </CardContent>
        </Card>
      ) : (
        <div className="grid gap-4">
          {filteredVehicles.map((space) => (
            <Card
              key={space.id}
              className="bg-card/50 border-border/50 hover:bg-card/80 transition-colors border-l-4 border-l-warning cursor-pointer"
              onClick={() => onSpaceClick?.(space)}
            >
              <CardContent className="p-4">
                <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4">
                  <div className="space-y-2 flex-1">
                    {/* Cliente */}
                    <div className="flex items-center gap-2">
                      <User className="h-4 w-4 text-info shrink-0" />
                      <span className="font-medium text-sm sm:text-base leading-snug">
                        {space.client?.name || "Cliente não informado"}
                      </span>
                    </div>

                    {/* Veículo */}
                    <div className="flex items-center gap-2">
                      <Car className="h-4 w-4 text-muted-foreground shrink-0" />
                      <span className="text-xs sm:text-sm">
                        {space.vehicle
                          ? `${space.vehicle.brand} ${space.vehicle.model} - ${space.vehicle.plate || "Sem placa"}`
                          : "Veículo não informado"}
                      </span>
                    </div>

                    {/* Datas */}
                    <div className="flex flex-col sm:flex-row sm:items-center gap-1 sm:gap-4 text-xs sm:text-sm text-muted-foreground pt-1 sm:pt-0">
                      <span className="flex items-center gap-1.5">
                        <Calendar className="h-3.5 w-3.5" />
                        Entrada: {formatDate(space.entry_date)}{" "}
                        {space.entry_time && `às ${space.entry_time.slice(0, 5)}`}
                      </span>
                      <span className="flex items-center gap-1.5">
                        <Clock className="h-3.5 w-3.5" />
                        Saída: {formatDate(space.exit_date)}{" "}
                        {space.exit_time && `às ${space.exit_time.slice(0, 5)}`}
                      </span>
                    </div>

                    {/* Observações */}
                    {space.observations && (
                      <div className="flex items-start gap-2 mt-2 pt-2 border-t border-border/40 sm:border-0 sm:pt-0">
                        <FileText className="h-4 w-4 text-muted-foreground mt-0.5 shrink-0" />
                        <p className="text-xs sm:text-sm text-muted-foreground">
                          {space.observations}
                        </p>
                      </div>
                    )}
                  </div>

                  {/* Status e Valor */}
                  <div className="flex flex-row sm:flex-col items-center sm:items-end justify-between sm:justify-start gap-2 w-full sm:w-auto mt-2 sm:mt-0 pt-3 sm:pt-0 border-t sm:border-0 border-border/40 shrink-0">
                    <div className="flex flex-col sm:items-end">
                      <Badge className="bg-warning/20 text-warning border-warning/30 w-fit mb-1 px-1.5 py-0">
                        <AlertTriangle className="h-3 w-3 mr-1" />
                        Não Pago
                      </Badge>
                      {space.sale && (
                        <span className="text-base sm:text-lg font-bold text-warning flex items-center gap-1">
                          <DollarSign className="h-4 w-4" />
                          R$ {space.sale.total.toFixed(2)}
                        </span>
                      )}
                    </div>
                    <Button
                      size="sm"
                      variant="outline"
                      className="text-success border-success/30 hover:bg-success/10 self-center sm:self-auto h-10 sm:h-9"
                      onClick={(e) => {
                        e.stopPropagation();
                        openPaymentConfirmation(space);
                      }}
                      disabled={markingPaidId === space.id}
                    >
                      {markingPaidId === space.id ? (
                        <Loader2 className="h-4 w-4 animate-spin mr-1" />
                      ) : (
                        <CheckCircle className="h-4 w-4 mr-1" />
                      )}
                      Marcar como Pago
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Modal de confirmação de pagamento */}
      <Dialog open={!!confirmSpace} onOpenChange={(open) => !open && setConfirmSpace(null)}>
        <DialogContent className="w-[95vw] max-w-xl rounded-lg max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <DollarSign className="h-5 w-5 text-success" />
              Confirmar Pagamento
            </DialogTitle>
            <DialogDescription>
              Confirme as formas de pagamento antes de registrar o recebimento.
            </DialogDescription>
          </DialogHeader>

          {confirmSpace && (
            <div className="space-y-5 py-2">
              {/* Resumo da vaga */}
              <div className="rounded-lg bg-muted/50 border p-3 space-y-1.5">
                <div className="flex items-center gap-2 text-sm">
                  <User className="h-4 w-4 text-info" />
                  <span className="font-medium">{confirmSpace.client?.name || "Cliente não informado"}</span>
                </div>
                <div className="flex items-center gap-2 text-sm text-muted-foreground">
                  <Car className="h-4 w-4" />
                  <span>
                    {confirmSpace.vehicle
                      ? `${confirmSpace.vehicle.brand} ${confirmSpace.vehicle.model} - ${confirmSpace.vehicle.plate || "Sem placa"}`
                      : "Veículo não informado"}
                  </span>
                </div>
                {confirmSpace.sale && (
                  <div className="flex items-center justify-between pt-2 mt-2 border-t border-border/50">
                    <span className="text-sm text-muted-foreground">Total a receber:</span>
                    <span className="text-lg font-bold text-success">
                      R$ {confirmSpace.sale.total.toFixed(2)}
                    </span>
                  </div>
                )}
              </div>

              {/* Seção de Pagamentos */}
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <Label className="text-sm font-semibold">Pagamentos</Label>
                  <Button
                    variant="outline"
                    size="sm"
                    className="h-8 gap-1 text-xs"
                    onClick={() => {
                      const totalToReceive = confirmSpace?.sale?.total || 0;
                      const currentPaid = payments.reduce((acc, curr) => acc + curr.amount, 0);
                      const remaining = Math.max(0, totalToReceive - currentPaid);
                      setPayments([...payments, {
                        tempId: Math.random().toString(36).substr(2, 9),
                        payment_method: "Pix",
                        amount: remaining,
                        account_id: payments[0]?.account_id || null,
                        machine_id: null,
                        installments: 1,
                        due_date: new Date().toISOString(),
                        status: 'received'
                      }]);
                    }}
                  >
                    <Plus className="h-3.5 w-3.5" />
                    Adicionar Forma
                  </Button>
                </div>

                <div className="space-y-3">
                  {payments.map((p, index) => (
                    <PaymentBlock
                      key={p.tempId}
                      payment={p}
                      isFirst={index === 0}
                      companyId={companyId || 0}
                      totalRemaining={confirmSpace?.sale ? confirmSpace.sale.total - payments.reduce((acc, curr, i) => i < index ? acc + curr.amount : acc, 0) : 0}
                      onUpdate={(updated) => setPayments(payments.map(item => item.tempId === p.tempId ? updated : item))}
                      onRemove={() => setPayments(payments.filter(item => item.tempId !== p.tempId))}
                    />
                  ))}
                </div>

                {(() => {
                  const totalToReceive = confirmSpace?.sale?.total || 0;
                  const paidTotal = payments.reduce((acc, p) => acc + p.amount, 0);
                  const diff = paidTotal - totalToReceive;
                  const isBalanced = Math.abs(diff) < 0.01;
                  const isExcess = diff > 0.01;
                  const isShort = diff < -0.01;

                  return (
                    <div className={cn(
                      "p-3 rounded-lg text-sm font-medium space-y-1 border",
                      isBalanced
                        ? "bg-green-500/10 text-green-600 border-green-500/20"
                        : isExcess
                          ? "bg-amber-500/10 text-amber-600 border-amber-500/20"
                          : "bg-red-500/10 text-red-600 border-red-500/20"
                    )}>
                      <div className="flex justify-between items-center">
                        <span>Total Pago: R$ {paidTotal.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                        <span>Total Venda: R$ {totalToReceive.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      </div>
                      {!isBalanced && (
                        <div className={cn(
                          "text-xs pt-1 border-t flex items-center gap-1.5",
                          isExcess ? "border-amber-500/20" : "border-red-500/20"
                        )}>
                          {isExcess ? (
                            <span>⚠ Valor superior em <strong>R$ {Math.abs(diff).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</strong></span>
                          ) : (
                            <span>⚠ Restam <strong>R$ {Math.abs(diff).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</strong> para concluir</span>
                          )}
                        </div>
                      )}
                    </div>
                  );
                })()}
              </div>
            </div>
          )}

          <DialogFooter className="flex-row gap-2 justify-end sm:justify-end">
            <Button variant="outline" onClick={() => setConfirmSpace(null)}>
              Cancelar
            </Button>
            <Button
              className="bg-success hover:bg-success/90 text-white gap-2"
              onClick={handleConfirmPayment}
              disabled={markingPaidId === confirmSpace?.id}
            >
              {markingPaidId === confirmSpace?.id ? (
                <Loader2 className="h-4 w-4 animate-spin" />
              ) : (
                <CheckCircle className="h-4 w-4" />
              )}
              Confirmar Pagamento
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default UnpaidExitedVehicles;

import { useState, useEffect } from "react";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog";
import {
  Car,
  CheckCircle,
  Calendar,
  Clock,
  Search,
  DollarSign,
  User,
  FileText,
  Loader2,
  Trash2,
  Undo2,
} from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { useToast } from "@/hooks/use-toast";
import { logger } from "@/lib/logger";
import { reverseAllSaleTransactions } from "@/lib/financialTransactions";

interface PaidExitedVehicle {
  id: number;
  name: string;
  client_id: number | null;
  vehicle_id: number | null;
  sale_id: number | null;
  entry_date: string | null;
  entry_time: string | null;
  exit_date: string | null;
  exit_time: string | null;
  payment_status: string | null;
  observations: string | null;
  client?: {
    id: number;
    name: string;
    phone: string;
  } | null;
  vehicle?: {
    id: number;
    brand: string;
    model: string;
    plate: string | null;
    year: number | null;
  } | null;
  sale?: {
    id: number;
    total: number;
  } | null;
}

interface PaidExitedVehiclesProps {
  refreshTrigger?: number;
}

const PaidExitedVehicles = ({ refreshTrigger }: PaidExitedVehiclesProps) => {
  const { user } = useAuth();
  const { toast } = useToast();
  const [vehicles, setVehicles] = useState<PaidExitedVehicle[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");

  // Custom dialog states
  const [revertSpace, setRevertSpace] = useState<PaidExitedVehicle | null>(null);
  const [isReverting, setIsReverting] = useState(false);
  const [deleteSpaceId, setDeleteSpaceId] = useState<number | null>(null);
  const [deleteReason, setDeleteReason] = useState("");
  const [isDeleting, setIsDeleting] = useState(false);

  const companyId = user?.companyId;

  useEffect(() => {
    if (companyId) {
      fetchPaidExitedVehicles();
    }
  }, [companyId, refreshTrigger]);

  const fetchPaidExitedVehicles = async () => {
    try {
      const { data, error } = await supabase
        .from("spaces")
        .select(`
          id, name, client_id, vehicle_id, sale_id, entry_date, entry_time, exit_date, exit_time, payment_status, observations, company_id,
          client:clients(id, name, phone, email),
          vehicle:vehicles(id, brand, model, plate, year),
          sale:sales(id, total)
        `)
        .eq("company_id", companyId)
        .eq("payment_status", "paid")
        .is("deleted_at", null)
        .order("updated_at", { ascending: false });

      if (error) throw error;

      setVehicles((data || []) as unknown as PaidExitedVehicle[]);
    } catch (error) {
      logger.error("Erro ao buscar veículos pagos:", error);
      toast({
        title: "Erro ao carregar veículos pagos",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleRevertConfirm = async () => {
    if (!revertSpace) return;
    setIsReverting(true);

    try {
      // 1) First update the space — clears sale_id FK and resets status
      const { error: spaceError } = await supabase
        .from("spaces")
        .update({
          payment_status: "pending",
          sale_id: null,
          has_exited: false,
          exit_date: null,
          exit_time: null
        })
        .eq("id", revertSpace.id);

      if (spaceError) throw spaceError;

      // 2) If there was a linked sale, delete all dependent records then the sale
      if (revertSpace.sale_id) {
        // Delete service_items_detailed linked to the sale
        const { error: sidError } = await supabase
          .from("service_items_detailed")
          .delete()
          .eq("sale_id", revertSpace.sale_id);
        if (sidError) logger.error("Erro ao deletar service_items_detailed:", sidError);

        // Delete sale_items linked to the sale
        const { error: siError } = await supabase
          .from("sale_items")
          .delete()
          .eq("sale_id", revertSpace.sale_id);
        if (siError) logger.error("Erro ao deletar sale_items:", siError);

        // Delete sale_commissions linked to the sale
        const { error: scError } = await supabase
          .from("sale_commissions")
          .delete()
          .eq("sale_id", revertSpace.sale_id);
        if (scError) logger.error("Erro ao deletar sale_commissions:", scError);

        // Delete transactions linked to the sale via centralized service
        // The trigger handles balance correction on DELETE
        const { count: reversedTxs } = await reverseAllSaleTransactions(revertSpace.sale_id, "delete");
        if (reversedTxs > 0) {
          logger.log(`[PaidExited] Reversed ${reversedTxs} transactions for sale ${revertSpace.sale_id}`);
        }

        // Delete warranties linked to the sale
        const { error: wError } = await supabase
          .from("warranties")
          .delete()
          .eq("sale_id", revertSpace.sale_id);
        if (wError) logger.error("Erro ao deletar warranties:", wError);

        // Finally delete the sale itself
        const { error: saleError } = await supabase
          .from("sales")
          .delete()
          .eq("id", revertSpace.sale_id);

        if (saleError) {
          logger.error("Erro ao deletar venda vinculada:", saleError);
          // Sale deletion failed but space was already reverted — log but don't throw
        }
      }

      toast({
        title: "Vaga revertida com sucesso!",
        description: "A vaga retornou para o status original na aba de espaços ativos.",
      });
      fetchPaidExitedVehicles();
      setRevertSpace(null);
    } catch (error) {
      logger.error("Erro ao reverter vaga:", error);
      toast({
        title: "Erro ao reverter",
        description: "Não foi possível reverter a vaga.",
        variant: "destructive",
      });
    } finally {
      setIsReverting(false);
    }
  };

  const handleDeleteConfirm = async () => {
    if (!deleteSpaceId) return;
    setIsDeleting(true);

    try {
      const { error } = await supabase.rpc('soft_delete_space', {
        p_space_id: deleteSpaceId,
        p_reason: deleteReason.trim() || "Nenhum motivo informado."
      });

      if (error) throw error;

      toast({
        title: "Vaga movida para a lixeira com sucesso!",
      });
      fetchPaidExitedVehicles();
      setDeleteSpaceId(null);
      setDeleteReason("");
    } catch (error) {
      logger.error("Erro ao excluir registro:", error);
      toast({
        title: "Erro ao excluir",
        description: "Não foi possível mover o registro para a lixeira.",
        variant: "destructive",
      });
    } finally {
      setIsDeleting(false);
    }
  };

  const formatDate = (dateStr: string | null) => {
    if (!dateStr) return "-";
    return format(new Date(dateStr), "dd/MM/yyyy", { locale: ptBR });
  };

  const filteredVehicles = vehicles.filter((v) => {
    const term = searchTerm.toLowerCase();
    return (
      v.client?.name?.toLowerCase().includes(term) ||
      v.vehicle?.brand?.toLowerCase().includes(term) ||
      v.vehicle?.model?.toLowerCase().includes(term) ||
      v.vehicle?.plate?.toLowerCase().includes(term)
    );
  });

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* Header com busca */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h3 className="text-lg font-semibold flex items-center gap-2">
            <CheckCircle className="h-5 w-5 text-success" />
            Veículos Pagos
          </h3>
          <p className="text-sm text-muted-foreground">
            {filteredVehicles.length} registro(s)
          </p>
        </div>
        <div className="relative w-full sm:w-64">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Buscar por cliente, veículo..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-9"
          />
        </div>
      </div>

      {/* Lista de veículos */}
      {filteredVehicles.length === 0 ? (
        <Card className="bg-card/50 border-border/50">
          <CardContent className="flex flex-col items-center justify-center py-12">
            <Car className="h-12 w-12 text-muted-foreground/50 mb-4" />
            <p className="text-muted-foreground">
              {searchTerm
                ? "Nenhum veículo encontrado com esse termo"
                : "Nenhum veículo pago ainda"}
            </p>
          </CardContent>
        </Card>
      ) : (
        <div className="grid gap-4">
          {filteredVehicles.map((space) => (
            <Card
              key={space.id}
              className="bg-card/50 border-border/50 hover:bg-card/80 transition-colors"
            >
              <CardContent className="p-4">
                <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4">
                  <div className="space-y-2 flex-1">
                    {/* Cliente */}
                    <div className="flex items-center gap-2">
                      <User className="h-4 w-4 text-info shrink-0" />
                      <span className="font-medium text-sm sm:text-base leading-snug">
                        {space.client?.name || "Cliente não informado"}
                      </span>
                    </div>

                    {/* Veículo */}
                    <div className="flex items-center gap-2">
                      <Car className="h-4 w-4 text-muted-foreground shrink-0" />
                      <span className="text-xs sm:text-sm">
                        {space.vehicle
                          ? `${space.vehicle.brand} ${space.vehicle.model} - ${space.vehicle.plate || "Sem placa"}`
                          : "Veículo não informado"}
                      </span>
                    </div>

                    {/* Datas */}
                    <div className="flex flex-col sm:flex-row sm:items-center gap-1 sm:gap-4 text-xs sm:text-sm text-muted-foreground pt-1 sm:pt-0">
                      <span className="flex items-center gap-1.5">
                        <Calendar className="h-3.5 w-3.5" />
                        Entrada: {formatDate(space.entry_date)}{" "}
                        {space.entry_time && `às ${space.entry_time.slice(0, 5)}`}
                      </span>
                      <span className="flex items-center gap-1.5">
                        <Clock className="h-3.5 w-3.5" />
                        Saída: {formatDate(space.exit_date)}{" "}
                        {space.exit_time && `às ${space.exit_time.slice(0, 5)}`}
                      </span>
                    </div>

                    {/* Observações */}
                    {space.observations && (
                      <div className="flex items-start gap-2 mt-2 pt-2 border-t border-border/40 sm:border-0 sm:pt-0">
                        <FileText className="h-4 w-4 text-muted-foreground mt-0.5 shrink-0" />
                        <p className="text-xs sm:text-sm text-muted-foreground">
                          {space.observations}
                        </p>
                      </div>
                    )}
                  </div>

                  {/* Status e Valor */}
                  <div className="flex flex-row sm:flex-col items-center sm:items-end justify-between sm:justify-start gap-2 w-full sm:w-auto mt-2 sm:mt-0 pt-3 sm:pt-0 border-t sm:border-0 border-border/40 shrink-0">
                    <div className="flex flex-col sm:items-end">
                      <Badge className="bg-success/20 text-success border-success/30 w-fit mb-1 px-1.5 py-0">
                        <CheckCircle className="h-3 w-3 mr-1" />
                        Pago
                      </Badge>
                      {space.sale && (
                        <span className="text-base sm:text-lg font-bold text-success flex items-center gap-1">
                          <DollarSign className="h-4 w-4" />
                          R$ {space.sale.total.toFixed(2)}
                        </span>
                      )}
                    </div>
                    <div className="flex gap-2 sm:mt-auto self-center sm:self-auto">
                      <Button
                        variant="ghost"
                        size="sm"
                        className="text-amber-500 hover:text-amber-600 hover:bg-amber-500/10 h-10 sm:h-9"
                        onClick={() => setRevertSpace(space)}
                      >
                        <Undo2 className="h-4 w-4 mr-1 sm:mr-2" />
                        Reverter
                      </Button>
                      <Button
                        variant="ghost"
                        size="sm"
                        className="text-destructive hover:text-destructive hover:bg-destructive/10 h-10 sm:h-9"
                        onClick={() => setDeleteSpaceId(space.id)}
                      >
                        <Trash2 className="h-4 w-4 mr-1 sm:mr-2" />
                        Excluir
                      </Button>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Modal de Confirmação de Reversão */}
      <Dialog open={!!revertSpace} onOpenChange={(open) => !open && setRevertSpace(null)}>
        <DialogContent className="w-[95vw] max-w-md rounded-lg">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Undo2 className="h-5 w-5 text-amber-500" />
              Reverter Vaga
            </DialogTitle>
            <DialogDescription>
              Deseja reverter esta vaga para não paga? Caso esteja vinculada a uma venda, a venda será excluída e os serviços retornarão para a vaga.
            </DialogDescription>
          </DialogHeader>

          <DialogFooter className="flex-row gap-2 justify-end sm:justify-end mt-4">
            <Button variant="outline" onClick={() => setRevertSpace(null)} disabled={isReverting}>
              Cancelar
            </Button>
            <Button
              className="bg-amber-500 hover:bg-amber-600 text-white gap-2"
              onClick={handleRevertConfirm}
              disabled={isReverting}
            >
              {isReverting ? (
                <Loader2 className="h-4 w-4 animate-spin" />
              ) : (
                <Undo2 className="h-4 w-4" />
              )}
              Reverter Vaga
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Modal de Exclusão (Mover para Lixeira) */}
      <Dialog open={!!deleteSpaceId} onOpenChange={(open) => !open && (setDeleteSpaceId(null), setDeleteReason(""))}>
        <DialogContent className="w-[95vw] max-w-md rounded-lg">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Trash2 className="h-5 w-5 text-destructive" />
              Mover para a Lixeira
            </DialogTitle>
            <DialogDescription>
              Tem certeza que deseja mover esta vaga para a lixeira operacional?
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-2 py-2">
            <Label htmlFor="delete-reason" className="text-xs font-semibold">Motivo da Exclusão</Label>
            <Input
              id="delete-reason"
              placeholder="Digite o motivo da exclusão..."
              value={deleteReason}
              onChange={(e) => setDeleteReason(e.target.value)}
              className="w-full"
            />
          </div>

          <DialogFooter className="flex-row gap-2 justify-end sm:justify-end mt-4">
            <Button variant="outline" onClick={() => (setDeleteSpaceId(null), setDeleteReason(""))} disabled={isDeleting}>
              Cancelar
            </Button>
            <Button
              className="bg-destructive hover:bg-destructive/90 text-white gap-2"
              onClick={handleDeleteConfirm}
              disabled={isDeleting}
            >
              {isDeleting ? (
                <Loader2 className="h-4 w-4 animate-spin" />
              ) : (
                <Trash2 className="h-4 w-4" />
              )}
              Mover para Lixeira
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default PaidExitedVehicles;

import { useState, useEffect } from "react";
import { Plus, Search, AlertTriangle, CheckCircle, Package, ArrowDown, ArrowUp, Tag, Trash2, StopCircle, History, Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { usePlanGate } from "@/hooks/usePlanGate";
import { useNavigate } from "react-router-dom";
import { cn } from "@/lib/utils";
import { NewMaterialModal } from "@/components/estoque/NewMaterialModal";
import { StockEntryModal } from "@/components/estoque/StockEntryModal";
import { StockExitModal } from "@/components/estoque/StockExitModal";
import { ConsumptionRulesModal } from "@/components/estoque/ConsumptionRulesModal";
import { MaterialDetailsModal } from "@/components/estoque/MaterialDetailsModal";
import { ProductTypesTab } from "@/components/estoque/ProductTypesTab";
import { MaterialHistoryTab } from "@/components/estoque/MaterialHistoryTab";
import { CloseRollModal } from "@/components/estoque/CloseRollModal";
import { HelpOverlay } from "@/components/help/HelpOverlay";
import { toast } from "sonner";

interface Material {
  id: number;
  name: string;
  type: string | null;
  brand: string | null;
  unit: string;
  current_stock: number | null;
  minimum_stock: number | null;
  average_cost: number | null;
  is_active: boolean | null;
  is_open_roll: boolean | null;
  open_roll_accumulated: number | null;
  company_id: number | null;
  product_type_id: number | null;
  product_types: { light_transmission: string | null; cost_per_meter: number | null } | null;
  width: number | null;
}

export default function Estoque() {
  const { user, isLoading: authLoading } = useAuth();
  const gate = usePlanGate('estoque');
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState("product-types");
  const [search, setSearch] = useState("");
  const [typeFilter, setTypeFilter] = useState("todos");
  const [statusFilter, setStatusFilter] = useState("todos");
  const [materials, setMaterials] = useState<Material[]>([]);
  const [loading, setLoading] = useState(true);
  const [showNewMaterial, setShowNewMaterial] = useState(false);
  const [showEntry, setShowEntry] = useState(false);
  const [showExit, setShowExit] = useState(false);
  const [showRules, setShowRules] = useState(false);
  const [showDetails, setShowDetails] = useState(false);
  const [showCloseRoll, setShowCloseRoll] = useState(false);
  const [selectedMaterial, setSelectedMaterial] = useState<Material | null>(null);
  const [companyId, setCompanyId] = useState<number | null>(null);

  const fetchMaterials = async () => {
    if (!user?.id || !gate.hasAccess) return;

    try {
      const { data: profile } = await supabase
        .from("profiles")
        .select("company_id")
        .eq("user_id", user.id)
        .single();

      if (!profile?.company_id) {
        setLoading(false);
        return;
      }

      setCompanyId(profile.company_id);

      const { data, error } = await supabase
        .from("materials")
        .select("*, product_types(light_transmission, cost_per_meter)")
        .eq("company_id", profile.company_id)
        .eq("is_active", true)
        .order("name");

      if (error) throw error;

      setMaterials((data as any as Material[]) || []);
    } catch (error) {
      console.error("Error fetching materials:", error);
      toast.error("Erro ao carregar materiais");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (user?.id && gate.hasAccess) {
      fetchMaterials();
    }
  }, [user?.id, gate.hasAccess]);

  useEffect(() => {
    if (!authLoading && !gate.hasAccess) {
      if (gate.message) {
        toast.error(gate.message);
      }
      if (gate.redirectTo) {
        navigate(gate.redirectTo, { replace: true });
      }
    }
  }, [authLoading, gate.hasAccess, gate.redirectTo, gate.message, navigate]);

  const getStockStatus = (material: Material) => {
    const currentStock = material.current_stock || 0;
    const minStock = material.minimum_stock || 1;
    const ratio = currentStock / minStock;

    if (ratio <= 0.5) return { status: "critico", label: "Crítico", color: "text-red-500", bg: "bg-red-500/10" };
    if (ratio <= 1) return { status: "baixo", label: "Baixo", color: "text-yellow-500", bg: "bg-yellow-500/10" };
    return { status: "ok", label: "OK", color: "text-green-500", bg: "bg-green-500/10" };
  };

  const filteredMaterials = materials.filter(m => {
    let pass = true;

    if (search) {
      const lowerSearch = search.toLowerCase();
      if (!m.name.toLowerCase().includes(lowerSearch) &&
        !(m.type?.toLowerCase() || "").includes(lowerSearch)) {
        pass = false;
      }
    }

    if (typeFilter !== "todos" && m.type !== typeFilter) {
      pass = false;
    }

    if (statusFilter !== "todos") {
      if (statusFilter === "em_uso") {
        if (!m.is_open_roll) pass = false;
      } else {
        if (m.is_open_roll) {
          pass = false;
        } else {
          const status = getStockStatus(m).status;
          if (status !== statusFilter) pass = false;
        }
      }
    }

    return pass;
  });

  const openRolls = filteredMaterials.filter(m => m.is_open_roll);
  const regularMaterials = filteredMaterials.filter(m => !m.is_open_roll);
  const insulfilmMaterials = filteredMaterials.filter(m => m.type?.toUpperCase() === "INSULFILM");
  const ppfMaterials = filteredMaterials.filter(m => m.type?.toUpperCase() === "PPF");
  const otherMaterials = filteredMaterials.filter(m => m.type?.toUpperCase() !== "INSULFILM" && m.type?.toUpperCase() !== "PPF");

  const criticalCount = materials.filter(m => {
    if (m.is_open_roll) return false;
    const ratio = (m.current_stock || 0) / (m.minimum_stock || 1);
    return ratio <= 0.5;
  }).length;

  const lowCount = materials.filter(m => {
    if (m.is_open_roll) return false;
    const ratio = (m.current_stock || 0) / (m.minimum_stock || 1);
    return ratio > 0.5 && ratio <= 1;
  }).length;

  const openRollsCount = materials.filter(m => m.is_open_roll).length;

  const closedStockValue = materials.reduce((sum, m) => {
    if (m.is_open_roll) return sum;
    const currentCost = m.product_types?.cost_per_meter || m.average_cost || 0;
    return sum + ((m.current_stock || 0) * currentCost);
  }, 0);

  const openStockValue = materials.reduce((sum, m) => {
    if (!m.is_open_roll) return sum;
    const currentCost = m.product_types?.cost_per_meter || m.average_cost || 0;
    return sum + ((m.open_roll_accumulated || 0) * currentCost);
  }, 0);

  const handleEntry = (material: Material) => {
    setSelectedMaterial(material);
    setShowEntry(true);
  };

  const handleExit = (material: Material) => {
    setSelectedMaterial(material);
    setShowExit(true);
  };

  const handleDetails = (material: Material) => {
    setSelectedMaterial(material);
    setShowDetails(true);
  };

  const handleDelete = async (material: Material) => {
    if (!confirm(`Tem certeza que deseja excluir "${material.name}"?`)) return;

    try {
      // Verifica se existem movimentações
      const { count } = await supabase
        .from("stock_movements")
        .select("*", { count: "exact", head: true })
        .eq("material_id", material.id);

      if (count && count > 0) {
        // Soft delete - apenas desativa
        const { error } = await supabase
          .from("materials")
          .update({ is_active: false })
          .eq("id", material.id);

        if (error) throw error;
      } else {
        // Hard delete - remove completamente
        const { error } = await supabase
          .from("materials")
          .delete()
          .eq("id", material.id);

        if (error) throw error;
      }

      toast.success("Material excluído com sucesso");
      fetchMaterials();
    } catch (error) {
      console.error("Error deleting material:", error);
      toast.error("Erro ao excluir material");
    }
  };

  const handleCloseOpenRoll = async (material: Material) => {
    setSelectedMaterial(material);
    setShowCloseRoll(true);
  };

  const handleMaterialCreated = () => {
    fetchMaterials();
    setShowNewMaterial(false);
    toast.success("Material criado com sucesso!");
  };

  const handleMovementCompleted = () => {
    fetchMaterials();
    setShowEntry(false);
    setShowExit(false);
    setSelectedMaterial(null);
  };

  const renderMaterialTable = (items: Material[]) => (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
      {items.map((material) => {
        const stockStatus = getStockStatus(material);
        const currentCost = material.product_types?.cost_per_meter || material.average_cost || 0;
        const totalVal = (material.is_open_roll
          ? (material.open_roll_accumulated || 0)
          : (material.current_stock || 0)) * currentCost;

        return (
          <Card key={material.id} className="bg-card/50 border-border/50 p-4 flex flex-col justify-between space-y-3 hover:border-primary/30 transition-all duration-300">
            <div className="space-y-3">
              {/* Topo: Nome e Ações Rápidas (Excluir e Detalhes) */}
              <div className="flex items-start justify-between gap-2">
                <div
                  className="cursor-pointer hover:text-primary hover:underline transition-colors flex-1"
                  onClick={() => handleDetails(material)}
                >
                  <h4 className="font-semibold text-base text-foreground leading-tight">{material.name}</h4>
                  {material.brand && (
                    <span className="text-xs text-muted-foreground">{material.brand}</span>
                  )}
                </div>
                <Button
                  variant="ghost"
                  size="icon"
                  onClick={() => handleDelete(material)}
                  title="Excluir"
                  className="text-muted-foreground hover:text-destructive h-8 w-8 -mt-1 -mr-1 shrink-0"
                >
                  <Trash2 className="h-4 w-4" />
                </Button>
              </div>

              {/* Informações de Bobina / Transmissão */}
              {(material.unit === "Metros" && material.width) || material.product_types?.light_transmission || material.type ? (
                <div className="flex flex-wrap gap-1.5 text-xs">
                  {material.type && (
                    <Badge variant="outline" className="text-[10px] py-0 px-2 font-normal">
                      {material.type}
                    </Badge>
                  )}
                  {material.product_types?.light_transmission && (
                    <Badge variant="outline" className="text-[10px] py-0 px-2 font-normal border-amber-500/20 text-amber-600 bg-amber-500/5">
                      VLT: {material.product_types.light_transmission}
                    </Badge>
                  )}
                  {material.unit === "Metros" && material.width && (
                    <Badge variant="outline" className="text-[10px] py-0 px-2 font-normal border-blue-500/20 text-blue-600 bg-blue-500/5">
                      Bobina: {Number(material.width).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}m
                    </Badge>
                  )}
                </div>
              ) : null}

              {/* Status e Indicadores Principais */}
              <div className="grid grid-cols-3 gap-2 py-2.5 border-y border-border/40 text-center">
                <div>
                  <span className="text-[10px] text-muted-foreground block mb-0.5">Estoque</span>
                  <span className="font-semibold text-xs text-foreground block truncate">
                    {material.is_open_roll ? (
                      <span className="text-blue-500 font-semibold" title={`Aberta. Usado: ${material.open_roll_accumulated || 0}m`}>
                        Aberta
                      </span>
                    ) : (
                      `${material.current_stock || 0} ${material.unit}`
                    )}
                  </span>
                </div>
                <div>
                  <span className="text-[10px] text-muted-foreground block mb-0.5">Mínimo / Status</span>
                  <div className="flex flex-col items-center justify-center">
                    {material.is_open_roll ? (
                      <Badge className="bg-blue-500/10 text-blue-500 hover:bg-blue-500/10 border-0 text-[10px] py-0 px-1.5 font-normal">Em Uso</Badge>
                    ) : (
                      <Badge className={cn(stockStatus.bg, stockStatus.color, "border-0 hover:bg-transparent text-[10px] py-0 px-1.5 font-normal")}>
                        {stockStatus.label}
                      </Badge>
                    )}
                  </div>
                </div>
                <div>
                  <span className="text-[10px] text-muted-foreground block mb-0.5">
                    {material.is_open_roll ? "Consumido" : "Valor Total"}
                  </span>
                  <span className="font-semibold text-xs text-foreground block truncate" title={`R$ ${totalVal.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}`}>
                    R$ {totalVal.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}
                  </span>
                </div>
              </div>
            </div>

            {/* Botões de Ações de Transação */}
            <div className="flex gap-2 pt-2">
              {!material.is_open_roll ? (
                <>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => handleEntry(material)}
                    className="flex-1 h-9 text-xs border-green-500/20 hover:bg-green-500/5 hover:text-green-600"
                  >
                    <ArrowDown className="mr-1 h-3.5 w-3.5 text-green-500" /> Entrada
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => handleExit(material)}
                    className="flex-1 h-9 text-xs border-red-500/20 hover:bg-red-500/5 hover:text-red-600"
                  >
                    <ArrowUp className="mr-1 h-3.5 w-3.5 text-red-500" /> Saída
                  </Button>
                </>
              ) : (
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleCloseOpenRoll(material)}
                  className="w-full h-9 text-xs border-blue-500/20 text-blue-600 hover:bg-blue-500/5"
                >
                  <StopCircle className="mr-1 h-3.5 w-3.5 text-blue-500" /> Encerrar Bobina
                </Button>
              )}
            </div>
          </Card>
        );
      })}
    </div>
  );

  const renderCategorySections = (categoryName: string, items: Material[]) => {
    const openRolls = items.filter(m => m.is_open_roll);
    const regularMaterials = items.filter(m => !m.is_open_roll);

    if (items.length === 0) return null;

    return (
      <div className="space-y-6 border border-border/30 bg-card/20 p-5 rounded-2xl shadow-sm">
        {/* Cabeçalho da Categoria */}
        <div className="flex items-center justify-between pb-2 border-b border-border/40">
          <div className="flex items-center gap-2">
            <div className="h-2 w-2 rounded-full bg-primary" />
            <h3 className="text-lg font-bold tracking-tight text-foreground">
              {categoryName}
            </h3>
            <Badge variant="secondary" className="ml-2 font-mono text-[10px] py-0 px-2 font-normal border border-border/50">
              {items.length} {items.length === 1 ? 'item' : 'itens'}
            </Badge>
          </div>
        </div>

        {/* Subseções */}
        <div className="space-y-6">
          {openRolls.length > 0 && (
            <div className="space-y-3">
              <h4 className="text-sm font-semibold text-blue-500 dark:text-blue-400 flex items-center gap-1.5 pl-1">
                <StopCircle className="h-4 w-4 text-blue-500" /> Bobinas Abertas ({openRolls.length})
              </h4>
              {renderMaterialTable(openRolls)}
            </div>
          )}

          {regularMaterials.length > 0 && (
            <div className="space-y-3">
              <h4 className="text-sm font-semibold text-emerald-500 dark:text-emerald-400 flex items-center gap-1.5 pl-1">
                <Package className="h-4 w-4 text-emerald-500" /> Estoque Padrão (Fechado) ({regularMaterials.length})
              </h4>
              {renderMaterialTable(regularMaterials)}
            </div>
          )}
        </div>
      </div>
    );
  };

  if (loading || authLoading || !gate.hasAccess) {
    return (
      <div className="space-y-6 p-6">
        <Skeleton className="h-10 w-48" />
        <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
          {[1, 2, 3, 4, 5].map((i) => (
            <Skeleton key={i} className="h-24" />
          ))}
        </div>
        <Skeleton className="h-96" />
      </div>
    );
  }

  return (
    <div className="space-y-6 p-6 max-w-[100vw] overflow-x-hidden">
      <HelpOverlay
        tabId="estoque"
        title="Guia de Estoque"
        sections={[
          {
            title: "Vídeo Aula — Estoque",
            description: "Assista ao vídeo tutorial completo para aprender a usar todas as funcionalidades da gestão de estoque.",
            videoUrl: "/help/video-aula-estoque.mp4"
          },
          {
            title: "Tipos de Materiais",
            description: "Na aba 'Tipos de Materiais', cadastre os tipos de películas e materiais com detalhes como marca, modelo e transmissão de luz. Esses tipos são usados para identificar qual película foi aplicada em cada serviço.",
            screenshotUrl: "/help/help-estoque-tipos.png"
          },
          {
            title: "Cadastrar Metragem de Materiais",
            description: "Na aba 'Metragem de Materiais', clique em 'Novo Material' para cadastrar um item. Defina o nome, tipo, marca, unidade de medida, estoque mínimo e custo médio. O sistema alertará quando o estoque ficar baixo ou crítico.",
            screenshotUrl: "/help/help-estoque-materiais.png"
          },
          {
            title: "Entradas e Saídas",
            description: "Use as setas ↓ (entrada) e ↑ (saída) na tabela para registrar movimentações de estoque. O saldo é atualizado automaticamente. Cards no topo mostram o valor total em estoque e alertas de itens baixos/críticos.",
            screenshotUrl: "/help/help-estoque-movimentacoes.png"
          },
        ]}
      />

      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold">Gestão de Estoque</h1>
        <p className="text-muted-foreground">Controle de metragem de materiais e tipos de materiais</p>
      </div>

      {/* Sistema de Abas Principal */}
      <Tabs value={activeTab} onValueChange={setActiveTab} className="space-y-6">
        <TabsList className="grid grid-cols-3 w-full max-w-lg">
          <TabsTrigger value="product-types" className="flex items-center gap-2">
            <Tag className="h-4 w-4" />
            <span className="hidden sm:inline">Tipos de Materiais</span>
          </TabsTrigger>
          <TabsTrigger value="materials" className="flex items-center gap-2">
            <Package className="h-4 w-4" />
            <span className="hidden sm:inline">Metragem de Materiais</span>
          </TabsTrigger>
          <TabsTrigger value="history" className="flex items-center gap-2">
            <History className="h-4 w-4" />
            <span className="hidden sm:inline">Histórico</span>
          </TabsTrigger>
        </TabsList>

        {/* Aba Materiais */}
        <TabsContent value="materials" className="space-y-6">
          {/* Header da aba */}
          <div className="flex items-center justify-end gap-2">
            <Button onClick={() => setShowNewMaterial(true)}>
              <Plus className="h-4 w-4 mr-2" /> Adicionar Metros
            </Button>
          </div>

          {/* Stats */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            <Card className="bg-card/50 border-border/50">
              <CardContent className="p-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 rounded-lg bg-primary/10">
                    <Package className="h-5 w-5 text-primary" />
                  </div>
                  <div className="overflow-hidden">
                    <p className="text-sm text-muted-foreground truncate">Total de Itens</p>
                    <p className="text-2xl font-bold truncate">{materials.length}</p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card className="bg-card/50 border-border/50">
              <CardContent className="p-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 rounded-lg bg-green-500/10">
                    <CheckCircle className="h-5 w-5 text-green-500" />
                  </div>
                  <div className="overflow-hidden">
                    <p className="text-sm text-muted-foreground truncate" title="Valor Est. Fechado">Valor Est. Fechado</p>
                    <p className="text-2xl font-bold truncate" title={`R$ ${closedStockValue.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}`}>
                      R$ {closedStockValue.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card className="bg-card/50 border-border/50">
              <CardContent className="p-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 rounded-lg bg-blue-500/10">
                    <CheckCircle className="h-5 w-5 text-blue-500" />
                  </div>
                  <div className="overflow-hidden">
                    <p className="text-sm text-muted-foreground truncate" title="Valor Est. Aberto">Valor Est. Aberto</p>
                    <p className="text-2xl font-bold text-blue-500 truncate" title={`R$ ${openStockValue.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}`}>
                      R$ {openStockValue.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card className="bg-card/50 border-border/50">
              <CardContent className="p-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 rounded-lg bg-yellow-500/10">
                    <AlertTriangle className="h-5 w-5 text-yellow-500" />
                  </div>
                  <div className="overflow-hidden">
                    <p className="text-sm text-muted-foreground truncate">Estoque Baixo</p>
                    <p className="text-2xl font-bold text-yellow-500 truncate">{lowCount}</p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card className="bg-card/50 border-border/50">
              <CardContent className="p-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 rounded-lg bg-red-500/10">
                    <AlertTriangle className="h-5 w-5 text-red-500" />
                  </div>
                  <div className="overflow-hidden">
                    <p className="text-sm text-muted-foreground truncate">Estoque Crítico</p>
                    <p className="text-2xl font-bold text-red-500 truncate">{criticalCount}</p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card className="bg-card/50 border-border/50">
              <CardContent className="p-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 rounded-lg bg-blue-500/10">
                    <Package className="h-5 w-5 text-blue-500" />
                  </div>
                  <div className="overflow-hidden">
                    <p className="text-sm text-muted-foreground truncate">Bobinas Abertas</p>
                    <p className="text-2xl font-bold text-blue-500 truncate">{openRollsCount}</p>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Search & Filters */}
          <div className="flex flex-col sm:flex-row gap-4">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder="Buscar material..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="pl-10"
              />
            </div>

            <div className="flex gap-2 w-full sm:w-auto">
              <Select value={typeFilter} onValueChange={setTypeFilter}>
                <SelectTrigger className="w-full sm:w-[150px]">
                  <SelectValue placeholder="Tipo" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="todos">Todos Tipos</SelectItem>
                  {Array.from(new Set(materials.map(m => m.type).filter(Boolean))).sort().map(tipo => (
                    <SelectItem key={tipo} value={tipo as string}>{tipo}</SelectItem>
                  ))}
                </SelectContent>
              </Select>

              <Select value={statusFilter} onValueChange={setStatusFilter}>
                <SelectTrigger className="w-full sm:w-[150px]">
                  <SelectValue placeholder="Status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="todos">Todos Status</SelectItem>
                  <SelectItem value="ok">OK</SelectItem>
                  <SelectItem value="baixo">Baixo</SelectItem>
                  <SelectItem value="critico">Crítico</SelectItem>
                  <SelectItem value="em_uso">Em Uso</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>

          {/* Empty State or Table */}
          {materials.length === 0 ? (
            <Card className="bg-card/50 border-border/50">
              <CardContent className="p-12 text-center">
                <Package className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
                <h3 className="text-lg font-medium mb-2">Nenhum material cadastrado</h3>
                <p className="text-muted-foreground mb-4">
                  Comece adicionando os materiais utilizados nos seus serviços
                </p>
                <Button onClick={() => setShowNewMaterial(true)}>
                  <Plus className="h-4 w-4 mr-2" /> Cadastrar Primeiro Material
                </Button>
              </CardContent>
            </Card>
          ) : (
            <div className="space-y-8">
              {/* Categoria Insulfilm */}
              {renderCategorySections("Películas INSULFILM", insulfilmMaterials)}

              {/* Categoria PPF */}
              {renderCategorySections("Películas PPF", ppfMaterials)}

              {/* Outros Materiais */}
              {renderCategorySections("Outros Materiais", otherMaterials)}

              {filteredMaterials.length === 0 && (
                <Card className="bg-card/50 border-border/50">
                  <CardContent className="p-12 text-center">
                    <p className="text-muted-foreground">
                      Nenhum material encontrado para os filtros atuais.
                    </p>
                  </CardContent>
                </Card>
              )}
            </div>
          )}
        </TabsContent>

        {/* Aba Tipos de Produtos */}
        <TabsContent value="product-types">
          <ProductTypesTab companyId={companyId} />
        </TabsContent>

        {/* Aba Histórico de Materiais */}
        <TabsContent value="history">
          <MaterialHistoryTab companyId={companyId} />
        </TabsContent>
      </Tabs>

      {/* Modals */}
      <NewMaterialModal
        open={showNewMaterial}
        onOpenChange={setShowNewMaterial}
        onSuccess={handleMaterialCreated}
      />
      <StockEntryModal
        open={showEntry}
        onOpenChange={setShowEntry}
        material={selectedMaterial}
        onSuccess={handleMovementCompleted}
      />
      <StockExitModal
        open={showExit}
        onOpenChange={setShowExit}
        material={selectedMaterial}
        onSuccess={handleMovementCompleted}
      />
      <ConsumptionRulesModal open={showRules} onOpenChange={setShowRules} />
      <MaterialDetailsModal
        open={showDetails}
        onOpenChange={setShowDetails}
        material={selectedMaterial}
      />
      <CloseRollModal
        open={showCloseRoll}
        onOpenChange={setShowCloseRoll}
        material={selectedMaterial}
        onSuccess={() => {
          setShowCloseRoll(false);
          fetchMaterials();
        }}
      />
    </div>
  );
}

import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Landmark, PiggyBank, Wallet, TrendingUp, CreditCard, Search } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";

interface Account {
  id: number;
  name: string;
  account_type: string | null;
  current_balance: number | null;
  is_main: boolean | null;
  accepted_payment_methods?: string[] | null;
}

interface Transaction {
  id: number;
  name: string;
  amount: number;
  type: string;
  transaction_date: string;
}

interface AccountDetailsModalProps {
  account: Account | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function AccountDetailsModal({ account, open, onOpenChange }: AccountDetailsModalProps) {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [filterType, setFilterType] = useState<"all" | "Entrada" | "Saída">("all");

  useEffect(() => {
    if (open && account) {
      fetchTransactions();
    }
  }, [open, account]);

  const fetchTransactions = async () => {
    if (!account) return;
    setLoading(true);
    try {
      const { data } = await supabase
        .from("transactions")
        .select("id, name, amount, type, transaction_date")
        .eq("account_id", account.id)
        .order("transaction_date", { ascending: false })
        .limit(300); // Fetch more for client-side filtering

      setTransactions(data || []);
    } catch (error) {
      console.error("Error fetching account transactions:", error);
    } finally {
      setLoading(false);
    }
  };

  const getAccountIcon = (type: string | null) => {
    switch (type) {
      case 'Conta Corrente': return <Landmark className="h-6 w-6" />;
      case 'Poupança': return <PiggyBank className="h-6 w-6" />;
      case 'Carteira': return <Wallet className="h-6 w-6" />;
      case 'Investimento': return <TrendingUp className="h-6 w-6" />;
      default: return <CreditCard className="h-6 w-6" />;
    }
  };

  const formatCurrency = (value: number) => {
    return `R$ ${value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;
  };

  const filteredTransactions = transactions.filter(t => {
    let pass = true;
    if (searchTerm && !t.name.toLowerCase().includes(searchTerm.toLowerCase())) {
      pass = false;
    }
    if (filterType !== "all" && t.type !== filterType) {
      pass = false;
    }
    return pass;
  });

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>Detalhes da Conta</DialogTitle>
        </DialogHeader>

        {account && (
          <div className="space-y-6">
            <div className="flex items-center gap-4 bg-muted/30 p-4 rounded-xl border">
              <div className="p-3 bg-primary/10 text-primary rounded-xl">
                {getAccountIcon(account.account_type)}
              </div>
              <div>
                <h3 className="text-xl font-bold leading-none mb-1">{account.name}</h3>
                <p className="text-sm text-muted-foreground">{account.account_type}</p>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="bg-card border p-4 rounded-xl text-center">
                <p className="text-sm text-muted-foreground mb-1 uppercase tracking-wider font-semibold">Saldo Atual</p>
                <p className="text-2xl font-bold font-mono tracking-tight text-primary">
                  {formatCurrency(account.current_balance || 0)}
                </p>
              </div>
              <div className="bg-card border p-4 rounded-xl text-center flex flex-col justify-center items-center">
                <p className="text-sm text-muted-foreground mb-1 uppercase tracking-wider font-semibold">Status</p>
                {account.is_main ? (
                  <span className="text-xs bg-primary/20 text-primary px-3 py-1.5 rounded-full font-bold uppercase tracking-wider">
                    Conta Principal
                  </span>
                ) : (
                  <span className="text-xs bg-muted text-muted-foreground px-3 py-1.5 rounded-full font-bold uppercase tracking-wider">
                    Conta Secundária
                  </span>
                )}
              </div>
            </div>

            {/* Formas de pagamento */}
            <div className="bg-card border p-4 rounded-xl">
              <p className="text-sm text-muted-foreground mb-1 font-semibold">Formas de Pagamento Aceitas</p>
              <div className="flex flex-wrap gap-2 mt-2">
                {account.accepted_payment_methods ? (
                  account.accepted_payment_methods.map(method => (
                    <span key={method} className="text-xs bg-muted text-foreground px-2 py-1 rounded-md border">
                      {method}
                    </span>
                  ))
                ) : (
                  <span className="text-xs text-muted-foreground italic">Todas as formas (não configurado)</span>
                )}
              </div>
            </div>

            <div>
              <div className="flex flex-col sm:flex-row items-center justify-between gap-2 mb-3">
                <h4 className="text-sm font-semibold">Transações da Conta</h4>

                <div className="flex items-center gap-2 w-full sm:w-auto">
                  <div className="relative flex-1 sm:max-w-[200px]">
                    <Search className="absolute left-2 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground" />
                    <Input
                      placeholder="Buscar descrição..."
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                      className="pl-8 h-8 text-xs"
                    />
                  </div>
                  <div className="flex items-center rounded-md border p-0.5">
                    <Button
                      variant="ghost"
                      size="sm"
                      className={`h-7 px-2 text-xs rounded-sm ${filterType === 'all' ? 'bg-secondary' : ''}`}
                      onClick={() => setFilterType('all')}
                    >
                      Todas
                    </Button>
                    <Button
                      variant="ghost"
                      size="sm"
                      className={`h-7 px-2 text-xs rounded-sm ${filterType === 'Entrada' ? 'bg-green-500/20 text-green-600' : ''}`}
                      onClick={() => setFilterType('Entrada')}
                    >
                      Entradas
                    </Button>
                    <Button
                      variant="ghost"
                      size="sm"
                      className={`h-7 px-2 text-xs rounded-sm ${filterType === 'Saída' ? 'bg-red-500/20 text-red-600' : ''}`}
                      onClick={() => setFilterType('Saída')}
                    >
                      Saídas
                    </Button>
                  </div>
                </div>
              </div>

              {loading ? (
                <p className="text-sm text-muted-foreground text-center py-4">Carregando...</p>
              ) : filteredTransactions.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-4 bg-muted/30 rounded-lg border border-dashed">Nenhuma transação encontrada nesta conta.</p>
              ) : (
                <div className="space-y-2 max-h-[250px] overflow-y-auto pr-2">
                  {filteredTransactions.map(t => (
                    <div key={t.id} className="flex justify-between items-center p-3 border rounded-lg hover:bg-muted/50 transition-colors">
                      <div className="flex-1 min-w-0 pr-4">
                        <p className="font-medium text-sm truncate">{t.name}</p>
                        <p className="text-xs text-muted-foreground">
                          {new Date(t.transaction_date).toLocaleDateString('pt-BR')}
                        </p>
                      </div>
                      <span className={`text-sm font-bold whitespace-nowrap ${t.type === 'Entrada' ? 'text-green-500' : 'text-red-500'}`}>
                        {t.type === 'Entrada' ? '+' : '-'}{formatCurrency(t.amount)}
                      </span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Card } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { format, subDays, startOfMonth, endOfMonth, parseISO, addMonths, subMonths } from "date-fns";
import { ptBR } from "date-fns/locale";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from "recharts";
import { CAC_ORIGIN_OPTIONS, CacOrigin } from "@/constants/origins";
import { toast } from "sonner";
import { Target, TrendingUp, Users, DollarSign, PieChart, Plus, RefreshCw, UserPlus, Trash2, ChevronLeft, ChevronRight } from "lucide-react";
import { RoasEntryModal } from "./RoasEntryModal";
import { createExpenseTransaction } from "@/lib/financialTransactions";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";

export function CacTab() {
  const { user } = useAuth();
  const [currentMonth, setCurrentMonth] = useState<Date>(startOfMonth(new Date()));
  const startDate = format(startOfMonth(currentMonth), "yyyy-MM-dd");
  const endDate = format(endOfMonth(currentMonth), "yyyy-MM-dd");

  const handlePrevMonth = () => {
    setCurrentMonth(prev => subMonths(prev, 1));
  };

  const handleNextMonth = () => {
    setCurrentMonth(prev => addMonths(prev, 1));
  };
  const [loading, setLoading] = useState(false);
  const [isRoasModalOpen, setIsRoasModalOpen] = useState(false);
  const [targetRoas, setTargetRoas] = useState<number>(4);

  // Seller Expense Card States
  const [sellers, setSellers] = useState<any[]>([]);
  const [sellerId, setSellerId] = useState<string>("");
  const [sellerAmount, setSellerAmount] = useState<string>("");
  const [sellerDate, setSellerDate] = useState<string>(format(new Date(), "yyyy-MM-dd"));
  const [sellerDescription, setSellerDescription] = useState<string>("");
  const [submittingSellerExpense, setSubmittingSellerExpense] = useState<boolean>(false);
  const [accounts, setAccounts] = useState<any[]>([]);
  const [accountId, setAccountId] = useState<string>("");

  useEffect(() => {
    if (user?.companyId) {
      fetchSellers();
      fetchAccounts();
    }
  }, [user?.companyId]);

  const fetchSellers = async () => {
    try {
      const { data, error } = await supabase
        .from('commission_people')
        .select('id, name')
        .eq('company_id', user.companyId)
        .eq('type', 'VENDEDOR')
        .eq('is_active', true)
        .order('name');

      if (error) throw error;
      setSellers(data || []);
    } catch (e) {
      console.error("Error fetching sellers", e);
    }
  };

  const fetchAccounts = async () => {
    try {
      const { data, error } = await supabase
        .from('accounts')
        .select('id, name, is_main')
        .eq('company_id', user.companyId)
        .eq('is_active', true)
        .order('name');

      if (error) throw error;
      setAccounts(data || []);

      // Define a conta principal como padrão inicial, ou a primeira da lista
      const mainAcc = data?.find(a => a.is_main);
      if (mainAcc) {
        setAccountId(mainAcc.id.toString());
      } else if (data && data.length > 0) {
        setAccountId(data[0].id.toString());
      }
    } catch (e) {
      console.error("Error fetching accounts", e);
    }
  };

  useEffect(() => {
    const saved = localStorage.getItem("@stealth-crm:target-roas");
    if (saved) setTargetRoas(Number(saved));
  }, []);

  const handleTargetRoasChange = (val: string) => {
    if (val === '') {
      setTargetRoas(0);
      return;
    }
    const num = parseFloat(val);
    if (!isNaN(num)) {
      setTargetRoas(num);
      localStorage.setItem("@stealth-crm:target-roas", num.toString());
    }
  };

  // States for aggregated data
  const [totalCac, setTotalCac] = useState(0);
  const [marketingCost, setMarketingCost] = useState(0);
  const [salesCost, setSalesCost] = useState(0);
  const [newPayingClients, setNewPayingClients] = useState(0);
  const [cohortRevenue, setCohortRevenue] = useState(0);

  const [channelStats, setChannelStats] = useState<any[]>([]);
  const [cacTransactions, setCacTransactions] = useState<any[]>([]);
  const [sellerRanking, setSellerRanking] = useState<any[]>([]);

  // New vs Returning stats
  const [newClientSales, setNewClientSales] = useState(0);
  const [returningClientSales, setReturningClientSales] = useState(0);
  const [newClientRevenue, setNewClientRevenue] = useState(0);
  const [returningClientRevenue, setReturningClientRevenue] = useState(0);

  useEffect(() => {
    fetchCacData();
  }, [startDate, endDate]);

  const fetchCacData = async () => {
    if (!user?.id) return;
    setLoading(true);

    try {
      const { data: profile } = await supabase
        .from('profiles')
        .select('company_id')
        .eq('user_id', user.id)
        .single();

      if (!profile?.company_id) return;

      const companyId = profile.company_id;

      // 1. Fetch Expenses marked as CAC
      const { data: cacTxData, error: cacError } = await supabase
        .from('transactions')
        .select('*')
        .eq('company_id', companyId)
        .eq('include_in_cac', true)
        .gte('transaction_date', startDate)
        .lte('transaction_date', endDate);

      if (cacError) throw cacError;

      const transactions = (cacTxData || []) as any[];
      setCacTransactions(transactions);

      // 1.2 Fetch Commissions in period
      const { data: commData, error: commError } = await supabase
        .from('sale_commissions')
        .select(`
          commission_amount,
          commission_person_id,
          person_name_snapshot,
          person_type,
          sale:sales!inner(sale_date, status, total)
        `)
        .eq('company_id', companyId)
        .eq('sale.status', 'Fechada')
        .gte('sale.sale_date', startDate)
        .lte('sale.sale_date', endDate);

      if (commError) throw commError;

      const commissions = (commData || []) as any[];

      // Agrupar ranking de vendedores
      const sellerPerformance: Record<string, {
        id: number;
        name: string;
        vendasCount: number;
        faturamentoTotal: number;
        comissaoTotal: number;
      }> = {};

      commissions.forEach((c: any) => {
        if (c.person_type === 'VENDEDOR' && c.commission_person_id) {
          const sellerId = c.commission_person_id;
          if (!sellerPerformance[sellerId]) {
            sellerPerformance[sellerId] = {
              id: sellerId,
              name: c.person_name_snapshot || 'Vendedor',
              vendasCount: 0,
              faturamentoTotal: 0,
              comissaoTotal: 0
            };
          }
          sellerPerformance[sellerId].vendasCount += 1;
          sellerPerformance[sellerId].faturamentoTotal += Number(c.sale?.total || 0);
          sellerPerformance[sellerId].comissaoTotal += Number(c.commission_amount || 0);
        }
      });

      const sellersRank = Object.values(sellerPerformance).sort((a, b) => b.faturamentoTotal - a.faturamentoTotal);
      setSellerRanking(sellersRank);

      // Soma de comissões de vendedores no período
      const totalComissoesVendedores = commissions
        .filter((c: any) => c.person_type === 'VENDEDOR')
        .reduce((sum: number, c: any) => sum + Number(c.commission_amount || 0), 0);

      let tCac = totalComissoesVendedores;
      let mCost = 0;
      let sCost = totalComissoesVendedores;
      // Object to hold specific costs (not Geral)
      const costByOrigin: Record<string, number> = {};
      let geralCost = 0;

      transactions.forEach((tx) => {
        tCac += Number(tx.amount);
        if (tx.cac_bucket === 'marketing') mCost += Number(tx.amount);
        if (tx.cac_bucket === 'vendas') sCost += Number(tx.amount);

        const origin = tx.cac_origin || 'Desconhecido';
        if (origin === 'Geral') {
          geralCost += Number(tx.amount);
        } else {
          costByOrigin[origin] = (costByOrigin[origin] || 0) + Number(tx.amount);
        }
      });

      setTotalCac(tCac);
      setMarketingCost(mCost);
      setSalesCost(sCost);

      // 2. Fetch New Clients created in period
      const { data: clientsData, error: clientsError } = await supabase
        .from('clients')
        .select('id, origem, created_at')
        .eq('company_id', companyId)
        .gte('created_at', `${startDate}T00:00:00Z`)
        .lte('created_at', `${endDate}T23:59:59Z`);

      if (clientsError) throw clientsError;
      const clients = clientsData || [];

      // 3. Fetch Closed Sales in the period to find paying clients and their revenue
      // (Cohort: clients created in this period who also bought in this period)
      const clientIds = clients.map(c => c.id);

      let salesData: any[] = [];
      if (clientIds.length > 0) {
        const { data: sData, error: salesError } = await supabase
          .from('sales')
          .select('client_id, total')
          .in('client_id', clientIds)
          .gte('sale_date', startDate)
          .lte('sale_date', endDate)
          .eq('status', 'Fechada');

        if (salesError) throw salesError;
        salesData = sData || [];
      }

      // Aggregate revenue and count paying clients by origin
      const payingClientsByOrigin: Record<string, Set<number>> = {};
      const revenueByOrigin: Record<string, number> = {};

      let totPayingClients = 0;
      let totRevenue = 0;

      const payingClientIds = new Set(salesData.map(s => s.client_id));

      salesData.forEach(sale => {
        const client = clients.find(c => c.id === sale.client_id);
        const origin = client?.origem || 'Passante';

        revenueByOrigin[origin] = (revenueByOrigin[origin] || 0) + Number(sale.total);
        totRevenue += Number(sale.total);
      });

      clients.forEach(client => {
        if (payingClientIds.has(client.id)) {
          const origin = client.origem || 'Passante';
          if (!payingClientsByOrigin[origin]) {
            payingClientsByOrigin[origin] = new Set();
          }
          payingClientsByOrigin[origin].add(client.id);
        }
      });

      // Count unique paying clients
      Object.values(payingClientsByOrigin).forEach(set => {
        totPayingClients += set.size;
      });

      setNewPayingClients(totPayingClients);
      setCohortRevenue(totRevenue);

      // 4. Calculate stats per channel and prorate "Geral"
      const geralCostPerClient = totPayingClients > 0 ? geralCost / totPayingClients : 0;

      const stats = CAC_ORIGIN_OPTIONS.filter(o => o !== 'Geral').map((origin) => {
        const pClients = payingClientsByOrigin[origin]?.size || 0;
        const rev = revenueByOrigin[origin] || 0;

        // Direct cost for this origin
        const directCost = costByOrigin[origin] || 0;
        // Prorated general cost
        const proratedCost = pClients * geralCostPerClient;

        const totCost = directCost + proratedCost;

        const cac = pClients > 0 ? totCost / pClients : 0;
        const roas = totCost > 0 ? rev / totCost : 0;

        return {
          origem: origin,
          direto: directCost,
          rateado: proratedCost,
          custoTotal: totCost,
          clientesPagantes: pClients,
          cac: cac,
          receita: rev,
          roas: roas
        };
      });

      // Sort by paying clients descending
      stats.sort((a, b) => b.clientesPagantes - a.clientesPagantes);
      setChannelStats(stats);

      // 5. Fetch New vs Returning client data from ALL sales in the period
      const { data: allPeriodSales } = await supabase
        .from('sales')
        .select('id, client_id, total, is_new_client')
        .eq('company_id', companyId)
        .eq('status', 'Fechada')
        .gte('sale_date', startDate)
        .lte('sale_date', endDate) as { data: any[] | null };

      const allSales = allPeriodSales || [];
      let nNew = 0, nReturn = 0, revNew = 0, revReturn = 0;
      allSales.forEach(s => {
        if (s.is_new_client === false) {
          nReturn++;
          revReturn += Number(s.total);
        } else {
          nNew++;
          revNew += Number(s.total);
        }
      });
      setNewClientSales(nNew);
      setReturningClientSales(nReturn);
      setNewClientRevenue(revNew);
      setReturningClientRevenue(revReturn);

    } catch (error: any) {
      console.error("Error fetching CAC data", error);
      toast.error(`Erro ao buscar dados: ${error?.message || 'Desconhecido'}`);
    } finally {
      setLoading(false);
    }
  };

  const handleSellerExpenseSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user?.companyId) {
      toast.error("Empresa não vinculada");
      return;
    }

    if (!sellerId) {
      toast.error("Selecione um vendedor");
      return;
    }

    const valorInvestido = parseFloat(sellerAmount.replace(",", "."));
    if (isNaN(valorInvestido) || valorInvestido <= 0) {
      toast.error("Digite um valor válido maior que 0");
      return;
    }

    setSubmittingSellerExpense(true);

    try {
      if (!accountId) {
        toast.error("Selecione uma conta financeira");
        setSubmittingSellerExpense(false);
        return;
      }

      // Get seller name
      const selectedSeller = sellers.find(s => s.id.toString() === sellerId);
      const sellerName = selectedSeller ? selectedSeller.name : "Vendedor";

      const result = await createExpenseTransaction({
        name: sellerDescription ? `Comissão - ${sellerDescription}` : `Gasto Vendedor - ${sellerName}`,
        amount: valorInvestido,
        transactionDate: sellerDate,
        companyId: user.companyId,
        accountId: parseInt(accountId),
        isPaid: true,
        description: `Gasto Vendedor: ${sellerName}${sellerDescription ? ` - ${sellerDescription}` : ''}`,
        originType: "manual",
      });

      if (!result) throw new Error("Falha ao criar transação");

      // Update CAC fields in transaction
      const { error: updateError } = await supabase
        .from("transactions")
        .update({
          include_in_cac: true,
          cac_bucket: "vendas",
          cac_origin: "Geral",
        })
        .eq("id", result.id);

      if (updateError) throw updateError;

      toast.success(`Gasto com ${sellerName} registrado com sucesso!`);

      // Reset form
      setSellerAmount("");
      setSellerDescription("");
      setSellerId("");
      setSellerDate(format(new Date(), "yyyy-MM-dd"));

      // Refresh CAC data
      fetchCacData();
    } catch (error: any) {
      console.error(error);
      toast.error(`Erro ao registrar gasto: ${error.message}`);
    } finally {
      setSubmittingSellerExpense(false);
    }
  };

  const handleDeleteCacTransaction = async (id: number) => {
    if (!confirm("Tem certeza que deseja excluir esta despesa de CAC? Esta ação irá remover o lançamento do financeiro permanentemente.")) {
      return;
    }

    try {
      const { error } = await supabase
        .from('transactions')
        .delete()
        .eq('id', id);

      if (error) throw error;

      toast.success("Despesa de CAC excluída com sucesso!");
      fetchCacData();
    } catch (e: any) {
      console.error(e);
      toast.error(`Erro ao excluir despesa: ${e.message}`);
    }
  };

  const avgCac = newPayingClients > 0 ? totalCac / newPayingClients : 0;
  const globalRoas = totalCac > 0 ? cohortRevenue / totalCac : 0;
  const roasProgress = targetRoas > 0 ? Math.min((globalRoas / targetRoas) * 100, 100) : 0;

  return (
    <div className="space-y-6 animate-in fade-in duration-500">

      {/* Header and Filters */}
      <div className="flex flex-col gap-4 p-4 bg-muted/30 rounded-xl border">
        <div>
          <h2 className="text-xl font-bold tracking-tight">Custo de Aquisição de Clientes</h2>
          <p className="text-sm text-muted-foreground mt-1">Analise o retorno dos seus investimentos em marketing e vendas.</p>
          <div className="flex flex-col sm:flex-row gap-2 mt-3">
            <Button size="sm" variant="outline" className="h-8 gap-1 bg-background w-full sm:w-auto" onClick={() => setIsRoasModalOpen(true)}>
              <Plus className="h-3.5 w-3.5" /> Registrar Gasto em Ads
            </Button>
            <Button
              size="sm"
              variant="outline"
              className="h-8 gap-1 bg-background border-blue-500/30 text-blue-500 hover:text-blue-600 hover:bg-blue-500/10 transition-all w-full sm:w-auto"
              onClick={() => {
                const element = document.getElementById("quick-seller-expense-card");
                if (element) {
                  element.scrollIntoView({ behavior: "smooth", block: "center" });
                  element.classList.add("ring-2", "ring-blue-500");
                  setTimeout(() => {
                    element.classList.remove("ring-2", "ring-blue-500");
                  }, 1500);
                }
              }}
            >
              <Plus className="h-3.5 w-3.5" /> Registrar Gasto com Vendedor
            </Button>
          </div>
        </div>
        <div className="space-y-1.5 w-full sm:max-w-[280px]">
          <Label className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Período de Análise</Label>
          <div className="flex items-center gap-1.5 sm:gap-2 w-full justify-center">
            <Button
              variant="outline"
              size="icon"
              className="h-9 w-9 shrink-0 bg-background"
              onClick={handlePrevMonth}
            >
              <ChevronLeft className="h-4 w-4" />
            </Button>

            <div className="relative flex-1 min-w-0 h-9 bg-background border rounded-md flex items-center justify-center">
              <span className="text-sm font-semibold capitalize text-center">
                {format(currentMonth, 'MMMM yyyy', { locale: ptBR })}
              </span>
              <Input
                type="month"
                value={format(currentMonth, "yyyy-MM")}
                onChange={(e) => {
                  if (e.target.value) {
                    const [year, month] = e.target.value.split("-").map(Number);
                    setCurrentMonth(new Date(year, month - 1, 1, 12, 0, 0));
                  }
                }}
                className="absolute inset-0 opacity-0 w-full h-full cursor-pointer"
              />
            </div>

            <Button
              variant="outline"
              size="icon"
              className="h-9 w-9 shrink-0 bg-background"
              onClick={handleNextMonth}
            >
              <ChevronRight className="h-4 w-4" />
            </Button>
          </div>
        </div>
      </div>

      {/* Main KPI Cards */}
      <div className="grid grid-cols-2 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-3 sm:gap-4">
        <Card className="p-3 sm:p-5 flex flex-col justify-center space-y-2 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-4 opacity-5">
            <DollarSign className="w-12 h-12 sm:w-16 sm:h-16" />
          </div>
          <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Investimento (CAC)</p>
          <h3 className="text-lg sm:text-3xl font-bold text-red-500" title={new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(totalCac)}>
            {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(totalCac)}
          </h3>
          <div className="flex flex-col sm:flex-row text-[10px] text-muted-foreground gap-0.5 sm:gap-2 mt-1">
            <span className="text-orange-500/80 truncate">Mkt: {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(marketingCost)}</span>
            <span className="hidden sm:inline">•</span>
            <span className="text-blue-500/80 truncate">Vendas: {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(salesCost)}</span>
          </div>
        </Card>

        <Card className="p-3 sm:p-5 flex flex-col justify-center space-y-2 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-4 opacity-5">
            <Users className="w-12 h-12 sm:w-16 sm:h-16" />
          </div>
          <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Novos Clientes <span className="hidden sm:inline">(Pagantes)</span></p>
          <h3 className="text-2xl sm:text-3xl font-bold text-foreground">
            {newPayingClients}
          </h3>
          <p className="text-[10px] sm:text-xs text-muted-foreground mt-1 truncate">
            Clientes que geraram vendas
          </p>
        </Card>

        <Card className="p-3 sm:p-5 flex flex-col justify-center space-y-2 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-4 opacity-5">
            <Target className="w-12 h-12 sm:w-16 sm:h-16" />
          </div>
          <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">CAC Médio Global</p>
          <h3 className="text-lg sm:text-3xl font-bold text-info" title={new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(avgCac)}>
            {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(avgCac)}
          </h3>
          <p className="text-[10px] sm:text-xs text-muted-foreground mt-1 truncate">
            Custo médio por aquisição
          </p>
        </Card>

        <Card className="p-3 sm:p-5 flex flex-col justify-center space-y-2 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-4 opacity-5">
            <TrendingUp className="w-12 h-12 sm:w-16 sm:h-16" />
          </div>
          <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Receita da Coorte</p>
          <h3 className="text-lg sm:text-3xl font-bold text-green-500" title={new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(cohortRevenue)}>
            {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(cohortRevenue)}
          </h3>
          <p className="text-[10px] sm:text-xs text-muted-foreground mt-1 truncate">
            LTV Inicial gerado
          </p>
        </Card>

        <Card className="p-3 sm:p-5 flex flex-col justify-between space-y-2 relative overflow-hidden group min-h-[120px] sm:min-h-[140px]">
          <div className="absolute top-0 right-0 p-4 opacity-10">
            <PieChart className="w-12 h-12 sm:w-16 sm:h-16 text-primary" />
          </div>
          <div>
            <p className="text-xs sm:text-sm font-medium text-muted-foreground">ROAS Global</p>
            <div className="flex flex-col sm:flex-row sm:items-baseline gap-0.5 sm:gap-2 mt-1">
              <h3 className={`text-lg sm:text-3xl font-bold ${globalRoas === 0 ? 'text-primary' : (globalRoas >= targetRoas ? 'text-green-500' : 'text-red-500')}`}>
                {globalRoas === 0 ? '0.00x' : `${globalRoas.toFixed(2)}x`}
              </h3>
              {targetRoas > 0 && globalRoas > 0 && (
                <span className="text-[10px] text-muted-foreground font-medium truncate">
                  ({roasProgress.toFixed(0)}% da meta)
                </span>
              )}
            </div>

            {/* Barra de Progresso da Meta */}
            {targetRoas > 0 && (
              <div className="w-full bg-muted/60 h-1.5 rounded-full overflow-hidden mt-2">
                <div
                  className={`h-full transition-all duration-500 ${globalRoas >= targetRoas ? 'bg-green-500' : 'bg-red-500'}`}
                  style={{ width: `${roasProgress}%` }}
                />
              </div>
            )}
          </div>

          <div className="flex items-center justify-between pt-1 border-t border-border/10">
            <span className={`text-[10px] ${globalRoas === 0 ? 'text-muted-foreground' : (globalRoas >= targetRoas ? 'text-green-500/80 font-medium' : 'text-red-400/80 font-medium')}`}>
              {globalRoas === 0 ? 'Sem retorno' : (globalRoas >= targetRoas ? 'Meta atingida 🎉' : 'Abaixo da meta ⚠️')}
            </span>
            <div className="flex items-center gap-1 bg-muted/40 rounded px-1.5 py-0.5 border border-border/50">
              <span className="text-[9px] text-muted-foreground font-semibold uppercase">Meta:</span>
              <input
                type="number"
                step="0.5"
                value={targetRoas || ''}
                onChange={(e) => handleTargetRoasChange(e.target.value)}
                className="w-8 h-4 bg-transparent text-foreground text-center rounded text-[10px] focus:outline-none border-none p-0 font-bold"
              />
              <span className="text-[9px] text-muted-foreground font-medium">x</span>
            </div>
          </div>
        </Card>
      </div>

      {/* Client classification & Seller Gasto row */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* New vs Returning Card */}
        <Card className="lg:col-span-2 p-5 relative overflow-hidden flex flex-col justify-between">
          <div className="absolute top-0 right-0 p-4 opacity-5">
            <UserPlus className="w-20 h-20" />
          </div>
          <div>
            <h3 className="font-semibold flex items-center gap-2 mb-4">
              <UserPlus className="w-4 h-4 text-primary" />
              Novos vs Retorno
            </h3>
            {(newClientSales + returningClientSales) === 0 ? (
              <p className="text-sm text-muted-foreground">Sem dados de classificação de clientes no período.</p>
            ) : (
              <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-4">
                {/* New Clients */}
                <div className="space-y-1">
                  <div className="flex items-center gap-2">
                    <span className="h-3 w-3 rounded-full bg-green-500" />
                    <span className="text-sm font-medium text-muted-foreground">Novos</span>
                  </div>
                  <p className="text-2xl font-bold">{newClientSales}</p>
                  <p className="text-xs text-muted-foreground">
                    {((newClientSales / (newClientSales + returningClientSales)) * 100).toFixed(0)}% das vendas
                  </p>
                </div>
                {/* Returning Clients */}
                <div className="space-y-1">
                  <div className="flex items-center gap-2">
                    <span className="h-3 w-3 rounded-full bg-blue-500" />
                    <span className="text-sm font-medium text-muted-foreground">Retorno</span>
                  </div>
                  <p className="text-2xl font-bold">{returningClientSales}</p>
                  <p className="text-xs text-muted-foreground">
                    {((returningClientSales / (newClientSales + returningClientSales)) * 100).toFixed(0)}% das vendas
                  </p>
                </div>
                {/* Ticket Médio Novos */}
                <div className="space-y-1">
                  <p className="text-sm font-medium text-muted-foreground">Ticket Médio <span className="text-green-500">Novo</span></p>
                  <p className="text-2xl font-bold text-green-500">
                    {newClientSales > 0
                      ? new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(newClientRevenue / newClientSales)
                      : 'N/A'
                    }
                  </p>
                </div>
                {/* Ticket Médio Retorno */}
                <div className="space-y-1">
                  <p className="text-sm font-medium text-muted-foreground">Ticket Médio <span className="text-blue-500">Retorno</span></p>
                  <p className="text-2xl font-bold text-blue-500">
                    {returningClientSales > 0
                      ? new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(returningClientRevenue / returningClientSales)
                      : 'N/A'
                    }
                  </p>
                </div>
              </div>
            )}
          </div>
          {/* Progress bar */}
          {(newClientSales + returningClientSales) > 0 && (
            <div className="mt-4">
              <div className="flex h-2.5 rounded-full overflow-hidden bg-muted">
                <div
                  className="bg-green-500 transition-all duration-500"
                  style={{ width: `${(newClientSales / (newClientSales + returningClientSales)) * 100}%` }}
                />
                <div
                  className="bg-blue-500 transition-all duration-500"
                  style={{ width: `${(returningClientSales / (newClientSales + returningClientSales)) * 100}%` }}
                />
              </div>
              <div className="flex justify-between mt-1">
                <span className="text-[10px] text-green-500 font-medium">Novos</span>
                <span className="text-[10px] text-blue-500 font-medium">Retorno</span>
              </div>
            </div>
          )}
        </Card>

        {/* Gasto com Vendedor Card */}
        <Card id="quick-seller-expense-card" className="lg:col-span-1 p-5 relative overflow-hidden flex flex-col justify-between border-blue-500/15 dark:border-blue-500/30 bg-gradient-to-br from-background via-background to-blue-500/[0.03] dark:to-blue-500/[0.015] shadow-sm transition-all duration-300">
          <div className="absolute top-0 right-0 p-4 opacity-5">
            <Users className="w-20 h-20 text-blue-500" />
          </div>
          <div className="space-y-4">
            <div>
              <h3 className="font-semibold flex items-center gap-2 text-foreground">
                <Users className="w-4 h-4 text-blue-500" />
                Registrar Gasto com Vendedor
              </h3>
              <p className="text-xs text-muted-foreground mt-0.5">Lançamento de comissões/despesas de vendas para cálculo de CAC.</p>
            </div>

            <form onSubmit={handleSellerExpenseSubmit} className="space-y-3">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 sm:gap-3">
                <div className="space-y-1">
                  <Label htmlFor="sellerId" className="text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">Vendedor *</Label>
                  {sellers.length > 0 ? (
                    <Select value={sellerId} onValueChange={setSellerId}>
                      <SelectTrigger id="sellerId" className="h-9 text-xs bg-background">
                        <SelectValue placeholder="Selecione..." />
                      </SelectTrigger>
                      <SelectContent>
                        {sellers.map((s) => (
                          <SelectItem key={s.id} value={s.id.toString()} className="text-xs">
                            {s.name}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  ) : (
                    <Input
                      placeholder="Sem vendedores..."
                      disabled
                      className="h-9 text-xs bg-background"
                    />
                  )}
                </div>

                <div className="space-y-1">
                  <Label htmlFor="sellerAmount" className="text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">Valor (R$) *</Label>
                  <Input
                    id="sellerAmount"
                    type="number"
                    step="0.01"
                    required
                    placeholder="Ex: 150.00"
                    value={sellerAmount}
                    onChange={(e) => setSellerAmount(e.target.value)}
                    className="h-9 text-xs bg-background"
                  />
                </div>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 sm:gap-3">
                <div className="space-y-1">
                  <Label htmlFor="sellerDate" className="text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">Data *</Label>
                  <Input
                    id="sellerDate"
                    type="date"
                    required
                    value={sellerDate}
                    onChange={(e) => setSellerDate(e.target.value)}
                    className="h-9 text-xs bg-background"
                  />
                </div>

                <div className="space-y-1">
                  <Label htmlFor="accountId" className="text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">Conta Financeira *</Label>
                  {accounts.length > 0 ? (
                    <Select value={accountId} onValueChange={setAccountId}>
                      <SelectTrigger id="accountId" className="h-9 text-xs bg-background">
                        <SelectValue placeholder="Selecione..." />
                      </SelectTrigger>
                      <SelectContent>
                        {accounts.map((a) => (
                          <SelectItem key={a.id} value={a.id.toString()} className="text-xs">
                            {a.name} {a.is_main && "(Principal)"}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  ) : (
                    <Input
                      placeholder="Sem contas..."
                      disabled
                      className="h-9 text-xs bg-background"
                    />
                  )}
                </div>
              </div>

              <div className="space-y-1">
                <Label htmlFor="sellerDescription" className="text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">Descrição Opcional</Label>
                <Input
                  id="sellerDescription"
                  placeholder="Ex: Comissão, Bônus..."
                  value={sellerDescription}
                  onChange={(e) => setSellerDescription(e.target.value)}
                  className="h-9 text-xs bg-background"
                />
              </div>

              <Button
                type="submit"
                size="sm"
                className="w-full h-9 mt-2 text-xs bg-blue-600 hover:bg-blue-700 text-white font-medium shadow-sm transition-all"
                disabled={submittingSellerExpense || sellers.length === 0}
              >
                {submittingSellerExpense ? "Registrando..." : "Registrar Gasto"}
              </Button>

              {sellers.length === 0 && (
                <p className="text-[10px] text-amber-500 font-medium text-center mt-1">
                  ⚠️ Cadastre vendedores na aba de Comissões para habilitar.
                </p>
              )}
            </form>
          </div>
        </Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Table representation */}
        <Card className="lg:col-span-2 p-1">
          <div className="p-4 border-b">
            <h3 className="font-semibold flex items-center gap-2">
              <Target className="w-4 h-4 text-primary" />
              Performance por Canal
            </h3>
            <p className="text-sm text-muted-foreground">Custo direto + custo 'Geral' rateado.</p>
          </div>
          {/* Desktop: Tabela */}
          <div className="hidden sm:block w-full overflow-x-auto">
            <Table>
              <TableHeader className="bg-muted/30">
                <TableRow>
                  <TableHead>Origem</TableHead>
                  <TableHead className="text-right">Custo Total</TableHead>
                  <TableHead className="text-center">Pagantes</TableHead>
                  <TableHead className="text-right">CAC</TableHead>
                  <TableHead className="text-right">Receita</TableHead>
                  <TableHead className="text-right text-primary">ROAS</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {channelStats.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={6} className="text-center h-24 text-muted-foreground">
                      Sem dados o suficiente no período.
                    </TableCell>
                  </TableRow>
                ) : channelStats.map((stat) => (
                  <TableRow key={stat.origem}>
                    <TableCell className="font-medium">{stat.origem}</TableCell>
                    <TableCell className="text-right text-muted-foreground">
                      {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(stat.custoTotal)}
                    </TableCell>
                    <TableCell className="text-center font-semibold">
                      {stat.clientesPagantes}
                    </TableCell>
                    <TableCell className="text-right text-info">
                      {stat.clientesPagantes === 0 ? 'N/A' : new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(stat.cac)}
                    </TableCell>
                    <TableCell className="text-right text-green-500">
                      {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(stat.receita)}
                    </TableCell>
                    <TableCell className={`text-right font-bold ${stat.custoTotal === 0 ? 'text-primary' : (stat.roas >= targetRoas ? 'text-green-500' : 'text-red-500')}`}>
                      {stat.custoTotal === 0 ? 'N/A' : `${stat.roas.toFixed(2)}x`}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>

          {/* Mobile: Cards */}
          <div className="block sm:hidden p-3 space-y-3">
            {channelStats.length === 0 ? (
              <p className="text-center text-sm text-muted-foreground py-6">Sem dados o suficiente no período.</p>
            ) : channelStats.map((stat) => (
              <div key={stat.origem} className="p-3 rounded-lg border text-sm space-y-2 bg-card">
                <div className="flex items-center justify-between gap-1.5">
                  <span className="font-semibold">{stat.origem}</span>
                  <span className={`text-xs font-bold px-2 py-0.5 rounded-full ${stat.custoTotal === 0 ? 'bg-primary/10 text-primary' : (stat.roas >= targetRoas ? 'bg-green-500/10 text-green-500' : 'bg-red-500/10 text-red-500')}`}>
                    {stat.custoTotal === 0 ? 'N/A' : `ROAS ${stat.roas.toFixed(2)}x`}
                  </span>
                </div>
                <div className="grid grid-cols-3 gap-2 pt-2 border-t text-center">
                  <div>
                    <span className="text-[10px] text-muted-foreground block">Custo Total</span>
                    <span className="font-medium text-xs">{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(stat.custoTotal)}</span>
                  </div>
                  <div>
                    <span className="text-[10px] text-muted-foreground block">Pagantes</span>
                    <span className="font-semibold text-xs">{stat.clientesPagantes}</span>
                  </div>
                  <div>
                    <span className="text-[10px] text-muted-foreground block">CAC</span>
                    <span className="font-medium text-xs text-info">{stat.clientesPagantes === 0 ? 'N/A' : new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(stat.cac)}</span>
                  </div>
                </div>
                <div className="flex justify-between items-center pt-1 text-xs">
                  <span className="text-muted-foreground">Receita:</span>
                  <span className="font-semibold text-green-500">{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(stat.receita)}</span>
                </div>
              </div>
            ))}
          </div>
        </Card>

        {/* Chart representation */}
        <Card className="p-5 flex flex-col">
          <h3 className="font-semibold mb-4">Eficiência de Conversão (CAC)</h3>
          <div className="flex-1 min-h-[300px] w-full mt-2">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart
                data={channelStats.filter(s => s.clientesPagantes > 0)}
                margin={{ top: 20, right: 0, left: 10, bottom: 0 }}
              >
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#88888833" />
                <XAxis
                  dataKey="origem"
                  axisLine={false}
                  tickLine={false}
                  tick={{ fontSize: 12, fill: 'currentColor', opacity: 0.7 }}
                />
                <YAxis
                  axisLine={false}
                  tickLine={false}
                  tickFormatter={(value) => `R$${value}`}
                  tick={{ fontSize: 12, fill: 'currentColor', opacity: 0.7 }}
                  width={75}
                />
                <Tooltip
                  cursor={{ fill: '#88888811' }}
                  contentStyle={{ borderRadius: '8px', border: '1px solid #88888833', backgroundColor: 'var(--background)' }}
                  formatter={(value: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value)}
                />
                <Bar dataKey="cac" name="CAC Médio" fill="hsl(var(--primary))" radius={[4, 4, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mt-6">
        {/* Table representation */}
        <Card className="lg:col-span-2 p-1">
          <div className="p-4 border-b">
            <h3 className="font-semibold flex items-center gap-2">
              <DollarSign className="w-4 h-4 text-orange-500" />
              Despesas de CAC Mapeadas no Período
            </h3>
            <p className="text-sm text-muted-foreground">Transações de saída que estão compondo o investimento total exibido acima.</p>
          </div>
          {/* Desktop: Tabela */}
          <div className="hidden sm:block w-full overflow-x-auto">
            <Table>
              <TableHeader className="bg-muted/10">
                <TableRow>
                  <TableHead>Data</TableHead>
                  <TableHead>Nome da Transação</TableHead>
                  <TableHead>Área</TableHead>
                  <TableHead>Canal Marcado</TableHead>
                  <TableHead className="text-right">Valor</TableHead>
                  <TableHead className="text-right w-[80px]">Ações</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {cacTransactions.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={6} className="text-center h-16 text-muted-foreground">
                      Nenhuma despesa marcada como CAC no período.
                    </TableCell>
                  </TableRow>
                ) : cacTransactions.map((tx) => (
                  <TableRow key={tx.id}>
                    <TableCell>{format(parseISO(tx.transaction_date), "dd/MM/yyyy")}</TableCell>
                    <TableCell className="font-medium">{tx.name}</TableCell>
                    <TableCell>
                      <span className={`px-2 py-1 rounded-full text-[10px] font-medium uppercase tracking-wider ${tx.cac_bucket === 'marketing' ? 'bg-orange-500/10 text-orange-600' : 'bg-blue-500/10 text-blue-600'}`}>
                        {tx.cac_bucket}
                      </span>
                    </TableCell>
                    <TableCell>{tx.cac_origin || 'Não classificado'}</TableCell>
                    <TableCell className="text-right text-red-500">
                      -{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(tx.amount)}
                    </TableCell>
                    <TableCell className="text-right">
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => handleDeleteCacTransaction(tx.id)}
                        className="h-7 w-7 text-muted-foreground hover:text-red-500 transition-colors"
                        title="Excluir despesa"
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>

          {/* Mobile: Cards */}
          <div className="block sm:hidden p-3 space-y-3">
            {cacTransactions.length === 0 ? (
              <p className="text-center text-sm text-muted-foreground py-6">Nenhuma despesa marcada como CAC no período.</p>
            ) : cacTransactions.map((tx) => (
              <div key={tx.id} className="p-3 rounded-lg border text-sm space-y-2 bg-card">
                <div className="flex items-center justify-between gap-1.5">
                  <span className="font-semibold truncate max-w-[55%]">{tx.name}</span>
                  <div className="flex items-center gap-1.5 shrink-0">
                    <span className={`px-2 py-0.5 rounded-full text-[10px] font-medium uppercase tracking-wider ${tx.cac_bucket === 'marketing' ? 'bg-orange-500/10 text-orange-600' : 'bg-blue-500/10 text-blue-600'}`}>
                      {tx.cac_bucket}
                    </span>
                    <Button
                      variant="ghost"
                      size="icon"
                      onClick={() => handleDeleteCacTransaction(tx.id)}
                      className="h-6 w-6 text-muted-foreground hover:text-red-500"
                    >
                      <Trash2 className="h-3.5 w-3.5" />
                    </Button>
                  </div>
                </div>
                <div className="grid grid-cols-3 gap-2 pt-2 border-t text-center">
                  <div>
                    <span className="text-[10px] text-muted-foreground block">Data</span>
                    <span className="font-medium text-xs">{format(parseISO(tx.transaction_date), "dd/MM/yy")}</span>
                  </div>
                  <div>
                    <span className="text-[10px] text-muted-foreground block">Canal</span>
                    <span className="font-medium text-xs">{tx.cac_origin || 'N/C'}</span>
                  </div>
                  <div>
                    <span className="text-[10px] text-red-400 block">Valor</span>
                    <span className="font-semibold text-xs text-red-500">-{new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(tx.amount)}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </Card>

        {/* Ranking de Vendedores */}
        <Card className="lg:col-span-1 p-1 flex flex-col justify-between">
          <div>
            <div className="p-4 border-b">
              <h3 className="font-semibold flex items-center gap-2 text-foreground">
                <Users className="w-4 h-4 text-blue-500" />
                Eficiência Comercial
              </h3>
              <p className="text-xs text-muted-foreground mt-0.5">Ranking de vendas por faturamento no período.</p>
            </div>
            <div className="flex-1 overflow-y-auto max-h-[350px]">
              {sellerRanking.length === 0 ? (
                <div className="text-center py-12 text-xs text-muted-foreground">
                  Nenhuma venda comercial registrada no período.
                </div>
              ) : (
                <div className="divide-y divide-border">
                  {sellerRanking.map((seller, index) => (
                    <div key={seller.id} className="p-3 flex items-center justify-between text-xs hover:bg-muted/20 transition-all duration-200">
                      <div className="flex items-center gap-3">
                        <span className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold ${index === 0 ? 'bg-amber-500/20 text-amber-500' :
                          index === 1 ? 'bg-slate-400/20 text-slate-400' :
                            index === 2 ? 'bg-amber-700/20 text-amber-700' : 'bg-muted text-muted-foreground'
                          }`}>
                          {index + 1}
                        </span>
                        <div>
                          <span className="font-medium text-foreground block">{seller.name}</span>
                          <span className="text-[10px] text-muted-foreground">{seller.vendasCount} {seller.vendasCount === 1 ? 'venda' : 'vendas'}</span>
                        </div>
                      </div>
                      <div className="text-right">
                        <span className="font-semibold text-foreground block">
                          {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(seller.faturamentoTotal)}
                        </span>
                        <span className="text-[10px] text-blue-500">
                          Comissão: {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(seller.comissaoTotal)}
                        </span>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </Card>
      </div>

      <RoasEntryModal
        open={isRoasModalOpen}
        onOpenChange={setIsRoasModalOpen}
        onSuccess={fetchCacData}
      />
    </div>
  );
}

import { useState, useEffect } from "react";
import { format } from "date-fns";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { Loader2, TrendingUp } from "lucide-react";
import { CAC_ORIGIN_OPTIONS } from "@/constants/origins";
import { createExpenseTransaction } from "@/lib/financialTransactions";

interface RoasEntryModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSuccess: () => void;
}

export function RoasEntryModal({ open, onOpenChange, onSuccess }: RoasEntryModalProps) {
  const { toast } = useToast();
  const { user } = useAuth();
  const [isLoading, setIsLoading] = useState(false);

  const [entryDate, setEntryDate] = useState(format(new Date(), "yyyy-MM-dd"));
  const [origin, setOrigin] = useState<string>("Google Ads");
  const [amount, setAmount] = useState<string>("");
  const [description, setDescription] = useState("");
  const [accounts, setAccounts] = useState<any[]>([]);
  const [accountId, setAccountId] = useState<string>("");

  useEffect(() => {
    if (user?.companyId) {
      fetchAccounts();
    }
  }, [user?.companyId]);

  const fetchAccounts = async () => {
    try {
      const { data, error } = await supabase
        .from('accounts')
        .select('id, name, is_main')
        .eq('company_id', user.companyId)
        .eq('is_active', true)
        .order('name');
      
      if (error) throw error;
      setAccounts(data || []);
      
      // Define a conta principal como padrão inicial, ou a primeira da lista
      const mainAcc = data?.find(a => a.is_main);
      if (mainAcc) {
        setAccountId(mainAcc.id.toString());
      } else if (data && data.length > 0) {
        setAccountId(data[0].id.toString());
      }
    } catch (e) {
      console.error("Error fetching accounts", e);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user?.companyId) {
      toast({ title: "Empresa não vinculada", variant: "destructive" });
      return;
    }

    const valorInvestido = parseFloat(amount.replace(",", "."));
    if (isNaN(valorInvestido) || valorInvestido <= 0) {
      toast({ title: "Digite um valor válido maior que 0", variant: "destructive" });
      return;
    }

    setIsLoading(true);

    try {
      if (!accountId) {
        toast({ title: "Selecione uma conta financeira", variant: "destructive" });
        setIsLoading(false);
        return;
      }

      const result = await createExpenseTransaction({
        name: description ? `Ads - ${description}` : `Investimento ${origin}`,
        amount: valorInvestido,
        transactionDate: entryDate,
        companyId: user.companyId,
        accountId: parseInt(accountId),
        isPaid: true,
        description: `CAC - ${origin}`,
        originType: "roas",
      });

      if (!result) throw new Error("Falha ao criar transação");

      // Atualizar campos CAC na transação criada
      await supabase
        .from("transactions")
        .update({
          include_in_cac: true,
          cac_bucket: "marketing",
          cac_origin: origin,
        })
        .eq("id", result.id);

      toast({
        title: "Investimento Registrado!",
        description: `R$ ${valorInvestido.toFixed(2)} cadastrados para ${origin}. O cálculo do CAC/ROAS foi atualizado.`,
      });

      setAmount("");
      setDescription("");
      onSuccess();
      onOpenChange(false);
    } catch (error: any) {
      console.error(error);
      toast({
        title: "Erro ao registrar gasto",
        description: error.message,
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[425px]">
        <DialogHeader>
          <div className="flex items-center gap-3">
            <div className="p-2 bg-primary/20 text-primary rounded-lg">
              <TrendingUp className="h-5 w-5" />
            </div>
            <div>
              <DialogTitle>Registrar Investimento (Ads)</DialogTitle>
              <DialogDescription>
                Lancamento rápido de gastos com tráfego para os cálculos de ROAS e CAC.
              </DialogDescription>
            </div>
          </div>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-4 pt-4">
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="entryDate">Data</Label>
              <Input
                id="entryDate"
                type="date"
                required
                value={entryDate}
                onChange={(e) => setEntryDate(e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="origin">Canal/Origem</Label>
              <Select value={origin} onValueChange={setOrigin}>
                <SelectTrigger id="origin">
                  <SelectValue placeholder="Selecione" />
                </SelectTrigger>
                <SelectContent>
                  {CAC_ORIGIN_OPTIONS.filter((o) => o !== "Geral").map((org) => (
                    <SelectItem key={org} value={org}>
                      {org}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="amount">Valor Investido (R$)</Label>
              <Input
                id="amount"
                type="number"
                step="0.01"
                required
                placeholder="Ex: 150.00"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="accountId">Conta Financeira</Label>
              {accounts.length > 0 ? (
                <Select value={accountId} onValueChange={setAccountId}>
                  <SelectTrigger id="accountId">
                    <SelectValue placeholder="Selecione" />
                  </SelectTrigger>
                  <SelectContent>
                    {accounts.map((a) => (
                      <SelectItem key={a.id} value={a.id.toString()}>
                        {a.name} {a.is_main && "(Principal)"}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              ) : (
                <Input 
                  placeholder="Sem contas..." 
                  disabled 
                />
              )}
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="description">Descrição Opcional</Label>
            <Input
              id="description"
              placeholder="Ex: Campanha Dia dos Pais, Impulsionamento..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
            />
          </div>

          <div className="flex justify-end gap-3 pt-4">
            <Button
              type="button"
              variant="outline"
              disabled={isLoading}
              onClick={() => onOpenChange(false)}
            >
              Cancelar
            </Button>
            <Button type="submit" disabled={isLoading}>
              {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Registrar Lançamento
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

// @ts-nocheck
import { useState, useEffect } from "react";
import { Plus, ArrowUpRight, ArrowDownRight, RefreshCw, Wallet, TrendingUp, TrendingDown, Eye, EyeOff, Landmark, PiggyBank, CreditCard, Tag, ShoppingCart, Receipt, FileText, DollarSign, ChevronLeft, ChevronRight } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger, DropdownMenuSeparator } from "@/components/ui/dropdown-menu";
import { Skeleton } from "@/components/ui/skeleton";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { format, subDays, startOfMonth, endOfMonth, addDays, subMonths, addMonths } from "date-fns";
import { ptBR } from "date-fns/locale";
import { AreaChart, Area, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from "recharts";
import { cn } from "@/lib/utils";
import { AddTransactionModal } from "@/shared/components/financeiro/AddTransactionModal";
import { AddTransferModal } from "@/shared/components/financeiro/AddTransferModal";
import { AddAccountModal } from "@/shared/components/financeiro/AddAccountModal";
import { ManageCategoriesModal } from "@/shared/components/financeiro/ManageCategoriesModal";
import { AccountDetailsModal } from "@/pages/Financeiro/components/AccountDetailsModal";
import { toast } from "sonner";

interface Account {
    id: number;
    name: string;
    account_type: string | null;
    current_balance: number | null;
    is_main: boolean | null;
}

interface Transaction {
    id: number;
    type: string;
    amount: number;
    transaction_date: string;
    sale_id: number | null;
    origin_type: string | null;
    name: string;
    is_paid: boolean | null;
}

interface Sale {
    id: number;
    total: number;
    sale_date: string;
    status: string | null;
}

interface Transfer {
    id: number;
    amount: number;
    transfer_date: string;
    from_account_id: number;
    to_account_id: number;
}

interface CardMachine {
    id: number;
    name: string;
    debit_rate: number | null;
}

interface CardMachineRate {
    id: number;
    machine_id: number;
    brand: string | null;
    installments: number | null;
    rate: number;
}

export function VisaoGeral() {
    const { user } = useAuth();
    const [currentMonth, setCurrentMonth] = useState(new Date());
    const [accounts, setAccounts] = useState<Account[]>([]);
    const [transactions, setTransactions] = useState<Transaction[]>([]);
    const [transfers, setTransfers] = useState<Transfer[]>([]);
    const [monthSales, setMonthSales] = useState<Sale[]>([]);
    const [machines, setMachines] = useState<CardMachine[]>([]);
    const [machineRates, setMachineRates] = useState<CardMachineRate[]>([]);
    const [loading, setLoading] = useState(true);
    const [showValues, setShowValues] = useState(true);
    const [transactionModalOpen, setTransactionModalOpen] = useState(false);
    const [transactionType, setTransactionType] = useState<'entrada' | 'saida'>('entrada');
    const [transferModalOpen, setTransferModalOpen] = useState(false);
    const [accountModalOpen, setAccountModalOpen] = useState(false);
    const [categoriesModalOpen, setCategoriesModalOpen] = useState(false);
    const [selectedAccount, setSelectedAccount] = useState<Account | null>(null);
    const [detailsModalOpen, setDetailsModalOpen] = useState(false);

    const fetchData = async () => {
        if (!user?.id) return;

        try {
            const { data: profile } = await supabase
                .from("profiles")
                .select("company_id")
                .eq("user_id", user.id)
                .single();

            if (!profile?.company_id) {
                setLoading(false);
                return;
            }

            // Fetch accounts
            const { data: accountsData } = await supabase
                .from("accounts")
                .select("*")
                .eq("company_id", profile.company_id)
                .eq("is_active", true)
                .order("is_main", { ascending: false });

            // Fetch bounds
            const monthStartObj = startOfMonth(currentMonth);
            const queryStart = format(monthStartObj, "yyyy-MM-dd");
            const monthEndObj = endOfMonth(currentMonth);
            const monthEnd = format(monthEndObj, "yyyy-MM-dd");

            const isCurrentMonth =
                currentMonth.getMonth() === new Date().getMonth() &&
                currentMonth.getFullYear() === new Date().getFullYear();

            const futureEndObj = isCurrentMonth ? addDays(new Date(), 7) : monthEndObj;
            const queryLimitStr = format(futureEndObj > monthEndObj ? futureEndObj : monthEndObj, "yyyy-MM-dd");

            const { data: transactionsData } = await supabase
                .from("transactions")
                .select("id, type, amount, transaction_date, sale_id, origin_type, name, is_paid, sale_payment_id")
                .eq("company_id", profile.company_id)
                .gte("transaction_date", queryStart)
                .lte("transaction_date", queryLimitStr)
                .order("transaction_date", { ascending: false });

            // Fetch sales for the month with payments
            const { data: salesData } = await supabase
                .from("sales")
                .select(`
          id, 
          total, 
          sale_date, 
          status,
          sale_payments (
            id,
            amount,
            method,
            installments,
            machine_id,
            brand
          )
        `)
                .eq("company_id", profile.company_id)
                .gte("sale_date", queryStart)
                .lte("sale_date", monthEnd);

            // Fetch transfers 
            const { data: transfersData } = await supabase
                .from("transfers")
                .select("*")
                .eq("company_id", profile.company_id)
                .gte("transfer_date", queryStart)
                .lte("transfer_date", queryLimitStr)
                .order("transfer_date", { ascending: false });

            // Fetch card machines
            const { data: machinesData } = await supabase
                .from("card_machines")
                .select("id, name, debit_rate")
                .eq("company_id", profile.company_id);

            // Fetch card machine rates
            const { data: ratesData } = await supabase
                .from("card_machine_rates")
                .select("id, machine_id, brand, installments, rate")
                .eq("company_id", profile.company_id);

            setAccounts(accountsData || []);
            setTransactions(transactionsData || []);
            setTransfers(transfersData || []);
            setMonthSales(salesData || []);
            setMachines(machinesData || []);
            setMachineRates(ratesData || []);
        } catch (error) {
            console.error("Error fetching financial data:", error);
            toast.error("Erro ao carregar dados financeiros");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, [user?.id, currentMonth]);

    const todayStr = format(new Date(), 'yyyy-MM-dd');
    const monthStartStr = format(startOfMonth(currentMonth), "yyyy-MM-dd");
    const monthEndStr = format(endOfMonth(currentMonth), "yyyy-MM-dd");
    const futureEndStr = format(addDays(new Date(), 7), "yyyy-MM-dd");

    const isCurrentMonth = currentMonth.getMonth() === new Date().getMonth() && currentMonth.getFullYear() === new Date().getFullYear();

    const totalBalance = accounts.reduce((sum, acc) => sum + (acc.current_balance || 0), 0);

    const monthTransactions = transactions.filter(t => t.transaction_date >= monthStartStr && t.transaction_date <= monthEndStr);
    const futureTransactions = transactions.filter(t => t.transaction_date > todayStr && t.transaction_date <= futureEndStr);

    // === ENTRADAS ===
    const entradasTransactions = monthTransactions.filter(t => t.type === 'Entrada' && t.is_paid);
    const totalEntradas = entradasTransactions.reduce((sum, t) => sum + t.amount, 0);

    // Vendas do mês (from sales table, para garantir contagem correta)
    const totalVendasMes = monthSales.reduce((sum, s) => sum + s.total, 0);
    const qtdVendasMes = monthSales.length;

    // Entradas que vieram de vendas (transações com sale_id)
    const entradasDeVendas = entradasTransactions
        .filter(t => t.sale_id !== null)
        .reduce((sum, t) => sum + t.amount, 0);

    // Outras entradas manuais (transações sem sale_id)
    const outrasEntradas = entradasTransactions
        .filter(t => t.sale_id === null)
        .reduce((sum, t) => sum + t.amount, 0);

    // === SAÍDAS ===
    const saidasTransactions = monthTransactions.filter(t => t.type === 'Saida' && t.is_paid);
    const totalSaidas = saidasTransactions.reduce((sum, t) => sum + t.amount, 0);

    // Despesas fixas / recorrentes (transações com "Despesa fixa" ou "recorrente" no nome, ou origin_type de purchase)
    const saidasCompras = saidasTransactions
        .filter(t => t.origin_type === 'purchase_installment')
        .reduce((sum, t) => sum + t.amount, 0);

    // Outras saídas (manuais, ROAS, etc)
    const outrasSaidas = saidasTransactions
        .filter(t => t.origin_type !== 'purchase_installment')
        .reduce((sum, t) => sum + t.amount, 0);

    const futureEntradas = futureTransactions
        .filter(t => t.type === 'Entrada')
        .reduce((sum, t) => sum + t.amount, 0);

    const futureSaidas = futureTransactions
        .filter(t => t.type === 'Saida')
        .reduce((sum, t) => sum + t.amount, 0);

    // === NOVOS INDICADORES DE MAQUININHA E TRANSFERÊNCIAS ===

    // 1. Total de transferências no mês
    const monthTransfers = transfers.filter(t => t.transfer_date >= monthStartStr && t.transfer_date <= monthEndStr);
    const totalTransferenciasMes = monthTransfers.reduce((sum, t) => sum + t.amount, 0);

    // Total de taxas de TED/DOC no mês
    const totalTaxasTedDocMes = monthTransactions
        .filter(t => t.type === 'Saida' && t.is_paid && t.name.includes("Taxa de TED/DOC"))
        .reduce((sum, t) => sum + t.amount, 0);

    // 2. Extrair todos os pagamentos em maquininha de vendas fechadas no mês corrente
    const closedMonthSales = monthSales.filter(s => s.status === 'Fechada');
    const maquininhaPayments = closedMonthSales.flatMap(sale => {
        const payments = (sale as any).sale_payments || [];
        return payments.filter((p: any) =>
            (p.method === "Crédito" || p.method === "Débito") && p.machine_id !== null
        );
    });

    // Valor Bruto de Maquininha
    const totalVendasMaquininha = maquininhaPayments.reduce((sum, p) => sum + p.amount, 0);

    // Calcular Taxas e Líquido Real/Estimado
    let totalTaxaMaquininha = 0;
    let totalLiquidoMaquininha = 0;

    maquininhaPayments.forEach((p: any) => {
        // Tenta encontrar a transação real pelo sale_payment_id ou sale_id (se for pagamento único)
        const tx = transactions.find(t =>
            t.type === 'Entrada' &&
            t.is_paid &&
            (t.sale_payment_id === p.id || (t.sale_id === p.sale_id && t.sale_payment_id === null))
        );

        if (tx) {
            const liquido = tx.amount;
            const taxa = Math.max(0, p.amount - liquido);
            totalTaxaMaquininha += taxa;
            totalLiquidoMaquininha += liquido;
        } else {
            // Fallback: cálculo baseado nas configurações de taxas
            let rate = 0;
            if (p.method === "Débito") {
                const machine = machines.find(m => m.id === p.machine_id);
                rate = machine?.debit_rate || 0;
            } else {
                // Crédito
                const rateRecord = machineRates.find(r =>
                    r.machine_id === p.machine_id &&
                    r.installments === (p.installments || 1) &&
                    (!p.brand || !r.brand || r.brand.toLowerCase() === p.brand.toLowerCase())
                );
                rate = rateRecord?.rate || 0;
            }
            const taxaEstimada = p.amount * (rate / 100);
            const liquidoEstimado = p.amount - taxaEstimada;

            totalTaxaMaquininha += taxaEstimada;
            totalLiquidoMaquininha += liquidoEstimado;
        }
    });

    // 5. Maquininha mais usada
    const usageMap: { [key: number]: number } = {};
    maquininhaPayments.forEach((p: any) => {
        if (p.machine_id) {
            usageMap[p.machine_id] = (usageMap[p.machine_id] || 0) + 1;
        }
    });

    let mostUsedMachineId: number | null = null;
    let mostUsedMachineCount = 0;
    Object.entries(usageMap).forEach(([idStr, count]) => {
        if (count > mostUsedMachineCount) {
            mostUsedMachineCount = count;
            mostUsedMachineId = parseInt(idStr);
        }
    });

    const mostUsedMachineName = mostUsedMachineId
        ? (machines.find(m => m.id === mostUsedMachineId)?.name || `Maquininha #${mostUsedMachineId}`)
        : "Nenhuma";

    // Generate chart data for last 7 days working backwards from today's balance
    let currentBal = totalBalance;
    const reversedChartData = [];

    for (let i = 0; i < 7; i++) {
        const dateObj = subDays(new Date(), i);
        const dateStr = format(dateObj, 'yyyy-MM-dd');

        reversedChartData.push({
            date: format(dateObj, 'dd/MM'),
            saldo: currentBal,
        });

        const dayTransactions = transactions.filter(t => t.transaction_date === dateStr && t.is_paid);
        const dayEntradas = dayTransactions.filter(t => t.type === 'Entrada').reduce((s, t) => s + t.amount, 0);
        const daySaidas = dayTransactions.filter(t => t.type === 'Saida').reduce((s, t) => s + t.amount, 0);
        const netFlow = dayEntradas - daySaidas;

        // Balance before this day's transactions happened:
        currentBal -= netFlow;
    }

    const chartData = reversedChartData.reverse();

    // Generate transfer chart data for the last 7 days
    const transferChartData = [];
    for (let i = 6; i >= 0; i--) {
        const dateObj = subDays(new Date(), i);
        const dateStr = format(dateObj, 'yyyy-MM-dd');

        const dayTransfers = transfers.filter(t => t.transfer_date === dateStr);
        const dayTotalTransferred = dayTransfers.reduce((sum, t) => sum + t.amount, 0);

        transferChartData.push({
            date: format(dateObj, 'dd/MM'),
            volume: dayTotalTransferred,
        });
    }

    const getAccountIcon = (type: string | null) => {
        switch (type) {
            case 'Conta Corrente': return <Landmark className="h-5 w-5" />;
            case 'Poupança': return <PiggyBank className="h-5 w-5" />;
            case 'Carteira': return <Wallet className="h-5 w-5" />;
            case 'Investimento': return <TrendingUp className="h-5 w-5" />;
            default: return <CreditCard className="h-5 w-5" />;
        }
    };

    const formatCurrency = (value: number) => {
        if (!showValues) return "••••••";
        return `R$ ${value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;
    };

    const openTransactionModal = (type: 'entrada' | 'saida') => {
        setTransactionType(type);
        setTransactionModalOpen(true);
    };

    if (loading) {
        return (
            <div className="space-y-6">
                <Skeleton className="h-10 w-48" />
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    {[1, 2, 3].map((i) => <Skeleton key={i} className="h-32" />)}
                </div>
                <Skeleton className="h-96" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Header com controles do mês e ações */}
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div className="flex items-center gap-2">
                    <Button variant="outline" size="icon" className="h-7 w-7 transition-colors hover:bg-muted" onClick={() => setCurrentMonth(prev => subMonths(prev, 1))}>
                        <ChevronLeft className="h-4 w-4" />
                    </Button>
                    <span className="text-sm font-semibold capitalize text-foreground min-w-[110px] text-center">
                        {format(currentMonth, 'MMMM yyyy', { locale: ptBR })}
                    </span>
                    <Button variant="outline" size="icon" className="h-7 w-7 transition-colors hover:bg-muted" onClick={() => setCurrentMonth(prev => addMonths(prev, 1))}>
                        <ChevronRight className="h-4 w-4" />
                    </Button>
                    {!isCurrentMonth && (
                        <Button variant="secondary" size="sm" className="h-7 text-xs px-3 ml-1" onClick={() => setCurrentMonth(new Date())}>
                            Voltar para o mês atual
                        </Button>
                    )}
                </div>
                <div className="flex gap-2 w-full sm:w-auto">
                    <Button variant="ghost" size="icon" className="shrink-0" onClick={() => setShowValues(!showValues)}>
                        {showValues ? <Eye className="h-5 w-5" /> : <EyeOff className="h-5 w-5" />}
                    </Button>
                    <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                            <Button className="flex-1 sm:flex-none">
                                <Plus className="h-4 w-4 mr-2" /> Adicionar
                            </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end">
                            <DropdownMenuItem onClick={() => openTransactionModal('entrada')}>
                                <ArrowUpRight className="h-4 w-4 mr-2 text-green-500" /> Nova Entrada
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => openTransactionModal('saida')}>
                                <ArrowDownRight className="h-4 w-4 mr-2 text-red-500" /> Nova Saída
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => setTransferModalOpen(true)}>
                                <RefreshCw className="h-4 w-4 mr-2 text-blue-500" /> Transferência
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => setAccountModalOpen(true)}>
                                <Wallet className="h-4 w-4 mr-2" /> Nova Conta
                            </DropdownMenuItem>
                            <DropdownMenuSeparator />
                            <DropdownMenuItem onClick={() => setCategoriesModalOpen(true)}>
                                <Tag className="h-4 w-4 mr-2" /> Gerenciar Categorias
                            </DropdownMenuItem>
                        </DropdownMenuContent>
                    </DropdownMenu>
                </div>
            </div>

            {/* Visão Geral (Overview) - Cards Grid */}
            <div className="grid grid-cols-1 md:grid-cols-12 gap-4 md:gap-6">

                {/* Saldo Geral - Takes full width on mobile, 4 columns on desktop */}
                <Card className="md:col-span-12 lg:col-span-4 bg-gradient-to-br from-primary/20 to-primary/5 border-primary/30 relative overflow-hidden flex flex-col justify-between">
                    <div className="absolute right-4 top-4 opacity-10">
                        <Landmark size={100} />
                    </div>
                    <CardContent className="p-6 relative z-10 flex flex-col justify-between h-full min-h-[160px]">
                        <div>
                            <p className="text-sm font-medium text-muted-foreground/90 uppercase tracking-wider">Saldo Geral Atual</p>
                            <p className="text-4xl font-bold mt-2">{formatCurrency(totalBalance)}</p>
                        </div>
                        <div className="mt-4">
                            <div className="inline-flex items-center bg-background/50 backdrop-blur-sm px-3 py-1.5 rounded-full text-xs font-medium text-foreground border border-border/50 shadow-sm">
                                <Wallet className="h-3 w-3 mr-2 text-primary" />
                                {accounts.length} {accounts.length === 1 ? 'conta conectada' : 'contas conectadas'}
                            </div>
                        </div>
                    </CardContent>
                </Card>

                {/* Entradas Card */}
                <Card className="md:col-span-6 lg:col-span-4 bg-card/50 border-border/50 relative overflow-hidden flex flex-col">
                    <div className="p-6 pb-3 flex-1">
                        <div className="flex items-center justify-between mb-3">
                            <div className="flex items-center gap-2 text-green-500 bg-green-500/10 px-3 py-1 rounded-full">
                                <ArrowUpRight className="h-4 w-4" />
                                <span className="text-xs font-semibold uppercase tracking-wider">Entradas</span>
                            </div>
                        </div>

                        <div className="space-y-1 mb-4">
                            <p className="text-sm text-muted-foreground">Total no Mês</p>
                            <p className="text-3xl font-bold text-foreground">{formatCurrency(totalEntradas)}</p>
                        </div>

                        {/* Breakdown */}
                        <div className="space-y-2">
                            <div className="flex items-center justify-between text-sm">
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    <ShoppingCart className="h-3.5 w-3.5 text-green-500/70" />
                                    <span>Vendas ({qtdVendasMes})</span>
                                </div>
                                <span className="font-medium text-foreground">{formatCurrency(entradasDeVendas)}</span>
                            </div>
                            <div className="flex items-center justify-between text-sm">
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    <DollarSign className="h-3.5 w-3.5 text-green-500/70" />
                                    <span>Outras entradas</span>
                                </div>
                                <span className="font-medium text-foreground">{formatCurrency(outrasEntradas)}</span>
                            </div>
                        </div>
                    </div>
                    <div className="bg-green-500/5 px-6 py-3 border-t border-green-500/10 flex justify-between items-center">
                        <span className="text-xs text-muted-foreground">Previsão (Próx. 7 dias)</span>
                        <span className="text-sm font-semibold text-green-500">+{formatCurrency(futureEntradas)}</span>
                    </div>
                </Card>

                {/* Saídas Card */}
                <Card className="md:col-span-6 lg:col-span-4 bg-card/50 border-border/50 relative overflow-hidden flex flex-col">
                    <div className="p-6 pb-3 flex-1">
                        <div className="flex items-center justify-between mb-3">
                            <div className="flex items-center gap-2 text-red-500 bg-red-500/10 px-3 py-1 rounded-full">
                                <ArrowDownRight className="h-4 w-4" />
                                <span className="text-xs font-semibold uppercase tracking-wider">Saídas</span>
                            </div>
                        </div>

                        <div className="space-y-1 mb-4">
                            <p className="text-sm text-muted-foreground">Total no Mês</p>
                            <p className="text-3xl font-bold text-foreground">{formatCurrency(totalSaidas)}</p>
                        </div>

                        {/* Breakdown */}
                        <div className="space-y-2">
                            <div className="flex items-center justify-between text-sm">
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    <Receipt className="h-3.5 w-3.5 text-red-500/70" />
                                    <span>Compras / Fornecedores</span>
                                </div>
                                <span className="font-medium text-foreground">{formatCurrency(saidasCompras)}</span>
                            </div>
                            <div className="flex items-center justify-between text-sm">
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    <FileText className="h-3.5 w-3.5 text-red-500/70" />
                                    <span>Despesas / Outros</span>
                                </div>
                                <span className="font-medium text-foreground">{formatCurrency(outrasSaidas)}</span>
                            </div>
                        </div>
                    </div>
                    <div className="bg-red-500/5 px-6 py-3 border-t border-red-500/10 flex justify-between items-center">
                        <span className="text-xs text-muted-foreground">Previsão (Próx. 7 dias)</span>
                        <span className="text-sm font-semibold text-red-500">-{formatCurrency(futureSaidas)}</span>
                    </div>
                </Card>

            </div>

            {/* Novos Cards de Detalhes de Maquininha e Transferências */}
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4 md:gap-6 mt-6 animate-in fade-in duration-500">

                {/* Total de Transferências */}
                <Card className="bg-card/50 border-border/50 relative overflow-hidden flex flex-col justify-between">
                    <CardContent className="p-6 relative z-10">
                        <div className="flex items-center justify-between mb-3">
                            <span className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Transferências no Mês</span>
                            <div className="p-1.5 rounded-lg bg-blue-500/10 text-blue-500">
                                <RefreshCw className="h-4 w-4" />
                            </div>
                        </div>
                        <p className="text-2xl font-bold tracking-tight mt-1">{formatCurrency(totalTransferenciasMes)}</p>
                        <p className="text-[10px] text-muted-foreground mt-2">Volume movimentado entre contas</p>
                    </CardContent>
                </Card>

                {/* Total de Taxas TED/DOC */}
                <Card className="bg-yellow-500/5 border-yellow-500/30 relative overflow-hidden flex flex-col justify-between">
                    <CardContent className="p-6 relative z-10">
                        <div className="flex items-center justify-between mb-3">
                            <span className="text-xs font-semibold text-yellow-600 dark:text-yellow-500 uppercase tracking-wider">Taxas de Transferência</span>
                            <div className="p-1.5 rounded-lg bg-yellow-500/20 text-yellow-600 dark:text-yellow-500">
                                <Receipt className="h-4 w-4" />
                            </div>
                        </div>
                        <p className="text-2xl font-bold tracking-tight mt-1 text-yellow-600 dark:text-yellow-500">{formatCurrency(totalTaxasTedDocMes)}</p>
                        <p className="text-[10px] text-yellow-600/70 dark:text-yellow-500/70 mt-2">Gasto com taxas de TED/DOC</p>
                    </CardContent>
                </Card>

                {/* Total de Vendas em Maquininha */}
                <Card className="bg-card/50 border-border/50 relative overflow-hidden flex flex-col justify-between">
                    <CardContent className="p-6 relative z-10">
                        <div className="flex items-center justify-between mb-3">
                            <span className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Vendas em Maquininha</span>
                            <div className="p-1.5 rounded-lg bg-primary/10 text-primary">
                                <CreditCard className="h-4 w-4" />
                            </div>
                        </div>
                        <p className="text-2xl font-bold tracking-tight mt-1">{formatCurrency(totalVendasMaquininha)}</p>
                        <p className="text-[10px] text-muted-foreground mt-2">Valor bruto total no mês</p>
                    </CardContent>
                </Card>

                {/* Valor de Taxa Consumido */}
                <Card className="bg-card/50 border-border/50 relative overflow-hidden flex flex-col justify-between">
                    <CardContent className="p-6 relative z-10">
                        <div className="flex items-center justify-between mb-3">
                            <span className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Taxas de Maquininha</span>
                            <div className="p-1.5 rounded-lg bg-red-500/10 text-red-500">
                                <TrendingDown className="h-4 w-4" />
                            </div>
                        </div>
                        <p className="text-2xl font-bold tracking-tight mt-1">{formatCurrency(totalTaxaMaquininha)}</p>
                        <p className="text-[10px] text-muted-foreground mt-2">Custos de intermediação no mês</p>
                    </CardContent>
                </Card>

                {/* Valor Líquido Recebido */}
                <Card className="bg-card/50 border-border/50 relative overflow-hidden flex flex-col justify-between">
                    <CardContent className="p-6 relative z-10">
                        <div className="flex items-center justify-between mb-3">
                            <span className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Valor Líquido Recebido</span>
                            <div className="p-1.5 rounded-lg bg-green-500/10 text-green-500">
                                <PiggyBank className="h-4 w-4" />
                            </div>
                        </div>
                        <p className="text-2xl font-bold tracking-tight mt-1">{formatCurrency(totalLiquidoMaquininha)}</p>
                        <p className="text-[10px] text-muted-foreground mt-2">Valor líquido a receber em conta</p>
                    </CardContent>
                </Card>

                {/* Maquininha Mais Usada */}
                <Card className="bg-card/50 border-border/50 relative overflow-hidden flex flex-col justify-between">
                    <CardContent className="p-6 relative z-10">
                        <div className="flex items-center justify-between mb-3">
                            <span className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Maquininha Mais Usada</span>
                            <div className="p-1.5 rounded-lg bg-purple-500/10 text-purple-500">
                                <Tag className="h-4 w-4" />
                            </div>
                        </div>
                        <p className="text-lg font-bold tracking-tight mt-2 truncate" title={mostUsedMachineName}>
                            {mostUsedMachineName}
                        </p>
                        <p className="text-[10px] text-muted-foreground mt-2">
                            {mostUsedMachineCount} {mostUsedMachineCount === 1 ? 'venda registrada' : 'vendas registradas'}
                        </p>
                    </CardContent>
                </Card>

            </div>

            {/* Divisor do Dashboard */}
            <h2 className="text-lg font-semibold mt-8 mb-4 tracking-tight">Análise de Performance</h2>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {/* Chart Evolução do Saldo */}
                <Card className="bg-card/50 border-border/50">
                    <CardHeader className="flex flex-col sm:flex-row sm:items-center justify-between pb-2">
                        <div>
                            <CardTitle className="text-lg">Evolução do Saldo</CardTitle>
                            <p className="text-sm text-muted-foreground mt-1">Acompanhe seu patrimônio diário nos últimos 7 dias</p>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <div className="h-[300px] mt-4">
                            <ResponsiveContainer width="100%" height="100%">
                                <AreaChart data={chartData} margin={{ top: 10, right: 10, left: 10, bottom: 0 }}>
                                    <defs>
                                        <linearGradient id="colorSaldo" x1="0" y1="0" x2="0" y2="1">
                                            <stop offset="5%" stopColor="hsl(var(--primary))" stopOpacity={0.3} />
                                            <stop offset="95%" stopColor="hsl(var(--primary))" stopOpacity={0} />
                                        </linearGradient>
                                    </defs>
                                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="hsl(var(--border))" />
                                    <XAxis dataKey="date" stroke="hsl(var(--muted-foreground))" fontSize={12} tickLine={false} axisLine={false} dy={10} />
                                    <YAxis
                                        stroke="hsl(var(--muted-foreground))"
                                        fontSize={12}
                                        tickLine={false}
                                        axisLine={false}
                                        tickFormatter={(value) => `R$${value.toLocaleString('pt-BR', { notation: "compact" })}`}
                                        width={75}
                                    />
                                    <Tooltip
                                        contentStyle={{
                                            backgroundColor: 'hsl(var(--card))',
                                            border: '1px solid hsl(var(--border))',
                                            borderRadius: '8px',
                                            boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'
                                        }}
                                        itemStyle={{ color: 'hsl(var(--foreground))', fontWeight: 600 }}
                                        formatter={(value: number) => [formatCurrency(value), 'Saldo em Conta']}
                                        labelStyle={{ color: 'hsl(var(--muted-foreground))', marginBottom: '4px' }}
                                    />
                                    <Area
                                        type="monotone"
                                        dataKey="saldo"
                                        stroke="hsl(var(--primary))"
                                        fillOpacity={1}
                                        fill="url(#colorSaldo)"
                                        strokeWidth={3}
                                        activeDot={{ r: 6, fill: "hsl(var(--primary))", stroke: "hsl(var(--background))", strokeWidth: 2 }}
                                    />
                                </AreaChart>
                            </ResponsiveContainer>
                        </div>
                    </CardContent>
                </Card>

                {/* Chart Volume de Transferências */}
                <Card className="bg-card/50 border-border/50">
                    <CardHeader className="flex flex-col sm:flex-row sm:items-center justify-between pb-2">
                        <div>
                            <CardTitle className="text-lg">Volume de Transferências</CardTitle>
                            <p className="text-sm text-muted-foreground mt-1">Movimentações entre suas contas nos últimos 7 dias</p>
                        </div>
                    </CardHeader>
                    <CardContent>
                        <div className="h-[300px] mt-4">
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart data={transferChartData} margin={{ top: 10, right: 10, left: 10, bottom: 0 }}>
                                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="hsl(var(--border))" />
                                    <XAxis dataKey="date" stroke="hsl(var(--muted-foreground))" fontSize={12} tickLine={false} axisLine={false} dy={10} />
                                    <YAxis
                                        stroke="hsl(var(--muted-foreground))"
                                        fontSize={12}
                                        tickLine={false}
                                        axisLine={false}
                                        tickFormatter={(value) => `R$${value.toLocaleString('pt-BR', { notation: "compact" })}`}
                                        width={75}
                                    />
                                    <Tooltip
                                        cursor={{ fill: 'hsl(var(--muted)/0.5)' }}
                                        contentStyle={{
                                            backgroundColor: 'hsl(var(--card))',
                                            border: '1px solid hsl(var(--border))',
                                            borderRadius: '8px',
                                            boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'
                                        }}
                                        itemStyle={{ color: 'hsl(var(--foreground))', fontWeight: 600 }}
                                        formatter={(value: number) => [formatCurrency(value), 'Volume Transferido']}
                                        labelStyle={{ color: 'hsl(var(--muted-foreground))', marginBottom: '4px' }}
                                    />
                                    <Bar
                                        dataKey="volume"
                                        fill="hsl(var(--blue-500, 221 83% 53%))"
                                        radius={[4, 4, 0, 0]}
                                    />
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    </CardContent>
                </Card>
            </div>

            <h2 className="text-lg font-semibold mt-8 mb-4 tracking-tight">Detalhes Bancários</h2>

            {/* Accounts */}
            <Card className="bg-card/50 border-border/50">
                <CardHeader>
                    <CardTitle className="text-lg">Minhas Contas</CardTitle>
                </CardHeader>
                <CardContent>
                    {accounts.length === 0 ? (
                        <div className="text-center py-8 text-muted-foreground">
                            <Wallet className="h-8 w-8 mx-auto mb-2 opacity-50" />
                            <p>Nenhuma conta cadastrada</p>
                            <Button onClick={() => setAccountModalOpen(true)} className="mt-4" variant="outline">
                                <Plus className="h-4 w-4 mr-2" /> Cadastrar Primeira Conta
                            </Button>
                        </div>
                    ) : (
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            {accounts.map(account => (
                                <Card key={account.id} className={cn(
                                    "hover:shadow-md transition-shadow cursor-default",
                                    account.is_main ? "bg-gradient-to-br from-primary/10 to-transparent border-primary/30" : "bg-card border-border/50"
                                )}>
                                    <CardContent className="p-5">
                                        <div className="flex items-center justify-between mb-4">
                                            <div className="flex items-center gap-3">
                                                <div className={cn(
                                                    "p-2 rounded-lg",
                                                    account.is_main ? "bg-primary/20 text-primary" : "bg-muted text-muted-foreground"
                                                )}>
                                                    {getAccountIcon(account.account_type)}
                                                </div>
                                                <div>
                                                    <span className="font-semibold block leading-tight">{account.name}</span>
                                                    <span className="text-xs text-muted-foreground">{account.account_type}</span>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-2">
                                                {account.is_main && (
                                                    <span className="text-[10px] bg-primary text-primary-foreground px-2 py-1 rounded-full uppercase font-bold tracking-wider">Principal</span>
                                                )}
                                                <Button
                                                    variant="ghost"
                                                    size="icon"
                                                    className="h-8 w-8 text-muted-foreground hover:text-foreground hover:bg-muted"
                                                    onClick={(e) => {
                                                        e.stopPropagation();
                                                        setSelectedAccount(account);
                                                        setDetailsModalOpen(true);
                                                    }}
                                                >
                                                    <Eye className="h-4 w-4" />
                                                </Button>
                                            </div>
                                        </div>
                                        <div className="mt-2 text-right">
                                            <p className="text-xs text-muted-foreground mb-1 uppercase tracking-wider font-semibold">Balanço</p>
                                            <p className="text-2xl font-bold font-mono tracking-tight">{formatCurrency(account.current_balance || 0)}</p>
                                        </div>
                                    </CardContent>
                                </Card>
                            ))}
                        </div>
                    )}
                </CardContent>
            </Card>

            {/* Modals */}
            <AddTransactionModal
                open={transactionModalOpen}
                onOpenChange={setTransactionModalOpen}
                type={transactionType}
                onSuccess={fetchData}
            />
            <AddTransferModal
                open={transferModalOpen}
                onOpenChange={setTransferModalOpen}
                onSuccess={fetchData}
            />
            <AddAccountModal
                open={accountModalOpen}
                onOpenChange={setAccountModalOpen}
                onSuccess={fetchData}
            />
            <ManageCategoriesModal
                open={categoriesModalOpen}
                onOpenChange={setCategoriesModalOpen}
            />
            <AccountDetailsModal
                account={selectedAccount}
                open={detailsModalOpen}
                onOpenChange={setDetailsModalOpen}
            />
        </div>
    );
}

import { useState, useRef } from 'react';
import { Link } from 'react-router-dom';
import { ArrowLeft, Loader2, Mail, CheckCircle } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { useToast } from '@/hooks/use-toast';
import { supabase } from '@/integrations/supabase/client';
import wfeLogo from '@/assets/wfe-logo.png';
import HCaptcha from '@hcaptcha/react-hcaptcha';

const ForgotPassword = () => {
  const [email, setEmail] = useState('');
  const [captchaToken, setCaptchaToken] = useState<string | null>(null);
  const captchaRef = useRef<HCaptcha>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [emailSent, setEmailSent] = useState(false);
  const {
    toast
  } = useToast();
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email) {
      toast({
        title: "Email obrigatório",
        description: "Por favor, insira seu email para continuar.",
        variant: "destructive"
      });
      return;
    }
    setIsLoading(true);
    try {
      const redirectUrl = `${window.location.origin}/redefinir-senha`;
      const {
        error
      } = await supabase.auth.resetPasswordForEmail(email, {
        redirectTo: redirectUrl,
        captchaToken: captchaToken || undefined
      });
      if (error) {
        throw error;
      }
      setEmailSent(true);
      toast({
        title: "Email enviado!",
        description: "Verifique sua caixa de entrada para redefinir sua senha."
      });
    } catch (error: any) {
      console.error('Error sending reset email:', error);
      captchaRef.current?.resetCaptcha();
      setCaptchaToken(null);
      toast({
        title: "Erro ao enviar email",
        description: error.message || "Tente novamente mais tarde.",
        variant: "destructive"
      });
    } finally {
      setIsLoading(false);
    }
  };
  return <div className="min-h-screen flex items-center justify-center bg-background px-4">
      <div className="w-full max-w-md space-y-8">
        {/* Logo */}
        <div className="flex flex-col items-center">
          <div className="flex items-center gap-3 mb-8">
            <Link to="/login">
              <img src={wfeLogo} alt="WFE Evolution" className="h-12 w-auto object-contain cursor-pointer" />
            </Link>
            <span className="text-xl font-semibold tracking-tight">
          </span>
          </div>
        </div>

        <Card className="border-border/50 shadow-lg">
          <CardHeader className="text-center">
            <CardTitle className="text-2xl">
              {emailSent ? "Email Enviado!" : "Recuperar Senha"}
            </CardTitle>
            <CardDescription>
              {emailSent ? "Verifique sua caixa de entrada e clique no link para redefinir sua senha." : "Insira seu email e enviaremos um link para redefinir sua senha."}
            </CardDescription>
          </CardHeader>

          <CardContent>
            {emailSent ? <div className="space-y-6">
                <div className="flex justify-center">
                  <div className="p-4 rounded-full bg-success/20">
                    <CheckCircle className="h-12 w-12 text-success" />
                  </div>
                </div>
                <div className="space-y-2 text-center text-sm text-muted-foreground">
                  <p>Um email foi enviado para:</p>
                  <p className="font-medium text-foreground">{email}</p>
                  <p className="pt-4">
                    Não recebeu o email? Verifique sua pasta de spam ou{' '}
                    <button onClick={() => setEmailSent(false)} className="text-primary hover:underline">
                      tente novamente
                    </button>
                  </p>
                </div>
                <Link to="/login">
                  <Button variant="outline" className="w-full gap-2">
                    <ArrowLeft className="h-4 w-4" />
                    Voltar para o login
                  </Button>
                </Link>
              </div> : <form onSubmit={handleSubmit} className="space-y-6">
                <div className="space-y-2">
                  <Label htmlFor="email">Email</Label>
                  <div className="relative">
                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <Input id="email" type="email" placeholder="seu@email.com" className="pl-10" value={email} onChange={e => setEmail(e.target.value)} disabled={isLoading} />
                  </div>
                </div>

                {/* hCaptcha Component */}
                <div className="flex justify-center py-2">
                  <HCaptcha
                    ref={captchaRef}
                    sitekey="34724568-8f44-4a36-adba-60c843d04452"
                    onVerify={(token) => setCaptchaToken(token)}
                    onExpire={() => setCaptchaToken(null)}
                    theme="dark"
                  />
                </div>

                <Button type="submit" className="w-full" disabled={isLoading || !captchaToken}>
                  {isLoading ? <>
                      <Loader2 className="mr-2 h-4 w-4 animate-spin" />
