      {/* Tabs */}
      <Tabs defaultValue="subscriptions">
        <TabsList>
          <TabsTrigger value="subscriptions" className="gap-2">
            <Shield className="h-4 w-4" />
            Assinaturas
          </TabsTrigger>
          <TabsTrigger value="terms" className="gap-2">
            <FileCheck className="h-4 w-4" />
            Termos
          </TabsTrigger>
          <TabsTrigger value="employees" className="gap-2">
            <Users className="h-4 w-4" />
            Funcionários
          </TabsTrigger>
        </TabsList>



        <TabsContent value="subscriptions" className="mt-6">
          <SubscriptionsManager />
        </TabsContent>

        <TabsContent value="employees" className="mt-6">
          <EmployeesManager />
        </TabsContent>

        <TabsContent value="terms" className="space-y-6 mt-6">
          {/* Stats */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium text-muted-foreground">Total de Aceites</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold">{termsAcceptances.length}</div>
              </CardContent>
            </Card>
            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium text-muted-foreground">Aceites no Último Mês</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-primary">
                  {termsAcceptances.filter(t => {
                    const d = new Date(t.accepted_at);
                    const now = new Date();
                    return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
                  }).length}
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Search + Export */}
          <div className="flex items-center gap-2">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder="Filtrar por nome ou email..."
                value={termsSearch}
                onChange={(e) => setTermsSearch(e.target.value)}
                className="pl-9"
              />
            </div>
            <Button
              variant="outline"
              size="sm"
              onClick={() => {
                const csv = ['Nome,Email,Versão,Data do Aceite,IP']
                  .concat(termsAcceptances.map(t =>
                    `"${t.user_name}","${t.user_email}","${t.terms_version}","${new Date(t.accepted_at).toLocaleString('pt-BR')}","${t.ip_address || ''}"`
                  )).join('\n');
                const blob = new Blob([csv], { type: 'text/csv' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'termos_aceites.csv';
                a.click();
              }}
            >
              <Download className="mr-2 h-4 w-4" />
              CSV
            </Button>
          </div>

          {/* Table */}
          <Card>
            <CardContent className="pt-6">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Nome</TableHead>
                    <TableHead>Email</TableHead>
                    <TableHead>Versão</TableHead>
                    <TableHead>Data do Aceite</TableHead>
                    <TableHead>IP</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {termsAcceptances
                    .filter(t => {
                      if (!termsSearch) return true;
                      const s = termsSearch.toLowerCase();
                      return t.user_name.toLowerCase().includes(s) || t.user_email.toLowerCase().includes(s);
                    })
                    .map((t) => (
                      <TableRow key={t.id}>
                        <TableCell className="font-medium">{t.user_name}</TableCell>
                        <TableCell>{t.user_email}</TableCell>
                        <TableCell>
                          <Badge variant="outline">v{t.terms_version}</Badge>
                        </TableCell>
                        <TableCell>{new Date(t.accepted_at).toLocaleString('pt-BR')}</TableCell>
                        <TableCell className="text-muted-foreground">{t.ip_address || '—'}</TableCell>
                      </TableRow>
                    ))}
                  {termsAcceptances.length === 0 && (
                    <TableRow>
                      <TableCell colSpan={5} className="text-center text-muted-foreground py-8">
                        <FileCheck className="h-12 w-12 mx-auto mb-4 opacity-50" />
                        Nenhum aceite registrado
                      </TableCell>
                    </TableRow>
                  )}
                </TableBody>
              </Table>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

    </div>
  );
}

// @ts-nocheck
import { useState, useMemo, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { usePlanGate } from '@/hooks/usePlanGate';
import { useNavigate } from 'react-router-dom';
import { toast } from 'sonner';
import { Skeleton } from '@/components/ui/skeleton';
import { useMaterialLosses } from '@/hooks/useMaterialLosses';
import { useMaterialLossLimits } from '@/hooks/useMaterialLossLimits';
import { MaterialLossFormModal } from '@/components/material-losses/MaterialLossFormModal';
import { MaterialLossLimitsModal } from '@/components/material-losses/MaterialLossLimitsModal';
import { StatsCard } from '@/components/shared/StatsCard';
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { Badge } from "@/components/ui/badge";
import { AlertTriangle, Plus, Settings, TrendingDown, DollarSign, Ruler, FileWarning, MoreHorizontal, Pencil, Trash2, FileSpreadsheet, FileText } from 'lucide-react';
import { format } from 'date-fns';
import { useDeleteMaterialLoss } from '@/hooks/useMaterialLosses';
import { generateReportPDF } from '@/lib/pdfGenerator';
import { cn } from '@/lib/utils';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";

const formatSafeDate = (dateStr: string | null | undefined): string => {
  if (!dateStr) return 'N/A';
  try {
    const date = new Date(dateStr);
    if (isNaN(date.getTime())) return 'N/A';
    return format(date, 'dd/MM/yyyy HH:mm');
  } catch (error) {
    console.error('Error formatting date:', error);
    return 'N/A';
  }
};

export default function MaterialLosses() {
  const { user, isLoading: authLoading } = useAuth();
  const gate = usePlanGate('perdas');
  const navigate = useNavigate();
  const [showFormModal, setShowFormModal] = useState(false);
  const [showLimitsModal, setShowLimitsModal] = useState(false);
  const [selectedLoss, setSelectedLoss] = useState<any>(null);
  const [lossToCancel, setLossToCancel] = useState<any>(null);

  // Filters
  const [categoryFilter, setCategoryFilter] = useState<'ALL' | 'PPF' | 'INSULFILM'>('ALL');

  useEffect(() => {
    if (!authLoading && !gate.hasAccess) {
      if (gate.message) {
        toast.error(gate.message);
      }
      if (gate.redirectTo) {
        navigate(gate.redirectTo, { replace: true });
      }
    }
  }, [authLoading, gate.hasAccess, gate.redirectTo, gate.message, navigate]);

  const { data: losses, isLoading } = useMaterialLosses({
    category: categoryFilter !== 'ALL' ? categoryFilter : undefined,
  });

  const { data: limits } = useMaterialLossLimits();
  const deleteMutation = useDeleteMaterialLoss();

  const isAdmin = user?.role === 'ADMIN';

  // Calculations for cards
  const stats = useMemo(() => {
    if (!losses) return { meters: 0, m2: 0, count: 0, cost: 0 };
    return losses.reduce((acc, curr) => {
      if (curr.status === 'cancelled') return acc;
      acc.meters += Number(curr.lost_meters);
      acc.m2 += Number(curr.lost_m2);
      acc.cost += Number(curr.cost);
      acc.count += 1;
      return acc;
    }, { meters: 0, m2: 0, count: 0, cost: 0 });
  }, [losses]);

  // Alert calculations
  const alerts = useMemo(() => {
    if (!limits || !losses) return [];

    const triggered: string[] = [];

    const startOfMonth = new Date();
    startOfMonth.setDate(1);
    startOfMonth.setHours(0, 0, 0, 0);

    // Group losses by category for limit checking (only current month)
    const lossesByCategory = losses.reduce((acc, curr) => {
      if (curr.status === 'cancelled') return acc;

      const lossDate = new Date(curr.created_at);
      if (lossDate < startOfMonth) return acc;

      if (!acc[curr.category]) acc[curr.category] = { cost: 0, meters: 0, count: 0 };
      acc[curr.category].cost += Number(curr.cost);
      acc[curr.category].meters += Number(curr.lost_meters);
      acc[curr.category].count += 1;
      return acc;
    }, {} as Record<string, { cost: number; meters: number; count: number }>);

    limits.forEach(limit => {
      const catStats = lossesByCategory[limit.category];
      if (!catStats) return;

      let valueToCheck = 0;
      let limitLabel = '';

      if (limit.limit_type === 'cost') {
        valueToCheck = catStats.cost;
        limitLabel = `R$ ${limit.limit_value}`;
      } else if (limit.limit_type === 'meters') {
        valueToCheck = catStats.meters;
        limitLabel = `${limit.limit_value}m`;
      } else if (limit.limit_type === 'count') {
        valueToCheck = catStats.count;
        limitLabel = `${limit.limit_value} registros`;
      }

      if (valueToCheck > Number(limit.limit_value)) {
        triggered.push(`Alerta de limite excedido: ${limit.category} ultrapassou o teto de ${limitLabel}. Atual: ${limit.limit_type === 'cost' ? `R$ ${valueToCheck.toFixed(2)}` :
            limit.limit_type === 'meters' ? `${valueToCheck.toFixed(2)}m` :
              valueToCheck
          }`);
      }
    });

    return triggered;
  }, [limits, losses]);

  if (authLoading || isLoading || !gate.hasAccess) {
    return (
      <div className="space-y-6 p-6">
        <Skeleton className="h-10 w-48" />
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          {[1, 2, 3, 4].map((i) => (
            <Skeleton key={i} className="h-24" />
          ))}
        </div>
        <Skeleton className="h-96" />
      </div>
    );
  }

  const exportToPDF = async () => {
    if (!losses) return;

    const columns = ['Data', 'Instalador', 'Material', 'Categoria', 'Metros', 'Motivo', 'Custo'];
    const rows = losses
      .filter(loss => loss.status !== 'cancelled')
      .map(loss => [
        formatSafeDate(loss.created_at),
        loss.installer?.name || 'Não identificado',
        loss.material?.name || '',
        loss.category,
        `${loss.lost_meters}m`,
        loss.reason,
        `R$ ${Number(loss.cost).toFixed(2)}`
      ]);

    const reportData = {
      title: 'Relatório de Perdas de Material',
      columns,
      rows,
      summary: [
        { label: 'Total de Metros Perdidos', value: `${stats.meters.toFixed(2)} m` },
        { label: 'Total de Área Perdida', value: `${stats.m2.toFixed(2)} m²` },
        { label: 'Custo Total Estimado', value: `R$ ${stats.cost.toFixed(2)}` },
        { label: 'Quantidade de Registros', value: String(stats.count) }
      ]
    };

    try {
      await generateReportPDF(reportData, user?.companyId ? Number(user.companyId) : undefined);
    } catch (error) {
      console.error('Error generating PDF:', error);
    }
  };



  const exportToExcel = () => {
    if (!losses) return;

    const activeLosses = losses.filter(loss => loss.status !== 'cancelled');

    let html = `<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">`;
    html += `<head><meta charset="utf-8" /><style>table { border-collapse: collapse; } th { background-color: #333333; color: #ffffff; font-weight: bold; } th, td { border: 1px solid #dddddd; padding: 8px; text-align: left; } .number { text-align: right; }</style></head>`;
    html += `<body>`;
    html += `<h2>Relatório de Perdas de Material</h2>`;
    html += `<p>Gerado em: ${format(new Date(), 'dd/MM/yyyy HH:mm')}</p>`;
    html += `<table>`;
    html += `<thead><tr>`;
    html += `<th>Data</th><th>Instalador</th><th>Material</th><th>Categoria</th><th>Metros</th><th>Motivo</th><th>Custo</th>`;
    html += `</tr></thead><tbody>`;

    activeLosses.forEach(loss => {
      html += `<tr>`;
      html += `<td>${formatSafeDate(loss.created_at)}</td>`;
      html += `<td>${loss.installer?.name || 'Não identificado'}</td>`;
      html += `<td>${loss.material?.name || ''}</td>`;
      html += `<td>${loss.category}</td>`;
      html += `<td>${loss.lost_meters}m</td>`;
      html += `<td>${loss.reason}</td>`;
      html += `<td class="number">R$ ${Number(loss.cost).toFixed(2)}</td>`;
      html += `</tr>`;
    });

    html += `</tbody></table>`;

    // Resumo
    html += `<h3>Resumo</h3>`;
    html += `<ul>`;
    html += `<li><strong>Total de Metros Perdidos:</strong> ${stats.meters.toFixed(2)} m</li>`;
    html += `<li><strong>Total de Área Perdida:</strong> ${stats.m2.toFixed(2)} m²</li>`;
    html += `<li><strong>Custo Total Estimado:</strong> R$ ${stats.cost.toFixed(2)}</li>`;
    html += `<li><strong>Quantidade de Registros:</strong> ${stats.count}</li>`;
    html += `</ul>`;

    html += `</body></html>`;

    const blob = new Blob([html], { type: 'application/vnd.ms-excel' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `perdas_material_${format(new Date(), 'yyyy-MM-dd')}.xls`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="p-4 sm:p-6 lg:p-8 space-y-8 max-w-[100vw] overflow-x-hidden">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl lg:text-3xl font-light">Perdas de <span className="font-semibold">Material</span></h1>
          <p className="text-muted-foreground">Monitore e registre o desperdício de insumos.</p>
        </div>
        <div className="flex gap-2">
          {isAdmin && (
            <Button variant="outline" onClick={() => setShowLimitsModal(true)}>
              <Settings className="w-4 h-4 mr-2" />
              Limites
            </Button>
          )}
          <Button onClick={() => setShowFormModal(true)}>
            <Plus className="w-4 h-4 mr-2" />
            Nova Perda
          </Button>
        </div>
      </div>

      {/* Alerts */}
      {alerts.length > 0 && (
        <div className="space-y-2">
          {alerts.map((msg, i) => (
            <Alert variant="destructive" key={i}>
              <AlertTriangle className="h-4 w-4" />
              <AlertTitle>Atenção</AlertTitle>
              <AlertDescription>{msg}</AlertDescription>
            </Alert>
          ))}
        </div>
      )}

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatsCard
          title="Metros Perdidos"
          value={`${stats.meters.toFixed(2)} m`}
          icon={<Ruler className="w-5 h-5" />}
          variant="warning"
        />
        <StatsCard
          title="Área Perdida"
          value={`${stats.m2.toFixed(2)} m²`}
          icon={<TrendingDown className="w-5 h-5" />}
          variant="destructive"
        />
        <StatsCard
          title="Custo Estimado"
          value={`R$ ${stats.cost.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`}
          icon={<DollarSign className="w-5 h-5" />}
          variant="destructive"
        />
        <StatsCard
          title="Qtd. Registros"
          value={stats.count}
          icon={<FileWarning className="w-5 h-5" />}
          variant="info"
        />
      </div>

      {/* Visual Limits Panel */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-card/30 border border-border/50 rounded-xl p-5 backdrop-blur-sm">
        <div className="col-span-full flex items-center justify-between border-b border-border/40 pb-3">
          <div>
            <h3 className="text-lg font-semibold tracking-tight text-foreground">Limites de Desperdício Mensal</h3>
            <p className="text-xs text-muted-foreground">Acompanhamento de perdas do mês corrente em relação aos tetos definidos.</p>
          </div>
          {isAdmin && (
            <Button variant="ghost" size="sm" className="h-8 text-xs hover:bg-muted/50 text-muted-foreground hover:text-foreground" onClick={() => setShowLimitsModal(true)}>
              <Settings className="w-3.5 h-3.5 mr-1.5" />
              Configurar
            </Button>
          )}
        </div>

        {['PPF', 'INSULFILM'].map((cat) => {
          const limit = limits?.find(l => l.category === cat);

          // Calculate usage for current month
          const startOfMonth = new Date();
          startOfMonth.setDate(1);
          startOfMonth.setHours(0, 0, 0, 0);

          const catStats = losses?.reduce((acc, curr) => {
            if (curr.status === 'cancelled' || curr.category !== cat) return acc;
            const lossDate = new Date(curr.created_at);
            if (lossDate < startOfMonth) return acc;

            acc.cost += Number(curr.cost);
            acc.meters += Number(curr.lost_meters);
            acc.count += 1;
            return acc;
          }, { cost: 0, meters: 0, count: 0 });

          if (!limit) {
            return (
              <div key={cat} className="flex flex-col justify-center items-center p-6 border border-dashed border-border/60 rounded-lg bg-card/10 min-h-[140px]">
                <span className="text-sm font-semibold text-foreground/80 mb-1">{cat}</span>
                <span className="text-xs text-muted-foreground text-center mb-3">Nenhum limite mensal definido</span>
                {isAdmin && (
                  <Button variant="outline" size="sm" className="h-7 text-[10px] py-0 px-3 hover:bg-muted/50" onClick={() => setShowLimitsModal(true)}>
                    Definir Limite
                  </Button>
                )}
              </div>
            );
          }

          let valueToCheck = 0;
          let limitLabel = '';
          let currentValueLabel = '';

          if (limit.limit_type === 'cost') {
            valueToCheck = catStats?.cost || 0;
            limitLabel = `R$ ${Number(limit.limit_value).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
            currentValueLabel = `R$ ${valueToCheck.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
          } else if (limit.limit_type === 'meters') {
            valueToCheck = catStats?.meters || 0;
            limitLabel = `${Number(limit.limit_value).toFixed(2)}m`;
            currentValueLabel = `${valueToCheck.toFixed(2)}m`;
          } else if (limit.limit_type === 'count') {
            valueToCheck = catStats?.count || 0;
            limitLabel = `${limit.limit_value} registros`;
            currentValueLabel = `${valueToCheck} registros`;
          }

          const percent = limit.limit_value > 0 ? (valueToCheck / Number(limit.limit_value)) * 100 : 0;
          const percentClamped = Math.min(100, percent);

          let barColorClass = "bg-emerald-500";
          let statusLabel = "Sob Controle";
          let statusColorClass = "text-emerald-500 border-emerald-500/30 bg-emerald-500/10";

          if (percent >= 100) {
            barColorClass = "bg-red-500 animate-pulse";
            statusLabel = "Excedido";
            statusColorClass = "text-red-500 border-red-500/30 bg-red-500/10";
          } else if (percent >= 75) {
            barColorClass = "bg-amber-500";
            statusLabel = "Atenção";
            statusColorClass = "text-amber-500 border-amber-500/30 bg-amber-500/10";
          }

          const limitTypeName =
            limit.limit_type === 'cost' ? 'Custo Financeiro' :
              limit.limit_type === 'meters' ? 'Metragem' : 'Registros';

          return (
            <div key={cat} className="p-4 border border-border/50 rounded-lg bg-card/45 space-y-3">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <span className="font-semibold text-sm tracking-wide text-foreground">{cat}</span>
                  <Badge variant="outline" className={`text-[10px] font-medium py-0 px-2 rounded-full border ${statusColorClass}`}>
                    {statusLabel}
                  </Badge>
                </div>
                <span className="text-[10px] text-muted-foreground uppercase font-semibold">{limitTypeName}</span>
              </div>

              <div className="space-y-1">
                <div className="flex justify-between text-xs">
                  <span className="text-muted-foreground">Consumo no mês</span>
                  <span className="font-medium text-foreground">{percent.toFixed(0)}%</span>
                </div>
                {/* Custom premium progress bar */}
                <div className="relative w-full h-2 bg-muted/60 rounded-full overflow-hidden">
                  <div
                    className={`h-full rounded-full transition-all duration-500 ease-out ${barColorClass}`}
                    style={{ width: `${percentClamped}%` }}
                  />
                </div>
                <div className="flex justify-between text-[11px] text-muted-foreground">
                  <span>{currentValueLabel}</span>
                  <span>Teto: {limitLabel}</span>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Filters and List */}
      <div className="space-y-4">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div className="flex items-center gap-4">
            <Select value={categoryFilter} onValueChange={(v: any) => setCategoryFilter(v)}>
              <SelectTrigger className="w-[180px]">
                <SelectValue placeholder="Categoria" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="ALL">Todas Categorias</SelectItem>
                <SelectItem value="PPF">PPF</SelectItem>
                <SelectItem value="INSULFILM">Insulfilm</SelectItem>
              </SelectContent>
            </Select>
          </div>

          <div className="flex gap-2 flex-wrap">
            <Button variant="outline" size="sm" onClick={exportToPDF} disabled={!losses || losses.length === 0}>
              <FileText className="w-4 h-4 mr-2" />
              PDF
            </Button>
            <Button variant="outline" size="sm" onClick={exportToExcel} disabled={!losses || losses.length === 0}>
              <FileSpreadsheet className="w-4 h-4 mr-2" />
              Excel
            </Button>
          </div>
          <div className="space-y-4">
            {/* 🖥️ Visualização Desktop: Tabela Completa */}
            <div className="hidden md:block rounded-md border bg-card overflow-x-auto">
              <Table className="min-w-[700px]">
                <TableHeader>
                  <TableRow>
                    <TableHead>Data</TableHead>
                    <TableHead>Instalador</TableHead>
                    <TableHead>Material</TableHead>
                    <TableHead>Categoria</TableHead>
                    <TableHead>Metros</TableHead>
                    <TableHead>Motivo</TableHead>
                    <TableHead className="text-right">Custo</TableHead>
                    <TableHead className="w-[50px]"></TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {losses?.map((loss: any) => (
                    <TableRow key={loss.id} className={loss.status === 'cancelled' ? 'opacity-50 line-through' : ''}>
                      <TableCell>{formatSafeDate(loss.created_at)}</TableCell>
                      <TableCell>{loss.installer?.name || 'Não identificado'}</TableCell>
                      <TableCell>{loss.material?.name}</TableCell>
                      <TableCell>{loss.category}</TableCell>
                      <TableCell>{loss.lost_meters}m</TableCell>
                      <TableCell>{loss.reason}</TableCell>
                      <TableCell className="text-right">
                        R$ {Number(loss.cost).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </TableCell>
                      <TableCell>
                        {loss.status !== 'cancelled' && (
                          <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                              <Button variant="ghost" className="h-8 w-8 p-0">
                                <span className="sr-only">Abrir menu</span>
                                <MoreHorizontal className="h-4 w-4" />
                              </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end">
                              <DropdownMenuItem onClick={() => {
                                setSelectedLoss(loss);
                                setShowFormModal(true);
                              }}>
                                <Pencil className="h-4 w-4 mr-2" />
                                Editar
                              </DropdownMenuItem>
                              {isAdmin && (
                                <DropdownMenuItem
                                  className="text-destructive focus:text-destructive"
                                  onClick={() => setLossToCancel(loss)}
                                >
                                  <Trash2 className="h-4 w-4 mr-2" />
                                  Cancelar Registro
                                </DropdownMenuItem>
                              )}
                            </DropdownMenuContent>
                          </DropdownMenu>
                        )}
                      </TableCell>
                    </TableRow>
                  ))}
                  {!isLoading && (!losses || losses.length === 0) && (
                    <TableRow>
                      <TableCell colSpan={8} className="text-center py-4 text-muted-foreground">
                        Nenhum registro de perda encontrado.
                      </TableCell>
                    </TableRow>
                  )}
                </TableBody>
              </Table>
            </div>

            {/* 📱 Visualização Mobile: Cards Empilhados */}
            <div className="grid grid-cols-1 gap-3 md:hidden">
              {losses?.map((loss: any) => (
                <Card key={loss.id} className={cn("bg-card/50 border-border/50 p-4 space-y-3", loss.status === 'cancelled' ? 'opacity-50' : '')}>
                  {/* Topo: Data, Categoria e Ações */}
                  <div className="flex items-start justify-between gap-2">
                    <div>
                      <span className="text-[10px] text-muted-foreground block">{formatSafeDate(loss.created_at)}</span>
                      <h4 className="font-semibold text-sm text-foreground leading-tight">{loss.material?.name || 'Material não identificado'}</h4>
                    </div>
                    {loss.status !== 'cancelled' && (
                      <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                          <Button variant="ghost" className="h-8 w-8 p-0">
                            <MoreHorizontal className="h-4 w-4" />
                          </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end">
                          <DropdownMenuItem onClick={() => {
                            setSelectedLoss(loss);
                            setShowFormModal(true);
                          }}>
                            <Pencil className="h-4 w-4 mr-2" />
                            Editar
                          </DropdownMenuItem>
                          {isAdmin && (
                            <DropdownMenuItem
                              className="text-destructive focus:text-destructive"
                              onClick={() => setLossToCancel(loss)}
                            >
                              <Trash2 className="h-4 w-4 mr-2" />
                              Cancelar Registro
                            </DropdownMenuItem>
                          )}
                        </DropdownMenuContent>
                      </DropdownMenu>
                    )}
                  </div>

                  {/* Informações do Instalador e Motivo */}
                  <div className="text-xs text-muted-foreground bg-muted/30 p-2.5 rounded space-y-1">
                    <p className="flex justify-between">
                      <span className="font-medium text-foreground">Instalador:</span>
                      <span>{loss.installer?.name || 'Não identificado'}</span>
                    </p>
                    <p className="flex flex-col gap-0.5">
                      <span className="font-medium text-foreground">Motivo:</span>
                      <span className="text-muted-foreground text-left">{loss.reason}</span>
                    </p>
                  </div>

                  {/* Métricas: Categoria, Metros, Custo */}
                  <div className="grid grid-cols-3 gap-2 pt-2.5 border-t border-border/40 text-center text-xs">
                    <div>
                      <span className="text-[10px] text-muted-foreground block mb-0.5">Categoria</span>
                      <Badge variant="outline" className="text-[10px] py-0 px-1.5 font-normal">{loss.category}</Badge>
                    </div>
                    <div>
                      <span className="text-[10px] text-muted-foreground block mb-0.5">Comprimento</span>
                      <span className="font-semibold text-foreground">{loss.lost_meters}m</span>
                    </div>
                    <div>
                      <span className="text-[10px] text-muted-foreground block mb-0.5">Custo</span>
                      <span className="font-semibold text-destructive">
                        R$ {Number(loss.cost).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </span>
                    </div>
                  </div>
                </Card>
              ))}
              {!isLoading && (!losses || losses.length === 0) && (
                <div className="text-center py-8 text-muted-foreground bg-card border rounded-md">
                  Nenhum registro de perda encontrado.
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      <MaterialLossFormModal
        open={showFormModal}
        onOpenChange={(open) => {
          setShowFormModal(open);
          if (!open) setSelectedLoss(null);
        }}
        lossToEdit={selectedLoss}
      />

      {isAdmin && (
        <MaterialLossLimitsModal
          open={showLimitsModal}
          onOpenChange={setShowLimitsModal}
        />
      )}

      {/* Cancel Confirmation Dialog */}
      <AlertDialog open={!!lossToCancel} onOpenChange={(open) => !open && setLossToCancel(null)}>
        <AlertDialogContent className="bg-card border-border">
          <AlertDialogHeader>
            <AlertDialogTitle>Confirmar cancelamento</AlertDialogTitle>
            <AlertDialogDescription>
              Tem certeza que deseja cancelar este registro de perda? O estoque do material será devolvido.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel className="border-border">Voltar</AlertDialogCancel>
            <AlertDialogAction
              onClick={async () => {
                if (lossToCancel) {
                  try {
                    await deleteMutation.mutateAsync(lossToCancel.id);
                  } catch (err) {
                    console.error("Error cancelling loss:", err);
                  } finally {
                    setLossToCancel(null);
                  }
                }
              }}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              Confirmar
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

﻿import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/integrations/supabase/client';
import { StatsCard } from '@/components/shared/StatsCard';
import { QuickActions } from './components/QuickActions';
import { TopClientsRanking } from './components/TopClientsRanking';
import { SalesChart } from './components/SalesChart';
import { CapacityWidget } from './components/CapacityWidget';
import { FinancialSummary } from './components/FinancialSummary';
import { HelpOverlay } from '@/components/help/HelpOverlay';
import { Search, DollarSign, TrendingUp, Users, Phone, Settings, Save, X, Car, User, Loader2 } from 'lucide-react';
import { Skeleton } from '@/components/ui/skeleton';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { toast } from 'sonner';
import NewClientModal from '@/pages/Vendas/components/NewClientModal';
import { FillSlotModal } from '@/shared/components/espaco/FillSlotModal';
import { startOfMonth, endOfMonth, format } from 'date-fns';

interface DashboardStats {
  totalSales: number;
  salesCount: number;
  averageTicket: number;
  newClients: number;
  pendingContacts: number;
  monthlyGoal: number;
  monthlyProgress: number;
}

const Dashboard = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [showFillSlotModal, setShowFillSlotModal] = useState(false);
  const [showNewClientModal, setShowNewClientModal] = useState(false);
  const [loading, setLoading] = useState(true);

  // State for search
  const [searchQuery, setSearchQuery] = useState("");
  const [isSearching, setIsSearching] = useState(false);
  const [showSearchResults, setShowSearchResults] = useState(false);
  const [searchResults, setSearchResults] = useState<{
    activeSpaces: any[];
    clients: any[];
    vehicles: any[];
  }>({ activeSpaces: [], clients: [], vehicles: [] });

  // Handle click outside of search dropdown
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as HTMLElement;
      if (!target.closest('.search-container')) {
        setShowSearchResults(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Search logic with debounce
  useEffect(() => {
    const delayDebounce = setTimeout(async () => {
      const cleanQuery = searchQuery.trim();
      if (cleanQuery.length < 2) {
        setSearchResults({ activeSpaces: [], clients: [], vehicles: [] });
        setIsSearching(false);
        return;
      }

      setIsSearching(true);
      try {
        const { data: profile } = await supabase
          .from('profiles')
          .select('company_id')
          .eq('user_id', user?.id)
          .single();

        if (!profile?.company_id) return;

        const term = `%${cleanQuery}%`;

        // 1. Fetch active spaces
        const { data: allActiveSpaces } = await supabase
          .from('spaces')
          .select(`
            id, name, entry_date, payment_status,
            client:clients(name, phone),
            vehicle:vehicles(brand, model, plate)
          `)
          .eq('company_id', profile.company_id)
          .eq('has_exited', false)
          .is('deleted_at', null);

        // Filter in-memory to match name, plate, brand, model or space name
        const cleanTerm = cleanQuery.toLowerCase();
        const matchedActiveSpaces = (allActiveSpaces || []).filter(space => {
          const clientName = space.client?.name?.toLowerCase() || '';
          const clientPhone = space.client?.phone || '';
          const vehicleBrand = space.vehicle?.brand?.toLowerCase() || '';
          const vehicleModel = space.vehicle?.model?.toLowerCase() || '';
          const vehiclePlate = space.vehicle?.plate?.toLowerCase() || '';
          const spaceName = space.name?.toLowerCase() || '';

          return clientName.includes(cleanTerm) ||
            clientPhone.includes(cleanTerm) ||
            vehicleBrand.includes(cleanTerm) ||
            vehicleModel.includes(cleanTerm) ||
            vehiclePlate.includes(cleanTerm) ||
            spaceName.includes(cleanTerm);
        });

        // 2. Fetch clients
        const { data: clientsData } = await supabase
          .from('clients')
          .select('id, name, phone')
          .eq('company_id', profile.company_id)
          .or(`name.ilike.${term},phone.ilike.${term}`)
          .limit(5);

        // 3. Fetch vehicles
        const { data: vehiclesData } = await supabase
          .from('vehicles')
          .select('id, brand, model, plate, client:clients(name)')
          .eq('company_id', profile.company_id)
          .or(`brand.ilike.${term},model.ilike.${term},plate.ilike.${term}`)
          .limit(5);

        setSearchResults({
          activeSpaces: matchedActiveSpaces,
          clients: clientsData || [],
          vehicles: vehiclesData || []
        });
      } catch (err) {
        console.error("Erro na busca instantânea:", err);
      } finally {
        setIsSearching(false);
      }
    }, 300);

    return () => clearTimeout(delayDebounce);
  }, [searchQuery, user?.id]);

  // States para Meta
  const [isEditingGoal, setIsEditingGoal] = useState(false);
  const [editingGoalValue, setEditingGoalValue] = useState<number>(0);
  const [isSavingGoal, setIsSavingGoal] = useState(false);

  const [stats, setStats] = useState<DashboardStats>({
    totalSales: 0,
    salesCount: 0,
    averageTicket: 0,
    newClients: 0,
    pendingContacts: 0,
    monthlyGoal: 50000,
    monthlyProgress: 0,
  });

  const userName = user?.profile?.name || user?.email?.split('@')[0] || 'Usuário';

  const today = new Date().toLocaleDateString('pt-BR', {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric'
  });

  useEffect(() => {
    const fetchDashboardStats = async () => {
      if (!user?.id) return;

      try {
        const { data: profile } = await supabase
          .from('profiles')
          .select('company_id')
          .eq('user_id', user.id)
          .single();

        if (!profile?.company_id) {
          setLoading(false);
          return;
        }

        const now = new Date();
        const monthStart = startOfMonth(now);
        const monthEnd = endOfMonth(now);

        const startDateStr = format(monthStart, 'yyyy-MM-dd');
        const endDateStr = format(monthEnd, 'yyyy-MM-dd');

        // Fetch sales for the current month
        const { data: salesData } = await supabase
          .from('sales')
          .select('total, is_open, sale_date')
          .eq('company_id', profile.company_id)
          .is('deleted_at', null)
          .gte('sale_date', startDateStr)
          .lte('sale_date', endDateStr);

        // Fetch new clients for the current month
        const { count: newClientsCount } = await supabase
          .from('clients')
          .select('*', { count: 'exact', head: true })
          .eq('company_id', profile.company_id)
          .gte('created_at', monthStart.toISOString())
          .lte('created_at', monthEnd.toISOString());

        // Fetch open sales (pending contacts)
        const { count: pendingCount } = await supabase
          .from('sales')
          .select('*', { count: 'exact', head: true })
          .eq('company_id', profile.company_id)
          .is('deleted_at', null)
          .eq('is_open', true);

        const sales = salesData || [];
        const totalRevenue = sales.reduce((sum, s) => sum + (s.total || 0), 0);
        const salesCount = sales.length;
        const avgTicket = salesCount > 0 ? totalRevenue / salesCount : 0;

        // Fetch monthly goal
        const { data: settingsData } = await supabase
          .from('company_settings')
          .select('monthly_goal')
          .eq('company_id', profile.company_id)
          .maybeSingle();

        const monthlyGoalSetting = settingsData?.monthly_goal || 50000;

        setStats({
          totalSales: totalRevenue,
          salesCount,
          averageTicket: avgTicket,
          newClients: newClientsCount || 0,
          pendingContacts: pendingCount || 0,
          monthlyGoal: monthlyGoalSetting,
          monthlyProgress: totalRevenue,
        });
      } catch (error) {
        console.error('Error fetching dashboard stats:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchDashboardStats();
  }, [user?.id]);

  const handleSaveGoal = async () => {
    if (!user?.id) return;
    try {
      setIsSavingGoal(true);
      if (editingGoalValue <= 0) {
        toast.error("Valor inválido");
        return;
      }

      const { data: profile } = await supabase
        .from('profiles')
        .select('company_id')
        .eq('user_id', user.id)
        .single();

      if (!profile?.company_id) return;

      // Tenta atualizar primeiro
      const { data: existing } = await supabase
        .from('company_settings')
        .select('id')
        .eq('company_id', profile.company_id)
        .maybeSingle();

      let error;
      if (existing) {
        // Já existe registro => update
        ({ error } = await supabase
          .from('company_settings')
          .update({ monthly_goal: editingGoalValue })
          .eq('company_id', profile.company_id));
      } else {
        // Não existe => insert
        ({ error } = await supabase
          .from('company_settings')
          .insert({ company_id: profile.company_id, monthly_goal: editingGoalValue }));
      }

      if (error) throw error;

      setStats(prev => ({ ...prev, monthlyGoal: editingGoalValue }));
      setIsEditingGoal(false);
      toast.success("Meta atualizada com sucesso!");
    } catch (err: any) {
      console.error("Erro ao salvar meta:", err);
      toast.error(err.message || "Erro ao atualizar a meta do mês. Talvez falte rodar uma Migration no Supabase.");
    } finally {
      setIsSavingGoal(false);
    }
  };

  return (
    <div className="p-4 sm:p-6 lg:p-8 space-y-8 max-w-[100vw] overflow-x-hidden">
      <HelpOverlay
        tabId="dashboard"
        title="Guia do Painel de Controle"
        sections={[
          {
            title: "Vídeo Aula — Painel",
            description: "Assista ao vídeo tutorial completo para aprender a usar todas as funcionalidades do painel de controle.",
            videoUrl: "/help/video-aula-painel.mp4"
          },
          {
            title: "Indicadores Principais",
            description: "No topo você encontra 4 cards com os principais indicadores do mês: Faturamento Total, Ticket Médio, Novos Clientes e Pós-Venda Pendente. Eles são atualizados automaticamente conforme você registra vendas.",
            screenshotUrl: "/help/help-dashboard-stats.png"
          },
          {
            title: "Ações Rápidas",
            description: "Use os botões de ação rápida para 'Preencher Vaga' (registrar a entrada de um veículo para serviço) ou 'Novo Cliente' (cadastrar um cliente rapidamente sem sair do painel).",
            screenshotUrl: "/help/help-dashboard-actions.png"
          },
          {
            title: "Gráfico de Vendas e Resumo Financeiro",
            description: "O gráfico mostra a tendência de vendas nos últimos dias. Ao lado, o Resumo Financeiro apresenta entradas, saídas e saldo. Use esses dados para identificar padrões de faturamento.",
            screenshotUrl: "/help/help-dashboard-charts.png"
          },
          {
            title: "Meta do Mês e Ranking de Clientes",
            description: "Acompanhe o progresso em relação à sua meta mensal pela barra de progresso. O Ranking mostra os clientes que mais gastaram, ajudando a identificar seus melhores clientes.",
            screenshotUrl: "/help/help-dashboard-goal.png"
          },
        ]}
      />
      {/* Header */}
      <div className="flex flex-col lg:flex-row lg:items-center lg:justify-between gap-4">
        <div className="animate-fade-in">
          <h1 className="text-2xl lg:text-3xl font-light">
            Olá, <span className="font-semibold">{userName.split(' ')[0]}</span>
          </h1>
          <p className="text-muted-foreground capitalize">{today}</p>
        </div>

        {/* Search Bar */}
        <div className="relative max-w-md w-full search-container z-50 animate-fade-in" style={{ animationDelay: '0.1s' }}>
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground" />
            <input
              type="text"
              placeholder="Buscar cliente, placa ou veículo..."
              value={searchQuery}
              onChange={(e) => {
                setSearchQuery(e.target.value);
                setShowSearchResults(true);
              }}
              onFocus={() => setShowSearchResults(true)}
              className="w-full h-12 pl-12 pr-4 rounded-xl bg-card border border-border focus:border-primary focus:ring-1 focus:ring-primary transition-all"
            />
            {isSearching && (
              <Loader2 className="absolute right-4 top-1/2 -translate-y-1/2 w-5 h-5 animate-spin text-muted-foreground" />
            )}
          </div>

          {showSearchResults && searchQuery.trim().length >= 2 && (
            <div className="absolute top-full left-0 right-0 mt-2 bg-card/95 backdrop-blur-md border border-border rounded-xl shadow-2xl overflow-hidden max-h-[400px] overflow-y-auto z-50">
              {isSearching ? (
                <div className="p-8 text-center text-muted-foreground flex items-center justify-center gap-2">
                  <Loader2 className="w-5 h-5 animate-spin text-primary" />
                  <span>Buscando...</span>
                </div>
              ) : searchResults.activeSpaces.length === 0 && searchResults.clients.length === 0 && searchResults.vehicles.length === 0 ? (
                <div className="p-8 text-center text-muted-foreground">
                  Nenhum resultado encontrado
                </div>
              ) : (
                <div className="p-2 space-y-4">
                  {/* Category: Vagas Ativas */}
                  {searchResults.activeSpaces.length > 0 && (
                    <div className="space-y-1">
                      <h4 className="text-[10px] uppercase font-bold text-muted-foreground px-3 py-1 tracking-wider">
                        Vagas Ativas (Em Andamento)
                      </h4>
                      {searchResults.activeSpaces.map(space => (
                        <button
                          key={space.id}
                          onClick={() => {
                            setShowSearchResults(false);
                            navigate(`/espaco?search=${space.vehicle?.plate || space.name}`);
                          }}
                          className="w-full text-left px-3 py-2 rounded-lg hover:bg-accent transition-colors flex items-center gap-3"
                        >
                          <div className="w-8 h-8 rounded-lg bg-info/20 flex items-center justify-center shrink-0">
                            <Car className="w-4 h-4 text-info" />
                          </div>
                          <div className="truncate">
                            <p className="text-sm font-semibold">
                              {space.vehicle ? `${space.vehicle.brand} ${space.vehicle.model}` : space.name}
                              {space.vehicle?.plate && <span className="ml-2 text-xs bg-muted px-1.5 py-0.5 rounded text-muted-foreground font-mono">{space.vehicle.plate}</span>}
                            </p>
                            <p className="text-xs text-muted-foreground truncate">
                              Cliente: {space.client?.name || "Sem Nome"}
                            </p>
                          </div>
                        </button>
                      ))}
                    </div>
                  )}

                  {/* Category: Clientes */}
                  {searchResults.clients.length > 0 && (
                    <div className="space-y-1">
                      <h4 className="text-[10px] uppercase font-bold text-muted-foreground px-3 py-1 tracking-wider">
                        Clientes
                      </h4>
                      {searchResults.clients.map(client => (
                        <button
                          key={client.id}
                          onClick={() => {
                            setShowSearchResults(false);
                            navigate(`/clientes?search=${client.name}`);
                          }}
                          className="w-full text-left px-3 py-2 rounded-lg hover:bg-accent transition-colors flex items-center gap-3"
                        >
                          <div className="w-8 h-8 rounded-lg bg-primary/20 flex items-center justify-center shrink-0">
                            <User className="w-4 h-4 text-primary" />
                          </div>
                          <div className="truncate">
                            <p className="text-sm font-semibold">{client.name}</p>
                            <p className="text-xs text-muted-foreground truncate">
                              WhatsApp: {client.phone}
                            </p>
                          </div>
                        </button>
                      ))}
                    </div>
                  )}

                  {/* Category: Veículos */}
                  {searchResults.vehicles.length > 0 && (
                    <div className="space-y-1">
                      <h4 className="text-[10px] uppercase font-bold text-muted-foreground px-3 py-1 tracking-wider">
                        Veículos Cadastrados
                      </h4>
                      {searchResults.vehicles.map(vehicle => (
                        <button
                          key={vehicle.id}
                          onClick={() => {
                            setShowSearchResults(false);
                            navigate(`/clientes?search=${vehicle.plate || vehicle.model}`);
                          }}
                          className="w-full text-left px-3 py-2 rounded-lg hover:bg-accent transition-colors flex items-center gap-3"
                        >
                          <div className="w-8 h-8 rounded-lg bg-success/20 flex items-center justify-center shrink-0">
                            <Car className="w-4 h-4 text-success" />
                          </div>
                          <div className="truncate">
                            <p className="text-sm font-semibold">
                              {vehicle.brand} {vehicle.model}
                              {vehicle.plate && <span className="ml-2 text-xs bg-muted px-1.5 py-0.5 rounded text-muted-foreground font-mono">{vehicle.plate}</span>}
                            </p>
                            <p className="text-xs text-muted-foreground truncate">
                              Proprietário: {vehicle.client?.name || "Sem Proprietário"}
                            </p>
                          </div>
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Quick Actions */}
      <div className="animate-fade-in" style={{ animationDelay: '0.2s' }}>
        <QuickActions
          onNewSlot={() => setShowFillSlotModal(true)}
          onNewClient={() => setShowNewClientModal(true)}
        />
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 animate-fade-in" style={{ animationDelay: '0.3s' }}>
        {loading ? (
          <>
            <Skeleton className="h-32" />
            <Skeleton className="h-32" />
            <Skeleton className="h-32" />
          </>
        ) : (
          <>
            <StatsCard
              title="Faturamento do Mês"
              value={`R$ ${stats.totalSales.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`}
              subtitle={`${stats.salesCount} vendas realizadas`}
              icon={<DollarSign className="w-5 h-5" />}
              variant="success"
              trend={{ value: 0, isPositive: true }}
            />
            <StatsCard
              title="Ticket Médio"
              value={`R$ ${stats.averageTicket.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`}
              subtitle="Valor médio por venda"
              icon={<TrendingUp className="w-5 h-5" />}
              variant="info"
            />
            <StatsCard
              title="Novos Clientes"
              value={stats.newClients}
              subtitle="Este mês"
              icon={<Users className="w-5 h-5" />}
              variant="warning"
            />

          </>
        )}
      </div>

      {/* Main Widgets Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-fade-in" style={{ animationDelay: '0.4s' }}>
        {/* Sales Chart - Takes 2 columns */}
        <div className="lg:col-span-2">
          <SalesChart />
        </div>

        {/* Financial Summary - Only for ADMIN */}
        {user?.role === 'ADMIN' && <FinancialSummary />}
      </div>

      {/* Secondary Widgets */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-fade-in" style={{ animationDelay: '0.5s' }}>
        <CapacityWidget />

        {/* Goal Progress */}
        <div className="rounded-xl border border-border bg-card p-5">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-sm font-medium text-muted-foreground">
              Meta do Mês
            </h3>
            {!isEditingGoal && (
              <Button
                variant="ghost"
                size="sm"
                className="h-8 w-8 p-0"
                onClick={() => {
                  setEditingGoalValue(stats.monthlyGoal);
                  setIsEditingGoal(true);
                }}
              >
                <Settings className="h-4 w-4 text-muted-foreground hover:text-foreground transition-colors" />
              </Button>
            )}
          </div>

          {loading ? (
            <Skeleton className="h-24" />
          ) : isEditingGoal ? (
            <div className="space-y-4">
              <div className="space-y-2">
                <label className="text-xs text-muted-foreground">Novo valor da meta (R$)</label>
                <Input
                  type="number"
                  value={editingGoalValue || ''}
                  onChange={(e) => setEditingGoalValue(Number(e.target.value))}
                  placeholder="Ex: 50000"
                />
              </div>
              <div className="flex gap-2">
                <Button
                  size="sm"
                  className="flex-1"
                  onClick={handleSaveGoal}
                  disabled={isSavingGoal}
                >
                  <Save className="h-4 w-4 mr-2" />
                  Salvar
                </Button>
                <Button
                  size="sm"
                  variant="outline"
                  className="w-10 p-0"
                  onClick={() => setIsEditingGoal(false)}
                  disabled={isSavingGoal}
                >
                  <X className="h-4 w-4" />
                </Button>
              </div>
            </div>
          ) : (
            <>
              <div className="flex items-baseline gap-2 mb-4">
                <span className="text-3xl font-bold text-primary">
                  {stats.monthlyGoal > 0 ? Math.round((stats.monthlyProgress / stats.monthlyGoal) * 100) : 0}%
                </span>
                <span className="text-sm text-muted-foreground">atingido</span>
              </div>
              <div className="h-3 bg-muted rounded-full overflow-hidden mb-4">
                <div
                  className="h-full bg-gradient-to-r from-primary to-success rounded-full transition-all duration-500 animate-glow"
                  style={{ width: `${Math.min((stats.monthlyProgress / stats.monthlyGoal) * 100, 100)}%` }}
                />
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">
                  R$ {stats.monthlyProgress.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                </span>
                <span className="font-medium">
                  R$ {stats.monthlyGoal.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                </span>
              </div>
            </>
          )}
        </div>
      </div>

      {/* Top Clients */}
      <div className="animate-fade-in" style={{ animationDelay: '0.6s' }}>
        <TopClientsRanking />
      </div>

      {/* Modals */}
      <FillSlotModal
        open={showFillSlotModal}
        onOpenChange={setShowFillSlotModal}
        onSlotFilled={() => setShowFillSlotModal(false)}
      />
      <NewClientModal
        open={showNewClientModal}
        onOpenChange={setShowNewClientModal}
        onClientCreated={() => setShowNewClientModal(false)}
      />
    </div>
  );
};

export default Dashboard;

import { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { Eye, EyeOff, Loader2, Lock, CheckCircle, AlertTriangle } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { useToast } from '@/hooks/use-toast';
import { supabase } from '@/integrations/supabase/client';
import { checkPwnedPassword } from '@/lib/passwordSecurity';
import wfeLogo from '@/assets/wfe-logo.png';
const ResetPassword = () => {
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isCheckingSession, setIsCheckingSession] = useState(true);
  const [hasValidSession, setHasValidSession] = useState(false);
  const [passwordChanged, setPasswordChanged] = useState(false);
  const navigate = useNavigate();
  const {
    toast
  } = useToast();
  useEffect(() => {
    const handleRecovery = async () => {
      // Parse hash fragment (Supabase sends tokens in the URL hash)
      const hash = window.location.hash.substring(1);
      const params = new URLSearchParams(hash);
      const accessToken = params.get('access_token');
      const refreshToken = params.get('refresh_token');
      const tokenHash = params.get('token_hash');
      const type = params.get('type');
      const error = params.get('error');
      const errorDescription = params.get('error_description');

      // Handle error from Supabase
      if (error) {
        console.error('Recovery error:', errorDescription);
        toast({
          title: "Link inválido",
          description: errorDescription || "O link de recuperação é inválido ou expirou.",
          variant: "destructive"
        });
        setIsCheckingSession(false);
        return;
      }

      // Method 1: Verify with token_hash (newer Supabase versions)
      if (tokenHash && type === 'recovery') {
        try {
          const {
            data,
            error: verifyError
          } = await supabase.auth.verifyOtp({
            token_hash: tokenHash,
            type: 'recovery'
          });
          if (verifyError) throw verifyError;
          if (data.session) {
            setHasValidSession(true);
            // Clean URL for security
            window.history.replaceState(null, '', window.location.pathname);
          }
        } catch (err: any) {
          console.error('Token verification failed:', err);
          toast({
            title: "Link expirado ou inválido",
            description: "Por favor, solicite um novo link de recuperação.",
            variant: "destructive"
          });
        }
        setIsCheckingSession(false);
        return;
      }

      // Method 2: Set session with access_token (PKCE flow)
      if (accessToken) {
        try {
          const {
            data,
            error: sessionError
          } = await supabase.auth.setSession({
            access_token: accessToken,
            refresh_token: refreshToken || ''
          });
          if (sessionError) throw sessionError;
          if (data.session) {
            setHasValidSession(true);
            // Clean URL for security
            window.history.replaceState(null, '', window.location.pathname);
          }
        } catch (err: any) {
          console.error('Session setup failed:', err);
          toast({
            title: "Link expirado ou inválido",
            description: "Por favor, solicite um novo link de recuperação.",
            variant: "destructive"
          });
        }
        setIsCheckingSession(false);
        return;
      }

      // Method 3: Check existing session (user already authenticated)
      const {
        data: {
          session
        }
      } = await supabase.auth.getSession();
      if (session) {
        setHasValidSession(true);
      } else {
        toast({
          title: "Link inválido ou expirado",
          description: "Solicite um novo link de recuperação de senha.",
          variant: "destructive"
        });
      }
      setIsCheckingSession(false);
    };

    // Listen for PASSWORD_RECOVERY event
    const {
      data: {
        subscription
      }
    } = supabase.auth.onAuthStateChange((event, session) => {
      if (event === 'PASSWORD_RECOVERY' && session) {
        setHasValidSession(true);
        setIsCheckingSession(false);
      }
    });
    handleRecovery();
    return () => subscription.unsubscribe();
  }, [toast]);
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newPassword || !confirmPassword) {
      toast({
        title: "Campos obrigatórios",
        description: "Preencha todos os campos para continuar.",
        variant: "destructive"
      });
      return;
    }
    if (newPassword.length < 8) {
      toast({
        title: "Senha muito curta",
        description: "A senha deve ter no mínimo 8 caracteres.",
        variant: "destructive"
      });
      return;
    }
    if (newPassword !== confirmPassword) {
      toast({
        title: "Senhas não conferem",
        description: "A nova senha e a confirmação devem ser iguais.",
        variant: "destructive"
      });
      return;
    }
    setIsLoading(true);
    try {
      // Check if password has been pwned
      const pwnedResult = await checkPwnedPassword(newPassword);
      if (pwnedResult.isPwned) {
        toast({
          title: "Senha comprometida",
          description: `Esta senha foi exposta em ${pwnedResult.count.toLocaleString()} vazamentos de dados. Por favor, escolha outra senha.`,
          variant: "destructive"
        });
        setIsLoading(false);
        return;
      }

      // Update password
      const {
        error
      } = await supabase.auth.updateUser({
        password: newPassword
      });
      if (error) {
        throw error;
      }
      setPasswordChanged(true);
      toast({
        title: "Senha alterada!",
        description: "Sua senha foi redefinida com sucesso."
      });

      // Redirect to login after 3 seconds
      setTimeout(() => {
        navigate('/login');
      }, 3000);
    } catch (error: any) {
      console.error('Error updating password:', error);
      toast({
        title: "Erro ao alterar senha",
        description: error.message || "Tente novamente mais tarde.",
        variant: "destructive"
      });
    } finally {
      setIsLoading(false);
    }
  };
  if (isCheckingSession) {
    return <div className="min-h-screen flex items-center justify-center bg-background">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>;
  }
  return <div className="min-h-screen flex items-center justify-center bg-background px-4">
      <div className="w-full max-w-md space-y-8">
        {/* Logo */}
        <div className="flex flex-col items-center">
          <div className="flex items-center gap-3 mb-8">
            <Link to="/login">
              <img src={wfeLogo} alt="WFE Evolution" className="h-12 w-auto object-contain cursor-pointer" />
            </Link>
            
          </div>
        </div>

        <Card className="border-border/50 shadow-lg">
          <CardHeader className="text-center">
            <CardTitle className="text-2xl">
              {passwordChanged ? "Senha Redefinida!" : "Redefinir Senha"}
            </CardTitle>
            <CardDescription>
              {passwordChanged ? "Sua senha foi alterada com sucesso. Você será redirecionado para o login." : "Crie uma nova senha segura para sua conta."}
            </CardDescription>
          </CardHeader>

          <CardContent>
            {!hasValidSession ? <div className="space-y-6">
                <div className="flex justify-center">
                  <div className="p-4 rounded-full bg-destructive/20">
                    <AlertTriangle className="h-12 w-12 text-destructive" />
                  </div>
                </div>
                <p className="text-center text-muted-foreground">
                  O link de recuperação é inválido ou expirou.
                </p>
                <Button onClick={() => navigate('/esqueci-senha')} className="w-full">
                  Solicitar novo link
                </Button>
              </div> : passwordChanged ? <div className="space-y-6">
                <div className="flex justify-center">
                  <div className="p-4 rounded-full bg-success/20">
                    <CheckCircle className="h-12 w-12 text-success" />
                  </div>
                </div>
                <div className="flex items-center justify-center gap-2 text-muted-foreground">
                  <Loader2 className="h-4 w-4 animate-spin" />
                  <span>Redirecionando para o login...</span>
                </div>
              </div> : <form onSubmit={handleSubmit} className="space-y-6">
                <div className="space-y-2">
                  <Label htmlFor="newPassword">Nova Senha</Label>
                  <div className="relative">
                    <Lock className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <Input id="newPassword" type={showPassword ? "text" : "password"} placeholder="Mínimo 8 caracteres" className="pl-10 pr-10" value={newPassword} onChange={e => setNewPassword(e.target.value)} disabled={isLoading} />
                    <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground">
                      {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                    </button>
                  </div>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="confirmPassword">Confirmar Nova Senha</Label>
                  <div className="relative">
                    <Lock className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <Input id="confirmPassword" type={showConfirmPassword ? "text" : "password"} placeholder="Digite novamente" className="pl-10 pr-10" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} disabled={isLoading} />
                    <button type="button" onClick={() => setShowConfirmPassword(!showConfirmPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground">
                      {showConfirmPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                    </button>
                  </div>
                </div>

                <Button type="submit" className="w-full" disabled={isLoading}>
                  {isLoading ? <>
                      <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                      Salvando...
                    </> : 'Salvar nova senha'}
                </Button>
              </form>}
          </CardContent>
        </Card>
      </div>
    </div>;
};
export default ResetPassword;

import { useState, useRef } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Checkbox } from '@/components/ui/checkbox';
import { useToast } from '@/hooks/use-toast';
import { Loader2, Plane, Eye, EyeOff, ShieldCheck } from 'lucide-react';
import jetFighter from '@/assets/jet-fighter.jpg';
import PhoneInputWithDDI from '@/components/ui/PhoneInputWithDDI';
import { supabase } from '@/integrations/supabase/client';
import HCaptcha from '@hcaptcha/react-hcaptcha';

export default function SignUp() {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isCheckingPassword, setIsCheckingPassword] = useState(false);
  const [acceptedTerms, setAcceptedTerms] = useState(false);
  const { signUp } = useAuth();
  const navigate = useNavigate();
  const { toast } = useToast();
  const [captchaToken, setCaptchaToken] = useState<string | null>(null);
  const captchaRef = useRef<HCaptcha>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (password !== confirmPassword) {
      toast({
        title: 'Erro',
        description: 'As senhas não coincidem',
        variant: 'destructive',
      });
      return;
    }

    if (!acceptedTerms) {
      toast({
        title: 'Termos obrigatórios',
        description: 'Você precisa aceitar os Termos de Uso e a Política de Privacidade para criar sua conta.',
        variant: 'destructive',
      });
      return;
    }

    setIsLoading(true);
    setIsCheckingPassword(true);
    
    const { error, isPwnedPassword } = await signUp(email, password, name, phone, captchaToken);
    
    setIsCheckingPassword(false);
    
    if (error) {
      captchaRef.current?.resetCaptcha();
      setCaptchaToken(null);
      toast({
        title: isPwnedPassword ? 'Senha comprometida' : 'Erro ao criar conta',
        description: error.message,
        variant: 'destructive',
      });
      setIsLoading(false);
      return;
    }

    // Save terms acceptance
    try {
      const { data: { user: newUser } } = await supabase.auth.getUser();
      if (newUser) {
        await supabase.from('terms_acceptances' as any).insert({
          user_id: newUser.id,
          user_email: email,
          user_name: name,
          terms_version: '1.0',
        });
      }
    } catch (err) {
      console.error('Error saving terms acceptance:', err);
    }

    toast({
      title: 'Conta criada!',
      description: 'Escolha o plano ideal para você.',
    });
    
    navigate('/planos');
  };

  return (
    <div className="min-h-screen flex">
      {/* Left side - Form */}
      <div className="flex-1 flex items-center justify-center p-8 bg-background">
        <Card className="w-full max-w-md border-0 shadow-none">
          <CardHeader className="space-y-1 text-center">
            <div className="flex justify-center mb-4">
              <div className="w-16 h-16 rounded-xl bg-primary flex items-center justify-center">
                <Plane className="w-9 h-9 text-primary-foreground" />
              </div>
            </div>
            <CardTitle className="text-2xl font-bold">Criar conta</CardTitle>
            <CardDescription>
              Preencha os dados abaixo para começar
            </CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="name">Nome completo</Label>
                <Input
                  id="name"
                  type="text"
                  placeholder="Seu nome completo"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  required
                  minLength={2}
                  maxLength={100}
                />
              </div>
              
              <div className="space-y-2">
                <Label htmlFor="email">Email</Label>
                <Input
                  id="email"
                  type="email"
                  placeholder="seu@email.com"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="phone">WhatsApp</Label>
                <PhoneInputWithDDI
                  value={phone}
                  onChange={setPhone}
                />
              </div>
              
              <div className="space-y-2">
                <Label htmlFor="password">Senha</Label>
                <div className="relative">
                  <Input
                    id="password"
                    type={showPassword ? 'text' : 'password'}
                    placeholder="Mínimo 8 caracteres"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    required
                    minLength={8}
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                  >
                    {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                  </button>
                </div>
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <ShieldCheck className="h-3 w-3" />
                  Sua senha será verificada contra vazamentos conhecidos
                </p>
              </div>

              <div className="space-y-2">
                <Label htmlFor="confirmPassword">Confirmar senha</Label>
                <Input
                  id="confirmPassword"
                  type="password"
                  placeholder="Confirme sua senha"
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  required
                />
              </div>

              {/* Terms Acceptance Checkbox */}
              <div className="flex items-start space-x-2 py-2">
                <Checkbox
                  id="terms"
                  checked={acceptedTerms}
                  onCheckedChange={(checked) => setAcceptedTerms(checked === true)}
                  className="mt-0.5"
                />
                <label
                  htmlFor="terms"
                  className="text-sm leading-snug text-muted-foreground cursor-pointer"
                >
                  Li e aceito os{' '}
                  <span className="text-primary underline font-medium">Termos de Uso</span>,{' '}
                  <span className="text-primary underline font-medium">Política de Privacidade</span>{' '}
                  e{' '}
                  <span className="text-primary underline font-medium">Política de Segurança de Dados</span>{' '}
                  da plataforma.
                </label>
              </div>

              {/* hCaptcha Component */}
              <div className="flex justify-center py-2">
                <HCaptcha
                  ref={captchaRef}
                  sitekey="34724568-8f44-4a36-adba-60c843d04452"
                  onVerify={(token) => setCaptchaToken(token)}
                  onExpire={() => setCaptchaToken(null)}
                />
              </div>

              <Button type="submit" className="w-full" disabled={isLoading || !acceptedTerms || !captchaToken}>
                {isLoading ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    {isCheckingPassword ? 'Verificando senha...' : 'Criando conta...'}
                  </>
                ) : (
                  'Criar conta'
                )}
              </Button>

              <p className="text-center text-sm text-muted-foreground">
                Já tem uma conta?{' '}
                <Link to="/login" className="text-primary hover:underline font-medium">
                  Fazer login
                </Link>
              </p>
            </form>
          </CardContent>
        </Card>
      </div>

      {/* Right side - Image */}
      <div className="hidden lg:flex flex-1 relative overflow-hidden">
        <img 
          src={jetFighter} 
          alt="WFE Evolution" 
          className="absolute inset-0 w-full h-full object-cover"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-black/20 to-transparent" />
        <div className="absolute bottom-0 left-0 right-0 p-12">
          <h2 className="text-4xl font-bold text-white mb-4">
            WFE Evolution CRM
          </h2>
          <p className="text-xl text-white/80">
            Sistema completo para gestão de vendas, clientes e produção.
          </p>
        </div>
      </div>
    </div>
  );
}

