          <div className="space-y-4">
            <h3 className="font-medium">Selecione o que deseja incluir:</h3>
            <div className="grid grid-cols-2 gap-2">
              {Object.entries(options).map(([key, value]) => (
                <div key={key} className="flex items-center gap-2">
                  <Checkbox
                    id={key}
                    checked={value}
                    onCheckedChange={() => toggleOption(key as keyof typeof options)}
                  />
                  <Label htmlFor={key} className="text-sm">
                    {OPTIONS_LABELS[key] || key}
                  </Label>
                </div>
              ))}
            </div>
          </div>

          {/* Preview */}
          <div className="flex justify-center">
            <Card
              className={cn(
                previewWidth,
                "p-4 bg-white text-black text-xs font-mono"
              )}
            >
              {/* Logo/Header */}
              {options.companyName && (
                <div className="text-center mb-3">
                  {companyData?.logo_url ? (
                    <img 
                      src={companyData.logo_url} 
                      alt="Logo" 
                      className="max-h-12 max-w-[120px] object-contain mx-auto mb-2"
                    />
                  ) : (
                    <div className="w-12 h-12 bg-gray-200 rounded-full mx-auto mb-2 flex items-center justify-center border border-gray-200">
                      <span className="text-lg font-bold">
                        {companyData?.company_name ? companyData.company_name.substring(0, 2).toUpperCase() : 'EMP'}
                      </span>
                    </div>
                  )}
                  <p className="font-bold">{companyData?.company_name || 'NOME DA EMPRESA'}</p>
                  {options.companyCnpj && companyData?.cnpj && (
                    <p className="text-[10px] text-gray-500">CNPJ: {companyData.cnpj}</p>
                  )}
                </div>
              )}

              <div className="border-t border-dashed border-gray-400 my-2" />

              {/* Date */}
              <p className="text-center text-[10px] text-gray-600 mb-2">
                {format(new Date(sale.sale_date), "dd/MM/yyyy HH:mm")}
              </p>

              {options.saleNumber && (
                <p className="text-center font-bold mb-2">Venda Nº {sale.id}</p>
              )}

              {/* Client */}
              {(options.clientName || options.clientWhatsApp || options.clientCpf || options.clientEmail) && (
                <div className="bg-gray-100 p-2 rounded mb-2">
                  <p className="font-bold text-[10px] text-gray-500 mb-1">
                    INFORMAÇÕES DO CLIENTE
                  </p>
                  {options.clientName && <p>Nome: {client?.name}</p>}
                  {options.clientWhatsApp && <p>Tel: {client?.phone}</p>}
                  {options.clientCpf && clientDetails?.cpf_cnpj && <p>CPF/CNPJ: {clientDetails.cpf_cnpj}</p>}
                  {options.clientEmail && clientDetails?.email && <p>Email: {clientDetails.email}</p>}
                </div>
              )}

              {/* Vehicle */}
              {options.vehicle && vehicle && (
                <div className="bg-gray-100 p-2 rounded mb-2">
                  <p className="font-bold text-[10px] text-gray-500 mb-1">
                    DADOS DO VEÍCULO
                  </p>
                  <p>
                    {vehicle.brand} {vehicle.model}
                  </p>
                  <p>Placa: {vehicle.plate}</p>
                  <p>Ano: {vehicle.year}</p>
                </div>
              )}

              {/* Services */}
              {options.serviceName && formattedServices.length > 0 && (
                <div className="bg-gray-100 p-2 rounded mb-2">
                  <p className="font-bold text-[10px] text-gray-500 mb-1">
                    SERVIÇOS REALIZADOS
                  </p>
                  {formattedServices.map((item, idx) => (
                    <div key={item.id} className="mb-1">
                      <div className="flex justify-between">
                        <span>
                          {idx + 1}. {item.name}
                        </span>
                        {options.servicePrice && (
                          <span>R$ {item.price.toFixed(2)}</span>
                        )}
                      </div>
                      {item.description && (
                        <p className="text-[9px] text-gray-500 pl-3 leading-tight">
                          {item.description}
                        </p>
                      )}
                    </div>
                  ))}
                </div>
              )}

              <div className="border-t border-dashed border-gray-400 my-2" />

              {/* Totals */}
              <div className="bg-gray-100 p-2 rounded">
                <p className="font-bold text-[10px] text-gray-500 mb-1">
                  VALORES FINAIS
                </p>
                {options.subtotal && (
                  <div className="flex justify-between">
                    <span>Subtotal:</span>
                    <span>R$ {sale.subtotal.toFixed(2)}</span>
                  </div>
                )}
                {options.discount && (sale.discount || 0) > 0 && (
                  <div className="flex justify-between text-red-600">
                    <span>Desconto:</span>
                    <span>- R$ {(sale.discount || 0).toFixed(2)}</span>
                  </div>
                )}
                {options.total && (
                  <div className="flex justify-between font-bold pt-1 border-t border-dashed mt-1">
                    <span>TOTAL:</span>
                    <span>R$ {sale.total.toFixed(2)}</span>
                  </div>
                )}
                {options.paymentMethod && (
                  <div className="flex justify-between mt-1">
                    <span>Pagamento:</span>
                    <span>{sale.payment_method || 'Não informado'}</span>
                  </div>
                )}
              </div>

              <div className="border-t border-dashed border-gray-400 my-2" />

              <p className="text-center text-[10px] text-gray-500">
                Obrigado pela preferência!
              </p>
            </Card>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
};

