﻿// @ts-nocheck
import { useState } from "react";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { useAuth } from "@/contexts/AuthContext";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  DollarSign,
  User,
  Phone,
  Car,
  Calendar,
  CreditCard,
  FileText,
  MessageCircle,
  Eye,
  ArrowRightLeft,
  Edit,
  Trash2,
  Settings,
  Layers,
  Percent,
  Shield,
  Banknote,
} from "lucide-react";
import { SaleWithDetails, DetailedServiceItemDB } from "@/types/sales";
import { toast } from "@/hooks/use-toast";
import { getFriendlyErrorMessage } from "@/lib/logger";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import PdfA4Modal from "@/pages/Vendas/components/PdfA4Modal";
import PdfNotinhaModal from "@/pages/Vendas/components/PdfNotinhaModal";
import WhatsAppPreviewModal from "@/pages/Vendas/components/WhatsAppPreviewModal";
import TransferToSpaceModal from "@/pages/Vendas/components/TransferToSpaceModal";
import { ClientProfileModal } from "@/components/clientes/ClientProfileModal";
import EditSaleModal from "@/pages/Vendas/components/EditSaleModal";
import NewSaleModal from "@/pages/Vendas/components/NewSaleModal";
import { FillSlotModal } from "@/shared/components/espaco/FillSlotModal";
import { EditClientModal } from "@/components/clientes/EditClientModal";
import { Loader2 } from "lucide-react";
import { IssueWarrantyModal } from "@/components/garantias/IssueWarrantyModal";
import { calculateCardMachineNetAmount, formatCardMachineRatePercent } from "@/lib/cardMachineFees";

interface SaleDetailsModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  sale: SaleWithDetails | null;
}

const SaleDetailsModal = ({ open, onOpenChange, sale }: SaleDetailsModalProps) => {
  const queryClient = useQueryClient();
  const { user } = useAuth();

  const [isPdfA4Open, setIsPdfA4Open] = useState(false);
  const [isPdfNotinhaOpen, setIsPdfNotinhaOpen] = useState(false);
  const [pdfNotinhaSize, setPdfNotinhaSize] = useState<"80mm" | "58mm">("80mm");
  const [isWhatsAppOpen, setIsWhatsAppOpen] = useState(false);
  const [isTransferOpen, setIsTransferOpen] = useState(false);
  const [isEditSaleOpen, setIsEditSaleOpen] = useState(false);
  const [isIssueWarrantyOpen, setIsIssueWarrantyOpen] = useState(false);

  // Soft Delete and Lixeira states
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [deleteReason, setDeleteReason] = useState("");
  const [isRestoring, setIsRestoring] = useState(false);
  const [isPermanentlyDeleting, setIsPermanentlyDeleting] = useState(false);
  const [isPermanentDeleteDialogOpen, setIsPermanentDeleteDialogOpen] = useState(false);
  const [permanentConfirmText, setPermanentConfirmText] = useState("");

  // Client Profile state
  const [profileLoading, setProfileLoading] = useState(false);
  const [profileClient, setProfileClient] = useState<any>(null);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [showEditClientModal, setShowEditClientModal] = useState(false);
  const [showNewSaleModal, setShowNewSaleModal] = useState(false);
  const [showNewSlotModal, setShowNewSlotModal] = useState(false);
  const [clientToDelete, setClientToDelete] = useState<any>(null);

  const confirmDeleteClient = async () => {
    if (!clientToDelete) return;

    if (clientToDelete.sales_count > 0) {
      toast({
        title: "Erro",
        description: "Cliente possui vendas vinculadas. Não pode ser excluído.",
        variant: "destructive",
      });
      setClientToDelete(null);
      return;
    }

    try {
      const vehicleIds = (clientToDelete.vehicles || []).map((v: any) => v.id);

      // 1. Delete pipeline items and events associated with the client's vehicles
      if (vehicleIds.length > 0) {
        const { data: pipelineItems } = await supabase
          .from("pipeline_items")
          .select("id")
          .in("vehicle_id", vehicleIds);

        const pipelineItemIds = pipelineItems?.map(item => item.id) || [];
        if (pipelineItemIds.length > 0) {
          await supabase.from("whatsapp_messages").delete().in("related_pipeline_item", pipelineItemIds);
          await supabase.from("pipeline_events").delete().in("item_id", pipelineItemIds);
          await supabase.from("pipeline_items").delete().in("id", pipelineItemIds);
        }

        // Delete other operational data associated with the vehicles
        await supabase.from("pipeline_stages").delete().in("vehicle_id", vehicleIds);
        await supabase.from("spaces").delete().in("vehicle_id", vehicleIds);
        await supabase.from("warranties").delete().in("vehicle_id", vehicleIds);
      }

      // 2. Delete pipeline items and events associated directly with the client
      const { data: clientPipelineItems } = await supabase
        .from("pipeline_items")
        .select("id")
        .eq("client_id", clientToDelete.id);

      const clientPipelineItemIds = clientPipelineItems?.map(item => item.id) || [];
      if (clientPipelineItemIds.length > 0) {
        await supabase.from("whatsapp_messages").delete().in("related_pipeline_item", clientPipelineItemIds);
        await supabase.from("pipeline_events").delete().in("item_id", clientPipelineItemIds);
        await supabase.from("pipeline_items").delete().in("id", clientPipelineItemIds);
      }

      // 3. Delete other operational data associated directly with the client_id
      await supabase.from("pipeline_stages").delete().eq("client_id", clientToDelete.id);
      await supabase.from("spaces").delete().eq("client_id", clientToDelete.id);
      await supabase.from("warranties").delete().eq("client_id", clientToDelete.id);

      // 4. Delete associated vehicles
      const { error: vehiclesError } = await supabase
        .from("vehicles")
        .delete()
        .eq("client_id", clientToDelete.id);

      if (vehiclesError) throw vehiclesError;

      // 5. Delete the client
      const { error } = await supabase
        .from("clients")
        .delete()
        .eq("id", clientToDelete.id);

      if (error) throw error;

      toast({
        title: "Sucesso",
        description: `Cliente "${clientToDelete.name}" excluído com sucesso`,
      });
    } catch (error: any) {
      console.error("Error deleting client:", error);
      toast({
        title: "Erro",
        description: `Erro ao excluir cliente: ${error?.message || "Erro desconhecido"}`,
        variant: "destructive",
      });
    } finally {
      setClientToDelete(null);
    }
  };

  // Fetch deleter user profile if sale is deleted
  const { data: deleterProfile } = useQuery({
    queryKey: ['profile-deleter', sale?.deleted_by],
    queryFn: async () => {
      if (!sale?.deleted_by) return null;
      const { data, error } = await supabase
        .from('profiles')
        .select('name')
        .eq('user_id', sale.deleted_by)
        .maybeSingle();
      if (error) {
        console.error('Error fetching deleter profile:', error);
        return null;
      }
      return data;
    },
    enabled: !!sale?.deleted_by && open,
  });

  // Fetch detailed service items
  const { data: detailedItems } = useQuery({
    queryKey: ['sale-detailed-items', sale?.id],
    queryFn: async () => {
      if (!sale?.id) return [];
      const { data, error } = await supabase
        .from('service_items_detailed')
        .select(`
          *,
          product_type:product_types(brand, name, model, category, light_transmission),
          region:vehicle_regions(name, description)
        `)
        .eq('sale_id', sale.id);

      if (error) {
        console.error('Error fetching detailed items:', error);
        return [];
      }
      return (data || []) as DetailedServiceItemDB[];
    },
    enabled: !!sale?.id && open,
  });

  // Fetch commissions
  const { data: commissions } = useQuery({
    queryKey: ['sale-commissions', sale?.id],
    queryFn: async () => {
      if (!sale?.id) return [];
      const { data: commissions, error: error } = await supabase
        .from('sale_commissions')
        .select('id, person_name_snapshot, person_type, percentage_snapshot, commission_amount')
        .eq('sale_id', sale.id);

      if (error) {
        console.error('Error fetching commissions:', error);
        return [];
      }
      return data;
    },
    enabled: !!sale?.id && open,
  });

  // Fetch sale payments with machine info
  const { data: salePayments } = useQuery({
    queryKey: ['sale-payments-details', sale?.id],
    queryFn: async () => {
      if (!sale?.id) return [];
      const { data, error } = await supabase
        .from('sale_payments')
        .select(`
          *,
          card_machines (
            id,
            name,
            is_anticipated,
            debit_rate
          )
        `)
        .eq('sale_id', sale.id);

      if (error) {
        console.error('Error fetching sale payments:', error);
        return [];
      }
      return data || [];
    },
    enabled: !!sale?.id && open,
  });

  // Fetch rates for the used machines
  const machineIds = salePayments?.map((p: any) => p.machine_id).filter(Boolean) || [];
  const { data: machineRates } = useQuery({
    queryKey: ['sale-payments-rates', machineIds],
    queryFn: async () => {
      if (machineIds.length === 0) return [];
      const { data, error } = await supabase
        .from('card_machine_rates')
        .select('machine_id, installments, rate')
        .in('machine_id', machineIds);
      if (error) {
        console.error('Error fetching machine rates:', error);
        return [];
      }
      return data || [];
    },
    enabled: machineIds.length > 0,
  });

  // Fetch linked space (vaga)
  const { data: linkedSpace } = useQuery({
    queryKey: ['sale-linked-space', sale?.id],
    queryFn: async () => {
      if (!sale?.id) return null;
      const { data, error } = await supabase
        .from('spaces')
        .select('id, name')
        .eq('sale_id', sale.id)
        .maybeSingle();

      if (error) {
        console.error('Error fetching linked space:', error);
        return null;
      }
      return data;
    },
    enabled: !!sale?.id && open,
  });

  if (!sale) return null;

  const client = sale.client;
  const vehicle = sale.vehicle;
  const saleItems = sale.sale_items || [];
  const hasDetailedItems = detailedItems && detailedItems.length > 0;

  const handleOpenNotinha = (size: "80mm" | "58mm") => {
    setPdfNotinhaSize(size);
    setIsPdfNotinhaOpen(true);
  };

  // Calculate services total from sale_items (legacy) or detailed items
  const servicesTotal = hasDetailedItems
    ? detailedItems.reduce((sum, item) => sum + item.total_price, 0)
    : saleItems.reduce((sum, item) => sum + item.total_price, 0);

  // Calculate total meters used
  const totalMeters = hasDetailedItems
    ? detailedItems.reduce((sum, item) => sum + item.meters_used, 0)
    : 0;

  const handleOpenClientProfile = async () => {
    if (!client) return;
    setProfileLoading(true);

    try {
      const { data: clientData, error: clientError } = await supabase
        .from("clients")
        .select("id, name, phone, email, cpf_cnpj, birth_date, cep, street, number, complement, neighborhood, city, state, origem, created_at, company_id")
        .eq("id", client.id)
        .single();

      if (clientError) throw clientError;

      const { data: vehiclesData } = await supabase
        .from("vehicles")
        .select("id, brand, model, plate, year, size, client_id, created_at")
        .eq("client_id", client.id);

      const { data: salesData } = await supabase
        .from("sales")
        .select("total")
        .eq("client_id", client.id);

      const totalSpent = (salesData || []).reduce((sum, s) => sum + (s.total || 0), 0);

      const fullClient = {
        ...clientData,
        vehicles: vehiclesData || [],
        total_spent: totalSpent,
        sales_count: (salesData || []).length,
        created_at: clientData?.created_at || new Date().toISOString()
      };

      setProfileClient(fullClient);
      setShowProfileModal(true);
    } catch (error) {
      console.error(error);
      toast({ title: "Erro", description: "Falha ao carregar perfil do cliente", variant: "destructive" });
    } finally {
      setProfileLoading(false);
    }
  };

  const handleDeleteSale = async () => {
    if (!sale) return;
    setIsDeleting(true);
    try {
      const { data, error } = await supabase.rpc('soft_delete_sale', {
        p_sale_id: sale.id,
        p_reason: deleteReason.trim() || "Nenhum motivo informado."
      });

      if (error) throw error;

      toast({
        title: "Venda excluída",
        description: "A venda foi enviada para a lixeira operacional com sucesso.",
      });

      queryClient.invalidateQueries({ queryKey: ['sales'] });
      queryClient.invalidateQueries({ queryKey: ['sales-deleted'] });
      queryClient.invalidateQueries({ queryKey: ['sale-detailed-items'] });
      queryClient.invalidateQueries({ queryKey: ['dashboard-metrics'] });
      queryClient.invalidateQueries({ queryKey: ['transactions'] });

      setIsDeleteDialogOpen(false);
      onOpenChange(false);
      setDeleteReason("");
    } catch (error: any) {
      console.error("Erro ao enviar venda para a lixeira:", error);
      toast({
        title: "Erro ao excluir",
        description: getFriendlyErrorMessage(error, "Ocorreu um erro ao excluir a venda."),
        variant: "destructive",
      });
    } finally {
      setIsDeleting(false);
    }
  };

  const handleRestoreSale = async () => {
    if (!sale) return;
    setIsRestoring(true);
    try {
      const { data, error } = await supabase.rpc('restore_sale', {
        p_sale_id: sale.id
      });

      if (error) throw error;

      toast({
        title: "Venda restaurada",
        description: "A venda foi restaurada e retornou à operação ativa com sucesso.",
      });

      queryClient.invalidateQueries({ queryKey: ['sales'] });
      queryClient.invalidateQueries({ queryKey: ['sales-deleted'] });
      queryClient.invalidateQueries({ queryKey: ['sale-detailed-items'] });
      queryClient.invalidateQueries({ queryKey: ['dashboard-metrics'] });
      queryClient.invalidateQueries({ queryKey: ['transactions'] });

      onOpenChange(false);
    } catch (error: any) {
      console.error("Erro ao restaurar venda:", error);
      toast({
        title: "Erro ao restaurar",
        description: getFriendlyErrorMessage(error, "Ocorreu um erro ao restaurar a venda."),
        variant: "destructive",
      });
    } finally {
      setIsRestoring(false);
    }
  };

  const handlePermanentDeleteSale = async () => {
    if (!sale) return;
    if (permanentConfirmText !== "EXCLUIR") {
      toast({
        title: "Confirmação incorreta",
        description: "Digite exatamente 'EXCLUIR' para confirmar a exclusão.",
        variant: "destructive",
      });
      return;
    }
    setIsPermanentlyDeleting(true);
    try {
      const { data, error } = await supabase.rpc('permanently_delete_sale', {
        p_sale_id: sale.id
      });

      if (error) throw error;

      toast({
        title: "Venda excluída permanentemente",
        description: "A venda foi excluída definitivamente e todos os dados foram apagados fisicamente.",
      });

      queryClient.invalidateQueries({ queryKey: ['sales'] });
      queryClient.invalidateQueries({ queryKey: ['sales-deleted'] });
      queryClient.invalidateQueries({ queryKey: ['sale-detailed-items'] });
      queryClient.invalidateQueries({ queryKey: ['dashboard-metrics'] });
      queryClient.invalidateQueries({ queryKey: ['transactions'] });

      setIsPermanentDeleteDialogOpen(false);
      onOpenChange(false);
      setPermanentConfirmText("");
    } catch (error: any) {
      console.error("Erro na exclusão definitiva:", error);
      toast({
        title: "Erro ao excluir definitivamente",
        description: getFriendlyErrorMessage(error, "Ocorreu um erro ao excluir a venda permanentemente."),
        variant: "destructive",
      });
    } finally {
      setIsPermanentlyDeleting(false);
    }
  };

  return (
    <>
      <Dialog open={open} onOpenChange={onOpenChange}>
        <DialogContent className="max-w-2xl w-[92vw] sm:w-full overflow-x-hidden" confirmClose={false}>
          <DialogHeader>
            <div className="flex items-center gap-3">
              <div className="p-2 rounded-lg bg-success/20">
                <DollarSign className="h-5 w-5 text-success" />
              </div>
              <div className="flex-1">
                <div className="flex items-center gap-2">
                  <DialogTitle>Venda Nº {sale.id}</DialogTitle>
                  <Badge variant={!sale.is_open ? "default" : "outline"}>
                    {sale.is_open ? 'Aberta' : 'Fechada'}
                  </Badge>
                </div>
              </div>
            </div>
          </DialogHeader>

          <div className="space-y-6 py-4">
            {sale.deleted_at && (
              <div className="p-4 rounded-lg bg-destructive/10 border border-destructive/20 text-destructive text-sm flex flex-col gap-2 shadow-sm animate-pulse-subtle">
                <div className="font-bold flex items-center gap-2 text-base">
                  <Trash2 className="h-5 w-5 text-destructive" />
                  Venda Excluída (Lixeira Operacional)
                </div>
                <div className="text-muted-foreground">
                  Esta venda foi movida para a lixeira operacional em{" "}
                  <span className="font-semibold text-destructive">
                    {format(new Date(sale.deleted_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}
                  </span>{" "}
                  por <span className="font-semibold text-destructive">{deleterProfile?.name || "Carregando..."}</span>.
                </div>
                {sale.deleted_reason && (
                  <div className="mt-1 bg-destructive/5 p-3 rounded border border-destructive/10 text-xs text-muted-foreground">
                    <span className="font-semibold block text-destructive mb-1">Motivo da Exclusão:</span>
                    <span className="italic">"{sale.deleted_reason}"</span>
                  </div>
                )}
              </div>
            )}

            {/* Client Section */}
            <div className="space-y-2">
              <h3 className="text-sm font-medium text-muted-foreground">Cliente</h3>
              <div className="flex flex-col sm:flex-row sm:items-center gap-2 sm:gap-4">
                <div className="flex items-center gap-2">
                  <User className="h-4 w-4 text-info" />
                  <span className="font-medium">{client?.name || "Cliente"}</span>
                </div>
                {client?.phone && (
                  <a
                    href={`https://wa.me/${client.phone.replace(/\D/g, "")}`}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="flex items-center gap-2 text-success hover:underline w-fit"
                  >
                    <Phone className="h-4 w-4" />
                    {client.phone}
                  </a>
                )}
              </div>
            </div>

            {/* Vehicle & Services Card */}
            <Card className="p-4 space-y-4">
              {vehicle && (
                <>
                  <div className="flex items-center gap-3">
                    <Car className="h-5 w-5 text-muted-foreground" />
                    <div>
                      <p className="font-medium">
                        {vehicle.brand} {vehicle.model}
                      </p>
                      <p className="text-sm text-muted-foreground">
                        {vehicle.year} • {vehicle.plate}
                        {vehicle.size && (
                          <Badge variant="outline" className="ml-2">
                            {vehicle.size}
                          </Badge>
                        )}
                      </p>
                    </div>
                  </div>
                  <Separator />
                </>
              )}

              {/* Detailed Service Items (new system) */}
              {hasDetailedItems ? (
                <div className="space-y-3">
                  <div className="flex items-center gap-2 text-sm font-medium text-muted-foreground">
                    <Layers className="h-4 w-4" />
                    Serviços Detalhados
                  </div>
                  {/* Tabela para Desktop */}
                  <div className="hidden sm:block w-full overflow-x-auto border rounded-md">
                    <Table className="w-full">
                      <TableHeader>
                        <TableRow>
                          <TableHead>Região</TableHead>
                          <TableHead>Material</TableHead>
                          <TableHead className="text-right">Metros</TableHead>
                          <TableHead className="text-right">R$/m</TableHead>
                          <TableHead className="text-right">Total</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {detailedItems.map((item) => (
                          <TableRow key={item.id} className={(item as any).is_customized ? 'bg-muted/30' : ''}>
                            <TableCell>
                              <div>
                                <span>{(item as any).display_name || item.region?.name || 'Região'}</span>
                                <Badge variant="outline" className="ml-2 text-xs">
                                  {item.category}
                                </Badge>
                                {(item as any).is_customized && (
                                  <Badge variant="secondary" className="ml-1 text-xs">
                                    Personalizado
                                  </Badge>
                                )}
                              </div>
                            </TableCell>
                            <TableCell>
                              {item.product_type
                                ? `${item.product_type.brand} ${item.product_type.name}${item.product_type.light_transmission ? ` ${item.product_type.light_transmission}` : ''}`
                                : 'Material'}
                            </TableCell>
                            <TableCell className="text-right">
                              {item.meters_used.toFixed(2)}m
                            </TableCell>
                            <TableCell className="text-right">
                              R$ {item.unit_price.toFixed(2)}
                            </TableCell>
                            <TableCell className="text-right font-medium">
                              R$ {item.total_price.toFixed(2)}
                            </TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </div>

                  {/* Cards para Mobile */}
                  <div className="block sm:hidden space-y-3">
                    {detailedItems.map((item) => (
                      <div
                        key={item.id}
                        className={`p-3 rounded-lg border text-sm space-y-2 bg-card ${(item as any).is_customized ? 'border-primary/30 bg-primary/5' : 'border-border'
                          }`}
                      >
                        {/* Região e Badges */}
                        <div className="flex flex-wrap items-center gap-1.5 justify-between">
                          <span className="font-semibold text-foreground">
                            {(item as any).display_name || item.region?.name || 'Região'}
                          </span>
                          <div className="flex gap-1">
                            <Badge variant="outline" className="text-[10px] px-1.5 py-0">
                              {item.category}
                            </Badge>
                            {(item as any).is_customized && (
                              <Badge variant="secondary" className="text-[10px] px-1.5 py-0 bg-primary/10 text-primary border-primary/20">
                                Personalizado
                              </Badge>
                            )}
                          </div>
                        </div>

                        {/* Produto */}
                        <div className="text-xs text-muted-foreground bg-muted/30 p-2 rounded">
                          <span className="font-medium text-foreground block mb-0.5 text-[10px] uppercase tracking-wider text-muted-foreground">Material:</span>
                          {item.product_type
                            ? `${item.product_type.brand} ${item.product_type.name}${item.product_type.light_transmission ? ` ${item.product_type.light_transmission}` : ''}`
                            : 'Material'}
                        </div>

                        {/* Métricas */}
                        <div className="grid grid-cols-3 gap-2 pt-2 border-t border-border/40 text-center">
                          <div>
                            <span className="text-[10px] text-muted-foreground block">Metragem</span>
                            <span className="font-medium text-xs">{item.meters_used.toFixed(2)}m</span>
                          </div>
                          <div>
                            <span className="text-[10px] text-muted-foreground block">Valor/m</span>
                            <span className="font-medium text-xs">R$ {item.unit_price.toFixed(2)}</span>
                          </div>
                          <div>
                            <span className="text-[10px] text-muted-foreground block text-success">Total</span>
                            <span className="font-semibold text-xs text-success">R$ {item.total_price.toFixed(2)}</span>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                  <div className="flex justify-between text-sm pt-2">
                    <span className="text-muted-foreground">
                      Total de metros: <span className="font-medium">{totalMeters.toFixed(2)}m</span>
                    </span>
                  </div>
                </div>
              ) : (
                /* Legacy sale items */
                <div className="space-y-2">
                  {saleItems.length > 0 ? (
                    saleItems.map((item) => (
                      <div key={item.id} className="flex justify-between">
                        <span>
                          {item.service?.name || `Serviço #${item.service_id}`}
                          {item.quantity && item.quantity > 1 ? ` (x${item.quantity})` : ''}
                        </span>
                        <span className="font-medium">
                          R$ {item.total_price.toFixed(2)}
                        </span>
                      </div>
                    ))
                  ) : (
                    <p className="text-muted-foreground text-sm">Nenhum serviço registrado</p>
                  )}
                </div>
              )}

              <Separator />

              <div className="flex justify-between font-semibold">
                <span>Total do veículo</span>
                <span className="text-success">
                  R$ {servicesTotal.toFixed(2)}
                </span>
              </div>
            </Card>

            {/* Resumo da Venda Premium list */}
            <Card className="p-5 space-y-4 bg-muted/20 border border-border/60">
              <div>
                <h4 className="font-semibold text-base text-foreground">Resumo da venda</h4>
                <p className="text-xs text-muted-foreground">Informações importantes dessa venda</p>
              </div>

              <div className="space-y-3 text-sm">
                {/* 1. Services count */}
                <div className="flex items-center gap-3">
                  <div className="p-1.5 rounded bg-muted">
                    <Settings className="h-4 w-4 text-muted-foreground" />
                  </div>
                  <span>
                    Venda com <span className="font-semibold text-primary">{hasDetailedItems ? detailedItems.length : saleItems.length} serviço(s)</span>
                  </span>
                </div>

                {/* 2. Sale Date */}
                <div className="flex items-center gap-3">
                  <div className="p-1.5 rounded bg-muted">
                    <Calendar className="h-4 w-4 text-muted-foreground" />
                  </div>
                  <span>
                    Venda do dia <span className="font-semibold text-primary">{format(new Date(sale.sale_date + 'T12:00:00'), "dd/MM/yyyy", { locale: ptBR })}</span>
                  </span>
                </div>

                {/* 3. Subtotal */}
                <div className="flex items-center gap-3">
                  <div className="p-1.5 rounded bg-muted">
                    <Banknote className="h-4 w-4 text-muted-foreground" />
                  </div>
                  <span>
                    Subtotal ficou <span className="font-semibold text-primary">R$ {sale.subtotal.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </span>
                </div>

                {/* 4. Discount */}
                <div className="flex items-center gap-3">
                  <div className="p-1.5 rounded bg-muted">
                    <Percent className="h-4 w-4 text-muted-foreground" />
                  </div>
                  <span>
                    Desconto de <span className="font-semibold text-primary">R$ {(sale.discount || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </span>
                </div>

                {/* 5. Total */}
                <div className="flex items-center gap-3">
                  <div className="p-1.5 rounded bg-muted">
                    <Shield className="h-4 w-4 text-muted-foreground" />
                  </div>
                  <span>
                    Valor total da venda ficou <span className="font-semibold text-primary">R$ {sale.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </span>
                </div>

                {/* 6, 7, 8. Payments (Card Machines details if Crédito/Débito) */}
                {salePayments && salePayments.length > 0 ? (
                  salePayments.map((p: any, index: number) => {
                    const isCard = p.method === "Crédito" || p.method === "Débito";
                    if (!isCard || !p.machine_id) return null;

                    const machine = p.card_machines;
                    const rate = p.method === "Débito"
                      ? machine?.debit_rate || 0
                      : machineRates?.find(r => r.machine_id === p.machine_id && r.installments === p.installments)?.rate || 0;

                    const netAmount = calculateCardMachineNetAmount(p.amount, rate);
                    const isAnticipated = machine?.is_anticipated;

                    const methodLabel = p.method;
                    const installmentsLabel = p.method === "Crédito" ? `${p.installments}x no ` : "no ";
                    const antLabel = ` (${isAnticipated ? "antecipação" : "sem antecipação"})`;

                    return (
                      <div key={p.id || index} className="space-y-3 pt-2 border-t border-dashed border-border">
                        <div className="flex items-center gap-3">
                          <div className="p-1.5 rounded bg-muted">
                            <CreditCard className="h-4 w-4 text-muted-foreground" />
                          </div>
                          <span>
                            Forma de pagamento é <span className="font-semibold text-primary">{installmentsLabel}{methodLabel}{antLabel} (R$ {p.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })})</span>
                          </span>
                        </div>

                        <div className="flex items-center gap-3">
                          <div className="p-1.5 rounded bg-muted">
                            <Percent className="h-4 w-4 text-muted-foreground" />
                          </div>
                          <span>
                            Taxas de maquininhas <span className="font-semibold text-primary">{formatCardMachineRatePercent(rate)}% no {methodLabel}</span>
                          </span>
                        </div>

                        <div className="flex items-center gap-3">
                          <div className="p-1.5 rounded bg-muted">
                            <DollarSign className="h-4 w-4 text-muted-foreground" />
                          </div>
                          <span>
                            Valor total com desconto da maquininha <span className="font-semibold text-primary">R$ {netAmount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                          </span>
                        </div>
                      </div>
                    );
                  })
                ) : (
                  <div className="flex items-center gap-3 pt-2 border-t border-dashed border-border">
                    <div className="p-1.5 rounded bg-muted">
                      <CreditCard className="h-4 w-4 text-muted-foreground" />
                    </div>
                    <span>
                      Forma de pagamento é <span className="font-semibold text-primary">{sale.payment_method || 'Não informado'}</span>
                    </span>
                  </div>
                )}

                {/* 10. Space slot linkage */}
                <div className="flex items-center gap-3 pt-2 border-t border-dashed border-border">
                  <div className="p-1.5 rounded bg-muted">
                    <ArrowRightLeft className="h-4 w-4 text-muted-foreground" />
                  </div>
                  {linkedSpace ? (
                    <span>
                      Vinculado a uma vaga: <Button variant="link" className="p-0 h-auto font-semibold text-primary underline hover:text-primary/80" onClick={() => {
                        setProfileClient(sale.client);
                        setShowNewSlotModal(true);
                      }}>Visualizar vaga ({linkedSpace.name})</Button>
                    </span>
                  ) : (
                    <span>
                      Não vinculado a nenhuma vaga
                    </span>
                  )}
                </div>
              </div>
            </Card>


            {/* Commissions Summary */}
            {commissions && commissions.length > 0 && (
              <div className="space-y-2">
                <h3 className="text-sm font-medium text-muted-foreground flex items-center gap-2">
                  <Percent className="h-4 w-4" /> Comissões
                </h3>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                  {commissions.map((comm) => (
                    <div key={comm.id} className="flex justify-between items-center p-2 rounded border bg-muted/20">
                      <div>
                        <p className="text-sm font-medium">{comm.person_name_snapshot}</p>
                        <p className="text-xs text-muted-foreground">
                          {comm.person_type.replace('_', ' ')} • {comm.percentage_snapshot}%
                        </p>
                      </div>
                      <span className="text-sm font-medium text-success">
                        R$ {Number(comm.commission_amount).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Document Actions */}
            <div className="space-y-2">
              <h3 className="text-sm font-medium text-muted-foreground">
                Central de Documentos
              </h3>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
                <Button
                  variant="outline"
                  className="gap-2 border-primary text-primary hover:bg-primary/10"
                  onClick={() => setIsPdfA4Open(true)}
                >
                  <FileText className="h-4 w-4" />
                  PDF A4
                </Button>
                <Button
                  variant="outline"
                  className="gap-2 border-primary text-primary hover:bg-primary/10"
                  onClick={() => handleOpenNotinha("80mm")}
                >
                  <FileText className="h-4 w-4" />
                  Notinha 80mm
                </Button>
                <Button
                  variant="outline"
                  className="gap-2 border-primary text-primary hover:bg-primary/10"
                  onClick={() => handleOpenNotinha("58mm")}
                >
                  <FileText className="h-4 w-4" />
                  Notinha 58mm
                </Button>
              </div>
            </div>

            {/* CRM Actions */}
            <div className="space-y-2">
              <h3 className="text-sm font-medium text-muted-foreground">
                Ações CRM
              </h3>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
                <Button
                  className="gap-2 bg-success hover:bg-success/90"
                  onClick={() => setIsWhatsAppOpen(true)}
                >
                  <MessageCircle className="h-4 w-4" />
                  WhatsApp
                </Button>
                <Button
                  variant="outline"
                  className="gap-2 border-violet-500 text-violet-500 hover:bg-violet-500/10"
                  onClick={handleOpenClientProfile}
                  disabled={profileLoading}
                >
                  {profileLoading ? (
                    <Loader2 className="h-4 w-4 animate-spin" />
                  ) : (
                    <Eye className="h-4 w-4" />
                  )}
                  Ver cliente
                </Button>
                <Button
                  variant="outline"
                  className="gap-2 border-info text-info hover:bg-info/10"
                  onClick={() => setIsTransferOpen(true)}
                >
                  <ArrowRightLeft className="h-4 w-4" />
                  Enviar p/ Espaço
                </Button>
                <Button
                  variant="outline"
                  className="gap-2 border-amber-500 text-amber-500 hover:bg-amber-500/10"
                  onClick={() => setIsIssueWarrantyOpen(true)}
                >
                  <Shield className="h-4 w-4" />
                  Emitir Garantia
                </Button>
              </div>
            </div>
          </div>

          {/* Footer */}
          <div className="flex gap-2 pt-4 border-t">
            {sale.deleted_at ? (
              <>
                {/* Visualização de Venda na Lixeira */}
                {(user?.role === "ADMIN" || (user?.role === "VENDEDOR" && sale.seller_id === user?.id)) ? (
                  <Button
                    variant="default"
                    className="flex-1 gap-2 bg-success hover:bg-success/90 text-white"
                    onClick={handleRestoreSale}
                    disabled={isRestoring}
                  >
                    {isRestoring ? (
                      <Loader2 className="h-4 w-4 animate-spin" />
                    ) : (
                      <ArrowRightLeft className="h-4 w-4" />
                    )}
                    Restaurar Venda
                  </Button>
                ) : (
                  <div className="flex-1 text-center py-2 text-sm text-muted-foreground italic">
                    Apenas o autor da venda ou um administrador podem restaurar esta venda.
                  </div>
                )}

                {user?.role === "ADMIN" && (
                  <>
                    <Button
                      variant="outline"
                      className="gap-2 border-primary text-primary hover:bg-primary/10"
                      onClick={() => setIsEditSaleOpen(true)}
                    >
                      <Edit className="h-4 w-4" />
                      Editar
                    </Button>
                    <Button
                      variant="destructive"
                      className="flex-1 gap-2"
                      onClick={() => setIsPermanentDeleteDialogOpen(true)}
                    >
                      <Trash2 className="h-4 w-4" />
                      Excluir Permanente
                    </Button>
                  </>
                )}
              </>
            ) : (
              <>
                {/* Visualização de Venda Ativa Normal */}
                <Button variant="default" className="flex-1 gap-2" onClick={() => setIsEditSaleOpen(true)}>
                  <Edit className="h-4 w-4" />
                  Editar
                </Button>
                <Button variant="destructive" className="flex-1 gap-2" onClick={() => setIsDeleteDialogOpen(true)}>
                  <Trash2 className="h-4 w-4" />
                  Excluir
                </Button>
              </>
            )}
          </div>
        </DialogContent>
      </Dialog>

      {/* Diálogo de Soft Delete */}
      <AlertDialog open={isDeleteDialogOpen} onOpenChange={setIsDeleteDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Excluir venda?</AlertDialogTitle>
            <AlertDialogDescription>
              Esta venda será movida para a lixeira operacional e todos os KPIs, gráficos e comissões associados serão suspensos. Você poderá restaurá-la a qualquer momento.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <div className="space-y-2 py-2">
            <label className="text-sm font-medium text-muted-foreground block">
              Motivo da exclusão (opcional):
            </label>
            <Textarea
              placeholder="Digite o motivo pelo qual está excluindo esta venda (ex: cliente desistiu, erro de digitação)..."
              value={deleteReason}
              onChange={(e) => setDeleteReason(e.target.value)}
              className="resize-none h-20"
              maxLength={200}
            />
          </div>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={isDeleting} onClick={() => setDeleteReason("")}>
              Cancelar
            </AlertDialogCancel>
            <AlertDialogAction
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              onClick={(e) => {
                e.preventDefault();
                handleDeleteSale();
              }}
              disabled={isDeleting}
            >
              {isDeleting ? (
                <Loader2 className="h-4 w-4 animate-spin mr-2" />
              ) : null}
              Mover para a Lixeira
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Diálogo de Hard Delete Permanente */}
      <AlertDialog open={isPermanentDeleteDialogOpen} onOpenChange={setIsPermanentDeleteDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle className="text-destructive flex items-center gap-2">
              <Trash2 className="h-5 w-5" />
              Exclusão Permanente e Irreversível!
            </AlertDialogTitle>
            <AlertDialogDescription className="text-foreground font-medium">
              Esta ação apagará fisicamente a venda e todas as dependências do banco de dados para sempre.
              Um snapshot de segurança completo será salvo de forma estruturada nos logs de auditoria.
            </AlertDialogDescription>
            <p className="text-xs text-muted-foreground bg-destructive/10 p-3 rounded border border-destructive/20 mt-2">
              Para confirmar que deseja apagar DEFINITIVAMENTE todos os registros dessa venda, digite <span className="font-bold text-destructive">EXCLUIR</span> no campo abaixo:
            </p>
          </AlertDialogHeader>
          <div className="py-2">
            <Input
              type="text"
              placeholder="Digite EXCLUIR para confirmar"
              value={permanentConfirmText}
              onChange={(e) => setPermanentConfirmText(e.target.value)}
              className="border-destructive focus-visible:ring-destructive"
            />
          </div>
          <AlertDialogFooter>
            <AlertDialogCancel
              disabled={isPermanentlyDeleting}
              onClick={() => setPermanentConfirmText("")}
            >
              Cancelar
            </AlertDialogCancel>
            <AlertDialogAction
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
              onClick={(e) => {
                e.preventDefault();
                handlePermanentDeleteSale();
              }}
              disabled={isPermanentlyDeleting || permanentConfirmText !== "EXCLUIR"}
            >
              {isPermanentlyDeleting ? (
                <Loader2 className="h-4 w-4 animate-spin mr-2" />
              ) : null}
              Excluir Permanentemente
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <PdfA4Modal
        open={isPdfA4Open}
        onOpenChange={setIsPdfA4Open}
        sale={sale}
      />

      <PdfNotinhaModal
        open={isPdfNotinhaOpen}
        onOpenChange={setIsPdfNotinhaOpen}
        sale={sale}
        size={pdfNotinhaSize}
      />

      <WhatsAppPreviewModal
        open={isWhatsAppOpen}
        onOpenChange={setIsWhatsAppOpen}
        sale={sale}
      />

      <TransferToSpaceModal
        open={isTransferOpen}
        onOpenChange={setIsTransferOpen}
        sale={sale}
      />

      {profileClient && (
        <>
          <ClientProfileModal
            open={showProfileModal}
            onOpenChange={(open) => {
              setShowProfileModal(open);
              if (!open) {
                setTimeout(() => setProfileClient(null), 300);
              }
            }}
            client={profileClient}
            onEdit={() => {
              setShowProfileModal(false);
              setShowEditClientModal(true);
            }}
            onCreateSale={() => {
              setShowProfileModal(false);
              setShowNewSaleModal(true);
            }}
            onAddToSpace={() => {
              setShowProfileModal(false);
              setShowNewSlotModal(true);
            }}
            onDelete={(client) => {
              setShowProfileModal(false);
              setClientToDelete(client);
            }}
          />

          <EditClientModal
            open={showEditClientModal}
            onOpenChange={(open) => {
              setShowEditClientModal(open);
              if (!open) {
                setProfileClient(null);
              }
            }}
            client={profileClient}
            onSave={() => {
              setShowEditClientModal(false);
              setProfileClient(null);
              toast({
                title: "Sucesso",
                description: "Cliente atualizado com sucesso!",
              });
              queryClient.invalidateQueries({ queryKey: ['sale-detailed-items'] });
            }}
          />
        </>
      )}

      {/* New Sale Modal */}
      <NewSaleModal
        open={showNewSaleModal}
        onOpenChange={(open) => {
          setShowNewSaleModal(open);
          if (!open) setProfileClient(null);
        }}
        defaultClientId={profileClient?.id}
      />

      {/* New Slot Modal */}
      <FillSlotModal
        open={showNewSlotModal}
        onOpenChange={(open) => {
          setShowNewSlotModal(open);
          if (!open) setProfileClient(null);
        }}
        defaultClientId={profileClient?.id}
      />

      {/* Client Delete Confirmation */}
      <AlertDialog open={!!clientToDelete} onOpenChange={(open) => {
        if (!open) setClientToDelete(null);
      }}>
        <AlertDialogContent className="bg-card border-border">
          <AlertDialogHeader>
            <AlertDialogTitle>Confirmar exclusão</AlertDialogTitle>
            <AlertDialogDescription>
              Tem certeza que deseja excluir o cliente "{clientToDelete?.name}"?
              Esta ação não pode ser desfeita.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel className="border-border">Cancelar</AlertDialogCancel>
            <AlertDialogAction
              onClick={confirmDeleteClient}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              Excluir
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <EditSaleModal
        open={isEditSaleOpen}
        onOpenChange={setIsEditSaleOpen}
        sale={sale}
      />

      <IssueWarrantyModal
        open={isIssueWarrantyOpen}
        onOpenChange={setIsIssueWarrantyOpen}
        preselectedSale={sale}
      />
    </>
  );
};

export default SaleDetailsModal;

﻿import { useState, useEffect } from "react";
import { format, addDays, subDays, isSameDay } from "date-fns";
import { ptBR } from "date-fns/locale";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Card } from "@/components/ui/card";
import {
  ChevronLeft,
  ChevronRight,
  Search,
  BarChart3,
  DollarSign,
  Plus,
} from "lucide-react";
import { SaleWithDetails } from "@/types/sales";
import SalesKPIBar from "@/pages/Vendas/components/SalesKPIBar";
import SaleDetailsModal from "@/pages/Vendas/components/SaleDetailsModal";
import SalesChartsModal from "@/pages/Vendas/components/SalesChartsModal";

interface SalesDayDrawerProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  selectedDate: Date | null;
  allSales: SaleWithDetails[];
  onNewSale?: (date: Date) => void;
}

const SalesDayDrawer = ({ open, onOpenChange, selectedDate, allSales, onNewSale }: SalesDayDrawerProps) => {
  const [currentDate, setCurrentDate] = useState(selectedDate || new Date());
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedSale, setSelectedSale] = useState<SaleWithDetails | null>(null);
  const [isChartsModalOpen, setIsChartsModalOpen] = useState(false);

  // Update current date when selectedDate changes
  useEffect(() => {
    if (selectedDate && !isSameDay(currentDate, selectedDate)) {
      setCurrentDate(selectedDate);
    }
  }, [selectedDate]);

  // Filter sales for the current day
  const daySales = allSales.filter((sale) =>
    isSameDay(new Date(sale.sale_date + 'T12:00:00'), currentDate)
  );

  const filteredSales = daySales.filter((sale) => {
    if (!searchQuery) return true;
    const searchLower = searchQuery.toLowerCase();
    return (
      sale.id.toString().includes(searchLower) ||
      sale.client?.name.toLowerCase().includes(searchLower)
    );
  });

  return (
    <>
      <Sheet open={open} onOpenChange={onOpenChange}>
        <SheetContent side="right" className="w-full sm:max-w-xl overflow-y-auto max-w-[100vw]">
          <SheetHeader className="space-y-4">
            {/* Date Navigation */}
            <div className="flex items-center justify-between px-6 sm:px-0 sm:pr-8">
              <Button
                variant="ghost"
                size="icon"
                onClick={() => setCurrentDate(subDays(currentDate, 1))}
                className="h-8 w-8 shrink-0"
              >
                <ChevronLeft className="h-4 w-4" />
              </Button>
              <SheetTitle className="text-center text-sm sm:text-base font-semibold capitalize max-w-[70%] line-clamp-2">
                {format(currentDate, "EEEE, d 'de' MMMM yyyy", { locale: ptBR })}
              </SheetTitle>
              <Button
                variant="ghost"
                size="icon"
                onClick={() => setCurrentDate(addDays(currentDate, 1))}
                className="h-8 w-8 shrink-0"
              >
                <ChevronRight className="h-4 w-4" />
              </Button>
            </div>

            {/* Search and Charts */}
            <div className="flex gap-2">
              <div className="relative flex-1">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Buscar por venda..."
                  className="pl-9"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
              </div>
              {onNewSale && (
                <Button 
                  className="gap-2 shrink-0 px-3"
                  onClick={() => onNewSale(currentDate)}
                >
                  <Plus className="h-4 w-4" />
                  <span className="hidden sm:inline">Nova venda</span>
                  <span className="sm:hidden">Nova</span>
                </Button>
              )}
              <Button 
                variant="outline" 
                className="gap-2 shrink-0 px-3"
                onClick={() => setIsChartsModalOpen(true)}
              >
                <BarChart3 className="h-4 w-4" />
                <span className="hidden sm:inline">Ver gráficos</span>
                <span className="sm:hidden">Gráficos</span>
              </Button>
            </div>
          </SheetHeader>

          <div className="mt-6 space-y-6">
            {/* KPIs */}
            <SalesKPIBar sales={daySales} className="grid grid-cols-2 sm:grid-cols-3 gap-3" />

            {/* Sales List */}
            <div className="space-y-3">
              <h3 className="font-medium text-sm text-muted-foreground">
                {filteredSales.length} venda{filteredSales.length !== 1 ? "s" : ""} no dia
              </h3>

              {filteredSales.length === 0 ? (
                <Card className="p-8 text-center text-muted-foreground">
                  Nenhuma venda encontrada
                </Card>
              ) : (
                filteredSales.map((sale) => {
                  return (
                    <Card
                      key={sale.id}
                      className="p-4 cursor-pointer hover:bg-muted/50 transition-colors"
                      onClick={() => setSelectedSale(sale)}
                    >
                      <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                          <div className="w-10 h-10 rounded-full bg-success/20 flex items-center justify-center">
                            <DollarSign className="h-5 w-5 text-success" />
                          </div>
                          <div>
                            <p className="font-medium">Venda #{sale.id}</p>
                            <p className="text-sm text-muted-foreground">
                              {sale.client?.name || "Cliente"}
                            </p>
                          </div>
                        </div>
                        <div className="text-right">
                          <p className="font-semibold text-success">
                            R$ {sale.total.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}
                          </p>
                          <Badge
                            variant={!sale.is_open ? "default" : "outline"}
                            className="mt-1"
                          >
                            {sale.is_open ? 'Aberta' : 'Fechada'}
                          </Badge>
                        </div>
                      </div>
                    </Card>
                  );
                })
              )}
            </div>
          </div>
        </SheetContent>
      </Sheet>

      <SaleDetailsModal
        open={!!selectedSale}
        onOpenChange={(open) => !open && setSelectedSale(null)}
        sale={selectedSale}
      />

      <SalesChartsModal
        open={isChartsModalOpen}
        onOpenChange={setIsChartsModalOpen}
        sales={daySales}
      />
    </>
  );
};

export default SalesDayDrawer;

// @ts-nocheck
import { useState, useEffect } from "react";
import { format } from "date-fns";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { ArrowRightLeft, Car, User, DollarSign, Loader2, Wrench } from "lucide-react";
import { Separator } from "@/components/ui/separator";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";

interface SaleData {
  id: number;
  total: number;
  client_id: number;
  vehicle_id?: number;
}

interface TransferToSpaceModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  sale: SaleData | null;
  onTransferComplete?: () => void;
}

interface Vehicle {
  id: number;
  brand: string;
  model: string;
  plate: string | null;
}

interface Client {
  id: number;
  name: string;
}

const TransferToSpaceModal = ({
  open,
  onOpenChange,
  sale,
  onTransferComplete,
}: TransferToSpaceModalProps) => {
  const { toast } = useToast();
  const { user } = useAuth();
  const [isLoading, setIsLoading] = useState(false);
  const [vehicleId, setVehicleId] = useState<string>("");
  const [entryDate, setEntryDate] = useState(format(new Date(), "yyyy-MM-dd"));
  const [entryTime, setEntryTime] = useState(format(new Date(), "HH:mm"));
  const [exitDate, setExitDate] = useState("");
  const [exitTime, setExitTime] = useState("");
  const [paymentStatus, setPaymentStatus] = useState<"paid" | "pending">("pending");
  const [observations, setObservations] = useState("");
  const [client, setClient] = useState<Client | null>(null);
  const [vehicles, setVehicles] = useState<Vehicle[]>([]);
  const [servicesData, setServicesData] = useState<any[]>([]);

  useEffect(() => {
    if (sale?.client_id && open) {
      fetchClientAndVehicles();
    }
  }, [sale?.client_id, open]);

  const fetchClientAndVehicles = async () => {
    if (!sale?.client_id) return;

    const [clientRes, vehiclesRes, detailedItemsRes, saleItemsRes] = await Promise.all([
      supabase.from("clients").select("id, name").eq("id", sale.client_id).single(),
      supabase.from("vehicles").select("id, brand, model, plate").eq("client_id", sale.client_id),
      supabase.from("service_items_detailed").select("*, product_type:product_types(id, name, brand, light_transmission, category), region:vehicle_regions(id, name, region_code)").eq("sale_id", sale.id),
      supabase.from("sale_items").select("*, service:services(name)").eq("sale_id", sale.id)
    ]);

    if (clientRes.data) setClient(clientRes.data);
    
    if (vehiclesRes.data && vehiclesRes.data.length > 0) {
      setVehicles(vehiclesRes.data);
      if (sale.vehicle_id) {
        setVehicleId(sale.vehicle_id.toString());
      } else {
        setVehicleId(vehiclesRes.data[0].id.toString());
      }
    }

    // Build structured services_data from the sale's service items
    const builtServicesData: any[] = [];
    if (detailedItemsRes.data && detailedItemsRes.data.length > 0) {
      for (const item of detailedItemsRes.data) {
        const productName = item.product_type
          ? `${item.product_type.brand || ''} ${item.product_type.name || ''}`.trim()
          : '';
        builtServicesData.push({
          category: item.category || 'INSULFILM',
          regionId: item.region?.id || item.region_id || null,
          regionName: item.region?.name || item.display_name || 'Serviço',
          productTypeId: item.product_type?.id || item.product_type_id || null,
          productTypeName: productName,
          totalPrice: item.total_price || 0,
          metersUsed: item.meters_used || 0,
          serviceName: item.service_name || item.region?.name || 'Serviço',
          regionCode: item.region?.region_code || null,
          displayName: item.display_name || `${item.region?.name || 'Serviço'} • ${productName}`,
          isCustomized: false,
        });
      }
    } else if (saleItemsRes.data && saleItemsRes.data.length > 0) {
      for (const item of saleItemsRes.data) {
        builtServicesData.push({
          category: 'INSULFILM',
          regionId: null,
          regionName: item.service?.name || `Serviço #${item.service_id}`,
          productTypeId: null,
          productTypeName: '',
          totalPrice: item.total_price || 0,
          metersUsed: 0,
          serviceName: item.service?.name || `Serviço #${item.service_id}`,
          regionCode: null,
          displayName: item.service?.name || `Serviço #${item.service_id}`,
          isCustomized: false,
        });
      }
    }

    setServicesData(builtServicesData);
  };

  if (!sale) return null;

  const selectedVehicle = vehicles.find(v => v.id === Number(vehicleId));

  const handleTransfer = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!vehicleId) {
      toast({
        title: "Selecione um veículo",
        variant: "destructive",
      });
      return;
    }

    if (!user?.companyId) {
      toast({
        title: "Erro: empresa não encontrada",
        variant: "destructive",
      });
      return;
    }

    setIsLoading(true);

    try {
      // Insert the space
      const { data: spaceData, error } = await supabase.from("spaces").insert({
        company_id: user.companyId,
        name: `Vaga - ${client?.name || 'Cliente'}`,
        client_id: sale.client_id,
        vehicle_id: Number(vehicleId),
        sale_id: sale.id,
        status: "ocupado",
        tag: "Em andamento",
        entry_date: entryDate,
        entry_time: entryTime,
        exit_date: exitDate || null,
        exit_time: exitTime || null,
        payment_status: paymentStatus,
        has_exited: !!exitDate,
        observations: observations || null,
      }).select().single();

      if (error) throw error;

      // Save services as services_data JSONB
      if (servicesData.length > 0 && spaceData) {
        await supabase
          .from("spaces")
          .update({ services_data: servicesData } as any)
          .eq("id", spaceData.id);
      }

      toast({
        title: "Venda transferida para Espaço!",
        description: `Vaga criada para ${client?.name}`,
      });

      onOpenChange(false);
      onTransferComplete?.();
      resetForm();
    } catch (error) {
      console.error("Erro ao transferir:", error);
      toast({
        title: "Erro ao transferir venda",
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const resetForm = () => {
    setVehicleId("");
    setEntryDate(format(new Date(), "yyyy-MM-dd"));
    setEntryTime(format(new Date(), "HH:mm"));
    setExitDate("");
    setExitTime("");
    setPaymentStatus("pending");
    setObservations("");
    setServicesData([]);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-md max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <div className="flex items-center gap-3">
            <div className="p-2 rounded-lg bg-info/20">
              <ArrowRightLeft className="h-5 w-5 text-info" />
            </div>
            <div>
              <DialogTitle>Transferir para Espaço</DialogTitle>
              <DialogDescription>
                Vincular esta venda a uma ocupação de vaga
              </DialogDescription>
            </div>
          </div>
        </DialogHeader>

        {/* Resumo da Venda */}
        <div className="bg-muted/50 rounded-lg p-3 space-y-2">
          <div className="flex items-center gap-2">
            <DollarSign className="h-4 w-4 text-success" />
            <span className="text-sm font-medium">Venda #{sale.id}</span>
            <span className="text-sm text-success ml-auto">
              R$ {sale.total.toFixed(2)}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <User className="h-4 w-4 text-muted-foreground" />
            <span className="text-sm">{client?.name || 'Carregando...'}</span>
          </div>
          {selectedVehicle && (
            <div className="flex items-center gap-2">
              <Car className="h-4 w-4 text-muted-foreground" />
              <span className="text-sm">
                {selectedVehicle.brand} {selectedVehicle.model} - {selectedVehicle.plate}
              </span>
            </div>
          )}
        </div>

        {/* Card visual dos serviços da venda */}
        {servicesData.length > 0 && (
          <div className="rounded-lg border border-border/50 bg-muted/30 overflow-hidden">
            <div className="flex items-center gap-2 px-3 py-2 bg-muted/50 border-b border-border/50">
              <Wrench className="h-4 w-4 text-primary" />
              <span className="text-xs font-medium text-muted-foreground uppercase tracking-wider">
                Serviços da Venda ({servicesData.length})
              </span>
            </div>
            <div className="p-3 space-y-2">
              {servicesData.map((service: any, index: number) => (
                <div key={index} className="flex items-center justify-between text-sm">
                  <span className="text-muted-foreground truncate mr-2">
                    {service.displayName || service.regionName || 'Serviço'}
                  </span>
                  <span className="font-medium text-foreground whitespace-nowrap">
                    R$ {(service.totalPrice || 0).toFixed(2)}
                  </span>
                </div>
              ))}
              <Separator className="my-1" />
              <div className="flex items-center justify-between text-sm font-semibold">
                <span>Total em serviços</span>
                <span className="text-success">
                  R$ {servicesData.reduce((sum: number, s: any) => sum + (s.totalPrice || 0), 0).toFixed(2)}
                </span>
              </div>
            </div>
          </div>
        )}

        <form onSubmit={handleTransfer} className="space-y-4">
          {/* Seleção de Veículo */}
          <div className="space-y-2">
            <Label htmlFor="vehicle">Veículo *</Label>
            {vehicles.length > 0 ? (
              <Select key={vehicleId} value={vehicleId} onValueChange={setVehicleId}>
                <SelectTrigger>
                  <SelectValue placeholder="Selecione um veículo" />
                </SelectTrigger>
                <SelectContent>
                  {vehicles.map((v) => (
                    <SelectItem key={v.id} value={v.id.toString()}>
                      {v.brand} {v.model} - {v.plate || 'Sem placa'}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            ) : (
              <div className="text-sm p-2 border rounded text-muted-foreground flex items-center justify-between">
                <span>Nenhum veículo disponível</span>
                {isLoading && <Loader2 className="h-4 w-4 animate-spin" />}
              </div>
            )}
          </div>

          {/* Data e Hora de Entrada */}
          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-2">
              <Label htmlFor="entryDate">Data Entrada *</Label>
              <Input
                id="entryDate"
                type="date"
                value={entryDate}
                onChange={(e) => setEntryDate(e.target.value)}
                required
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="entryTime">Hora Entrada *</Label>
              <Input
                id="entryTime"
                type="time"
                value={entryTime}
                onChange={(e) => setEntryTime(e.target.value)}
                required
              />
            </div>
          </div>

          {/* Data e Hora de Saída (Opcional) */}
          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-2">
              <Label htmlFor="exitDate">Data Saída (opcional)</Label>
              <Input
                id="exitDate"
                type="date"
                value={exitDate}
                onChange={(e) => setExitDate(e.target.value)}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="exitTime">Hora Saída (opcional)</Label>
              <Input
                id="exitTime"
                type="time"
                value={exitTime}
                onChange={(e) => setExitTime(e.target.value)}
              />
            </div>
          </div>

          {/* Status do Pagamento */}
          <div className="space-y-2">
            <Label>Status do Pagamento *</Label>
            <RadioGroup
              value={paymentStatus}
              onValueChange={(value) => setPaymentStatus(value as "paid" | "pending")}
              className="flex gap-4"
            >
              <div className="flex items-center space-x-2">
                <RadioGroupItem value="paid" id="paid" />
                <Label htmlFor="paid" className="text-sm cursor-pointer">
                  Já pago
                </Label>
              </div>
              <div className="flex items-center space-x-2">
                <RadioGroupItem value="pending" id="pending" />
                <Label htmlFor="pending" className="text-sm cursor-pointer">
                  Ainda não pago
                </Label>
              </div>
            </RadioGroup>
          </div>

          {/* Observações */}
          <div className="space-y-2">
            <Label htmlFor="observations">Observações (opcional)</Label>
            <Textarea
              id="observations"
              value={observations}
              onChange={(e) => setObservations(e.target.value)}
              placeholder="Informações adicionais sobre a vaga..."
              rows={3}
            />
          </div>

          {/* Botões */}
          <div className="flex gap-2 pt-4">
            <Button
              type="submit"
              className="flex-1"
              disabled={isLoading}
            >
              {isLoading ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  Transferindo...
                </>
              ) : (
                <>
                  <ArrowRightLeft className="mr-2 h-4 w-4" />
                  Confirmar Transferência
                </>
              )}
            </Button>
            <Button
              type="button"
              variant="outline"
              onClick={() => onOpenChange(false)}
              disabled={isLoading}
            >
              Cancelar
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
};

export default TransferToSpaceModal;

// @ts-nocheck
import { useState } from "react";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Card } from "@/components/ui/card";
import { MessageCircle, Edit, X, Send, Loader2 } from "lucide-react";
import { SaleWithDetails, DetailedServiceItemDB } from "@/types/sales";
import { toast } from "@/hooks/use-toast";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { cn } from "@/lib/utils";

interface WhatsAppPreviewModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  sale: SaleWithDetails | null;
}

const WhatsAppPreviewModal = ({ open, onOpenChange, sale }: WhatsAppPreviewModalProps) => {
  const [isEditing, setIsEditing] = useState(false);
  const [customMessage, setCustomMessage] = useState("");

  // Fetch detailed service items
  const { data: detailedItems, isLoading: loadingItems } = useQuery({
    queryKey: ['sale-detailed-items', sale?.id],
    queryFn: async () => {
      if (!sale?.id) return [];
      const { data, error } = await supabase
        .from('service_items_detailed')
        .select(`
          *,
          product_type:product_types(brand, name, model, category, light_transmission),
          region:vehicle_regions(name, description)
        `)
        .eq('sale_id', sale.id);
      
      if (error) {
        console.error('Error fetching detailed items:', error);
        return [];
      }
      return (data || []) as DetailedServiceItemDB[];
    },
    enabled: !!sale?.id && open,
  });

  // Fetch sale payments
  const { data: salePayments, isLoading: loadingPayments } = useQuery({
    queryKey: ['sale-payments', sale?.id],
    queryFn: async () => {
      if (!sale?.id) return [];
      const { data, error } = await supabase
        .from('sale_payments')
        .select('*')
        .eq('sale_id', sale.id);
      
      if (error) {
        console.error('Error fetching sale payments:', error);
        return [];
      }
      return data || [];
    },
    enabled: !!sale?.id && open,
  });

  if (!sale) return null;

  const client = sale.client;
  const vehicle = sale.vehicle;
  const saleItems = sale.sale_items || [];
  const isLoading = loadingItems || loadingPayments;

  const companyName = "WFE EVOLUTION";

  // Format detailed services list
  const servicesListString = detailedItems && detailedItems.length > 0
    ? detailedItems.map((item, i) => {
        const regionName = item.display_name || item.region?.name || 'Região';
        const categoryBadge = item.category ? ` [${item.category}]` : '';
        return `${i + 1}. ${regionName}${categoryBadge} R$ ${item.total_price.toFixed(2)}`;
      }).join("\n")
    : saleItems.map((item, i) => `${i + 1}. ${item.service?.name || `Serviço #${item.service_id}`} - R$ ${item.total_price.toFixed(2)}`).join("\n");

  // Format payments information
  let paymentInfo = "";
  if (sale.is_open) {
    paymentInfo = "*Forma de Pagamento:* Em aberto (a receber)";
  } else if (salePayments && salePayments.length > 0) {
    if (salePayments.length === 1) {
      const p = salePayments[0];
      paymentInfo = `*Forma de Pagamento:* ${p.method}${p.installments > 1 ? ` (${p.installments}x)` : ''}`;
    } else {
      paymentInfo = `*Formas de Pagamento:* \n${salePayments.map(p => `• ${p.method}${p.installments > 1 ? ` (${p.installments}x)` : ''}: R$ ${p.amount.toFixed(2)}`).join("\n")}`;
    }
  } else {
    paymentInfo = `*Forma de Pagamento:* ${sale.payment_method || 'Não informado'}`;
  }

  const defaultMessage = `Olá, ${client?.name}! Muito obrigado pela confiança! 
Segue abaixo o recibo da sua compra na ${companyName}.

🗓️ Data da Venda: ${format(new Date(sale.sale_date), "dd/MM/yyyy", { locale: ptBR })}
_______________________________________

📋 DETALHES DO VEÍCULO:
🚗 Veículo: ${vehicle?.brand || ''} ${vehicle?.model || ''}
🏷️ Placa: ${vehicle?.plate || 'N/A'}${vehicle?.year ? `\n📅 Ano: ${vehicle.year}` : ''}${vehicle?.size ? `\n📏 Porte: ${vehicle.size}` : ''}

🛠️ LISTA DE SERVIÇOS:
${servicesListString || 'Nenhum serviço registrado'}
_______________________________________

💰 Subtotal: R$ ${sale.subtotal.toFixed(2)}
💸 Desconto: R$ ${(sale.discount || 0).toFixed(2)}
💵 Total: R$ ${sale.total.toFixed(2)}

${paymentInfo}

Obrigado pela preferência! Qualquer dúvida, é só me chamar. Tenha uma ótima semana!`;

  const messageToSend = isEditing && customMessage ? customMessage : defaultMessage;

  const getWhatsAppUrl = () => {
    if (!client?.phone) return "#";
    const phone = client.phone.replace(/\D/g, "");
    const phoneWithCountryCode = phone.startsWith("55") ? phone : `55${phone}`;
    const encodedMessage = encodeURIComponent(messageToSend);
    return `https://wa.me/${phoneWithCountryCode}?text=${encodedMessage}`;
  };

  const handleSend = (e: React.MouseEvent) => {
    if (!client?.phone) {
      e.preventDefault();
      toast({
        title: "Erro!",
        description: "Cliente sem telefone cadastrado.",
        variant: "destructive",
      });
      return;
    }
    toast({
      title: "Abrindo WhatsApp Web!",
      description: "A mensagem será aberta em uma nova aba.",
    });
    onOpenChange(false);
  };

  const handleEdit = () => {
    if (!isEditing) {
      setCustomMessage(defaultMessage);
    }
    setIsEditing(!isEditing);
  };

  const charCount = messageToSend.length;
  const isOverLimit = charCount > 4000;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent hideCloseButton className="max-w-2xl max-h-[90vh] overflow-y-auto" confirmClose={false}>
        <DialogHeader>
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2 rounded-lg bg-success/20">
                <MessageCircle className="h-5 w-5 text-success" />
              </div>
              <DialogTitle>Enviar WhatsApp</DialogTitle>
            </div>
            <div className="flex gap-2">
              <a
                href={isLoading ? "#" : getWhatsAppUrl()}
                target="_blank"
                rel="noopener noreferrer"
                onClick={(e) => {
                  if (isLoading) {
                    e.preventDefault();
                    return;
                  }
                  handleSend(e);
                }}
                className={cn(
                  "inline-flex items-center justify-center gap-2 rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 bg-success text-white hover:bg-success/90 h-10 px-4 py-2",
                  isLoading && "opacity-50 pointer-events-none"
                )}
              >
                <Send className="h-4 w-4" />
                Enviar whatsapp
              </a>
              <Button variant="outline" onClick={handleEdit} className="gap-2" disabled={isLoading}>
                <Edit className="h-4 w-4" />
                {isEditing ? "Cancelar edição" : "Editar mensagem"}
              </Button>
              <Button variant="destructive" onClick={() => onOpenChange(false)}>
                <X className="h-4 w-4" />
              </Button>
            </div>
          </div>
        </DialogHeader>

        <div className="py-4 space-y-4">
          {isLoading ? (
            <div className="flex flex-col items-center justify-center min-h-[300px] gap-3">
              <Loader2 className="w-8 h-8 animate-spin text-success animate-duration-1000" />
              <p className="text-muted-foreground text-sm">Carregando detalhes da venda...</p>
            </div>
          ) : (
            <>
              {/* Warning Banner */}
              <Card className="p-3 bg-primary/20 border-primary">
                <p className="text-sm text-primary-foreground">
                  ⚠️ Caso o tamanho de 4000 caracteres seja excedido, o campo descrição do serviço não aparecerá
                </p>
              </Card>

              {/* Character count */}
              <div className="text-sm text-right">
                <span className={isOverLimit ? "text-destructive" : "text-muted-foreground"}>
                  {charCount} / 4000 caracteres
                </span>
              </div>

              {/* Message Preview/Editor */}
              {isEditing ? (
                <Textarea
                  value={customMessage}
                  onChange={(e) => setCustomMessage(e.target.value)}
                  className="min-h-[400px] font-mono text-sm"
                  maxLength={4000}
                />
              ) : (
                <div
                  className="relative rounded-lg p-4 min-h-[400px]"
                  style={{
                    backgroundImage: `url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23128C7E' fill-opacity='0.1'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E")`,
                    backgroundColor: "#E5DDD5",
                  }}
                >
                  <Card className="bg-[#DCF8C6] p-4 rounded-lg shadow-md max-w-md ml-auto">
                    <pre className="whitespace-pre-wrap text-sm text-gray-800 font-sans">
                      {messageToSend}
                    </pre>
                    <div className="text-right mt-2">
                      <span className="text-[10px] text-gray-500">
                        {format(new Date(), "HH:mm")}
                      </span>
                    </div>
                  </Card>
                </div>
              )}
            </>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
};

export default WhatsAppPreviewModal;

import { useState, useEffect } from "react";
import { format } from "date-fns";
import { Search, Trash2, RefreshCw } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { cn } from "@/lib/utils";
import { SaleWithDetails } from "@/types/sales";
import SaleDetailsModal from "@/pages/Vendas/components/SaleDetailsModal";

export function Lixeira() {
    const { user } = useAuth();
    const [searchTerm, setSearchTerm] = useState("");
    const [deletedSales, setDeletedSales] = useState<SaleWithDetails[]>([]);
    const [deletedLoading, setDeletedLoading] = useState(false);
    const [selectedDetailedSale, setSelectedDetailedSale] = useState<SaleWithDetails | null>(null);

    useEffect(() => {
        fetchDeletedSales();
    }, [user?.id]);

    const fetchDeletedSales = async () => {
        if (!user?.id || !user?.companyId) {
            setDeletedLoading(false);
            return;
        }
        setDeletedLoading(true);
        try {
            let query = supabase
                .from('sales')
                .select(`
          *,
          client:clients(id, name, phone),
          vehicle:vehicles(id, brand, model, year, plate, size),
          sale_items(
            id, service_id, quantity, unit_price, total_price,
            service:services(id, name, base_price)
          )
        `)
                .eq('company_id', user.companyId)
                .not('deleted_at', 'is', null)
                .order('deleted_at', { ascending: false });

            const { data, error } = await query;

            if (!error && data) {
                const transformedSales: SaleWithDetails[] = data.map((sale: any) => ({
                    id: sale.id,
                    client_id: sale.client_id,
                    vehicle_id: sale.vehicle_id,
                    sale_date: sale.sale_date,
                    subtotal: sale.subtotal,
                    discount: sale.discount,
                    total: sale.total,
                    payment_method: sale.payment_method,
                    status: sale.status,
                    is_open: sale.is_open,
                    observations: sale.observations,
                    created_at: sale.created_at,
                    client: sale.client,
                    vehicle: sale.vehicle,
                    sale_items: sale.sale_items || [],
                    deleted_at: sale.deleted_at,
                    deleted_by: sale.deleted_by,
                    deleted_reason: sale.deleted_reason,
                    restored_at: sale.restored_at,
                    restored_by: sale.restored_by
                }));
                setDeletedSales(transformedSales);
            }
        } catch (error) {
            console.error('Error fetching deleted sales:', error);
        } finally {
            setDeletedLoading(false);
        }
    };

    const filteredDeleted = deletedSales.filter((sale) => {
        if (!searchTerm) return true;
        const term = searchTerm.toLowerCase();
        const matchClient = sale.client?.name?.toLowerCase().includes(term);
        const matchId = sale.id.toString() === term;
        const matchVehicle = sale.vehicle?.plate?.toLowerCase().includes(term) ||
            sale.vehicle?.model?.toLowerCase().includes(term);
        return matchClient || matchId || matchVehicle;
    });

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-card p-4 rounded-lg border shadow-sm">
                <div className="space-y-1">
                    <h3 className="text-lg font-bold flex items-center gap-2 text-destructive">
                        <Trash2 className="h-5 w-5" />
                        Lixeira Operacional
                    </h3>
                    <p className="text-xs text-muted-foreground">
                        Exibindo vendas excluídas logicamente. Apenas administradores podem fazer exclusão permanente.
                    </p>
                </div>
                <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-2 w-full sm:w-auto">
                    <div className="relative flex-1 min-w-[200px]">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                        <Input
                            placeholder="Buscar na lixeira..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="pl-10 h-9"
                        />
                    </div>
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={fetchDeletedSales}
                        disabled={deletedLoading}
                        className="gap-2 h-9"
                    >
                        <RefreshCw className={cn("h-4 w-4", deletedLoading && "animate-spin")} />
                        Atualizar
                    </Button>
                </div>
            </div>

            {deletedLoading ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {[1, 2, 3].map((n) => (
                        <Card key={n} className="p-5 space-y-3">
                            <Skeleton className="h-6 w-1/3" />
                            <Skeleton className="h-12 w-full" />
                            <Skeleton className="h-10 w-full" />
                        </Card>
                    ))}
                </div>
            ) : filteredDeleted.length === 0 ? (
                <Card className="flex flex-col items-center justify-center p-8 text-center min-h-[300px] border-dashed">
                    <div className="p-4 rounded-full bg-muted mb-4">
                        <Trash2 className="h-8 w-8 text-muted-foreground" />
                    </div>
                    <h3 className="text-lg font-semibold">Lixeira vazia</h3>
                    <p className="text-sm text-muted-foreground max-w-sm mt-1">
                        Nenhuma venda excluída logicamente foi encontrada para os termos buscados.
                    </p>
                </Card>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {filteredDeleted.map((sale) => (
                        <Card key={sale.id} className="p-5 flex flex-col justify-between border border-destructive/10 hover:border-destructive/20 hover:shadow-md transition-all">
                            <div className="space-y-3">
                                <div className="flex justify-between items-start">
                                    <div className="space-y-1">
                                        <h4 className="font-bold text-base flex items-center gap-1.5">
                                            Venda Nº {sale.id}
                                        </h4>
                                        <span className="text-xs text-muted-foreground block">
                                            Realizada em {format(new Date(sale.sale_date + 'T12:00:00'), "dd/MM/yyyy")}
                                        </span>
                                    </div>
                                    <Badge variant="destructive" className="gap-1 bg-destructive/10 text-destructive border-destructive/20 hover:bg-destructive/10">
                                        <Trash2 className="h-3 w-3" />
                                        Excluída
                                    </Badge>
                                </div>

                                <div className="text-sm space-y-1.5 text-muted-foreground border-t pt-2 mt-2">
                                    <p><strong className="text-foreground font-medium">Cliente:</strong> {sale.client?.name || "Sem Nome"}</p>
                                    {sale.vehicle && (
                                        <p><strong className="text-foreground font-medium">Veículo:</strong> {sale.vehicle.brand} {sale.vehicle.model} ({sale.vehicle.plate || "S/ Placa"})</p>
                                    )}
                                    <p className="text-base font-semibold text-destructive mt-2">
                                        Total: R$ {sale.total.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}
                                    </p>
                                </div>

                                {sale.deleted_at && (
                                    <div className="bg-destructive/5 p-3 rounded border border-destructive/10 text-xs text-muted-foreground space-y-1 mt-3">
                                        <span className="font-semibold text-destructive block">Motivo da exclusão:</span>
                                        <p className="italic">"{sale.deleted_reason || "Nenhum motivo fornecido."}"</p>
                                    </div>
                                )}
                            </div>

                            <Button
                                variant="outline"
                                className="w-full mt-5 gap-2 border-destructive/20 text-destructive hover:bg-destructive/5 hover:text-destructive"
                                onClick={() => setSelectedDetailedSale(sale)}
                            >
                                Visualizar & Gerenciar
                            </Button>
                        </Card>
                    ))}
                </div>
            )}

            <SaleDetailsModal
                open={!!selectedDetailedSale}
                onOpenChange={(open) => {
                    if (!open) {
                        setSelectedDetailedSale(null);
                        fetchDeletedSales();
                    }
                }}
                sale={selectedDetailedSale}
            />
        </div>
    );
}

import { useState, useEffect } from "react";
import {
    format,
    startOfMonth,
    endOfMonth,
    eachDayOfInterval,
    isSameMonth,
    isSameDay,
    addMonths,
    subMonths,
    startOfWeek,
    endOfWeek,
} from "date-fns";
import { ptBR } from "date-fns/locale";
import { ChevronLeft, ChevronRight, Plus, BarChart3, List, Calendar, Search, Loader2, Car, User, DollarSign } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { cn } from "@/lib/utils";
import { BrazilCalendarLegend } from "@/components/calendar/BrazilCalendarLegend";
import SalesKPIBar from "@/pages/Vendas/components/SalesKPIBar";
import NewSaleModal from "@/pages/Vendas/components/NewSaleModal";
import SalesDayDrawer from "@/pages/Vendas/components/SalesDayDrawer";
import SalesChartsModal from "@/pages/Vendas/components/SalesChartsModal";
import SaleDetailsModal from "@/pages/Vendas/components/SaleDetailsModal";
import { SaleWithDetails } from "@/types/sales";
import {
    BRAZIL_CALENDAR_EVENT_STYLES,
    getBrazilCalendarTitle,
    getPrimaryBrazilCalendarEvent,
} from "@/lib/brazilCalendar";

export function Principal() {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [currentDate, setCurrentDate] = useState(new Date());
    const [viewMode, setViewMode] = useState<"calendar" | "list">("calendar");
    const [isNewSaleModalOpen, setIsNewSaleModalOpen] = useState(false);
    const [selectedDay, setSelectedDay] = useState<Date | null>(null);
    const [isChartsModalOpen, setIsChartsModalOpen] = useState(false);
    const [sales, setSales] = useState<SaleWithDetails[]>([]);
    const [loading, setLoading] = useState(true);
    const [initialSaleDate, setInitialSaleDate] = useState<Date | undefined>(undefined);
    const [searchTerm, setSearchTerm] = useState("");
    const [statusFilter, setStatusFilter] = useState("all");
    const [selectedDetailedSale, setSelectedDetailedSale] = useState<SaleWithDetails | null>(null);

    // State for search dropdown
    const [showSearchResults, setShowSearchResults] = useState(false);
    const [isSearching, setIsSearching] = useState(false);
    const [searchResults, setSearchResults] = useState<{
        sales: any[];
        clients: any[];
        vehicles: any[];
    }>({ sales: [], clients: [], vehicles: [] });

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as HTMLElement;
            if (!target.closest('.search-container')) {
                setShowSearchResults(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    useEffect(() => {
        const delayDebounce = setTimeout(async () => {
            const cleanQuery = searchTerm.trim();
            if (cleanQuery.length < 2) {
                setSearchResults({ sales: [], clients: [], vehicles: [] });
                setIsSearching(false);
                return;
            }
            setIsSearching(true);
            try {
                const companyId = user?.companyId;
                if (!companyId) return;
                const term = `%${cleanQuery}%`;

                const { data: clientsData } = await supabase
                    .from('clients')
                    .select('id, name, phone')
                    .eq('company_id', companyId)
                    .or(`name.ilike.${term},phone.ilike.${term}`)
                    .limit(5);

                const clientIds = (clientsData || []).map(c => c.id);

                const { data: vehiclesData } = await supabase
                    .from('vehicles')
                    .select('id, brand, model, plate, client:clients(name)')
                    .eq('company_id', companyId)
                    .or(`brand.ilike.${term},model.ilike.${term},plate.ilike.${term}`)
                    .limit(5);

                const vehicleIds = (vehiclesData || []).map(v => v.id);

                let salesQuery = supabase
                    .from('sales')
                    .select(`
            *,
            client:clients(id, name, phone),
            vehicle:vehicles(id, brand, model, year, plate, size),
            sale_items(
              id, service_id, quantity, unit_price, total_price,
              service:services(id, name, base_price)
            )
          `)
                    .eq('company_id', companyId)
                    .is('deleted_at', null);

                const filters = [];
                if (!isNaN(Number(cleanQuery))) {
                    filters.push(`id.eq.${Number(cleanQuery)}`);
                }
                if (clientIds.length > 0) {
                    filters.push(`client_id.in.(${clientIds.join(',')})`);
                }
                if (vehicleIds.length > 0) {
                    filters.push(`vehicle_id.in.(${vehicleIds.join(',')})`);
                }

                if (filters.length > 0) {
                    salesQuery = salesQuery.or(filters.join(','));
                } else {
                    salesQuery = salesQuery.ilike('observations', term);
                }

                const { data: salesData } = await salesQuery.limit(5);

                setSearchResults({
                    sales: salesData || [],
                    clients: clientsData || [],
                    vehicles: vehiclesData || []
                });
            } catch (err) {
                console.error("Erro na busca instantânea:", err);
            } finally {
                setIsSearching(false);
            }
        }, 300);
        return () => clearTimeout(delayDebounce);
    }, [searchTerm, user?.companyId]);

    const monthStart = startOfMonth(currentDate);
    const monthEnd = endOfMonth(currentDate);
    const calendarStart = startOfWeek(monthStart, { weekStartsOn: 0 });
    const calendarEnd = endOfWeek(monthEnd, { weekStartsOn: 0 });
    const calendarDays = eachDayOfInterval({ start: calendarStart, end: calendarEnd });

    useEffect(() => {
        fetchSales();
    }, [user?.id, currentDate]);

    const fetchSales = async (silently: boolean = false) => {
        if (!user?.id || !user?.companyId) return;
        if (!silently) setLoading(true);
        try {
            const { data, error } = await supabase
                .from('sales')
                .select(`
          *,
          client:clients(id, name, phone),
          vehicle:vehicles(id, brand, model, year, plate, size),
          sale_items(
            id, service_id, quantity, unit_price, total_price,
            service:services(id, name, base_price)
          )
        `)
                .eq('company_id', user.companyId)
                .is('deleted_at', null)
                .gte('sale_date', format(monthStart, 'yyyy-MM-dd'))
                .lte('sale_date', format(monthEnd, 'yyyy-MM-dd'))
                .order('sale_date', { ascending: false });

            if (data) {
                const transformedSales: SaleWithDetails[] = data.map((sale: any) => ({
                    ...sale,
                    sale_items: sale.sale_items || [],
                }));
                setSales(transformedSales);
            }
        } catch (error) {
            console.error('Error fetching sales:', error);
        } finally {
            if (!silently) setLoading(false);
        }
    };

    const handleNewSaleSuccess = (newSale?: any) => {
        setIsNewSaleModalOpen(false);
        if (newSale && newSale.id) {
            const isCurrentMonth = isSameMonth(new Date(newSale.sale_date + 'T12:00:00'), currentDate);
            if (isCurrentMonth) {
                setSales(prev => {
                    if (prev.some(s => s.id === newSale.id)) return prev;
                    return [{
                        ...newSale,
                        client: undefined,
                        vehicle: undefined,
                        sale_items: [],
                    }, ...prev];
                });
            }
        }
        fetchSales(true);
    };

    const getSalesForDay = (day: Date): SaleWithDetails[] => {
        return monthSales.filter((sale) => isSameDay(new Date(sale.sale_date + 'T12:00:00'), day));
    };

    const monthSales = sales.filter((sale) => {
        let pass = true;
        if (statusFilter !== "all") {
            const wantOpen = statusFilter === "aberta";
            if (sale.is_open !== wantOpen) pass = false;
        }
        if (searchTerm) {
            const term = searchTerm.toLowerCase();
            const matchClient = sale.client?.name?.toLowerCase().includes(term);
            const matchId = sale.id.toString() === term;
            const matchVehicle = sale.vehicle?.plate?.toLowerCase().includes(term) ||
                sale.vehicle?.brand?.toLowerCase().includes(term) ||
                sale.vehicle?.model?.toLowerCase().includes(term);
            if (!matchClient && !matchId && !matchVehicle) pass = false;
        }
        return pass;
    });

    const totalMonthValue = monthSales.reduce((sum, sale) => sum + sale.total, 0);
    const weekDays = ["Dom", "Seg", "Ter", "Qua", "Qui", "Sex", "Sáb"];

    return (
        <div className="space-y-6">
            <div className="flex flex-col gap-4">
                <div className="flex flex-col sm:flex-row justify-between gap-4">
                    <div className="flex flex-wrap items-center gap-2 sm:gap-4">
                        <div className="flex bg-card rounded-lg p-1 w-full sm:w-auto">
                            <Button
                                variant={viewMode === "calendar" ? "default" : "ghost"}
                                size="sm"
                                onClick={() => setViewMode("calendar")}
                                className="gap-2 flex-1 sm:flex-none"
                            >
                                <Calendar className="h-4 w-4" />
                                Calendário
                            </Button>
                            <Button
                                variant={viewMode === "list" ? "default" : "ghost"}
                                size="sm"
                                onClick={() => setViewMode("list")}
                                className="gap-2 flex-1 sm:flex-none"
                            >
                                <List className="h-4 w-4" />
                                Lista
                            </Button>
                        </div>

                        <div className="relative flex-1 min-w-[200px] w-full sm:w-auto search-container z-50">
                            <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                                <Input
                                    placeholder="Buscar venda, cliente ou veículo..."
                                    value={searchTerm}
                                    onChange={(e) => {
                                        setSearchTerm(e.target.value);
                                        setShowSearchResults(true);
                                    }}
                                    onFocus={() => setShowSearchResults(true)}
                                    className="pl-10"
                                />
                                {isSearching && (
                                    <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 animate-spin text-muted-foreground" />
                                )}
                            </div>

                            {showSearchResults && searchTerm.trim().length >= 2 && (
                                <div className="absolute top-full left-0 right-0 mt-2 bg-card/95 backdrop-blur-md border border-border rounded-xl shadow-2xl overflow-hidden max-h-[400px] overflow-y-auto z-50">
                                    {isSearching ? (
                                        <div className="p-8 text-center text-muted-foreground flex items-center justify-center gap-2">
                                            <Loader2 className="w-5 h-5 animate-spin text-primary" />
                                            <span>Buscando...</span>
                                        </div>
                                    ) : searchResults.sales.length === 0 && searchResults.clients.length === 0 && searchResults.vehicles.length === 0 ? (
                                        <div className="p-8 text-center text-muted-foreground">
                                            Nenhum resultado encontrado
                                        </div>
                                    ) : (
                                        <div className="p-2 space-y-4">
                                            {searchResults.sales.length > 0 && (
                                                <div className="space-y-1">
                                                    <h4 className="text-[10px] uppercase font-bold text-muted-foreground px-3 py-1 tracking-wider">
                                                        Vendas Encontradas
                                                    </h4>
                                                    {searchResults.sales.map(sale => (
                                                        <button
                                                            key={sale.id}
                                                            onClick={() => {
                                                                setShowSearchResults(false);
                                                                setSelectedDetailedSale(sale);
                                                            }}
                                                            className="w-full text-left px-3 py-2 rounded-lg hover:bg-accent transition-colors flex items-center gap-3"
                                                        >
                                                            <div className="w-8 h-8 rounded-lg bg-success/20 flex items-center justify-center shrink-0">
                                                                <DollarSign className="w-4 h-4 text-success" />
                                                            </div>
                                                            <div className="truncate">
                                                                <p className="text-sm font-semibold">
                                                                    Venda #{sale.id} - R$ {sale.total.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}
                                                                </p>
                                                                <p className="text-xs text-muted-foreground truncate">
                                                                    Cliente: {sale.client?.name || "Sem Nome"} {sale.vehicle ? `(${sale.vehicle.brand} ${sale.vehicle.model})` : ''}
                                                                </p>
                                                            </div>
                                                        </button>
                                                    ))}
                                                </div>
                                            )}

                                            {searchResults.clients.length > 0 && (
                                                <div className="space-y-1">
                                                    <h4 className="text-[10px] uppercase font-bold text-muted-foreground px-3 py-1 tracking-wider">
                                                        Clientes
                                                    </h4>
                                                    {searchResults.clients.map(client => (
                                                        <button
                                                            key={client.id}
                                                            onClick={() => {
                                                                setShowSearchResults(false);
                                                                setSearchTerm(client.name);
                                                            }}
                                                            className="w-full text-left px-3 py-2 rounded-lg hover:bg-accent transition-colors flex items-center gap-3"
                                                        >
                                                            <div className="w-8 h-8 rounded-lg bg-primary/20 flex items-center justify-center shrink-0">
                                                                <User className="w-4 h-4 text-primary" />
                                                            </div>
                                                            <div className="truncate">
                                                                <p className="text-sm font-semibold">{client.name}</p>
                                                                <p className="text-xs text-muted-foreground truncate">
                                                                    WhatsApp: {client.phone}
                                                                </p>
                                                            </div>
                                                        </button>
                                                    ))}
                                                </div>
                                            )}

                                            {searchResults.vehicles.length > 0 && (
                                                <div className="space-y-1">
                                                    <h4 className="text-[10px] uppercase font-bold text-muted-foreground px-3 py-1 tracking-wider">
