                                variant="ghost"
                                size="icon"
                                onClick={() => setCurrentDate(subMonths(currentDate, 1))}
                            >
                                <ChevronLeft className="h-4 w-4" />
                            </Button>
                            <span className="text-base sm:text-lg font-medium min-w-[140px] sm:min-w-[180px] text-center capitalize">
