                            </span>
                            <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => setCurrentDate(addMonths(currentDate, 1))}
                            >
                                <ChevronRight className="h-4 w-4" />
                            </Button>
                        </div>

                        <div className="flex items-center w-full justify-between sm:w-auto gap-2 sm:gap-4">
                            <Badge variant="outline" className="text-sm py-1.5 px-3 whitespace-nowrap flex-1 justify-center sm:flex-none">
                                {monthSales.length} vendas | R$ {totalMonthValue.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}
                            </Badge>

                            <Button variant="outline" onClick={() => setIsChartsModalOpen(true)} className="gap-2 flex-1 sm:flex-none">
                                <BarChart3 className="h-4 w-4" />
                                <span className="hidden sm:inline">Ver gráficos</span>
                                <span className="sm:hidden">Gráficos</span>
                            </Button>
                        </div>
                    </div>
                </div>
            </div>

            <SalesKPIBar sales={monthSales} />

            {loading ? (
                <Card className="p-4">
                    <div className="grid grid-cols-7 gap-1">
                        {Array.from({ length: 35 }).map((_, i) => (
                            <Skeleton key={i} className="h-24" />
                        ))}
                    </div>
                </Card>
            ) : (
                <>
                    {viewMode === "calendar" && (
                        <Card className="p-4">
                            <div className="mb-4">
                                <BrazilCalendarLegend />
                            </div>

                            <div className="grid grid-cols-7 gap-1 sm:gap-2 mb-1">
                                {weekDays.map((day) => (
                                    <div key={day} className="text-center text-[11px] sm:text-sm font-semibold text-muted-foreground py-1 sm:py-2 truncate">
                                        {day}
                                    </div>
                                ))}
                            </div>

                            <div className="grid grid-cols-7 gap-1 sm:gap-2">
                                {calendarDays.map((day) => {
                                    const daySales = getSalesForDay(day);
                                    const dayTotal = daySales.reduce((sum, sale) => sum + sale.total, 0);
                                    const isCurrentMonth = isSameMonth(day, currentDate);
                                    const isToday = isSameDay(day, new Date());
                                    const calendarEvent = getPrimaryBrazilCalendarEvent(day);
                                    const eventTitle = getBrazilCalendarTitle(day);

                                    return (
                                        <div
                                            key={day.toISOString()}
                                            onClick={() => setSelectedDay(day)}
                                            title={eventTitle}
                                            className={cn(
                                                "h-[72px] sm:h-auto sm:aspect-square sm:min-h-[100px] p-1.5 sm:p-2 border border-border rounded-lg sm:rounded-xl transition-all flex flex-col items-center cursor-pointer hover:bg-accent/80 hover:scale-[1.02] overflow-hidden relative shadow-sm",
                                                isCurrentMonth ? "bg-card" : "bg-background opacity-40",
                                                calendarEvent &&
                                                BRAZIL_CALENDAR_EVENT_STYLES[calendarEvent.kind].dayClass,
                                                isToday && "border-primary ring-1 ring-primary/20"
                                            )}
                                        >
                                            <div className="flex w-full justify-between items-start mb-0.5 sm:mb-0 sm:absolute sm:top-1.5 sm:left-1.5 sm:right-1.5 pointer-events-none">
                                                {isToday ? (
                                                    <span className="rounded bg-red-600 text-white text-[8px] sm:text-[10px] font-black px-1 py-px sm:px-1.5 sm:py-0.5 shadow-[0_0_8px_rgba(239,68,68,0.7)] border border-red-500 uppercase tracking-wide leading-none z-10 shrink-0">
                                                        Hoje
                                                    </span>
                                                ) : <div className="shrink-0" />}

                                                {calendarEvent ? (
                                                    <span
                                                        className={cn(
                                                            "max-w-[60%] truncate rounded px-1 py-px sm:px-1.5 sm:py-0.5 text-[7px] sm:text-[7px] font-bold leading-none origin-right",
                                                            BRAZIL_CALENDAR_EVENT_STYLES[calendarEvent.kind].chipClass
                                                        )}
                                                    >
                                                        {calendarEvent.shortName}
                                                    </span>
                                                ) : null}
                                            </div>

                                            <span className={cn(
                                                "text-xl sm:text-4xl font-extrabold tracking-tight leading-none my-auto",
                                                isToday ? "text-primary" : "text-foreground"
                                            )}>
                                                {format(day, "d")}
                                            </span>

                                            {daySales.length > 0 ? (
                                                <>
                                                    <div className="hidden sm:flex flex-col space-y-1 items-center w-full mt-auto">
                                                        <Badge variant="default" className="w-full justify-center text-xs bg-green-500 text-white hover:bg-green-600 px-2 py-0.5 max-w-full font-bold shadow-sm">
                                                            <span className="truncate">{daySales.length} venda{daySales.length > 1 ? "s" : ""}</span>
                                                        </Badge>
                                                        <Badge variant="outline" className="w-full justify-center text-xs px-2 py-0.5 max-w-full">
                                                            <span className="truncate">R$ {dayTotal.toLocaleString("pt-BR", { minimumFractionDigits: 0 })}</span>
                                                        </Badge>
                                                    </div>

                                                    <div className="flex sm:hidden items-center justify-center mt-auto w-full">
                                                        <div className="w-4 h-4 rounded-full bg-green-500 text-white flex items-center justify-center text-[8px] font-extrabold shadow-sm">
                                                            {daySales.length}
                                                        </div>
                                                    </div>
                                                </>
                                            ) : (
                                                <div className="h-4 sm:h-10 w-full pointer-events-none opacity-0 mt-auto" />
                                            )}
                                        </div>
                                    );
                                })}
                            </div>
                        </Card>
                    )}

                    {viewMode === "list" && (
                        <Card className="p-4">
                            <div className="space-y-2">
                                {monthSales.length === 0 ? (
                                    <div className="text-center py-12 text-muted-foreground">
                                        Nenhuma venda encontrada neste período
                                    </div>
                                ) : (
                                    monthSales.map((sale) => (
                                        <div
                                            key={sale.id}
                                            className="flex items-center justify-between p-4 bg-muted/30 rounded-lg hover:bg-muted/50 cursor-pointer transition-colors"
                                            onClick={() => setSelectedDay(new Date(sale.sale_date + 'T12:00:00'))}
                                        >
                                            <div className="flex items-center gap-4">
                                                <div className="w-10 h-10 rounded-full bg-success/20 flex items-center justify-center">
                                                    <span className="text-success font-semibold">💰</span>
                                                </div>
                                                <div>
                                                    <p className="font-medium">Venda #{sale.id}</p>
                                                    <p className="text-sm text-muted-foreground">{sale.client?.name || "Cliente"}</p>
                                                </div>
                                            </div>
                                            <div className="text-right">
                                                <p className="font-semibold text-success">
                                                    R$ {sale.total.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}
                                                </p>
                                                <p className="text-sm text-muted-foreground">
                                                    {format(new Date(sale.sale_date + 'T12:00:00'), "dd/MM/yyyy")}
                                                </p>
                                            </div>
                                            <Badge variant={!sale.is_open ? "default" : "outline"}>
                                                {sale.is_open ? 'Aberta' : 'Fechada'}
                                            </Badge>
                                        </div>
                                    ))
                                )}
                            </div>
                        </Card>
                    )}
                </>
            )}

            <NewSaleModal
                open={isNewSaleModalOpen}
                onOpenChange={(open) => {
                    setIsNewSaleModalOpen(open);
                    if (!open) {
                        setInitialSaleDate(undefined);
                    }
                }}
                initialDate={initialSaleDate}
                onSuccess={handleNewSaleSuccess}
            />

            <SalesDayDrawer
                open={!!selectedDay}
                onOpenChange={(open) => !open && setSelectedDay(null)}
                selectedDate={selectedDay}
                allSales={sales}
                onNewSale={(date) => {
                    setSelectedDay(null);
                    setInitialSaleDate(date);
                    setIsNewSaleModalOpen(true);
                }}
            />

            <SalesChartsModal
                open={isChartsModalOpen}
                onOpenChange={setIsChartsModalOpen}
                sales={monthSales}
            />

            <SaleDetailsModal
                open={!!selectedDetailedSale}
                onOpenChange={(open) => {
                    if (!open) {
                        setSelectedDetailedSale(null);
                        fetchSales();
                    }
                }}
                sale={selectedDetailedSale}
            />
        </div>
    );
}

﻿// @ts-nocheck
import { useState, useEffect, useRef } from "react";
import { format, parseISO } from "date-fns";
import { ptBR } from "date-fns/locale";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList } from "@/components/ui/command";
import { Calendar as CalendarPicker } from "@/components/ui/calendar";
import { cn } from "@/lib/utils";

import { Calendar, Clock, Car, User, Camera, Tag, FileText, DollarSign, Package, Plus, RefreshCw, Loader2, Check, Percent, X, Sliders, ChevronsUpDown, CalendarIcon, AlertTriangle } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Alert, AlertTitle, AlertDescription } from "@/components/ui/alert";
import { toast } from "sonner";
import ServiceItemRow, { DetailedServiceItem, ProductCategory } from "@/pages/Vendas/components/ServiceItemRow";
import CustomizedServiceBlock, { CustomizedRegionItem, createInitialCustomItems } from "@/pages/Vendas/components/CustomizedServiceBlock";
import NewVehicleModal from "@/pages/Vendas/components/NewVehicleModal";
import NewClientModal from "@/pages/Vendas/components/NewClientModal";
import { validateUpload, sanitizeFilename } from "@/lib/uploadValidator";

interface FillSlotModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSlotFilled?: () => void;
  preselectedDate?: Date;
  totalSlots?: number;
  occupiedCount?: number;
  defaultClientId?: number;
}

interface ClientVehicle {
  id: number;
  brand: string;
  model: string;
  plate: string | null;
  year: number | null;
  size: string | null;
}

interface VehicleRegion {
  id: number;
  category: string;
  name: string;
  description: string | null;
  fixed_price: number | null;
  region_code?: string | null;
}

export function FillSlotModal({ open, onOpenChange, onSlotFilled, preselectedDate, totalSlots, occupiedCount, defaultClientId }: FillSlotModalProps) {
  const { user } = useAuth();
  const queryClient = useQueryClient();
  const companyId = user?.companyId;

  // Form state
  const [slotName, setSlotName] = useState("");
  const [selectedClientId, setSelectedClientId] = useState<string>("");
  const [selectedVehicleId, setSelectedVehicleId] = useState<string>("");
  const [entryDate, setEntryDate] = useState<Date>(preselectedDate || new Date());
  const [entryTime, setEntryTime] = useState(format(new Date(), 'HH:mm'));
  const [isEntryCalendarOpen, setIsEntryCalendarOpen] = useState(false);
  const [exitDate, setExitDate] = useState<Date | undefined>(undefined);
  const [exitTime, setExitTime] = useState("");
  const [isExitCalendarOpen, setIsExitCalendarOpen] = useState(false);
  const [discount, setDiscount] = useState<number>(0);
  const [discountPercent, setDiscountPercent] = useState<number>(0);
  const [discountType, setDiscountType] = useState<'fixed' | 'percent'>('fixed');
  const [observations, setObservations] = useState("");
  const [tag, setTag] = useState("");
  const [photos, setPhotos] = useState<File[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Detailed services state
  const [detailedItems, setDetailedItems] = useState<DetailedServiceItem[]>([]);
  const [customizedGroups, setCustomizedGroups] = useState<Map<string, CustomizedRegionItem[]>>(new Map());

  // New vehicle modal
  const [showNewVehicleModal, setShowNewVehicleModal] = useState(false);
  const [showNewClientModal, setShowNewClientModal] = useState(false);
  const [openClientPopover, setOpenClientPopover] = useState(false);

  // Toggle states for optional fields
  const [showDiscount, setShowDiscount] = useState(false);
  const [showObservations, setShowObservations] = useState(false);
  const [showTag, setShowTag] = useState(false);
  const [isNewClient, setIsNewClient] = useState(true);
  const [pastSalesCount, setPastSalesCount] = useState(0);

  // Fetch clients
  const { data: clients, isLoading: loadingClients, refetch: refetchClients } = useQuery({
    queryKey: ['clients-for-slot', companyId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('clients')
        .select('id, name, phone, birth_date')
        .eq('company_id', companyId)
        .order('name');
      if (error) throw error;
      return data;
    },
    enabled: !!companyId && open,
  });

  // Fetch client's vehicles
  const { data: clientVehicles, isLoading: loadingVehicles, refetch: refetchVehicles } = useQuery({
    queryKey: ['client-vehicles', selectedClientId, companyId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('vehicles')
        .select('id, brand, model, plate, year, size')
        .eq('client_id', parseInt(selectedClientId))
        .eq('company_id', companyId);
      if (error) throw error;
      return data as ClientVehicle[];
    },
    enabled: !!selectedClientId && !!companyId,
  });

  // Fetch product types for services
  const { data: productTypes } = useQuery({
    queryKey: ['product-types', companyId],
    queryFn: async () => {
      // 1. Fetch materials (bobinas) from stock
      const { data: materialsData, error: materialsError } = await supabase
        .from('materials')
        .select('product_type_id, is_open_roll')
        .eq('company_id', companyId)
        .eq('is_active', true);

      if (materialsError) throw materialsError;

      // 2. Fetch product types
      const { data: productsData, error: productsError } = await supabase
        .from('product_types')
        .select('id, category, brand, name, model, light_transmission, unit_price')
        .eq('company_id', companyId)
        .eq('is_active', true);

      if (productsError) throw productsError;

      // 3. Map stock to products
      const materialsList = materialsData || [];
      const enrichedProducts = (productsData || []).map(pt => {
        const ptMaterials = materialsList.filter(m => m.product_type_id === pt.id);
        const openRolls = ptMaterials.filter(m => m.is_open_roll);
        const closedRolls = ptMaterials.filter(m => !m.is_open_roll);
        return {
          ...pt,
          openRollsCount: openRolls.length,
          hasClosedRoll: closedRolls.length > 0
        };
      });

      return enrichedProducts;
    },
    enabled: !!companyId && open,
  });

  // Fetch vehicle regions (services) with fixed_price
  const { data: vehicleRegions } = useQuery({
    queryKey: ['vehicle-regions-with-price', companyId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('vehicle_regions')
        .select('id, category, name, description, fixed_price, region_code')
        .eq('company_id', companyId)
        .eq('is_active', true)
        .order('sort_order');
      if (error) throw error;
      return data as unknown as VehicleRegion[];
    },
    enabled: !!companyId && open,
  });

  // Fetch consumption rules
  const { data: consumptionRules } = useQuery({
    queryKey: ['consumption-rules', companyId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('region_consumption_rules')
        .select('id, category, region_id, vehicle_size, meters_consumed')
        .eq('company_id', companyId);
      if (error) throw error;
      return data as any[];
    },
    enabled: !!companyId && open,
  });

  // Get selected data
  const selectedClient = clients?.find(c => c.id === parseInt(selectedClientId));
  const selectedVehicle = clientVehicles?.find(v => v.id === parseInt(selectedVehicleId));

  const rulesWithRegionCode = (consumptionRules || []).map(rule => {
    const region = vehicleRegions?.find(r => r.id === rule.region_id);
    return { ...rule, region_code: (region as any)?.region_code || null };
  });

  // Calculate totals
  const subtotal = detailedItems.reduce((sum, item) => sum + (item.totalPrice || 0), 0);
  const calculatedDiscount = discountType === 'percent'
    ? (subtotal * (discountPercent / 100))
    : (discount || 0);
  const finalTotal = subtotal - calculatedDiscount;
  const serviceCount = detailedItems.length;

  // Reset form when modal closes, or prefill client if open
  useEffect(() => {
    if (!open) {
      setSlotName("");
      setSelectedClientId("");
      setSelectedVehicleId("");
      setEntryDate(new Date());
      setEntryTime(format(new Date(), 'HH:mm'));
      setExitDate(undefined);
      setExitTime("");
      setDiscount(0);
      setDiscountPercent(0);
      setDiscountType('fixed');
      setObservations("");
      setTag("");
      setDetailedItems([]);
      setCustomizedGroups(new Map());
      setPhotos([]);
      setShowDiscount(false);
      setShowObservations(false);
      setShowTag(false);
      setIsNewClient(true);
      setPastSalesCount(0);
    } else if (defaultClientId) {
      setSelectedClientId(defaultClientId.toString());
    }
  }, [open, defaultClientId]);

  // Update entry date when preselectedDate changes
  useEffect(() => {
    if (preselectedDate) {
      setEntryDate(preselectedDate);
    }
  }, [preselectedDate]);


  // Reset vehicle and services when client changes
  useEffect(() => {
    setDetailedItems([]);
    setSelectedVehicleId("");
    setIsNewClient(true);
    setPastSalesCount(0);
  }, [selectedClientId]);

  // Auto-detect if client is new or returning
  useEffect(() => {
    const detectClientType = async () => {
      if (!selectedClientId || !companyId) {
        setIsNewClient(true);
        setPastSalesCount(0);
        return;
      }
      const { count } = await supabase
        .from('sales')
        .select('id', { count: 'exact', head: true })
        .eq('client_id', parseInt(selectedClientId))
        .eq('company_id', companyId)
        .eq('status', 'Fechada');
      const total = count || 0;
      setPastSalesCount(total);
      setIsNewClient(total === 0);
    };
    detectClientType();
  }, [selectedClientId, companyId]);

  // Auto-select vehicle if there is exactly 1
  useEffect(() => {
    if (clientVehicles && clientVehicles.length === 1 && !selectedVehicleId) {
      setSelectedVehicleId(clientVehicles[0].id.toString());
    }
  }, [clientVehicles]);

  // Handle adding a new detailed service item
  const handleAddDetailedItem = () => {
    const newItem: DetailedServiceItem = {
      id: Math.random().toString(36).substr(2, 9),
      category: "INSULFILM" as ProductCategory,
      regionId: null,
      regionName: "",
      productTypeId: null,
      productTypeName: "",
      metersUsed: 0,
      totalPrice: 0,
      serviceName: "",
      regionCode: null,
      displayName: "",
      isCustomized: false,
      customizationGroup: null,
    };
    setDetailedItems([...detailedItems, newItem]);
  };

  // Toggle customized mode for an INSULFILM item
  const handleToggleCustomize = (itemId: string) => {
    const item = detailedItems.find(i => i.id === itemId);
    if (!item || (item.isCustomized && item.customizationGroup)) return;

    const groupId = Math.random().toString(36).substr(2, 9);
    const initialItems = createInitialCustomItems(
      selectedVehicle?.size || null,
      consumptionRules || [],
      item.productTypeId,
      item.productTypeName,
      item.regionId
    );

    setDetailedItems(prev =>
      prev.map(i =>
        i.id === itemId
          ? { ...i, isCustomized: true, customizationGroup: groupId }
          : i
      )
    );
    setCustomizedGroups(prev => new Map(prev).set(groupId, initialItems));
  };

  const handleRevertToSimple = (itemId: string, groupId: string) => {
    setDetailedItems(prev =>
      prev.map(i =>
        i.id === itemId
          ? { ...i, isCustomized: false, customizationGroup: null, productTypeId: null, productTypeName: "" }
          : i
      )
    );
    setCustomizedGroups(prev => {
      const next = new Map(prev);
      next.delete(groupId);
      return next;
    });
  };

  const handleUpdateCustomizedItems = (groupId: string, items: CustomizedRegionItem[]) => {
    setCustomizedGroups(prev => new Map(prev).set(groupId, items));
  };

  // Handle updating a detailed service item with fixed_price support
  const handleUpdateDetailedItem = (updatedItem: DetailedServiceItem) => {
    // If region changed, apply fixed_price if available
    const region = vehicleRegions?.find(r => r.id === updatedItem.regionId);
    if (region?.fixed_price && region.fixed_price > 0 && updatedItem.totalPrice === 0) {
      updatedItem = { ...updatedItem, totalPrice: region.fixed_price };
    }

    setDetailedItems(items =>
      items.map(item => item.id === updatedItem.id ? updatedItem : item)
    );
  };

  // Update customized group price
  const handleUpdateCustomizedPrice = (itemId: string, newPrice: number) => {
    setDetailedItems(prev =>
      prev.map(i => i.id === itemId ? { ...i, totalPrice: newPrice } : i)
    );
  };

  // Handle removing a detailed service item
  const handleRemoveDetailedItem = (itemId: string) => {
    setDetailedItems(items => items.filter(item => item.id !== itemId));
  };

  const handlePhotoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles = Array.from(e.target.files);

      const validFiles: File[] = [];
      for (const file of newFiles) {
        const validation = validateUpload(file, {
          type: 'checklist-photo',
          maxFiles: 20,
          currentFiles: photos.length + validFiles.length
        });

        if (!validation.valid) {
          toast.error(`Falha em ${file.name}: ${validation.error}`);
          continue;
        }
        validFiles.push(file);
      }

      setPhotos([...photos, ...validFiles]);
    }
  };

  // Handle new vehicle created
  const handleVehicleCreated = async (vehicleData: any) => {
    try {
      const { data, error } = await supabase
        .from('vehicles')
        .insert({
          client_id: parseInt(selectedClientId),
          brand: vehicleData.brand,
          model: vehicleData.model,
          plate: vehicleData.plate,
          year: vehicleData.year,
          size: vehicleData.size,
          company_id: companyId,
        })
        .select()
        .single();

      if (error) throw error;

      toast.success("Veículo cadastrado com sucesso!");
      refetchVehicles();
      setSelectedVehicleId(data.id.toString());
      setShowNewVehicleModal(false);
    } catch (error) {
      console.error("Erro ao cadastrar veículo:", error);
      toast.error("Erro ao cadastrar veículo");
    }
  };

  // Mutation to create space (without sale_id)
  const createMutation = useMutation({
    mutationFn: async () => {
      if (!companyId || !selectedClientId || !selectedVehicleId) {
        throw new Error("Dados inválidos");
      }

      // Insert space without sale_id
      const { data: spaceData, error: spaceError } = await supabase
        .from('spaces')
        .insert({
          name: slotName || `Vaga de ${selectedClient?.name}`,
          client_id: parseInt(selectedClientId),
          vehicle_id: parseInt(selectedVehicleId),
          sale_id: null, // No sale yet - will be created later
          company_id: companyId,
          entry_date: format(entryDate, 'yyyy-MM-dd'),
          entry_time: entryTime,
          exit_date: exitDate ? format(exitDate, 'yyyy-MM-dd') : null,
          exit_time: exitTime || null,
          discount: calculatedDiscount || null,
          observations: observations || null,
          tag: tag || null,
          status: 'ocupado',
          payment_status: 'pending',
          has_exited: false,
          is_new_client: isNewClient,
        })
        .select()
        .single();

      if (spaceError) throw spaceError;

      // Save services data as JSONB
      if (detailedItems.length > 0) {
        const servicesData: any[] = [];
        for (const item of detailedItems) {
          if (item.isCustomized && item.customizationGroup) {
            const groupItems = customizedGroups.get(item.customizationGroup) || [];
            servicesData.push({
              category: item.category,
              isCustomized: true,
              customizationGroup: item.customizationGroup,
              totalPrice: item.totalPrice || 0,
              items: groupItems.map(gi => ({
                regionCode: gi.regionCode,
                regionLabel: gi.regionLabel,
                productTypeId: gi.productTypeId,
                productTypeName: gi.productTypeName,
                metersUsed: gi.metersUsed,
                totalPrice: gi.totalPrice,
              })),
            });
          } else {
            const region = (vehicleRegions || []).find(r => r.id === item.regionId);
            servicesData.push({
              category: item.category,
              regionId: item.regionId,
              regionName: item.regionName || 'Serviço',
              productTypeId: item.productTypeId,
              productTypeName: item.productTypeName || '',
              totalPrice: item.totalPrice || 0,
              metersUsed: item.metersUsed || 0,
              serviceName: item.serviceName || item.regionName,
              regionCode: region?.region_code || null,
              displayName: item.displayName || `${item.regionName} • ${item.productTypeName}`,
              isCustomized: false,
            });
          }
        }

        await supabase
          .from('spaces')
          .update({ services_data: servicesData } as any)
          .eq('id', spaceData.id);
      }

      // Upload photos (validated locally, but Storage RLS ensures bounds too)
      if (photos.length > 0) {
        for (let i = 0; i < photos.length; i++) {
          const photo = photos[i];
          const fileExt = photo.name.split('.').pop() || 'jpg';
          const sanitizedName = sanitizeFilename(photo.name.replace(`.${fileExt}`, ''));
          const fileName = `${Date.now()}_${i}_${sanitizedName}.${fileExt}`;
          const filePath = `${companyId}/${spaceData.id}/${fileName}`;

          const { error: uploadError } = await supabase.storage
            .from('checklists')
            .upload(filePath, photo, { upsert: true });

          if (uploadError) {
            console.error("Erro no upload da foto", photo.name, uploadError);
          }
        }
      }

      return spaceData;
    },
    onSuccess: () => {
      toast.success("Vaga preenchida com sucesso!");
      queryClient.invalidateQueries({ queryKey: ['spaces'] });
      onSlotFilled?.();
      onOpenChange(false);
    },
    onError: (error) => {
      console.error("Erro ao criar vaga:", error);
      toast.error("Erro ao preencher vaga");
    },
  });

  const handleSubmit = () => {
    if (!selectedClientId) {
      toast.error("Selecione um cliente");
      return;
    }
    if (!selectedVehicleId) {
      toast.error("Selecione um veículo");
      return;
    }
    if (!entryDate || !entryTime) {
      toast.error("Informe a data e hora de entrada");
      return;
    }
    createMutation.mutate();
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Preencher vaga</DialogTitle>
          <DialogDescription>Informe os dados para preencher a vaga</DialogDescription>
        </DialogHeader>

        <div className="space-y-6">
          {totalSlots !== undefined && occupiedCount !== undefined && occupiedCount >= totalSlots && (
            <Alert
              variant={occupiedCount > totalSlots ? "destructive" : "default"}
              className={cn(
                "transition-all duration-300 shadow-md border-2",
                occupiedCount > totalSlots
                  ? "bg-red-500/10 border-red-500/30 text-red-200"
                  : "bg-amber-500/10 border-amber-500/30 text-amber-200"
              )}
            >
              <AlertTriangle className={cn(
                "h-5 w-5 animate-pulse shrink-0",
                occupiedCount > totalSlots ? "text-red-500" : "text-amber-500"
              )} />
              <AlertTitle className="font-bold text-base ml-2">
                {occupiedCount > totalSlots ? "Limite de Vagas Excedido!" : "Limite de Vagas Atingido!"}
              </AlertTitle>
              <AlertDescription className="text-sm opacity-90 mt-1 ml-2">
                O limite de vagas ({totalSlots}) do seu estabelecimento foi {occupiedCount > totalSlots ? "excedido" : "atingido"}. Para que uma nova vaga fique disponível, outra vaga deve encerrar o serviço.
              </AlertDescription>
            </Alert>
          )}
          {/* Nome da vaga */}
          <div className="space-y-2">
            <Label>Nome da vaga (opcional)</Label>
            <Input
              value={slotName}
              onChange={(e) => setSlotName(e.target.value)}
              placeholder="Ex: Vaga 1, Box A, etc."
            />
          </div>

          {/* Cliente */}
          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <Label>Cliente *</Label>
              <Button
                variant="default"
                size="sm"
                onClick={() => setShowNewClientModal(true)}
                className="h-8 text-xs bg-green-600 hover:bg-green-700 text-white border-0"
              >
                <Plus className="h-3 w-3 mr-1" />
                Novo
              </Button>
            </div>
            <Popover open={openClientPopover} onOpenChange={setOpenClientPopover}>
              <PopoverTrigger asChild>
                <Button
                  variant="outline"
                  role="combobox"
                  aria-expanded={openClientPopover}
                  className="w-full justify-between justify-items-stretch"
                >
                  {selectedClientId
                    ? (
                      <div className="flex items-center gap-2">
                        <User className="h-4 w-4 text-muted-foreground" />
                        <span className="truncate">
                          {clients?.find((c) => c.id.toString() === selectedClientId)?.name}
                        </span>
                      </div>
                    )
                    : loadingClients ? "Carregando..." : "Selecione um cliente"}
                  <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-[400px] max-w-[calc(100vw-32px)] p-0" align="start">
                <Command>
                  <CommandInput placeholder="Buscar cliente por nome..." />
                  <CommandList>
                    <CommandEmpty>Nenhum cliente encontrado.</CommandEmpty>
                    <CommandGroup>
                      {clients?.map((client) => (
                        <CommandItem
                          key={client.id}
                          value={client.name}
                          onSelect={() => {
                            setSelectedClientId(client.id.toString());
                            setOpenClientPopover(false);
                          }}
                        >
                          <div className="flex items-center gap-2 w-full">
                            <User className="h-4 w-4 text-muted-foreground" />
                            <span>{client.name}</span>
                            {client.phone && (
                              <span className="text-muted-foreground text-xs ml-auto whitespace-nowrap">
                                ({client.phone})
                              </span>
                            )}
                            <Check
                              className={cn(
                                "mr-2 h-4 w-4",
                                selectedClientId === client.id.toString() ? "opacity-100" : "opacity-0"
                              )}
                            />
                          </div>
                        </CommandItem>
                      ))}
                    </CommandGroup>
                  </CommandList>
                </Command>
              </PopoverContent>
            </Popover>
          </div>

          {/* Client Type: Novo vs Retorno */}
          {selectedClientId && (
            <div className="space-y-2">
              <Label>Tipo de Atendimento</Label>
              <Select value={isNewClient ? 'new' : 'returning'} onValueChange={(v) => setIsNewClient(v === 'new')}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="new">
                    <div className="flex items-center gap-2">
                      <span className="h-2 w-2 rounded-full bg-green-500" />
                      Novo Cliente
                    </div>
                  </SelectItem>
                  <SelectItem value="returning">
                    <div className="flex items-center gap-2">
                      <span className="h-2 w-2 rounded-full bg-blue-500" />
                      Cliente Retorno
                    </div>
                  </SelectItem>
                </SelectContent>
              </Select>
              {pastSalesCount > 0 && (
                <p className="text-xs text-muted-foreground">
                  ⓘ Detectado automaticamente: cliente possui {pastSalesCount} venda(s) anterior(es).
                </p>
              )}
            </div>
          )}

          {/* Veículo */}
          {selectedClientId && (
            <div className="space-y-2">
              <Label>Veículo *</Label>
              {loadingVehicles ? (
                <div className="flex items-center justify-center py-4">
                  <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
                </div>
              ) : (
                <div className="flex gap-2">
                  <Select value={selectedVehicleId} onValueChange={setSelectedVehicleId}>
                    <SelectTrigger className="flex-1">
                      <SelectValue placeholder="Selecione um veículo" />
                    </SelectTrigger>
                    <SelectContent>
                      {clientVehicles && clientVehicles.length > 0 ? (
                        clientVehicles.map(vehicle => (
                          <SelectItem key={vehicle.id} value={vehicle.id.toString()}>
                            <div className="flex items-center gap-2">
                              <Car className="h-4 w-4 text-muted-foreground" />
                              <span>{vehicle.brand} {vehicle.model}</span>
                              {vehicle.plate && (
                                <Badge variant="outline" className="text-xs">{vehicle.plate}</Badge>
                              )}
                            </div>
                          </SelectItem>
                        ))
                      ) : (
                        <SelectItem value="none" disabled>
                          Nenhum veículo cadastrado
                        </SelectItem>
                      )}
                    </SelectContent>
                  </Select>
                  <Button variant="default" className="bg-green-600 hover:bg-green-700 text-white border-0" onClick={() => setShowNewVehicleModal(true)}>
                    <Plus className="h-4 w-4 mr-1" /> Novo
                  </Button>
                </div>
              )}
            </div>
          )}

          {/* Serviços Detalhados */}
          {selectedVehicleId && (
            <div className="space-y-3">
              <div className="flex items-center justify-between">
                <Label>Serviços</Label>
                <Button variant="default" size="sm" className="bg-blue-600 hover:bg-blue-700 text-white border-0" onClick={handleAddDetailedItem}>
                  <Plus className="h-4 w-4 mr-1" /> Adicionar Serviço
                </Button>
              </div>

              {detailedItems.length === 0 ? (
                <p className="text-sm text-muted-foreground text-center py-4">
                  Clique em "Adicionar Serviço" para incluir serviços na vaga
                </p>
              ) : (
                <div className="space-y-2">
                  {detailedItems.map(item => (
                    <div key={item.id} className="space-y-2">
                      {item.isCustomized && item.customizationGroup ? (
                        <CustomizedServiceBlock
                          groupId={item.customizationGroup}
                          items={customizedGroups.get(item.customizationGroup) || []}
                          productTypes={productTypes || []}
                          vehicleSize={selectedVehicle?.size || null}
                          consumptionRules={rulesWithRegionCode}
                          servicePrice={item.totalPrice}
                          onUpdate={(items) => handleUpdateCustomizedItems(item.customizationGroup!, items)}
                          onRevertToSimple={() => handleRevertToSimple(item.id, item.customizationGroup!)}
                          onPriceChange={(price) => handleUpdateCustomizedPrice(item.id, price)}
                        />
                      ) : (
                        <div className="flex items-center gap-2">
                          <div className="flex-1">
                            <ServiceItemRow
                              item={item}
                              vehicleSize={selectedVehicle?.size || null}
                              productTypes={productTypes || []}
                              vehicleRegions={vehicleRegions || []}
                              consumptionRules={rulesWithRegionCode}
                              onUpdate={handleUpdateDetailedItem}
                              onRemove={handleRemoveDetailedItem}
                            />
                          </div>
                          {item.category === 'INSULFILM' && (item.regionCode === 'SIDE_REAR' || item.regionName?.toLowerCase().includes('latera')) && (
                            <Button
                              type="button"
                              variant="outline"
                              size="icon"
                              className="h-8 w-8 shrink-0"
                              onClick={() => handleToggleCustomize(item.id)}
                              title="Personalizar"
                            >
                              <Sliders className="h-4 w-4" />
                            </Button>
                          )}
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              )}

              {detailedItems.length > 0 && (
                <div className="flex justify-end">
                  <Badge variant="secondary">
                    {serviceCount} serviço(s) - R$ {subtotal.toFixed(2)}
                  </Badge>
                </div>
              )}
            </div>
          )}

          {/* Datas de entrada e saída */}
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label className="flex items-center gap-2">
                <CalendarIcon className="h-4 w-4" />
                Dia da entrada *
              </Label>
              <Popover open={isEntryCalendarOpen} onOpenChange={setIsEntryCalendarOpen}>
                <PopoverTrigger asChild>
                  <Button
                    variant="outline"
                    className="w-full justify-start text-left font-normal"
                  >
                    <CalendarIcon className="mr-2 h-4 w-4" />
                    {format(entryDate, "dd 'de' MMMM 'de' yyyy", { locale: ptBR })}
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0" align="start">
                  <CalendarPicker
                    mode="single"
                    selected={entryDate}
                    onSelect={(date) => {
                      if (date) {
                        setEntryDate(date);
                        setIsEntryCalendarOpen(false);
                      }
                    }}
                    initialFocus
                    className="p-3 pointer-events-auto"
                  />
                </PopoverContent>
              </Popover>
            </div>
            <div className="space-y-2">
              <Label className="flex items-center gap-2">
                <Clock className="h-4 w-4" />
                Hora da entrada *
              </Label>
              <Input
                type="time"
                value={entryTime}
                onChange={(e) => setEntryTime(e.target.value)}
              />
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label className="flex items-center gap-2">
                <CalendarIcon className="h-4 w-4" />
                Dia da saída (previsão)
              </Label>
              <Popover open={isExitCalendarOpen} onOpenChange={setIsExitCalendarOpen}>
                <PopoverTrigger asChild>
                  <Button
                    variant="outline"
                    className={cn(
                      "w-full justify-start text-left font-normal",
                      !exitDate && "text-muted-foreground"
                    )}
                  >
                    <CalendarIcon className="mr-2 h-4 w-4" />
                    {exitDate
                      ? format(exitDate, "dd 'de' MMMM 'de' yyyy", { locale: ptBR })
                      : "Selecione uma data"}
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0" align="start">
                  <CalendarPicker
                    mode="single"
                    selected={exitDate}
                    onSelect={(date) => {
                      setExitDate(date);
                      setIsExitCalendarOpen(false);
                    }}
                    initialFocus
                    className="p-3 pointer-events-auto"
                  />
                </PopoverContent>
              </Popover>
            </div>
            <div className="space-y-2">
              <Label className="flex items-center gap-2">
                <Clock className="h-4 w-4" />
                Hora da saída
              </Label>
              <Input
                type="time"
                value={exitTime}
                onChange={(e) => setExitTime(e.target.value)}
              />
            </div>
          </div>

          {/* Fotos de checklist */}
          <div className="space-y-2">
            <div className="flex justify-between items-center">
              <Label className="flex items-center gap-2">
                <Camera className="h-4 w-4" />
                Fotos de checklist
              </Label>
              <span className="text-xs text-muted-foreground">{photos.length}/20</span>
            </div>
            <p className="text-sm text-muted-foreground">Opcional: Adicione fotos para referenciar a avaria ou condição de recebimento do veículo.</p>

            {photos.length > 0 && (
              <div className="flex gap-2 overflow-x-auto overscroll-x-contain pb-2">
                {photos.map((photo, index) => (
                  <div key={index} className="relative min-w-[80px] h-[80px] rounded border overflow-hidden shrink-0">
                    <img src={URL.createObjectURL(photo)} alt={`Foto ${index + 1}`} className="w-full h-full object-cover" />
                    <button
                      type="button"
                      onClick={() => setPhotos(photos.filter((_, i) => i !== index))}
                      className="absolute top-1 right-1 bg-black/50 hover:bg-black p-1 rounded-full text-white transition-colors"
                    >
                      <X className="h-3 w-3" />
                    </button>
                  </div>
                ))}
              </div>
            )}

            <input
              type="file"
              multiple
              accept="image/png, image/jpeg, image/webp, image/heic"
              className="hidden"
              ref={fileInputRef}
              onChange={handlePhotoSelect}
            />
            <Button
              variant="outline"
              className="w-full"
              onClick={() => fileInputRef.current?.click()}
              disabled={photos.length >= 20}
              type="button"
            >
              <Plus className="h-4 w-4 mr-2" />
              Carregar nova foto
            </Button>
          </div>

          {/* Campos opcionais */}
          <div className="space-y-2">
            <Label>Campos opcionais</Label>
            <div className="flex gap-2 flex-wrap">
              <Button
                variant={showDiscount ? "default" : "outline"}
                size="sm"
                onClick={() => setShowDiscount(!showDiscount)}
              >
                <DollarSign className="h-4 w-4 mr-1" />
                Desconto
              </Button>
              <Button
                variant={showObservations ? "default" : "outline"}
                size="sm"
                onClick={() => setShowObservations(!showObservations)}
              >
                <FileText className="h-4 w-4 mr-1" />
                Observações
              </Button>
              <Button
                variant={showTag ? "default" : "outline"}
                size="sm"
                onClick={() => setShowTag(!showTag)}
              >
                <Tag className="h-4 w-4 mr-1" />
                Tag
              </Button>
            </div>
          </div>

          {/* Campos opcionais expandidos */}
          {showDiscount && (
            <div className="space-y-3">
              {/* Seleção do tipo de desconto */}
              <div className="flex gap-2">
                <Card
                  className={`flex-1 cursor-pointer transition-all ${discountType === 'fixed'
                    ? "border-primary bg-primary/10"
                    : "border-border/50 hover:border-muted-foreground"
                    }`}
                  onClick={() => setDiscountType('fixed')}
                >
                  <CardContent className="p-3 text-center">
                    <DollarSign className="h-5 w-5 mx-auto mb-1" />
                    <span className="text-sm font-medium">Valor (R$)</span>
                  </CardContent>
                </Card>

                <Card
                  className={`flex-1 cursor-pointer transition-all ${discountType === 'percent'
                    ? "border-primary bg-primary/10"
                    : "border-border/50 hover:border-muted-foreground"
                    }`}
                  onClick={() => setDiscountType('percent')}
                >
                  <CardContent className="p-3 text-center">
                    <Percent className="h-5 w-5 mx-auto mb-1" />
                    <span className="text-sm font-medium">Percentual (%)</span>
                  </CardContent>
                </Card>
              </div>

              {/* Input baseado no tipo selecionado */}
              {discountType === 'fixed' ? (
                <div className="space-y-2">
                  <Label>Desconto (R$)</Label>
                  <Input
                    type="number"
                    value={discount || ""}
                    onChange={(e) => setDiscount(parseFloat(e.target.value) || 0)}
                    placeholder="0.00"
                  />
                </div>
              ) : (
                <div className="space-y-2">
                  <Label>Desconto (%)</Label>
                  <Input
                    type="number"
                    value={discountPercent || ""}
                    onChange={(e) => setDiscountPercent(parseFloat(e.target.value) || 0)}
                    placeholder="0"
                    max={100}
                  />
                  {discountPercent > 0 && subtotal > 0 && (
                    <p className="text-xs text-muted-foreground">
                      = R$ {(subtotal * (discountPercent / 100)).toFixed(2)} de desconto
                    </p>
                  )}
                </div>
              )}
            </div>
          )}

          {showObservations && (
            <div className="space-y-2">
              <Label>Observações</Label>
              <Textarea
                value={observations}
                onChange={(e) => setObservations(e.target.value)}
                placeholder="Observações sobre a vaga..."
              />
            </div>
          )}

          {showTag && (
            <div className="space-y-2">
              <Label>Tag</Label>
              <Select value={tag} onValueChange={setTag}>
                <SelectTrigger>
                  <SelectValue placeholder="Selecione uma tag" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="Em andamento">Em andamento</SelectItem>
                  <SelectItem value="Pausado">Pausado</SelectItem>
                  <SelectItem value="Em espera">Em espera</SelectItem>
                  <SelectItem value="Finalizado">Finalizado</SelectItem>
                </SelectContent>
              </Select>
            </div>
          )}

          {/* Resumo da vaga */}
          {selectedVehicleId && (
            <Card className="bg-muted/30 border-border/50">
              <CardContent className="p-4 space-y-2">
                <h4 className="font-medium">Resumo da vaga</h4>
                <div className="space-y-1 text-sm">
                  <p className="flex items-center gap-2">
                    <User className="h-4 w-4 text-muted-foreground" />
                    <span>{selectedClient?.name}</span>
                  </p>
                  <p className="flex items-center gap-2">
                    <Car className="h-4 w-4 text-muted-foreground" />
                    <span>{selectedVehicle?.brand} {selectedVehicle?.model} {selectedVehicle?.plate && `- ${selectedVehicle.plate}`}</span>
                  </p>
                  <p className="flex items-center gap-2">
                    <Package className="h-4 w-4 text-muted-foreground" />
                    <span>{serviceCount} serviço(s) adicionado(s)</span>
                  </p>
                  <p className="flex items-center gap-2">
                    <DollarSign className="h-4 w-4 text-muted-foreground" />
                    <span>Sub-total: R$ {subtotal.toFixed(2)}</span>
                  </p>
                  {calculatedDiscount > 0 && (
                    <p className="flex items-center gap-2">
                      <Tag className="h-4 w-4 text-muted-foreground" />
                      <span>
                        Desconto: R$ {calculatedDiscount.toFixed(2)}
                        {discountType === 'percent' && ` (${discountPercent}%)`}
                      </span>
                    </p>
                  )}
                  <p className="flex items-center gap-2 font-medium">
                    <DollarSign className="h-4 w-4 text-primary" />
                    <span className="text-primary">Total: R$ {finalTotal.toFixed(2)}</span>
                  </p>
                  <p className="flex items-center gap-2">
                    <Calendar className="h-4 w-4 text-muted-foreground" />
                    <span>Entrada em {format(new Date(entryDate), "dd/MM/yyyy", { locale: ptBR })}</span>
                  </p>
                </div>
              </CardContent>
            </Card>
          )}

          {/* Botão de ação */}
          <Button
            className="w-full"
            size="lg"
            onClick={handleSubmit}
            disabled={createMutation.isPending || !selectedClientId || !selectedVehicleId}
          >
            {createMutation.isPending ? (
              <Loader2 className="h-5 w-5 animate-spin mr-2" />
            ) : (
              <Check className="h-5 w-5 mr-2" />
            )}
            Adicionar vaga
          </Button>
        </div>
      </DialogContent>

      {/* New Vehicle Modal */}
      <NewVehicleModal
        open={showNewVehicleModal}
        onOpenChange={setShowNewVehicleModal}
        onVehicleCreated={handleVehicleCreated}
      />

      {/* New Client Modal */}
      <NewClientModal
        open={showNewClientModal}
        onOpenChange={setShowNewClientModal}
        onClientCreated={(newClient) => {
          refetchClients();
          if (newClient?.id) {
            setSelectedClientId(newClient.id.toString());
          }
          setShowNewClientModal(false);
        }}
      />
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { Plus, Minus } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Switch } from "@/components/ui/switch";
import { toast } from "sonner";
import { NewCategoryModal } from "./NewCategoryModal";
import { CAC_ORIGIN_OPTIONS, CacOrigin } from "@/constants/origins";
import { format } from "date-fns";
interface Account {
  id: number;
  name: string;
  accepted_payment_methods?: string[] | null;
}

interface Category {
  id: number;
  name: string;
  type: string;
}

interface AddTransactionModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  type: 'entrada' | 'saida';
  onSuccess?: () => void;
  defaultAccountId?: string;
}

export function AddTransactionModal({ open, onOpenChange, type, onSuccess, defaultAccountId }: AddTransactionModalProps) {
  const { user } = useAuth();
  const [amount, setAmount] = useState("");
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [categoryId, setCategoryId] = useState("");
  const [accountId, setAccountId] = useState("");
  const [paymentMethod, setPaymentMethod] = useState("");
  const [date, setDate] = useState(format(new Date(), 'yyyy-MM-dd'));
  const [accounts, setAccounts] = useState<Account[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(false);
  const [companyId, setCompanyId] = useState<number | null>(null);
  const [newCategoryModalOpen, setNewCategoryModalOpen] = useState(false);
  const [isPaid, setIsPaid] = useState(true);
  const [isRecurring, setIsRecurring] = useState(false);
  const [recurringMonths, setRecurringMonths] = useState(1);
  const [includeInCac, setIncludeInCac] = useState(false);
  const [cacBucket, setCacBucket] = useState<'marketing' | 'vendas' | ''>('');
  const [cacOrigin, setCacOrigin] = useState<CacOrigin | ''>('');

  useEffect(() => {
    if (open) {
      if (defaultAccountId) {
        setAccountId(defaultAccountId);
      }
      fetchData();
    } else {
      resetForm();
    }
  }, [open, user?.id, type, defaultAccountId]);

  const fetchData = async () => {
    if (!user?.id) return;

    try {
      const { data: profile } = await supabase
        .from("profiles")
        .select("company_id")
        .eq("user_id", user.id)
        .single();

      if (!profile?.company_id) return;

      setCompanyId(profile.company_id);

      // Fetch accounts
      const { data: accountsData } = await supabase
        .from("accounts")
        .select("id, name, accepted_payment_methods")
        .eq("company_id", profile.company_id)
        .eq("is_active", true);

      // Fetch categories
      const typeFilter = type === 'entrada' ? 'Entrada' : 'Saida';
      const { data: categoriesData } = await supabase
        .from("categories")
        .select("id, name, type")
        .eq("company_id", profile.company_id)
        .eq("type", typeFilter);

      setAccounts((accountsData || []) as any);
      setCategories(categoriesData || []);
    } catch (error) {
      console.error("Error fetching data:", error);
    }
  };

  const handleSubmit = async () => {
    if (!amount || !name || !categoryId || !accountId || !companyId) {
      toast.error("Preencha todos os campos obrigatórios");
      return;
    }

    if (type === 'saida' && includeInCac && !cacBucket) {
      toast.error("Para controle de CAC, informe se o custo foi Vendas ou Marketing.");
      return;
    }

    if (paymentMethod && paymentMethod !== "Crédito" && paymentMethod !== "Débito") {
      const account = accounts.find(a => a.id.toString() === accountId.toString());
      if (account && account.accepted_payment_methods && !account.accepted_payment_methods.includes(paymentMethod)) {
        toast.error(`A forma de pagamento "${paymentMethod}" não é aceita pela conta selecionada.`);
        return;
      }
    }

    setLoading(true);

    try {
      const transactionType = type === 'entrada' ? 'Entrada' : 'Saida';
      const amountValue = parseFloat(amount);

      const transactionsToInsert = [];
      const monthsCount = (type === 'saida' && isRecurring) ? recurringMonths : 1;

      for (let i = 0; i < monthsCount; i++) {
        const d = new Date(date + "T12:00:00");
        d.setMonth(d.getMonth() + i);
        const nextDate = d.toISOString().split('T')[0];

        transactionsToInsert.push({
          company_id: companyId,
          name: monthsCount > 1 ? `${name} (${i + 1}/${monthsCount})` : name,
          description: description || null,
          amount: amountValue,
          type: transactionType,
          category_id: parseInt(categoryId),
          account_id: parseInt(accountId),
          payment_method: paymentMethod || null,
          transaction_date: nextDate,
          is_paid: i === 0 ? isPaid : false,
          include_in_cac: type === 'saida' ? includeInCac : false,
          cac_bucket: (type === 'saida' && includeInCac) ? cacBucket : null,
          cac_origin: (type === 'saida' && includeInCac) ? cacOrigin : null,
        });
      }

      const { error } = await supabase.from("transactions").insert(transactionsToInsert);

      if (error) throw error;

      toast.success(`${type === 'entrada' ? 'Entrada' : 'Saída'} registrada com sucesso!`);
      onOpenChange(false);
      resetForm();
      onSuccess?.();
    } catch (error) {
      console.error("Error creating transaction:", error);
      toast.error("Erro ao registrar transação");
    } finally {
      setLoading(false);
    }
  };

  const resetForm = () => {
    setAmount("");
    setName("");
    setDescription("");
    setCategoryId("");
    setAccountId("");
    setPaymentMethod("");
    setDate(format(new Date(), 'yyyy-MM-dd'));
    setIsPaid(true);
    setIsRecurring(false);
    setRecurringMonths(1);
    setIncludeInCac(false);
    setCacBucket('');
    setCacOrigin('');
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md max-h-[90vh] overflow-y-auto flex flex-col">
        <DialogHeader>
          <DialogTitle className={type === 'entrada' ? 'text-green-500' : 'text-red-500'}>
            Nova {type === 'entrada' ? 'Entrada' : 'Saída'}
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-4 overflow-y-auto pr-2">
          <div className="space-y-2">
            <Label>Valor *</Label>
            <Input
              type="number"
              placeholder="0,00"
              value={amount}
              onChange={e => setAmount(e.target.value)}
            />
          </div>

          <div className="space-y-2">
            <Label>Nome *</Label>
            <Input
              placeholder="Ex: Pagamento cliente"
              value={name}
              onChange={e => setName(e.target.value)}
            />
          </div>

          <div className="space-y-2">
            <Label>Descrição</Label>
            <Textarea
              placeholder="Descrição da transação..."
              value={description}
              onChange={e => setDescription(e.target.value)}
            />
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Categoria *</Label>
              <div className="flex gap-2 items-center">
                <div className="flex-1 min-w-0 overflow-hidden">
                  <Select value={categoryId} onValueChange={setCategoryId}>
                    <SelectTrigger>
                      <SelectValue placeholder="Selecione..." />
                    </SelectTrigger>
                    <SelectContent>
                      {categories.map(cat => (
                        <SelectItem key={cat.id} value={cat.id.toString()}>
                          {cat.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <Button
                  type="button"
                  size="icon"
                  variant="outline"
                  onClick={() => setNewCategoryModalOpen(true)}
                  title="Nova categoria"
                >
                  <Plus className="h-4 w-4" />
                </Button>
              </div>
            </div>

            <div className="space-y-2">
              <Label>Conta *</Label>
              <Select value={accountId} onValueChange={setAccountId}>
                <SelectTrigger>
                  <SelectValue placeholder="Selecione..." />
                </SelectTrigger>
                <SelectContent>
                  {accounts.map(acc => (
                    <SelectItem key={acc.id} value={acc.id.toString()}>
                      {acc.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>Forma de Pagamento</Label>
              <Select value={paymentMethod} onValueChange={setPaymentMethod}>
                <SelectTrigger>
                  <SelectValue placeholder="Selecione..." />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="Pix">Pix</SelectItem>
                  <SelectItem value="Dinheiro">Dinheiro</SelectItem>
                  <SelectItem value="Crédito">Crédito</SelectItem>
                  <SelectItem value="Débito">Débito</SelectItem>
                  <SelectItem value="Boleto">Boleto</SelectItem>
                  <SelectItem value="Transferência">Transferência</SelectItem>
                </SelectContent>
              </Select>
              {paymentMethod && accountId && !accounts.find(a => a.id.toString() === accountId)?.accepted_payment_methods?.includes(paymentMethod) && accounts.find(a => a.id.toString() === accountId)?.accepted_payment_methods && (
                <div className="mt-2 text-xs font-semibold text-red-500 bg-red-50 border border-red-200 p-2 rounded-md">
                  Atenção: A conta selecionada não costuma aceitar a forma de pagamento "{paymentMethod}".
                </div>
              )}
            </div>

            <div className="space-y-2">
              <Label>Data</Label>
              <Input
                type="date"
                value={date}
                onChange={e => setDate(e.target.value)}
              />
            </div>
          </div>

          {type === 'entrada' && (
            <div className="flex items-center justify-between rounded-lg border p-3">
              <div className="space-y-0.5">
                <Label>A entrada foi paga?</Label>
              </div>
              <Switch
                checked={isPaid}
                onCheckedChange={setIsPaid}
              />
            </div>
          )}

          {type === 'saida' && (
            <div className="space-y-4">
              <div className="flex items-center justify-between rounded-lg border p-3 bg-muted/20">
                <div className="space-y-0.5">
                  <Label>Custo de Aquisição de Cliente (CAC) ?</Label>
                  <p className="text-[11px] text-muted-foreground w-[90%]">
                    Se for um custo de comissão ou marketing que deve ser rateado para os novos clientes deste mês, ative esta opção.
                  </p>
                </div>
                <Switch
                  checked={includeInCac}
                  onCheckedChange={setIncludeInCac}
                />
              </div>

              {includeInCac && (
                <div className="p-3 border rounded-lg bg-orange-500/5 border-orange-500/20 space-y-4">
                  <div className="space-y-2">
                    <Label className="text-orange-700 dark:text-orange-300">Área do Custo *</Label>
                    <Select value={cacBucket} onValueChange={(v) => setCacBucket(v as any)}>
                      <SelectTrigger className="border-orange-500/30">
                        <SelectValue placeholder="Foi Marketing ou Vendas?" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="marketing">Marketing (ex: Tráfego)</SelectItem>
                        <SelectItem value="vendas">Vendas (ex: Comissão)</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>

                  <div className="space-y-2">
                    <Label className="text-orange-700 dark:text-orange-300">Origem Principal</Label>
                    <Select value={cacOrigin} onValueChange={(v) => setCacOrigin(v as any)}>
                      <SelectTrigger className="border-orange-500/30">
                        <SelectValue placeholder="Canal Específico ou Geral?" />
                      </SelectTrigger>
                      <SelectContent>
                        {CAC_ORIGIN_OPTIONS.map((opt) => (
                          <SelectItem key={opt} value={opt}>
                            {opt}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>
              )}

              <div className="flex items-center justify-between rounded-lg border p-3 mt-4">
                <div className="space-y-0.5">
                  <Label>Essa saída vai se repetir nos próximos meses?</Label>
                </div>
                <Switch
                  checked={isRecurring}
                  onCheckedChange={setIsRecurring}
                />
              </div>

              {isRecurring && (
                <div className="space-y-3 p-3 border rounded-lg bg-muted/50">
                  <Label>A saída irá se repetir por quantos meses?</Label>
                  <div className="flex items-center gap-4">
                    <Button
                      type="button"
                      variant="outline"
                      size="icon"
                      onClick={() => setRecurringMonths(Math.max(1, recurringMonths - 1))}
                    >
                      <Minus className="h-4 w-4" />
                    </Button>
                    <span className="font-semibold min-w-[3ch] text-center">
                      {recurringMonths} {recurringMonths === 1 ? 'mês' : 'meses'}
                    </span>
                    <Button
                      type="button"
                      variant="outline"
                      size="icon"
                      onClick={() => setRecurringMonths(recurringMonths + 1)}
                    >
                      <Plus className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              )}
            </div>
          )}

          <div className="flex gap-2 pt-4">
            <Button variant="outline" className="flex-1" onClick={() => onOpenChange(false)} disabled={loading}>
              Cancelar
            </Button>
            <Button
              className={`flex-1 ${type === 'entrada' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'}`}
              onClick={handleSubmit}
              disabled={loading}
            >
              {loading ? "Salvando..." : "Confirmar"}
            </Button>
          </div>
        </div>
      </DialogContent>

      <NewCategoryModal
        open={newCategoryModalOpen}
        onOpenChange={setNewCategoryModalOpen}
        defaultType={type}
        onSuccess={(newCategoryId) => {
          fetchData();
          setCategoryId(newCategoryId.toString());
        }}
      />
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { ArrowRight } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { format } from "date-fns";

interface Account {
  id: number;
  name: string;
}

interface AddTransferModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSuccess?: () => void;
}

export function AddTransferModal({ open, onOpenChange, onSuccess }: AddTransferModalProps) {
  const { user } = useAuth();
  const [amount, setAmount] = useState("");
  const [tedFee, setTedFee] = useState("");
  const [fromAccountId, setFromAccountId] = useState("");
  const [toAccountId, setToAccountId] = useState("");
  const [description, setDescription] = useState("");
  const [accounts, setAccounts] = useState<Account[]>([]);
  const [loading, setLoading] = useState(false);
  const [companyId, setCompanyId] = useState<number | null>(null);

  useEffect(() => {
    if (open) {
      fetchAccounts();
    }
  }, [open, user?.id]);

  const fetchAccounts = async () => {
    if (!user?.id) return;

    try {
      const { data: profile } = await supabase
        .from("profiles")
        .select("company_id")
        .eq("user_id", user.id)
        .single();

      if (!profile?.company_id) return;

      setCompanyId(profile.company_id);

      const { data: accountsData } = await supabase
        .from("accounts")
        .select("id, name")
        .eq("company_id", profile.company_id)
        .eq("is_active", true);

      setAccounts(accountsData || []);
    } catch (error) {
      console.error("Error fetching accounts:", error);
    }
  };

  const handleSubmit = async () => {
    if (!amount || !fromAccountId || !toAccountId || !companyId) {
      toast.error("Preencha todos os campos obrigatórios");
      return;
    }

    if (fromAccountId === toAccountId) {
      toast.error("Selecione contas diferentes");
      return;
    }

    setLoading(true);

    try {
      const amountValue = parseFloat(amount);
      const tedFeeValue = tedFee ? parseFloat(tedFee) : 0;
      const today = format(new Date(), 'yyyy-MM-dd');

      // Create transfer record
      const { data: transferRecord, error } = await supabase.from("transfers").insert({
        company_id: companyId,
        from_account_id: parseInt(fromAccountId),
        to_account_id: parseInt(toAccountId),
        amount: amountValue,
        description: description || null,
        transfer_date: today,
      }).select().single();

      if (error) throw error;

      if (tedFeeValue > 0 && transferRecord) {
        const { error: feeError } = await supabase.from("transactions").insert({
          company_id: companyId,
          type: 'Saida',
          name: 'Taxa de TED/DOC - Transferência',
          amount: tedFeeValue,
          account_id: parseInt(fromAccountId),
          transaction_date: today,
          is_paid: true,
          description: `Taxa da transferência para a conta ${accounts.find(a => a.id.toString() === toAccountId)?.name || 'destino'}`,
          origin_type: 'transfer_fee',
          origin_id: transferRecord.id
        });

        if (feeError) {
          console.error("Error creating fee transaction:", feeError);
          toast.error("Transferência realizada, mas erro ao registrar a taxa");
        }
      }

      toast.success("Transferência realizada com sucesso!");
      onOpenChange(false);
      resetForm();
      onSuccess?.();
    } catch (error) {
      console.error("Error creating transfer:", error);
      toast.error("Erro ao realizar transferência");
    } finally {
      setLoading(false);
    }
  };

  const resetForm = () => {
    setAmount("");
    setTedFee("");
    setFromAccountId("");
    setToAccountId("");
    setDescription("");
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle className="text-blue-500">Nova Transferência</DialogTitle>
        </DialogHeader>

        <div className="space-y-4">
          <div className="flex gap-4">
            <div className="space-y-2 flex-1">
              <Label>Valor *</Label>
              <Input
                type="number"
                placeholder="0,00"
                value={amount}
                onChange={e => setAmount(e.target.value)}
              />
            </div>
            <div className="space-y-2 flex-1 relative">
              <Label className="text-yellow-500">Taxa TED/DOC</Label>
              <Input
                type="number"
                placeholder="0,00"
                value={tedFee}
                onChange={e => setTedFee(e.target.value)}
                className="border-yellow-500/50 focus-visible:ring-yellow-500"
              />
            </div>
          </div>

          <div className="flex items-center gap-2">
            <div className="flex-1 space-y-2">
              <Label>De *</Label>
              <Select value={fromAccountId} onValueChange={setFromAccountId}>
                <SelectTrigger>
                  <SelectValue placeholder="Conta origem..." />
                </SelectTrigger>
                <SelectContent>
                  {accounts.map(acc => (
                    <SelectItem key={acc.id} value={acc.id.toString()}>
                      {acc.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <ArrowRight className="h-5 w-5 text-muted-foreground mt-6" />

            <div className="flex-1 space-y-2">
              <Label>Para *</Label>
              <Select value={toAccountId} onValueChange={setToAccountId}>
                <SelectTrigger>
                  <SelectValue placeholder="Conta destino..." />
                </SelectTrigger>
                <SelectContent>
                  {accounts.map(acc => (
                    <SelectItem key={acc.id} value={acc.id.toString()}>
                      {acc.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>

          <div className="space-y-2">
            <Label>Descrição (opcional)</Label>
            <Input
              placeholder="Ex: Reserva mensal"
              value={description}
              onChange={e => setDescription(e.target.value)}
            />
          </div>

          <div className="flex gap-2 pt-4">
            <Button variant="outline" className="flex-1" onClick={() => onOpenChange(false)} disabled={loading}>
              Cancelar
            </Button>
            <Button className="flex-1 bg-blue-600 hover:bg-blue-700" onClick={handleSubmit} disabled={loading}>
              {loading ? "Transferindo..." : "Transferir"}
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

﻿// @ts-nocheck
import { useState, useEffect } from "react";
import {
  Receipt,
  Search,
  Filter,
  Calendar,
  CheckCircle2,
  Clock,
  AlertTriangle,
  ChevronDown,
  ChevronUp,
  ExternalLink,
  MoreVertical,
  Check,
  RotateCcw,
  User,
  Car,
  Plus,
  DollarSign
} from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow
} from "@/components/ui/table";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { format } from "date-fns";
import { ptBR } from "date-fns/locale";
import { toast } from "sonner";
import { logger } from "@/lib/logger";
import { Skeleton } from "@/components/ui/skeleton";
import { settleTransaction, reverseTransaction } from "@/lib/financialTransactions";
import { cn } from "@/lib/utils";
import { Loader2 } from "lucide-react";
import SaleDetailsModal from "@/pages/Vendas/components/SaleDetailsModal";
import { SaleWithDetails } from "@/types/sales";
import { PaymentBlock, SalePayment } from "@/pages/Vendas/components/PaymentBlock";




interface BoletoManagementProps {
  accountId?: number | null;
  onRefreshRequired?: () => void;
}

interface BoletoRow {
  id: number;
  sale_id: number;
  total_amount: number;
  status: string;
  created_at: string;
  account_id: number;
  account_name: string;
  client_id: number | null;
  company_id: number;
  client_name: string;
  installments_count: number;
}

interface Installment {
  id: number;
  boleto_id: number;
  installment_number: number;
  amount: number;
  due_date: string;
  status: string;
  paid_amount: number | null;
  payment_date: string | null;
  transaction_id: number | null;
}

export function BoletoManagement({ accountId, onRefreshRequired }: BoletoManagementProps) {
  const { user } = useAuth();
  const [boletos, setBoletos] = useState<BoletoRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [expandedBoleto, setExpandedBoleto] = useState<number | null>(null);
  const [installments, setInstallments] = useState<Record<number, Installment[]>>({});
  const [statusFilter, setStatusFilter] = useState<string>("all");
  const [accountFilter, setAccountFilter] = useState<string>("all");
  const [selectedSaleDetails, setSelectedSaleDetails] = useState<SaleWithDetails | null>(null);
  const [loadingSaleId, setLoadingSaleId] = useState<number | null>(null);

  // States for payment confirmation and revert
  const [paymentModalOpen, setPaymentModalOpen] = useState(false);
  const [selectedInstallment, setSelectedInstallment] = useState<Installment | null>(null);
  const [selectedBoletoRow, setSelectedBoletoRow] = useState<BoletoRow | null>(null);
  const [payments, setPayments] = useState<SalePayment[]>([]);
  const [companyId, setCompanyId] = useState<number | null>(null);
  const [isPaying, setIsPaying] = useState(false);



  useEffect(() => {
    if (user?.id) fetchBoletos();
  }, [user?.id, accountId]);

  const fetchBoletos = async () => {
    setLoading(true);
    try {
      const { data: profile } = await supabase
        .from("profiles")
        .select("company_id")
        .eq("user_id", user?.id)
        .single();

      if (!profile) return;
      setCompanyId(profile.company_id);

      // Build query - fetch boletos with client info via join
      let query = supabase
        .from("boletos")
        .select(`
          id,
          sale_id,
          total_amount,
          status,
          created_at,
          account_id,
          client_id,
          company_id,
          clients (
            name
          ),
          accounts (
            name
          )
        `)
        .eq("company_id", profile.company_id)
        .order("created_at", { ascending: false });

      // We removed the accountId filter so the user can see ALL boletos across all accounts
      // if (accountId) {
      //   query = query.eq("account_id", accountId);
      // }

      const { data, error } = await query;

      if (error) throw error;

      // Now fetch installment counts for each boleto
      const boletoIds = (data || []).map(b => b.id);
      let installmentCounts: Record<number, number> = {};

      if (boletoIds.length > 0) {
        const { data: installData } = await supabase
          .from("boleto_installments")
          .select("boleto_id")
          .in("boleto_id", boletoIds);

        if (installData) {
          installData.forEach(inst => {
            installmentCounts[inst.boleto_id] = (installmentCounts[inst.boleto_id] || 0) + 1;
          });
        }
      }

      // Map to proper structure
      const mappedBoletos: BoletoRow[] = (data || []).map(b => ({
        id: b.id,
        sale_id: b.sale_id,
        total_amount: b.total_amount,
        status: b.status,
        created_at: b.created_at,
        account_id: b.account_id,
        account_name: (b.accounts as any)?.name || 'Conta N/A',
        client_id: b.client_id,
        company_id: b.company_id,
        client_name: (b.clients as any)?.name || 'Cliente N/A',
        installments_count: installmentCounts[b.id] || 0,
      }));

      setBoletos(mappedBoletos);
    } catch (error) {
      logger.error("Error fetching boletos:", error);
      toast.error("Erro ao carregar boletos");
    } finally {
      setLoading(false);
    }
  };

  const fetchInstallments = async (boletoId: number) => {
    try {
      const { data, error } = await supabase
        .from("boleto_installments")
        .select("id, boleto_id, installment_number, amount, due_date, status, paid_amount, payment_date, transaction_id")
        .eq("boleto_id", boletoId)
        .order("installment_number");

      if (error) throw error;
      setInstallments(prev => ({ ...prev, [boletoId]: data || [] }));
    } catch (error) {
      logger.error("Error fetching installments:", error);
      setInstallments(prev => ({ ...prev, [boletoId]: [] }));
      toast.error("Erro ao carregar parcelas do boleto. Verifique se a estrutura do banco está atualizada.");
    }
  };


  const toggleExpand = (boletoId: number) => {
    if (expandedBoleto === boletoId) {
      setExpandedBoleto(null);
    } else {
      setExpandedBoleto(boletoId);
      if (!installments[boletoId]) {
        fetchInstallments(boletoId);
      }
    }
  };

  const handleOpenSaleDetails = async (saleId: number) => {
    setLoadingSaleId(saleId);
    try {
      const { data, error } = await supabase
        .from("sales")
        .select(`
          *,
          client:clients(id, name, phone),
          vehicle:vehicles(id, brand, model, year, plate, size),
          sale_items(
            id, service_id, quantity, unit_price, total_price,
            service:services(id, name, base_price)
          )
        `)
        .eq("id", saleId)
        .single();

      if (error) {
        console.error("Error fetching sale details:", error);
        toast.error("Erro ao buscar detalhes da venda");
        return;
      }

      if (data) {
        const saleDetails: SaleWithDetails = {
          id: data.id,
          client_id: data.client_id,
          vehicle_id: data.vehicle_id,
          sale_date: data.sale_date,
          subtotal: data.subtotal,
          discount: data.discount,
          total: data.total,
          payment_method: data.payment_method,
          status: data.status,
          is_open: data.is_open,
          observations: data.observations,
          created_at: data.created_at,
          client: data.client,
          vehicle: data.vehicle,
          sale_items: data.sale_items || [],
        };
        setSelectedSaleDetails(saleDetails);
      }
    } catch (err) {
      console.error("Error fetching sale details:", err);
      toast.error("Erro inesperado ao buscar detalhes da venda");
    } finally {
      setLoadingSaleId(null);
    }
  };


  const updateInstallmentStatus = async (inst: Installment, newStatus: string) => {
    try {
      const updateData: any = {
        status: newStatus,
      };

      if (newStatus === 'paid') {
        updateData.payment_date = format(new Date(), 'yyyy-MM-dd');
        updateData.paid_amount = inst.amount;
      } else {
        updateData.payment_date = null;
        updateData.paid_amount = null;
      }

      const { error } = await supabase
        .from("boleto_installments")
        .update(updateData)
        .eq("id", inst.id);

      if (error) throw error;

      // === Liquidar/reverter transação vinculada ===
      if (inst.transaction_id) {
        if (newStatus === 'paid') {
          await settleTransaction({
            transactionId: inst.transaction_id,
            paymentDate: format(new Date(), 'yyyy-MM-dd'),
            paidAmount: inst.amount,
          });
        } else {
          // Reverter: marcar transação como não-paga
          await reverseTransaction(inst.transaction_id, 'unpay');
        }
      }

      toast.success("Status atualizado");
      fetchInstallments(inst.boleto_id);

      // Check if all installments are paid and update boleto status
      const { data: allInstallments } = await supabase
        .from("boleto_installments")
        .select("status")
        .eq("boleto_id", inst.boleto_id);

      if (allInstallments) {
        const allPaid = allInstallments.every(i => i.status === 'paid');
        if (allPaid) {
          await supabase
            .from("boletos")
            .update({ status: 'paid' })
            .eq("id", inst.boleto_id);
          fetchBoletos();
        } else {
          // If not all paid but status was 'paid', revert to pending
          const { data: boletoCheck } = await supabase
            .from("boletos")
            .select("status")
            .eq("id", inst.boleto_id)
            .single();

          if (boletoCheck?.status === 'paid') {
            await supabase
              .from("boletos")
              .update({ status: 'pending' })
              .eq("id", inst.boleto_id);
            fetchBoletos();
          }
        }
      }
      onRefreshRequired?.();
    } catch (error) {
      toast.error("Erro ao atualizar status");
    }
  };

  const handleOpenPaymentModal = async (inst: Installment, boleto: BoletoRow) => {
    setSelectedInstallment(inst);
    setSelectedBoletoRow(boleto);

    // Set default payment item
    setPayments([
      {
        tempId: Math.random().toString(36).substring(2, 9),
        payment_method: "Pix",
        amount: inst.amount,
        account_id: boleto.account_id || null, // Default to the boleto's account
        machine_id: null,
        installments: 1,
        due_date: new Date().toISOString(),
        status: 'received'
      }
    ]);

    setPaymentModalOpen(true);
  };

  const handleConfirmPayment = async () => {
    if (!selectedInstallment || !selectedBoletoRow) return;

    if (payments.length === 0) {
      toast.error("Adicione pelo menos uma forma de pagamento");
      return;
    }

    if (payments.some(p => !p.account_id)) {
      toast.error("Selecione a conta de destino para todos os pagamentos");
      return;
    }

    const totalToPay = selectedInstallment.amount;
    const totalPaid = payments.reduce((sum, p) => sum + p.amount, 0);

    if (Math.abs(totalPaid - totalToPay) > 0.01) {
      toast.error(`O valor total pago (R$ ${totalPaid.toFixed(2)}) deve ser igual ao valor da parcela (R$ ${totalToPay.toFixed(2)})`);
      return;
    }

    setIsPaying(true);

    try {
      // 1. Update the installment status to 'paid'
      const updateData: any = {
        status: 'paid',
        payment_date: format(new Date(), 'yyyy-MM-dd'),
        paid_amount: totalToPay,
      };

      const { error: instError } = await supabase
        .from("boleto_installments")
        .update(updateData)
        .eq("id", selectedInstallment.id);

      if (instError) throw instError;

      // 2. Handle the transactions and sale_payments
      for (let index = 0; index < payments.length; index++) {
        const p = payments[index];

        // Calculate net amount if card
        let finalNetAmount = p.amount;
        if ((p.payment_method === "Crédito" || p.payment_method === "Débito") && p.machine_id) {
          const { data: rateData } = await supabase
            .from("card_machine_rates")
            .select("rate")
            .eq("machine_id", p.machine_id)
            .eq("installments", p.installments)
            .single();

          if (rateData) {
            finalNetAmount = p.amount * (1 - rateData.rate / 100);
          }
        }

        // Create sale_payments record
        const { data: salePayment, error: salePaymentError } = await supabase
          .from("sale_payments")
          .insert({
            sale_id: selectedBoletoRow.sale_id,
            method: p.payment_method,
            amount: p.amount,
            account_id: p.account_id,
            machine_id: p.machine_id,
            installments: p.installments,
            status: p.status || 'received',
            company_id: selectedBoletoRow.company_id || companyId || 0
          })
          .select("id")
          .single();

        if (salePaymentError) throw salePaymentError;

        if (index === 0 && selectedInstallment.transaction_id) {
          // Update the main transaction
          const txUpdate: any = {
            is_paid: true,
            transaction_date: format(new Date(), 'yyyy-MM-dd'),
            amount: finalNetAmount,
            account_id: p.account_id,
            payment_method: p.payment_method,
            sale_payment_id: salePayment.id
          };

          const { error: txError } = await supabase
            .from("transactions")
            .update(txUpdate)
            .eq("id", selectedInstallment.transaction_id);

          if (txError) throw txError;
        } else {
          // Create a new transaction (either a split payment or because there was no transaction_id on the installment)
          const isFirstPaymentNoTx = index === 0 && !selectedInstallment.transaction_id;
          const txName = isFirstPaymentNoTx
            ? `Boleto #${selectedBoletoRow.sale_id} - ${selectedBoletoRow.client_name} - Parcela ${selectedInstallment.installment_number}`
            : `Boleto #${selectedBoletoRow.sale_id} - ${selectedBoletoRow.client_name} - Parcela ${selectedInstallment.installment_number} (Split)`;

          const txDescription = isFirstPaymentNoTx
            ? `Pagamento da Parcela ${selectedInstallment.installment_number}`
            : `Pagamento complementar da Parcela ${selectedInstallment.installment_number}`;

          const { data: newTx, error: newTxError } = await supabase
            .from("transactions")
            .insert({
              name: txName,
              amount: finalNetAmount,
              type: "Entrada",
              transaction_date: format(new Date(), 'yyyy-MM-dd'),
              account_id: p.account_id,
              company_id: selectedBoletoRow.company_id || companyId || 0,
              is_paid: true,
              payment_method: p.payment_method,
              sale_id: selectedBoletoRow.sale_id,
              description: txDescription,
              origin_type: "boleto_installment",
              origin_id: selectedInstallment.id,
              sale_payment_id: salePayment.id
            })
            .select("id")
            .single();

          if (newTxError) throw newTxError;

          // Update the first transaction_id on the installment if needed
          if (isFirstPaymentNoTx && newTx) {
            const { error: updateInstTxError } = await supabase
              .from("boleto_installments")
              .update({ transaction_id: newTx.id })
              .eq("id", selectedInstallment.id);

            if (updateInstTxError) throw updateInstTxError;
          }
        }
      }

      toast.success("Pagamento da parcela registrado!");
      setPaymentModalOpen(false);
      fetchInstallments(selectedInstallment.boleto_id);

      // Check if all installments are paid to update the main boleto status
      const { data: allInstallments } = await supabase
        .from("boleto_installments")
        .select("status")
        .eq("boleto_id", selectedInstallment.boleto_id);

      if (allInstallments) {
        const allPaid = allInstallments.every(i => i.status === 'paid');
        if (allPaid) {
          await supabase
            .from("boletos")
            .update({ status: 'paid' })
            .eq("id", selectedInstallment.boleto_id);
          fetchBoletos();
        } else {
          // Verify if boleto status needs update to pending
          const { data: boletoCheck } = await supabase
            .from("boletos")
            .select("status")
            .eq("id", selectedInstallment.boleto_id)
            .single();

          if (boletoCheck?.status === 'paid') {
            await supabase
              .from("boletos")
              .update({ status: 'pending' })
              .eq("id", selectedInstallment.boleto_id);
            fetchBoletos();
          }
        }
      }
      console.log("[BoletoManagement] Chamando onRefreshRequired (Confirmar Pagamento)...");
      await onRefreshRequired?.();
      console.log("[BoletoManagement] onRefreshRequired concluído.");
    } catch (err) {
      console.error("Error confirming payment:", err);
      toast.error("Erro ao registrar o pagamento");
    } finally {
      setIsPaying(false);
    }
  };

  const handleRevertPayment = async (inst: Installment, boleto: BoletoRow) => {
    try {
      console.log("[BoletoManagement] Iniciando reversão de pagamento da parcela:", inst.id);
      // 1. Update installment status to 'pending' and clear payment fields
      const { error: instError } = await supabase
        .from("boleto_installments")
        .update({
          status: 'pending',
          payment_date: null,
          paid_amount: null
        })
        .eq("id", inst.id);

      if (instError) throw instError;

      // 2. Revert the transactions and delete associated sale_payments
      if (inst.transaction_id) {
        const salePaymentIdsToDelete: number[] = [];

        // Fetch main transaction's sale_payment_id
        const { data: mainTx } = await supabase
          .from("transactions")
          .select("sale_payment_id")
          .eq("id", inst.transaction_id)
          .maybeSingle();

        if (mainTx?.sale_payment_id) {
          salePaymentIdsToDelete.push(mainTx.sale_payment_id);
        }

        // Fetch split transactions
        const { data: splitTxs } = await supabase
          .from("transactions")
          .select("id, sale_payment_id")
          .eq("origin_type", "boleto_installment")
          .eq("origin_id", inst.id)
          .neq("id", inst.transaction_id);

        if (splitTxs && splitTxs.length > 0) {
          for (const tx of splitTxs) {
            if (tx.sale_payment_id) {
              salePaymentIdsToDelete.push(tx.sale_payment_id);
            }
          }

          // Delete split transactions
          const splitIds = splitTxs.map(t => t.id);
          await supabase
            .from("transactions")
            .delete()
            .in("id", splitIds);
        }

        // Reset main transaction to unpaid, default method, original amount & original account
        const { error: resetTxError } = await supabase
          .from("transactions")
          .update({
            is_paid: false,
            payment_method: "Boleto",
            amount: inst.amount,
            account_id: boleto.account_id,
            sale_payment_id: null
          })
          .eq("id", inst.transaction_id);

        if (resetTxError) throw resetTxError;

        // Delete associated sale_payments
        if (salePaymentIdsToDelete.length > 0) {
          await supabase
            .from("sale_payments")
            .delete()
            .in("id", salePaymentIdsToDelete);
        }
      }

      toast.success("Pagamento revertido com sucesso!");
      fetchInstallments(inst.boleto_id);

      // 3. Update main boleto status if it was paid
      const { data: boletoCheck } = await supabase
        .from("boletos")
        .select("status")
        .eq("id", inst.boleto_id)
        .single();

      if (boletoCheck?.status === 'paid') {
        await supabase
          .from("boletos")
          .update({ status: 'pending' })
          .eq("id", inst.boleto_id);
        fetchBoletos();
      }
      console.log("[BoletoManagement] Chamando onRefreshRequired (Reverter Pagamento)...");
      await onRefreshRequired?.();
      console.log("[BoletoManagement] onRefreshRequired concluído.");
    } catch (err) {
      console.error("Error reverting payment:", err);
      toast.error("Erro ao reverter o pagamento");
    }
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'paid': return <Badge className="bg-green-500 hover:bg-green-600">Pago</Badge>;
      case 'pending': return <Badge variant="outline" className="text-amber-600 border-amber-600">Pendente</Badge>;
      case 'overdue': return <Badge variant="destructive">Atrasado</Badge>;
      default: return <Badge variant="secondary">{status}</Badge>;
    }
  };

  const uniqueAccounts = Array.from(
    new Map(boletos.map(b => [b.account_id, b.account_name])).entries()
  ).map(([id, name]) => ({ id, name }));

  const filteredBoletos = boletos.filter(b => {
    const clientName = b.client_name || "";
    const saleId = b.sale_id?.toString() || "";
    const search = searchTerm.toLowerCase().replace("#", "").trim();

    const matchesSearch = clientName.toLowerCase().includes(search) || saleId.includes(search);
    const matchesStatus = statusFilter === "all" || b.status === statusFilter;
    const matchesAccount = accountFilter === "all" || b.account_id.toString() === accountFilter;

    return matchesSearch && matchesStatus && matchesAccount;
  });


  if (loading) {
    return (
      <div className="space-y-4">
        <Skeleton className="h-12 w-full" />
        <Skeleton className="h-64 w-full" />
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
        <div className="relative w-full md:w-96">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Buscar por cliente ou venda..."
            className="pl-9"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2">
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="outline" size="sm" className="gap-2">
                <Filter className="h-4 w-4" /> Filtros
                {(statusFilter !== "all" || accountFilter !== "all") && (
                  <Badge variant="secondary" className="ml-1 px-1.5 py-0.5 text-[10px] bg-amber-500/20 text-amber-500 border-none">
                    {(statusFilter !== "all" ? 1 : 0) + (accountFilter !== "all" ? 1 : 0)}
                  </Badge>
                )}
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end" className="w-56 bg-background border border-border/80">
              <div className="p-2 text-xs font-semibold text-muted-foreground border-b border-border/50">Status</div>
              <DropdownMenuItem onClick={() => setStatusFilter("all")} className={cn("cursor-pointer", statusFilter === "all" && "bg-muted font-medium")}>
                Todos
              </DropdownMenuItem>
              <DropdownMenuItem onClick={() => setStatusFilter("pending")} className={cn("cursor-pointer", statusFilter === "pending" && "bg-muted font-medium")}>
                Pendente
              </DropdownMenuItem>
              <DropdownMenuItem onClick={() => setStatusFilter("paid")} className={cn("cursor-pointer", statusFilter === "paid" && "bg-muted font-medium")}>
                Pago
              </DropdownMenuItem>
              <DropdownMenuItem onClick={() => setStatusFilter("overdue")} className={cn("cursor-pointer", statusFilter === "overdue" && "bg-muted font-medium")}>
                Atrasado
              </DropdownMenuItem>

              {uniqueAccounts.length > 0 && (
                <>
                  <div className="p-2 text-xs font-semibold text-muted-foreground border-t border-border/50 border-b border-b-border/50">Conta</div>
                  <DropdownMenuItem onClick={() => setAccountFilter("all")} className={cn("cursor-pointer", accountFilter === "all" && "bg-muted font-medium")}>
                    Todas as Contas
                  </DropdownMenuItem>
                  {uniqueAccounts.map(acc => (
                    <DropdownMenuItem
                      key={acc.id}
                      onClick={() => setAccountFilter(acc.id.toString())}
                      className={cn("cursor-pointer", accountFilter === acc.id.toString() && "bg-muted font-medium")}
                    >
                      {acc.name}
                    </DropdownMenuItem>
                  ))}
                </>
              )}

              {(statusFilter !== "all" || accountFilter !== "all") && (
                <>
                  <div className="border-t border-border/50 my-1" />
                  <DropdownMenuItem
                    onClick={() => {
                      setStatusFilter("all");
                      setAccountFilter("all");
                    }}
                    className="text-destructive focus:text-destructive font-medium justify-center cursor-pointer"
                  >
                    Limpar Filtros
                  </DropdownMenuItem>
                </>
              )}
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
      </div>

      {/* Desktop Table */}
      <div className="hidden md:block">
        <Card className="border-border/50">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="w-10"></TableHead>
                <TableHead>Venda</TableHead>
                <TableHead>Cliente</TableHead>
                <TableHead>Conta</TableHead>
                <TableHead>Total</TableHead>
                <TableHead>Parcelas</TableHead>
                <TableHead>Status</TableHead>
                <TableHead>Data</TableHead>
                <TableHead className="w-10"></TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredBoletos.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={9} className="text-center py-10 text-muted-foreground">
                    Nenhum boleto encontrado
                  </TableCell>
                </TableRow>
              ) : (
                filteredBoletos.map(boleto => (
                  <>
                    <TableRow key={boleto.id} className="cursor-pointer hover:bg-muted/30" onClick={() => toggleExpand(boleto.id)}>
                      <TableCell>
                        {expandedBoleto === boleto.id ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
                      </TableCell>
                      <TableCell className="font-medium">#{boleto.sale_id}</TableCell>
                      <TableCell>{boleto.client_name}</TableCell>
                      <TableCell className="text-muted-foreground">{boleto.account_name}</TableCell>
                      <TableCell>R$ {Number(boleto.total_amount).toFixed(2)}</TableCell>
                      <TableCell>{boleto.installments_count}x</TableCell>
                      <TableCell>{getStatusBadge(boleto.status)}</TableCell>
                      <TableCell className="text-xs text-muted-foreground">
                        {format(new Date(boleto.created_at), "dd/MM/yyyy")}
                      </TableCell>
                      <TableCell onClick={(e) => e.stopPropagation()}>
                        <DropdownMenu>
                          <DropdownMenuTrigger asChild>
                            <Button variant="ghost" size="icon" className="h-8 w-8"><MoreVertical className="h-4 w-4" /></Button>
                          </DropdownMenuTrigger>
                          <DropdownMenuContent align="end">
                            <DropdownMenuItem
                              className="gap-2 cursor-pointer"
                              onClick={() => handleOpenSaleDetails(boleto.sale_id)}
                              disabled={loadingSaleId === boleto.sale_id}
                            >
                              {loadingSaleId === boleto.sale_id ? (
                                <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />
                              ) : (
                                <ExternalLink className="h-4 w-4" />
                              )}
                              Ver Venda
                            </DropdownMenuItem>
                          </DropdownMenuContent>

                        </DropdownMenu>
                      </TableCell>
                    </TableRow>

                    {expandedBoleto === boleto.id && (
                      <TableRow className="bg-muted/10 border-b">
                        <TableCell colSpan={9} className="p-0">
                          <div className="p-4 bg-muted/5 animate-in slide-in-from-top-2 duration-200">
                            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-4">
                              {!installments[boleto.id] ? (
                                <div className="col-span-4 py-4 text-center text-xs text-muted-foreground">Carregando parcelas...</div>
                              ) : installments[boleto.id].length === 0 ? (
                                <div className="col-span-4 py-4 text-center text-xs text-muted-foreground">Nenhuma parcela registrada</div>
                              ) : (
                                installments[boleto.id].map(inst => (
                                  <Card key={inst.id} className="bg-background border-border/40">
                                    <CardContent className="p-3 space-y-2">
                                      <div className="flex justify-between items-start">
                                        <span className="text-[10px] font-bold text-muted-foreground uppercase">Parcela {inst.installment_number}</span>
                                        {getStatusBadge(inst.status)}
                                      </div>
                                      <div className="text-lg font-bold">R$ {Number(inst.amount).toFixed(2)}</div>
                                      <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                                        <Calendar className="h-3 w-3" />
                                        Venc: {format(new Date(inst.due_date + 'T12:00:00'), "dd/MM/yyyy")}
                                      </div>

                                      {inst.status !== 'paid' ? (
                                        <Button
                                          variant="outline"
                                          size="sm"
                                          className="w-full h-8 text-xs gap-1 mt-1 border-green-500/50 text-green-600 hover:bg-green-500/10"
                                          onClick={() => handleOpenPaymentModal(inst, boleto)}
                                        >
                                          <Check className="h-3 w-3" /> Baixar Parcela
                                        </Button>
                                      ) : (
                                        <div className="space-y-2 mt-1">
                                          <div className="text-[10px] text-green-600 flex items-center gap-1 italic">
                                            <CheckCircle2 className="h-3 w-3" /> Pago em {inst.payment_date ? format(new Date(inst.payment_date + 'T12:00:00'), "dd/MM/yy") : ''}
                                          </div>
                                          <Button
                                            variant="outline"
                                            size="sm"
                                            className="w-full h-8 text-xs gap-1 mt-1 border-amber-500/50 text-amber-600 hover:bg-amber-500/10"
                                            onClick={() => handleRevertPayment(inst, boleto)}
                                          >
                                            <RotateCcw className="h-3 w-3" /> Reverter Pagamento
                                          </Button>
                                        </div>
                                      )}
                                    </CardContent>
                                  </Card>
                                ))
                              )}
                            </div>
                          </div>
                        </TableCell>
                      </TableRow>
                    )}
                  </>
                ))
              )}
            </TableBody>
          </Table>
        </Card>
      </div>

      {/* Mobile Cards */}
      <div className="grid grid-cols-1 gap-3 md:hidden">
        {filteredBoletos.length === 0 ? (
          <div className="text-center py-10 text-muted-foreground border border-border/50 rounded-xl bg-card">
            Nenhum boleto encontrado
          </div>
        ) : (
          filteredBoletos.map(boleto => (
            <div key={boleto.id} className="rounded-xl border border-border/50 bg-card/30 p-4 space-y-3 cursor-pointer select-none transition-colors hover:bg-card/40" onClick={() => toggleExpand(boleto.id)}>
              <div className="flex items-start justify-between gap-2">
                <div>
                  <p className="text-sm font-semibold text-foreground leading-snug">
                    #{boleto.sale_id} — {boleto.client_name}
                  </p>
                  <p className="text-[10px] text-muted-foreground mt-0.5">
                    {format(new Date(boleto.created_at), "dd/MM/yyyy")}
                  </p>
                </div>
                <div className="flex flex-col items-end gap-1 shrink-0">
                  {getStatusBadge(boleto.status)}
                  {expandedBoleto === boleto.id ? <ChevronUp className="h-4 w-4 text-muted-foreground mt-1" /> : <ChevronDown className="h-4 w-4 text-muted-foreground mt-1" />}
                </div>
              </div>

              <div className="flex items-center gap-2">
                <div className="w-7 h-7 rounded-lg bg-primary/10 flex items-center justify-center shrink-0">
                  <Receipt className="h-3.5 w-3.5 text-primary" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-xs font-medium truncate">
                    {boleto.account_name}
                  </p>
                  <Badge variant="outline" className="text-[9px] mt-0.5 bg-muted text-muted-foreground border-border/50">
                    {boleto.installments_count}x Boleto
                  </Badge>
                </div>
                <p className="text-sm font-bold text-foreground whitespace-nowrap">
                  R$ {Number(boleto.total_amount).toFixed(2)}
                </p>
              </div>

              <div className="pt-2 border-t border-border/40 flex justify-end">
                <Button
                  variant="ghost"
                  size="sm"
                  className="h-8 text-xs gap-1.5 px-2"
                  onClick={(e) => {
                    e.stopPropagation();
                    handleOpenSaleDetails(boleto.sale_id);
                  }}
                  disabled={loadingSaleId === boleto.sale_id}
                >
                  {loadingSaleId === boleto.sale_id ? (
                    <Loader2 className="h-3.5 w-3.5 animate-spin text-muted-foreground" />
                  ) : (
                    <ExternalLink className="h-3.5 w-3.5 text-muted-foreground" />
                  )}
                  Ver Venda
                </Button>
              </div>

              {expandedBoleto === boleto.id && (
                <div className="pt-3 mt-3 border-t border-border/40 space-y-2 relative" onClick={(e) => e.stopPropagation()}>
                  <h4 className="text-xs font-semibold mb-2 flex items-center gap-1.5 text-foreground">
                    <Clock className="w-3.5 h-3.5" /> Detalhes das Parcelas
                  </h4>
                  {!installments[boleto.id] ? (
                    <p className="py-4 text-center text-xs text-muted-foreground">Carregando parcelas...</p>
                  ) : installments[boleto.id].length === 0 ? (
                    <p className="py-4 text-center text-xs text-muted-foreground">Nenhuma parcela registrada</p>
                  ) : (
                    <div className="grid gap-2">
                      {installments[boleto.id].map(inst => (
                        <div key={inst.id} className="flex flex-col p-2.5 rounded-md bg-background border text-xs gap-2 shadow-sm">
                          <div className="flex items-start justify-between gap-2">
                            <div className="flex flex-col">
                              <span className="font-semibold text-[10px] text-muted-foreground uppercase">Parcela {inst.installment_number}</span>
                              <span className="text-[10px] text-muted-foreground mt-0.5">Venc: {format(new Date(inst.due_date + 'T12:00:00'), "dd/MM/yyyy")}</span>
                            </div>
                            <div className="flex flex-col items-end gap-1">
                              {getStatusBadge(inst.status)}
                              <span className="font-semibold text-sm">R$ {Number(inst.amount).toFixed(2)}</span>
                            </div>
                          </div>

                          <div className="flex flex-col mt-1 pt-3 border-t border-border/50 space-y-2">
                            {inst.status !== 'paid' ? (
                              <Button
                                variant="outline"
                                size="sm"
                                className="w-full h-8 text-[10px] px-2 gap-1 border-green-500/50 text-green-600 hover:bg-green-500/10"
                                onClick={() => handleOpenPaymentModal(inst, boleto)}
                              >
                                <Check className="h-3 w-3 inline" /> Baixar Parcela
                              </Button>
                            ) : (
                              <>
                                <div className="text-[10px] text-green-600 flex items-center justify-center gap-1 italic mb-1">
                                  <CheckCircle2 className="h-3 w-3" /> Pago em {inst.payment_date ? format(new Date(inst.payment_date + 'T12:00:00'), "dd/MM/yy") : ''}
                                </div>
                                <Button
                                  variant="outline"
                                  size="sm"
                                  className="w-full h-8 text-[10px] px-2 gap-1 border-amber-500/50 text-amber-600 hover:bg-amber-500/10"
                                  onClick={() => handleRevertPayment(inst, boleto)}
                                >
                                  <RotateCcw className="h-3 w-3 inline" /> Reverter Pagamento
                                </Button>
                              </>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}
            </div>
          ))
        )}
      </div>

      <SaleDetailsModal
        open={!!selectedSaleDetails}
        onOpenChange={(open) => !open && setSelectedSaleDetails(null)}
        sale={selectedSaleDetails}
      />

      {/* Modal de confirmação de pagamento */}
      <Dialog open={paymentModalOpen} onOpenChange={(open) => !open && setPaymentModalOpen(false)}>
        <DialogContent className="w-[95vw] max-w-xl rounded-lg max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <DollarSign className="h-5 w-5 text-success" />
              Confirmar Pagamento
            </DialogTitle>
            <DialogDescription>
              Confirme as formas de pagamento antes de registrar o recebimento.
            </DialogDescription>
          </DialogHeader>

          {selectedInstallment && selectedBoletoRow && (
            <div className="space-y-5 py-2">
              {/* Seção de Pagamentos */}
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <Label className="text-sm font-semibold">Pagamentos</Label>
                  <Button
                    variant="outline"
                    size="sm"
                    className="h-8 gap-1 text-xs"
                    onClick={() => {
                      const totalToPay = selectedInstallment.amount;
                      const currentPaid = payments.reduce((acc, curr) => acc + curr.amount, 0);
                      const remaining = Math.max(0, totalToPay - currentPaid);
                      setPayments([...payments, {
                        tempId: Math.random().toString(36).substring(2, 9),
                        payment_method: "Pix",
                        amount: remaining,
                        account_id: payments[0]?.account_id || null,
                        machine_id: null,
                        installments: 1,
                        due_date: new Date().toISOString(),
                        status: 'received'
                      }]);
                    }}
                  >
                    <Plus className="h-3.5 w-3.5" />
                    Adicionar Forma
                  </Button>
                </div>

                <div className="space-y-3">
                  {payments.map((p, index) => (
                    <PaymentBlock
                      key={p.tempId}
                      payment={p}
                      isFirst={index === 0}
                      companyId={companyId || selectedBoletoRow.company_id || 0}
                      totalRemaining={selectedInstallment.amount - payments.reduce((acc, curr, i) => i < index ? acc + curr.amount : acc, 0)}
                      onUpdate={(updated) => setPayments(payments.map(item => item.tempId === p.tempId ? updated : item))}
                      onRemove={() => setPayments(payments.filter(item => item.tempId !== p.tempId))}
                    />
                  ))}
                </div>

                {(() => {
                  const totalToPay = selectedInstallment.amount;
                  const paidTotal = payments.reduce((acc, p) => acc + p.amount, 0);
                  const diff = paidTotal - totalToPay;
                  const isBalanced = Math.abs(diff) < 0.01;
                  const isExcess = diff > 0.01;
                  const isShort = diff < -0.01;

                  return (
                    <div className={cn(
                      "p-3 rounded-lg text-sm font-medium space-y-1 border",
                      isBalanced
                        ? "bg-green-500/10 text-green-600 border-green-500/20"
                        : isExcess
                          ? "bg-amber-500/10 text-amber-600 border-amber-500/20"
                          : "bg-red-500/10 text-red-600 border-red-500/20"
                    )}>
                      <div className="flex justify-between items-center">
                        <span>Total Pago: R$ {paidTotal.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                        <span>Total Parcela: R$ {totalToPay.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      </div>
                      {!isBalanced && (
                        <div className={cn(
                          "text-xs pt-1 border-t flex items-center gap-1.5",
                          isExcess ? "border-amber-500/20" : "border-red-500/20"
                        )}>
                          {isExcess ? (
                            <span>⚠ Valor superior em <strong>R$ {Math.abs(diff).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</strong></span>
                          ) : (
                            <span>⚠ Restam <strong>R$ {Math.abs(diff).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</strong> para concluir</span>
                          )}
                        </div>
                      )}
                    </div>
                  );
                })()}
              </div>
            </div>
          )}

          <DialogFooter className="flex-row gap-2 justify-end sm:justify-end">
            <Button variant="outline" onClick={() => setPaymentModalOpen(false)}>
              Cancelar
            </Button>
            <Button
              className="bg-success hover:bg-success/90 text-white gap-2"
              onClick={handleConfirmPayment}
              disabled={isPaying}
            >
              {isPaying ? (
                <Loader2 className="h-4 w-4 animate-spin" />
              ) : (
                <Check className="h-4 w-4" />
              )}
              Confirmar Pagamento
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

// @ts-nocheck
import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle, 
  DialogFooter 
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { Loader2, Percent, CreditCard, Clock, Calendar as CalendarIcon, Save } from "lucide-react";
import { cn } from "@/lib/utils";

interface Rate {
  installments: number;
  rate: number;
}

interface CardMachineModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  machineId?: number | null;
  onSuccess: () => void;
}

interface MachineFormData {
  name: string;
  account_id: string;
  machine_type: "credit" | "debit" | "both";
  max_installments: number;
  is_anticipated: boolean;
  anticipation_type: "hours" | "days";
  anticipation_value: number;
  debit_rate: number;
  is_active: boolean;
}

export function CardMachineModal({ open, onOpenChange, machineId, onSuccess }: CardMachineModalProps) {
  const { user } = useAuth();
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(false);
  const [accounts, setAccounts] = useState<any[]>([]);
  const [rates, setRates] = useState<Rate[]>([]);
  // Texto digitado em cada input de taxa (evita que o React apague a vírgula durante a digitação)
  const [rateInputs, setRateInputs] = useState<Map<number, string>>(new Map());
  
  const { register, handleSubmit, watch, setValue, reset, formState: { errors } } = useForm<MachineFormData>({
    defaultValues: {
      name: "",
      account_id: "none",
      machine_type: "credit",
      max_installments: 12,
      is_anticipated: false,
      anticipation_type: "days",
      anticipation_value: 1,
      debit_rate: 0,
      is_active: true
    }
  });

  const isAnticipated = watch("is_anticipated");
  const anticipationType = watch("anticipation_type");
  const maxInstallments = watch("max_installments");
  const machineType = watch("machine_type");

  useEffect(() => {
    if (open) {
      fetchAccounts();
      if (machineId) {
        fetchMachineData();
      } else {
        reset({
          name: "",
          account_id: "none",
          machine_type: "credit",
          max_installments: 12,
          is_anticipated: false,
          anticipation_type: "days",
          anticipation_value: 1,
          debit_rate: 0,
          is_active: true
        });
        // Initialize default rates (0%)
        const initialRates = Array.from({ length: 12 }, (_, i) => ({
          installments: i + 1,
          rate: 0
        }));
        setRates(initialRates);
        setRateInputs(new Map(initialRates.map(r => [r.installments, ""])));
      }
    }
  }, [open, machineId]);

  // Adjust rates array when maxInstallments changes
  useEffect(() => {
    const currentMax = rates.length;
    if (maxInstallments > currentMax) {
      const newRates = [...rates];
      for (let i = currentMax + 1; i <= maxInstallments; i++) {
        newRates.push({ installments: i, rate: 0 });
      }
      setRates(newRates);
    } else if (maxInstallments < currentMax) {
      setRates(rates.slice(0, maxInstallments));
    }
  }, [maxInstallments]);

  const fetchAccounts = async () => {
    try {
      const { data: profile } = await supabase
        .from("profiles")
        .select("company_id")
        .eq("user_id", user?.id)
        .single();

      if (!profile) return;

      const { data } = await supabase
        .from("accounts")
        .select("id, name")
        .eq("company_id", profile.company_id)
        .eq("is_active", true);

      setAccounts(data || []);
    } catch (error) {
      console.error("Error fetching accounts:", error);
    }
  };

  const fetchMachineData = async () => {
    setFetching(true);
    try {
      const { data: machine, error: mError } = await supabase
        .from("card_machines")
        .select("*")
        .eq("id", machineId)
        .single();

      if (mError) throw mError;

      reset({
        name: machine.name,
        account_id: machine.account_id?.toString() || "none",
        machine_type: machine.machine_type || "credit",
        max_installments: machine.max_installments || 12,
        is_anticipated: machine.is_anticipated || false,
        anticipation_type: (machine.anticipation_type as any) || "days",
        anticipation_value: machine.anticipation_value || 1,
        debit_rate: machine.debit_rate || 0,
        is_active: machine.is_active ?? true
      });

      const { data: ratesData, error: rError } = await supabase
        .from("card_machine_rates")
        .select("installments, rate")
        .eq("machine_id", machineId)
        .order("installments", { ascending: true });

      if (rError) throw rError;

      // Ensure we have rates for all installments up to max_installments
      const fullRates = Array.from({ length: machine.max_installments || 12 }, (_, i) => {
        const existing = ratesData?.find(r => r.installments === i + 1);
        return existing || { installments: i + 1, rate: 0 };
      });
      
      setRates(fullRates);
      setRateInputs(new Map(fullRates.map(r => [r.installments, r.rate ? r.rate.toString().replace(".", ",") : ""])));
    } catch (error) {
      console.error("Error fetching machine data:", error);
      toast.error("Erro ao carregar dados da maquininha");
    } finally {
      setFetching(false);
    }
  };

  const handleRateInputChange = (installments: number, value: string) => {
    // Aceita apenas dígitos, vírgula e ponto
    const sanitized = value.replace(/[^0-9.,]/g, "");
    setRateInputs(prev => new Map(prev).set(installments, sanitized));
    const numValue = parseFloat(sanitized.replace(",", ".")) || 0;
    setRates(prev => prev.map(r =>
      r.installments === installments ? { ...r, rate: numValue } : r
    ));
  };

  const handleRateInputBlur = (installments: number) => {
    // Ao sair do campo, normaliza o texto para o valor numérico armazenado
    const rate = rates.find(r => r.installments === installments);
    if (rate !== undefined) {
      setRateInputs(prev => new Map(prev).set(installments, rate.rate ? rate.rate.toString().replace(".", ",") : ""));
    }
  };

  const onSubmit = async (data: MachineFormData) => {
    setLoading(true);
    try {
      const { data: profile } = await supabase
        .from("profiles")
        .select("company_id")
        .eq("user_id", user?.id)
        .single();

      if (!profile?.company_id) throw new Error("Empresa não encontrada");

      const isDebitOnly = data.machine_type === "debit";
      const isCredit = data.machine_type === "credit" || data.machine_type === "both";
      const isDebit = data.machine_type === "debit" || data.machine_type === "both";

      const machinePayload = {
        company_id: profile.company_id,
        name: data.name,
        account_id: (data.account_id && data.account_id !== "none") ? parseInt(data.account_id) : null,
        machine_type: data.machine_type,
        max_installments: isCredit ? data.max_installments : 1,
        is_anticipated: isCredit ? data.is_anticipated : false,
        anticipation_type: isCredit && data.is_anticipated ? data.anticipation_type : null,
        anticipation_value: isCredit && data.is_anticipated ? data.anticipation_value : null,
        debit_rate: isDebit ? data.debit_rate : 0,
        is_active: data.is_active
      };

      let currentMachineId = machineId;

      if (machineId) {
        const { error } = await supabase
          .from("card_machines")
          .update(machinePayload)
          .eq("id", machineId);
        if (error) throw error;
      } else {
        const { data: newMachine, error } = await supabase
          .from("card_machines")
          .insert(machinePayload)
          .select()
          .single();
        if (error) throw error;
        currentMachineId = newMachine.id;
      }

      // Upsert rates
      // First delete existing rates to avoid conflicts or leftovers if max_installments decreased
      const { error: delError } = await supabase
        .from("card_machine_rates")
        .delete()
        .eq("machine_id", currentMachineId);
      
      if (delError) throw delError;

      // For debit ONLY machines, we don't need to insert card_machine_rates anymore
      // We rely on debit_rate column in card_machines.
      // But for backward compatibility or ease, let's just use the debit_rate column directly
      // and only insert credit rates into card_machine_rates if it's credit or both.
      if (isCredit) {
        const ratesPayload = rates.map(r => ({
          company_id: profile.company_id,
          machine_id: currentMachineId,
          installments: r.installments,
          rate: r.rate
        }));

        const { error: ratesError } = await supabase
          .from("card_machine_rates")
          .insert(ratesPayload);

        if (ratesError) throw ratesError;
      }

      toast.success(machineId ? "Maquininha atualizada!" : "Maquininha cadastrada!");
      onSuccess();
      onOpenChange(false);
    } catch (error: any) {
      console.error("Error saving card machine:", error);
      toast.error(error.message || "Erro ao salvar maquininha");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[600px] max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <CreditCard className="h-5 w-5 text-primary" />
            {machineId ? "Editar Maquininha" : "Nova Maquininha"}
          </DialogTitle>
        </DialogHeader>

        {fetching ? (
          <div className="py-20 flex justify-center">
            <Loader2 className="h-8 w-8 animate-spin text-primary" />
          </div>
        ) : (
          <form id="card-machine-form" onSubmit={handleSubmit(onSubmit)} className="space-y-6 py-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="name">Nome da Maquininha</Label>
                <Input 
                  id="name" 
                  placeholder="Ex: Getnet, Stone, PagSeguro" 
                  {...register("name", { required: "Nome é obrigatório" })}
                />
                {errors.name && <p className="text-xs text-red-500">{errors.name.message}</p>}
              </div>

              <div className="space-y-2">
                <Label htmlFor="account_id">Conta de Recebimento</Label>
                <Select 
                  value={watch("account_id")} 
                  onValueChange={(val) => setValue("account_id", val)}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Selecione a conta" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="none">Nenhuma conta vinculada</SelectItem>
                    {accounts.map(acc => (
                      <SelectItem key={acc.id} value={acc.id.toString()}>
                        {acc.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            {/* Tipo de Maquininha: Crédito ou Débito */}
            <div className="space-y-2">
              <Label className="text-sm font-semibold">Tipo de Maquininha</Label>
              <div className="flex p-1 bg-muted rounded-lg">
                <Button
                  type="button"
                  variant={machineType === "credit" ? "default" : "ghost"}
                  size="sm"
                  className="flex-1 h-9 text-sm gap-2"
                  onClick={() => setValue("machine_type", "credit")}
                >
                  <CreditCard className="h-4 w-4" />
                  Crédito
                </Button>
                <Button
                  type="button"
                  variant={machineType === "debit" ? "default" : "ghost"}
                  size="sm"
                  className="flex-1 h-9 text-sm gap-2"
                  onClick={() => {
                    setValue("machine_type", "debit");
                    setValue("max_installments", 1);
                    setValue("is_anticipated", false);
                  }}
                >
                  <CreditCard className="h-4 w-4" />
                  Débito
                </Button>
                <Button
                  type="button"
                  variant={machineType === "both" ? "default" : "ghost"}
                  size="sm"
                  className="flex-1 h-9 text-sm gap-2"
                  onClick={() => setValue("machine_type", "both")}
                >
                  <CreditCard className="h-4 w-4" />
                  Ambos
                </Button>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {(machineType === "credit" || machineType === "both") && (
                <div className="space-y-2">
                  <Label htmlFor="max_installments">Máximo de Parcelas</Label>
                  <Input 
                    id="max_installments" 
                    type="number" 
                    min={1} 
                    max={24}
                    {...register("max_installments", { valueAsNumber: true })}
                  />
                </div>
              )}

              <div className={cn(
                "flex items-center justify-between p-3 border rounded-lg bg-muted/30",
                machineType === "debit" && "col-span-full"
              )}>
                <div className="space-y-0.5">
                  <Label>Maquininha Ativa</Label>
                  <p className="text-[10px] text-muted-foreground">Disponível para novos pagamentos</p>
                </div>
                <Switch 
                  checked={watch("is_active")} 
                  onCheckedChange={(val) => setValue("is_active", val)} 
                />
              </div>
            </div>

            {/* --- DÉBITO: apenas taxa única --- */}
            {(machineType === "debit" || machineType === "both") && (
              <div className="space-y-4 p-4 border rounded-xl bg-primary/5 animate-in fade-in slide-in-from-top-2">
                <div className="flex items-center gap-2">
                  <Percent className="h-4 w-4 text-primary" />
                  <Label className="text-base font-semibold">Taxa no Débito</Label>
                </div>
                <p className="text-[10px] text-muted-foreground -mt-2">
                  Toda venda no débito será em 1x com essa taxa aplicada.
                </p>
                <div className="max-w-[200px]">
                  <div className="relative">
                    <Input 
                      className="pr-6 text-sm"
                      value={watch("debit_rate") ? watch("debit_rate").toString().replace(".", ",") : ""}
                      onChange={(e) => {
                        const val = parseFloat(e.target.value.replace(",", ".")) || 0;
                        setValue("debit_rate", val);
                      }}
                      placeholder="0,00"
                    />
                    <span className="absolute right-2 top-1/2 -translate-y-1/2 text-[10px] text-muted-foreground">%</span>
                  </div>
                </div>
              </div>
            )}

            {/* --- CRÉDITO: antecipação + taxas por parcela --- */}
            {(machineType === "credit" || machineType === "both") && (
              <>
                <div className="space-y-4 p-4 border rounded-xl bg-primary/5">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <Clock className="h-4 w-4 text-primary" />
                      <Label className="text-base font-semibold">Antecipação Automática</Label>
                    </div>
                    <Switch 
                      checked={isAnticipated} 
                      onCheckedChange={(val) => setValue("is_anticipated", val)} 
                    />
                  </div>

                  {isAnticipated ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-2 animate-in fade-in slide-in-from-top-2">
                      <div className="space-y-2">
                        <Label>Tipo de Prazo</Label>
                        <div className="flex p-1 bg-muted rounded-lg">
                          <Button
                            type="button"
                            variant={anticipationType === "hours" ? "default" : "ghost"}
                            size="sm"
                            className="flex-1 h-8 text-xs"
                            onClick={() => setValue("anticipation_type", "hours")}
                          >
                            <Clock className="h-3 w-3 mr-1" /> Horas
                          </Button>
                          <Button
                            type="button"
                            variant={anticipationType === "days" ? "default" : "ghost"}
                            size="sm"
                            className="flex-1 h-8 text-xs"
                            onClick={() => setValue("anticipation_type", "days")}
                          >
                            <CalendarIcon className="h-3 w-3 mr-1" /> Dias
                          </Button>
                        </div>
                      </div>

                      <div className="space-y-2">
                        <Label>Valor do Prazo</Label>
                        {anticipationType === "hours" ? (
                          <Select 
                            value={watch("anticipation_value").toString()} 
                            onValueChange={(val) => setValue("anticipation_value", parseInt(val))}
                          >
                            <SelectTrigger>
                              <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                              <SelectItem value="1">1 hora</SelectItem>
                              <SelectItem value="2">2 horas</SelectItem>
                              <SelectItem value="24">24 horas</SelectItem>
                            </SelectContent>
                          </Select>
                        ) : (
                          <Input 
                            type="number" 
                            min={1} 
                            max={31}
                            {...register("anticipation_value", { valueAsNumber: true })}
                            placeholder="Ex: 1 dia"
                          />
                        )}
                      </div>
                    </div>
                  ) : (
                    <div className="pt-2 animate-in fade-in slide-in-from-top-2">
                      <div className="space-y-2">
                        <Label>Prazo de Recebimento Padrão (Dias úteis)</Label>
                        <div className="flex items-center gap-2">
                          <Input 
                            type="number" 
                            min={0} 
                            max={60}
                            {...register("anticipation_value", { valueAsNumber: true })}
                            placeholder="Ex: 30"
                            className="max-w-[120px]"
                          />
                          <span className="text-sm text-muted-foreground">dias (D+X)</span>
                        </div>
                        <p className="text-[10px] text-muted-foreground">
                          Prazo padrão para recebimento de vendas no crédito sem antecipação.
                        </p>
                      </div>
                    </div>
                  )}
                </div>

                <div className="space-y-4">
                  <div className="flex items-center gap-2 border-b pb-2">
                    <Percent className="h-4 w-4 text-primary" />
                    <Label className="text-base font-semibold">Taxas por Parcela</Label>
                  </div>
                  
                  <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-3">
                    {rates.map((rate) => (
                      <div key={rate.installments} className="space-y-1.5">
                        <Label className="text-[10px] text-muted-foreground uppercase">{rate.installments}x</Label>
                        <div className="relative">
                          <Input 
                            className="pr-6 text-sm"
                            value={rateInputs.get(rate.installments) ?? (rate.rate ?? 0).toString().replace(".", ",")}
                            onChange={(e) => handleRateInputChange(rate.installments, e.target.value)}
                            onBlur={() => handleRateInputBlur(rate.installments)}
                            placeholder="0,00"
                            inputMode="decimal"
                          />
                          <span className="absolute right-2 top-1/2 -translate-y-1/2 text-[10px] text-muted-foreground">%</span>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </>
            )}
          </form>
        )}

        <DialogFooter className="gap-2 sm:gap-0">
          <Button variant="outline" onClick={() => onOpenChange(false)} disabled={loading}>
            Cancelar
          </Button>
          <Button form="card-machine-form" type="submit" disabled={loading || fetching}>
            {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
            <Save className="mr-2 h-4 w-4" />
            {machineId ? "Salvar Alterações" : "Cadastrar Maquininha"}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import React, { useState, useEffect } from "react";
import { toast } from "sonner";
import {
  CreditCard,
  ChevronDown,
  ChevronUp,
  Search,
  Receipt,
  Calendar,
  Layers,
  Clock,
  Check,
  Undo
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { format, parseISO } from "date-fns";
import { ptBR } from "date-fns/locale";
import { cn } from "@/lib/utils";

interface CardMachineSale {
  id: number;
  sale_id: number;
  method: string;
  amount: number;
  installments: number | null;
  status: string | null;
  machine_id: number | null;
  account_id: number | null;
  company_id: number | null;
  sales: {
    id: number;
    sale_date: string;
    clients: {
      name: string;
    } | null;
  } | null;
  card_machines: {
    id: number;
    name: string;
    machine_type: string | null;
    is_anticipated: boolean | null;
    anticipation_value: number | null;
    anticipation_type: string | null;
  } | null;
}

interface ProcessedRow {
  paymentId: number;
  saleId: number;
  saleDate: string;
  clientName: string;
  method: string;
  amount: number;
  totalInstallments: number;
  paidInstallments: number;
  remainingInstallments: number;
  machineName: string;
  machineType: string | null;
  machineId: number | null;
  isAnticipated: boolean | null;
  anticipationValue: number | null;
  anticipationType: string | null;
  status: string | null;
}

function getAnticipationLabel(row: ProcessedRow): string {
  if (!row.isAnticipated) return "Não";
  const val = row.anticipationValue ?? 1;
  const type = row.anticipationType === "hours" ? "hora(s)" : "dia(s)";
  return `${val} ${type}`;
}

function getMethodColor(method: string) {
  if (method === "Crédito") return "bg-purple-500/10 text-purple-500 border-purple-500/20";
  if (method === "Débito") return "bg-blue-500/10 text-blue-500 border-blue-500/20";
  return "bg-muted text-muted-foreground";
}

function getProgressColor(paid: number, total: number) {
  const ratio = total > 0 ? paid / total : 0;
  if (ratio === 1) return "bg-green-500";
  if (ratio >= 0.5) return "bg-yellow-500";
  return "bg-red-500";
}

export function CardMachineSalesTable() {
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  const [rows, setRows] = useState<ProcessedRow[]>([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [filterMethod, setFilterMethod] = useState("todos");
  const [filterStatus, setFilterStatus] = useState("todos");
  const [sortField, setSortField] = useState<"saleDate" | "amount" | "remaining">("saleDate");
  const [sortDir, setSortDir] = useState<"asc" | "desc">("desc");
  const [isCollapsed, setIsCollapsed] = useState(false);
  const [expandedRows, setExpandedRows] = useState<Set<number>>(new Set());
  const [rowTransactions, setRowTransactions] = useState<Record<number, any[]>>({});

  const toggleRow = async (saleId: number) => {
    const newExp = new Set(expandedRows);
    if (newExp.has(saleId)) {
      newExp.delete(saleId);
      setExpandedRows(newExp);
      return;
    }
    try {
      const { data } = await supabase.from('transactions')
        .select('*')
        .eq('sale_id', saleId)
        .order('transaction_date', { ascending: true });
      setRowTransactions(prev => ({ ...prev, [saleId]: data || [] }));
      newExp.add(saleId);
      setExpandedRows(newExp);
    } catch (e) {
      console.error(e);
    }
  };

  const toggleTransactionStatus = async (saleId: number, tx: any) => {
    const newStatus = !tx.is_paid;
    if (!tx.id) {
      toast.error("ID da parcela não encontrado. Recarregue a página e tente novamente.");
      return;
    }

    // Calcula o comportamento para o Pai
    const targetRow = rows.find(r => r.saleId === saleId);
    const targetRowPaymentId = targetRow?.paymentId;
    let computedPaiStatus = targetRow?.status;
    let willBecomeReceived = false;
    let willBecomePending = false;

    if (targetRow) {
      const u = newStatus ? targetRow.paidInstallments + 1 : targetRow.paidInstallments - 1;
      const s = u >= targetRow.totalInstallments ? "received" : "pending";
      willBecomeReceived = targetRow.status !== "received" && s === "received";
      willBecomePending = targetRow.status === "received" && s === "pending";
      computedPaiStatus = s;
    }

    // Otimista: transações locais e tabela pai
    setRowTransactions((prev) => {
      const current = prev[saleId] || [];
      return {
        ...prev,
        [saleId]: current.map((t) => (t.id === tx.id ? { ...t, is_paid: newStatus } : t)),
      };
    });

    setRows((prev) => prev.map(row => {
      if (row.saleId === saleId) {
        const updatedPaid = newStatus ? row.paidInstallments + 1 : Math.max(0, row.paidInstallments - 1);
        const isReceived = updatedPaid >= row.totalInstallments;
        return {
          ...row,
          paidInstallments: updatedPaid,
          remainingInstallments: row.totalInstallments - updatedPaid,
          status: isReceived ? "received" : "pending"
        };
      }
      return row;
    }));

    try {
      const { error } = await supabase
        .from("transactions")
        .update({ is_paid: newStatus })
        .eq("id", tx.id);
      if (error) throw error;

      // Sincroniza tabela de sale_payments se marcou de recebido p/ pendente (ou vice-versa)
      if (targetRowPaymentId && (willBecomeReceived || willBecomePending)) {
        await supabase.from("sale_payments").update({ status: computedPaiStatus }).eq("id", targetRowPaymentId);
      }

      toast.success(newStatus ? "Parcela marcada como paga!" : "Status da parcela revertido!");
      window.dispatchEvent(new Event("financial-data-changed"));
    } catch (err: any) {
      console.error(err);
      toast.error(err.message || "Erro no banco de dados ao atualizar a parcela");

      // Reverte otimismo
      setRowTransactions((prev) => {
        const current = prev[saleId] || [];
        return {
          ...prev,
          [saleId]: current.map((t) => (t.id === tx.id ? { ...t, is_paid: !newStatus } : t)),
        };
      });
      setRows((prev) => prev.map(row => {
        if (row.saleId === saleId) {
          const revertPaid = !newStatus ? row.paidInstallments + 1 : Math.max(0, row.paidInstallments - 1);
          const isReceived = revertPaid >= row.totalInstallments;
          return {
            ...row,
            paidInstallments: revertPaid,
            remainingInstallments: row.totalInstallments - revertPaid,
            status: isReceived ? "received" : "pending"
          };
        }
        return row;
      }));
    }
  };

  const fetchSales = async () => {
    setLoading(true);
    try {
      const { data: profile } = await supabase
        .from("profiles")
        .select("company_id")
        .eq("user_id", user?.id)
        .single();

      if (!profile?.company_id) return;

      const { data, error } = await supabase
        .from("sale_payments")
        .select(`
          id,
          sale_id,
          method,
          amount,
          installments,
          status,
          machine_id,
          account_id,
          company_id,
          sales (
            id,
            sale_date,
            created_at,
            clients (
              name
            )
          ),
          card_machines (
            id,
            name,
            machine_type,
            is_anticipated,
            anticipation_value,
            anticipation_type
          )
        `)
        .eq("company_id", profile.company_id)
        .in("method", ["Crédito", "Débito"])
        .not("machine_id", "is", null)
        .order("id", { ascending: false });

      if (error) throw error;

      // Process each payment row into a display row
      const processed: ProcessedRow[] = (data || []).map((sp: any) => {
        const totalInstallments = sp.installments ?? 1;

        let calculatedStatus = sp.status;
        let pInstallments = sp.status === "received" ? totalInstallments : 0;

        if (sp.status !== "received" && sp.card_machines) {
          const machine = sp.card_machines;
          const sDate = sp.sales?.created_at ? new Date(sp.sales.created_at) : (sp.sales?.sale_date ? new Date(sp.sales.sale_date) : new Date());
          const now = new Date();

          if (machine.is_anticipated) {
            const dt = new Date(sDate);
            if (machine.anticipation_type === 'hours') {
              // For UI purpose, hours anticipate almost next day if sale_date has 0 hours
              dt.setHours(dt.getHours() + (machine.anticipation_value || 0));
            } else {
              dt.setDate(dt.getDate() + (machine.anticipation_value || 0));
            }
            if (now >= dt) {
              calculatedStatus = "received";
              pInstallments = totalInstallments;
            }
          } else {
            // Non-anticipated: divides in 30, 60, 90 days.
            let paidCount = 0;
            for (let i = 1; i <= totalInstallments; i++) {
              const pDate = new Date(sDate);
              pDate.setDate(pDate.getDate() + (i * 30));
              if (now >= pDate) {
                paidCount++;
              }
            }
            pInstallments = Math.min(paidCount, totalInstallments);
            if (pInstallments === totalInstallments) {
              calculatedStatus = "received";
            }
          }
        }

        const paidInstallments = pInstallments;
        const remainingInstallments = totalInstallments - paidInstallments;

        return {
          paymentId: sp.id,
          saleId: sp.sale_id,
          saleDate: sp.sales?.sale_date ?? "",
          clientName: sp.sales?.clients?.name ?? "Cliente",
          method: sp.method,
          amount: sp.amount,
          totalInstallments,
          paidInstallments,
          remainingInstallments,
          machineName: sp.card_machines?.name ?? "—",
          machineType: sp.card_machines?.machine_type ?? null,
          machineId: sp.machine_id,
          isAnticipated: sp.card_machines?.is_anticipated ?? null,
          anticipationValue: sp.card_machines?.anticipation_value ?? null,
          anticipationType: sp.card_machines?.anticipation_type ?? null,
          status: calculatedStatus,
        };
      });

      setRows(processed);
    } catch (err) {
      console.error("[CardMachineSalesTable] Erro ao carregar vendas:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (user?.id) fetchSales();
  }, [user?.id]);

  const handleSort = (field: typeof sortField) => {
    if (sortField === field) {
      setSortDir((d) => (d === "asc" ? "desc" : "asc"));
    } else {
      setSortField(field);
      setSortDir("desc");
    }
  };

  const SortIcon = ({ field }: { field: typeof sortField }) => {
    if (sortField !== field) return null;
    return sortDir === "asc" ? (
      <ChevronUp className="h-3 w-3 inline ml-1" />
    ) : (
      <ChevronDown className="h-3 w-3 inline ml-1" />
    );
  };

  // Filter
  let filtered = rows.filter((r) => {
    const term = searchTerm.toLowerCase();
    const matchSearch =
      !term ||
      r.clientName.toLowerCase().includes(term) ||
      r.machineName.toLowerCase().includes(term) ||
      r.saleId.toString().includes(term);
    const matchMethod =
      filterMethod === "todos" || r.method === filterMethod;
    const matchStatus =
      filterStatus === "todos" ||
      (filterStatus === "recebido" && r.status === "received") ||
      (filterStatus === "pendente" && r.status !== "received");
    return matchSearch && matchMethod && matchStatus;
  });

  // Sort
  filtered = [...filtered].sort((a, b) => {
    let va: number | string = 0;
    let vb: number | string = 0;
    if (sortField === "saleDate") {
      va = a.saleDate;
      vb = b.saleDate;
    } else if (sortField === "amount") {
      va = a.amount;
      vb = b.amount;
    } else if (sortField === "remaining") {
      va = a.remainingInstallments;
      vb = b.remainingInstallments;
    }
    if (va < vb) return sortDir === "asc" ? -1 : 1;
    if (va > vb) return sortDir === "asc" ? 1 : -1;
    return 0;
  });

  const formatCurrency = (v: number) =>
    `R$ ${v.toLocaleString("pt-BR", { minimumFractionDigits: 2 })}`;

  const formatDate = (dateStr: string) => {
    if (!dateStr) return "—";
    try {
      return format(parseISO(dateStr), "dd/MM/yyyy", { locale: ptBR });
    } catch {
      return dateStr;
    }
  };

  return (
    <Card className="bg-card/50 border-border/50">
      <CardHeader
        className="cursor-pointer select-none"
        onClick={() => setIsCollapsed((c) => !c)}
      >
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center">
              <Receipt className="h-4 w-4 text-primary" />
            </div>
            <div>
              <CardTitle className="text-sm font-semibold">
                Vendas nas Maquininhas
              </CardTitle>
              <p className="text-xs text-muted-foreground mt-0.5">
                Crédito e débito — controle de parcelas
              </p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            {!loading && (
              <Badge
                variant="outline"
                className="text-[10px] bg-primary/5 border-primary/20 text-primary"
              >
                {rows.length} registro{rows.length !== 1 ? "s" : ""}
              </Badge>
            )}
            {isCollapsed ? (
              <ChevronDown className="h-4 w-4 text-muted-foreground" />
            ) : (
              <ChevronUp className="h-4 w-4 text-muted-foreground" />
            )}
          </div>
        </div>
      </CardHeader>

      {!isCollapsed && (
        <CardContent className="pt-0 space-y-4">
          {/* Filters */}
          <div className="flex flex-col sm:flex-row gap-2">
            <div className="relative flex-1">
              <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder="Buscar por cliente, maquininha ou nº da venda..."
                className="pl-8 bg-background text-sm"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                onClick={(e) => e.stopPropagation()}
              />
            </div>
            <div
              className="flex gap-2"
              onClick={(e) => e.stopPropagation()}
            >
              <Select value={filterMethod} onValueChange={setFilterMethod}>
                <SelectTrigger className="w-[110px] bg-background text-sm">
                  <SelectValue placeholder="Tipo" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="todos">Todos</SelectItem>
                  <SelectItem value="Crédito">Crédito</SelectItem>
                  <SelectItem value="Débito">Débito</SelectItem>
                </SelectContent>
              </Select>
              <Select value={filterStatus} onValueChange={setFilterStatus}>
                <SelectTrigger className="w-[120px] bg-background text-sm">
                  <SelectValue placeholder="Status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="todos">Todos</SelectItem>
                  <SelectItem value="recebido">Recebido</SelectItem>
                  <SelectItem value="pendente">Pendente</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </div>

          {/* Table */}
          {loading ? (
            <div className="space-y-2">
              {[1, 2, 3].map((i) => (
                <Skeleton key={i} className="h-12 w-full rounded-lg" />
              ))}
            </div>
          ) : filtered.length === 0 ? (
            <div className="text-center py-10 text-muted-foreground">
              <div className="w-12 h-12 rounded-full bg-muted flex items-center justify-center mx-auto mb-3">
                <CreditCard className="h-5 w-5 text-muted-foreground" />
              </div>
              <p className="text-sm font-medium">
                {rows.length === 0
                  ? "Nenhuma venda em maquininha encontrada"
                  : "Nenhum resultado para os filtros aplicados"}
              </p>
              <p className="text-xs mt-1 max-w-xs mx-auto">
                {rows.length === 0
                  ? "Registre vendas com pagamento em Crédito ou Débito para visualizá-las aqui."
                  : "Tente ajustar os filtros de busca."}
              </p>
            </div>
          ) : (
            <>
              {/* Desktop */}
              <div className="hidden md:block rounded-md border border-border/50 overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow className="bg-muted/30">
                      <TableHead className="min-w-[160px]">
                        <button
                          className="flex items-center gap-1 text-xs font-semibold hover:text-foreground transition-colors"
                          onClick={() => handleSort("saleDate")}
                        >
                          <Calendar className="h-3 w-3" />
                          Venda
                          <SortIcon field="saleDate" />
                        </button>
                      </TableHead>
                      <TableHead className="min-w-[120px] text-xs font-semibold">
                        <div className="flex items-center gap-1">
                          <CreditCard className="h-3 w-3" />
                          Maquininha
                        </div>
                      </TableHead>
                      <TableHead className="text-center text-xs font-semibold">
                        Tipo
                      </TableHead>
                      <TableHead className="text-center text-xs font-semibold">
                        <div className="flex items-center justify-center gap-1">
                          <Layers className="h-3 w-3" />
                          Parcelas
                        </div>
                      </TableHead>
                      <TableHead className="text-center text-xs font-semibold">
                        <button
                          className="flex items-center gap-1 hover:text-foreground transition-colors mx-auto"
                          onClick={() => handleSort("remaining")}
                        >
                          <Clock className="h-3 w-3" />
                          Restantes
                          <SortIcon field="remaining" />
                        </button>
                      </TableHead>
                      <TableHead className="text-center text-xs font-semibold">
                        Antecipação
                      </TableHead>
                      <TableHead className="text-right text-xs font-semibold">
                        <button
                          className="hover:text-foreground transition-colors"
                          onClick={() => handleSort("amount")}
                        >
                          Valor
                          <SortIcon field="amount" />
                        </button>
                      </TableHead>
                      <TableHead className="text-center text-xs font-semibold">
                        Status
                      </TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {filtered.map((row) => {
                      const progressPct =
                        row.totalInstallments > 0
                          ? (row.paidInstallments / row.totalInstallments) * 100
                          : 100;
                      const isExpanded = expandedRows.has(row.saleId);
                      const txs = rowTransactions[row.saleId] || [];

                      return (
                        <React.Fragment key={row.paymentId}>
                          <TableRow
                            className="hover:bg-muted/20 transition-colors cursor-pointer"
                            onClick={() => toggleRow(row.saleId)}
                          >
                            <TableCell>
                              <div className="flex flex-col gap-0.5">
                                <span className="text-xs font-semibold text-foreground">
                                  #{row.saleId} — {row.clientName}
                                </span>
                                <span className="text-[10px] text-muted-foreground">
                                  {formatDate(row.saleDate)}
                                </span>
                              </div>
                            </TableCell>

                            <TableCell>
                              <div className="flex items-center gap-1.5">
                                <div className="w-6 h-6 rounded bg-primary/10 flex items-center justify-center shrink-0">
                                  <CreditCard className="h-3 w-3 text-primary" />
                                </div>
                                <span className="text-xs font-medium truncate max-w-[120px]">
                                  {row.machineName}
                                </span>
                              </div>
                            </TableCell>

                            <TableCell className="text-center">
                              <Badge
                                variant="outline"
                                className={cn(
                                  "text-[10px] font-medium",
                                  getMethodColor(row.method)
                                )}
                              >
                                {row.method}
                              </Badge>
                            </TableCell>

                            <TableCell className="text-center">
                              <div className="flex flex-col items-center gap-1">
                                <span className="text-xs font-semibold">
                                  {row.paidInstallments}/{row.totalInstallments}
                                </span>
                                <div className="w-16 h-1.5 rounded-full bg-muted overflow-hidden">
                                  <div
                                    className={cn(
                                      "h-full rounded-full transition-all",
                                      getProgressColor(row.paidInstallments, row.totalInstallments)
                                    )}
                                    style={{ width: `${progressPct}%` }}
                                  />
                                </div>
                              </div>
                            </TableCell>

                            <TableCell className="text-center">
                              <span
                                className={cn(
                                  "text-xs font-bold",
                                  row.remainingInstallments === 0
                                    ? "text-green-500"
                                    : "text-orange-500"
                                )}
                              >
                                {row.remainingInstallments === 0
                                  ? "✓ Quitado"
                                  : `${row.remainingInstallments}x`}
                              </span>
                            </TableCell>

                            <TableCell className="text-center">
                              <span
                                className={cn(
                                  "text-xs",
                                  row.isAnticipated
                                    ? "text-primary font-medium"
                                    : "text-muted-foreground"
                                )}
                              >
                                {getAnticipationLabel(row)}
                              </span>
                            </TableCell>

                            <TableCell className="text-right">
                              <span className="text-sm font-semibold text-foreground whitespace-nowrap">
                                {formatCurrency(row.amount)}
                              </span>
                            </TableCell>

                            <TableCell className="text-center">
                              <div className="flex items-center justify-center gap-2">
                                <Badge
                                  variant="outline"
                                  className={cn(
                                    "text-[10px]",
                                    row.status === "received"
                                      ? "bg-green-500/10 text-green-600 border-green-500/20"
                                      : "bg-yellow-500/10 text-yellow-600 border-yellow-500/20"
                                  )}
                                >
                                  {row.status === "received" ? "Recebido" : "Pendente"}
                                </Badge>
                                {isExpanded ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
                              </div>
                            </TableCell>
                          </TableRow>

                          {isExpanded && (
                            <TableRow className="bg-muted/5 hover:bg-muted/5">
                              <TableCell colSpan={8} className="p-0 border-b">
                                <div className="px-10 py-4">
                                  <h4 className="text-xs font-semibold mb-3 flex items-center gap-2">
                                    <Clock className="w-4 h-4" /> Detalhes das Parcelas / Transações Agendadas
                                  </h4>
                                  {txs.length === 0 ? (
                                    <p className="text-xs text-muted-foreground">Nenhuma transação futura encontrada para esta venda.</p>
                                  ) : (
                                    <div className="grid gap-2">
                                      {txs.map((tx: any, idx: number) => (
                                        <div key={idx} className="flex flex-col sm:flex-row sm:items-center justify-between p-3 rounded-md bg-background border text-xs">
                                          <div className="flex flex-col">
                                            <span className="font-semibold">{tx.name || 'Parcela'}</span>
                                            <span className="text-muted-foreground">Previsão de Crédito: {formatDate(tx.transaction_date)}</span>
                                          </div>
                                          <div className="flex items-center justify-between sm:justify-end gap-3 mt-2 sm:mt-0">
                                            <span className="font-semibold text-sm mr-2">{formatCurrency(tx.amount)}</span>
                                            <Badge
                                              variant="outline"
                                              className={cn(
                                                "text-[10px]",
                                                tx.is_paid
                                                  ? "bg-green-500/10 text-green-600 border-green-500/20"
                                                  : "bg-yellow-500/10 text-yellow-600 border-yellow-500/20"
                                              )}
                                            >
                                              {tx.is_paid ? "Creditado/Pago" : "A Receber"}
                                            </Badge>
                                            <Button
                                              variant="ghost"
                                              size="icon"
                                              className="h-6 w-6 rounded-full"
                                              title={tx.is_paid ? "Desfazer Pagamento" : "Marcar como Pago"}
                                              onClick={() => toggleTransactionStatus(row.saleId, tx)}
                                            >
                                              {tx.is_paid ? (
                                                <Undo className="h-3.5 w-3.5 text-muted-foreground hover:text-red-500 transition-colors" />
                                              ) : (
                                                <Check className="h-3.5 w-3.5 text-muted-foreground hover:text-green-500 transition-colors" />
                                              )}
                                            </Button>
                                          </div>
                                        </div>
                                      ))}
                                    </div>
                                  )}
                                </div>
                              </TableCell>
                            </TableRow>
                          )}
                        </React.Fragment>
                      );
                    })}
                  </TableBody>
                </Table>
              </div>

              <div className="grid grid-cols-1 gap-3 md:hidden">
                {filtered.map((row) => {
                  const progressPct =
                    row.totalInstallments > 0
                      ? (row.paidInstallments / row.totalInstallments) * 100
                      : 100;
                  const isExpanded = expandedRows.has(row.saleId);
                  const txs = rowTransactions[row.saleId] || [];

                  return (
                    <div
                      key={row.paymentId}
                      className="rounded-xl border border-border/50 bg-card/30 p-4 space-y-3 cursor-pointer select-none transition-colors hover:bg-card/40"
                      onClick={() => toggleRow(row.saleId)}
                    >
                      <div className="flex items-start justify-between gap-2">
                        <div>
                          <p className="text-sm font-semibold text-foreground leading-snug">
                            #{row.saleId} — {row.clientName}
                          </p>
                          <p className="text-[10px] text-muted-foreground mt-0.5">
                            {formatDate(row.saleDate)}
                          </p>
                        </div>
                        <div className="flex flex-col items-end gap-1">
                          <Badge
                            variant="outline"
                            className={cn(
                              "text-[10px] shrink-0",
                              row.status === "received"
                                ? "bg-green-500/10 text-green-600 border-green-500/20"
                                : "bg-yellow-500/10 text-yellow-600 border-yellow-500/20"
                            )}
                          >
                            {row.status === "received" ? "Recebido" : "Pendente"}
                          </Badge>
                          {isExpanded ? <ChevronUp className="h-4 w-4 text-muted-foreground mt-1" /> : <ChevronDown className="h-4 w-4 text-muted-foreground mt-1" />}
                        </div>
                      </div>

                      <div className="flex items-center gap-2">
                        <div className="w-7 h-7 rounded-lg bg-primary/10 flex items-center justify-center shrink-0">
                          <CreditCard className="h-3.5 w-3.5 text-primary" />
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className="text-xs font-medium truncate">
                            {row.machineName}
                          </p>
                          <Badge
                            variant="outline"
                            className={cn(
                              "text-[9px] mt-0.5",
                              getMethodColor(row.method)
                            )}
                          >
                            {row.method}
                          </Badge>
                        </div>
                        <p className="text-sm font-bold text-foreground whitespace-nowrap">
                          {formatCurrency(row.amount)}
                        </p>
                      </div>

                      <div className="pt-2 border-t border-border/40 space-y-2">
                        <div className="flex items-center justify-between text-xs">
                          <span className="text-muted-foreground">Parcelas</span>
                          <span className="font-semibold">
                            {row.paidInstallments}/{row.totalInstallments}
                          </span>
                        </div>
                        <div className="w-full h-1.5 rounded-full bg-muted overflow-hidden">
                          <div
                            className={cn(
                              "h-full rounded-full transition-all",
                              getProgressColor(
                                row.paidInstallments,
                                row.totalInstallments
                              )
                            )}
                            style={{ width: `${progressPct}%` }}
                          />
                        </div>
                        <div className="flex items-center justify-between text-xs">
                          <span className="text-muted-foreground">Restantes</span>
                          <span
                            className={cn(
                              "font-bold",
                              row.remainingInstallments === 0
                                ? "text-green-500"
                                : "text-orange-500"
                            )}
                          >
                            {row.remainingInstallments === 0
                              ? "✓ Quitado"
                              : `${row.remainingInstallments}x`}
                          </span>
                        </div>
                        {row.isAnticipated && (
                          <div className="flex items-center justify-between text-xs">
                            <span className="text-muted-foreground">Antecipação</span>
                            <span className="text-primary font-medium">
                              {getAnticipationLabel(row)}
                            </span>
                          </div>
                        )}
                      </div>

                      {isExpanded && (
                        <div className="pt-3 mt-3 border-t border-border/40 space-y-2 relative" onClick={(e) => e.stopPropagation()}>
                          <h4 className="text-xs font-semibold mb-2 flex items-center gap-1.5 text-foreground">
                            <Clock className="w-3.5 h-3.5" /> Detalhes das Parcelas
                          </h4>
                          {txs.length === 0 ? (
                            <p className="text-xs text-muted-foreground">Nenhuma transação futura encontrada.</p>
                          ) : (
                            <div className="grid gap-2">
                              {txs.map((tx: any, idx: number) => (
                                <div key={idx} className="flex flex-col p-2.5 rounded-md bg-background border text-xs gap-2">
                                  <div className="flex items-start justify-between gap-2">
                                    <div className="flex flex-col">
                                      <span className="font-semibold">{tx.name || 'Parcela'}</span>
                                      <span className="text-[10px] text-muted-foreground mt-0.5">Venc: {formatDate(tx.transaction_date)}</span>
                                    </div>
                                    <span className="font-semibold">{formatCurrency(tx.amount)}</span>
                                  </div>

                                  <div className="flex items-center justify-between mt-1 pt-2 border-t border-border/50">
                                    <Badge
                                      variant="outline"
                                      className={cn(
                                        "text-[9px]",
                                        tx.is_paid
                                          ? "bg-green-500/10 text-green-600 border-green-500/20"
                                          : "bg-yellow-500/10 text-yellow-600 border-yellow-500/20"
                                      )}
                                    >
                                      {tx.is_paid ? "Pago" : "A Receber"}
                                    </Badge>

                                    <Button
                                      variant="ghost"
                                      size="sm"
                                      className="h-7 px-2 text-[10px] gap-1"
                                      onClick={() => toggleTransactionStatus(row.saleId, tx)}
                                    >
                                      {tx.is_paid ? (
                                        <>
                                          <Undo className="h-3 w-3 text-muted-foreground" />
                                          <span className="text-muted-foreground">Desfazer</span>
                                        </>
                                      ) : (
                                        <>
                                          <Check className="h-3 w-3 text-green-500" />
                                          <span className="text-green-500">Marcar Pago</span>
                                        </>
                                      )}
                                    </Button>
                                  </div>
                                </div>
                              ))}
                            </div>
                          )}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>

              {/* Footer summary */}
              <div className="flex flex-wrap gap-4 pt-2 border-t border-border/30 text-xs text-muted-foreground">
                <span>
                  <strong className="text-foreground">{filtered.length}</strong>{" "}
                  registro(s)
                </span>
                <span>
                  Total:{" "}
                  <strong className="text-foreground">
                    {formatCurrency(
                      filtered.reduce((acc, r) => acc + r.amount, 0)
                    )}
                  </strong>
                </span>
                <span>
                  Pendentes:{" "}
                  <strong className="text-orange-500">
                    {filtered.filter((r) => r.status !== "received").length}
                  </strong>
                </span>
                <span>
                  Recebidos:{" "}
                  <strong className="text-green-500">
                    {filtered.filter((r) => r.status === "received").length}
                  </strong>
                </span>
              </div>
            </>
          )}
        </CardContent>
      )}
    </Card>
  );
}

// @ts-nocheck
import { useState, useEffect } from "react";
import { 
  Plus, 
  Search, 
  MoreVertical, 
  Edit2, 
  Trash2, 
  CreditCard, 
  CheckCircle2, 
  XCircle,
  Clock,
  Settings2,
  Landmark
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { CardMachineModal } from "./CardMachineModal";
import { CardMachineSalesTable } from "./CardMachineSalesTable";
import { Skeleton } from "@/components/ui/skeleton";
import { cn } from "@/lib/utils";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";

interface CardMachine {
  id: number;
  name: string;
  account_id: number | null;
  machine_type: string | null;
  max_installments: number | null;
  is_anticipated: boolean | null;
  anticipation_type: string | null;
  anticipation_value: number | null;
  debit_rate: number | null;
  is_active: boolean | null;
  accounts?: {
    name: string;
  } | null;
}

export function CardMachinesList() {
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  const [machines, setMachines] = useState<CardMachine[]>([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [modalOpen, setModalOpen] = useState(false);
  const [selectedMachineId, setSelectedMachineId] = useState<number | null>(null);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [machineToDelete, setMachineToDelete] = useState<number | null>(null);

  const fetchMachines = async () => {
    setLoading(true);
    try {
      const { data: profile } = await supabase
        .from("profiles")
        .select("company_id")
        .eq("user_id", user?.id)
        .single();

      if (!profile) return;

      const { data, error } = await supabase
        .from("card_machines")
        .select(`
          *,
          accounts (
            name
          )
        `)
        .eq("company_id", profile.company_id)
        .order("name", { ascending: true });

      if (error) throw error;
      setMachines(data || []);
    } catch (error) {
      console.error("Error fetching machines:", error);
      toast.error("Erro ao carregar maquininhas");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (user?.id) {
      fetchMachines();
    }
  }, [user?.id]);

  const handleDelete = async () => {
    if (!machineToDelete) return;

    try {
      // Rates will be deleted automatically if CASCADE is on, 
      // but let's delete them manually to be safe or if FK doesn't cascade
      await supabase
        .from("card_machine_rates")
        .delete()
        .eq("machine_id", machineToDelete);

      const { error } = await supabase
        .from("card_machines")
        .delete()
        .eq("id", machineToDelete);

      if (error) throw error;

      toast.success("Maquininha removida com sucesso");
      fetchMachines();
    } catch (error) {
      console.error("Error deleting machine:", error);
      toast.error("Erro ao remover maquininha");
    } finally {
      setDeleteDialogOpen(false);
      setMachineToDelete(null);
    }
  };

  const filteredMachines = machines.filter(m => 
    (m.name || "").toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div className="relative w-full sm:w-72">
          <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Buscar maquininhas..."
            className="pl-8"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <Button onClick={() => { setSelectedMachineId(null); setModalOpen(true); }} className="w-full sm:w-auto">
          <Plus className="h-4 w-4 mr-2" /> Nova Maquininha
        </Button>
      </div>

      {loading ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {[1, 2, 3].map(i => (
            <Skeleton key={i} className="h-48 w-full rounded-xl" />
          ))}
        </div>
      ) : filteredMachines.length === 0 ? (
        <Card className="border-dashed border-2 bg-muted/30">
          <CardContent className="flex flex-col items-center justify-center py-12 text-center">
            <div className="w-12 h-12 rounded-full bg-muted flex items-center justify-center mb-4">
              <CreditCard className="h-6 w-6 text-muted-foreground" />
            </div>
            <h3 className="font-semibold text-lg">Nenhuma maquininha encontrada</h3>
            <p className="text-muted-foreground max-w-xs mt-1">
              Cadastre suas maquininhas de cartão para gerenciar as taxas e prazos de recebimento.
            </p>
            <Button variant="outline" className="mt-6" onClick={() => { setSelectedMachineId(null); setModalOpen(true); }}>
              <Plus className="h-4 w-4 mr-2" /> Cadastrar agora
            </Button>
          </CardContent>
        </Card>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {filteredMachines.map(machine => (
            <Card key={machine.id} className="overflow-hidden border-border/50 hover:border-primary/30 transition-colors group">
              <CardHeader className="p-4 flex flex-row items-center justify-between space-y-0 pb-2">
                <div className="flex items-center gap-3">
                  <div className={cn(
                    "w-10 h-10 rounded-lg flex items-center justify-center",
                    machine.is_active ? "bg-primary/10 text-primary" : "bg-muted text-muted-foreground"
                  )}>
                    <CreditCard className="h-5 w-5" />
                  </div>
                  <div>
                    <CardTitle className="text-sm font-bold truncate max-w-[150px]">
                      {machine.name}
                    </CardTitle>
                    <div className="flex items-center gap-1 mt-0.5">
                      {machine.is_active ? (
                        <Badge variant="outline" className="text-[9px] h-4 bg-green-500/10 text-green-600 border-green-500/20">Ativa</Badge>
                      ) : (
                        <Badge variant="outline" className="text-[9px] h-4 bg-red-500/10 text-red-600 border-red-500/20">Inativa</Badge>
                      )}
                      <Badge variant="outline" className={cn(
                        "text-[9px] h-4",
                        machine.machine_type === "both"
                          ? "bg-indigo-500/10 text-indigo-600 border-indigo-500/20"
                          : machine.machine_type === "debit" 
                            ? "bg-blue-500/10 text-blue-600 border-blue-500/20" 
                            : "bg-purple-500/10 text-purple-600 border-purple-500/20"
                      )}>
                        {machine.machine_type === "both" ? "Crédito e Débito" : machine.machine_type === "debit" ? "Débito" : "Crédito"}
                      </Badge>
                    </div>
                  </div>
                </div>
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <Button variant="ghost" size="icon" className="h-8 w-8">
                      <MoreVertical className="h-4 w-4" />
                    </Button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent align="end">
                    <DropdownMenuItem onClick={() => { setSelectedMachineId(machine.id); setModalOpen(true); }}>
                      <Edit2 className="h-4 w-4 mr-2" /> Editar
                    </DropdownMenuItem>
                    <DropdownMenuItem className="text-red-600" onClick={() => { setMachineToDelete(machine.id); setDeleteDialogOpen(true); }}>
                      <Trash2 className="h-4 w-4 mr-2" /> Excluir
                    </DropdownMenuItem>
                  </DropdownMenuContent>
                </DropdownMenu>
              </CardHeader>
              <CardContent className="p-4 pt-2">
                <div className="space-y-3">
                  <div className="flex items-center justify-between text-xs text-muted-foreground">
                    <div className="flex items-center gap-1.5">
                      <Landmark className="h-3 w-3" />
                      <span>Conta:</span>
                    </div>
                    <span className="font-medium text-foreground">{machine.accounts?.name || "Não definida"}</span>
                  </div>

                  <div className="flex items-center justify-between text-xs text-muted-foreground">
                    <div className="flex items-center gap-1.5">
                      <Settings2 className="h-3 w-3" />
                      <span>{machine.machine_type === "debit" ? "Taxa débito:" : "Parcelas máx:"}</span>
                    </div>
                    <span className="font-medium text-foreground">
                      {machine.machine_type === "debit" 
                        ? `${machine.debit_rate || 0}%` 
                        : `${machine.max_installments}x`
                      }
                    </span>
                  </div>

                  {machine.machine_type !== "debit" && (
                    <div className="flex items-center justify-between text-xs text-muted-foreground">
                      <div className="flex items-center gap-1.5">
                        <Clock className="h-3 w-3" />
                        <span>Antecipação:</span>
                      </div>
                      <span className={cn(
                        "font-medium",
                        machine.is_anticipated ? "text-primary" : "text-foreground"
                      )}>
                        {machine.is_anticipated 
                          ? `${machine.anticipation_value} ${machine.anticipation_type === 'hours' ? 'hora(s)' : 'dia(s)'}`
                          : "Não"
                        }
                      </span>
                    </div>
                  )}
                </div>

                <div className="mt-4 pt-4 border-t border-border/50">
                  <Button 
                    variant="secondary" 
                    className="w-full text-xs h-8 bg-primary/5 hover:bg-primary/10 text-primary border border-primary/20"
                    onClick={() => { setSelectedMachineId(machine.id); setModalOpen(true); }}
                  >
                    Ver Taxas e Detalhes
                  </Button>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Tabela de vendas realizadas nas maquininhas */}
      <CardMachineSalesTable />

      <CardMachineModal 
        open={modalOpen}
        onOpenChange={setModalOpen}
        machineId={selectedMachineId}
        onSuccess={fetchMachines}
      />

      <AlertDialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Você tem certeza?</AlertDialogTitle>
            <AlertDialogDescription>
              Esta ação não pode ser desfeita. Isso excluirá permanentemente a maquininha
              e todas as suas taxas cadastradas.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete} className="bg-red-600 hover:bg-red-700">
              Excluir
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

// @ts-nocheck
import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Plus, Pencil, Trash2, Check, X } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";
import { NewCategoryModal } from "./NewCategoryModal";

interface Category {
  id: number;
  name: string;
  type: string;
  color: string | null;
  natureza?: string | null;
}

interface ManageCategoriesModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onCategoriesChange?: () => void;
}

const COLORS = [
  { value: '#22c55e', label: 'Verde' },
  { value: '#3b82f6', label: 'Azul' },
  { value: '#eab308', label: 'Amarelo' },
  { value: '#ef4444', label: 'Vermelho' },
  { value: '#a855f7', label: 'Roxo' },
  { value: '#6b7280', label: 'Cinza' },
];

export function ManageCategoriesModal({ open, onOpenChange, onCategoriesChange }: ManageCategoriesModalProps) {
  const { user } = useAuth();
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(false);
  const [newCategoryModalOpen, setNewCategoryModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editName, setEditName] = useState("");
  const [editColor, setEditColor] = useState("");

  useEffect(() => {
    if (open) {
      fetchCategories();
    }
  }, [open, user?.id]);

  const fetchCategories = async () => {
    if (!user?.id) return;

    setLoading(true);
    try {
      const { data: profile } = await supabase
        .from("profiles")
        .select("company_id")
        .eq("user_id", user.id)
        .single();

      if (!profile?.company_id) return;

      const { data, error } = await supabase
        .from("categories")
        .select("*")
        .eq("company_id", profile.company_id)
        .order("type")
        .order("name");

      if (error) throw error;
      setCategories(data || []);
    } catch (error) {
      console.error("Error fetching categories:", error);
      toast.error("Erro ao carregar categorias");
    } finally {
      setLoading(false);
    }
  };

  const startEditing = (category: Category) => {
    setEditingId(category.id);
    setEditName(category.name);
    setEditColor(category.color || COLORS[0].value);
  };

  const cancelEditing = () => {
    setEditingId(null);
    setEditName("");
    setEditColor("");
  };

  const saveEdit = async (category: Category) => {
    if (!editName.trim()) {
      toast.error("O nome não pode estar vazio");
      return;
    }

    try {
      const { error } = await supabase
        .from("categories")
        .update({ name: editName.trim(), color: editColor })
        .eq("id", category.id);

      if (error) throw error;

      toast.success("Categoria atualizada!");
      setEditingId(null);
      fetchCategories();
      onCategoriesChange?.();
    } catch (error) {
      console.error("Error updating category:", error);
      toast.error("Erro ao atualizar categoria");
    }
  };

  const deleteCategory = async (category: Category) => {
    try {
      // Check if category has transactions
      const { count } = await supabase
        .from("transactions")
        .select("*", { count: 'exact', head: true })
        .eq("category_id", category.id);

      if (count && count > 0) {
        toast.error(`Esta categoria possui ${count} transação(ões). Não pode ser excluída.`);
        return;
      }

      const { error } = await supabase
        .from("categories")
        .delete()
        .eq("id", category.id);

      if (error) throw error;

      toast.success("Categoria excluída!");
      fetchCategories();
      onCategoriesChange?.();
    } catch (error) {
      console.error("Error deleting category:", error);
      toast.error("Erro ao excluir categoria");
    }
  };

  const entradas = categories.filter(c => c.type === 'Entrada');
  const custosFixos = categories.filter(c => c.type === 'Saida' && c.natureza === 'Custo Fixo');
  const custosVariaveis = categories.filter(c => c.type === 'Saida' && c.natureza === 'Custo Variável');
  const despesasFixas = categories.filter(c => c.type === 'Saida' && c.natureza === 'Despesa Fixa');
  const despesasVariaveis = categories.filter(c => c.type === 'Saida' && c.natureza === 'Despesa Variável');
  const outrasSaidas = categories.filter(c => c.type === 'Saida' && !['Custo Fixo', 'Custo Variável', 'Despesa Fixa', 'Despesa Variável'].includes(c.natureza || ''));

  const renderCategoryItem = (category: Category) => {
    const isEditing = editingId === category.id;

    if (isEditing) {
      return (
        <div key={category.id} className="flex items-center gap-2 p-2 bg-muted/50 rounded-lg">
          <div
            className="w-3 h-3 rounded-full flex-shrink-0"
            style={{ backgroundColor: editColor }}
          />
          <Input
            value={editName}
            onChange={e => setEditName(e.target.value)}
            className="flex-1 h-8"
            autoFocus
          />
          <div className="flex gap-1">
            {COLORS.map(c => (
              <button
                key={c.value}
                type="button"
                onClick={() => setEditColor(c.value)}
                className={`w-5 h-5 rounded-full border transition-all ${editColor === c.value ? 'border-foreground scale-110' : 'border-transparent'
                  }`}
                style={{ backgroundColor: c.value }}
              />
            ))}
          </div>
          <Button size="icon" variant="ghost" className="h-8 w-8" onClick={() => saveEdit(category)}>
            <Check className="h-4 w-4 text-green-500" />
          </Button>
          <Button size="icon" variant="ghost" className="h-8 w-8" onClick={cancelEditing}>
            <X className="h-4 w-4 text-red-500" />
          </Button>
        </div>
      );
    }

    return (
      <div key={category.id} className="flex items-center justify-between p-2 hover:bg-muted/50 rounded-lg group">
        <div className="flex items-center gap-2">
          <div
            className="w-3 h-3 rounded-full"
            style={{ backgroundColor: category.color || '#6b7280' }}
          />
          <span>{category.name}</span>
        </div>
        <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
          <Button size="icon" variant="ghost" className="h-8 w-8" onClick={() => startEditing(category)}>
            <Pencil className="h-4 w-4" />
          </Button>
          <Button size="icon" variant="ghost" className="h-8 w-8 text-destructive" onClick={() => deleteCategory(category)}>
            <Trash2 className="h-4 w-4" />
          </Button>
        </div>
      </div>
    );
  };

  return (
    <>
      <Dialog open={open} onOpenChange={onOpenChange}>
        <DialogContent className="sm:max-w-lg max-h-[80vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Gerenciar Categorias</DialogTitle>
          </DialogHeader>

          <div className="space-y-6">
            <Button onClick={() => setNewCategoryModalOpen(true)} className="w-full">
              <Plus className="h-4 w-4 mr-2" /> Nova Categoria
            </Button>

            {loading ? (
              <div className="text-center py-4 text-muted-foreground">Carregando...</div>
            ) : categories.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground">
                <p>Nenhuma categoria cadastrada</p>
                <p className="text-sm">Crie sua primeira categoria para começar</p>
              </div>
            ) : (
              <div className="space-y-6">
                {/* Entradas */}
                <div className="space-y-2">
                  <h3 className="text-sm font-semibold text-green-500 flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-green-500" />
                    Entradas ({entradas.length})
                  </h3>
                  <div className="space-y-1 pl-4">
                    {entradas.length === 0 ? (
                      <p className="text-sm text-muted-foreground py-2">Nenhuma categoria de entrada</p>
                    ) : (
                      entradas.map(renderCategoryItem)
                    )}
                  </div>
                </div>

                {/* Custos Fixos */}
                {(custosFixos.length > 0 || categoriasVazias(custosFixos)) && (
                  <div className="space-y-2">
                    <h3 className="text-sm font-semibold text-red-500 flex items-center gap-2">
                      <div className="w-2 h-2 rounded-full bg-red-500" />
                      Custos Fixos ({custosFixos.length})
                    </h3>
                    <div className="space-y-1 pl-4">
                      {custosFixos.length > 0 ? custosFixos.map(renderCategoryItem) : <p className="text-sm text-muted-foreground py-2">Nenhum custo fixo cadastrado</p>}
                    </div>
                  </div>
                )}

                {/* Custos Variáveis */}
                {(custosVariaveis.length > 0 || categoriasVazias(custosVariaveis)) && (
                  <div className="space-y-2">
                    <h3 className="text-sm font-semibold text-red-500 flex items-center gap-2">
                      <div className="w-2 h-2 rounded-full bg-red-500" />
                      Custos Variáveis ({custosVariaveis.length})
                    </h3>
                    <div className="space-y-1 pl-4">
                      {custosVariaveis.length > 0 ? custosVariaveis.map(renderCategoryItem) : <p className="text-sm text-muted-foreground py-2">Nenhum custo variável cadastrado</p>}
                    </div>
                  </div>
                )}

                {/* Despesas Fixas */}
                {(despesasFixas.length > 0 || categoriasVazias(despesasFixas)) && (
                  <div className="space-y-2">
                    <h3 className="text-sm font-semibold text-red-500 flex items-center gap-2">
                      <div className="w-2 h-2 rounded-full bg-red-500" />
                      Despesas Fixas ({despesasFixas.length})
                    </h3>
                    <div className="space-y-1 pl-4">
                      {despesasFixas.length > 0 ? despesasFixas.map(renderCategoryItem) : <p className="text-sm text-muted-foreground py-2">Nenhuma despesa fixa cadastrada</p>}
                    </div>
                  </div>
                )}

                {/* Despesas Variáveis */}
                {(despesasVariaveis.length > 0 || categoriasVazias(despesasVariaveis)) && (
                  <div className="space-y-2">
                    <h3 className="text-sm font-semibold text-red-500 flex items-center gap-2">
                      <div className="w-2 h-2 rounded-full bg-red-500" />
                      Despesas Variáveis ({despesasVariaveis.length})
                    </h3>
                    <div className="space-y-1 pl-4">
                      {despesasVariaveis.length > 0 ? despesasVariaveis.map(renderCategoryItem) : <p className="text-sm text-muted-foreground py-2">Nenhuma despesa variável cadastrada</p>}
                    </div>
                  </div>
                )}

                {/* Outras Saídas (Fallback para antigas sem natureza) */}
                {outrasSaidas.length > 0 && (
                  <div className="space-y-2">
                    <h3 className="text-sm font-semibold text-red-500 flex items-center gap-2">
                      <div className="w-2 h-2 rounded-full bg-red-500" />
                      Outras Saídas ({outrasSaidas.length})
                    </h3>
                    <div className="space-y-1 pl-4">
                      {outrasSaidas.map(renderCategoryItem)}
                    </div>
                  </div>
                )}

              </div>
            )}
          </div>
        </DialogContent>
      </Dialog>

      <NewCategoryModal
        open={newCategoryModalOpen}
        onOpenChange={setNewCategoryModalOpen}
        onSuccess={() => {
          fetchCategories();
          onCategoriesChange?.();
        }}
      />
    </>
  );
}

// helper to always show headers even if empty
function categoriasVazias(arr: any[]) {
  return true; // We always show the block 
}

// @ts-nocheck
import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { toast } from "sonner";

interface NewCategoryModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  defaultType?: 'entrada' | 'saida';
  onSuccess?: (categoryId: number) => void;
}

const COLORS = [
  { value: '#22c55e', label: 'Verde' },
  { value: '#3b82f6', label: 'Azul' },
  { value: '#eab308', label: 'Amarelo' },
  { value: '#ef4444', label: 'Vermelho' },
  { value: '#a855f7', label: 'Roxo' },
  { value: '#6b7280', label: 'Cinza' },
];

export function NewCategoryModal({ open, onOpenChange, defaultType = 'entrada', onSuccess }: NewCategoryModalProps) {
  const { user } = useAuth();
  const [name, setName] = useState("");
  const [type, setType] = useState<'entrada' | 'saida'>(defaultType);
  const [color, setColor] = useState(COLORS[0].value);
  const [natureza, setNatureza] = useState("");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (open) {
      setType(defaultType);
    }
  }, [open, defaultType]);

  const handleSubmit = async () => {
    if (!name.trim()) {
      toast.error("Informe o nome da categoria");
      return;
    }

    if (type === 'saida' && !natureza) {
      toast.error("Selecione a natureza da saída");
      return;
    }

    if (!user?.id) return;

    setLoading(true);

    try {
      const { data: profile } = await supabase
        .from("profiles")
        .select("company_id")
        .eq("user_id", user.id)
        .single();

      if (!profile?.company_id) {
        toast.error("Empresa não encontrada");
        return;
      }

      const { data, error } = await supabase
        .from("categories")
        .insert({
          name: name.trim(),
          type: type === 'entrada' ? 'Entrada' : 'Saida',
          color,
          company_id: profile.company_id,
          natureza: type === 'saida' ? natureza : null,
        })
        .select()
        .single();

      if (error) throw error;

      toast.success("Categoria criada com sucesso!");
      onOpenChange(false);
      resetForm();
      onSuccess?.(data.id);
    } catch (error) {
      console.error("Error creating category:", error);
      toast.error("Erro ao criar categoria");
    } finally {
      setLoading(false);
    }
  };

  const resetForm = () => {
    setName("");
    setType(defaultType);
    setColor(COLORS[0].value);
    setNatureza("");
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>Nova Categoria</DialogTitle>
        </DialogHeader>

        <div className="space-y-4">
          <div className="space-y-2">
            <Label>Nome *</Label>
            <Input
              placeholder="Ex: Vendas Online"
              value={name}
              onChange={e => setName(e.target.value)}
            />
          </div>

          <div className="space-y-2">
            <Label>Tipo *</Label>
            <RadioGroup value={type} onValueChange={(v) => setType(v as 'entrada' | 'saida')} className="flex gap-4">
              <div className="flex items-center space-x-2">
                <RadioGroupItem value="entrada" id="entrada" />
                <Label htmlFor="entrada" className="cursor-pointer text-green-500 font-medium">Entrada</Label>
              </div>
              <div className="flex items-center space-x-2">
                <RadioGroupItem value="saida" id="saida" />
                <Label htmlFor="saida" className="cursor-pointer text-red-500 font-medium">Saída</Label>
              </div>
            </RadioGroup>
          </div>

          {type === 'saida' && (
            <div className="space-y-2">
              <Label>Natureza da Saída *</Label>
              <Select value={natureza} onValueChange={setNatureza}>
                <SelectTrigger>
                  <SelectValue placeholder="Selecione a classificação" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="Custo Fixo">Custo Fixo</SelectItem>
                  <SelectItem value="Custo Variável">Custo Variável</SelectItem>
                  <SelectItem value="Despesa Fixa">Despesa Fixa</SelectItem>
                  <SelectItem value="Despesa Variável">Despesa Variável</SelectItem>
                </SelectContent>
              </Select>
            </div>
          )}

          <div className="space-y-2">
            <Label>Cor</Label>
            <div className="flex gap-2">
              {COLORS.map(c => (
                <button
                  key={c.value}
                  type="button"
                  onClick={() => setColor(c.value)}
                  className={`w-8 h-8 rounded-full border-2 transition-all ${color === c.value ? 'border-foreground scale-110' : 'border-transparent'
                    }`}
                  style={{ backgroundColor: c.value }}
                  title={c.label}
                />
              ))}
            </div>
          </div>

          <div className="flex gap-2 pt-4">
            <Button variant="outline" className="flex-1" onClick={() => onOpenChange(false)} disabled={loading}>
              Cancelar
            </Button>
            <Button className="flex-1" onClick={handleSubmit} disabled={loading}>
              {loading ? "Criando..." : "Criar Categoria"}
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}
